/* ============================================================
   Procedure: [dbo].[Usp_ViewProductsBySearchCriteriaAndUserID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_ViewProductsBySearchCriteriaAndUserID] --3,34594        
(        
  @CriteriaID bigint,    
  @UserID_Microsite bigint        
)        
as        
Begin        

 -- declare  @CriteriaID bigint = 2        
  Declare @UserID bigint = 0        
  Declare @CriteriaType nvarchar(50) = ''        
  Declare @AllProductDefault bit = 0        
  Declare @ProductIDCollections nvarchar(max) = ''         
  Declare @SearchApplyTo nvarchar(50) = ''        
  Declare @AndOrOR nvarchar(50) = ''        
  Declare @SortByColumnName nvarchar(500) = ''         
  Declare @OrderBy nvarchar(50) = ''        
        
          
   select top 1  @UserID = isnull(createdby,0), @CriteriaType = isnull(CriteriaType,''),@AllProductDefault = ISNULL(AllProductDefault,0) , @SearchApplyTo = isnull(SearchApplyTo,'') , @ProductIDCollections =  isnull(ProductIDs,'') , @SortByColumnName = isnull(SortByColumnName,'ProductID')        
   ,@OrderBy = ISNULL(OrderBy,'Desc')    from ProductSearchCriteria(nolock) where ID = @CriteriaID        
        
    select top 1 @UserID = isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @UserID
	
	exec Usp_createProductMasterTable @UserID


     if(@SearchApplyTo = 'All')        
      Begin        
       set @AndOrOR = 'And'            
   End        
     else        
    Begin        
      set @AndOrOR = 'Or'            
    End        
        
        
   if(rtrim(ltrim(@CriteriaType))  = 'manual')        
      Begin        
        
    -- select @CriteriaType  , @SortByColumnName , @OrderBy        
          
 declare @QmxManual nvarchar(max) = N'         
  select        
    [ProductID]         
   ,[Name]        
      ,[UserID]        
      ,[Image]        
      ,[Description]        
      ,[Price]        
      ,[IsPublished]        
      ,[IsActive]        
      ,[CreatedOn]        
      ,[CreatedBy]      
   ,(select user_login from user_detail(nolock) where user_id = CreatedBy ) as CreatedByName        
      ,[FullPath]        
      ,[IsFeatured]        
      ,[sku]        
      ,[quantity]        
      ,isnull([category_id],0) as category_id     
   ,isnull((select CategoryName from Product_Category(nolock) where id = category_id ),''DefaultCategory'') as CategoryName        
      ,[HomeTaxIDs]        
      ,[OtherTaxIDs]        
      ,[UpdatedAt]        
      ,[DeletedAt]        
      ,[SellingAccount]        
      ,[CostPrice]        
      ,[Cast_Account]        
      ,[IsDigitalService]        
      ,[IsGoods]        
      ,[IsServices]        
      ,[SACCode]        
      ,[HSNCode]        
      ,[IsTaxable]        
      ,[DecimalRateItemQuantity]        
      ,[UnitID]        
      ,[IsSaleable] from tbl_ProductMaster_' +cast(@UserID as nvarchar(max))+ '  (nolock) where isnull(IsActive,0) = 1 and  USERID = '
	  +cast(@UserID as nvarchar(max))+' and ProductID in (select cast(isnull(value,0) as bigint) from fn_Split('''+@ProductIDCollections+''','',''))        
     order by category_id , '+ @SortByColumnName +' ' + @OrderBy          
        
   print @QmxManual        
        
    EXEC sp_executesql @QmxManual;        
        
        
   End        
   else if(rtrim(ltrim(@CriteriaType))  = 'Conditional')        
     Begin        
      if(isnull(@AllProductDefault,0) = 1)        
     Begin        
   declare @QmxTotal nvarchar(max) = N'         
  select        
    [ProductID]         
   ,[Name]        
      ,[UserID]        
      ,[Image]        
      ,[Description]        
      ,[Price]        
      ,[IsPublished]        
      ,[IsActive]        
      ,[CreatedOn]        
      ,[CreatedBy]      
   ,(select user_login from user_detail(nolock) where user_id = CreatedBy ) as CreatedByName         
      ,[FullPath]        
      ,[IsFeatured]        
      ,[sku]        
      ,[quantity]        
      ,isnull([category_id],0) as category_id    
   ,isnull((select CategoryName from Product_Category(nolock) where id = category_id ),''DefaultCategory'') as CategoryName         
      ,[HomeTaxIDs]        
      ,[OtherTaxIDs]        
      ,[UpdatedAt]        
      ,[DeletedAt]        
      ,[SellingAccount]        
      ,[CostPrice]        
      ,[Cast_Account]        
      ,[IsDigitalService]        
     ,[IsGoods]        
      ,[IsServices]        
      ,[SACCode]        
      ,[HSNCode]        
      ,[IsTaxable]        
      ,[DecimalRateItemQuantity]        
      ,[UnitID]        
      ,[IsSaleable] from tbl_ProductMaster_' +cast(@UserID as nvarchar(max))+ ' (nolock)
	   where isnull(IsActive,0) = 1 and  USERID = '+cast(@UserID as nvarchar(max))+'        
     order by category_id , '+ @SortByColumnName +' ' + @OrderBy          
        
   print @QmxTotal        
        
    EXEC sp_executesql @QmxTotal;        
               
     End        
           else        
    Begin        
    Declare @FilterText nvarchar(max) =  dbo.funcToGetSearchFilterByCriteriaID(@CriteriaID,@AndOrOR)         
    Declare @QueryMax nvarchar(max) = N'select        
    [ProductID]         
   ,[Name]        
      ,[UserID]        
      ,[Image]        
      ,[Description]        
      ,[Price]        
      ,[IsPublished]        
      ,[IsActive]        
      ,[CreatedOn]        
  ,[CreatedBy]      
   ,(select user_login from user_detail(nolock) where user_id = CreatedBy ) as CreatedByName         
      ,[FullPath]        
      ,[IsFeatured]        
      ,[sku]        
      ,[quantity]        
      ,isnull([category_id],0) as category_id     
    ,isnull((select CategoryName from Product_Category(nolock) where id = category_id ),''DefaultCategory'') as CategoryName          
      ,[HomeTaxIDs]        
      ,[OtherTaxIDs]        
      ,[UpdatedAt]        
      ,[DeletedAt]        
      ,[SellingAccount]        
      ,[CostPrice]        
      ,[Cast_Account]        
      ,[IsDigitalService]        
      ,[IsGoods]        
      ,[IsServices]        
      ,[SACCode]        
      ,[HSNCode]        
      ,[IsTaxable]        
      ,[DecimalRateItemQuantity]        
      ,[UnitID]        
      ,[IsSaleable] from tbl_ProductMaster_' +cast(@UserID as nvarchar(max))+ ' (nolock) where isnull(IsActive,0) = 1 and UserID = '
	  + cast( @UserID as nvarchar(max) )+' and ( '+ @FilterText +' )        
    order by category_id , '+ @SortByColumnName +' ' + @OrderBy         
               
        
            
    print @QueryMax        
        
    EXEC sp_executesql @QueryMax;        
    End           
  End        
            
               
End


GO

/* ============================================================
   Procedure: [dbo].[usp_ViewReferrersDetailed]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_ViewReferrersDetailed]        
@referid int        
as        
begin     
if exists(select 1 from Referrer_Details where id=@referid and isadmin=1)    
begin    
select a.id,User_Login,a.Name,a.Status,a.DateCreated,UserGroup,LastLogin,ReferrerLinkid,kit19userid,COUNT(r.id) as ContactsReferred,isnull(Conversionstracked,0) as Conversionstracked,isnull(SUM(Commissionamount),0) as TotalCommissionEarned from referrer_details a left join ReferredContacts r on r.ReferrerID=a.ID left join 
(select COUNT(id) as Conversionstracked,ReferrerID from ReferredContacts r where ConversionStatus=1 group by r.ReferrerID)
r1 on r1.ReferrerID=a.ID left join   
(select referrerid,referredcontactid,CommissionAmount,Status from PayoutTracking pt where pt.status='Payout Approved' and pt.ID=(select MAX(id) from PayoutTracking pt1 where pt1.ReferredContactId=pt.referredcontactid)    
) p on p.Referrerid=a.id group by r1.Conversionstracked,a.id,User_Login,a.Name,a.Status,a.DateCreated,UserGroup,LastLogin,ReferrerLinkid,kit19userid order by a.DateCreated desc    
end    
end    
    
     
     
     


GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewSearch_Lead_KiteverDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

       
CREATE   PROC [dbo].[Usp_ViewSearch_Lead_KiteverDetails]-- '' ,1             
(@Search NVARCHAR(50), @IsActive BIT)            
AS            
BEGIN  
 SELECT A.ID,  
        A.SearchName,  
        A.MicrositeName,  
        A.FromDate,  
        A.ToDate,  
        A.IsActive,  
        A.KiteverLeadType,  
        (  
            CASE   
                 WHEN  ISNULL(  A.MicrositeName,'') <> '' THEN '<p><b>MicrositeName:</b>' +  
                     ISNULL( A.MicrositeName   ,'')
                      + '</p>'  
                 ELSE ''  
            END +  
              
            CASE   
                 WHEN A.FromDate <> ''  
            OR A.LoginDateTo <> '' THEN '<p><b>Date:</b>' +  
               CAST( ISNULL( A.FromDate,'') AS VARCHAR(50)) + ' - ' + CAST( ISNULL( A.ToDate,'') AS VARCHAR(50))   
               + '</p>'   
               ELSE ''   
               END  
        )              AS SearchCriteria  
 FROM   SearchDetails     A  
 WHERE  (  
            ISNULL(@Search, '') = ''  
            OR MicrositeName LIKE '%' + @Search + '%'  
        )  
        AND (IsLeads = 1)  
        AND (IsKitever = 1)  
        AND (IsActive = @IsActive)  
END  


GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewSearchCriteria]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_ViewSearchCriteria]   --34594    
(      
  @UserID bigint        
)       
as      
Begin      
   
   -- Declare @UserID bigint = 34594          
    Declare @ParentID bigint = (select top 1 isnull(ParentID,0) from user_detail with(nolock) where user_id = @UserID) 
    exec Usp_createProductMasterTable @ParentID    
	
	Declare @Query nvarchar(max) = N'
	       
    SELECT       
       PSC.ID       
      ,PSC.CriteriaName      
      ,PSC.CriteriaType      
      ,PSC.ProductIDs     
   ,      
    (select    
  stuff    
      (     
    (select '','' + tblMain.Name from    
        (    
     select PM.Name    
     from (    
      select  value from fn_split(PSC.ProductIDs,'','') ) as tbl    
   join tbl_ProductMaster_' +Cast( @ParentID as nvarchar(max))+ '  (nolock) PM    
   on tbl.value = PM.ProductID    
   ) as tblMain    
        FOR XML PATH('''')), 1, 1, '''')    
     ) as ProductNames     
      ,PSC.AllProductDefault  
   ,(select case when isnull(PSC.AllProductDefault,0) = 1 then ''Yes'' else ''No'' end) as AllProductDefaultByName       
      ,PSC.SearchApplyTo      
      ,PSC.SortByColumnName      
      ,PSC.OrderBy      
      ,PSC.ParentID      
      ,PSC.CreatedOn      
      ,PSC.ModifiedOn      
      ,PSC.IsActive      
      ,PSC.CreatedBy      
   ,UD.User_Login  as CreatedByName        
  FROM ProductSearchCriteria(nolock) PSC      
      join User_Detail(nolock) UD      
   on PSC.CreatedBy = UD.User_ID        
   where PSC.CreatedBy = ' + Cast(@UserID as nvarchar(max)) + '  and isnull(PSC.IsActive,0) = 1 '    
             
    print @Query
	exec sp_executesql @Query   
End


GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewSearchCriteriaList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--Usp_ViewSearchCriteriaList 34594

  
CREATE   PROCEDURE [dbo].[Usp_ViewSearchCriteriaList] --34594        
 (@UserID BIGINT,
  @crtname varchar(max) = null,
  @fromdate datetime = null,
  @todate datetime= null,
  @isactive char(1)=null)    
AS    
BEGIN    
 DECLARE @ParentID BIGINT = 0    
    
 SELECT TOP 1 @ParentID = isnull(ParentID, USER_ID)    
 FROM User_Detail(NOLOCK)    
 WHERE User_ID = @UserID    
    
 SELECT TSC.ID    
  ,TSC.CriteriaName    
  ,TSC.CriteriaType    
  ,TSC.ApplyTo    
  ,TSC.ParentID    
  ,TSC.IsActive    
  ,TSC.CreatedOn    
  ,TSC.ModifiedOn    
  ,TSC.CreatedBy    
  ,TSC.ModifiedBy    
  ,ud.User_Login AS CreatedByName    
 FROM tbl_SearchCriteria(NOLOCK) AS TSC    
 JOIN User_Detail(NOLOCK) AS UD ON TSC.CreatedBy = UD.User_ID    
 WHERE TSC.ParentID = @ParentID --and isnull(TSC.IsActive,0) = 1       
	AND (@crtname IS NULL OR TSC.CriteriaName like '%'+@crtname+'%')
	AND (@fromdate IS NULL OR TSC.CreatedOn>@fromdate)
	AND (@todate IS NULL OR TSC.CreatedOn<@todate)
	AND (@isactive IS NULL OR TSC.IsActive=@isactive)
    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID    
  ,@Activity_type = 'view_Segmnt'    
  ,@ActionType = 'S'    
  ,@RowJson = ''    
  ,@Table_name = 'tbl_SearchCriteria'    
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewSearchCriteriaListwithPaging]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_ViewSearchCriteriaListwithPaging]

    @UserID    BIGINT,

    @crtname   VARCHAR(MAX) = NULL,

    @fromdate  DATETIME     = NULL,

    @todate    DATETIME     = NULL,

    @isactive  CHAR(1)      = NULL,

    @PageIndex INT          = 1,       -- 1-based

    @PageSize  INT          = 10       -- page size

AS

BEGIN

    SET NOCOUNT ON;
 
    DECLARE @ParentID BIGINT = 0;
 
    SELECT TOP 1 @ParentID = ISNULL(ParentID, USER_ID)

    FROM User_Detail (NOLOCK)

    WHERE User_ID = @UserID;
 
    ;WITH Base AS (

        SELECT

              TSC.ID

            , TSC.CriteriaName

            , TSC.CriteriaType

            , TSC.ApplyTo

            , TSC.ParentID

            , TSC.IsActive

            , TSC.CreatedOn

            , TSC.ModifiedOn

            , TSC.CreatedBy

            , TSC.ModifiedBy

            , UD.User_Login AS CreatedByName

        FROM tbl_SearchCriteria (NOLOCK) AS TSC

        JOIN User_Detail (NOLOCK) AS UD ON TSC.CreatedBy = UD.User_ID

        WHERE TSC.ParentID = @ParentID

          AND (@crtname  IS NULL OR TSC.CriteriaName LIKE '%' + @crtname + '%')

          AND (@fromdate IS NULL OR TSC.CreatedOn > @fromdate)

          AND (@todate   IS NULL OR TSC.CreatedOn < @todate)

          AND (@isactive IS NULL OR TSC.IsActive = @isactive)

    ),

    CTE AS (

        SELECT

              B.*

            , ROW_NUMBER() OVER (ORDER BY B.CreatedOn DESC) AS RowNum

            , COUNT(1) OVER () AS TotalCount

        FROM Base AS B

    )

    SELECT

          ID

        , CriteriaName

        , CriteriaType

        , ApplyTo

        , ParentID

        , IsActive

        , CreatedOn

        , ModifiedOn

        , CreatedBy

        , ModifiedBy

        , CreatedByName

        , TotalCount

    FROM CTE

    WHERE RowNum BETWEEN ((@PageIndex - 1) * @PageSize) + 1

                      AND (@PageIndex * @PageSize);
 
    EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId

          @User_id      = @UserID,

          @Activity_type = 'view_Segmnt',

          @ActionType    = 'S',

          @RowJson       = '',

          @Table_name    = 'tbl_SearchCriteria';

END
 


GO

