CREATE   PROCEDURE [dbo].[Usp_ViewSearchDetails] --1,1,'',1
	@IsKit19 BIT,
	@IsUsers BIT,
	@Search NVARCHAR(50),
	@IsActive BIT
AS
BEGIN
	SELECT A.ID,
	       A.SearchName,
	       A.IsNewUser,
	       A.UserName,
	       A.UserNameFilter,
	       A.Mobile,
	       A.EmailID,
	       A.usertypeName,
	       A.LastLoginBeforeFrom,
	       A.LastLoginBeforeTo,
	       A.LastPurchaseDaysFrom,
	       A.LastPurchaseDaysTo,
	       A.LastPurchasePriceFrom,
	       A.LastPurchasePriceTo,
	       A.BalanceFrom,
	       A.BalanceTo,
	       A.CreatedBetweenFrom,
	       A.CreatedBetweenTo,
	       A.TotalCreditPurchasedFrom,
	       A.TotalCreditPurchasedTo,
	       A.TotalCreditConsumedFrom,
	       A.TotalCreditConsumedTo,
	       A.MailBalanceFrom,
	       A.MailBalanceTo,
	       A.TotalMailCreditPurchasedFrom,
	       A.TotalMailCreditPurchasedTo,
	       A.TotalMailCreditConsumedFrom,
	       A.TotalMailCreditConsumedTo,
	       A.LastCreditPurchaseFrom,
	       A.LastCreditPurchaseTo,
	       A.HasMicrosite,
	       A.IsActive,
	       A.UserFilterName,
	       (
	           '<p><b>New User : </b>' + CASE 
	                                          WHEN A.IsNewUser = 1 THEN 
	                                               'Yes</p>'
	                                          ELSE 'No</p>'
	                                     END +
	           
	           CASE 
	                WHEN A.UserName <> '' THEN '<p><b>User Name:</b>' + A.UserName 
	                     
	                     + '</p>'
	                ELSE ''
	           END +
	           
	           CASE 
	                WHEN A.UserFilterName <> '' THEN '<p><b>User Filter:</b>' +
	                     
	                     A.UserFilterName 
	                     
	                     + '</p>'
	                ELSE ''
	           END +
	           
	           CASE 
	                WHEN A.Mobile <> '' THEN '<p><b>Mobile:</b>' + A.Mobile 
	                     
	                     +
	                     
	                     '</p>'
	                ELSE ''
	           END +
	           
	           CASE 
	                WHEN A.EmailID <> '' THEN '<p><b>EmailID:</b>' + A.EmailID 
	                     
	                     +
	                     
	                     '</p>'
	                ELSE ''
	           END +
	           
	           CASE 
	                WHEN A.usertypeName <> '' THEN '<p><b>UserType:</b>' + A.usertypeName 
	                     
	                     + '</p>'
	                ELSE ''
	           END +
	           
	           CASE 
	                WHEN A.LastLoginBeforeFrom <> ''
	           OR A.LastLoginBeforeTo <> '' THEN 
	              
	              '<p><b>Last Login Before:</b>' 
	              
	              +
	              
	              CAST(A.LastLoginBeforeFrom AS VARCHAR(50)) 
	              
	              + ' - ' + CAST(A.LastLoginBeforeTo AS VARCHAR(50)) 
	              
	              + '</p>' 
	              
	              ELSE '' 
	              
	              END +
	              
	              CASE 
	                   WHEN A.LastPurchaseDaysFrom <> ''
	           OR A.LastPurchaseDaysTo <> '' THEN 
	              
	              '<p><b>Last Purchase Days:</b>' 
	              
	              +
	              
	              CAST(A.LastPurchaseDaysFrom AS VARCHAR(50)) 
	              
	              + ' - ' + CAST(A.LastPurchaseDaysTo AS VARCHAR(50)) 
	              
	              + '</p>' 
	              
	              ELSE '' 
	              
	              END +
	              
	              CASE 
	                   WHEN A.LastPurchasePriceFrom <> ''
	           OR A.LastPurchasePriceTo <> '' THEN 
	              
	              '<p><b>Last Purchase Price:</b>' 
	              
	              +
	              
	              CAST(A.LastPurchasePriceFrom AS VARCHAR(50)) 
	              
	              + ' - ' + CAST(A.LastPurchasePriceTo AS VARCHAR(50)) 
	              
	              + '</p>' 
	              
	              ELSE '' 
	              
	              END +
	              
	              CASE 
	                   WHEN A.BalanceFrom <> ''
	           OR A.BalanceTo <> '' THEN 
	              
	              '<p><b>Balance:</b>' +
	              
	              CAST(A.BalanceFrom AS VARCHAR(50)) 
	              
	              + ' - ' + CAST(A.BalanceTo AS VARCHAR(50)) 
	              
	              + '</p>' 
	              
	              ELSE '' 
	              
	              END +
	              
	              CASE 
	                   WHEN A.CreatedBetweenFrom <> ''
	           OR A.CreatedBetweenTo <> '' THEN 
	              
	              '<p><b>Created Between :</b>' 
	              
	              +
	              
	              CAST(A.CreatedBetweenFrom AS VARCHAR(50)) 
	              
	              + ' - ' + CAST(A.CreatedBetweenTo AS VARCHAR(50)) 
	              
	              + '</p>' 
	              
	              ELSE '' 
	              
	              END +
	              
	              CASE 
	                   WHEN A.TotalCreditPurchasedFrom <>
	                        
	                        ''
	           OR A.TotalCreditPurchasedTo <
	              
	              > '' THEN 
	              
	              '<p><b>Credit Purchased :</b>' 
	              
	              +
	              
	              CAST(A.TotalCreditPurchasedFrom AS VARCHAR(50)) 
	              
	              + ' - ' + CAST(A.TotalCreditPurchasedTo AS VARCHAR(50)) 
	              
	              + '</p>' 
	              
	              ELSE '' 
	              
	              END +
	              
	              CASE 
	                   WHEN A.TotalCreditConsumedFrom <>
	                        
	                        ''
	           OR A.TotalCreditConsumedTo <>
	              
	              '' THEN 
	              
	              '<p><b>Credit Consumed  :</b>' 
	              
	              +
	              
	              CAST(A.TotalCreditConsumedFrom AS VARCHAR(50)) 
	              
	              + ' - ' + CAST(A.TotalCreditConsumedTo AS VARCHAR(50)) 
	              
	              + '</p>' 
	              
	              ELSE '' 
	              
	              END +
	              
	              
	              
	              CASE 
	                   WHEN A.MailBalanceFrom <>
	                        
	                        ''
	           OR A.MailBalanceTo <>
	              
	              '' THEN 
	              
	              '<p><b> Mail Balance  :</b>' 
	              
	              +
	              
	              CAST(A.MailBalanceFrom AS VARCHAR(50)) 
	              
	              + ' - ' + CAST(A.MailBalanceTo AS VARCHAR(50)) 
	              
	              + '</p>' 
	              
	              ELSE '' 
	              
	              END 
	              
	              +
	              
	              CASE 
	                   WHEN A.TotalMailCreditPurchasedFrom <>
	                        
	                        ''
	           OR A.TotalMailCreditPurchasedTo <>
	              
	              '' THEN 
	              
	              '<p><b> Mail Credit Purchased  :</b>' 
	              
	              +
	              
	              CAST(A.TotalMailCreditPurchasedFrom AS VARCHAR(50)) 
	              
	              + ' - ' + CAST(A.TotalMailCreditPurchasedTo AS VARCHAR(50)) 
	              
	              + '</p>' 
	              
	              ELSE '' 
	              
	              END 
	              
	              +
	              
	              CASE 
	                   WHEN A.TotalMailCreditConsumedFrom <>
	                        
	                        ''
	           OR A.TotalMailCreditConsumedTo <>
	              
	              '' THEN 
	              
	              '<p><b> Mail Credit Consumed  :</b>' 
	              
	              +
	              
	              CAST(A.TotalMailCreditConsumedFrom AS VARCHAR(50)) 
	              
	              + ' - ' + CAST(A.TotalMailCreditConsumedTo AS VARCHAR(50)) 
	              
	              + '</p>' 
	              
	              ELSE '' 
	              
	              END 
	              
	              +
	              
	              
	              
	              CASE 
	                   WHEN A.LastCreditPurchaseFrom <>
	                        
	                        ''
	           OR A.LastCreditPurchaseTo <>
	              
	              '' THEN 
	              
	              '<p><b> Last Mail Credit Purchased  :</b>' 
	              
	              +
	              
	              CAST(A.LastCreditPurchaseFrom AS VARCHAR(50)) 
	              
	              + ' - ' + CAST(A.LastCreditPurchaseTo AS VARCHAR(50)) 
	              
	              + '</p>' 
	              
	              ELSE '' 
	              
	              END 
	              
	              
	              
	              +
	              
	              CASE 
	                   WHEN A.HasMicrosite <> 0 THEN 
	                        '<p><b>Microstite:</b> Has Microsite' 
	                        
	                        + '</p>'
	                   ELSE '<p><b>Microstite:</b> Does not Have Microsite</p>'
	              END
	       )  AS SearchCriteria
	FROM   (
	           SELECT SD.ID,
	                  SD.SearchName,
	                  SD.IsNewUser,
	                  (
	                      SELECT STUFF(
	                                 (
	                                     SELECT N', ' + ss.FName + ' ' + ss.LName
	                                     FROM   User_Detail AS ss
	                                            INNER JOIN dbo.fn_Split(SD.UserName, '#') AS 
	                                                 fs
	                                                 ON  fs.[value] = ss.[User_ID] 
	                                                     
	                                                     
	                                                     
	                                                     FOR XML 
	                                                     
	                                                     PATH(''),
	                                            TYPE
	                                 ) 
	                                 
	                                 .value('text()[1]', 'nvarchar(max)'),
	                                 1,
	                                 2,
	                                 N''
	                             )
	                  )              AS UserName,
	                  (
	                      SELECT STUFF(
	                                 (
	                                     SELECT N', ' + ss.FName + ' ' + ss.LName 
	                                            
	                                            + ' ( ' 
	                                            
	                                            +
	                                            
	                                            uf.Name + ' )'
	                                     FROM   User_Detail AS ss
	                                            INNER JOIN dbo.fn_Split(SD.UserName, '#') AS 
	                                                 fs
	                                                 ON  fs.[value] = ss.[User_ID]
	                                            LEFT JOIN User_Filter AS uf
	                                                 ON  uf.Code = ss.userfilter 
	                                                     
	                                                     FOR XML 
	                                                     
	                                                     PATH(''),
	                                            TYPE
	                                 ) 
	                                 
	                                 .value('text()[1]', 'nvarchar(max)'),
	                                 1,
	                                 2,
	                                 N''
	                             )
	                  )              AS UserNameFilter,
	                  SD.Mobile,
	                  SD.EmailID,
	                  (
	                      SELECT STUFF(
	                                 (
	                                     SELECT N', ' + ss.Name
	                                     FROM   User_Type AS ss
	                                            INNER JOIN dbo.fn_Split(SD.UserType, '#') AS 
	                                                 fs
	                                                 ON  ss.ID = fs.[value] 
	                                                     
	                                                     FOR XML 
	                                                     
	                                                     PATH(''),
	                                            TYPE
	                                 ) 
	                                 
	                                 .value('text()[1]', 'nvarchar(max)'),
	                                 1,
	                                 2,
	                                 N''
	                             )
	                  )              AS usertypeName,
	                  SD.LastLoginBeforeFrom,
	                  SD.LastLoginBeforeTo,
	                  SD.LastPurchaseDaysFrom,
	                  SD.LastPurchaseDaysTo,
	                  SD.LastPurchasePriceFrom,
	                  SD.LastPurchasePriceTo,
	                  SD.BalanceFrom,
	                  SD.BalanceTo,
	                  SD.CreatedBetweenFrom,
	                  SD.CreatedBetweenTo,
	                  SD.TotalCreditPurchasedFrom,
	                  SD.TotalCreditPurchasedTo,
	                  SD.TotalCreditConsumedFrom,
	                  SD.TotalCreditConsumedTo,
	                  SD.MailBalanceFrom,
	                  SD.MailBalanceTo,
	                  SD.TotalMailCreditPurchasedFrom,
	                  SD.TotalMailCreditPurchasedTo,
	                  SD.TotalMailCreditConsumedFrom,
	                  SD.TotalMailCreditConsumedTo,
	                  SD.LastCreditPurchaseFrom,
	                  SD.LastCreditPurchaseTo,
	                  SD.HasMicrosite,
	                  SD.IsActive,
	                  (
	                      SELECT STUFF(
	                                 (
	                                     SELECT N', ' + ss.Name
	                                     FROM   User_Filter AS ss
	                                            INNER JOIN dbo.fn_Split(SD.UserFilter, '#') AS 
	                                                 fs
	                                                 ON  ss.Code = fs.[value] 
	                                                     
	                                                     FOR XML 
	                                                     
	                                                     PATH(''),
	                                            TYPE
	                                 ) 
	                                 
	                                 .value('text()[1]', 'nvarchar(max)'),
	                                 1,
	                                 2,
	                                 N''
	                             )
	                  )              AS UserFilterName,
	                  SD.CreatedDate
	           FROM   SearchDetails  AS SD(NOLOCK)
	           WHERE  (
	                      ISNULL(@Search, '') = ''
	                      OR UserName LIKE '%' + @Search + '%'
	                  )
	                  AND (IsKit19 = @IsKit19)
	                  AND (IsUsers = @IsUsers)
	                  AND (IsActive = @IsActive)
	       )     A
	ORDER BY
	       A.CreatedDate DESC
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewSearchLeadDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/*        
  Created by : Santosh Kumar        
  Created Date :31-05-2017 08:45 PM        
  SP For View Lead Details                    
  Alter Date:        
  Altered By :         
*/        
        
CREATE   PROC [dbo].[Usp_ViewSearchLeadDetails] 
(@Search NVARCHAR(50), @IsActive BIT)        
AS        
BEGIN
	SELECT ID,
	       sd.SearchName,
	       sd.MicrositeName,
	       sd.FromDate,
	       sd.ToDate,
	       sd.IsActive,
	       sd.Kit19LeadType,
	       CASE 
	            WHEN sd.MicrositeName <> '' THEN '<p><b>Microsite :</b>' + sd.MicrositeName 
	                 + '</p>'
	            ELSE ''
	       END +
	       CASE 
	            WHEN sd.FromDate <> '' AND sd.ToDate <> '' THEN 
	                 '<p><b>Date :</b>' + CAST(sd.FromDate AS VARCHAR(50)) 
	                 + ' - ' + CAST(sd.ToDate AS VARCHAR(50)) + '</p>'
	            ELSE ''
	       END            AS SearchCriteria
	FROM   SearchDetails     sd
	WHERE  (
	           ISNULL(@Search, '') = ''
	           OR MicrositeName LIKE '%' + @Search + '%'
	       )
	       AND (IsLeads = 1)
	       AND (IsKit19 = 1)
	       AND (IsActive = @IsActive)
END



