/* ============================================================
   Procedure: [dbo].[Usp_ViewSourceDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.Usp_ViewSourceDetails --'',1,0,335               
 (  
 @SearchText NVARCHAR(max) =null  
 ,@IsActive BIT  
 ,@IsInactive BIT  
 ,@UserID INT  
 )  
AS  
BEGIN  
 SELECT @UserID = Parentid  
 FROM user_detail(NOLOCK)  
 WHERE USER_ID = @userid  
  
 SELECT uss.SourceID  
  ,uss.Name  
  ,uss.IsEditable  
  ,uss.IsActive  
  ,ud.FName + ISNULL(ud.LName, '') AS CreatedBy  
 FROM UserSourceSettings AS uss  
 LEFT JOIN User_Detail AS ud ON uss.UserID = ud.[User_ID]  
 WHERE uss.UserID = @UserID  
  AND (  
   ISNULL(@SearchText, '') = ''  
   OR uss.Name LIKE '%' + @SearchText + '%'  
   )  
  AND (  
   uss.IsActive = CASE   
    WHEN @IsActive = 0  
     THEN NULL  
    ELSE 1  
    END  
   OR uss.IsActive = CASE   
    WHEN @IsInactive = 1  
     THEN 0  
    ELSE NULL  
    END  
   )  
 ORDER BY uss.SourceID DESC  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID  
  ,@Activity_type = 'View_srce_sttng'  
  ,@ActionType = 'S'  
  ,@RowJson = ''  
  ,@Table_name = 'UserSourceSettings'  
END  


GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewSourceDetails1]
