        CREATE   PROC [dbo].[Usp_ViewSourceDetails1] --'',1,0,335           
(  
    @SearchText NVARCHAR(100),  
    @IsActive BIT,  
    @IsInactive BIT,  
    @UserID INT ,
    @parentID bigint 
)          
AS          
BEGIN  
set nocount on
if (@UserID=@parentID)
begin
SELECT SourceID,  
        uss.Name,  
        uss.IsEditable,  
        uss.IsActive,  
        ud.FName + ISNULL(ud.LName, '') AS CreatedBy  
 FROM   UserSourceSettings     AS uss  
        LEFT JOIN User_Detail  AS ud  
             ON  uss.UserID = ud.[User_ID] where ud.ParentID=@parentID  
             AND (  
                ISNULL(@SearchText, '') = ''  
                OR uss.Name LIKE '%' + @SearchText + '%'  
            )  
        AND (  
                uss.IsActive = CASE   
                                    WHEN @IsActive = 0 THEN NULL  
                                    ELSE 1  
                               END  
                OR uss.IsActive = CASE   
                                       WHEN @IsInactive = 1 THEN 0  
                                       ELSE NULL  
                                  END  
            )  
 ORDER BY  
        uss.SourceID DESC
end
else
begin
 SELECT uss.SourceID,  
        uss.Name,  
        uss.IsEditable,  
        uss.IsActive,  
        ud.FName + ISNULL(ud.LName, '') AS CreatedBy  
 FROM   UserSourceSettings     AS uss  
        LEFT JOIN User_Detail  AS ud  
             ON  uss.UserID = ud.[User_ID]  
 WHERE  uss.UserID = @UserID  
        AND (  
                ISNULL(@SearchText, '') = ''  
                OR uss.Name LIKE '%' + @SearchText + '%'  
            )  
        AND (  
                uss.IsActive = CASE   
                                    WHEN @IsActive = 0 THEN NULL  
                                    ELSE 1  
                               END  
                OR uss.IsActive = CASE   
                                       WHEN @IsInactive = 1 THEN 0  
                                       ELSE NULL  
                                  END  
            )  
 ORDER BY  
        uss.SourceID DESC  
        end
END  


