CREATE   PROCEDURE dbo.Usp_ViewTradeIndiaDetails  
(  
 @ParentID Bigint  
)   
as  
Begin  
    Select  
     TIM.ID  
      ,TIM.TradeIndia_Key  
      ,TIM.Kit19ParentID  
      ,TIM.Trade_UserID  
      ,TIM.Trade_ProfileID  
      ,TIM.LastAPIHit  
      ,TIM.LastDateFetched  
      ,TIM.ExpiredOn  
      ,TIM.Status  
      ,TIM.CreatedOn  
      ,TIM.ModifiedOn  
      ,TIM.CreatedBy,  
    UD.User_Login as CreatedByName  
