/* ============================================================
   Procedure: [dbo].[Usp_ViewTradeIndiaDetails_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_ViewTradeIndiaDetails_New --35218  
	(@ParentID BIGINT)
AS
BEGIN
	IF (@ParentID <> 335)
	BEGIN
		SELECT TIM.ID
			,TIM.TradeIndia_Key
			,TIM.Kit19ParentID
			,isnull((
					SELECT TOP 1 User_Login
					FROM User_Detail
					WHERE USER_ID = TIM.Kit19ParentID
					), '') AS User_Login
			,TIM.Trade_UserID
			,TIM.Trade_ProfileID
			,dbo.Func_toGetTotalRecordsCountWithDateForTradeIndia(TIM.TradeIndia_Key, TIM.Trade_UserID, TIM.Trade_ProfileID) AS Records
			,TIM.LastAPIHit
			,TIM.LastDateFetched
			,TIM.ExpiredOn
			,TIM.STATUS
			,TIM.CreatedOn
			,TIM.ModifiedOn
			,TIM.CreatedBy
			,UD.User_Login AS CreatedByName
		FROM TradeIndia_Mapping TIM
		INNER JOIN User_Detail UD ON TIM.Createdby = UD.User_ID
		WHERE TIM.Kit19ParentID = @ParentID
		ORDER BY TIM.CreatedOn DESC
	END
	ELSE
	BEGIN
		SELECT TIM.ID
			,TIM.TradeIndia_Key
			,TIM.Kit19ParentID
			,isnull((
					SELECT TOP 1 User_Login
					FROM User_Detail
					WHERE USER_ID = TIM.Kit19ParentID
					), '') AS User_Login
			,TIM.Trade_UserID
			,TIM.Trade_ProfileID
			,dbo.Func_toGetTotalRecordsCountWithDateForTradeIndia(TIM.TradeIndia_Key, TIM.Trade_UserID, TIM.Trade_ProfileID) AS Records
			,TIM.LastAPIHit
			,TIM.LastDateFetched
			,TIM.ExpiredOn
			,TIM.STATUS
			,TIM.CreatedOn
			,TIM.ModifiedOn
			,TIM.CreatedBy
			,UD.User_Login AS CreatedByName
		FROM TradeIndia_Mapping TIM
		INNER JOIN User_Detail UD ON TIM.Createdby = UD.User_ID
		ORDER BY TIM.CreatedOn DESC
	END

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @ParentID
		,@Activity_type = 'View_TrdInd_Mppng'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'TradeIndia_Mapping'
END



GO

