/* ============================================================
   Procedure: [dbo].[Usp_ViewUserEnquriyDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
CREATE   PROCEDURE [dbo].[Usp_ViewUserEnquriyDetails] --'',335,335  
 @Txtsearch NVARCHAR(100),                                            
 @Parentid BIGINT,                                        
 --@pageStartIndex int,                                                                        
--@PageendSize int,                              
 @Userid  INT=0  
                                              
AS                                            
BEGIN                              
                                
    select * into #TMPTBL from UserLeads where ParentID = @Parentid                          
                          
                                        
 SELECT distinct A.Enquiryid,                                            
        A.Personname,                                            
        A.Companyname,                                            
        A.MobileNo3,                                            
        A.MobileNo1,                                            
        A.MobileNo2,                                            
        A.EmailID3,                                            
        A.EmailID1,                                            
        A.EmailID2,                                            
        A.Residentialaddress,                                            
        A.Officeaddress,                                            
        A.User_login,                                            
        A.MobileNo,                                            
        A.EmailID,                                            
        A.City,                                            
        A.[State],                                            
        A.Country,                                            
        A.Countrycode,                                            
        A.Pincode,                                            
        A.[ADDRESS],                                            
        A.Initialremarks,                                            
        A.SourceName,                                            
        A.MediumName,                                            
        A.CampaignName,                                            
        A.Parentid,                                            
       -- A.CreatedDate,  
        dbo.[fn_getusertimefromindiantime](@Parentid,A.CreatedDate) as CreatedDate,      
        A.CreatedDate1,  
        dbo.[fn_getusertimefromindiantime](@Parentid,A.CreatedDate1) as CreatedDate1New,                                                
        A.Createdby,                                            
        A.Leads,                                            
        A.Isopen,                                            
        A.RowNumber                                            
 FROM   (                                            
            SELECT Ue.Enquiryid,                                            
                   Ue.Personname,                                            
                   Ue.Companyname,                                            
                   Ue.Mobileno  AS MobileNo3,                                            
                   Ue.Mobileno1,                                            
                   Ue.Mobileno2,                                            
                   Ue.Emailid   AS EmailID3,                                            
                   Ue.Emailid1,                                            
                   Ue.Emailid2,                                            
                   Ue.Residentialaddress,                                            
                   Ue.Officeaddress,                                            
                   Ud.User_login,      
                   Ue.CreatedDate as CreatedDate1,                      
                   CASE                                             
                        WHEN ISNULL(Ue.Countrycode, '') <> '' THEN +                         
                                                               
                 case when (ISNULL(Ue.Countrycode, '') + ISNULL(Ue.Mobileno, '')) in                      
                   (                      
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                         
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                        
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                        
              from   Client_UnSubscribeDetails C_UDTemp                   
                join ClientPageDetail_Unsubscribe cpd on                    
                 --'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID                     
                     C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID                     
                    
                    
              )                      
                    then '<p style="color:red;" >'+(ISNULL(Ue.Countrycode, '') + ISNULL(Ue.Mobileno, ''))+ '</p>'                      
                    else                      
                        (ISNULL(Ue.Countrycode, '') + ISNULL(Ue.Mobileno, ''))                      
                    end                           
                             
                     else ''        
                     end                     
                                          
          +                                            
                                         
                                         
                                                               
                   CASE                                             
                        WHEN ISNULL(Ue.Mobileno1, '') <> '' THEN ', ' +                                            
                                                   
                                  
                             --ISNULL(Ue.Countrycode1, '')                                             
                                                                         
                             --+ ISNULL(Ue.Mobileno1, '')                        
                                                   
                   case when (ISNULL(Ue.Countrycode1, '') + ISNULL(Ue.Mobileno1, '')) in                      
                   (                      
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                         
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                        
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                        
                 from   Client_UnSubscribeDetails C_UDTemp                   
                  join ClientPageDetail_Unsubscribe cpd on                    
                  --'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID                     
                    C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID             
                    )                      
                    then '<p style="color:red;" >'+(ISNULL(Ue.Countrycode1, '') + ISNULL(Ue.Mobileno1, ''))+ '</p>'                      
                    else                      
                        (ISNULL(Ue.Countrycode1, '') + ISNULL(Ue.Mobileno1, ''))                      
                    end                           
                                                   
                                                   
                                                   
                                                                       
                        ELSE ''                                            
                   END +    
                                                               
                   CASE                                             
                        WHEN ISNULL(Ue.Mobileno2, '') < > '' THEN ', ' +                                            
                                                   
                                                   
                             --ISNULL(Ue.Countrycode2, '')                                 
                                                                         
                             --+ ISNULL(Ue.Mobileno2, '')                                            
                                             
                                            
                   case when (ISNULL(Ue.Countrycode2, '') + ISNULL(Ue.MobileNo2, '')) in                      
                   (                      
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                         
       --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                        
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                        
                  from   Client_UnSubscribeDetails C_UDTemp                    
                  join ClientPageDetail_Unsubscribe cpd on                     
                  --'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID                     
                     C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID             
                    )                      
                    then '<p style="color:red;" >'+(ISNULL(Ue.Countrycode2, '') + ISNULL(Ue.Mobileno2, ''))+ '</p>'                      
                    else                      
                        (ISNULL(Ue.Countrycode2, '') + ISNULL(Ue.Mobileno2, ''))                      
                    end                           
                                             
                                             
                                             
                        ELSE ''                                            
                   END          AS MobileNo,                        
                                                             
                   CASE                                  
                        WHEN ISNULL(Ue.Emailid, '') <> '' THEN ', '                       
                        +                      
                                        
                                        
                        -- ISNULL(Ue.Emailid, '') +                        
                           
                         case when (ISNULL(Ue.Emailid, '')) in                      
                   (                      
                     select ISNULL(C_UDTemp.Email,'') as EmailID                         
                                             
                      from   Client_UnSubscribeDetails C_UDTemp join ClientPageDetail_Unsubscribe cpd on                     
                    --  'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID                      
                     C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID             
                     )                      
                    then '<p style="color:red;" >'+(ISNULL(Ue.Emailid, ''))+ '</p>'                      
                    else                      
                        (ISNULL(Ue.Emailid, ''))                      
                    END                      
                    ELSE   ''                      
                    END+                      
                                         
                     CASE                                             
                        WHEN ISNULL(Ue.Emailid1, '') <> '' THEN ', '                       
                        +                       
                                              
                 -- ISNULL(Ue.Emailid1, '')                        
                         case when (ISNULL(Ue.Emailid1, '')) in                      
                   (                      
                     select ISNULL(C_UDTemp.Email,'') as EmailID                         
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                        
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)          
                      from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                     
                    --  'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID                     
                     C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID             
            )                      
                    then '<p style="color:red;" >'+(ISNULL(Ue.Emailid1, ''))+ '</p>'                      
                    else                      
                        (ISNULL(Ue.Emailid1, ''))                      
                       END                      
                                                                 
                                              
           
                        ELSE ''                                            
                   END +                                            
                                                               
                   CASE                                             
                   WHEN ISNULL(Ue.Emailid2, '') <> '' THEN ', ' +                       
                       
                       
                       
                   --ISNULL(Ue.Emailid2, '')                         
                       case when (ISNULL(Ue.Emailid2, '')) in                      
 (                      
                     select ISNULL(C_UDTemp.Email,'') as EmailID                         
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                        
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                        
                      from   Client_UnSubscribeDetails C_UDTemp join ClientPageDetail_Unsubscribe cpd on                     
                    --  'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID                     
                    C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID             
                    )                      
                    then '<p style="color:red;" >'+(ISNULL(Ue.Emailid2, ''))+ '</p>'                      
                    else                      
                        (ISNULL(Ue.Emailid2, ''))                      
                       END                      
                    ELSE ''                                            
                   END          AS EmailID,                                            
                   Ue.City,                                            
                   Ue.[State],                                            
                   Ue.Country,                                            
                   Ue.Countrycode,                                            
               Ue.Pincode,                       
                   CASE                                             
                        WHEN Ue.Companyname <> '' THEN Ue.Officeaddress                                            
                        ELSE Ue.Residentialaddress                                            
             END          AS [ADDRESS],                                            
                   Ue.Initialremarks,                 
                   Uss.Name     AS SourceName,                                            
                   Ums.Name AS MediumName,                                            
        Ucs.Name     AS CampaignName,                                            
                   Ue.Parentid,                                            
                   CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF(                                         
                       RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),                                            
                       7,                                            
                       7,                                            
                       ' '                                            
                 )      AS CreatedDate,                                            
                 Ue.Createdby,                                       
                   ISNULL(                                            
                       (                                            
                           SELECT TOP 1                                            
                                                                  
                                  1                           
                           FROM   #TMPTBL AS Ul                                            
                           WHERE  Ul.Parentid = @Parentid                                            
                                  AND (                                            
                                          ISNULL(NULLIF(Ul.Countrycode, ''), '1')                                             
            +                                            
                                             
                                          ISNULL(NULLIF(Ul.Mobileno, ''), '1')                                             
                                          = ISNULL(NULLIF(Ue.Countrycode, ''), '2')                                             
                                                                                      
                                          + ISNULL(NULLIF(Ue.Mobileno, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Countrycode, ''), '1')                          
                                             +                                         
                                                                                         
                                             ISNULL(NULLIF(Ul.Mobileno, ''), '1')                                             
                                             =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Countrycode1, ''), '2')                                      
                                             +                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Countrycode, ''), '1')                                             
                                             +                                            
                                                                                         
                                             ISNULL(NULLIF(Ul.Mobileno, ''), '1')                                             
                                             =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Countrycode2, ''), '2')                                             
                                             +                                  
                                                                                       
                                 ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')                                
                                             +                                            
                                                                                         
                                  ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                                             
                                             =                                       
                                                                                                                                    ISNULL(NULLIF(Ue.Countrycode, ''), '2')                                             
                                             +                                            
                                                                                         
                      ISNULL(NULLIF(Ue.Mobileno, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')        
                                             +                                            
                                                                                         
         ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                                             
                    =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Countrycode1, ''), '2')                                             
                                  +                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                                            
                                  OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')                                             
                                             +                                            
                                                                                         
                                             ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                                             
                 =                              
                                                                                         
                                             ISNULL(NULLIF(Ue.Countrycode2, ''), '2')                                             
                                             +                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')                                             
                                             +                                            
                                                                                         
                                             ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                                             
                                             =                                            
                                                                                         
                            ISNULL(NULLIF(Ue.Countrycode, ''), '2')                                             
                                             +                                            
                                                                                         
ISNULL(NULLIF(Ue.Mobileno, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')                                             
                                             +                                            
                        
                                             ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                                             
                                             =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Countrycode1, ''), '2')                                             
                   +                                            
                     
                                             ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')                                             
               +                                            
                                                                                         
                                             ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                               
                                             =                                            
                                       
       ISNULL(NULLIF(Ue.Countrycode2, ''), '2')                                             
                                             +                                            
                                                                                         
                                            ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Emailid, ''), '1')                                  
                                           =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Emailid, ''), '2')                                 
                                          OR ISNULL(NULLIF(Ul.Emailid, ''), '1')                                             
                                             =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Emailid1, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Emailid, ''), '1')                                           
                                             =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Emailid2, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Emailid1, ''), '1')                                             
                                             =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Emailid, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Emailid1, ''), '1')                                             
                             =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Emailid1, ''), '2')                                            
                                 OR ISNULL(NULLIF(Ul.Emailid1, ''), '1')                                             
                                             =                                            
                                                                               
                                                                               
                                             ISNULL(NULLIF(Ue.Emailid2, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Emailid2, ''), '1')                                             
                                             =                                            
                                                                                         
                                  ISNULL(NULLIF(Ue.Emailid, ''), '2')                                            
             OR ISNULL(NULLIF(Ul.Emailid2, ''), '1')                                             
                                             =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Emailid1, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Emailid2, ''), '1')                    
                                             =                                            
                                                                                        
  ISNULL(NULLIF(Ue.Emailid2, ''), '2')                                            
                  )                                            
                       ),                                            
                       0                                            
                   )                                  
                                              
                                                         
            AS Leads,                                            
                   --Ue.Isopen,                                   
                   (CASE                                             
         WHEN Ue.Isopen = '1' THEN 'open'                                           
                        ELSE 'close'                                            
                   END) as Isopen  ,                                  
                                                         
                   ROW_NUMBER() OVER(ORDER BY Enquiryid DESC) AS RowNumber                                            
                                                           
           FROM   Userenquiry Ue                                         
                   INNER JOIN Usersourcesettings Uss                                          
                        ON  Ue.Sourcename = Uss.Sourceid                                            
                   LEFT JOIN Usermediumsettings Ums                                           
           ON  Ue.Mediumname = Ums.Mediumid                                            
                   LEFT JOIN Usercampaignsettings Ucs                                           
                        ON  Ue.Campaignname = Ucs.Campaignid                                            
                   LEFT JOIN User_detail Ud                                           
                        ON  Ue.Createdby = Ud.User_id                                  
                   left join tbl_MergeLeadsEnquiry  mergeenq                                  
                        on  Ue.EnquiryID= mergeenq.EnquiryNo                           
                                                                     
            WHERE  Ue.Parentid = @Parentid                             
            AND ue.CreatedBy = CASE                             
                               WHEN (@Userid = 0) THEN ue.CreatedBy                            
                           ELSE @Userid  END                              
             --AND Ue.CreatedBy = case when ISNULL(@Userid,,0) =0 then createdby else @Userid end                              
                   --AND Ue.CreatedBy = case when ISNULL(@Userid,null)=335  then createdby else @Userid end                              
                  -- AND Ud.User_ID = isnull(@Userid,335)                                           
                   AND (                                            
                           ISNULL(@Txtsearch, '') = ''                                            
                       OR Personname LIKE '%' + @Txtsearch + '%'                                            
                           OR Companyname LIKE '%' + @Txtsearch + '%'                                   
                       )                                          
       
        ) A    --where a.RowNumber>=@pageStartIndex and a.RowNumber<=@PageendSize                                        
 ORDER BY                                            
        A.CreatedDate1 DESC                          
                                  
       drop table #TMPTBL                                            
END     
    
    



GO

/* ============================================================
   Procedure: [dbo].[Usp_viewuserenquriydetails_1/12/2017]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [Dbo].[Usp_viewuserenquriydetails_1/12/2017] --'',335,335                    
 @Txtsearch NVARCHAR(100),                    
 @Parentid BIGINT,                
 --@pageStartIndex int,                                                
--@PageendSize int,      
 @Userid  INT=0                     
AS                    
BEGIN                    
 SELECT A.Enquiryid,                    
        A.Personname,                    
        A.Companyname,                    
        A.MobileNo3,                    
        A.MobileNo1,                    
        A.MobileNo2,                    
        A.EmailID3,                    
        A.EmailID1,                    
        A.EmailID2,                    
        A.Residentialaddress,                    
        A.Officeaddress,                    
        A.User_login,                    
        A.MobileNo,                    
        A.EmailID,                    
        A.City,                    
        A.[State],                    
        A.Country,                    
        A.Countrycode,                    
        A.Pincode,                    
        A.[ADDRESS],                    
        A.Initialremarks,                    
        A.SourceName,                    
        A.MediumName,                    
        A.CampaignName,                    
        A.Parentid,                    
        A.CreatedDate,                    
        A.Createdby,                    
        A.Leads,                    
        A.Isopen,                    
        A.RowNumber                    
 FROM   (                    
            SELECT Ue.Enquiryid,                    
                   Ue.Personname,                    
                   Ue.Companyname,                    
                   Ue.Mobileno  AS MobileNo3,                    
                   Ue.Mobileno1,                    
                   Ue.Mobileno2,                    
                   Ue.Emailid   AS EmailID3,                    
                   Ue.Emailid1,                    
                   Ue.Emailid2,                    
                   Ue.Residentialaddress,                    
                   Ue.Officeaddress,                    
                   Ud.User_login,                    
                   ISNULL(Ue.Countrycode, '') + ISNULL(Ue.Mobileno, '') +                    
                                       
                   CASE                     
                        WHEN ISNULL(Ue.Mobileno1, '') <> '' THEN ', ' +                    
                             ISNULL(Ue.Countrycode1, '')                     
                                                 
                             + ISNULL(Ue.Mobileno1, '')                    
                        ELSE ''                    
                   END +                    
                                       
                   CASE                     
                        WHEN ISNULL(Ue.Mobileno2, '') < > '' THEN ', ' +                    
                             ISNULL(Ue.Countrycode2, '')                     
                                                 
                             + ISNULL(Ue.Mobileno2, '')                    
                        ELSE ''                    
                   END          AS MobileNo,                    
                   ISNULL(Ue.Emailid, '') +                    
                                       
                   CASE                     
                        WHEN ISNULL(Ue.Emailid1, '') <> '' THEN ', ' + ISNULL(Ue.Emailid1, '')                    
                        ELSE ''                    
                   END +                    
                                       
                   CASE                     
                        WHEN ISNULL(Ue.Emailid2, '') <> '' THEN ', ' + ISNULL(Ue.Emailid2, '')                    
                        ELSE ''                    
                   END          AS EmailID,                    
                   Ue.City,          
                   Ue.[State],                    
                   Ue.Country,                    
                   Ue.Countrycode,                    
                Ue.Pincode,       
                   CASE                     
                        WHEN Ue.Companyname <> '' THEN Ue.Officeaddress                    
                        ELSE Ue.Residentialaddress                    
             END          AS [ADDRESS],                    
                   Ue.Initialremarks,                    
                   Uss.Name     AS SourceName,                    
                   Ums.Name AS MediumName,                    
                   Ucs.Name     AS CampaignName,                    
                   Ue.Parentid,                    
                   CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF(                 
                       RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),                    
                       7,                    
                       7,                    
                       ' '                    
                 )            AS CreatedDate,                    
                   Ue.Createdby,               
                   --ISNULL(                    
                   --    (                    
                   --        SELECT TOP 1                    
                                          
                   --               1                    
                   --        FROM   Userleads AS Ul                    
                   --        WHERE  Ul.Parentid = @Parentid                    
            --                      AND (                    
            --                              ISNULL(NULLIF(Ul.Countrycode, ''), '1')                     
            --+                    
                                                              
            --                              ISNULL(NULLIF(Ul.Mobileno, ''), '1')                     
            --                              = ISNULL(NULLIF(Ue.Countrycode, ''), '2')                     
                                                              
            --                              + ISNULL(NULLIF(Ue.Mobileno, ''), '2')                    
            --                              OR ISNULL(NULLIF(Ul.Countrycode, ''), '1')                     
            --                                 +                    
                                                                 
            --                                 ISNULL(NULLIF(Ul.Mobileno, ''), '1')                     
            --                                 =                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Countrycode1, ''), '2')                     
            --                                 +                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                    
            --                              OR ISNULL(NULLIF(Ul.Countrycode, ''), '1')                     
            --                                 +                    
                                                                 
            --                                 ISNULL(NULLIF(Ul.Mobileno, ''), '1')                     
            --                                 =                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Countrycode2, ''), '2')                     
            --                                 +                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                    
            --                              OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')                     
            --                                +                    
                                                                 
            --                                 ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                     
            --                                 =                
                                                                 
            --                                 ISNULL(NULLIF(Ue.Countrycode, ''), '2')                     
            --                                 +                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Mobileno, ''), '2')                    
            --                              OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')                     
            --                                 +                    
                                                                 
            --                                 ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                     
            --        =                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Countrycode1, ''), '2')                     
            --                                 +                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                    
            --                      OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')                     
            --                                 +                    
                                                                 
            --                                 ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                     
            --     =                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Countrycode2, ''), '2')                     
            --                                 +                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                    
            --                              OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')                     
            --                                 +                    
                                                                 
            --                                 ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                     
            --                                 =                    
                                                                 
            --                ISNULL(NULLIF(Ue.Countrycode, ''), '2')                     
            --                                 +                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Mobileno, ''), '2')                    
            --                              OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')                     
            --                                 +                    
                                                                 
            --                                 ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                     
            --                                 =                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Countrycode1, ''), '2')                     
            --                                 +                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                    
            --                              OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')                   
            --                                 +                    
                                                                 
            --                                 ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                     
            --                                 =                    
                
            --                                 ISNULL(NULLIF(Ue.Countrycode2, ''), '2')                     
            --                                 +                    
                                                                 
           --                                 ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                    
            --                              OR ISNULL(NULLIF(Ul.Emailid, ''), '1')                     
            --                                 =                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Emailid, ''), '2')         
            --                              OR ISNULL(NULLIF(Ul.Emailid, ''), '1')                     
            --                                 =                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Emailid1, ''), '2')                    
            --                              OR ISNULL(NULLIF(Ul.Emailid, ''), '1')                     
            --                                 =                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Emailid2, ''), '2')                    
            --                              OR ISNULL(NULLIF(Ul.Emailid1, ''), '1')                     
            --                                 =                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Emailid, ''), '2')                    
            --                              OR ISNULL(NULLIF(Ul.Emailid1, ''), '1')                     
            --                                 =                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Emailid1, ''), '2')                    
            --                              OR ISNULL(NULLIF(Ul.Emailid1, ''), '1')                     
            --                                 =                    
                                                       
                                                       
            --                                 ISNULL(NULLIF(Ue.Emailid2, ''), '2')                    
            --                              OR ISNULL(NULLIF(Ul.Emailid2, ''), '1')                     
            --                                 =                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Emailid, ''), '2')                    
            -- OR ISNULL(NULLIF(Ul.Emailid2, ''), '1')                     
            --                                 =                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Emailid1, ''), '2')                    
            --                              OR ISNULL(NULLIF(Ul.Emailid2, ''), '1')                     
            --                                 =                    
                                                                 
            --                                 ISNULL(NULLIF(Ue.Emailid2, ''), '2')                    
            --      )                    
            --           ),                    
            --           0                    
            --       )          
                      
                                 
           1 AS Leads,       
                   Ue.Isopen,           
                   --(CASE                     
                   --     WHEN mergeenq.Isopen = '1' THEN 'open'                   
                   --     ELSE 'close'                    
                   --END) as Isopen  ,          
                                 
                   ROW_NUMBER() OVER(ORDER BY Enquiryid DESC) AS RowNumber                    
        
            FROM   Userenquiry(nolock) Ue                 
                   INNER JOIN Usersourcesettings Uss                  
                        ON  Ue.Sourcename = Uss.Sourceid                    
                   LEFT JOIN Usermediumsettings Ums                   
           ON  Ue.Mediumname = Ums.Mediumid                    
                   LEFT JOIN Usercampaignsettings Ucs                   
                        ON  Ue.Campaignname = Ucs.Campaignid                    
                   LEFT JOIN User_detail Ud                   
                        ON  Ue.Createdby = Ud.User_id          
                   left join tbl_MergeLeadsEnquiry  mergeenq          
                        on  Ue.EnquiryID= mergeenq.EnquiryNo                       
            WHERE  Ue.Parentid = @Parentid     
            AND ue.CreatedBy = CASE     
                               WHEN (@Userid = 0) THEN ue.CreatedBy    
                               ELSE @Userid  END      
             --AND Ue.CreatedBy = case when ISNULL(@Userid,,0) =0 then createdby else @Userid end      
                   --AND Ue.CreatedBy = case when ISNULL(@Userid,null)=335  then createdby else @Userid end      
                  -- AND Ud.User_ID = isnull(@Userid,335)                   
                   AND (                    
                           ISNULL(@Txtsearch, '') = ''                    
                       OR Personname LIKE '%' + @Txtsearch + '%'                    
                           OR Companyname LIKE '%' + @Txtsearch + '%'                    
                       )                  
                                       
        ) A    --where a.RowNumber>=@pageStartIndex and a.RowNumber<=@PageendSize                
 ORDER BY                    
        A.CreatedDate DESC                    
END 


