/* ============================================================
   Procedure: [dbo].[Usp_ViewUserEnquriyDetails_Changed]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
CREATE   PROCEDURE [dbo].[Usp_ViewUserEnquriyDetails_Changed]  --@Parentid=17626,@userid                                                   
 @Txtsearch NVARCHAR(100)='',                                                          
 @Parentid BIGINT,                                                      
 @Userid  INT=0,            
 @FilterText nvarchar(max) = '',              
 @ordstr nvarchar(Max)='',            
 @srno NVARCHAR(100)=1,            
 @enno NVARCHAR(100)=1000,          
 @ue_query nvarchar(max) = ''                                                     
AS                                                          
BEGIN                                            
                    
     if(@FilterText = '')            
        begin            
          set @FilterText = ' (1=1) '            
        end             
                
       
                                         
  --  select Ue.Enquiryid,Ul.*,1 as Leads                   
  --  into #TMPTBL  from UserLeads Ul inner join Userenquiry Ue                 
  --on Ul.ParentID = Ue.Parentid where Ul.Parentid = '24876' --@Parentid                                                    
  --                                AND (                                                      
  --                                        ISNULL(NULLIF(Ul.Countrycode, ''), '1')+ ISNULL(NULLIF(Ul.Mobileno, ''), '1')                                                           
  --                                        = ISNULL(NULLIF(Ue.Countrycode, ''), '2')+ISNULL(NULLIF(Ue.Mobileno, ''), '2')                                                          
  --                                        OR ISNULL(NULLIF(Ul.Countrycode, ''), '1') +ISNULL(NULLIF(Ul.Mobileno, ''), '1')                                                           
  --                                           =  ISNULL(NULLIF(Ue.Countrycode1, ''), '2')+ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                                                          
  --                                        OR ISNULL(NULLIF(Ul.Countrycode, ''), '1')+ISNULL(NULLIF(Ul.Mobileno, ''), '1')                                                           
  --                                           =ISNULL(NULLIF(Ue.Countrycode2, ''), '2')+ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                                                          
  --                                        OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')+ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                                                     
  --                                           =ISNULL(NULLIF(Ue.Countrycode, ''), '2')+ISNULL(NULLIF(Ue.Mobileno, ''), '2')                                                          
  --                                        OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')+ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                                                           
  --         =ISNULL(NULLIF(Ue.Countrycode1, ''), '2')+ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                                                          
  --         OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')+ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                                                           
  --         =ISNULL(NULLIF(Ue.Countrycode2, ''), '2')+ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                                                          
  --                                        OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')+ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                                                           
  --                                           =ISNULL(NULLIF(Ue.Countrycode, ''), '2')+ISNULL(NULLIF(Ue.Mobileno, ''), '2')                                                          
  --                                        OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')+ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                                                           
  --         =ISNULL(NULLIF(Ue.Countrycode1, ''), '2')+ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                                                 
  --                       OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')+ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                                             
--                                           =ISNULL(NULLIF(Ue.Countrycode2, ''), '2')+ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                                               
  --                                        OR ISNULL(NULLIF(Ul.Emailid, ''), '1') =ISNULL(NULLIF(Ue.Emailid, ''), '2')                                     
  --     OR ISNULL(NULLIF(Ul.Emailid, ''), '1') =ISNULL(NULLIF(Ue.Emailid1, ''), '2')                                                        
  --                                        OR ISNULL(NULLIF(Ul.Emailid, ''), '1') =ISNULL(NULLIF(Ue.Emailid2, ''), '2')                                                        
  --                                        OR ISNULL(NULLIF(Ul.Emailid1, ''), '1') =ISNULL(NULLIF(Ue.Emailid, ''), '2')                                                        
  --                                        OR ISNULL(NULLIF(Ul.Emailid1, ''), '1') =ISNULL(NULLIF(Ue.Emailid1, ''), '2')                                                        
  --                                        OR ISNULL(NULLIF(Ul.Emailid1, ''), '1') =ISNULL(NULLIF(Ue.Emailid2, ''), '2')                                                        
  --                                        OR ISNULL(NULLIF(Ul.Emailid2, ''), '1') =ISNULL(NULLIF(Ue.Emailid, ''), '2')                                                        
  --         OR ISNULL(NULLIF(Ul.Emailid2, ''), '1') =ISNULL(NULLIF(Ue.Emailid1, ''), '2')                                                        
  --                                        OR ISNULL(NULLIF(Ul.Emailid2, ''), '1') =ISNULL(NULLIF(Ue.Emailid2, ''), '2')                                                       
  --                )                              
 --Declare @Parentid as int                
 --set @Parentid =   17626                  
 --declare @Txtsearch as nvarchar(100)                
 --set @Txtsearch = ''                
 --declare @Userid  INT                
 --set @Userid=0                    
             
  --select * into #TMPTBL from UserLeads where ParentID = @Parentid             
 -- Select 0 AS RowN, * into #TMPquery FROM Userenquiry Ue where 1=2          
   declare @Query1 nvarchar(max) = ''           
----set @Query1 = @Query1 +'Select ROW_NUMBER() OVER(Order By Ue.'+ @ordstr+ ') AS RowN, * into #TMPquery FROM Userenquiry Ue '          
---- set @Query1 = @Query1 +' where ParentID = ' + Convert(varchar(100),@ParentID)          
---- if @FilterText <>''          
----  set @Query1 =   @Query1 +' and '+ @FilterText --+' Order by ' + @ordstr              
-- set @Query1 =   @Query1 +' ; Select * from #TMPquery '          
           
-- select @Query1          
--exec (@Query1)            
          
--set @query1 = @query1  + 'Select * into  #TMPquery  from ('          
--set @Query1 = @Query1 +'Select ROW_NUMBER() OVER(Order By '+ @ordstr+ ') AS RowNumber, * FROM Userenquiry  '          
-- set @Query1 = @Query1 +' where ParentID = ' + Convert(varchar(100),@ParentID)          
----if @FilterText <>''          
-- set @Query1 =   @Query1 + ') aa where aa.RowNumber between '+@srno+' and ' +@enno +' Order by RowNumber'           
      
      
if @ue_query <>''        
begin          
 set @Query1 = @Query1 +'Select ROW_NUMBER() OVER(Order By '+ @ordstr+ ') AS RowNumber, * into  #TMPquery  FROM Userenquiry  Ue '          
  set @Query1 = @Query1 +' where ParentID = ' + Convert(varchar(100),@ParentID)          
 set @Query1 = @Query1 +'  AND ' + @ue_query         
 set @Query1 = @Query1 + ' ;Declare @Rcnt varchar(100); select top 1 @Rcnt = RowNumber from #TMPquery order by RowNumber desc'          
end        
else        
begin        
if @ordstr =''        
