set @Query = @Query + ' AND ue.CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN ue.CreatedBy ELSE '+  Convert(varchar(100),@Userid) +' END '                     
--AND ISNULL('+ @Txtsearch+', '''') = '''''                    
--set @Query = @Query +' OR Ue.Personname LIKE ''%' + @Txtsearch + '%'' OR Ue.Companyname LIKE ''%' + @Txtsearch + '% '''                    
--set @Query = @Query +' ) A where '+ @FilterText+' Order by ' + @ordstr                   
if @FilterText <>''                   
set @Query = @Query +'  AND ' + @FilterText                   
set @Query = @Query +' ) A '+' Order by ' + @ordstr                    
                    
--set @Query = @Query +' and  Ue.RowNumber between ' +@srno +' and '+@enno+' ) A '+' Order by ' + @ordstr                    
set @Query = @Query + '; drop table #TMPquery  ' --RowNumber between ' +@srno +' and '+@enno +' Order by ' + @ordstr                    
                   
exec (@Query)                    
                    
--select @Query           
                                                      
                
--drop table #TMPquery                                                                 
END 


