CREATE   PROCEDURE [dbo].[Usp_ViewUserEnquriyDetails_Changedss2]                                                                                          
 @Txtsearch NVARCHAR(100)='',                                                                                                
 @Parentid BIGINT,                                                                                            
 @Userid  INT=0,                                                  
 @FilterText nvarchar(max) = '',                                                    
 @ordstr nvarchar(Max)='',                                                  
 @srno NVARCHAR(100),                                                  
 @enno NVARCHAR(100),                                                
 @ue_query nvarchar(max) = ''                                                                                           
AS                                                                                                
BEGIN               
IF OBJECT_ID('tempdb.dbo.##temp3', 'U') IS NOT NULL                    
        begin                  
                             
  DROP TABLE ##temp3;                   
  end                 
       IF OBJECT_ID('tempdb.dbo.##temp1', 'U') IS NOT NULL                    
        begin                          
  DROP TABLE ##temp1;                   
  end                          
  IF OBJECT_ID('tempdb.dbo.##temp2', 'U') IS NOT NULL                   
  begin                           
  DROP TABLE ##temp2;                          
  end                                          
      if @srno =''            
      begin            
     set @srno='1';            
      end              
      if @enno=''            
      begin            
     set @enno='1000';            
      end                                                          
DECLARE @Pivot_Column [nvarchar](max);                                  
DECLARE @Querynew [nvarchar](max);                                  
                                      
/*Select Pivot Column*/                                  
SELECT @Pivot_Column= COALESCE(@Pivot_Column+',','')+ QUOTENAME(fieldname) FROM                                  
(SELECT DISTINCT [fieldname] FROM customfields where ParentID=@ParentID and isActive=1)Tab                               
                                 
/*Create Dynamic Query*/                                  
SELECT @Querynew='SELECT EnquiryID as enq, '+@Pivot_Column+' into ##temp1 FROM                                 
(SELECT EnquiryID, [fieldname] , fieldvalue FROM (select x.EnquiryID, y.fieldname, x.fieldvalue  From customfieldEnquiryvalue x inner join customfields y on x.fieldID=y.field_ID)q )Tab1                                
PIVOT                                
(                                
max(fieldvalue) FOR [fieldname] IN ('+@Pivot_Column+')) AS Tab2                                
ORDER BY Tab2.EnquiryID'                                  
EXEC  sp_executesql  @Querynew                                                        
     if(@FilterText = '')                                                  
        begin                                                  
          set @FilterText = ' (1=1) '                                                  
        end                                                   
                                                      
                                             
                                                                               
                                              
   declare @Query1 nvarchar(max) = ''                                                 
                               
                                            
                                            
if @ue_query <>''                                            
begin                
 set @Query1 = @Query1 +'Select ROW_NUMBER() OVER(Order By '+ @ordstr+ ') AS RowNumber, * into  #TMPquery  FROM Userenquiry  Ue '                                              
  set @Query1 = @Query1 +' where ParentID = ' + Convert(varchar(100),@ParentID)                                             
 set @Query1 = @Query1 +'  AND ' + @ue_query                                     
 set @Query1 = @Query1 + ' ;Declare @Rcnt varchar(100); select top 1 @Rcnt = RowNumber from #TMPquery order by RowNumber desc'                   
end                                            
else                                            
begin             
if @ordstr =''                                            
 set @ordstr = 'Enquiryid desc'                                            
 set @Query1 = @Query1 +'Select ROW_NUMBER() OVER(Order By EnquiryID Desc) AS RowNumber,* into  #TMPquery  FROM Userenquiry  Ue '                                            
 set @Query1 = @Query1 +' where ParentID = ' + Convert(varchar(100),@ParentID)                                             
 set @Query1 = @Query1 + ' ;Declare @Rcnt varchar(100); select top 1 @Rcnt = Count(*) from Userenquiry '                                                
 set @Query1 = @Query1 +' where ParentID = ' + Convert(varchar(100),@ParentID)                                           
end                                              
                                          
                                            
                                            
   declare @Query nvarchar(max) = ''                                                
 set @Query = @Query1+ '; SELECT distinct  @Rcnt  as rcnt, A.Enquiryid,A.Personname,A.Companyname,A.MobileNo3,A.MobileNo1,A.MobileNo2, '                                                                    
 set @Query = @Query +'A.EmailID3,A.EmailID1,A.EmailID2,A.Residentialaddress,A.Officeaddress,A.User_login, '                                                
  set @Query = @Query +'A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], '                                                
  set @Query = @Query +'A.Initialremarks,A.SourceName,A.MediumName,A.CampaignName,A.Parentid,A.CreatedDate, '                                                
  set @Query = @Query +'A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,A.RowNumber into ##Temp2 FROM   ( '                                                                                     
  set @Query = @Query +'SELECT Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno,Ue.Mobileno  AS MobileNo3,Ue.Mobileno1, '                                                
  set @Query = @Query +'Ue.Mobileno2,Ue.Emailid ,Ue.Emailid  AS EmailID3,Ue.Emailid1,Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress, '                                                
                                 
   set @Query = @Query +'Ud.User_login,Ue.CreatedDate , '                                       
                                         
                                  
 set @Query = @Query +' Ue.City, Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, '                                                  
 set @Query = @Query +' CASE WHEN Ue.Companyname <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END AS [ADDRESS],'                                                
 set @Query = @Query +' Ue.Initialremarks, Uss.Name     AS SourceName, Ums.Name AS MediumName, Ucs.Name     AS CampaignName, '                                                      
 set @Query = @Query +' Ue.Parentid,CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), '                                                
 set @Query = @Query +' Ue.Createddate, 109), 15),7,7, '' '')    AS CreatedDate1, Ue.Createdby,  '                                                
                                         
                                       
   set @Query = @Query+ 'ue.LeadNo AS Leads,'                                         
 set @Query = @Query +' (CASE WHEN Ue.Isopen = ''1'' THEN ''open'' ELSE (CASE WHEN Ue.Isopen = ''0'' THEN ''close'' ELSE ''lead'' END) END) as Isopen  , '                           
 set @Query = @Query +' RowNumber FROM   #TMPquery Ue '                                                
                                     
 set @Query = @Query +' INNER JOIN Usersourcesettings Uss ON  Ue.Sourcename = Uss.Sourceid '                                                     
set @Query = @Query +' LEFT JOIN Usermediumsettings Ums ON  Ue.Mediumname = Ums.Mediumid '                           
set @Query = @Query +' LEFT JOIN Usercampaignsettings Ucs ON  Ue.Campaignname = Ucs.Campaignid '                                      
set @Query = @Query +' LEFT JOIN User_detail Ud ON  Ue.Createdby = Ud.User_id '                                      
set @Query = @Query +' WHERE  Ue.Parentid = '+ Convert(varchar(100),@ParentID)                                      
                                                
                                              
if @Userid >0                                                
set @Query = @Query + ' AND ue.CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN ue.CreatedBy ELSE '+  Convert(varchar(100),@Userid) +' END '                                                  
                                             
--if @FilterText <>''                                                 
--set @Query = @Query +'  AND ' + @FilterText                                                 
set @Query = @Query +' ) A Order by ' + @ordstr                                                 
 EXEC  sp_executesql @Query                    
                
 IF OBJECT_ID('tempdb..##temp1') IS NOT NULL               
                         
      begin                        
        if @FilterText <>''              
        begin                 
    set @Query= 'select * into ##temp3 from ##Temp2 x left join ##temp1 y on x.Enquiryid=y.enq where '+@FilterText;              
 EXEC  sp_executesql @Query;              
               
        end                 
        else              
        begin              
          set @Query= 'select * into ##temp3 from ##Temp2 x left join ##temp1 y on x.Enquiryid=y.enq';              
          EXEC  sp_executesql @Query;              
                       
        end                                           
  end                             
 else                        
      begin               
      if @FilterText <>''              
        begin              
         set @Query= 'select * into ##temp3 from ##Temp2 where '+ @FilterText;              
         EXEC  sp_executesql @Query;              
                       
        end               
        else              
        begin              
          set @Query= 'select * into ##temp3 from ##Temp2';              
          EXEC  sp_executesql @Query;              
                        
        end                      
                                         
      end      
      IF OBJECT_ID('tempdb..##temp1') IS NOT NULL               
                         
      begin      
      alter table ##temp3 drop column enq;    
      end           
      declare @rc varchar(15) ;                 
      select  @rc = Count(*) from ##temp3;            
      select * from (select ROW_NUMBER() OVER(Order By Enquiryid desc) AS RowNumber1, @rc AS rc1, * from ##temp3)aa where  RowNumber1 between @srno and @enno;              
                       
      IF OBJECT_ID('tempdb.dbo.##temp3', 'U') IS NOT NULL                    
        begin                  
                            
  DROP TABLE ##temp3;                   
  end                 
       IF OBJECT_ID('tempdb.dbo.##temp1', 'U') IS NOT NULL                    
        begin                          
  DROP TABLE ##temp1;                   
  end                          
  IF OBJECT_ID('tempdb.dbo.##temp2', 'U') IS NOT NULL                   
  begin                     
  DROP TABLE ##temp2;                          
  end                                   
        --drop table #TMPquery;                              
                                       
--set @Query = @Query + '; drop table #TMPquery  '                                   
                                                 
                                            
                                                  
                                                                   
END 



