 declare @Query nvarchar(max) = ''    
 set @Query = @Query1 +'SELECT distinct A.Enquiryid,A.Personname,A.Companyname,A.MobileNo3,A.MobileNo1,A.MobileNo2, '    
 set @Query = @Query +'A.EmailID3,A.EmailID1,A.EmailID2,A.Residentialaddress,A.Officeaddress,A.User_login, '    
 set @Query = @Query +'A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], '    
 set @Query = @Query +'A.Initialremarks,A.SourceName,A.MediumName,A.CampaignName,A.Parentid,A.CreatedDate, '    
 set @Query = @Query +'A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,isnull(A.img_ext,'''') as img_ext into #Temp2'    
 set @Query = @Query + ' FROM ( SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno,ltrim(Ue.Countrycode+'' ''+Ue.Mobileno)+ case when isnull(Ue.Mobileno1,'''')<>'''' then '', ...'' else '''' end AS MobileNo3,
 Ue.Mobileno1,'    
 set @Query = @Query +'Ue.Mobileno2,Ue.Emailid ,Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress, '    
 set @Query = @Query +'Ud.User_login,Ue.CreatedDate , '    
 set @Query = @Query +' Ue.City, Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, '    
 set @Query = @Query +' CASE WHEN Ue.Companyname <> '''' THEN    
 Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END    
 ELSE Ue.Residentialaddress END AS [ADDRESS],'    
 set @Query = @Query +' Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName, '    
 set @Query = @Query +' Ue.Parentid,CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), '    
 set @Query = @Query +' Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, '    
 set @Query = @Query+ 'CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads,'    
 set @Query = @Query +' (CASE WHEN isnull(ue.isopen,1)=1 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext '    
 set @Query = @Query +' FROM Userenquiry (NOLOCK) Ue  '    
 set @Query = @Query +' INNER JOIN Usersourcesettings (NOLOCK) Uss ON Ue.Sourcename = Uss.Sourceid'    
 set @Query = @Query +' LEFT JOIN Usermediumsettings (NOLOCK) Ums ON Ue.Mediumname = Ums.Mediumid '    
 set @Query = @Query +' LEFT JOIN Usercampaignsettings (NOLOCK) Ucs ON Ue.Campaignname = Ucs.Campaignid '    
 set @Query = @Query +' LEFT JOIN User_detail (NOLOCK) Ud ON Ue.Createdby = Ud.User_id and Ue.Parentid = Ud.ParentID '    
 set @Query = @Query +' WHERE Ue.Parentid = '+ Convert(varchar(100),@ParentID)    
    
    
 if @Userid >0    
 Begin    
  set @Query = @Query + ' AND ue.CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN ue.CreatedBy ELSE '+ Convert(varchar(100),@Userid) +' END '    
 End    
    
 set @Query = @Query + ' ) A '    
    
  If(@ue_query = '')    
 Begin    
  set @ue_query = ' (1=1) '    
 End    
    
 If(@FilterText = '')    
 Begin    
  set @FilterText = ' (1=1) '    
 End    
    
 If(@FilterText != '' and @ue_query != '')    
 Begin    
  Set @FilterText += ' AND ' + @ue_query    
 End    
    
 If(@ordstr = '')    
 Begin    
  set @ordstr = ' Enquiryid desc '    
 End    
    
 IF(@Pivot_Column IS NOT NULL)        
 BEGIN        
   SELECT @Query+=CAST(N';Select * From (SELECT ROW_NUMBER() OVER(ORDER BY ' + @ordstr + ') AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], count(*) OVER(ORDER BY [ParentID]) AS [rcnt], EnquiryId, PersonName, CompanyName, MobileNo3, 
   MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, 
   CreatedDate1, Createdby, Leads, Isopen, Img_ext, ROW_NUMBER() OVER(ORDER BY ' + @ordstr + ') AS RowNumber, ' + @Pivot_Column +     
  ' FROM (SELECT EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, 
SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, [fieldname] , fieldvalue     
  FROM (select E.Enquiryid, E.PersonName, E.CompanyName, E.MobileNo3, E.MobileNo1, E.MobileNo2, E.EmailID3, E.EmailID1, E.EmailID2, E.Residentialaddress, E.Officeaddress, E.User_login, E.MobileNo, E.EmailID, E.City, E.[State], E.Country, E.Countrycode, E.
Pincode, E.[ADDRESS], E.Initialremarks, E.SourceName, E.MediumName, E.CampaignName, E.Parentid, E.CreatedDate, E.CreatedDate1, E.Createdby, E.Leads, E.Isopen, E.Img_ext, y.fieldname, x.fieldvalue       
  From #temp2 E left join customfieldEnquiryvalue(nolock) x     
  ON E.Enquiryid = x.Enquiryid left join customfields(nolock) y     
  ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1        
  )q )Tab1        
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2        
  WHERE ' + @FilterText + ') T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) AS NVARCHAR(MAX));        
 END        
 ELSE        
 BEGIN        
   SET @Query += CAST(N';Select * From (select ROW_NUMBER() OVER(ORDER BY ' + @ordstr + ') AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], * from #temp2 where ' + @FilterText + ') T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) 
 
 + ' AND ' + CONVERT(VARCHAR(100), @enno) AS NVARCHAR(MAX));    
  END        
    
 --set @Query += cast(N' IF OBJECT_ID(''tempdb..#temp1'') IS NOT NULL    
 --begin    
 --select * into #MyEnq1 from #Temp2 x left join #temp1 y on x.Enquiryid=y.enq    
 --alter table #MyEnq1 drop column enq;    
 --select * from (select ROW_NUMBER() OVER(Order By Enquiryid desc) AS RowNumber1,@Rcnt AS rc1, * from #MyEnq1)aa where RowNumber between ' + @srno + ' and ' + @enno + '    
 --end    
 --else    
 --begin    
 --select * into #MyEnq2 from #Temp2    
 --select * from (select ROW_NUMBER() OVER(Order By Enquiryid desc) AS RowNumber1,@Rcnt AS rc1, * from #MyEnq2)aa where RowNumber between ' + @srno + ' and ' + @enno + ' end' as nvarchar(max))    
    
 print '@FinalQuery:- ' + cast(@Query as varchar(max))    
 EXEC sp_executesql @Query;    
    
 update kit19_executionlogger    
 set EndDatetime = getdate(), Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)    
 where ID = @LoggerID    
    
 update kit19_executionlogger    
 set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)    
 where ID = @LoggerID    
    
 --DROP TABLE IF EXISTS #TMPquery;    
 --DROP TABLE IF EXISTS #TMPquery1;    
 --DROP TABLE IF EXISTS #temp1;    
 DROP TABLE IF EXISTS #temp2;    
 --DROP TABLE IF EXISTS #temp3;    
 --DROP TABLE IF EXISTS #MyEnq1;    
 --DROP TABLE IF EXISTS #MyEnq2;    
    
END     


GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserEnquriyDetails_Changedss21_1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_ViewUserEnquriyDetails_Changedss21_1]
(
  @Txtsearch NVARCHAR(max) = ''  
 ,@Parentid BIGINT  
 ,@Userid INT = 0  
 ,@FilterText NVARCHAR(max) = ''  
 ,@ordstr NVARCHAR(Max) = ''  
 ,@srno NVARCHAR(100)  
 ,@enno NVARCHAR(100)  
 ,@ue_query NVARCHAR(max) = ''  
)
AS
BEGIN
--declare @Txtsearch NVARCHAR(max) = ''  
-- ,@Parentid BIGINT=32222  
-- ,@Userid INT = 32222  
-- ,@FilterText NVARCHAR(max) = ''  
-- ,@ordstr NVARCHAR(Max) = 'City desc'  
-- ,@srno NVARCHAR(100) =1 
-- ,@enno NVARCHAR(100)=20  
-- ,@ue_query NVARCHAR(max) = ''  
 -- (kept your logic; only the ORDER BY qualification parts are changed)
 DECLARE @TimeZoneName NVARCHAR(255) = isnull((
    SELECT TimeZone
    FROM User_Detail(NOLOCK)
    WHERE User_ID = @Userid
    ), 'india standard time')
 DECLARE @IsAdmin BIT = 0
 DECLARE @Str NVARCHAR(200) = @ordstr;--' personname desc '
 DECLARE @ColumnName NVARCHAR(200) = ''
 DECLARE @StrPredefinedOrderBy NVARCHAR(500) = ''
 DECLARE @StrCustomOrderBy NVARCHAR(500) = ''
 DECLARE @actUserId BIGINT = @Userid

 IF (rtrim(ltrim(@Str)) <> '')
 BEGIN
  SET @Str = ltrim(RTRIM(@Str))
  SELECT TOP 1 @ColumnName = value FROM string_split(@Str, ' ')

  IF (EXISTS(SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE table_name = 'UserEnquiry' AND column_name = rtrim(ltrim(@ColumnName))))
  BEGIN
   -- insert a placeholder '???' that we will replace with the appropriate table alias
   SET @StrPredefinedOrderBy = N' ' + REPLACE(@Str, @ColumnName, '???' + @ColumnName) + ' , '
   SET @StrCustomOrderBy = ''
  END
  ELSE
  BEGIN
   DECLARE @FullDataType NVARCHAR(200) = 'nvarchar(max)'

   SELECT TOP 1 @FullDataType = CASE
     WHEN ISNULL(datatype, 'v') = 'd' THEN 'date'
     WHEN ISNULL(datatype, 'v') = 'f' THEN 'bigint'
     WHEN ISNULL(datatype, 'v') = 'v' THEN 'nvarchar(max)'
     ELSE 'nvarchar(max)'
     END
   FROM customfields WITH (NOLOCK)
   WHERE ParentID = @Parentid
    AND fieldname = rtrim(ltrim(@ColumnName))

   DECLARE @CustomStrExp NVARCHAR(200) = ''

   IF(EXISTS(SELECT value FROM string_split(@Str, ' ')WHERE rtrim(ltrim(value)) = 'asc'))
   BEGIN
    SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  asc '
   END
   ELSE
   BEGIN
    SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  desc '
   END

   SET @StrPredefinedOrderBy = ''
   SET @StrCustomOrderBy = N' ' + @CustomStrExp + ' , '
  END
 END

 -- rest of your procedure logic follows unchanged, except we replace uses of @StrPredefinedOrderBy
 -- with context-aware replacements (Ue., T., A., or blank) when concatenating into the dynamic query.

 DROP TABLE IF EXISTS #temp1;
 DROP TABLE IF EXISTS #temp2;

 IF @srno = '' SET @srno = '1';
 IF @enno = '' SET @enno = '20';
 IF (@Txtsearch = '') SET @Txtsearch = N' (1=1) ';
 IF (@FilterText = '') SET @FilterText = N' (1=1) ';
 IF (@FilterText LIKE '%MobileNo3%') SET @FilterText = replace(@FilterText, 'MobileNo3', 'MobileNo')

 DECLARE @Query1 NVARCHAR(max) = ''
 DECLARE @Pivot_Column [nvarchar] (max);
 DECLARE @maxScore NUMERIC(18, 2) = isnull((
                SELECT (max(currentscore) * 100) / 99
                FROM enquiry_score_history(NOLOCK) e
                WHERE parentid = @ParentID
                ), 0)
 DECLARE @hot INT,@warm INT,@cold INT

 SELECT @hot = hot,@warm = warm,@cold = cold
 FROM enquiry_cateogy_thresholds(NOLOCK)
 WHERE parentid = @ParentID

 IF @hot IS NULL
 BEGIN
  SELECT @hot = hot,@warm = warm,@cold = cold
  FROM lead_cateogy_thresholds(NOLOCK)
  WHERE parentid = 0
 END

 SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME(fieldname)
 FROM (
  SELECT DISTINCT [fieldname]
  FROM customfields(NOLOCK)
  WHERE ParentID = @ParentID AND isActive = 1
 ) Tab

 DECLARE @NoCustomFields BIGINT, @filterCnt INT = 0
 SET @NoCustomFields = (
   SELECT count(DISTINCT [fieldname])
   FROM customfields
   WHERE [ParentID] = @ParentID AND [isActive] = 1
 )

 DECLARE @Query NVARCHAR(max) = ''
 DECLARE @TeamCode VARCHAR(10) = ''
 DECLARE @ScopeCode VARCHAR(10) = ''
 DECLARE @UserIdTeamLst VARCHAR(Max) = ''
 DECLARE @UserLoginTeamLst VARCHAR(Max) = ''
 DECLARE @tbluser TABLE (
  User_ID BIGINT
  ,Name VARCHAR(100)
  ,IMAGE VARCHAR(100)
 )

 SELECT @IsAdmin = isnull(IsAdmin, 0) FROM User_Detail(NOLOCK) WHERE User_ID = @UserID

 select @ScopeCode = ScopeCode from ufn_GetUserRoleScope(@UserId)
 if(@ScopeCode = 'GLOBAL') set @IsAdmin = 1

 IF (@IsAdmin = 1)
 BEGIN
  SET @UserID = 0
  INSERT INTO @tbluser
  EXEC Use_GetUserDetails @ParentId
 END
 ELSE
 BEGIN
  INSERT INTO @tbluser
  EXEC Use_GetUserDetails @UserID
 END

 SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '') FROM @tbluser

 PRINT '@UserIdTeamLst: ' + @UserIdTeamLst
 IF (@ordstr = '') SET @ordstr = ' CurrentScore desc'

 IF (@FilterText = ' (1=1) ' AND @Txtsearch = ' (1=1) ')
 BEGIN
  PRINT 'Branch A'

  -- When embedding @StrPredefinedOrderBy here we want the alias used inside the Ue (Userenquiry) select
  -- so replace '???' with 'Ue.' to avoid ambiguity
  SET @Query =
   N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname,rtrim(ltrim(A.MobileNo3)) as MobileNo3 , rtrim(ltrim(A.MobileNo1)) as MobileNo1 , rtrim(ltrim(A.MobileNo2)) as MobileNo2, A.EmailID3, A.EmailID1, A.EmailID2,A.Owner, A.Residentialaddress, A.Officeaddress,A.User_login,rtrim(ltrim(A.MobileNo)) as MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], A.Initialremarks, A.SourceName, A.MediumName, A.CampaignName, A.Parentid, A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,    '
   + ' isnull(A.img_ext,'''') as img_ext, A.WhereAddress, A.Tags, RowNumber1, rc1, A.IsduplicateEmail, A.IsduplicateMobile ,A.Stages,A.StagesId,A.CurrentScore,A.Profit_Loss,A.ThresholdColor        '
   + ' into #Temp2    FROM     (     '
   + ' SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno, ltrim(trim(isnull(Ue.Countrycode, ''''))+'' ''+trim(isnull(Ue.Mobileno, '''')))+ case when trim(isnull(Ue.Mobileno1,''''))<>'''' then '', ...'' else '''' end AS MobileNo3, trim(Ue.Mobileno1) as Mobileno1, trim( Ue.Mobileno2) as Mobileno2,Ue.Emailid,  Ue.Emailid AS EmailID3, Ue.Emailid1, Ue.Emailid2,est.StageName AS Stages,Ue.Owner, Ue.Residentialaddress, Ue.Officeaddress, Ud.User_login, Ue.CreatedDate , Ue.City, Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads, (CASE WHEN isnull(ue.isopen,1)=1 and isnull(ue.LeadNo,0) = 0 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress, isnull(tg.Tags, '''') Tags , '
   + ' ROW_NUMBER() OVER(ORDER BY ' + REPLACE(ISNULL(@StrPredefinedOrderBy, ''), '???', 'Ue.') + '   Ue.Enquiryid DESC) AS RowNumber1, count(*) OVER(ORDER BY Ue.Parentid) AS rc1, Ue.IsduplicateEmail, Ue.IsduplicateMobile,ue.StagesId,Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, '
   + ' CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) , ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int)>' + cast(@warm AS NVARCHAR(max)) + N' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) between ' + cast(@cold AS NVARCHAR(max)) + N' and ' + cast(@warm AS NVARCHAR(max)) + N' then ''Warm'' else ''Cold'' end          '
   + ' FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss '
   + ' ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums     '
   + ' ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs     '
   + ' ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud     '
   + ' ON Ue.Createdby = Ud.User_id LEFT JOIN tbl_enquiry_stage (NOLOCK) est '
   + ' ON Ue.StagesId = est.StageID '
   + ' left join enquiry_score_history_latest(nolock) LS ON Ue.EnquiryID=LS.enquiryid '
   + ' and Ue.Parentid = Ud.ParentID LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''enquiry'' and tm.ParentID = ' + Convert(VARCHAR(100), @ParentID) + ' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = Ue.EnquiryId    '
   + ' WHERE Ue.Parentid = ' + Convert(VARCHAR(100), @Parentid)

  IF @Userid > 0
  BEGIN
   SET @Query += N' AND ' + CASE WHEN isnull(@UserIdTeamLst, '') != '' THEN ' ue.CreatedBy in (' + isnull(@UserIdTeamLst, '') + ') ' WHEN isnull(@Userid, 0) = 0 THEN ' ue.CreatedBy = ue.CreatedBy ' ELSE ' ue.CreatedBy = ' + Convert(VARCHAR(100), @Userid) END
  END

  SET @Query += N' ) A Where A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno)
 END
 ELSE
 BEGIN
  PRINT 'Branch B'

  -- In Branch B outer ROW_NUMBER() is applied to alias T; use 'T.' for the predefined order expression
  SET @Query += N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname, rtrim(ltrim(A.MobileNo3)) as MobileNo3 , rtrim(ltrim(A.MobileNo1)) as MobileNo1 ,rtrim(ltrim(A.MobileNo2)) as MobileNo2, A.EmailID3, A.EmailID1, A.EmailID2 
 ,A.Owner, A.Residentialaddress, A.Officeaddress,A.User_login,A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], A.Initialremarks, A.SourceName, A.MediumName, A.CampaignName, A.Parentid,A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,    '
   + ' isnull(A.img_ext,'''') as img_ext, A.WhereAddress, A.Tags, RowNumber1, rc1, A.IsduplicateEmail, A.IsduplicateMobile,A.Stages,A.StagesId,A.Profit_Loss,A.CurrentScore, A.ThresholdColor       
   into #Temp2    
   FROM     
   (     
  Select *, ROW_NUMBER() OVER(ORDER BY ' + REPLACE(ISNULL(@StrPredefinedOrderBy, ''), '???', 'T.') + N' T.Enquiryid DESC) AS RowNumber1, count(*) OVER(ORDER BY T.Parentid) AS rc1      
  From     
  (    
   SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,trim(Ue.Mobileno) as Mobileno,ltrim(trim(isnull(Ue.Countrycode, ''''))+'' ''+trim(isnull(Ue.Mobileno, '''')))+ case when trim(isnull(Ue.Mobileno1,''''))<>'''' then '', ...'' else '''' end AS MobileNo3, trim(Ue.Mobileno1) as Mobileno1, trim(Ue.Mobileno2) as Mobileno2,Ue.Emailid, Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2
,ue.Owner,Ue.Residentialaddress,Ue.Officeaddress, Ud.User_login,Ue.CreatedDate , Ue.City, Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads, (CASE
 WHEN isnull(ue.isopen,1)=1 and isnull(ue.LeadNo,0) = 0 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress, isnull(tg.Tags, '''') Tags ,Ue.IsduplicateEmail,ue.IsduplicateMobile,est.StageName as Stages,ue.StagesId,
 Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end,
 CurrentScore=cast(isnull((LS.currentscore/nullif('+ cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int), 
    ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int)>' + 
    cast(@warm AS NVARCHAR(max)) + N' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) 
    between ' + cast(@cold AS NVARCHAR(max)) + N'  and ' + cast(@warm AS NVARCHAR(max)) + N' then ''Warm'' else ''Cold'' end   
   FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss     
   ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums     
   ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs     
   ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud     
    
   ON Ue.Createdby = Ud.User_id LEFT JOIN tbl_enquiry_stage (NOLOCK) est
  ON Ue.StagesId = est.StageID
  left join enquiry_score_history_latest(nolock) LS ON Ue.EnquiryID=LS.enquiryid
   and Ue.Parentid = Ud.ParentID LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''enquiry'' and tm.ParentID = '   
   + Convert(VARCHAR(100), @ParentID) + ' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = Ue.EnquiryId  
   WHERE Ue.Parentid = ' + Convert(VARCHAR(100), @ParentID)

  IF @Userid > 0    
  BEGIN    
   SET @Query += N' AND ' + CASE     WHEN isnull(@UserIdTeamLst, '') != ''    THEN ' ue.CreatedBy in (' + isnull(@UserIdTeamLst, '') + ') '    WHEN isnull(@Userid, 0) = 0    THEN ' ue.CreatedBy = ue.CreatedBy '    ELSE ' ue.CreatedBy = ' + Convert(VARCHAR(100), @Userid)    END    
  END    
    
  SET @Query += N' ) T Where ' + @FilterText + N' ) A Where ' + CASE     WHEN @Txtsearch = ' (1=1) '    THEN ' A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno)    ELSE ' (1=1) '    END    
 END    

 IF (@ue_query = '')    
 BEGIN    
  SET @ue_query = ' (1=1) '    
 END    

 IF (@FilterText != '' AND @ue_query != '')    
 BEGIN    
  SET @FilterText += ' AND ' + @ue_query    
 END    

 IF (@ordstr = '')    
 BEGIN    
  SET @ordstr = ' Enquiryid desc '    
 END    

 IF (@Pivot_Column IS NOT NULL)    
 BEGIN    
  PRINT 'Branch C'    

  IF (@Txtsearch = ' (1=1) ') -- From Branch A      
  BEGIN    
   PRINT 'Branch CA'    

   -- Here the pivot result uses top-level columns, so remove the placeholder (no alias prefix)
   SET @Query += CAST(N';Select * From 
   (
   SELECT  rc1 AS [rcnt], EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, 
   Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, 
   CampaignName, Parentid, dbo.fn_ConvertDateTime(cast(CreatedDate as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as CreatedDate,   
   dbo.fn_ConvertDateTime(cast(CreatedDate1 as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as  CreatedDate1, Createdby, Leads, 
   Isopen, Img_ext, ROW_NUMBER() OVER(ORDER BY ' + REPLACE(ISNULL(@StrPredefinedOrderBy, ''), '???', '') + N' ' + @StrCustomOrderBy + '  EnquiryId Desc) + 
   cast( ' + cast(@srno - 1 AS NVARCHAR) + ' as int) ' + '  AS [RowNumber1], WhereAddress, rc1, IsduplicateEmail, IsduplicateMobile , 
   Stages,StagesId, Owner,Profit_Loss,CurrentScore,ThresholdColor, ' + @Pivot_Column +   N' FROM 
   
   (SELECT EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, 
   MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate,
   CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress, [fieldname], fieldvalue, RowNumber1, rc1, IsduplicateEmail, IsduplicateMobile ,Stages,
   StagesId, Owner,Profit_Loss,CurrentScore,ThresholdColor         
  FROM (
  select E.Enquiryid, E.PersonName, E.CompanyName, E.MobileNo3, E.MobileNo1, E.MobileNo2, E.EmailID3, E.EmailID1, E.EmailID2, E.Residentialaddress, 
  E.Officeaddress, E.User_login, E.MobileNo, E.EmailID,E.Stages,E.StagesId,E.Owner, E.City, E.[State], E.Country, E.Countrycode, E.Pincode, E.[ADDRESS],
  E.Initialremarks, E.SourceName, E.MediumName, E.CampaignName, E.Parentid, E.CreatedDate, E.CreatedDate1, E.Createdby, E.Leads, E.Isopen, E.Img_ext,
  E.WhereAddress, y.fieldname, x.fieldvalue ,E.RowNumber1, E.rc1, E.IsduplicateEmail, E.IsduplicateMobile,E.Profit_Loss,E.CurrentScore,E.ThresholdColor          
  From #temp2 E left join customfieldEnquiryvalue(nolock) x       
  ON E.Enquiryid = x.Enquiryid left join customfields(nolock) y       
  ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1  )q )Tab1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ') ) AS Tab2      
  WHERE ' + @Txtsearch + '  ) T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));    
  END    
  ELSE    
  BEGIN    
   PRINT 'Branch CB'    

   SELECT @filterCnt = count(*)    
   FROM dbo.fn_Split(@Txtsearch, ' ) ')

  SELECT @Query += CAST(N'; select * into #Temp1 From (select [x].EnquiryId, [y].[fieldname],   
 [x].[fieldvalue] from customfieldEnquiryvalue(nolock) x inner join customfields(nolock) y  
 ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) T1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @Txtsearch AS NVARCHAR(MAX));  
  
   SET @Query += CAST(N';Select * From (SELECT ROW_NUMBER() OVER(ORDER BY ' + REPLACE(ISNULL(@StrPredefinedOrderBy, ''), '???', 'A.') + N' ' + @StrCustomOrderBy + '  A.EnquiryId Desc) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], count(*) OVER(ORDER BY [ParentID]) AS [rcnt],
   A.EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo,
   EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, 
 MediumName, CampaignName, Parentid,Stages,StagesId,CurrentScore,Profit_Loss, ThresholdColor, dbo.fn_ConvertDateTime(cast(CreatedDate as datetime), ''' + 
 cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as CreatedDate,      dbo.fn_ConvertDateTime(cast(CreatedDate1 as datetime), ''' + 
 cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as  CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress, ' + @Pivot_Column +     
     N' From #Temp1 A inner join #temp2 E       
  ON A.EnquiryId = E.Enquiryid  ) T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) AS NVARCHAR(MAX)) + N' ORDER BY ' + @ordstr;    
  END    
 END    
 ELSE    
 BEGIN    
  PRINT 'Branch D'    

  SET @Query += CAST(N'; select distinct Enquiryid, Personname, Companyname, MobileNo3, MobileNo1, MobileNo2, EmailID3,EmailID1,EmailID2,
  Residentialaddress,Officeaddress,User_login,MobileNo,EmailID,City,[State], Country,Countrycode,Pincode,[ADDRESS], Initialremarks,  SourceName, 
  MediumName, CampaignName,Parentid,dbo.fn_ConvertDateTime(cast(CreatedDate as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as 
  CreatedDate, dbo.fn_ConvertDateTime(cast(CreatedDate1 as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as  CreatedDate1,
  Createdby,Leads,Isopen, isnull(img_ext,'''') as img_ext, WhereAddress, Tags, RowNumber1, rc1, IsduplicateEmail, IsduplicateMobile ,Stages, StagesId,
  Owner, Profit_Loss,CurrentScore,ThresholdColor 
  from #temp2 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));    
 END    

 PRINT '@FinalQuery:- ' + cast(@Query AS VARCHAR(max))    

 EXEC sp_executesql @Query;    

 DROP TABLE IF EXISTS #temp1;    
 DROP TABLE IF EXISTS #temp2;    

 EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @actUserId    
   ,@Activity_type = 'view_enqry'    
   ,@ActionType = 'S'    
   ,@RowJson = ''    
   ,@Table_name = 'UserEnquiry'
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserEnquriyDetails_Changedss21_1$]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_ViewUserEnquriyDetails_Changedss21_1$] 
(  
  @Txtsearch NVARCHAR(max) = ''  
 ,@Parentid BIGINT  
 ,@Userid INT = 0  
 ,@FilterText NVARCHAR(max) = ''  
 ,@ordstr NVARCHAR(Max) = ''  
 ,@srno NVARCHAR(100)  
 ,@enno NVARCHAR(100)  
 ,@ue_query NVARCHAR(max) = ''  
 )  
AS  
BEGIN  
 DECLARE @TimeZoneName NVARCHAR(255) = isnull((  
    SELECT TimeZone  
    FROM User_Detail(NOLOCK)  
    WHERE User_ID = @Userid  
    ), 'india standard time')  
 DECLARE @IsAdmin BIT = 0  
 DECLARE @Str NVARCHAR(200) = @ordstr;--' personname desc '  
 DECLARE @ColumnName NVARCHAR(200) = ''  
 DECLARE @StrPredefinedOrderBy NVARCHAR(500) = ''  
 DECLARE @StrCustomOrderBy NVARCHAR(500) = ''  
 DECLARE @actUserId BIGINT = @Userid  
  
 IF (rtrim(ltrim(@Str)) <> '')  
 BEGIN  
  SET @Str = ltrim(RTRIM(@Str))  
  
  --select @Str  
  SELECT TOP 1 @ColumnName = value  
  FROM string_split(@Str, ' ')  
  
  --select @ColumnName   
  IF (EXISTS(SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE table_name = 'UserEnquiry' AND column_name = rtrim(ltrim(@ColumnName))))  
  BEGIN  
   --set @StrPredefinedOrderBy = N' order by ' +  @Str;  
   SET @StrPredefinedOrderBy = N' ' + @Str + ' , ';  
   SET @StrCustomOrderBy = '';  
  END  
  ELSE  
  BEGIN  
   DECLARE @FullDataType NVARCHAR(200) = 'nvarchar(max)'  
  
   SELECT TOP 1 @FullDataType = CASE   
     WHEN ISNULL(datatype, 'v') = 'd'  
      THEN 'date'  
     WHEN ISNULL(datatype, 'v') = 'f'  
      THEN 'bigint'  
     WHEN ISNULL(datatype, 'v') = 'v'  
      THEN 'nvarchar(max)'  
     ELSE 'nvarchar(max)'  
     END  
   FROM customfields WITH (NOLOCK)  
   WHERE ParentID = @Parentid  
    AND fieldname = rtrim(ltrim(@ColumnName))  
  
   DECLARE @CustomStrExp NVARCHAR(200) = '';  
  
   IF(EXISTS(SELECT value FROM string_split(@Str, ' ')WHERE rtrim(ltrim(value)) = 'asc'))  
   BEGIN  
    SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  asc '  
   END  
   ELSE  
   BEGIN  
    SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  desc '  
   END  
  
   SET @StrPredefinedOrderBy = ''  
   --set @StrCustomOrderBy = N' order by ' +  @Str;    
   SET @StrCustomOrderBy = N' ' + @CustomStrExp + ' , ';  
  END  
    --select @StrPredefinedOrderBy  
    --select @StrCustomOrderBy  
 END  
  
 --select @StrCustomOrderBy  
 -- declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=32222,@Userid INT=0,@FilterText nvarchar(max)=N'',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N''  -- AC    
 -- declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=32222,@Userid INT=0,@FilterText nvarchar(max)=N' (Personname like ''%test%'') ',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N'' -- BCA    
 -- declare @Txtsearch NVARCHAR(max)=N'( fieldname=''test02'' and cast(fieldvalue as varchar(50)) like  ''%2%'' )  or  ( fieldname=''test03'' and cast(fieldvalue as varchar(50)) like  ''%3%'' ) ',@Parentid BIGINT=32222,@Userid INT=0,@FilterText nvarchar(max)=N' (Personname like ''%test%'') ',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N'' -- BCB    
 -- declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=38750,@Userid INT=0,@FilterText nvarchar(max)=N'',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N''  -- AD    
 --declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=38750,@Userid INT=0,@FilterText nvarchar(max)=N' (Personname like ''%test%'') ',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N'' -- BD    
 
 -- DECLARE @Parameterlist NVARCHAR(max),@LoggerID BIGINT  
 -- SET @Parameterlist = 'txtSearch : ' + @txtSearch + ' ,ParentID : ' + CONVERT(VARCHAR(100), @ParentID) + ' ,Userid : ' + CONVERT(VARCHAR(100), @Userid) + ' ,FilterText : ' + @FilterText + ' ,ordstr : ' + @ordstr + ' ,srno : ' + @srno + ' ,enno : ' + @enno + ' ,ue_query : ' + @ue_query;  
  
 --INSERT INTO kit19_executionlogger(ObjectName,Parameterlist,StartDatetime,EndDatetime,Remarks)  
 --VALUES('Usp_ViewUserEnquriyDetails_Changedss21',@Parameterlist,getdate(),'','')  
  
 --SET @LoggerID = Scope_Identity();  
  
  DROP TABLE IF EXISTS #temp1;
  DROP TABLE IF EXISTS #temp2;

  IF @srno = ''  
  BEGIN  
   SET @srno = '1';  
  END  
  
  IF @enno = ''  
  BEGIN  
   SET @enno = '20';  
  END  
  
  IF (@Txtsearch = '')  
  BEGIN  
   SET @Txtsearch = N' (1=1) ';  
  END;  
  
  IF (@FilterText = '')  
  BEGIN  
   SET @FilterText = N' (1=1) ';  
  END;  
  
  IF (@FilterText LIKE '%MobileNo3%')  
  BEGIN  
   SET @FilterText = replace(@FilterText, 'MobileNo3', 'MobileNo')  
  END  
  
  DECLARE @Query1 NVARCHAR(max) = ''  
  DECLARE @Pivot_Column [nvarchar] (max);  
  DECLARE @maxScore NUMERIC(18, 2) = isnull((
				SELECT (max(currentscore) * 100) / 99
				FROM enquiry_score_history(NOLOCK) e
				WHERE parentid = @ParentID
				), 0)
	DECLARE @hot INT,@warm INT,@cold INT

	SELECT @hot = hot,@warm = warm,@cold = cold
	FROM enquiry_cateogy_thresholds(NOLOCK)
	WHERE parentid = @ParentID

	IF @hot IS NULL
	BEGIN
		SELECT @hot = hot,@warm = warm,@cold = cold
		FROM lead_cateogy_thresholds(NOLOCK)
		WHERE parentid = 0
	END



 /*Select Pivot Column*/  
  SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME(fieldname)  
  FROM 
  (  
	SELECT DISTINCT [fieldname]  
	FROM customfields(NOLOCK)  
	WHERE ParentID = @ParentID AND isActive = 1  
  ) Tab  
  
 DECLARE @NoCustomFields BIGINT, @filterCnt INT = 0  
  
 SET @NoCustomFields = (  
   SELECT count(DISTINCT [fieldname])  
   FROM customfields  
   WHERE [ParentID] = @ParentID AND [isActive] = 1  
   )  
  
 DECLARE @Query NVARCHAR(max) = ''  
 DECLARE @TeamCode VARCHAR(10) = ''  
 DECLARE @ScopeCode VARCHAR(10) = ''  
 DECLARE @UserIdTeamLst VARCHAR(Max) = ''  
 DECLARE @UserLoginTeamLst VARCHAR(Max) = ''  
 --select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@UserId)  
 DECLARE @tbluser TABLE (  
  User_ID BIGINT  
  ,Name VARCHAR(100)  
  ,IMAGE VARCHAR(100)  
  )  
  
 SELECT @IsAdmin = isnull(IsAdmin, 0)  
 FROM User_Detail(NOLOCK)  
 WHERE User_ID = @UserID  
  
select @ScopeCode = ScopeCode    
     from ufn_GetUserRoleScope(@UserId) 

	 if(@ScopeCode = 'GLOBAL')
	   begin
	       set @IsAdmin = 1 
	   end
 IF (@IsAdmin = 1)  
 BEGIN  
  SET @UserID = 0  
  
  INSERT INTO @tbluser  
  EXEC Use_GetUserDetails @ParentId  
 END  
 ELSE  
 BEGIN  
  INSERT INTO @tbluser  
  EXEC Use_GetUserDetails @UserID  
 END  
  
 SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')  
 FROM @tbluser  
  
 PRINT '@UserIdTeamLst: ' + @UserIdTeamLst  
  IF (@ordstr = '')
	BEGIN
		
		SET @ordstr = ' CurrentScore desc'
	END
 IF (@FilterText = ' (1=1) ' AND @Txtsearch = ' (1=1) ')  
 BEGIN  
  PRINT 'Branch A'  
  
  SET @Query =   
   N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname,rtrim(ltrim(A.MobileNo3)) as MobileNo3 , rtrim(ltrim(A.MobileNo1)) as MobileNo1 , rtrim(ltrim(A.MobileNo2)) as MobileNo2, A.EmailID3, A.EmailID1, A.EmailID2,A.Owner, A.Residentialaddress, A.Officeaddress,A.User_login,rtrim(ltrim(A.MobileNo)) as MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], A.Initialremarks, A.SourceName, A.MediumName, A.CampaignName, A.Parentid, A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,    
   isnull(A.img_ext,'''') as img_ext, A.WhereAddress, A.Tags, RowNumber1, rc1, A.IsduplicateEmail, A.IsduplicateMobile ,A.Stages,A.StagesId,A.CurrentScore,A.Profit_Loss,A.ThresholdColor        
   into #Temp2    
   FROM     
   (     
  SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno, ltrim(trim(isnull(Ue.Countrycode, ''''))+'' ''+trim(isnull(Ue.Mobileno, '''')))+ case when trim(isnull(Ue.Mobileno1,''''))<>'''' then '', ...'' else '''' end AS MobileNo3, trim(Ue.Mobileno1) as Mobileno1, trim( Ue.Mobileno2) as Mobileno2,Ue.Emailid,  Ue.Emailid AS EmailID3, Ue.Emailid1, Ue.Emailid2,est.StageName AS Stages,Ue.Owner, Ue.Residentialaddress, Ue.Officeaddress, Ud.User_login, Ue.CreatedDate , Ue.City, Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads, (CASE WHEN isnull(ue.isopen,1)=1 and isnull(ue.LeadNo,0) = 0 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress, isnull(tg.Tags, '''') Tags , ROW_NUMBER() OVER(ORDER BY '   
   + @StrPredefinedOrderBy + '   Ue.Enquiryid DESC) AS RowNumber1, count(*) OVER(ORDER BY Ue.Parentid) AS rc1, Ue.IsduplicateEmail, Ue.IsduplicateMobile,ue.StagesId,Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end,
   CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) , ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int)>' + cast(@warm AS NVARCHAR(max)) + N' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) between ' + cast(@cold AS NVARCHAR(max)) + N' and ' + cast(@warm AS NVARCHAR(max)) + N' then ''Warm'' else ''Cold'' end          
  FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss
  
  ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums     
  ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs     
  ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud     
  ON Ue.Createdby = Ud.User_id LEFT JOIN tbl_enquiry_stage (NOLOCK) est
  ON Ue.StagesId = est.StageID
  left join enquiry_score_history_latest(nolock) LS ON Ue.EnquiryID=LS.enquiryid
  
  and Ue.Parentid = Ud.ParentID LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''enquiry'' and tm.ParentID = ' + Convert(VARCHAR(100), @ParentID) + ' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = Ue.EnquiryId    
  WHERE Ue.Parentid = ' + Convert(VARCHAR(100), @Parentid)  
  
  --CASE WHEN @Userid = 0 THEN N' = UL.AssignedTo '   
  --WHEN @Userid > 0 and isnull(@TeamCode,'') != '' THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'   
  --ELSE ' = ' + CAST(@Userid AS NVARCHAR(MAX)) End + '  
  IF @Userid > 0  
  BEGIN  
   SET @Query += N' AND ' + CASE --When isnull(@Userid,0) > 0 and isnull(@TeamCode,'') != '' then  ' ue.CreatedBy in ('+ isnull(@UserIdTeamLst, '') + ') '  
     WHEN isnull(@UserIdTeamLst, '') != ''  
      THEN ' ue.CreatedBy in (' + isnull(@UserIdTeamLst, '') + ') '  
     WHEN isnull(@Userid, 0) = 0  
      THEN ' ue.CreatedBy = ue.CreatedBy '  
     ELSE ' ue.CreatedBy = ' + Convert(VARCHAR(100), @Userid)  
     END  
  END  
  
  SET @Query += N' ) A Where A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno)  
 END  
 ELSE  
 BEGIN  
  PRINT 'Branch B'  
  
  SET @Query += N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname, rtrim(ltrim(A.MobileNo3)) as MobileNo3 , rtrim(ltrim(A.MobileNo1)) as MobileNo1 ,rtrim(ltrim(A.MobileNo2)) as MobileNo2, A.EmailID3, A.EmailID1, A.EmailID2 
,A.Owner, A.Residentialaddress, A.Officeaddress,A.User_login,A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], A.Initialremarks, A.SourceName, A.MediumName, A.CampaignName, A.Parentid,A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,    
   isnull(A.img_ext,'''') as img_ext, A.WhereAddress, A.Tags, RowNumber1, rc1, A.IsduplicateEmail, A.IsduplicateMobile,A.Stages,A.StagesId,A.Profit_Loss,A.CurrentScore, A.ThresholdColor       
   into #Temp2    
   FROM     
   (     
  Select *, ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy +   
   ' T.Enquiryid DESC) AS RowNumber1, count(*) OVER(ORDER BY T.Parentid) AS rc1      
  From     
  (    
   SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,trim(Ue.Mobileno) as Mobileno,ltrim(trim(isnull(Ue.Countrycode, ''''))+'' ''+trim(isnull(Ue.Mobileno, '''')))+ case when trim(isnull(Ue.Mobileno1,''''))<>'''' then '', ...'' else '''' end AS MobileNo3, trim(Ue.Mobileno1) as Mobileno1, trim(Ue.Mobileno2) as Mobileno2,Ue.Emailid, Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2
,ue.Owner,Ue.Residentialaddress,Ue.Officeaddress, Ud.User_login,Ue.CreatedDate , Ue.City, Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads, (CASE
 WHEN isnull(ue.isopen,1)=1 and isnull(ue.LeadNo,0) = 0 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress, isnull(tg.Tags, '''') Tags ,Ue.IsduplicateEmail,ue.IsduplicateMobile,est.StageName as Stages,ue.StagesId,
 Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end,
 CurrentScore=cast(isnull((LS.currentscore/nullif('+ cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int), 
	ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int)>' + 
	cast(@warm AS NVARCHAR(max)) + N' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) 
	between ' + cast(@cold AS NVARCHAR(max)) + N'  and ' + cast(@warm AS NVARCHAR(max)) + N' then ''Warm'' else ''Cold'' end   
   FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss     
   ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums     
   ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs     
   ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud     
    
   ON Ue.Createdby = Ud.User_id LEFT JOIN tbl_enquiry_stage (NOLOCK) est
  ON Ue.StagesId = est.StageID
  left join enquiry_score_history_latest(nolock) LS ON Ue.EnquiryID=LS.enquiryid
   and Ue.Parentid = Ud.ParentID LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''enquiry'' and tm.ParentID = '   
   + Convert(VARCHAR(100), @ParentID) + ' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = Ue.EnquiryId  
   WHERE Ue.Parentid = ' + Convert(VARCHAR(100), @ParentID)  
  
  IF @Userid > 0    
  BEGIN    
   --When isnull(@Userid,0) > 0 and isnull(@TeamCode,'') != '' then  ' ue.CreatedBy in ('+ isnull(@UserIdTeamLst, '') + ') '    
   SET @Query += N' AND ' + CASE     
     WHEN isnull(@UserIdTeamLst, '') != ''    
      THEN ' ue.CreatedBy in (' + isnull(@UserIdTeamLst, '') + ') '    
     WHEN isnull(@Userid, 0) = 0    
      THEN ' ue.CreatedBy = ue.CreatedBy '    
     ELSE ' ue.CreatedBy = ' + Convert(VARCHAR(100), @Userid)    
     END    
  END    
    
  SET @Query += N' ) T Where ' + @FilterText + N' ) A Where ' + CASE     
    WHEN @Txtsearch = ' (1=1) '    
     THEN ' A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno)    
    ELSE ' (1=1) '    
    END    
 END    
    
 IF (@ue_query = '')    
 BEGIN    
  SET @ue_query = ' (1=1) '    
 END    
    
 IF (@FilterText != '' AND @ue_query != '')    
 BEGIN    
  SET @FilterText += ' AND ' + @ue_query    
 END    
    
 IF (@ordstr = '')    
 BEGIN    
  SET @ordstr = ' Enquiryid desc '    
 END    
  
 IF (@Pivot_Column IS NOT NULL)    
 BEGIN    
  PRINT 'Branch C'    
    
  IF (@Txtsearch = ' (1=1) ') -- From Branch A      
  BEGIN    
   PRINT 'Branch CA'    
    
   SET @Query += CAST(N';Select * From 
   (
   SELECT  rc1 AS [rcnt], EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, 
   Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, 
   CampaignName, Parentid, dbo.fn_ConvertDateTime(cast(CreatedDate as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as CreatedDate,   
   dbo.fn_ConvertDateTime(cast(CreatedDate1 as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as  CreatedDate1, Createdby, Leads, 
   Isopen, Img_ext, ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + '  EnquiryId Desc) + 
   cast( ' + cast(@srno - 1 AS NVARCHAR) + ' as int) ' + '  AS [RowNumber1], WhereAddress, rc1, IsduplicateEmail, IsduplicateMobile , 
   Stages,StagesId, Owner,Profit_Loss,CurrentScore,ThresholdColor, ' + @Pivot_Column +   N' FROM 
   
   (SELECT EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, 
   MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate,
   CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress, [fieldname], fieldvalue, RowNumber1, rc1, IsduplicateEmail, IsduplicateMobile ,Stages,
   StagesId, Owner,Profit_Loss,CurrentScore,ThresholdColor         
  FROM (
  select E.Enquiryid, E.PersonName, E.CompanyName, E.MobileNo3, E.MobileNo1, E.MobileNo2, E.EmailID3, E.EmailID1, E.EmailID2, E.Residentialaddress, 
  E.Officeaddress, E.User_login, E.MobileNo, E.EmailID,E.Stages,E.StagesId,E.Owner, E.City, E.[State], E.Country, E.Countrycode, E.Pincode, E.[ADDRESS],
  E.Initialremarks, E.SourceName, E.MediumName, E.CampaignName, E.Parentid, E.CreatedDate, E.CreatedDate1, E.Createdby, E.Leads, E.Isopen, E.Img_ext,
  E.WhereAddress, y.fieldname, x.fieldvalue ,E.RowNumber1, E.rc1, E.IsduplicateEmail, E.IsduplicateMobile,E.Profit_Loss,E.CurrentScore,E.ThresholdColor          
  From #temp2 E left join customfieldEnquiryvalue(nolock) x       
  ON E.Enquiryid = x.Enquiryid left join customfields(nolock) y       
  ON x.fieldID=y.field_ID AND y.[ParentID] = '     
     + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1  )q )Tab1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ') ) AS Tab2      
  WHERE ' + @Txtsearch + '  ) T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));    
  END    
  ELSE    
  BEGIN    
   PRINT 'Branch CB'    
    
   SELECT @filterCnt = count(*)    
   FROM dbo.fn_Split(@Txtsearch, ' ) ')    
    
  SELECT @Query += CAST(N'; select * into #Temp1 From (select [x].EnquiryId, [y].[fieldname],   
 [x].[fieldvalue] from customfieldEnquiryvalue(nolock) x inner join customfields(nolock) y  
 ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) T1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @Txtsearch AS NVARCHAR(MAX));  
  
   SET @Query += CAST(N';Select * From (SELECT ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + '  A.EnquiryId Desc) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], count(*) OVER(ORDER BY [ParentID]) AS [rcnt],
   A.EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo,
   EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, 
MediumName, CampaignName, Parentid,Stages,StagesId,CurrentScore,Profit_Loss, ThresholdColor, dbo.fn_ConvertDateTime(cast(CreatedDate as datetime), ''' + 
cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as CreatedDate,      dbo.fn_ConvertDateTime(cast(CreatedDate1 as datetime), ''' + 
cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as  CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress, ' + @Pivot_Column +     
     N' From #Temp1 A inner join #temp2 E       
  ON A.EnquiryId = E.Enquiryid  ) T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) AS NVARCHAR(MAX)) + N' ORDER BY ' + @ordstr;    
  END    
 END    
 ELSE    
 BEGIN    
  PRINT 'Branch D'    
    
  SET @Query += CAST(N'; select distinct Enquiryid, Personname, Companyname, MobileNo3, MobileNo1, MobileNo2, EmailID3,EmailID1,EmailID2,
  Residentialaddress,Officeaddress,User_login,MobileNo,EmailID,City,[State], Country,Countrycode,Pincode,[ADDRESS], Initialremarks,  SourceName, 
  MediumName, CampaignName,Parentid,dbo.fn_ConvertDateTime(cast(CreatedDate as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as 
  CreatedDate, dbo.fn_ConvertDateTime(cast(CreatedDate1 as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as  CreatedDate1,
  Createdby,Leads,Isopen, isnull(img_ext,'''') as img_ext, WhereAddress, Tags, RowNumber1, rc1, IsduplicateEmail, IsduplicateMobile ,Stages, StagesId,
  Owner, Profit_Loss,CurrentScore,ThresholdColor 
  from #temp2 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));    
 END    
    
 PRINT '@FinalQuery:- ' + cast(@Query AS VARCHAR(max))    
    
 EXEC sp_executesql @Query;    
    
 --UPDATE kit19_executionlogger    
 --SET EndDatetime = getdate()    
 -- ,Remarks = 'No. of Custom Fields : ' + Convert(NVARCHAR(100), @NoCustomFields)    
 --WHERE ID = @LoggerID    
    
 --UPDATE kit19_executionlogger    
 --SET TimeInSeconds = CAST(Datediff(ms, StartDatetime, EndDatetime) AS FLOAT) / CAST(1000 AS FLOAT)    
 --WHERE ID = @LoggerID    
    
  DROP TABLE IF EXISTS #temp1;    
  DROP TABLE IF EXISTS #temp2;    
  
  EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @actUserId    
   ,@Activity_type = 'view_enqry'    
   ,@ActionType = 'S'    
   ,@RowJson = ''    
   ,@Table_name = 'UserEnquiry'  
     
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserEnquriyDetails_Changedss21_1_FORV3]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Replicated Stored Procedure: Usp_ViewUserEnquriyDetails_Changedss21_1_FORV3
-- Optimized for V3 and including the fix for SQL Error 4145 (Non-boolean expression in WHERE clause)

CREATE   PROCEDURE [dbo].[Usp_ViewUserEnquriyDetails_Changedss21_1_FORV3]
(
  @Txtsearch NVARCHAR(max) = ''  
, @Parentid BIGINT  
, @Userid INT = 0  
, @FilterText NVARCHAR(max) = ''  
, @ordstr NVARCHAR(Max) = ''  
, @srno NVARCHAR(100)  
, @enno NVARCHAR(100)  
, @ue_query NVARCHAR(max) = ''  
)
AS
BEGIN
SET NOCOUNT ON;

-- Safety: Use local variables to ensure trimmed, non-null values for dynamic SQL
DECLARE @LocalTxtsearch NVARCHAR(max) = LTRIM(RTRIM(ISNULL(@Txtsearch, '')))
DECLARE @LocalFilterText NVARCHAR(max) = LTRIM(RTRIM(ISNULL(@FilterText, '')))
DECLARE @LocalUeQuery NVARCHAR(max) = LTRIM(RTRIM(ISNULL(@ue_query, '')))

-- CRITICAL FIX: Ensure default conditions (1=1) if empty to prevent SQL Error 4145
IF (@LocalTxtsearch = '' OR @LocalTxtsearch = '(1=1)') SET @LocalTxtsearch = N' (1=1) '
IF (@LocalFilterText = '' OR @LocalFilterText = '(1=1)') SET @LocalFilterText = N' (1=1) '
IF (@LocalUeQuery = '' OR @LocalUeQuery = '(1=1)') SET @LocalUeQuery = N' (1=1) '

-- Fix for specific column name mapping if present in filter string
IF (@LocalFilterText LIKE '%MobileNo3%') SET @LocalFilterText = REPLACE(@LocalFilterText, 'MobileNo3', 'MobileNo')

DECLARE @TimeZoneName NVARCHAR(255) = isnull((
    SELECT TimeZone
    FROM User_Detail(NOLOCK)
    WHERE User_ID = @Userid
    ), 'india standard time')
DECLARE @IsAdmin BIT = 0
DECLARE @Str NVARCHAR(200) = @ordstr;
DECLARE @ColumnName NVARCHAR(200) = ''
DECLARE @StrPredefinedOrderBy NVARCHAR(500) = ''
DECLARE @StrCustomOrderBy NVARCHAR(500) = ''
DECLARE @actUserId BIGINT = @Userid
 
IF (rtrim(ltrim(@Str)) <> '')
BEGIN
  SET @Str = ltrim(RTRIM(@Str))
  SELECT TOP 1 @ColumnName = value FROM string_split(@Str, ' ')
 
  IF (EXISTS(SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE table_name = 'UserEnquiry' AND column_name = rtrim(ltrim(@ColumnName))))
  BEGIN
   SET @StrPredefinedOrderBy = N' ' + REPLACE(@Str, @ColumnName, '???' + @ColumnName) + ' , '
   SET @StrCustomOrderBy = ''
  END
  ELSE
  BEGIN
   DECLARE @FullDataType NVARCHAR(200) = 'nvarchar(max)'
 
   SELECT TOP 1 @FullDataType = CASE
     WHEN ISNULL(datatype, 'v') = 'd' THEN 'date'
     WHEN ISNULL(datatype, 'v') = 'f' THEN 'bigint'
     WHEN ISNULL(datatype, 'v') = 'v' THEN 'nvarchar(max)'
     ELSE 'nvarchar(max)'
     END
   FROM customfields WITH (NOLOCK)
   WHERE ParentID = @Parentid
    AND fieldname = rtrim(ltrim(@ColumnName))
 
   DECLARE @CustomStrExp NVARCHAR(200) = ''
 
   IF(EXISTS(SELECT value FROM string_split(@Str, ' ')WHERE rtrim(ltrim(value)) = 'asc'))
   BEGIN
    SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  asc '
   END
   ELSE
   BEGIN
    SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  desc '
   END
 
   SET @StrPredefinedOrderBy = ''
   SET @StrCustomOrderBy = N' ' + @CustomStrExp + ' , '
  END
END
 
DROP TABLE IF EXISTS #temp1;
DROP TABLE IF EXISTS #temp2;
 
IF @srno = '' SET @srno = '1';
IF @enno = '' SET @enno = '20';
 
DECLARE @Query1 NVARCHAR(max) = ''
DECLARE @Pivot_Column [nvarchar] (max);
DECLARE @maxScore NUMERIC(18, 2) = isnull((
                SELECT (max(currentscore) * 100) / 99
                FROM enquiry_score_history(NOLOCK) e
                WHERE parentid = @ParentID
                ), 0)
DECLARE @hot INT,@warm INT,@cold INT
 
SELECT @hot = hot,@warm = warm,@cold = cold
FROM enquiry_cateogy_thresholds(NOLOCK)
WHERE parentid = @ParentID
 
IF @hot IS NULL
BEGIN
  SELECT @hot = hot,@warm = warm,@cold = cold
  FROM lead_cateogy_thresholds(NOLOCK)
  WHERE parentid = 0
END
 
SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME(fieldname)
FROM (
  SELECT DISTINCT [fieldname]
  FROM customfields(NOLOCK)
  WHERE ParentID = @ParentID AND isActive = 1
) Tab
 
DECLARE @NoCustomFields BIGINT, @filterCnt INT = 0
SET @NoCustomFields = (
   SELECT count(DISTINCT [fieldname])
   FROM customfields
   WHERE [ParentID] = @ParentID AND [isActive] = 1
)
 
DECLARE @Query NVARCHAR(max) = ''
DECLARE @TeamCode VARCHAR(10) = ''
DECLARE @ScopeCode VARCHAR(10) = ''
DECLARE @UserIdTeamLst VARCHAR(Max) = ''
DECLARE @UserLoginTeamLst VARCHAR(Max) = ''
DECLARE @tbluser TABLE (
  User_ID BIGINT
  ,Name VARCHAR(100)
  ,IMAGE VARCHAR(100)
)
 
SELECT @IsAdmin = isnull(IsAdmin, 0) FROM User_Detail(NOLOCK) WHERE User_ID = @UserID
 
select @ScopeCode = ScopeCode from ufn_GetUserRoleScope(@UserId)
if(@ScopeCode = 'GLOBAL') set @IsAdmin = 1
 
IF (@IsAdmin = 1)
BEGIN
  SET @UserID = 0
  INSERT INTO @tbluser
  EXEC Use_GetUserDetails @ParentId
END
ELSE
BEGIN
  INSERT INTO @tbluser
  EXEC Use_GetUserDetails @UserID
END
 
SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '') FROM @tbluser
 
IF (@ordstr = '') SET @ordstr = ' CurrentScore desc'
 
-- Combine FilterText and UeQuery safely to avoid syntax errors
IF (@LocalFilterText != ' (1=1) ' AND @LocalUeQuery != ' (1=1) ')
BEGIN
    SET @LocalFilterText = '(' + @LocalFilterText + ') AND (' + @LocalUeQuery + ')'
END
ELSE IF (@LocalUeQuery != ' (1=1) ')
BEGIN
    SET @LocalFilterText = @LocalUeQuery
END
 
IF (@LocalFilterText = ' (1=1) ' AND @LocalTxtsearch = ' (1=1) ')
BEGIN
  -- Branch A: Direct select for performance when no filters are applied
  SET @Query =
   N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname,rtrim(ltrim(A.MobileNo3)) as MobileNo3 , rtrim(ltrim(A.MobileNo1)) as MobileNo1 , rtrim(ltrim(A.MobileNo2)) as MobileNo2, A.EmailID3, A.EmailID1, A.EmailID2,A.Owner, A.Residentialaddress, A.Officeaddress,A.User_login,rtrim(ltrim(A.MobileNo)) as MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], A.Initialremarks, A.SourceName, A.MediumName, A.CampaignName, A.Parentid, A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,    '
   + ' isnull(A.img_ext,'''') as img_ext, A.WhereAddress, A.Tags, RowNumber1, rc1, A.IsduplicateEmail, A.IsduplicateMobile ,A.Stages,A.StagesId,A.CurrentScore,A.Profit_Loss,A.ThresholdColor        '
   + ' into #Temp2    FROM     (     '
   + ' SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno, ltrim(trim(isnull(Ue.Countrycode, ''''))+'' ''+trim(isnull(Ue.Mobileno, '''')))+ case when trim(isnull(Ue.Mobileno1,''''))<>'''' then '', ...'' else '''' end AS MobileNo3, trim(Ue.Mobileno1) as Mobileno1, trim( Ue.Mobileno2) as Mobileno2,Ue.Emailid,  Ue.Emailid AS EmailID3, Ue.Emailid1, Ue.Emailid2,est.StageName AS Stages,Ue.Owner, Ue.Residentialaddress, Ue.Officeaddress, Ud.User_login, Ue.CreatedDate , Ue.City, Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads, (CASE WHEN isnull(ue.isopen,1)=1 and isnull(ue.LeadNo,0) = 0 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress, isnull(tg.Tags, '''') Tags , '
   + ' ROW_NUMBER() OVER(ORDER BY ' + REPLACE(ISNULL(@StrPredefinedOrderBy, ''), '???', 'Ue.') + '   Ue.Enquiryid DESC) AS RowNumber1, count(*) OVER(ORDER BY Ue.Parentid) AS rc1, Ue.IsduplicateEmail, Ue.IsduplicateMobile,ue.StagesId,Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, '
   + ' CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) , ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int)>' + cast(@warm AS NVARCHAR(max)) + N' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) between ' + cast(@cold AS NVARCHAR(max)) + N' and ' + cast(@warm AS NVARCHAR(max)) + N' then ''Warm'' else ''Cold'' end          '
   + ' FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss '
   + ' ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums     '
   + ' ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs     '
   + ' ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud     '
   + ' ON Ue.Createdby = Ud.User_id LEFT JOIN tbl_enquiry_stage (NOLOCK) est '
   + ' ON Ue.StagesId = est.StageID '
   + ' left join enquiry_score_history_latest(nolock) LS ON Ue.EnquiryID=LS.enquiryid '
   + ' and Ue.Parentid = Ud.ParentID LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''enquiry'' and tm.ParentID = ' + Convert(VARCHAR(100), @ParentID) + ' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = Ue.EnquiryId    '
   + ' WHERE Ue.Parentid = ' + Convert(VARCHAR(100), @Parentid)
 
  IF @Userid > 0
  BEGIN
   SET @Query += N' AND ' + CASE WHEN isnull(@UserIdTeamLst, '') != '' THEN ' ue.CreatedBy in (' + isnull(@UserIdTeamLst, '') + ') ' WHEN isnull(@Userid, 0) = 0 THEN ' ue.CreatedBy = ue.CreatedBy ' ELSE ' ue.CreatedBy = ' + Convert(VARCHAR(100), @Userid) END
  END
 
  SET @Query += N' ) A Where A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno)
END
ELSE
BEGIN
  -- Branch B: Filtered search
  SET @Query = N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname, rtrim(ltrim(A.MobileNo3)) as MobileNo3 , rtrim(ltrim(A.MobileNo1)) as MobileNo1 ,rtrim(ltrim(A.MobileNo2)) as MobileNo2, A.EmailID3, A.EmailID1, A.EmailID2 
,A.Owner, A.Residentialaddress, A.Officeaddress,A.User_login,A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], A.Initialremarks, A.SourceName, A.MediumName, A.CampaignName, A.Parentid,A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,    '
   + ' isnull(A.img_ext,'''') as img_ext, A.WhereAddress, A.Tags, RowNumber1, rc1, A.IsduplicateEmail, A.IsduplicateMobile,A.Stages,A.StagesId,A.Profit_Loss,A.CurrentScore, A.ThresholdColor       
   into #Temp2    
   FROM     
   (     
  Select *, ROW_NUMBER() OVER(ORDER BY ' + REPLACE(ISNULL(@StrPredefinedOrderBy, ''), '???', 'T.') + N' T.Enquiryid DESC) AS RowNumber1, count(*) OVER(ORDER BY T.Parentid) AS rc1      
  From     
  (    
   SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,trim(Ue.Mobileno) as Mobileno,ltrim(trim(isnull(Ue.Countrycode, ''''))+'' ''+trim(isnull(Ue.Mobileno, '''')))+ case when trim(isnull(Ue.Mobileno1,''''))<>'''' then '', ...'' else '''' end AS MobileNo3, trim(Ue.Mobileno1) as Mobileno1, trim(Ue.Mobileno2) as Mobileno2,Ue.Emailid, Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2
,ue.Owner,Ue.Residentialaddress,Ue.Officeaddress, Ud.User_login,Ue.CreatedDate , Ue.City, Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads, (CASE
WHEN isnull(ue.isopen,1)=1 and isnull(ue.LeadNo,0) = 0 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress, isnull(tg.Tags, '''') Tags ,Ue.IsduplicateEmail,ue.IsduplicateMobile,est.StageName as Stages,ue.StagesId,
Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end,
CurrentScore=cast(isnull((LS.currentscore/nullif('+ cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int), 
    ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int)>' + 
    cast(@warm AS NVARCHAR(max)) + N' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) 
    between ' + cast(@cold AS NVARCHAR(max)) + N'  and ' + cast(@warm AS NVARCHAR(max)) + N' then ''Warm'' else ''Cold'' end   
   FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss     
   ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums     
   ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs     
   ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud     
   ON Ue.Createdby = Ud.User_id LEFT JOIN tbl_enquiry_stage (NOLOCK) est
  ON Ue.StagesId = est.StageID
  left join enquiry_score_history_latest(nolock) LS ON Ue.EnquiryID=LS.enquiryid
   and Ue.Parentid = Ud.ParentID LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''enquiry'' and tm.ParentID = '   
   + Convert(VARCHAR(100), @ParentID) + ' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = Ue.EnquiryId  
   WHERE Ue.Parentid = ' + Convert(VARCHAR(100), @ParentID)
 
  IF @Userid > 0    
  BEGIN    
   SET @Query += N' AND ' + CASE     WHEN isnull(@UserIdTeamLst, '') != ''    THEN ' ue.CreatedBy in (' + isnull(@UserIdTeamLst, '') + ') '    WHEN isnull(@Userid, 0) = 0    THEN ' ue.CreatedBy = ue.CreatedBy '    ELSE ' ue.CreatedBy = ' + Convert(VARCHAR(100), @Userid)    END    
  END    
  SET @Query += N' ) T Where ' + @LocalFilterText + N' ) A Where ' + CASE     WHEN @LocalTxtsearch = ' (1=1) '    THEN ' A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno)    ELSE @LocalTxtsearch    END    
END    
 
IF (@ordstr = '') SET @ordstr = ' Enquiryid desc '    
 
IF (@Pivot_Column IS NOT NULL)    
BEGIN    
  -- Branch C: Pivot results for custom fields
  IF (@LocalTxtsearch = ' (1=1) ')       
  BEGIN    
   SET @Query += CAST(N';Select * From 
   (
   SELECT  rc1 AS [rcnt], EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, 
   Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, 
   CampaignName, Parentid, dbo.fn_ConvertDateTime(cast(CreatedDate as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as CreatedDate,   
   dbo.fn_ConvertDateTime(cast(CreatedDate1 as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as  CreatedDate1, Createdby, Leads, 
   Isopen, Img_ext, ROW_NUMBER() OVER(ORDER BY ' + REPLACE(ISNULL(@StrPredefinedOrderBy, ''), '???', '') + N' ' + @StrCustomOrderBy + '  EnquiryId Desc) + 
   cast( ' + cast(@srno - 1 AS NVARCHAR) + ' as int) ' + '  AS [RowNumber1], WhereAddress, rc1, IsduplicateEmail, IsduplicateMobile , 
   Stages,StagesId, Owner,Profit_Loss,CurrentScore,ThresholdColor, ' + @Pivot_Column +   N' FROM 
   (SELECT EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, 
   MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate,
   CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress, [fieldname], fieldvalue, RowNumber1, rc1, IsduplicateEmail, IsduplicateMobile ,Stages,
   StagesId, Owner,Profit_Loss,CurrentScore,ThresholdColor         
  FROM (
  select E.Enquiryid, E.PersonName, E.CompanyName, E.MobileNo3, E.MobileNo1, E.MobileNo2, E.EmailID3, E.EmailID1, E.EmailID2, E.Residentialaddress, 
  E.Officeaddress, E.User_login, E.MobileNo, E.EmailID,E.Stages,E.StagesId,E.Owner, E.City, E.[State], E.Country, E.Countrycode, E.Pincode, E.[ADDRESS],
  E.Initialremarks, E.SourceName, E.MediumName, E.CampaignName, E.Parentid, E.CreatedDate, E.CreatedDate1, E.Createdby, E.Leads, E.Isopen, E.Img_ext,
  E.WhereAddress, y.fieldname, x.fieldvalue ,E.RowNumber1, E.rc1, E.IsduplicateEmail, E.IsduplicateMobile,E.Profit_Loss,E.CurrentScore,E.ThresholdColor          
  From #temp2 E left join customfieldEnquiryvalue(nolock) x       
  ON E.Enquiryid = x.Enquiryid left join customfields(nolock) y       
  ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1  )q )Tab1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ') ) AS Tab2      
  WHERE ' + @LocalTxtsearch + '  ) T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));    
  END    
  ELSE    
  BEGIN    
   -- Branch CB: Filtered pivot results
   SET @Query += CAST(N'; select * into #Temp1 From (select [x].EnquiryId, [y].[fieldname],   
[x].[fieldvalue] from customfieldEnquiryvalue(nolock) x inner join customfields(nolock) y  
ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) T1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + ISNULL(@LocalTxtsearch, '(1=1)') AS NVARCHAR(MAX));  
   
   SET @Query += CAST(N';Select * From (SELECT ROW_NUMBER() OVER(ORDER BY ' + REPLACE(ISNULL(@StrPredefinedOrderBy, ''), '???', 'A.') + N' ' + @StrCustomOrderBy + '  A.EnquiryId Desc) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], count(*) OVER(ORDER BY [ParentID]) AS [rcnt],
   A.EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo,
   EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, 
MediumName, CampaignName, Parentid,Stages,StagesId,CurrentScore,Profit_Loss, ThresholdColor, dbo.fn_ConvertDateTime(cast(CreatedDate as datetime), ''' + 
cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as CreatedDate,      dbo.fn_ConvertDateTime(cast(CreatedDate1 as datetime), ''' + 
cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as  CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress, ' + @Pivot_Column +     
     N' From #Temp1 A inner join #temp2 E       
  ON A.EnquiryId = E.Enquiryid  ) T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) AS NVARCHAR(MAX)) + N' ORDER BY ' + @ordstr;    
  END    
END    
ELSE    
BEGIN    
  -- Branch D: Standard return when no custom fields exist
  SET @Query += CAST(N'; select distinct Enquiryid, Personname, Companyname, MobileNo3, MobileNo1, MobileNo2, EmailID3,EmailID1,EmailID2,
  Residentialaddress,Officeaddress,User_login,MobileNo,EmailID,City,[State], Country,Countrycode,Pincode,[ADDRESS], Initialremarks,  SourceName, 
  MediumName, CampaignName,Parentid,dbo.fn_ConvertDateTime(cast(CreatedDate as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as 
  CreatedDate, dbo.fn_ConvertDateTime(cast(CreatedDate1 as datetime), ''' + cast(@TimeZoneName AS NVARCHAR(255)) + ''', 0) as  CreatedDate1,
  Createdby,Leads,Isopen, isnull(img_ext,'''') as img_ext, WhereAddress, Tags, RowNumber1, rc1, IsduplicateEmail, IsduplicateMobile ,Stages, StagesId,
  Owner, Profit_Loss,CurrentScore,ThresholdColor 
  from #temp2 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));    
END    
 
PRINT '@FinalQuery:- ' + cast(@Query AS VARCHAR(max))    
 
EXEC sp_executesql @Query;    
 
DROP TABLE IF EXISTS #temp1;    
DROP TABLE IF EXISTS #temp2;    
 
EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @actUserId    
   ,@Activity_type = 'view_enqry'    
   ,@ActionType = 'S'    
   ,@RowJson = ''    
   ,@Table_name = 'UserEnquiry'
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserEnquriyDetails_Changedss21_Enquiryexists]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
-- exec Usp_ViewUserEnquriyDetails_Changedss21 @Txtsearch=N'',@Parentid=35610,@Userid=0,@FilterText=N'',@ordstr=N'',@srno=N'1',@enno=N'4000',@ue_query=N''     
-- exec Usp_ViewUserEnquriyDetails_Changedss21 @Txtsearch=N'',@Parentid=32821,@Userid=33195,@FilterText=N'',@ordstr=N'',@srno=N'1',@enno=N'20',@ue_query=N''    
-- exec Usp_ViewUserEnquriyDetails_Changedss21 @Txtsearch=N'',@Parentid=4827,@Userid=33520,@FilterText=N'',@ordstr=N'',@srno=N'1',@enno=N'4000',@ue_query=N''    
-- exec Usp_ViewUserEnquriyDetails_Changedss21 @Txtsearch=N'',@Parentid=32222,@Userid=0,@FilterText=N' PersonName like''%wwf''', @ordstr=N'', @srno=N'1', @enno=N'200', @ue_query=N''    
-- exec Usp_ViewUserEnquriyDetails_Changedss21_mkb @Txtsearch=N'',@Parentid=32222,@Userid=0,@FilterText=N' (SourceName = ''EshopSignUp'') ',@ordstr=N'',@srno=N'1',@enno=N'20',@ue_query=N''    
 -- exec [Usp_ViewUserEnquriyDetails_Changedss21_mkb] @Txtsearch=N'',@Parentid=335,@Userid=0,@FilterText=N' PersonName like''%''', @ordstr=N'', @srno=N'1', @enno=N'200', @ue_query=N''    
    
CREATE   PROCEDURE [dbo].[Usp_ViewUserEnquriyDetails_Changedss21_Enquiryexists]    
(    
 @Txtsearch NVARCHAR(max)='',    
 @Parentid BIGINT,    
 @Userid INT=0,    
 @FilterText nvarchar(max) = '',    
 @ordstr nvarchar(Max)='',    
 @srno NVARCHAR(100),    
 @enno NVARCHAR(100),    
 @ue_query nvarchar(max) = ''    
)    
AS    
BEGIN    
  
   -- Declare 
   --@txtSearch NVARCHAR(max) = N' (cast(Course_01_Name as nvarchar(max)) like ''%0%'')  
   --   and  (cast(Course_01_Expire_Date as date) between ''01/20/2021'' and ''09/21/2024'' ) ',                                          
   ----@txtSearch NVARCHAR(max) = N' (1=1) ',                                          

   --@ParentID BIGINT = 40834,                                          
   --@Userid INT= 40834,                                          
   --@FilterText NVARCHAR(MAX) = '',                                          
   --@srno NVARCHAR(100)= N'1',                                          
   --@enno NVARCHAR(100)= N'20',        
   --@ordstr nvarchar(Max)=N'' ,      
   --@ue_query nvarchar(max) = N'' 
   
    
    
-- declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=32222,@Userid INT=0,@FilterText nvarchar(max)=N'',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N''  -- AC    
-- declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=32222,@Userid INT=0,@FilterText nvarchar(max)=N' (Personname like ''%test%'') ',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N'' -- BCA    
-- declare @Txtsearch NVARCHAR(max)=N'( fieldname=''test02'' and cast(fieldvalue as varchar(50)) like  ''%2%'' )  or  ( fieldname=''test03'' and cast(fieldvalue as varchar(50)) like  ''%3%'' ) ',@Parentid BIGINT=32222,@Userid INT=0,@FilterText nvarchar(max)=N' (Personname like ''%test%'') ',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N'' -- BCB    
-- declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=38750,@Userid INT=0,@FilterText nvarchar(max)=N'',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N''  -- AD    
    
--declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=38750,@Userid INT=0,@FilterText nvarchar(max)=N' (Personname like ''%test%'') ',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N'' -- BD    
    
 declare @Parameterlist nvarchar(max) , @LoggerID bigint    
 set @Parameterlist = 'txtSearch : '+ @txtSearch + ' ,ParentID : '+ CONVERT(VARCHAR(100), @ParentID) + ' ,Userid : '+ CONVERT(VARCHAR(100), @Userid) + ' ,FilterText : '+ @FilterText + ' ,ordstr : '+ @ordstr + ' ,srno : '+ @srno + ' ,enno : '+ @enno + ' ,ue_query : '+ @ue_query;    
    
 --insert into kit19_executionlogger(ObjectName,Parameterlist,StartDatetime,EndDatetime,Remarks)    
 --values('Usp_ViewUserEnquriyDetails_Changedss21',@Parameterlist,getdate(),'','')    
    
 --set @LoggerID = Scope_Identity();    
    
 DROP TABLE IF EXISTS #temp1;    
 DROP TABLE IF EXISTS #temp2;    
    
 if @srno ='' begin set @srno='1'; end    
 if @enno='' begin set @enno='20'; end    
    
    
IF(@Txtsearch = '')            
BEGIN            
 SET @Txtsearch = N' (1=1) ';            
END;    
    
IF(@FilterText = '')    
BEGIN    
 SET @FilterText = N' (1=1) ';            
END;            
    
 IF(@FilterText LIKE '%MobileNo3%')    
 BEGIN    
set @FilterText = replace(@FilterText,'MobileNo3','MobileNo')    
 END    
    
 declare @Query1 nvarchar(max) = ''    
 DECLARE @Pivot_Column [nvarchar](max);    
    
    
 /*Select Pivot Column*/    
 SELECT @Pivot_Column= COALESCE(@Pivot_Column+',','')+ QUOTENAME(fieldname) FROM    
 (SELECT DISTINCT [fieldname] FROM customfields (NOLOCK) where ParentID=@ParentID and isActive=1)Tab    
    
    
 Declare @NoCustomFields bigint, @filterCnt int=0    
 set @NoCustomFields = (SELECT count(DISTINCT [fieldname]) FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1)    
    
 declare @Query nvarchar(max) = ''    
   
 Declare @TeamCode varchar(10) = ''  
 Declare @ScopeCode varchar(10) = ''   
Declare @UserIdTeamLst varchar(4000) = '' 
Declare @HierarchyJSON varchar(Max) = ''

 if Exists(select 1 from tbl_UA_UserHierarchy where ParentId = @ParentId) 
 Begin 
 Select @HierarchyJSON = HierarchyJSON from tbl_UA_UserHierarchy where ParentId = @ParentId 

  Create TABLE #TableData2 ([user_id] bigint, team_name Varchar(50), user_login varchar(50), username varchar(50), [parentid] bigint)
  Insert into #TableData2 ([user_id], team_name, user_login,username,[parentid])               
  Select [user_id], '', user_login, username, [parentid] from OPENJSON(@HierarchyJSON) with ([user_id] bigint, user_login Varchar(100), username Varchar(100), [parentid] bigint)

  ;with CTE(user_id) 
 as ( 
  select user_id 
  from #TableData2 where (User_id = @UserId or parentid = @UserId)
  union all 
  -- recursively add children
  select c.user_id
  from #TableData2 c 
  join CTE on c.parentid = CTE.User_id
 ) 
SELECT @UserIdTeamLst = STUFF((SELECT distinct ',' + Cast( a.user_id as varchar(4000)) from #TableData2 a join CTE on CTE.user_id = a.User_id FOR XML PATH('')),1,1,'')
 
--, @UserIdTeamLst = ''
 select @TeamCode = TeamCode, @ScopeCode = ScopeCode from ufn_GetUserRoleScope(@UserId) 

 --select * from #TableData2 
 --select @UserIdTeamLst 
 End
 Else
 Begin
 select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId) 
 End

 --Declare @UserIdTeamLst varchar(500) = ''   
 --select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId)   
  
    declare @IsAdmin bit = 0
	
	SELECT @IsAdmin = IsAdmin
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @ParentID
	 
    IF(@IsAdmin = 1)
	BEGIN
		SET @Userid = 0;
	END

  
IF(@FilterText = ' (1=1) ' and @Txtsearch = ' (1=1) ')    
BEGIN    
 print 'Branch A'    
    
  set @Query = N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname,A.MobileNo3,A.MobileNo1,A.MobileNo2,A.EmailID3,A.EmailID1,A.EmailID2,A.Residentialaddress,    
   A.Officeaddress,A.User_login,A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], A.Initialremarks,    
   A.SourceName,A.MediumName,A.CampaignName,A.Parentid,A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,    
   isnull(A.img_ext,'''') as img_ext, A.WhereAddress, RowNumber1, rc1     
   into #Temp2    
   FROM     
   (     
  SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno,ltrim(Ue.Countrycode+'' ''+Ue.Mobileno)+ case when isnull(Ue.Mobileno1,'''')<>'''' then '', ...'' else '''' end AS MobileNo3, Ue.Mobileno1, Ue.Mobileno2,Ue.Emailid ,    
  Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress, Ud.User_login,Ue.CreatedDate , Ue.City,     
  Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], Ue.Initialremarks, Uss.Name AS
  
 SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1
  
 then null else ue.LeadNo end AS Leads, (CASE WHEN isnull(ue.isopen,1)=1 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress, ROW_NUMBER() OVER(ORDER BY Ue.Enquiryid DESC) AS RowNumber1, count
(*) OVER(ORDER BY Ue.Parentid) AS rc1    
  FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss     
  ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums     
  ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs     
  ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud     
  ON Ue.Createdby = Ud.User_id and Ue.Parentid = Ud.ParentID     
  WHERE Ue.Parentid = '+ Convert(varchar(100),@Parentid)    
    
  
 --CASE WHEN @Userid = 0 THEN N' = UL.AssignedTo '   
 --WHEN @Userid > 0 and isnull(@TeamCode,'') != '' THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'   
 --ELSE ' = ' + CAST(@Userid AS NVARCHAR(MAX)) End + '  
  
  if isnull(@Userid,0) >=0   
  Begin   
  set @Query += N' AND ' + CASE WHEN isnull(@Userid,0) = 0 THEN ' ue.CreatedBy = ue.CreatedBy '  
  When isnull(@Userid,0) > 0  then  ' ue.CreatedBy = ue.CreatedBy ' ELSE ' ue.CreatedBy = ' + Convert(varchar(100),@Userid) END   
  End    
  
  set @Query += N' ) A Where A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno)     
    
 END    
 ELSE    
 BEGIN    
 print 'Branch B'    
    
  set @Query += N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname,A.MobileNo3,A.MobileNo1,A.MobileNo2,A.EmailID3,A.EmailID1,A.EmailID2,A.Residentialaddress,    
   A.Officeaddress,A.User_login,A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], A.Initialremarks,    
   A.SourceName,A.MediumName,A.CampaignName,A.Parentid,A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,    
   isnull(A.img_ext,'''') as img_ext, A.WhereAddress, RowNumber1, rc1     
   into #Temp2    
   FROM     
   (     
  Select *, ROW_NUMBER() OVER(ORDER BY T.Enquiryid DESC) AS RowNumber1, count(*) OVER(ORDER BY T.Parentid) AS rc1      
  From     
  (    
   SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno,ltrim(Ue.Countrycode+'' ''+Ue.Mobileno)+ case when isnull(Ue.Mobileno1,'''')<>'''' then '', ...'' else '''' end AS MobileNo3, Ue.Mobileno1, Ue.Mobileno2,Ue.Emailid ,    
   Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress, Ud.User_login,Ue.CreatedDate , Ue.City,     
   Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads, (CASE WHEN isnull(ue.isopen,1)=1 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress    
   FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss     
   ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums     
   ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs     
   ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud     
   ON Ue.Createdby = Ud.User_id and Ue.Parentid = Ud.ParentID     
   WHERE Ue.Parentid = ' + Convert(varchar(100),@ParentID)       
    
    
  if isnull(@Userid,0) >=0    
  Begin    
  set @Query += N' AND ue.CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN ue.CreatedBy   
  When '+ Convert(varchar(100),@Userid) +' > 0  THEN  ue.CreatedBy  
  ELSE '+ Convert(varchar(100),@Userid) +' END '   
  End    
    
  set @Query += N' ) T Where ' + @FilterText +    
       N' ) A Where ' + case when @Txtsearch = ' (1=1) ' then ' A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) else ' (1=1) ' end    
    
 END    
    
If(@ue_query = '')    
Begin    
 set @ue_query = ' (1=1) '    
End    
    
If(@FilterText != '' and @ue_query != '')    
Begin    
 Set @FilterText += ' AND ' + @ue_query    
End    
    
If(@ordstr = '')    
Begin    
 set @ordstr = ' Enquiryid desc '    
End    
    
 IF(@Pivot_Column IS NOT NULL)    
 BEGIN    
  print 'Branch C'    
 IF(@Txtsearch = ' (1=1) ')-- From Branch A    
 Begin    
  print 'Branch CA'    
    
  SET @Query+=CAST(N';Select 1 From (SELECT rc1 AS [rcnt], EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, RowNumber1, WhereAddress, rc1, ' + @Pivot_Column +     
  N' FROM (SELECT EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks,
  
 SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress, [fieldname], fieldvalue, RowNumber1,  rc1      
  FROM (select E.Enquiryid, E.PersonName, E.CompanyName, E.MobileNo3, E.MobileNo1, E.MobileNo2, E.EmailID3, E.EmailID1, E.EmailID2, E.Residentialaddress, E.Officeaddress, E.User_login, E.MobileNo, E.EmailID, E.City, E.[State], E.Country, E.Countrycode, 
  E.Pincode, E.[ADDRESS], E.Initialremarks, E.SourceName, E.MediumName, E.CampaignName, E.Parentid, E.CreatedDate, E.CreatedDate1, E.Createdby, E.Leads, E.Isopen, E.Img_ext, E.WhereAddress, y.fieldname, x.fieldvalue, E.RowNumber1, E.rc1     
  From #temp2 E left join customfieldEnquiryvalue(nolock) x     
  ON E.Enquiryid = x.Enquiryid left join customfields(nolock) y     
  ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1    
  )q )Tab1    
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2    
  WHERE ' + @Txtsearch + ') T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));    
 End    
 Else    
 Begin    
  print 'Branch CB'    
    
  Select @filterCnt=count(*) From dbo.fn_Split(@Txtsearch, ' ) ')    
      
  --SELECT @Query += CAST(N'; select x.EnquiryID    
  --into #Temp1    
  --from customfieldEnquiryvalue(nolock) x inner join customfields(nolock) y    
  --ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1    
  --Where ' + @Txtsearch + N'    
  --group by x.EnquiryID    
  --having count(*) >= ' + Cast(@filterCnt as NVARCHAR(MAX)) AS NVARCHAR(MAX));    

     SELECT @Query += CAST(N'; select * into #Temp1 From (select [x].EnquiryId, [y].[fieldname], 
	[x].[fieldvalue] from customfieldEnquiryvalue(nolock) x inner join customfields(nolock) y
	ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) T1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @Txtsearch AS NVARCHAR(MAX));

    
 SET @Query+=CAST(N';Select 1 From (SELECT ROW_NUMBER() OVER(ORDER BY EnquiryId Desc) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], count(*) OVER(ORDER BY [ParentID]) AS [rcnt], EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1
, Createdby, Leads, Isopen, Img_ext, WhereAddress FROM (SELECT EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks,
  
 SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress   
  FROM (select E.Enquiryid, E.PersonName, E.CompanyName, E.MobileNo3, E.MobileNo1, E.MobileNo2, E.EmailID3, E.EmailID1, E.EmailID2, E.Residentialaddress, E.Officeaddress, E.User_login, E.MobileNo, E.EmailID, E.City, E.[State], E.Country, E.Countrycode,
   E.Pincode, E.[ADDRESS], E.Initialremarks, E.SourceName, E.MediumName, E.CampaignName, E.Parentid, E.CreatedDate, E.CreatedDate1, E.Createdby, E.Leads, E.Isopen, E.Img_ext, E.WhereAddress    
  From #Temp1 A inner join #temp2 E 
   ON A.EnquiryId = E.Enquiryid    
  ) q 
  )Tab1  
  
  ) T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) AS NVARCHAR(MAX)) + N' ORDER BY ' + @ordstr;   
   
 End   
 END   
 ELSE   
 BEGIN   
 print 'Branch D'   
   
 SET @Query += CAST(N'; select 1 from #temp2 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));   
 END   
    
    
 print '@FinalQuery:- ' + cast(@Query as varchar(max))    
 EXEC sp_executesql @Query;    
    
 update kit19_executionlogger    
 set EndDatetime = getdate(), Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)    
 where ID = @LoggerID    
    
 update kit19_executionlogger    
 set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)    
 where ID = @LoggerID    
    
 DROP TABLE IF EXISTS #temp1;    
 DROP TABLE IF EXISTS #temp2;    
    
END  




GO

