 -- exec [Usp_ViewUserEnquriyDetails_Changedss21_mkb] @Txtsearch=N'',@Parentid=335,@Userid=0,@FilterText=N' PersonName like''%''', @ordstr=N'', @srno=N'1', @enno=N'200', @ue_query=N''    
    
CREATE   PROCEDURE [dbo].[Usp_ViewUserEnquriyDetails_Changedss21_Enquiryexists_1]    
(    
 @Txtsearch NVARCHAR(max)='',    
 @Parentid BIGINT,    
 @Userid INT=0,    
 @FilterText nvarchar(max) = '',    
 @ordstr nvarchar(Max)='',    
 @srno NVARCHAR(100),    
 @enno NVARCHAR(100),    
 @ue_query nvarchar(max) = '',
 @enquiryid bigint
)    
AS    
BEGIN    
  
   -- Declare 
   --@txtSearch NVARCHAR(max) = N' (cast(Course_01_Name as nvarchar(max)) like ''%0%'')  
   --   and  (cast(Course_01_Expire_Date as date) between ''01/20/2021'' and ''09/21/2024'' ) ',                                          
   ----@txtSearch NVARCHAR(max) = N' (1=1) ',                                          

   --@ParentID BIGINT = 40834,                                          
   --@Userid INT= 40834,                                          
   --@FilterText NVARCHAR(MAX) = '',                                          
   --@srno NVARCHAR(100)= N'1',                                          
   --@enno NVARCHAR(100)= N'20',        
   --@ordstr nvarchar(Max)=N'' ,      
   --@ue_query nvarchar(max) = N'' 
   
    
    
-- declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=32222,@Userid INT=0,@FilterText nvarchar(max)=N'',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N''  -- AC    
-- declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=32222,@Userid INT=0,@FilterText nvarchar(max)=N' (Personname like ''%test%'') ',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N'' -- BCA    
-- declare @Txtsearch NVARCHAR(max)=N'( fieldname=''test02'' and cast(fieldvalue as varchar(50)) like  ''%2%'' )  or  ( fieldname=''test03'' and cast(fieldvalue as varchar(50)) like  ''%3%'' ) ',@Parentid BIGINT=32222,@Userid INT=0,@FilterText nvarchar(max)=N' (Personname like ''%test%'') ',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N'' -- BCB    
-- declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=38750,@Userid INT=0,@FilterText nvarchar(max)=N'',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N''  -- AD    
    
--declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=38750,@Userid INT=0,@FilterText nvarchar(max)=N' (Personname like ''%test%'') ',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N'' -- BD    
select * into #enquiryid from userenquiry(nolock) where enquiryid=@enquiryid  
 declare @Parameterlist nvarchar(max) , @LoggerID bigint    
 set @Parameterlist = 'txtSearch : '+ @txtSearch + ' ,ParentID : '+ CONVERT(VARCHAR(100), @ParentID) + ' ,Userid : '+ CONVERT(VARCHAR(100), @Userid) + ' ,FilterText : '+ @FilterText + ' ,ordstr : '+ @ordstr + ' ,srno : '+ @srno + ' ,enno : '+ @enno + ' ,ue_query : '+ @ue_query;    
    
 --insert into kit19_executionlogger(ObjectName,Parameterlist,StartDatetime,EndDatetime,Remarks)    
 --values('Usp_ViewUserEnquriyDetails_Changedss21',@Parameterlist,getdate(),'','')    
    
 --set @LoggerID = Scope_Identity();    
    
 DROP TABLE IF EXISTS #temp1;    
 DROP TABLE IF EXISTS #temp2;    
    
 if @srno ='' begin set @srno='1'; end    
 if @enno='' begin set @enno='20'; end    
    
    
IF(@Txtsearch = '')            
BEGIN            
 SET @Txtsearch = N' (1=1) ';            
END;    
    
IF(@FilterText = '')    
BEGIN    
 SET @FilterText = N' (1=1) ';            
END;            
    
 IF(@FilterText LIKE '%MobileNo3%')    
 BEGIN    
set @FilterText = replace(@FilterText,'MobileNo3','MobileNo')    
 END    
    
 declare @Query1 nvarchar(max) = ''    
 DECLARE @Pivot_Column [nvarchar](max);    
    
    
 /*Select Pivot Column*/    
 SELECT @Pivot_Column= COALESCE(@Pivot_Column+',','')+ QUOTENAME(fieldname) FROM    
 (SELECT DISTINCT [fieldname] FROM customfields (NOLOCK) where ParentID=@ParentID and isActive=1)Tab    
    
    
 Declare @NoCustomFields bigint, @filterCnt int=0    
 set @NoCustomFields = (SELECT count(DISTINCT [fieldname]) FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1)    
    
 declare @Query nvarchar(max) = ''    
   
 Declare @TeamCode varchar(10) = ''  
 Declare @ScopeCode varchar(10) = ''   
Declare @UserIdTeamLst varchar(4000) = '' 
Declare @HierarchyJSON varchar(Max) = ''

 if Exists(select 1 from tbl_UA_UserHierarchy where ParentId = @ParentId) 
 Begin 
 Select @HierarchyJSON = HierarchyJSON from tbl_UA_UserHierarchy where ParentId = @ParentId 

  Create TABLE #TableData2 ([user_id] bigint, team_name Varchar(50), user_login varchar(50), username varchar(50), [parentid] bigint)
  Insert into #TableData2 ([user_id], team_name, user_login,username,[parentid])               
  Select [user_id], '', user_login, username, [parentid] from OPENJSON(@HierarchyJSON) with ([user_id] bigint, user_login Varchar(100), username Varchar(100), [parentid] bigint)

  ;with CTE(user_id) 
 as ( 
  select user_id 
  from #TableData2 where (User_id = @UserId or parentid = @UserId)
  union all 
  -- recursively add children
  select c.user_id
  from #TableData2 c 
  join CTE on c.parentid = CTE.User_id
 ) 
SELECT @UserIdTeamLst = STUFF((SELECT distinct ',' + Cast( a.user_id as varchar(4000)) from #TableData2 a join CTE on CTE.user_id = a.User_id FOR XML PATH('')),1,1,'')
 
--, @UserIdTeamLst = ''
 select @TeamCode = TeamCode, @ScopeCode = ScopeCode from ufn_GetUserRoleScope(@UserId) 

 --select * from #TableData2 
 --select @UserIdTeamLst 
 End
 Else
 Begin
 select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId) 
 End

 --Declare @UserIdTeamLst varchar(500) = ''   
 --select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId)   
  
    declare @IsAdmin bit = 0
	
	SELECT @IsAdmin = IsAdmin
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @ParentID
	 
    IF(@IsAdmin = 1)
	BEGIN
		SET @Userid = 0;
	END

  
IF(@FilterText = ' (1=1) ' and @Txtsearch = ' (1=1) ')    
BEGIN    
 print 'Branch A'    
    
  set @Query = N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname,A.MobileNo3,A.MobileNo1,A.MobileNo2,A.EmailID3,A.EmailID1,A.EmailID2,A.Residentialaddress,    
   A.Officeaddress,A.User_login,A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], A.Initialremarks,    
   A.SourceName,A.MediumName,A.CampaignName,A.Parentid,A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,    
   isnull(A.img_ext,'''') as img_ext, A.WhereAddress, RowNumber1, rc1     
   into #Temp2    
   FROM     
   (     
  SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno,ltrim(Ue.Countrycode+'' ''+Ue.Mobileno)+ case when isnull(Ue.Mobileno1,'''')<>'''' then '', ...'' else '''' end AS MobileNo3, Ue.Mobileno1, Ue.Mobileno2,Ue.Emailid ,    
  Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress, Ud.User_login,Ue.CreatedDate , Ue.City,     
  Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], Ue.Initialremarks, Uss.Name AS
  
 SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1
  
 then null else ue.LeadNo end AS Leads, (CASE WHEN isnull(ue.isopen,1)=1 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress, ROW_NUMBER() OVER(ORDER BY Ue.Enquiryid DESC) AS RowNumber1, count
(*) OVER(ORDER BY Ue.Parentid) AS rc1    
  FROM #enquiryid (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss     
  ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums     
  ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs     
  ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud     
  ON Ue.Createdby = Ud.User_id and Ue.Parentid = Ud.ParentID     
  WHERE Ue.Parentid = '+ Convert(varchar(100),@Parentid)    
    
  
 --CASE WHEN @Userid = 0 THEN N' = UL.AssignedTo '   
 --WHEN @Userid > 0 and isnull(@TeamCode,'') != '' THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'   
 --ELSE ' = ' + CAST(@Userid AS NVARCHAR(MAX)) End + '  
  
  if isnull(@Userid,0) >=0   
  Begin   
  set @Query += N' AND ' + CASE WHEN isnull(@Userid,0) = 0 THEN ' ue.CreatedBy = ue.CreatedBy '  
  When isnull(@Userid,0) > 0  then  ' ue.CreatedBy = ue.CreatedBy ' ELSE ' ue.CreatedBy = ' + Convert(varchar(100),@Userid) END   
  End    
  
  set @Query += N' ) A Where A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno)     
    
 END    
 ELSE    
 BEGIN    
 print 'Branch B'    
    
  set @Query += N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname,A.MobileNo3,A.MobileNo1,A.MobileNo2,A.EmailID3,A.EmailID1,A.EmailID2,A.Residentialaddress,    
   A.Officeaddress,A.User_login,A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], A.Initialremarks,    
   A.SourceName,A.MediumName,A.CampaignName,A.Parentid,A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,    
   isnull(A.img_ext,'''') as img_ext, A.WhereAddress, RowNumber1, rc1     
   into #Temp2    
   FROM     
   (     
  Select *, ROW_NUMBER() OVER(ORDER BY T.Enquiryid DESC) AS RowNumber1, count(*) OVER(ORDER BY T.Parentid) AS rc1      
  From     
  (    
   SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno,ltrim(Ue.Countrycode+'' ''+Ue.Mobileno)+ case when isnull(Ue.Mobileno1,'''')<>'''' then '', ...'' else '''' end AS MobileNo3, Ue.Mobileno1, Ue.Mobileno2,Ue.Emailid ,    
   Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress, Ud.User_login,Ue.CreatedDate , Ue.City,     
   Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads, (CASE WHEN isnull(ue.isopen,1)=1 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress    
   FROM #enquiryid (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss     
   ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums     
   ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs     
   ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud     
   ON Ue.Createdby = Ud.User_id and Ue.Parentid = Ud.ParentID     
   WHERE Ue.Parentid = ' + Convert(varchar(100),@ParentID)       
    
    
  if isnull(@Userid,0) >=0    
  Begin    
  set @Query += N' AND ue.CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN ue.CreatedBy   
  When '+ Convert(varchar(100),@Userid) +' > 0  THEN  ue.CreatedBy  
  ELSE '+ Convert(varchar(100),@Userid) +' END '   
  End    
    
  set @Query += N' ) T Where ' + @FilterText +    
       N' ) A Where ' + case when @Txtsearch = ' (1=1) ' then ' A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) else ' (1=1) ' end    
    
 END    
    
If(@ue_query = '')    
Begin    
 set @ue_query = ' (1=1) '    
End    
    
If(@FilterText != '' and @ue_query != '')    
Begin    
 Set @FilterText += ' AND ' + @ue_query    
End    
    
If(@ordstr = '')    
Begin    
 set @ordstr = ' Enquiryid desc '    
End    
    
 IF(@Pivot_Column IS NOT NULL)    
 BEGIN    
  print 'Branch C'    
 IF(@Txtsearch = ' (1=1) ')-- From Branch A    
 Begin    
  print 'Branch CA'    
    
  SET @Query+=CAST(N';Select 1 From (SELECT rc1 AS [rcnt], EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, RowNumber1, WhereAddress, rc1, ' + @Pivot_Column +     
  N' FROM (SELECT EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks,
  
 SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress, [fieldname], fieldvalue, RowNumber1,  rc1      
  FROM (select E.Enquiryid, E.PersonName, E.CompanyName, E.MobileNo3, E.MobileNo1, E.MobileNo2, E.EmailID3, E.EmailID1, E.EmailID2, E.Residentialaddress, E.Officeaddress, E.User_login, E.MobileNo, E.EmailID, E.City, E.[State], E.Country, E.Countrycode, 
  E.Pincode, E.[ADDRESS], E.Initialremarks, E.SourceName, E.MediumName, E.CampaignName, E.Parentid, E.CreatedDate, E.CreatedDate1, E.Createdby, E.Leads, E.Isopen, E.Img_ext, E.WhereAddress, y.fieldname, x.fieldvalue, E.RowNumber1, E.rc1     
  From #temp2 E left join customfieldEnquiryvalue(nolock) x     
  ON E.Enquiryid = x.Enquiryid left join customfields(nolock) y     
  ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1    
  )q )Tab1    
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2    
  WHERE ' + @Txtsearch + ') T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));    
 End    
 Else    
 Begin    
  print 'Branch CB'    
    
  Select @filterCnt=count(*) From dbo.fn_Split(@Txtsearch, ' ) ')    
      
  --SELECT @Query += CAST(N'; select x.EnquiryID    
  --into #Temp1    
  --from customfieldEnquiryvalue(nolock) x inner join customfields(nolock) y    
  --ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1    
  --Where ' + @Txtsearch + N'    
  --group by x.EnquiryID    
  --having count(*) >= ' + Cast(@filterCnt as NVARCHAR(MAX)) AS NVARCHAR(MAX));    

     SELECT @Query += CAST(N'; select * into #Temp1 From (select [x].EnquiryId, [y].[fieldname], 
	[x].[fieldvalue] from customfieldEnquiryvalue(nolock) x inner join customfields(nolock) y
	ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) T1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @Txtsearch AS NVARCHAR(MAX));

    
 SET @Query+=CAST(N';Select 1 From (SELECT ROW_NUMBER() OVER(ORDER BY EnquiryId Desc) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], count(*) OVER(ORDER BY [ParentID]) AS [rcnt], EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1
, Createdby, Leads, Isopen, Img_ext, WhereAddress FROM (SELECT EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode, Pincode, [ADDRESS], Initialremarks,
  
 SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress   
  FROM (select E.Enquiryid, E.PersonName, E.CompanyName, E.MobileNo3, E.MobileNo1, E.MobileNo2, E.EmailID3, E.EmailID1, E.EmailID2, E.Residentialaddress, E.Officeaddress, E.User_login, E.MobileNo, E.EmailID, E.City, E.[State], E.Country, E.Countrycode,
   E.Pincode, E.[ADDRESS], E.Initialremarks, E.SourceName, E.MediumName, E.CampaignName, E.Parentid, E.CreatedDate, E.CreatedDate1, E.Createdby, E.Leads, E.Isopen, E.Img_ext, E.WhereAddress    
  From #Temp1 A inner join #temp2 E 
   ON A.EnquiryId = E.Enquiryid    
  ) q 
  )Tab1  
  
  ) T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) AS NVARCHAR(MAX)) + N' ORDER BY ' + @ordstr;   
   
 End   
 END   
 ELSE   
 BEGIN   
 print 'Branch D'   
   
 SET @Query += CAST(N'; select 1 from #temp2 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));   
 END   
    
    
 print '@FinalQuery:- ' + cast(@Query as varchar(max))    
 EXEC sp_executesql @Query;    
    
 update kit19_executionlogger    
 set EndDatetime = getdate(), Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)    
 where ID = @LoggerID    
    
 update kit19_executionlogger    
 set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)    
 where ID = @LoggerID    
    
 DROP TABLE IF EXISTS #temp1;    
 DROP TABLE IF EXISTS #temp2;    
    
END  




GO

