SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 -- exec Usp_ViewUserEnquriyDetails_Changedss2121 @Txtsearch=N'',@Parentid=32222,@Userid=0,@FilterText=N' PersonName like  ''%wwf''', @ordstr=N'', @srno=N'1', @enno=N'200', @ue_query=N''    
CREATE   PROCEDURE [dbo].[Usp_ViewUserEnquriyDetails_Changedss2121]    
(                    
 @Txtsearch NVARCHAR(100)='',    
 @Parentid BIGINT,    
 @Userid INT=0,    
 @FilterText nvarchar(max) = '',    
 @ordstr nvarchar(Max)='',    
 @srno NVARCHAR(100),    
 @enno NVARCHAR(100),    
 @ue_query nvarchar(max) = ''    
)                    
AS                                                                                                                            
BEGIN    
    
-- declare @Txtsearch NVARCHAR(100)=N'',@Parentid BIGINT=32821,@Userid INT=33195,@FilterText nvarchar(max)=N'',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N''    
    
	declare @Parameterlist nvarchar(max) , @LoggerID bigint
set @Parameterlist = 'txtSearch : '+ @txtSearch + 'ParentID : '+ CONVERT(VARCHAR(100), @ParentID) + 'Userid : '+ CONVERT(VARCHAR(100), @Userid) + 'FilterText : '+ @FilterText + 'ordstr : '+ @ordstr + 'srno : '+ @srno + 'enno : '+ @enno + 'ue_query : '+ @ue_query;

		insert into kit19_executionlogger(ObjectName,Parameterlist,StartDatetime,EndDatetime,Remarks)
		values('Usp_ViewUserEnquriyDetails_Changedss21',@Parameterlist,getdate(),'','')

		set @LoggerID = Scope_Identity();

    DROP TABLE IF EXISTS #TMPquery;            
 DROP TABLE IF EXISTS #TMPquery1;                    
    DROP TABLE IF EXISTS #temp1;                    
    DROP TABLE IF EXISTS #temp2;                    
    DROP TABLE IF EXISTS #temp3;                    
    DROP TABLE IF EXISTS #MyEnq1;                    
    DROP TABLE IF EXISTS #MyEnq2;                    
                    
    if @srno ='' begin set @srno='1'; end    
 if @enno='' begin set @enno='1000'; end    
                    
    create table #TMPquery (RowNumber int, EnquiryID bigint)            
 create table #TMPquery1 (RowNumber int, EnquiryID bigint)              
    
 IF(@FilterText LIKE '%MobileNo3%')    
 BEGIN    
  set @FilterText = replace(@FilterText,'MobileNo3','MobileNo')    
 END    
 IF(@FilterText LIKE '%IsOpen%close%')    
 BEGIN    
  set @FilterText = replace(@FilterText,'(IsOpen = ''close'' )','(IsOpen = ''0'' )')    
 END    
 IF(@FilterText LIKE '%IsOpen%open%')    
 BEGIN    
  set @FilterText = replace(@FilterText,'(IsOpen = ''open'')','IsOpen = ''1''')    
 END    
               
 declare @Query1 nvarchar(max) = ''               
 if @ue_query <>''                    
 begin                    
    if @FilterText <> ''          
 begin    
  set @Query1 = @Query1 +'insert into #TMPquery (RowNumber,EnquiryID) Select ROW_NUMBER() OVER(Order By '+ @ordstr+ ') AS RowNumber, EnquiryID '    
  set @Query1 = @Query1 +' FROM Userenquiry (NOLOCK) Ue where ParentID = ' + Convert(varchar(100),@ParentID)    
  set @Query1 = @Query1 +' AND ' + @FilterText    
  set @Query1 = @Query1 +' AND ' + @ue_query    
  set @Query1 = @Query1 +' AND ue.CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN ue.CreatedBy ELSE '+ Convert(varchar(100),@Userid) +' END ;'    
 end    
 else    
 begin    
  set @Query1 = @Query1 +'insert into #TMPquery (RowNumber,EnquiryID) Select ROW_NUMBER() OVER(Order By '+ @ordstr+ ') AS RowNumber, EnquiryID '    
  set @Query1 = @Query1 +' FROM Userenquiry (NOLOCK) Ue where ParentID = ' + Convert(varchar(100),@ParentID)    
  set @Query1 = @Query1 +' AND ' + @ue_query    
  set @Query1 = @Query1 +' AND ue.CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN ue.CreatedBy ELSE '+ Convert(varchar(100),@Userid) +' END ;'    
 end    
 end              
else                      
begin                      
    if @ordstr =''          
  if @FilterText <> ''    
  begin    
   set @ordstr = 'Enquiryid desc'    
   set @Query1 = @Query1 +'insert into #TMPquery (RowNumber,EnquiryID) Select ROW_NUMBER() OVER(Order By EnquiryID Desc) AS RowNumber,EnquiryID '    
   set @Query1 = @Query1 +' FROM Userenquiry (NOLOCK) Ue where ParentID = ' + Convert(varchar(100),@ParentID)    
   set @Query1 = @Query1 +' AND ' + @FilterText    
   set @Query1 = @Query1 +' AND ue.CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN ue.CreatedBy ELSE '+ Convert(varchar(100),@Userid) +' END ;'    
  end    
  else    
  begin    
   set @ordstr = 'Enquiryid desc'    
   set @Query1 = @Query1 +'insert into #TMPquery (RowNumber,EnquiryID) Select ROW_NUMBER() OVER(Order By EnquiryID Desc) AS RowNumber,EnquiryID '    
   set @Query1 = @Query1 +' FROM Userenquiry (NOLOCK) Ue where ParentID = ' + Convert(varchar(100),@ParentID)    
   set @Query1 = @Query1 +' AND ue.CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN ue.CreatedBy ELSE '+ Convert(varchar(100),@Userid) +' END ;'    
  end    
end                
               
            
               
   set @Query1 = @Query1 + 'insert INTO #TMPquery1 SELECT RowNumber, EnquiryID from #TMPquery WHERE  RowNumber BETWEEN ' + Convert(varchar(100),@srno) +' AND '+ Convert(varchar(100),@enno)          
   set @Query1 = @Query1 + ' ;'            
    DECLARE @Pivot_Column [nvarchar](max);                 
            
                                                                
    /*Select Pivot Column*/                  
    SELECT @Pivot_Column= COALESCE(@Pivot_Column+',','')+ QUOTENAME(fieldname) FROM                  
    (SELECT DISTINCT [fieldname] FROM customfields (NOLOCK) where ParentID=@ParentID and isActive=1)Tab                  
                                                           
    If(@Pivot_Column is not null)                    
    Begin                    
    /*Create Dynamic Query*/                  
    set @Query1 = @Query1 +cast(N'SELECT EnquiryID as enq, '+@Pivot_Column+' into #temp1 FROM                  
    (SELECT EnquiryID, [fieldname] , fieldvalue FROM               
 (select x.EnquiryID, y.fieldname, x.fieldvalue From customfieldEnquiryvalue (NOLOCK) x               
 inner join customfields (NOLOCK) y on x.fieldID=y.field_ID inner join #TMPquery1 t               
 on x.EnquiryID = t.EnquiryID              
 WHERE y.[ParentID] = ' + cast(@ParentID as nvarchar(max)) + ' AND y.[isActive] = 1)q )Tab1 PIVOT                  
    (  max(fieldvalue) FOR [fieldname] IN ('+@Pivot_Column+')) AS Tab2                  
    ORDER BY Tab2.EnquiryID;' as nvarchar(max))              
    End                 
    Declare @NoCustomFields bigint          
    set @NoCustomFields = (SELECT count(DISTINCT [fieldname]) FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1)
	             
    if(@FilterText = '')                  
    begin                  
        set @FilterText = ' (1=1) '                  
    end                  
     --declare @Query nvarchar(max) = ''                
 declare @Query2 nvarchar(max) = ''                  
 set @Query2 = 'Declare @Rcnt varchar(100)  select  @Rcnt = Count(Enquiryid) from Userenquiry  (NOLOCK) where ParentID = '+ cast(@ParentID as nvarchar(max)) + 'And '+  @FilterText  +' AND CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN
  
 CreatedBy ELSE '+ Convert(varchar(100),@Userid) +' END ;'            
 set @Query1 = @Query1 + @Query2               
                  
                     
    declare @Query nvarchar(max) = ''                      
    set @Query = @Query1 +'SELECT distinct @Rcnt as rcnt, A.Enquiryid,A.Personname,A.Companyname,A.MobileNo3,A.MobileNo1,A.MobileNo2, '                      
    set @Query = @Query +'A.EmailID3,A.EmailID1,A.EmailID2,A.Residentialaddress,A.Officeaddress,A.User_login, '                      
    set @Query = @Query +'A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Pincode,A.[ADDRESS], '                      
    set @Query = @Query +'A.Initialremarks,A.SourceName,A.MediumName,A.CampaignName,A.Parentid,A.CreatedDate, '                      
    set @Query = @Query +'A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,isnull(A.img_ext,'''') as img_ext,A.RowNumber into #Temp2'              
 set @Query = @Query + ' FROM ( SELECT  distinct @Rcnt as rcnt,Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno,ltrim(Ue.Countrycode+'' ''+Ue.Mobileno)+ case when isnull(Ue.Mobileno1,'''')<>'''' then '', ...'' else '''' end AS MobileNo3,Ue.Mobileno1,
  
 '                      
    set @Query = @Query +'Ue.Mobileno2,Ue.Emailid ,Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress, '                      
    set @Query = @Query +'Ud.User_login,Ue.CreatedDate , '                      
    set @Query = @Query +' Ue.City, Ue.[State], Ue.Country, Ue.Countrycode, Ue.Pincode, '                      
    set @Query = @Query +' CASE WHEN Ue.Companyname <> '''' THEN     
 Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END      
   ELSE Ue.Residentialaddress END AS [ADDRESS],'                      
    set @Query = @Query +' Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName, '                      
    set @Query = @Query +' Ue.Parentid,CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), '                      
    set @Query = @Query +' Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, '                      
    set @Query = @Query+ 'ue.LeadNo AS Leads,'                      
    set @Query = @Query +' (CASE WHEN Ue.Isopen = ''1'' THEN ''open'' ELSE (CASE WHEN Ue.Isopen = ''0'' THEN ''close'' ELSE ''lead'' END) END) as Isopen, Ue.img_ext, '                      
    set @Query = @Query +' Te.RowNumber  FROM Userenquiry (NOLOCK)  Ue inner join #TMPquery1 Te on Ue.EnquiryID = Te.EnquiryID '                      
    set @Query = @Query +' INNER JOIN Usersourcesettings (NOLOCK) Uss ON Ue.Sourcename = Uss.Sourceid'                      
 set @Query = @Query +' LEFT JOIN Usermediumsettings (NOLOCK) Ums ON Ue.Mediumname = Ums.Mediumid '                      
    set @Query = @Query +' LEFT JOIN Usercampaignsettings (NOLOCK) Ucs ON Ue.Campaignname = Ucs.Campaignid '                      
    set @Query = @Query +' LEFT JOIN User_detail (NOLOCK) Ud ON Ue.Createdby = Ud.User_id and Ue.Parentid = Ud.ParentID '                      
    set @Query = @Query +' WHERE Ue.Parentid = '+ Convert(varchar(100),@ParentID)                      
                 
                      
    if @Userid >0                      
    set @Query = @Query + ' AND ue.CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN ue.CreatedBy ELSE '+ Convert(varchar(100),@Userid) +' END '    
    
    set @Query = @Query +' ) A Order by ' + @ordstr                      
                      
    set @Query += cast(N' IF OBJECT_ID(''tempdb..#temp1'') IS NOT NULL                      
    begin                      
    select * into #MyEnq1 from #Temp2 x left join #temp1 y on x.Enquiryid=y.enq           
        alter table #MyEnq1 drop column enq;                      
    select * from (select ROW_NUMBER() OVER(Order By Enquiryid desc) AS RowNumber1,@Rcnt AS rc1, * from #MyEnq1)aa where RowNumber between ' + @srno + ' and ' + @enno + '                        
    end                      
    else                      
    begin                      
    select * into #MyEnq2 from #Temp2                       
     select * from (select ROW_NUMBER() OVER(Order By Enquiryid desc) AS RowNumber1,@Rcnt AS rc1, * from #MyEnq2)aa where RowNumber between ' + @srno + ' and ' + @enno + ' end' as nvarchar(max))                      
                   
    -- print '@FinalQuery:- ' + cast(@Query as varchar(max))    
    EXEC sp_executesql @Query;                       
                    
	update kit19_executionlogger
	set EndDatetime =  getdate(), Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)
	where ID = @LoggerID

    DROP TABLE IF EXISTS #TMPquery;               
 DROP TABLE IF EXISTS #TMPquery1;                    
    DROP TABLE IF EXISTS #temp1;                    
    DROP TABLE IF EXISTS #temp2;                    
    DROP TABLE IF EXISTS #temp3;                    
    DROP TABLE IF EXISTS #MyEnq1;                    
    DROP TABLE IF EXISTS #MyEnq2;                    
                    
END 


