 /*Select Pivot Column*/
 SELECT @Pivot_Column= COALESCE(@Pivot_Column+',','')+ QUOTENAME(fieldname) FROM
 (SELECT DISTINCT [fieldname] FROM customfields (NOLOCK) where ParentID=@ParentID and isActive=1)Tab


 Declare @NoCustomFields bigint, @filterCnt int=0
 set @NoCustomFields = (SELECT count(DISTINCT [fieldname]) FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1)

  declare @admin bit = 0
   select top 1 @admin = isnull(IsAdmin,0) from User_Detail with(nolock) where User_ID = @Userid             
   if(@admin = 1)
      begin
	     set @Userid = 0
	  end


 declare @Query nvarchar(max) = ''

IF(@FilterText = ' (1=1) ' and @Txtsearch = ' (1=1) ')
BEGIN
	--print 'Branch A'

	 set @Query = N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname,A.MobileNo3,A.MobileNo1,A.MobileNo2,A.EmailID3,A.EmailID1,A.EmailID2,A.Residentialaddress,
	  A.Officeaddress,A.User_login,A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Countrycode1,A.Countrycode2,A.Pincode,A.[ADDRESS], A.Initialremarks,
	  A.SourceName,A.MediumName,A.CampaignName,A.Parentid,A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,
	  isnull(A.img_ext,'''') as img_ext, A.WhereAddress, RowNumber1, rc1, A.IsduplicateEmail, A.IsduplicateMobile 
	  into #Temp2
	  FROM 
	  ( 
		SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno,ltrim(Ue.Countrycode+'' ''+Ue.Mobileno)+ case when isnull(Ue.Mobileno1,'''')<>'''' then '', ...'' else '''' end AS MobileNo3, Ue.Mobileno1, Ue.Mobileno2,Ue.Emailid ,
		Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress, Ud.User_login,Ue.CreatedDate , Ue.City, 
		Ue.[State], Ue.Country,Ue.Countrycode,Ue.Countrycode1,Ue.Countrycode2,Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], 
		Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), 
		Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads,
		(CASE WHEN isnull(ue.isopen,1)=1 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress,
		ROW_NUMBER() OVER(ORDER BY Ue.Enquiryid DESC) AS RowNumber1, count(*) OVER(ORDER BY Ue.Parentid) AS rc1, Ue.IsduplicateEmail, Ue.IsduplicateMobile

	 FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss 
	 ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums 
	 ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs 
	 ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud 
	 ON Ue.Createdby = Ud.User_id and Ue.Parentid = Ud.ParentID 
	 WHERE Ue.Parentid = '+ Convert(varchar(100),@Parentid)


	 if @Userid >0
	 Begin
		set @Query += N' AND ue.CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN ue.CreatedBy ELSE '+ Convert(varchar(100),@Userid) +' END '
	 End

	 set @Query += N' ) A Where A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) 

 END
 ELSE
 BEGIN
	--print 'Branch B'

	 set @Query += N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname,A.MobileNo3,A.MobileNo1,A.MobileNo2,A.EmailID3,A.EmailID1,A.EmailID2,A.Residentialaddress,
	  A.Officeaddress,A.User_login,A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Countrycode1,A.Countrycode2,A.Pincode,A.[ADDRESS], A.Initialremarks,
	  A.SourceName,A.MediumName,A.CampaignName,A.Parentid,A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,
	  isnull(A.img_ext,'''') as img_ext, A.WhereAddress, RowNumber1, rc1, A.IsduplicateEmail, A.IsduplicateMobile
	  into #Temp2
	  FROM 
	  ( 
		Select *, ROW_NUMBER() OVER(ORDER BY T.Enquiryid DESC) AS RowNumber1, count(*) OVER(ORDER BY T.Parentid) AS rc1  
		From 
		(
			SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno,ltrim(Ue.Countrycode+'' ''+Ue.Mobileno)+ case when isnull(Ue.Mobileno1,'''')<>'''' then '', ...'' else '''' end AS MobileNo3, Ue.Mobileno1, Ue.Mobileno2,Ue.Emailid ,
			Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress, Ud.User_login,Ue.CreatedDate , Ue.City, 
			Ue.[State], Ue.Country, Ue.Countrycode,Ue.Countrycode1,Ue.Countrycode2,Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], 
			Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26),
			Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads,
			(CASE WHEN isnull(ue.isopen,1)=1 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress,Ue.IsduplicateEmail, Ue.IsduplicateMobile
			FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss 
			ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums 
			ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs 
			ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud 
			ON Ue.Createdby = Ud.User_id and Ue.Parentid = Ud.ParentID 
			WHERE Ue.Parentid = ' + Convert(varchar(100),@ParentID)   


	 if @Userid >0
	 Begin
		set @Query += N' AND ue.CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN ue.CreatedBy ELSE '+ Convert(varchar(100),@Userid) +' END '
	 End

	 set @Query += N' ) T Where ' + @FilterText +
				   N' ) A Where ' + case when @Txtsearch = ' (1=1) ' then ' A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) else ' (1=1) ' end

 END

If(@ue_query = '')
Begin
	set @ue_query = ' (1=1) '
End

If(@FilterText != '' and @ue_query != '')
Begin
	Set @FilterText += ' AND ' + @ue_query
End

If(@ordstr = '')
Begin
	set @ordstr = ' Enquiryid desc '
End

 IF(@Pivot_Column IS NOT NULL)
 BEGIN
 	--print 'Branch C'
	IF(@Txtsearch = ' (1=1) ')-- From Branch A
	Begin
		--print 'Branch CA'

		SET @Query+=CAST(N';select EnquiryId as ID, PersonName, CompanyName,MobileNo, MobileNo1, MobileNo2,Countrycode,Countrycode1,Countrycode2,EmailID, EmailID1, EmailID2, City, [State],
		Country, Pincode, Residentialaddress, Officeaddress, SourceName, MediumName, CampaignName, Initialremarks,CreatedDate
		From (SELECT rc1 AS [rcnt], EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo,
		EmailID, City, [State], Country,Countrycode,Countrycode1,Countrycode2,Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate,
		CreatedDate1, Createdby, Leads, Isopen, Img_ext, RowNumber1, WhereAddress, rc1, IsduplicateEmail, IsduplicateMobile,' + @Pivot_Column + 
		N' FROM (SELECT EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, 
		User_login, MobileNo, EmailID, City, [State], Country,Countrycode,Countrycode1,Countrycode2, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName,
		CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress, [fieldname], fieldvalue, RowNumber1,  rc1, IsduplicateEmail, IsduplicateMobile  
		FROM (select E.Enquiryid, E.PersonName, E.CompanyName, E.MobileNo3, E.MobileNo1, E.MobileNo2, E.EmailID3, E.EmailID1, E.EmailID2, E.Residentialaddress,
		E.Officeaddress, E.User_login, E.MobileNo, E.EmailID, E.City, E.[State], E.Country,E.Countrycode,E.Countrycode1,E.Countrycode2,E.Pincode, E.[ADDRESS], E.Initialremarks, E.SourceName,
		E.MediumName, E.CampaignName, E.Parentid, E.CreatedDate, E.CreatedDate1, E.Createdby, E.Leads, E.Isopen, E.Img_ext, E.WhereAddress, y.fieldname, x.fieldvalue, E.RowNumber1, E.rc1,
		E.IsduplicateEmail, E.IsduplicateMobile 
		From #temp2 E left join customfieldEnquiryvalue(nolock) x 
		ON E.Enquiryid = x.Enquiryid left join customfields(nolock) y 
		ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1
		)q )Tab1
		PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2
		WHERE ' + @Txtsearch + ') T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));
	End
	Else
	Begin
		--print 'Branch CB'

		Select @filterCnt=count(*) From dbo.fn_Split(@Txtsearch, ' ) ')
	
	  /*
		SELECT @Query += CAST(N'; select x.EnquiryID
		into #Temp1
		from customfieldEnquiryvalue(nolock) x inner join customfields(nolock) y
		ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1
		Where ' + @Txtsearch + N'
		group by x.EnquiryID
		having count(*) >= ' + Cast(@filterCnt as NVARCHAR(MAX)) AS NVARCHAR(MAX));
		*/

			SELECT @Query += CAST(N'; select * into #Temp1 From (select [x].EnquiryId, [y].[fieldname], 
	[x].[fieldvalue] from customfieldEnquiryvalue(nolock) x inner join customfields(nolock) y
	ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) T1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @Txtsearch AS NVARCHAR(MAX));





		SET @Query+=CAST(N';Select EnquiryId as ID, PersonName, CompanyName,MobileNo, MobileNo1, MobileNo2,Countrycode,Countrycode1,Countrycode2,EmailID, EmailID1, EmailID2, City,
		[State], Country, Pincode, Residentialaddress, Officeaddress, SourceName, MediumName, CampaignName, Initialremarks,CreatedDate
		From (SELECT ROW_NUMBER() OVER(ORDER BY EnquiryId Desc) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], count(*) OVER(ORDER BY [ParentID]) AS [rcnt], EnquiryId, PersonName,
		CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country,Countrycode,
		Countrycode1,Countrycode2,Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress,
		IsduplicateEmail, IsduplicateMobile,   ' + @Pivot_Column + 
		N' FROM (SELECT EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City,
		[State], Country, Countrycode,Countrycode1,Countrycode2 ,Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads,
		Isopen, Img_ext, WhereAddress, [fieldname] ,fieldvalue,IsduplicateEmail, IsduplicateMobile  
		FROM (select E.Enquiryid, E.PersonName, E.CompanyName, E.MobileNo3, E.MobileNo1, E.MobileNo2, E.EmailID3, E.EmailID1, E.EmailID2, E.Residentialaddress, E.Officeaddress, E.User_login,
		E.MobileNo, E.EmailID, E.City, E.[State], E.Country,E.Countrycode,E.Countrycode1,E.Countrycode2, E.Pincode, E.[ADDRESS], E.Initialremarks, E.SourceName, E.MediumName, E.CampaignName,
		E.Parentid, E.CreatedDate, E.CreatedDate1, E.Createdby, E.Leads, E.Isopen, E.Img_ext, E.WhereAddress, y.fieldname, x.fieldvalue ,E.IsduplicateEmail, E.IsduplicateMobile  
		From #Temp1 A inner join #temp2 E 
		ON A.EnquiryId = E.Enquiryid left join customfieldEnquiryvalue(nolock) x 
		ON E.Enquiryid = x.Enquiryid left join customfields(nolock) y 
		ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1
		)q )Tab1
		PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2
		) T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) AS NVARCHAR(MAX)) + N' ORDER BY ' + @ordstr;

	End
 END
 ELSE
 BEGIN
	--print 'Branch D'

	SET @Query += CAST(N'; select EnquiryId as ID, PersonName, CompanyName,MobileNo, MobileNo1, MobileNo2,Countrycode,Countrycode1,Countrycode2,EmailID, EmailID1, EmailID2, City, [State], 
	Country, Pincode, Residentialaddress, Officeaddress, SourceName, MediumName, CampaignName, Initialremarks,CreatedDate
	from #temp2 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));
 END

 
 --print '@FinalQuery:- ' + cast(@Query as varchar(max))
 EXEC sp_executesql @Query;

 update kit19_executionlogger
 set EndDatetime = getdate(), Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)
 where ID = @LoggerID

 update kit19_executionlogger
 set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)
 where ID = @LoggerID

 DROP TABLE IF EXISTS #temp1;
 DROP TABLE IF EXISTS #temp2;

END
 



GO

