CREATE   PROCEDURE [dbo].[Usp_ViewUserEnquriyDetails_DynamicSearchForConv_Search]
  (
 @Txtsearch NVARCHAR(max)='',
 @Parentid BIGINT,
 @Userid INT=0,
 @FilterText nvarchar(max) = '',
 @ordstr nvarchar(Max)='',
 @srno NVARCHAR(100),
 @enno NVARCHAR(100),
 @ue_query nvarchar(max) = ''
)
AS
BEGIN

   --  Declare 
   --  @txtSearch NVARCHAR(max) = N' (cast(Course_01_Name as nvarchar(max)) like ''%0%'')  
   --    and  (cast(Course_01_Expire_Date as date) between ''01/20/2021'' and ''09/21/2024'' ) ',                                          
   ----@txtSearch NVARCHAR(max) = N' (1=1) ',                                          

   -- @ParentID BIGINT = 40834,                                          
   -- @Userid INT= 40834,                                          
   -- @FilterText NVARCHAR(MAX) = '',                                          
   --@srno NVARCHAR(100)= N'1',                                          
   --@enno NVARCHAR(100)= N'20',        
   --@ordstr nvarchar(Max)=N'' ,      
   --@ue_query nvarchar(max) = N'' 


-- declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=32222,@Userid INT=0,@FilterText nvarchar(max)=N'',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N''  -- AC
-- declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=32222,@Userid INT=0,@FilterText nvarchar(max)=N' (Personname like ''%test%'') ',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N'' -- BCA
-- declare @Txtsearch NVARCHAR(max)=N'( fieldname=''test02'' and cast(fieldvalue as varchar(50)) like  ''%2%'' )  or  ( fieldname=''test03'' and cast(fieldvalue as varchar(50)) like  ''%3%'' ) ',@Parentid BIGINT=32222,@Userid INT=0,@FilterText nvarchar(max)=N' (Personname like ''%test%'') ',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N'' -- BCB
-- declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=38750,@Userid INT=0,@FilterText nvarchar(max)=N'',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N''  -- AD

--declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=38750,@Userid INT=0,@FilterText nvarchar(max)=N' (Personname like ''%test%'') ',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N'' -- BD

 declare @Parameterlist nvarchar(max) , @LoggerID bigint
 set @Parameterlist = 'txtSearch : '+ @txtSearch + ' ,ParentID : '+ CONVERT(VARCHAR(100), @ParentID) + ' ,Userid : '+ CONVERT(VARCHAR(100), @Userid) + ' ,FilterText : '+ @FilterText + ' ,ordstr : '+ @ordstr + ' ,srno : '+ @srno + ' ,enno : '+ @enno + ' ,ue_query : '+ @ue_query;

 insert into kit19_executionlogger(ObjectName,Parameterlist,StartDatetime,EndDatetime,Remarks)
 values('Usp_ViewUserEnquriyDetails_DynamicSearchForConv_Search',@Parameterlist,getdate(),'','')

 set @LoggerID = Scope_Identity();

 DROP TABLE IF EXISTS #temp1;
 DROP TABLE IF EXISTS #temp2;

 if @srno ='' begin set @srno='1'; end
 if @enno='' begin set @enno='20'; end


IF(@Txtsearch = '')        
BEGIN        
 SET @Txtsearch = N' (1=1) ';        
END;

IF(@FilterText = '')
BEGIN
 SET @FilterText = N' (1=1) ';        
END;        

 IF(@FilterText LIKE '%MobileNo3%')
 BEGIN
set @FilterText = replace(@FilterText,'MobileNo3','MobileNo')
 END

 declare @Query1 nvarchar(max) = ''
 DECLARE @Pivot_Column [nvarchar](max);


 /*Select Pivot Column*/
 SELECT @Pivot_Column= COALESCE(@Pivot_Column+',','')+ QUOTENAME(fieldname) FROM
 (SELECT DISTINCT [fieldname] FROM customfields (NOLOCK) where ParentID=@ParentID and isActive=1)Tab


 Declare @NoCustomFields bigint, @filterCnt int=0
 set @NoCustomFields = (SELECT count(DISTINCT [fieldname]) FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1)

     Declare @IsAdmin bit = 0
	 SELECT @IsAdmin = IsAdmin
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @ParentID

	IF (@IsAdmin = 1)
	BEGIN
		SET @Userid = 0;
	END   


 declare @Query nvarchar(max) = ''

IF(@FilterText = ' (1=1) ' and @Txtsearch = ' (1=1) ')
BEGIN
	--print 'Branch A'

	 set @Query = N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname,A.MobileNo3,A.MobileNo1,A.MobileNo2,A.EmailID3,A.EmailID1,A.EmailID2,A.Residentialaddress,
	  A.Officeaddress,A.User_login,A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Countrycode1,A.Countrycode2,A.Pincode,A.[ADDRESS], A.Initialremarks,
	  A.SourceName,A.MediumName,A.CampaignName,A.Parentid,A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,
	  isnull(A.img_ext,'''') as img_ext, A.WhereAddress, RowNumber1, rc1, A.WhatsAppNoColName 
	  into #Temp2
	  FROM 
	  ( 
		SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno,ltrim(Ue.Countrycode+'' ''+Ue.Mobileno)+ case when isnull(Ue.Mobileno1,'''')<>'''' then '', ...'' else '''' end AS MobileNo3, Ue.Mobileno1, Ue.Mobileno2,Ue.Emailid ,
		Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress, Ud.User_login,Ue.CreatedDate , Ue.City, 
		Ue.[State], Ue.Country,Ue.Countrycode,Ue.Countrycode1,Ue.Countrycode2,Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads, (CASE WHEN isnull(ue.isopen,1)=1 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress, ROW_NUMBER() OVER(ORDER BY Ue.Enquiryid DESC) AS RowNumber1, count(*) OVER(ORDER BY Ue.Parentid) AS rc1, Ue.WhatsAppNoColName
	 FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss 
	 ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums 
	 ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs 
	 ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud 
	 ON Ue.Createdby = Ud.User_id and Ue.Parentid = Ud.ParentID 
	 WHERE Ue.Parentid = '+ Convert(varchar(100),@Parentid)


	 if isnull(@Userid,0) >=0
	 Begin
		set @Query += N' AND ue.CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN ue.CreatedBy ELSE '+ Convert(varchar(100),@Userid) +' END '
	 End

	 set @Query += N' ) A Where A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) 

 END
 ELSE
 BEGIN
	--print 'Branch B'

	 set @Query += N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname,A.MobileNo3,A.MobileNo1,A.MobileNo2,A.EmailID3,A.EmailID1,A.EmailID2,A.Residentialaddress,
	  A.Officeaddress,A.User_login,A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Countrycode1,A.Countrycode2,A.Pincode,A.[ADDRESS], A.Initialremarks,
	  A.SourceName,A.MediumName,A.CampaignName,A.Parentid,A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,
	  isnull(A.img_ext,'''') as img_ext, A.WhereAddress, RowNumber1, rc1 , A.WhatsAppNoColName
	  into #Temp2
	  FROM 
	  ( 
		Select *, ROW_NUMBER() OVER(ORDER BY T.Enquiryid DESC) AS RowNumber1, count(*) OVER(ORDER BY T.Parentid) AS rc1  
		From 
		(
			SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno,ltrim(Ue.Countrycode+'' ''+Ue.Mobileno)+ case when isnull(Ue.Mobileno1,'''')<>'''' then '', ...'' else '''' end AS MobileNo3, Ue.Mobileno1, Ue.Mobileno2,Ue.Emailid ,
			Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress, Ud.User_login,Ue.CreatedDate , Ue.City, 
			Ue.[State], Ue.Country, Ue.Countrycode,Ue.Countrycode1,Ue.Countrycode2,Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS], Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby, CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads, (CASE WHEN isnull(ue.isopen,1)=1 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress,Ue.WhatsAppNoColName
			FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss 
			ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums 
			ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs 
			ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud 
			ON Ue.Createdby = Ud.User_id and Ue.Parentid = Ud.ParentID 
			WHERE Ue.Parentid = ' + Convert(varchar(100),@ParentID)   


	 if isnull(@Userid,0) >=0
	 Begin
		set @Query += N' AND ue.CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN ue.CreatedBy ELSE '+ Convert(varchar(100),@Userid) +' END '
	 End

	 set @Query += N' ) T Where ' + @FilterText +
				   N' ) A Where ' + case when @Txtsearch = ' (1=1) ' then ' A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) else ' (1=1) ' end

 END

If(@ue_query = '')
Begin
	set @ue_query = ' (1=1) '
End

If(@FilterText != '' and @ue_query != '')
Begin
	Set @FilterText += ' AND ' + @ue_query
End

If(@ordstr = '')
Begin
	set @ordstr = ' Enquiryid desc '
End

 IF(@Pivot_Column IS NOT NULL)
 BEGIN
 	--print 'Branch C'
	IF(@Txtsearch = ' (1=1) ')-- From Branch A
	Begin
		--print 'Branch CA'

		SET @Query+=CAST(N';select EnquiryId as ID, PersonName, CompanyName,MobileNo, MobileNo1, MobileNo2,Countrycode,Countrycode1,Countrycode2,EmailID, EmailID1, EmailID2, City, [State], Country, Pincode, Residentialaddress, Officeaddress, SourceName, MediumName, CampaignName, Initialremarks,CreatedDate,WhatsAppNoColName From (SELECT rc1 AS [rcnt], EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country,Countrycode,Countrycode1,Countrycode2,Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, RowNumber1, WhereAddress,WhatsAppNoColName ,rc1, ' + @Pivot_Column + 
		N' FROM (SELECT EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country,Countrycode,Countrycode1,Countrycode2, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress, [fieldname], fieldvalue, RowNumber1,  rc1,WhatsAppNoColName  
		FROM (select E.Enquiryid, E.PersonName, E.CompanyName, E.MobileNo3, E.MobileNo1, E.MobileNo2, E.EmailID3, E.EmailID1, E.EmailID2, E.Residentialaddress, E.Officeaddress, E.User_login, E.MobileNo, E.EmailID, E.City, E.[State], E.Country,E.Countrycode,E.Countrycode1,E.Countrycode2,E.Pincode, E.[ADDRESS], E.Initialremarks, E.SourceName, E.MediumName, E.CampaignName, E.Parentid, E.CreatedDate, E.CreatedDate1, E.Createdby, E.Leads, E.Isopen, E.Img_ext, E.WhereAddress, y.fieldname, x.fieldvalue, E.RowNumber1, E.rc1,E.WhatsAppNoColName 
		From #temp2 E left join customfieldEnquiryvalue(nolock) x 
		ON E.Enquiryid = x.Enquiryid left join customfields(nolock) y 
		ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1
		)q )Tab1
		PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2
		WHERE ' + @Txtsearch + ') T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));
	End
	Else
	Begin
	--	print 'Branch CB'

		Select @filterCnt=count(*) From dbo.fn_Split(@Txtsearch, ' ) ')
		
		--SELECT @Query += CAST(N'; select x.EnquiryID
		--into #Temp1
		--from customfieldEnquiryvalue(nolock) x inner join customfields(nolock) y
		--ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1
		--Where ' + @Txtsearch + N'
		--group by x.EnquiryID
		--having count(*) >= ' + Cast(@filterCnt as NVARCHAR(MAX)) AS NVARCHAR(MAX));

		SELECT @Query += CAST(N'; select * into #Temp1 From (select [x].EnquiryId, [y].[fieldname], 
	[x].[fieldvalue] from customfieldEnquiryvalue(nolock) x inner join customfields(nolock) y
	ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) T1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @Txtsearch AS NVARCHAR(MAX));


		SET @Query+=CAST(N';Select EnquiryId as ID, PersonName, CompanyName,MobileNo, MobileNo1, MobileNo2,Countrycode,Countrycode1,Countrycode2,EmailID, EmailID1, EmailID2, City, [State], Country, Pincode, Residentialaddress, Officeaddress, SourceName, MediumName, CampaignName, Initialremarks,CreatedDate,WhatsAppNoColName From (SELECT ROW_NUMBER() OVER(ORDER BY EnquiryId Desc) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], count(*) OVER(ORDER BY [ParentID]) AS [rcnt], EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country,Countrycode,Countrycode1,Countrycode2,Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress,WhatsAppNoColName FROM (SELECT EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode,Countrycode1,Countrycode2 ,Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress,WhatsAppNoColName
		FROM (select E.Enquiryid, E.PersonName, E.CompanyName, E.MobileNo3, E.MobileNo1, E.MobileNo2, E.EmailID3, E.EmailID1, E.EmailID2, E.Residentialaddress, E.Officeaddress, E.User_login, E.MobileNo, E.EmailID, E.City, E.[State], E.Country,E.Countrycode,E.Countrycode1,E.Countrycode2, E.Pincode, E.[ADDRESS], E.Initialremarks, E.SourceName, E.MediumName, E.CampaignName, E.Parentid, E.CreatedDate, E.CreatedDate1, E.Createdby, E.Leads, E.Isopen, E.Img_ext, E.WhereAddress, E.WhatsAppNoColName
		From #Temp1 A inner join #temp2 E 
		ON A.EnquiryId = E.Enquiryid 
		)q )Tab1
		) T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) AS NVARCHAR(MAX)) + N' ORDER BY ' + @ordstr;

	End
 END
 ELSE
 BEGIN
	--print 'Branch D'

	SET @Query += CAST(N'; select EnquiryId as ID, PersonName, CompanyName,MobileNo, MobileNo1, MobileNo2,Countrycode,Countrycode1,Countrycode2,EmailID, EmailID1, EmailID2, City, [State], Country, Pincode, Residentialaddress, Officeaddress, SourceName, MediumName, CampaignName, Initialremarks,CreatedDate,WhatsAppNoColName from #temp2 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));
 END


 --print '@FinalQuery:- ' + cast(@Query as varchar(max))
 EXEC sp_executesql @Query;

 update kit19_executionlogger
 set EndDatetime = getdate(), Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)
 where ID = @LoggerID

 update kit19_executionlogger
 set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)
 where ID = @LoggerID

 DROP TABLE IF EXISTS #temp1;
 DROP TABLE IF EXISTS #temp2;

END



GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserEnquriyDetails_DynamicSearchForConv_Search_startentityid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec Usp_ViewUserEnquriyDetails_Changedss21 @Txtsearch=N'',@Parentid=35610,@Userid=0,@FilterText=N'',@ordstr=N'',@srno=N'1',@enno=N'4000',@ue_query=N''   
-- exec Usp_ViewUserEnquriyDetails_Changedss21 @Txtsearch=N'',@Parentid=32821,@Userid=33195,@FilterText=N'',@ordstr=N'',@srno=N'1',@enno=N'20',@ue_query=N''  
-- exec Usp_ViewUserEnquriyDetails_Changedss21 @Txtsearch=N'',@Parentid=4827,@Userid=33520,@FilterText=N'',@ordstr=N'',@srno=N'1',@enno=N'4000',@ue_query=N''  
-- exec Usp_ViewUserEnquriyDetails_Changedss21 @Txtsearch=N'',@Parentid=32222,@Userid=0,@FilterText=N' PersonName like''%wwf''', @ordstr=N'', @srno=N'1', @enno=N'200', @ue_query=N''  
-- exec Usp_ViewUserEnquriyDetails_Changedss21_mkb @Txtsearch=N'',@Parentid=32222,@Userid=0,@FilterText=N' (SourceName = ''EshopSignUp'') ',@ordstr=N'',@srno=N'1',@enno=N'20',@ue_query=N''  
 -- exec [Usp_ViewUserEnquriyDetails_Changedss21_mkb] @Txtsearch=N'',@Parentid=335,@Userid=0,@FilterText=N' PersonName like''%''', @ordstr=N'', @srno=N'1', @enno=N'200', @ue_query=N''  
--  exec Usp_ViewUserEnquriyDetails_DynamicSearchForConv_Search_startentityid  @Txtsearch=' (1=1) ',@Parentid =50327, @Userid =50327,@FilterText = '((MobileNo IS NOT NULL AND LTRIM(RTRIM(MobileNo)) <> '''' AND MobileNo <> ''0'')  OR (MobileNo1 IS NOT NULL AND LTRIM(RTRIM(MobileNo1)) <> '''' AND MobileNo1 <> ''0'')  OR (MobileNo2 IS NOT NULL AND LTRIM(RTRIM(MobileNo2)) <> '''' AND MobileNo2 <> ''0'')) and  ( ( EnquiryID > 0 ) ) ',@ordstr=' enquiryid ',@srno ='1',@enno ='50',@ue_query = '',@start_entityid = 0 

CREATE   PROCEDURE [dbo].[Usp_ViewUserEnquriyDetails_DynamicSearchForConv_Search_startentityid]  
  (  
 @Txtsearch NVARCHAR(max)='',  
 @Parentid BIGINT,  
 @Userid INT=0,  
 @FilterText nvarchar(max) = '',  
 @ordstr nvarchar(Max)='',  
 @srno NVARCHAR(100),  
 @enno NVARCHAR(100),  
 @ue_query nvarchar(max) = '',  
 @start_entityid bigint  
)  
AS  
BEGIN  
  
   --  Declare                                          
   --@txtSearch NVARCHAR(max) = N' (1=1) ',
   -- @ParentID BIGINT = 50327,                                            
   -- @Userid INT= 50327,                                            
   -- @FilterText NVARCHAR(MAX) = N'((MobileNo IS NOT NULL AND LTRIM(RTRIM(MobileNo)) <> '''' AND MobileNo <> ''0'')  OR (MobileNo1 IS NOT NULL AND LTRIM(RTRIM(MobileNo1)) <> '''' AND MobileNo1 <> ''0'')  OR (MobileNo2 IS NOT NULL AND LTRIM(RTRIM(MobileNo2)) <> '''' AND MobileNo2 <> ''0'')) and  ( ( EnquiryID > 0 ) )',                                            
   --@srno NVARCHAR(100)= N'1',                                            
   --@enno NVARCHAR(100)= N'50',          
   --@ordstr nvarchar(Max)=N' enquiryid ' ,        
   --@ue_query nvarchar(max) = N'',
   --@start_entityid bigint=0
  
  
-- declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=32222,@Userid INT=0,@FilterText nvarchar(max)=N'',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N''  -- AC  
-- declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=32222,@Userid INT=0,@FilterText nvarchar(max)=N' (Personname like ''%test%'') ',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N'' -- BCA  
-- declare @Txtsearch NVARCHAR(max)=N'( fieldname=''test02'' and cast(fieldvalue as varchar(50)) like  ''%2%'' )  or  ( fieldname=''test03'' and cast(fieldvalue as varchar(50)) like  ''%3%'' ) ',@Parentid BIGINT=32222,@Userid INT=0,@FilterText nvarchar(max)=N' (Personname like ''%test%'') ',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N'' -- BCB  
-- declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=38750,@Userid INT=0,@FilterText nvarchar(max)=N'',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N''  -- AD  
  
--declare @Txtsearch NVARCHAR(max)=N'',@Parentid BIGINT=38750,@Userid INT=0,@FilterText nvarchar(max)=N' (Personname like ''%test%'') ',@ordstr nvarchar(Max)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ue_query NVARCHAR(100)=N'' -- BD  
  
 declare @Parameterlist nvarchar(max) , @LoggerID bigint  
 set @Parameterlist = 'txtSearch : '+ @txtSearch + ' ,ParentID : '+ CONVERT(VARCHAR(100), @ParentID) + ' ,Userid : '+ CONVERT(VARCHAR(100), @Userid) + ' ,FilterText : '+ @FilterText + ' ,ordstr : '+ @ordstr + ' ,srno : '+ @srno + ' ,enno : '+ @enno + ' ,ue_query : '+ @ue_query;  
  
 insert into kit19_executionlogger(ObjectName,Parameterlist,StartDatetime,EndDatetime,Remarks)  
 values('Usp_ViewUserEnquriyDetails_DynamicSearchForConv_Search',@Parameterlist,getdate(),'','')  
  
 set @LoggerID = Scope_Identity();  
  
 DROP TABLE IF EXISTS #temp1;  
 DROP TABLE IF EXISTS #temp2;  
  
 if @srno ='' begin set @srno='1'; end  
 if @enno='' begin set @enno='20'; end  
  
  
IF(@Txtsearch = '')          
BEGIN          
 SET @Txtsearch = N' (1=1) ';          
END;  
  
IF(@FilterText = '')  
BEGIN  
 SET @FilterText = N' (1=1) ';          
END;          
  
 IF(@FilterText LIKE '%MobileNo3%')  
 BEGIN  
set @FilterText = replace(@FilterText,'MobileNo3','MobileNo')  
 END  
  
 declare @Query1 nvarchar(max) = ''  
 DECLARE @Pivot_Column [nvarchar](max);  
  
  
 /*Select Pivot Column*/  
 SELECT @Pivot_Column= COALESCE(@Pivot_Column+',','')+ QUOTENAME(fieldname) FROM  
 (SELECT DISTINCT [fieldname] FROM customfields (NOLOCK) where ParentID=@ParentID and isActive=1)Tab  
  
  
 Declare @NoCustomFields bigint, @filterCnt int=0  
 set @NoCustomFields = (SELECT count(DISTINCT [fieldname]) FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1)  
  
     Declare @IsAdmin bit = 0  
  SELECT @IsAdmin = IsAdmin  
 FROM User_Detail(NOLOCK)  
 WHERE User_ID = @ParentID  
  
 IF (@IsAdmin = 1)  
 BEGIN  
  SET @Userid = 0;  
 END     
  
  
 declare @Query nvarchar(max) = ''  
  
IF(@FilterText = ' (1=1) ' and @Txtsearch = ' (1=1) ')  
BEGIN  
 print 'Branch A'  
  
  set @Query = N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname,A.MobileNo3,A.MobileNo1,A.MobileNo2,A.EmailID3,A.EmailID1,A.EmailID2,A.Residentialaddress,
   A.Officeaddress,A.User_login,A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Countrycode1,A.Countrycode2,A.Pincode,
   A.[ADDRESS], A.Initialremarks, A.SourceName,A.MediumName,A.CampaignName,A.Parentid,A.CreatedDate,A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,    isnull(A.img_ext,'''') as img_ext, A.WhereAddress, RowNumber1, rc1, A.hatsAppNoColName   
   into #Temp2  
   FROM   
   (   
  SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno,ltrim(Ue.Countrycode+'' ''+Ue.Mobileno)+   
  case when isnull(Ue.Mobileno1,'''')<>'''' then '', ...'' else '''' end AS MobileNo3, Ue.Mobileno1, Ue.Mobileno2,Ue.Emailid ,  
  Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress,   Ud.User_login,Ue.CreatedDate , Ue.City,   
  Ue.[State], Ue.Country,Ue.Countrycode,Ue.Countrycode1,Ue.Countrycode2,Ue.Pincode, CASE WHEN   
  Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END  
 ELSE Ue.Residentialaddress END AS [ADDRESS],   
 Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid,   
 CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26),   
 Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby,   
 CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads,   
 (CASE WHEN isnull(ue.isopen,1)=1 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress,   
 ROW_NUMBER() OVER(ORDER BY Ue.Enquiryid ASC) AS RowNumber1, count(*) OVER(ORDER BY Ue.Parentid) AS rc1, Ue.WhatsAppNoColName  
  FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss   
  ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums   
  ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs   
  ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud   
  ON Ue.Createdby = Ud.User_id and Ue.Parentid = Ud.ParentID   
  WHERE ue.enquiryid> '+ Convert(varchar(100),@start_entityid)+' and  Ue.Parentid = '+ Convert(varchar(100),@Parentid)  
  
  
  if isnull(@Userid,0) >=0  
  Begin  
  set @Query += N' AND ue.CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN ue.CreatedBy ELSE '+ Convert(varchar(100),@Userid) +' END '  
  End  
  
  set @Query += N' ) A Where A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno)   
  
 END  
 ELSE  
 BEGIN  
 print 'Branch B'  
  
  set @Query += N'SELECT distinct A.Enquiryid,A.Personname,A.Companyname,A.MobileNo3,A.MobileNo1,A.MobileNo2,A.EmailID3,A.EmailID1,A.EmailID2,A.Residentialaddress,  
   A.Officeaddress,A.User_login,A.MobileNo,A.EmailID,A.City,A.[State],A.Country,A.Countrycode,A.Countrycode1,A.Countrycode2,A.Pincode,A.[ADDRESS], A.Initialremarks,  
   A.SourceName,A.MediumName,A.CampaignName,A.Parentid,A.CreatedDate, A.CreatedDate1,A.Createdby,A.Leads,A.Isopen,  
   isnull(A.img_ext,'''') as img_ext, A.WhereAddress, RowNumber1, rc1 , A.WhatsAppNoColName  
   into #Temp2  
   FROM   
   (   
  Select *, ROW_NUMBER() OVER(ORDER BY T.Enquiryid ASC) AS RowNumber1, count(*) OVER(ORDER BY T.Parentid) AS rc1    
  From   
  (  
   SELECT distinct Ue.Enquiryid,Ue.Personname,Ue.Companyname,Ue.Mobileno,ltrim(Ue.Countrycode+'' ''+Ue.Mobileno)+ case when isnull(Ue.Mobileno1,'''')<>'''' then '', ...'' else '''' end AS MobileNo3, Ue.Mobileno1, Ue.Mobileno2,Ue.Emailid ,  
   Ue.Emailid AS EmailID3,Ue.Emailid1,Ue.Emailid2,Ue.Residentialaddress,Ue.Officeaddress, Ud.User_login,Ue.CreatedDate , Ue.City,   
   Ue.[State], Ue.Country, Ue.Countrycode,Ue.Countrycode1,Ue.Countrycode2,Ue.Pincode, CASE WHEN Ue.Companyname <> '''' THEN Case WHEN Ue.Officeaddress <> '''' THEN Ue.Officeaddress ELSE Ue.Residentialaddress END ELSE Ue.Residentialaddress END AS [ADDRESS]
, Ue.Initialremarks, Uss.Name AS SourceName, Ums.Name AS MediumName, Ucs.Name AS CampaignName,  Ue.Parentid, CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF( RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),7,7, '' '') AS CreatedDate1, Ue.Createdby,
 CASE WHEN isnull(ue.isopen,1)=1 then null else ue.LeadNo end AS Leads, (CASE WHEN isnull(ue.isopen,1)=1 then ''open'' when isnull(ue.LeadNo,0) > 0 THEN ''lead'' ELSE ''open'' END) as Isopen, Ue.img_ext, Ue.WhereAddress,Ue.WhatsAppNoColName  
   FROM Userenquiry (NOLOCK) Ue left JOIN Usersourcesettings (NOLOCK) Uss   
   ON Ue.Sourcename = Uss.Sourceid LEFT JOIN Usermediumsettings (NOLOCK) Ums   
   ON Ue.Mediumname = Ums.Mediumid LEFT JOIN Usercampaignsettings (NOLOCK) Ucs   
   ON Ue.Campaignname = Ucs.Campaignid LEFT JOIN User_detail (NOLOCK) Ud   
   ON Ue.Createdby = Ud.User_id and Ue.Parentid = Ud.ParentID   
   WHERE ue.enquiryid> '+ Convert(varchar(100),@start_entityid)+' and Ue.Parentid = ' + Convert(varchar(100),@ParentID)     
  
  
  if isnull(@Userid,0) >=0  
  Begin  
    print 'userid'
  set @Query += N' AND ue.CreatedBy = CASE WHEN ('+ Convert(varchar(100),@Userid)+' = 0) THEN ue.CreatedBy ELSE '+ Convert(varchar(100),@Userid) +' END '  
  End  
  
  set @Query += N' ) T Where ' + @FilterText +  
       N' ) A Where ' + case when @Txtsearch = ' (1=1) ' then ' A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) else ' (1=1) ' end  
  
 END  
  
If(@ue_query = '')  
Begin  
 set @ue_query = ' (1=1) '  
End  
  
If(@FilterText != '' and @ue_query != '')  
Begin  
 Set @FilterText += ' AND ' + @ue_query  
End  
  
If(@ordstr = '')  
Begin  
 set @ordstr = ' Enquiryid asc '  
End  
  
 IF(@Pivot_Column IS NOT NULL)  
 BEGIN  
  print 'Branch C'  
 IF(@Txtsearch = ' (1=1) ')-- From Branch A  
 Begin  
  print 'Branch CA'  
  
  SET @Query+=CAST(N';select EnquiryId as ID, PersonName, CompanyName,MobileNo, MobileNo1, MobileNo2,Countrycode,Countrycode1,Countrycode2,EmailID, EmailID1, EmailID2, City, [State], Country, Pincode, Residentialaddress, Officeaddress, SourceName, MediumName, CampaignName, Initialremarks,CreatedDate,WhatsAppNoColName From (SELECT rc1 AS [rcnt], EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country,Countrycode,Countrycode1,Countrycode2,Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, RowNumber1, WhereAddress,WhatsAppNoColName ,rc1, ' + @Pivot_Column +   
  N' FROM (SELECT EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country,Countrycode,Countrycode1,Countrycode2, Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress, [fieldname], fieldvalue, RowNumber1,  rc1,WhatsAppNoColName    
  FROM (select E.Enquiryid, E.PersonName, E.CompanyName, E.MobileNo3, E.MobileNo1, E.MobileNo2, E.EmailID3, E.EmailID1, E.EmailID2, E.Residentialaddress, E.Officeaddress, E.User_login, E.MobileNo, E.EmailID, E.City, E.[State], E.Country,E.Countrycode,E.Countrycode1,E.Countrycode2,E.Pincode, E.[ADDRESS], E.Initialremarks, E.SourceName, E.MediumName, E.CampaignName, E.Parentid, E.CreatedDate, E.CreatedDate1, E.Createdby, E.Leads, E.Isopen, E.Img_ext, E.WhereAddress, y.fieldname, x.fieldvalue, E.RowNumber1, E.rc1,E.WhatsAppNoColName   
  From #temp2 E left join customfieldEnquiryvalue(nolock) x   
  ON E.Enquiryid = x.Enquiryid left join customfields(nolock) y   
  ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1  
  )q )Tab1  
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2  
  WHERE ' + @Txtsearch + ') T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));  
 End  
 Else  
 Begin  
 print 'Branch CB'  
  
  Select @filterCnt=count(*) From dbo.fn_Split(@Txtsearch, ' ) ')  
    
  --SELECT @Query += CAST(N'; select x.EnquiryID  
  --into #Temp1  
  --from customfieldEnquiryvalue(nolock) x inner join customfields(nolock) y  
  --ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1  
  --Where ' + @Txtsearch + N'  
  --group by x.EnquiryID  
  --having count(*) >= ' + Cast(@filterCnt as NVARCHAR(MAX)) AS NVARCHAR(MAX));  
  
  SELECT @Query += CAST(N'; select * into #Temp1 From (select [x].EnquiryId, [y].[fieldname],   
 [x].[fieldvalue] from customfieldEnquiryvalue(nolock) x inner join customfields(nolock) y  
 ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) T1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @Txtsearch AS NVARCHAR(MAX));  
  
  
  SET @Query+=CAST(N';Select EnquiryId as ID, PersonName, CompanyName,MobileNo, MobileNo1, MobileNo2,Countrycode,Countrycode1,Countrycode2,EmailID, EmailID1, EmailID2, City, [State], Country, Pincode, Residentialaddress, Officeaddress, SourceName, MediumName, CampaignName, Initialremarks,CreatedDate,WhatsAppNoColName From (SELECT ROW_NUMBER() OVER(ORDER BY EnquiryId Desc) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], count(*) OVER(ORDER BY [ParentID]) AS [rcnt], EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country,Countrycode,Countrycode1,Countrycode2,Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress,WhatsAppNoColName FROM (SELECT EnquiryId, PersonName, CompanyName, MobileNo3, MobileNo1, MobileNo2, EmailID3, EmailID1, EmailID2, Residentialaddress, Officeaddress, User_login, MobileNo, EmailID, City, [State], Country, Countrycode,Countrycode1,Countrycode2 ,Pincode, [ADDRESS], Initialremarks, SourceName, MediumName, CampaignName, Parentid, CreatedDate, CreatedDate1, Createdby, Leads, Isopen, Img_ext, WhereAddress,WhatsAppNoColName  
  FROM (select E.Enquiryid, E.PersonName, E.CompanyName, E.MobileNo3, E.MobileNo1, E.MobileNo2, E.EmailID3, E.EmailID1, E.EmailID2, E.Residentialaddress, E.Officeaddress, E.User_login, E.MobileNo, E.EmailID, E.City, E.[State], E.Country,E.Countrycode,E.Countrycode1,E.Countrycode2, E.Pincode, E.[ADDRESS], E.Initialremarks, E.SourceName, E.MediumName, E.CampaignName, E.Parentid, E.CreatedDate, E.CreatedDate1, E.Createdby, E.Leads, E.Isopen, E.Img_ext, E.WhereAddress, E.hatsAppNoColName  
  From #Temp1 A inner join #temp2 E   
  ON A.EnquiryId = E.Enquiryid   
  )q )Tab1  
  ) T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) AS NVARCHAR(MAX)) + N' ORDER BY ' + @ordstr;  
  
 End  
 END  
 ELSE  
 BEGIN  
 print 'Branch D'  
  
 SET @Query += CAST(N'; select EnquiryId as ID, PersonName, CompanyName,MobileNo, MobileNo1, MobileNo2,Countrycode,Countrycode1,Countrycode2,EmailID, EmailID1, EmailID2, City, [State], Country, Pincode, Residentialaddress, Officeaddress, SourceName, Mediu
mName, CampaignName, Initialremarks,CreatedDate,WhatsAppNoColName from #temp2 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));  
 END  
  
  
 --print '@FinalQuery:- ' + cast(@Query as varchar(max))  
 EXEC sp_executesql @Query;  
  
 update kit19_executionlogger  
 set EndDatetime = getdate(), Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)  
 where ID = @LoggerID  
  
 update kit19_executionlogger  
 set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)  
 where ID = @LoggerID  
  
 DROP TABLE IF EXISTS #temp1;  
 DROP TABLE IF EXISTS #temp2;  
  
END  



GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserEnquriyDetails_INTDateTime]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
CREATE   PROCEDURE [dbo].[Usp_ViewUserEnquriyDetails_INTDateTime] --'',335,335  
 @Txtsearch NVARCHAR(100),                                            
 @Parentid BIGINT,                                        
 --@pageStartIndex int,                                                                        
--@PageendSize int,                              
 @Userid  INT=0  
                                              
AS                                            
BEGIN                              
                                
    select * into #TMPTBL from UserLeads where ParentID = @Parentid                          
                          
                                        
 SELECT distinct A.Enquiryid,                                            
        A.Personname,                                            
        A.Companyname,                                            
        A.MobileNo3,                                            
        A.MobileNo1,                                            
        A.MobileNo2,                                            
        A.EmailID3,                                            
        A.EmailID1,                                            
        A.EmailID2,                                            
        A.Residentialaddress,                                            
        A.Officeaddress,                                            
        A.User_login,                                            
        A.MobileNo,                                            
        A.EmailID,                                            
        A.City,                                            
        A.[State],                                            
        A.Country,                                            
        A.Countrycode,                                            
        A.Pincode,                                            
        A.[ADDRESS],                                            
        A.Initialremarks,                                            
        A.SourceName,                                            
        A.MediumName,                                            
        A.CampaignName,                                            
        A.Parentid,                                            
       -- A.CreatedDate,  
        dbo.[fn_getusertimefromindiantime](@Parentid,A.CreatedDate) as CreatedDate,      
        A.CreatedDate1,  
        dbo.[fn_getusertimefromindiantime](@Parentid,A.CreatedDate1) as CreatedDate1New,                                                
        A.Createdby,                                            
        A.Leads,                                            
        A.Isopen,                                            
        A.RowNumber                                            
 FROM   (                                            
            SELECT Ue.Enquiryid,                                            
                   Ue.Personname,                                            
                   Ue.Companyname,                                            
                   Ue.Mobileno  AS MobileNo3,                                            
                   Ue.Mobileno1,                                            
                   Ue.Mobileno2,                                            
                   Ue.Emailid   AS EmailID3,                                            
                   Ue.Emailid1,                                            
                   Ue.Emailid2,                                            
                   Ue.Residentialaddress,                                            
                   Ue.Officeaddress,                                            
                   Ud.User_login,      
                   Ue.CreatedDate as CreatedDate1,                      
                   CASE                                             
                        WHEN ISNULL(Ue.Countrycode, '') <> '' THEN +                         
                                                               
                 case when (ISNULL(Ue.Countrycode, '') + ISNULL(Ue.Mobileno, '')) in                      
                   (                      
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                         
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                        
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                        
              from   Client_UnSubscribeDetails C_UDTemp                   
                join ClientPageDetail_Unsubscribe cpd on                    
                 --'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID                     
                     C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID                     
                    
                    
              )                      
                    then '<p style="color:red;" >'+(ISNULL(Ue.Countrycode, '') + ISNULL(Ue.Mobileno, ''))+ '</p>'                      
                    else                      
                        (ISNULL(Ue.Countrycode, '') + ISNULL(Ue.Mobileno, ''))                      
                    end                           
                             
                     else ''        
                     end                     
                                          
          +                                            
                                         
                                         
                                                               
                   CASE                                             
                        WHEN ISNULL(Ue.Mobileno1, '') <> '' THEN ', ' +                                            
                                                   
                                  
                             --ISNULL(Ue.Countrycode1, '')                                             
                                                                         
                             --+ ISNULL(Ue.Mobileno1, '')                        
                                                   
                   case when (ISNULL(Ue.Countrycode1, '') + ISNULL(Ue.Mobileno1, '')) in                      
                   (                      
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                         
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                        
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                        
                 from   Client_UnSubscribeDetails C_UDTemp                   
                  join ClientPageDetail_Unsubscribe cpd on                    
                  --'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID                     
                    C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID             
                    )                      
                    then '<p style="color:red;" >'+(ISNULL(Ue.Countrycode1, '') + ISNULL(Ue.Mobileno1, ''))+ '</p>'                      
                    else                      
                        (ISNULL(Ue.Countrycode1, '') + ISNULL(Ue.Mobileno1, ''))                      
                    end                           
                                                   
                                                   
                                                   
                                                                       
                        ELSE ''                                            
                   END +    
                                                               
                   CASE                                             
                        WHEN ISNULL(Ue.Mobileno2, '') < > '' THEN ', ' +                                            
                                                   
                                                   
                             --ISNULL(Ue.Countrycode2, '')                                 
                                                                         
                             --+ ISNULL(Ue.Mobileno2, '')                                            
                                             
                                            
                   case when (ISNULL(Ue.Countrycode2, '') + ISNULL(Ue.MobileNo2, '')) in                      
                   (                      
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                         
       --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                        
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                        
                  from   Client_UnSubscribeDetails C_UDTemp                    
                  join ClientPageDetail_Unsubscribe cpd on                     
                  --'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID                     
                     C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID             
                    )                      
                    then '<p style="color:red;" >'+(ISNULL(Ue.Countrycode2, '') + ISNULL(Ue.Mobileno2, ''))+ '</p>'                      
                    else                      
                        (ISNULL(Ue.Countrycode2, '') + ISNULL(Ue.Mobileno2, ''))                      
                    end                           
                                             
                                             
                                             
                        ELSE ''                                            
                   END          AS MobileNo,                        
                                                             
                   CASE                                  
                        WHEN ISNULL(Ue.Emailid, '') <> '' THEN ', '                       
                        +                      
                                        
                                        
                        -- ISNULL(Ue.Emailid, '') +                        
                           
                         case when (ISNULL(Ue.Emailid, '')) in                      
                   (                      
                     select ISNULL(C_UDTemp.Email,'') as EmailID                         
                                             
                      from   Client_UnSubscribeDetails C_UDTemp join ClientPageDetail_Unsubscribe cpd on                     
                    --  'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID                      
                     C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID             
                     )                      
                    then '<p style="color:red;" >'+(ISNULL(Ue.Emailid, ''))+ '</p>'                      
                    else                      
                        (ISNULL(Ue.Emailid, ''))                      
                    END                      
                    ELSE   ''                      
                    END+                      
                                         
                     CASE                                             
                        WHEN ISNULL(Ue.Emailid1, '') <> '' THEN ', '                       
                        +                       
                                              
                 -- ISNULL(Ue.Emailid1, '')                        
                         case when (ISNULL(Ue.Emailid1, '')) in                      
                   (                      
                     select ISNULL(C_UDTemp.Email,'') as EmailID                         
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                        
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)          
                      from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                     
                    --  'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID                     
                     C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID             
            )                      
                    then '<p style="color:red;" >'+(ISNULL(Ue.Emailid1, ''))+ '</p>'                      
                    else                      
                        (ISNULL(Ue.Emailid1, ''))                      
                       END                      
                                                                 
                                              
           
                        ELSE ''                                            
                   END +                                            
                                                               
                   CASE                                             
                   WHEN ISNULL(Ue.Emailid2, '') <> '' THEN ', ' +                       
                       
                       
                       
                   --ISNULL(Ue.Emailid2, '')                         
                       case when (ISNULL(Ue.Emailid2, '')) in                      
 (                      
                     select ISNULL(C_UDTemp.Email,'') as EmailID                         
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                        
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                        
                      from   Client_UnSubscribeDetails C_UDTemp join ClientPageDetail_Unsubscribe cpd on                     
                    --  'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID                     
                    C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID             
                    )                      
                    then '<p style="color:red;" >'+(ISNULL(Ue.Emailid2, ''))+ '</p>'                      
                    else                      
                        (ISNULL(Ue.Emailid2, ''))                      
                       END                      
                    ELSE ''                                            
                   END          AS EmailID,                                            
                   Ue.City,                                            
                   Ue.[State],                                            
                   Ue.Country,                                            
                   Ue.Countrycode,                                            
               Ue.Pincode,                       
                   CASE                                             
                        WHEN Ue.Companyname <> '' THEN Ue.Officeaddress                                            
                        ELSE Ue.Residentialaddress                                            
             END          AS [ADDRESS],                                            
                   Ue.Initialremarks,                 
                   Uss.Name     AS SourceName,                                            
                   Ums.Name AS MediumName,                                            
        Ucs.Name     AS CampaignName,                                            
                   Ue.Parentid,                                            
                   CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF(                                         
                       RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),                                            
                       7,                                            
                       7,                                            
                       ' '                                            
                 )      AS CreatedDate,                                            
                 Ue.Createdby,                                       
                   ISNULL(                                            
                       (                                            
                           SELECT TOP 1                                            
                                                                  
                                  1                           
                           FROM   #TMPTBL AS Ul                                            
                           WHERE  Ul.Parentid = @Parentid                                            
                                  AND (                                            
                                          ISNULL(NULLIF(Ul.Countrycode, ''), '1')                                             
            +                                            
                                             
                                          ISNULL(NULLIF(Ul.Mobileno, ''), '1')                                             
                                          = ISNULL(NULLIF(Ue.Countrycode, ''), '2')                                             
                                                                                      
                                          + ISNULL(NULLIF(Ue.Mobileno, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Countrycode, ''), '1')                          
                                             +                                         
                                                                                         
                                             ISNULL(NULLIF(Ul.Mobileno, ''), '1')                                             
                                             =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Countrycode1, ''), '2')                                      
                                             +                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Countrycode, ''), '1')                                             
                                             +                                            
                                                                                         
                                             ISNULL(NULLIF(Ul.Mobileno, ''), '1')                                             
                                             =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Countrycode2, ''), '2')                                             
                                             +                                  
                                                                                       
                                 ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')                                
                                             +                                            
                                                                                         
                                  ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                                             
                                             =                                       
                                                                                                                                    ISNULL(NULLIF(Ue.Countrycode, ''), '2')                                             
                                             +                                            
                                                                                         
                      ISNULL(NULLIF(Ue.Mobileno, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')        
                                             +                                            
                                                                                         
         ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                                             
                    =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Countrycode1, ''), '2')                                             
                                  +                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                                            
                                  OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')                                             
                                             +                                            
                                                                                         
                                             ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                                             
                 =                              
                                                                                         
                                             ISNULL(NULLIF(Ue.Countrycode2, ''), '2')                                             
                                             +                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')                                             
                                             +                                            
                                                                                         
                                             ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                                             
                                             =                                            
                                                                                         
                            ISNULL(NULLIF(Ue.Countrycode, ''), '2')                                             
                                             +                                            
                                                                                         
ISNULL(NULLIF(Ue.Mobileno, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')                                             
                                             +                                            
                        
                                             ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                                             
                                             =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Countrycode1, ''), '2')                                             
                   +                                            
                     
                                             ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')                                             
               +                                            
                                                                                         
                                             ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                               
                                             =                                            
                                       
       ISNULL(NULLIF(Ue.Countrycode2, ''), '2')                                             
                                             +                                            
                                                                                         
                                            ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Emailid, ''), '1')                                  
                                           =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Emailid, ''), '2')                                 
                                          OR ISNULL(NULLIF(Ul.Emailid, ''), '1')                                             
                                             =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Emailid1, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Emailid, ''), '1')                                           
                                             =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Emailid2, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Emailid1, ''), '1')                                             
                                             =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Emailid, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Emailid1, ''), '1')                                             
                             =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Emailid1, ''), '2')                                            
                                 OR ISNULL(NULLIF(Ul.Emailid1, ''), '1')                                             
                                             =                                            
                                                                               
                                                                               
                                             ISNULL(NULLIF(Ue.Emailid2, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Emailid2, ''), '1')                                             
                                             =                                            
                                                                                         
                                  ISNULL(NULLIF(Ue.Emailid, ''), '2')                                            
             OR ISNULL(NULLIF(Ul.Emailid2, ''), '1')                                             
                                             =                                            
                                                                                         
                                             ISNULL(NULLIF(Ue.Emailid1, ''), '2')                                            
                                          OR ISNULL(NULLIF(Ul.Emailid2, ''), '1')                    
                                             =                                            
                                                                                        
  ISNULL(NULLIF(Ue.Emailid2, ''), '2')                                            
                  )                                            
                       ),                                            
                       0                                            
                   )                                  
                                              
                                                         
            AS Leads,                                            
                   --Ue.Isopen,                                   
                   (CASE                                             
         WHEN Ue.Isopen = '1' THEN 'open'                                           
                        ELSE 'close'                                            
                   END) as Isopen  ,                                  
                                                         
                   ROW_NUMBER() OVER(ORDER BY Enquiryid DESC) AS RowNumber                                            
                                                           
           FROM   Userenquiry Ue                                         
                   INNER JOIN Usersourcesettings Uss                                          
                        ON  Ue.Sourcename = Uss.Sourceid                                            
                   LEFT JOIN Usermediumsettings Ums                                           
           ON  Ue.Mediumname = Ums.Mediumid                                            
                   LEFT JOIN Usercampaignsettings Ucs                                           
                        ON  Ue.Campaignname = Ucs.Campaignid                                            
                   LEFT JOIN User_detail Ud                                           
                        ON  Ue.Createdby = Ud.User_id                                  
                   left join tbl_MergeLeadsEnquiry  mergeenq                                  
                        on  Ue.EnquiryID= mergeenq.EnquiryNo                           
                                                                     
            WHERE  Ue.Parentid = @Parentid                             
            AND ue.CreatedBy = CASE                             
                               WHEN (@Userid = 0) THEN ue.CreatedBy                            
                           ELSE @Userid  END                              
             --AND Ue.CreatedBy = case when ISNULL(@Userid,,0) =0 then createdby else @Userid end                              
                   --AND Ue.CreatedBy = case when ISNULL(@Userid,null)=335  then createdby else @Userid end                              
                  -- AND Ud.User_ID = isnull(@Userid,335)                                           
                   AND (                                            
                           ISNULL(@Txtsearch, '') = ''                                            
                       OR Personname LIKE '%' + @Txtsearch + '%'                                            
                           OR Companyname LIKE '%' + @Txtsearch + '%'                                   
                       )                                          
       
        ) A    --where a.RowNumber>=@pageStartIndex and a.RowNumber<=@PageendSize                                        
 ORDER BY                                            
        A.CreatedDate1 DESC                          
                                  
       drop table #TMPTBL                                            
END     
    
    


GO

/* ============================================================
   Procedure: [dbo].[Usp_viewuserenquriydetails_ShairedView]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE Usp_viewuserenquriydetails_ShairedView --'',335,335                                  
 @Txtsearch NVARCHAR(100),                                  
 @Parentid BIGINT,                              
 --@pageStartIndex int,                                                              
--@PageendSize int,                    
 @Userid  INT=0                                   
AS                                  
BEGIN                    
                      
    select * into #TMPTBL from UserLeads where ParentID = @Parentid                
                
                              
 SELECT distinct A.Enquiryid,                                  
        A.Personname,                                  
        A.Companyname,                                  
        A.MobileNo3,                                  
        A.MobileNo1,                                  
        A.MobileNo2,                                  
        A.EmailID3,                                  
        A.EmailID1,                                  
        A.EmailID2,                                  
        A.Residentialaddress,                                  
        A.Officeaddress,                                  
        A.User_login,                                  
        A.MobileNo,                                  
        A.EmailID,                                  
        A.City,                                  
        A.[State],                                  
        A.Country,                                  
        A.Countrycode,                                  
        A.Pincode,                                  
        A.[ADDRESS],                                  
        A.Initialremarks,                                  
        A.SourceName,                                  
        A.MediumName,                                  
        A.CampaignName,                                  
        A.Parentid,                                  
        A.CreatedDate,                                  
        A.Createdby,                                  
        A.Leads,                                  
        A.Isopen,                                  
        A.RowNumber                                  
 FROM   (                                  
            SELECT Ue.Enquiryid,                                  
                   Ue.Personname,                                  
                   Ue.Companyname,                                  
                   Ue.Mobileno  AS MobileNo3,                                  
                   Ue.Mobileno1,                                  
                   Ue.Mobileno2,                                  
                   Ue.Emailid   AS EmailID3,                                  
                   Ue.Emailid1,                                  
                   Ue.Emailid2,                                  
                   Ue.Residentialaddress,                                  
                   Ue.Officeaddress,                                  
                   Ud.User_login,            
                               
                                                     
                 case when (ISNULL(Ue.Countrycode, '') + ISNULL(Ue.Mobileno, '')) in            
                   (            
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo               
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp              
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)              
                from   Client_UnSubscribeDetails C_UDTemp         
                join ClientPageDetail_Unsubscribe cpd on          
                 --'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID           
                     C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID           
          
          
              )            
                    then '<p style="color:red;" >'+(ISNULL(Ue.Countrycode, '') + ISNULL(Ue.Mobileno, ''))+ '</p>'            
                    else            
                        (ISNULL(Ue.Countrycode, '') + ISNULL(Ue.Mobileno, ''))            
                    end                 
                                
                                
          +                                  
                               
                               
                                                     
                   CASE                                   
                        WHEN ISNULL(Ue.Mobileno1, '') <> '' THEN ', ' +                                  
                                         
                        
                             --ISNULL(Ue.Countrycode1, '')                                   
                                                               
                             --+ ISNULL(Ue.Mobileno1, '')              
                                         
                   case when (ISNULL(Ue.Countrycode1, '') + ISNULL(Ue.Mobileno1, '')) in            
                   (            
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo               
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp              
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)              
                 from   Client_UnSubscribeDetails C_UDTemp         
                  join ClientPageDetail_Unsubscribe cpd on          
                  --'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID           
                    C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID   
                    )            
                    then '<p style="color:red;" >'+(ISNULL(Ue.Countrycode1, '') + ISNULL(Ue.Mobileno1, ''))+ '</p>'            
                    else            
                        (ISNULL(Ue.Countrycode1, '') + ISNULL(Ue.Mobileno1, ''))            
                    end                 
                                         
                                         
                                         
                                                             
                        ELSE ''                                  
                   END +                                  
                                                     
                   CASE                                   
                        WHEN ISNULL(Ue.Mobileno2, '') < > '' THEN ', ' +                                  
                                         
                                         
                             --ISNULL(Ue.Countrycode2, '')                                   
                                                               
                             --+ ISNULL(Ue.Mobileno2, '')                                  
                                   
                                   
                   case when (ISNULL(Ue.Countrycode2, '') + ISNULL(Ue.MobileNo2, '')) in            
                   (            
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo               
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp              
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)              
                  from   Client_UnSubscribeDetails C_UDTemp          
                  join ClientPageDetail_Unsubscribe cpd on           
                  --'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID           
                     C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID   
                    )            
                    then '<p style="color:red;" >'+(ISNULL(Ue.Countrycode2, '') + ISNULL(Ue.Mobileno2, ''))+ '</p>'            
                    else            
                        (ISNULL(Ue.Countrycode2, '') + ISNULL(Ue.Mobileno2, ''))            
                    end                 
                                   
                                   
                                   
                        ELSE ''                                  
                   END          AS MobileNo,              
                                                   
                   CASE                        
                        WHEN ISNULL(Ue.Emailid, '') <> '' THEN ', '             
                        +            
                              
                              
                        -- ISNULL(Ue.Emailid, '') +              
                 
                         case when (ISNULL(Ue.Emailid, '')) in            
                   (            
                     select ISNULL(C_UDTemp.Email,'') as EmailID               
                                   
                      from   Client_UnSubscribeDetails C_UDTemp join ClientPageDetail_Unsubscribe cpd on           
                    --  'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID            
                     C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID   
                     )            
                    then '<p style="color:red;" >'+(ISNULL(Ue.Emailid, ''))+ '</p>'            
                    else            
                        (ISNULL(Ue.Emailid, ''))            
                    END            
                    ELSE   ''            
                    END+            
                               
                     CASE                                   
                        WHEN ISNULL(Ue.Emailid1, '') <> '' THEN ', '             
                        +             
                                    
                       -- ISNULL(Ue.Emailid1, '')              
                         case when (ISNULL(Ue.Emailid1, '')) in            
                   (            
                     select ISNULL(C_UDTemp.Email,'') as EmailID               
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp              
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)              
                      from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on           
                    --  'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID           
                     C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID   
                    )            
                    then '<p style="color:red;" >'+(ISNULL(Ue.Emailid1, ''))+ '</p>'            
                    else            
                        (ISNULL(Ue.Emailid1, ''))            
                       END            
                                                       
                                    
                                    
                        ELSE ''                                  
                   END +                                  
                                                     
                   CASE                                   
                   WHEN ISNULL(Ue.Emailid2, '') <> '' THEN ', ' +             
             
             
             
                   --ISNULL(Ue.Emailid2, '')               
                       case when (ISNULL(Ue.Emailid2, '')) in            
                   (            
                     select ISNULL(C_UDTemp.Email,'') as EmailID               
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp              
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)              
                      from   Client_UnSubscribeDetails C_UDTemp join ClientPageDetail_Unsubscribe cpd on           
                    --  'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID           
                    C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID   
                    )            
                    then '<p style="color:red;" >'+(ISNULL(Ue.Emailid2, ''))+ '</p>'            
                    else            
                        (ISNULL(Ue.Emailid2, ''))            
                       END            
                    ELSE ''                                  
                   END          AS EmailID,                                  
                   Ue.City,                                  
                   Ue.[State],                                  
                   Ue.Country,                                  
                   Ue.Countrycode,                                  
               Ue.Pincode,             
                   CASE                                   
                        WHEN Ue.Companyname <> '' THEN Ue.Officeaddress                                  
                        ELSE Ue.Residentialaddress                                  
             END          AS [ADDRESS],                                  
                   Ue.Initialremarks,       
                   Uss.Name     AS SourceName,                                  
                   Ums.Name AS MediumName,                                  
                   Ucs.Name     AS CampaignName,                                  
                   Ue.Parentid,                                  
                   CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF(                               
                       RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),                                  
                       7,                                  
                       7,                                  
                       ' '                                  
                 )            AS CreatedDate,                                  
                 Ue.Createdby,                             
                   ISNULL(                                  
                       (                                  
                           SELECT TOP 1                                  
                                                        
                                  1                                  
                           FROM   #TMPTBL AS Ul                                  
                           WHERE  Ul.Parentid = @Parentid                                  
                                  AND (                                  
                                          ISNULL(NULLIF(Ul.Countrycode, ''), '1')                                   
            +                                  
                                                                            
                                          ISNULL(NULLIF(Ul.Mobileno, ''), '1')                                   
                                          = ISNULL(NULLIF(Ue.Countrycode, ''), '2')                                   
                                                                            
                                          + ISNULL(NULLIF(Ue.Mobileno, ''), '2')                                  
                                          OR ISNULL(NULLIF(Ul.Countrycode, ''), '1')                
                                             +                                  
                                                                               
                                             ISNULL(NULLIF(Ul.Mobileno, ''), '1')                                   
                                             =                                  
                                                                               
                                             ISNULL(NULLIF(Ue.Countrycode1, ''), '2')                            
                                             +                                  
                                                                               
                                             ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                                  
                                          OR ISNULL(NULLIF(Ul.Countrycode, ''), '1')                                   
                                             +                                  
                                                                               
                                             ISNULL(NULLIF(Ul.Mobileno, ''), '1')                                   
                                             =                                  
                                                                               
                                             ISNULL(NULLIF(Ue.Countrycode2, ''), '2')                                   
                                             +                        
                                                                             
                                             ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                                  
                                          OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')                      
                                             +                                  
                                                                               
                                  ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                                   
                                             =                             
                                                                               
                                             ISNULL(NULLIF(Ue.Countrycode, ''), '2')                                   
                                             +                                  
                                                                               
                      ISNULL(NULLIF(Ue.Mobileno, ''), '2')                                  
                                          OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')                                   
                                             +                                  
                                                                               
         ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                                   
                    =                                  
                                                                               
                                             ISNULL(NULLIF(Ue.Countrycode1, ''), '2')                                   
                                             +                                  
                                                                               
                                             ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                                  
                                  OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')                                   
                                             +                                  
                                                                               
                                             ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                                   
                 =                                  
                                                                               
                                             ISNULL(NULLIF(Ue.Countrycode2, ''), '2')                                   
                                             +                                  
                                                                               
                                             ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                                  
                                          OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')                                   
                                             +                                  
                                                                               
                                             ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                                   
                                             =                                  
                                                                               
                            ISNULL(NULLIF(Ue.Countrycode, ''), '2')                                   
                                             +                                  
                                                                               
                                             ISNULL(NULLIF(Ue.Mobileno, ''), '2')                                  
                                          OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')                                   
                                             +                                  
              
                                             ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                                   
                                             =                                  
                                                                               
                                             ISNULL(NULLIF(Ue.Countrycode1, ''), '2')                                   
                                      +                                  
           
                                             ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                                  
                                          OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')                                   
               +                                  
                                                                               
                                             ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                                   
                                             =                                  
                             
       ISNULL(NULLIF(Ue.Countrycode2, ''), '2')                                   
                                             +                                  
                                                                               
                                            ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                                  
                                          OR ISNULL(NULLIF(Ul.Emailid, ''), '1')                                   
                                           =                                  
                                                                               
                                             ISNULL(NULLIF(Ue.Emailid, ''), '2')                       
                                          OR ISNULL(NULLIF(Ul.Emailid, ''), '1')                                   
                                             =                                  
                                                                               
                                             ISNULL(NULLIF(Ue.Emailid1, ''), '2')                                  
                                          OR ISNULL(NULLIF(Ul.Emailid, ''), '1')                                   
                                             =                                  
                                                                               
                                             ISNULL(NULLIF(Ue.Emailid2, ''), '2')                                  
                                          OR ISNULL(NULLIF(Ul.Emailid1, ''), '1')                                   
                                             =                                  
                                                                               
                                             ISNULL(NULLIF(Ue.Emailid, ''), '2')                                  
                                          OR ISNULL(NULLIF(Ul.Emailid1, ''), '1')                                   
                             =                                  
                                                                               
                                             ISNULL(NULLIF(Ue.Emailid1, ''), '2')                                  
                                          OR ISNULL(NULLIF(Ul.Emailid1, ''), '1')                                   
                                             =                                  
                                                                     
                                                                     
                                             ISNULL(NULLIF(Ue.Emailid2, ''), '2')                                  
                                          OR ISNULL(NULLIF(Ul.Emailid2, ''), '1')                                   
                                             =                                  
                                                                               
                                  ISNULL(NULLIF(Ue.Emailid, ''), '2')                                  
             OR ISNULL(NULLIF(Ul.Emailid2, ''), '1')                                   
                                             =                                  
                                                                               
                                             ISNULL(NULLIF(Ue.Emailid1, ''), '2')                                  
                                          OR ISNULL(NULLIF(Ul.Emailid2, ''), '1')          
                                             =                                  
                                                                               
  ISNULL(NULLIF(Ue.Emailid2, ''), '2')                                  
                  )                                  
                       ),                                  
                       0                                  
                   )                        
                                    
                                               
            AS Leads,                                  
                   --Ue.Isopen,                         
                   (CASE                                   
         WHEN Ue.Isopen = '1' THEN 'open'                                 
                        ELSE 'close'                                  
                   END) as Isopen  ,                        
                                               
                   ROW_NUMBER() OVER(ORDER BY Enquiryid DESC) AS RowNumber                                  
                                                 
           FROM   Userenquiry Ue                               
                   INNER JOIN Usersourcesettings Uss                                
                        ON  Ue.Sourcename = Uss.Sourceid                                  
                   LEFT JOIN Usermediumsettings Ums                                 
           ON  Ue.Mediumname = Ums.Mediumid                                  
                   LEFT JOIN Usercampaignsettings Ucs                                 
                        ON  Ue.Campaignname = Ucs.Campaignid                                  
                   LEFT JOIN User_detail Ud                                 
                        ON  Ue.Createdby = Ud.User_id                        
                   left join tbl_MergeLeadsEnquiry  mergeenq                        
                        on  Ue.EnquiryID= mergeenq.EnquiryNo                 
                                                           
            WHERE  Ue.Parentid = @Parentid                   
            AND ue.CreatedBy = CASE                   
                               WHEN (@Userid = 0) THEN ue.CreatedBy                  
                               ELSE @Userid  END                    
             --AND Ue.CreatedBy = case when ISNULL(@Userid,,0) =0 then createdby else @Userid end                    
                   --AND Ue.CreatedBy = case when ISNULL(@Userid,null)=335  then createdby else @Userid end                    
                  -- AND Ud.User_ID = isnull(@Userid,335)                                 
                   AND (                                  
                           ISNULL(@Txtsearch, '') = ''                                  
                       OR Personname LIKE '%' + @Txtsearch + '%'                                  
                           OR Companyname LIKE '%' + @Txtsearch + '%'                         
                       )                                
                                                     
        ) A    --where a.RowNumber>=@pageStartIndex and a.RowNumber<=@PageendSize                              
 ORDER BY                                  
        A.CreatedDate DESC                
                        
       drop table #TMPTBL                                  
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_viewuserenquriydetails080118]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE Usp_viewuserenquriydetails080118 --'',335,335                                      
 @Txtsearch NVARCHAR(100),                                      
 @Parentid BIGINT,                                  
 --@pageStartIndex int,                                                                  
--@PageendSize int,                        
 @Userid  INT=0                                       
AS                                      
BEGIN                        
                          
    select * into #TMPTBL from UserLeads where ParentID = @Parentid                    
                    
                                  
 SELECT distinct A.Enquiryid,                                      
        A.Personname,                                      
        A.Companyname,                                      
        A.MobileNo3,                                      
        A.MobileNo1,                                      
        A.MobileNo2,                                      
        A.EmailID3,                                      
        A.EmailID1,                                      
        A.EmailID2,                                      
        A.Residentialaddress,                                      
        A.Officeaddress,                                      
        A.User_login,                                      
        A.MobileNo,                                      
        A.EmailID,                                      
        A.City,                                      
        A.[State],                                      
        A.Country,                                      
        A.Countrycode,                                      
        A.Pincode,                                      
        A.[ADDRESS],                                      
        A.Initialremarks,                                      
        A.SourceName,                                      
        A.MediumName,                                      
        A.CampaignName,                                      
        A.Parentid,                                      
        A.CreatedDate,                                      
        A.Createdby,                                      
        A.Leads,                                      
        A.Isopen,                                      
        A.RowNumber                                      
 FROM   (                                      
            SELECT Ue.Enquiryid,                                      
                   Ue.Personname,                                      
                   Ue.Companyname,                                      
                   Ue.Mobileno  AS MobileNo3,                                      
                   Ue.Mobileno1,                                      
                   Ue.Mobileno2,                                      
                   Ue.Emailid   AS EmailID3,                                      
                   Ue.Emailid1,                                      
                   Ue.Emailid2,                                      
                   Ue.Residentialaddress,                                      
                   Ue.Officeaddress,                                      
                   Ud.User_login,                
                   CASE                                       
                        WHEN ISNULL(Ue.Countrycode, '') <> '' THEN +                   
                                                         
                 case when (ISNULL(Ue.Countrycode, '') + ISNULL(Ue.Mobileno, '')) in                
                   (                
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                   
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                  
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                  
      from   Client_UnSubscribeDetails C_UDTemp             
                join ClientPageDetail_Unsubscribe cpd on              
                 --'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID               
                     C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID               
              
              
              )                
                    then '<p style="color:red;" >'+(ISNULL(Ue.Countrycode, '') + ISNULL(Ue.Mobileno, ''))+ '</p>'                
                    else                
                        (ISNULL(Ue.Countrycode, '') + ISNULL(Ue.Mobileno, ''))                
                    end                     
                       
                     else ''  
                     end               
                                    
          +                                      
                                   
                                   
                                                         
                   CASE                                       
                        WHEN ISNULL(Ue.Mobileno1, '') <> '' THEN ', ' +                                      
                                             
                            
                             --ISNULL(Ue.Countrycode1, '')                                       
                                                                   
                             --+ ISNULL(Ue.Mobileno1, '')                  
                                             
                   case when (ISNULL(Ue.Countrycode1, '') + ISNULL(Ue.Mobileno1, '')) in                
                   (                
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                   
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                  
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                  
                 from   Client_UnSubscribeDetails C_UDTemp             
                  join ClientPageDetail_Unsubscribe cpd on              
                  --'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID               
                    C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID       
                    )                
                    then '<p style="color:red;" >'+(ISNULL(Ue.Countrycode1, '') + ISNULL(Ue.Mobileno1, ''))+ '</p>'                
                    else                
                        (ISNULL(Ue.Countrycode1, '') + ISNULL(Ue.Mobileno1, ''))                
                    end                     
                                             
                                             
                                             
                                                                 
                        ELSE ''                                      
                   END +                                      
                                                         
                   CASE                                       
                        WHEN ISNULL(Ue.Mobileno2, '') < > '' THEN ', ' +                                      
                                             
                                             
                             --ISNULL(Ue.Countrycode2, '')                                       
                                                                   
                             --+ ISNULL(Ue.Mobileno2, '')                                      
                                       
                                       
                   case when (ISNULL(Ue.Countrycode2, '') + ISNULL(Ue.MobileNo2, '')) in                
                   (                
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                   
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                  
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                  
                  from   Client_UnSubscribeDetails C_UDTemp              
                  join ClientPageDetail_Unsubscribe cpd on               
                  --'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID               
                     C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID       
                    )                
                    then '<p style="color:red;" >'+(ISNULL(Ue.Countrycode2, '') + ISNULL(Ue.Mobileno2, ''))+ '</p>'                
                    else                
                        (ISNULL(Ue.Countrycode2, '') + ISNULL(Ue.Mobileno2, ''))                
                    end                     
                                       
                                       
                                       
                        ELSE ''                                      
                   END          AS MobileNo,                  
                                                       
                   CASE                            
                        WHEN ISNULL(Ue.Emailid, '') <> '' THEN ', '                 
                        +                
                                  
                                  
                        -- ISNULL(Ue.Emailid, '') +                  
                     
                         case when (ISNULL(Ue.Emailid, '')) in                
                   (                
                     select ISNULL(C_UDTemp.Email,'') as EmailID                   
                                       
                      from   Client_UnSubscribeDetails C_UDTemp join ClientPageDetail_Unsubscribe cpd on               
                    --  'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID                
                     C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID       
                     )                
                    then '<p style="color:red;" >'+(ISNULL(Ue.Emailid, ''))+ '</p>'                
                    else                
                        (ISNULL(Ue.Emailid, ''))                
                    END                
                    ELSE   ''                
                    END+                
                                   
                     CASE                                       
                        WHEN ISNULL(Ue.Emailid1, '') <> '' THEN ', '                 
                        +                 
                                        
                       -- ISNULL(Ue.Emailid1, '')                  
                         case when (ISNULL(Ue.Emailid1, '')) in                
                   (                
                     select ISNULL(C_UDTemp.Email,'') as EmailID                   
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                  
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                  
                      from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on               
                    --  'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID               
                     C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID       
                    )                
                    then '<p style="color:red;" >'+(ISNULL(Ue.Emailid1, ''))+ '</p>'                
                    else                
                        (ISNULL(Ue.Emailid1, ''))                
                       END                
                                                           
                                        
                                        
                     ELSE ''                                      
                   END +                                      
                                                         
                   CASE                                       
                   WHEN ISNULL(Ue.Emailid2, '') <> '' THEN ', ' +                 
                 
                 
                 
                   --ISNULL(Ue.Emailid2, '')                   
                       case when (ISNULL(Ue.Emailid2, '')) in                
 (                
                     select ISNULL(C_UDTemp.Email,'') as EmailID                   
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                  
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                  
                      from   Client_UnSubscribeDetails C_UDTemp join ClientPageDetail_Unsubscribe cpd on               
                    --  'www.kit19.com/Unsubscribe/'+C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID               
                    C_UDTemp.cname = cpd.PageName and cpd.User_ID= @ParentID       
                    )                
                    then '<p style="color:red;" >'+(ISNULL(Ue.Emailid2, ''))+ '</p>'                
                    else                
                        (ISNULL(Ue.Emailid2, ''))                
                       END                
                    ELSE ''                                      
                   END          AS EmailID,                                      
                   Ue.City,                                      
                   Ue.[State],                                      
                   Ue.Country,                                      
                   Ue.Countrycode,                                      
               Ue.Pincode,                 
                   CASE                                       
                        WHEN Ue.Companyname <> '' THEN Ue.Officeaddress                                      
                        ELSE Ue.Residentialaddress                                      
             END          AS [ADDRESS],                                      
                   Ue.Initialremarks,           
                   Uss.Name     AS SourceName,                                      
                   Ums.Name AS MediumName,                                      
                   Ucs.Name     AS CampaignName,                                      
                   Ue.Parentid,                                      
                   CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF(                                   
                       RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),                                      
                       7,                                      
                       7,                                      
                       ' '                                      
                 )            AS CreatedDate,                                      
                 Ue.Createdby,                                 
                   ISNULL(                                      
                       (                                      
                           SELECT TOP 1                                      
                                                            
                                  1                                      
                           FROM   #TMPTBL AS Ul                                      
                           WHERE  Ul.Parentid = @Parentid                                      
                                  AND (                                      
                                          ISNULL(NULLIF(Ul.Countrycode, ''), '1')                                       
            +                                      
                               
                                          ISNULL(NULLIF(Ul.Mobileno, ''), '1')                                       
                                          = ISNULL(NULLIF(Ue.Countrycode, ''), '2')                                       
                                                                                
                                          + ISNULL(NULLIF(Ue.Mobileno, ''), '2')                                      
                                          OR ISNULL(NULLIF(Ul.Countrycode, ''), '1')                    
                                             +                                   
                                                                                   
                                             ISNULL(NULLIF(Ul.Mobileno, ''), '1')                                       
                                             =                                      
                                                                                   
                                             ISNULL(NULLIF(Ue.Countrycode1, ''), '2')                                
                                             +                                      
                                                                                   
                                             ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                                      
                                          OR ISNULL(NULLIF(Ul.Countrycode, ''), '1')                                       
                                             +                                      
                                                                                   
                                             ISNULL(NULLIF(Ul.Mobileno, ''), '1')                                       
                                             =                                      
                                                                                   
                                             ISNULL(NULLIF(Ue.Countrycode2, ''), '2')                                       
                                             +                            
                                                                                 
                                             ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                                      
                                          OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')                          
                                             +                                      
                                                                                   
                                  ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                                       
                                             =                                 
                                                                                   
                                             ISNULL(NULLIF(Ue.Countrycode, ''), '2')                                       
                                             +                                      
                                                                                   
                      ISNULL(NULLIF(Ue.Mobileno, ''), '2')                                      
                                          OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')                                       
                                             +                                      
                                                                                   
         ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                                       
                    =                                      
                                                                                   
                                             ISNULL(NULLIF(Ue.Countrycode1, ''), '2')                                       
                          +                                      
                                                                                   
                                             ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                                      
                                  OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1')                                       
                                             +                                      
                                                                                   
                                             ISNULL(NULLIF(Ul.Mobileno1, ''), '1')                                       
                 =                        
                                                                                   
                                             ISNULL(NULLIF(Ue.Countrycode2, ''), '2')                                       
                                             +                                      
                                                                                   
                                             ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                                      
                                          OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')                                       
                                             +                                      
                                                                                   
                                             ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                                       
                                             =                                      
                                                                                   
                            ISNULL(NULLIF(Ue.Countrycode, ''), '2')                                       
                                             +                                      
                                                                                   
                                             ISNULL(NULLIF(Ue.Mobileno, ''), '2')                                      
                                          OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')                                       
                                             +                                      
                  
                                             ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                                       
                                             =                                      
                                                                                   
                                             ISNULL(NULLIF(Ue.Countrycode1, ''), '2')                                       
                                      +                                      
               
                                             ISNULL(NULLIF(Ue.Mobileno1, ''), '2')                                      
                                          OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1')                                       
               +                                      
                                                                                   
                                             ISNULL(NULLIF(Ul.Mobileno2, ''), '1')                                       
                                             =                                      
                                 
       ISNULL(NULLIF(Ue.Countrycode2, ''), '2')                                       
                                             +                                      
                                                                                   
                                            ISNULL(NULLIF(Ue.Mobileno2, ''), '2')                                      
                                          OR ISNULL(NULLIF(Ul.Emailid, ''), '1')                    
                                           =                                      
                                                                                   
                                             ISNULL(NULLIF(Ue.Emailid, ''), '2')                           
                                          OR ISNULL(NULLIF(Ul.Emailid, ''), '1')                                       
                                             =                                      
                                                                                   
                                             ISNULL(NULLIF(Ue.Emailid1, ''), '2')                                      
                                          OR ISNULL(NULLIF(Ul.Emailid, ''), '1')                                     
                                             =                                      
                                                                                   
                                             ISNULL(NULLIF(Ue.Emailid2, ''), '2')                                      
                                          OR ISNULL(NULLIF(Ul.Emailid1, ''), '1')                                       
                                             =                                      
                                                                                   
                                             ISNULL(NULLIF(Ue.Emailid, ''), '2')                                      
                                          OR ISNULL(NULLIF(Ul.Emailid1, ''), '1')                                       
                             =                                      
                                                                                   
                                             ISNULL(NULLIF(Ue.Emailid1, ''), '2')                                      
                                          OR ISNULL(NULLIF(Ul.Emailid1, ''), '1')                                       
                                             =                                      
                                                                         
                                                                         
                                             ISNULL(NULLIF(Ue.Emailid2, ''), '2')                                      
                                          OR ISNULL(NULLIF(Ul.Emailid2, ''), '1')                                       
                                             =                                      
                                                                                   
                                  ISNULL(NULLIF(Ue.Emailid, ''), '2')                                      
             OR ISNULL(NULLIF(Ul.Emailid2, ''), '1')                                       
                                             =                                      
                                                                                   
                                             ISNULL(NULLIF(Ue.Emailid1, ''), '2')                                      
                                          OR ISNULL(NULLIF(Ul.Emailid2, ''), '1')              
                                             =                                      
                                                                                   
  ISNULL(NULLIF(Ue.Emailid2, ''), '2')                                      
                  )                                      
                       ),                                      
                       0                                      
                   )                            
                                        
                                                   
            AS Leads,                                      
                   --Ue.Isopen,                             
                   (CASE                                       
         WHEN Ue.Isopen = '1' THEN 'open'                                     
                        ELSE 'close'                                      
                   END) as Isopen  ,                            
                                                   
                   ROW_NUMBER() OVER(ORDER BY Enquiryid DESC) AS RowNumber                                      
                                                     
           FROM   Userenquiry Ue                                   
                   INNER JOIN Usersourcesettings Uss                                    
                        ON  Ue.Sourcename = Uss.Sourceid                                      
                   LEFT JOIN Usermediumsettings Ums                                     
           ON  Ue.Mediumname = Ums.Mediumid                                      
                   LEFT JOIN Usercampaignsettings Ucs                                     
                        ON  Ue.Campaignname = Ucs.Campaignid                                      
                   LEFT JOIN User_detail Ud                                     
                        ON  Ue.Createdby = Ud.User_id                            
                   left join tbl_MergeLeadsEnquiry  mergeenq                            
                        on  Ue.EnquiryID= mergeenq.EnquiryNo                     
                                                               
            WHERE  Ue.Parentid = @Parentid                       
            AND ue.CreatedBy = CASE                       
                               WHEN (@Userid = 0) THEN ue.CreatedBy                      
                               ELSE @Userid  END                        
             --AND Ue.CreatedBy = case when ISNULL(@Userid,,0) =0 then createdby else @Userid end                        
                   --AND Ue.CreatedBy = case when ISNULL(@Userid,null)=335  then createdby else @Userid end                        
                  -- AND Ud.User_ID = isnull(@Userid,335)                                     
                   AND (                                      
                           ISNULL(@Txtsearch, '') = ''                                      
                       OR Personname LIKE '%' + @Txtsearch + '%'                                      
                           OR Companyname LIKE '%' + @Txtsearch + '%'                             
                       )                                    
                                                         
        ) A    --where a.RowNumber>=@pageStartIndex and a.RowNumber<=@PageendSize                                  
 ORDER BY                                      
        A.CreatedDate DESC                    
                            
       drop table #TMPTBL                                      
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_viewuserenquriydetailsNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_viewuserenquriydetailsNew] --'',335,50
	@Txtsearch NVARCHAR(100),
	@Parentid BIGINT,
	@TopCount INT
AS
BEGIN
	SELECT A.Enquiryid,
	       A.Personname,
	       A.Companyname,
	       A.MobileNo3,
	       A.Mobileno1,
	       A.Mobileno2,
	       A.EmailID3,
	       A.Emailid1,
	       A.Emailid2,
	       A.Residentialaddress,
	       A.Officeaddress,
	       A.User_login,
	       A.MobileNo,
	       A.EmailID,
	       A.City,
	       A.[State],
	       A.Country,
	       A.Countrycode,
	       A.Pincode,
	       A.[ADDRESS],
	       A.Initialremarks,
	       A.SourceName,
	       A.MediumName,
	       A.CampaignName,
	       A.Parentid,
	       A.CreatedDate,
	       A.Createdby,
	       A.Leads,
	       A.Isopen,
	       A.RowNumber
	FROM   (
	           SELECT Ue.Enquiryid,
	                  Ue.Personname,
	                  Ue.Companyname,
	                  Ue.Mobileno  AS MobileNo3,
	                  Ue.Mobileno1,
	                  Ue.Mobileno2,
	                  Ue.Emailid   AS EmailID3,
	                  Ue.Emailid1,
	                  Ue.Emailid2,
	                  Ue.Residentialaddress,
	                  Ue.Officeaddress,
	                  Ud.User_login,
	                  ISNULL(Ue.Countrycode, '') + ISNULL(Ue.Mobileno, '') +
	                  
	                  CASE 
	                       WHEN ISNULL(Ue.Mobileno1, '') <> '' THEN ', ' +
	                            ISNULL(Ue.Countrycode1, '') 
	                            
	                            + ISNULL(Ue.Mobileno1, '')
	                       ELSE ''
	                  END +
	                  
	                  CASE 
	                       WHEN ISNULL(Ue.Mobileno2, '') < > '' THEN ', ' +
	                            ISNULL(Ue.Countrycode2, '') 
	                            
	                            + ISNULL(Ue.Mobileno2, '')
	                       ELSE ''
	                  END          AS MobileNo,
	                  ISNULL(Ue.Emailid, '') +
	                  
	                  CASE 
	                       WHEN ISNULL(Ue.Emailid1, '') <> '' THEN ', ' + ISNULL(Ue.Emailid1, '')
	                       ELSE ''
	                  END +
	                  
	                  CASE 
	                       WHEN ISNULL(Ue.Emailid2, '') <> '' THEN ', ' + ISNULL(Ue.Emailid2, '')
	                       ELSE ''
	                  END          AS EmailID,
	                  Ue.City,
	                  Ue.[State],
	                  Ue.Country,
	                  Ue.Countrycode,
	                  Ue.Pincode,
	                  CASE 
	                       WHEN Ue.Companyname <> '' THEN Ue.Officeaddress
	                       ELSE Ue.Residentialaddress
	                  END          AS [ADDRESS],
	                  Ue.Initialremarks,
	                  Uss.Name     AS SourceName,
	                  Ums.Name     AS MediumName,
	                  Ucs.Name     AS CampaignName,
	                  Ue.Parentid,
	                  CONVERT(VARCHAR(10), Ue.Createddate, 101) + STUFF(
	                      RIGHT(CONVERT(VARCHAR(26), Ue.Createddate, 109), 15),
	                      7,
	                      7,
	                      ' '
	                  )            AS CreatedDate,
	                  Ue.Createdby,
	                  ISNULL(
	                      (
	                          SELECT TOP 1
	                                 
	                                 1
	                          FROM   Userleads AS Ul
	                          WHERE  Ul.Parentid = @Parentid
	                                 AND (
	                                         ISNULL(NULLIF(Ul.Countrycode, ''), '1') 
	                                         +
	                                         
	                                         ISNULL(NULLIF(Ul.Mobileno, ''), '1') 
	                                         = ISNULL(NULLIF(Ue.Countrycode, ''), '2') 
	                                         
	                                         + ISNULL(NULLIF(Ue.Mobileno, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Countrycode, ''), '1') 
	                                            +
	                                            
	                                            ISNULL(NULLIF(Ul.Mobileno, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Countrycode1, ''), '2') 
	                                            +
	                                            
	                                            ISNULL(NULLIF(Ue.Mobileno1, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Countrycode, ''), '1') 
	                                            +
	                                            
	                                            ISNULL(NULLIF(Ul.Mobileno, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Countrycode2, ''), '2') 
	                                            +
	                                            
	                                            ISNULL(NULLIF(Ue.Mobileno2, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1') 
	                                            +
	                                            
	                                            ISNULL(NULLIF(Ul.Mobileno1, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Countrycode, ''), '2') 
	                                            +
	                                            
	                                            ISNULL(NULLIF(Ue.Mobileno, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1') 
	                                            +
	                                            
	                                            ISNULL(NULLIF(Ul.Mobileno1, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Countrycode1, ''), '2') 
	                                            +
	                                            
	                                            ISNULL(NULLIF(Ue.Mobileno1, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Countrycode1, ''), '1') 
	                                            +
	                                            
	                                            ISNULL(NULLIF(Ul.Mobileno1, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Countrycode2, ''), '2') 
	                                            +
	                                            
	                                            ISNULL(NULLIF(Ue.Mobileno2, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1') 
	                                            +
	                                            
	                                            ISNULL(NULLIF(Ul.Mobileno2, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Countrycode, ''), '2') 
	                                            +
	                                            
	                                            ISNULL(NULLIF(Ue.Mobileno, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1') 
	                                            +
	                                            
	                                            ISNULL(NULLIF(Ul.Mobileno2, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Countrycode1, ''), '2') 
	                                            +
	                                            
	                                            ISNULL(NULLIF(Ue.Mobileno1, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Countrycode2, ''), '1') 
	                                            +
	                                            
	                                            ISNULL(NULLIF(Ul.Mobileno2, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Countrycode2, ''), '2') 
	                                            +
	                                            
	                                            ISNULL(NULLIF(Ue.Mobileno2, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Emailid, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Emailid, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Emailid, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Emailid1, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Emailid, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Emailid2, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Emailid1, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Emailid, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Emailid1, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Emailid1, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Emailid1, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Emailid2, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Emailid2, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Emailid, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Emailid2, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Emailid1, ''), '2')
	                                         OR ISNULL(NULLIF(Ul.Emailid2, ''), '1') 
	                                            =
	                                            
	                                            ISNULL(NULLIF(Ue.Emailid2, ''), '2')
	                                     )
	                      ),
	                      0
	                  )            AS Leads,
	                  Ue.Isopen,
	                  ROW_NUMBER() OVER(ORDER BY ID DESC) AS RowNumber
	           FROM   Userenquiry Ue(NOLOCK)
	                  INNER JOIN Usersourcesettings Uss(NOLOCK)
	                       ON  Ue.Sourcename = Uss.Sourceid
	                  LEFT JOIN Usermediumsettings Ums(NOLOCK)
	                       ON  Ue.Mediumname = Ums.Mediumid
	                  LEFT JOIN Usercampaignsettings Ucs(NOLOCK)
	                       ON  Ue.Campaignname = Ucs.Campaignid
	                  LEFT JOIN User_detail Ud(NOLOCK)
	                       ON  Ue.Createdby = Ud.User_id
	           WHERE  Ue.Parentid = @Parentid
	                  AND (
	                          ISNULL(@Txtsearch, '') = ''
	                          OR Personname LIKE '%' + @Txtsearch + '%'
	                          OR Companyname LIKE '%' + @Txtsearch + '%'
	                      )
	       ) A
	ORDER BY
	       A.CreatedDate DESC
END 
 



GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserLeadDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE Usp_ViewUserLeadDetails                         
 @txtSearch NVARCHAR(100),                          
 @ParentID BIGINT,                          
 @Userid int=0                          
AS                          
BEGIN                          
 SELECT distinct A.ID,                          
        A.LeadNo,                          
        A.PersonName,                          
        A.CompanyName,                          
        A.MobileNo,                          
        A.EmailID,                          
        A.City,                          
        A.[State],                          
        A.Country,                          
        A.CountryCode,                          
        A.PinCode,                          
        A.ResidentialAddress,                          
        A.OfficeAddress,                          
        A.SourceName,                          
        A.MediumName,                          
        A.CampaignName,                          
        A.InitialRemarks,                          
        A.ParentID,                          
        A.User_Login,          
        dbo.[fn_getusertimefromindiantime](@ParentID,A.FollowupDate) as NextStatusDate,      
        dbo.[fn_getusertimefromindiantime](@ParentID,A.CreatedOn) as CreatedOn,            
        dbo.[fn_getusertimefromindiantime](@ParentID,A.CreatedOn1) as CreatedOn1New,            
        A.CreatedOn1,      
        A.AssignedTo,                          
        A.User_Login,                          
        A.Remarks,                          
        CASE                           
             WHEN ISNULL(A.FollowupStatus, '') <> '' THEN                           
                  '<p><b>Follow Up Status:&nbsp;&nbsp;</b>' + CAST(ISNULL(A.FollowupStatus, '')     
                  AS VARCHAR(50))                           
                  + '</p>'                          
             ELSE ''                          
        END +                          
        CASE                           
             WHEN ISNULL(A.FollowupDate, '') <> '' THEN                           
                  '<p><b>Next Status Date:&nbsp;&nbsp;</b>' + CAST(A.FollowupDate AS VARCHAR(50))                    + '</p>'                          
             ELSE ''                          
        END +                          
        CASE                           
             WHEN ISNULL(A.Products, '') <> '' THEN                           
                  '<p><b>Products:&nbsp;&nbsp;</b>' + CAST(A.Products AS VARCHAR(50))                          + '</p>'                          
             ELSE ''                          
        END +                          
        CASE                           
             WHEN ISNULL(A.AmountPaid, 0) <> 0 THEN                           
                  '<p><b>Amount Paid:&nbsp;&nbsp;</b>' + CAST(                          
                      CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS                           
                      VARCHAR(50)                          
                  ) + '</p>'                          
             ELSE ''                          
        END +                          
        CASE                           
             WHEN ISNULL(A.Remarks, '') <> '' THEN                           
                  '<p><b>Remarks:&nbsp;&nbsp;</b>' + ISNULL(A.Remarks, '') +                           
                  '</p>'                          
             ELSE ''                          
        END  AS FollowUp,                          
        A.MobileNo1,                          
        A.MobileNo2,                          
        A.MobileNo3,                          
        A.EmailID3,                          
        A.EmailID1,                          
        A.EmailID2,                          
        A.FollowupStatus,                          
        A.assigneduser                          
 FROM   (       
            SELECT UL.ID,                          
                   UL.LeadNo,                          
                   UL.PersonName,                          
                   UL.CompanyName,              
                   UL.CreatedOn as CreatedOn1 ,                          
                   --ISNULL(UL.CountryCode, '') + ISNULL(UL.MobileNo, '') +                          
                  -- CASE                           
                       -- WHEN ISNULL(UL.MobileNo1, '') < > '' THEN ', ' +                           
                            -- ISNULL(UL.CountryCode1, '') + ISNULL(UL.MobileNo1, '')                     
                     case When(ISNULL(UL.CountryCode, '') <> ''                
)                          then                
                         case   When(ISNULL(UL.CountryCode, '') + ISNULL(UL.MobileNo, '')) in           (                        
                                select ISNULL(C_UDTemp.CountryCode,'')  +     
                                ISNULL(C_UDTemp.Mobile,'') as MobileNo                         
        from   Client_UnSubscribeDetails C_UDTemp     
        join ClientPageDetail_Unsubscribe cpd on                     
                                 --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                        
                                   C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                                        )                        
                                                    
                            then '<p style="color:red;" >'+(ISNULL(UL.Countrycode, '') + ISNULL(UL.MobileNo, ''))+ '</p>'                        
                              else                        
              (ISNULL(UL.Countrycode, '') + ISNULL(UL.MobileNo, ''))                        
                     end                 
                                     
                     else ''                
                        end                
                                     
                     +                        
                                             
                       CASE                             
                        WHEN ISNULL(UL.Mobileno1, '') <> '' THEN ', ' +                         
                                                
                        case when (ISNULL(UL.Countrycode1, '') + ISNULL(UL.Mobileno1, '')) in                        
                   (                        
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                           
                      from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                     
                      --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                       
                           C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                     
                    )                        
                    then '<p style="color:red;" >'+(ISNULL(UL.Countrycode1, '') + ISNULL(UL.Mobileno1, ''))+ '</p>'                        
                    else                        
                        (ISNULL(UL.Countrycode1, '') + ISNULL(UL.Mobileno1, ''))                        
                    end                           
                                                    
                                                      
                        ELSE ''                          
                  END +                          
                   CASE                           
                        WHEN ISNULL(UL.MobileNo2, '') <> '' THEN ', ' +                          
                        case when (ISNULL(UL.Countrycode2, '') + ISNULL(UL.MobileNo2, '')) in                        
                   (                        
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                           
                      from   Client_UnSubscribeDetails C_UDTemp      
                      join ClientPageDetail_Unsubscribe cpd on                     
                     C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID     
                    )                        
                    then '<p style="color:red;" >'+(ISNULL(UL.Countrycode2, '') +     
                    ISNULL(UL.Mobileno2, ''))+ '</p>'                        
                    else                        
                        (ISNULL(UL.Countrycode2, '') + ISNULL(UL.Mobileno2, ''))                        
                    end                        
                                                
                                                 
                            -- ISNULL(UL.CountryCode2, '') + ISNULL(UL.MobileNo2, '')            
                        ELSE ''                          
                   END            AS MobileNo,                          
                    CASE                                               
                        WHEN ISNULL(UL.Emailid, '') <> '' THEN ', '                         
                +                        
                           case when (ISNULL(UL.Emailid, '')) in                        
                    (                        
                     select ISNULL(C_UDTemp.Email,'') as EmailID                           
          from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                     
                      -- 'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                      
                        C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                     
                    )                        
                                        
                    then '<p style="color:red;" >'+(ISNULL(UL.Emailid, ''))+ '</p>'                        
                    else                        
                        (ISNULL(UL.Emailid, ''))                        
                    END                        
                    ELSE   ''                        
      END+                        
                                         
                 --  ISNULL(UL.EmailID, '') +                          
                   CASE                           
                        WHEN ISNULL(UL.EmailID1, '') <> '' THEN ', ' +                        
                         case when (ISNULL(UL.Emailid1, '')) in                        
                   (                        
                     select ISNULL(C_UDTemp.Email,'') as EmailID                           
                                              
                      from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                     
                      --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                     
                      C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                      
                    )                        
                    then '<p style="color:red;" >'+(ISNULL(UL.Emailid1, ''))+ '</p>'                        
else                        
                        (ISNULL(UL.Emailid1, ''))                        
                       END                        
                                                        
                                                
                                                
                        -- ISNULL(UL.EmailID1, '')                          
                        ELSE ''                          
                   END +                          
                   CASE                           
                        WHEN ISNULL(UL.EmailID2, '') <> '' THEN ', ' +                        
                        case when (ISNULL(UL.Emailid2, '')) in                        
                   (                        
                     select ISNULL(C_UDTemp.Email,'') as EmailID                           
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                          
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                          
                      from   Client_UnSubscribeDetails C_UDTemp      
                      join ClientPageDetail_Unsubscribe cpd on                     
                      --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID    
                      C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                       
                    )                        
                    then '<p style="color:red;" >'+(ISNULL(UL.Emailid2, ''))+ '</p>'                                     else                        
                        (ISNULL(UL.Emailid2, ''))                        
                        end                        
                        -- ISNULL(UL.EmailID2, '')                          
                        ELSE ''                          
                   END            AS EmailID,                          
                   UL.City,                          
                   UL.[State],                          
                   UL.Country,                          
                   UL.CountryCode,                          
                   UL.PinCode,                          
                   UL.ResidentialAddress,                          
                   UL.OfficeAddress,                          
           UL.AssignedTo,                          
                   USS.Name       AS SourceName,                          
                   UMS.Name       AS MediumName,                          
                   UCS.Name       AS CampaignName,                          
                   UL.InitialRemarks,                          
                   UL.ParentID,                          
   (select FollowUpStatus from FollowUp_Status f where ul.FollowUpStatus=f.id) as FollowupStatus,                          
                   UL.FollowupDate,                          
                   UL.Remarks,                          
                   ISNULL(UL.AmountPaid, 0) AS AmountPaid,                          
                  CONVERT(VARCHAR(10),  UL.CreatedOn, 101) +                          
STUFF(                          
            RIGHT(CONVERT(VARCHAR(26),   UL.CreatedOn, 109), 15),                          
            7,                          
            7,                          
            ' '                          
        )  AS CreatedOn,                          
                   UL.CreatedBy,                          
                   UL.ModifiedOn,                          
                   UL.ModifiedBy,                          
                   UD.User_Login,                          
                   UL.MobileNo    AS MobileNo3,                          
                   UL.MobileNo1,                          
                   UL.MobileNo2,                          
                   UL.EmailID     AS EmailID3,                          
               UL.EmailID1,                          
                   UL.EmailID2,                          
                   (                          
                       SELECT STUFF(                          
                                  (                          
                                      SELECT N', ' + ss.Name                          
                                      FROM   ProductMaster AS ss                          
                                             INNER JOIN dbo.fn_Split(ul.Products, '#') AS                           
                                                  fs                          
                                                  ON  ss.ProductID = fs.[value]                           
                                                      FOR XML PATH(''),                         
                       TYPE                          
                                  ) .value('text()[1]', 'nvarchar(max)'),                          
                                  1,                          
                                  2,                          
                                  N''                          
                              )                          
                   )              AS Products,                          
                   UD.User_Login  AS assigneduser                          
            FROM   UserLeads UL(NOLOCK)                          
                   INNER JOIN UserSourceSettings USS(NOLOCK)                          
                        ON  UL.SourceName = USS.SourceID                          
                   LEFT JOIN UserMediumSettings UMS(NOLOCK)                          
                        ON  UL.MediumName = UMS.MediumID                          
                   LEFT JOIN UserCampaignSettings UCS(NOLOCK)                          
                        ON  UL.CampaignName = UCS.CampaignID                          
                   LEFT JOIN User_Detail UD(NOLOCK)                          
                        ON  UL.AssignedTo = UD.User_ID                          
                   --LEFT JOIN FollowUp_Status FUS(NOLOCK)                          
                   --     ON  UL.FollowUpStatus = FUS.ID                          
                   LEFT JOIN User_Detail UD1(NOLOCK)                          
                        ON  UL.CreatedBy = UD1.User_ID                          
            WHERE  UL.ParentID = @ParentID                          
            AND UL.AssignedTo = CASE                           
                               WHEN (@Userid = 0) THEN UL.AssignedTo                           
                               ELSE @Userid                          
                          END                           
             --AND UL.CreatedBy = CASE                           
             --                  WHEN (@Userid = 0) THEN UL.CreatedBy                           
             --                  ELSE @Userid                          
             --             END                              
                   AND (                          
                           ISNULL(@txtSearch, '') = ''                          
                           OR PersonName LIKE '%' + @txtSearch + '%'                          
                           OR CompanyName LIKE '%' + @txtSearch + '%'                          
                       )                          
        )       A                          
 ORDER BY                          
        A.CreatedOn1 DESC                          
END    



