                      --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID     
                           C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID   
                    )      
                    then '<p style="color:red;" >'+(ISNULL(UL.Countrycode1, '') + ISNULL(UL.Mobileno1, ''))+ '</p>'      
                    else      
