/* ============================================================
   Procedure: [dbo].[Usp_ViewUserLeadDetails1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

----------------------------------------------------------------------------------------------------------------------------------------------

CREATE   PROCEDURE [dbo].[Usp_ViewUserLeadDetails1]          
 @txtSearch NVARCHAR(100),                      
 @ParentID BIGINT,                      
 @Userid int=0                      
AS                      
BEGIN             
DECLARE @Pivot_Column [nvarchar](max);      
DECLARE @Query [nvarchar](max);      
      
/*Select Pivot Column*/      
SELECT @Pivot_Column= COALESCE(@Pivot_Column+',','')+ QUOTENAME(fieldname) FROM      
(SELECT DISTINCT [fieldname] FROM customfields where ParentID=@ParentID)Tab     
     
/*Create Dynamic Query*/      
SELECT @Query='SELECT leadid, '+@Pivot_Column+' into ##temp FROM       
(SELECT leadid, [fieldname] , fieldvalue FROM (select x.LeadID, y.fieldname, x.fieldvalue  From customfieldLeadvalue x inner join customfields y on x.fieldID=y.field_ID)q )Tab1      
PIVOT      
(      
max(fieldvalue) FOR [fieldname] IN ('+@Pivot_Column+')) AS Tab2      
ORDER BY Tab2.LeadID'    
EXEC  sp_executesql  @Query    
      
/*Execute Query*/      
    
--SELECT into #T1 execute ('execute ' + @Query )    
--select t2.* from ##temp t2             
 SELECT distinct A.ID,                      
        A.LeadNo,                      
        A.PersonName,                      
        A.CompanyName,                      
        A.MobileNo,                      
        A.EmailID,                      
        A.City,                      
        A.[State],                      
        A.Country,                      
        A.CountryCode,                      
        A.PinCode,                      
        A.ResidentialAddress,                      
        A.OfficeAddress,                      
        A.SourceName,                      
        A.MediumName,                      
        A.CampaignName,                      
        A.InitialRemarks,                      
        A.ParentID,                      
        A.User_Login,      
        A.NextStatusDate,                     
        A.CreatedOn,          
        A.CreatedOn1,                      
        A.AssignedTo,                      
        A.Remarks,                      
        CASE                       
             WHEN ISNULL(A.FollowupStatus, '') <> '' THEN                       
                  '<p><b>Follow Up Status:&nbsp;&nbsp;</b>' + CAST(ISNULL(A.FollowupStatus, '') AS VARCHAR(50))                       
                  + '</p>'                      
             ELSE ''                      
        END +                      
        CASE                       
             WHEN ISNULL(A.NextStatusDate, '') <> '' THEN                       
                  '<p><b>Next Status Date:&nbsp;&nbsp;</b>' + CAST(A.NextStatusDate AS VARCHAR(50))                       
                  + '</p>'                      
             ELSE ''                      
        END +                      
        CASE                       
             WHEN ISNULL(A.Products, '') <> '' THEN                       
                  '<p><b>Next Status Date:&nbsp;&nbsp;</b>' + CAST(A.Products AS VARCHAR(50))                       
                  + '</p>'                      
             ELSE ''                      
        END +                      
        CASE                       
             WHEN ISNULL(A.AmountPaid, 0) <> 0 THEN                       
                  '<p><b>Amount Paid:&nbsp;&nbsp;</b>' + CAST(                      
                      CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS                       
                      VARCHAR(50)                      
                  ) + '</p>'                      
             ELSE ''                      
        END +                      
        CASE                       
             WHEN ISNULL(A.Remarks, '') <> '' THEN                       
                  '<p><b>Remarks:&nbsp;&nbsp;</b>' + ISNULL(A.Remarks, '') +                       
                  '</p>'                      
             ELSE ''                      
        END  AS FollowUp,                      
        A.MobileNo1,                      
        A.MobileNo2,                      
        A.MobileNo3,                      
        A.EmailID3,                      
        A.EmailID1,                
        A.EmailID2,                      
        A.FollowupStatus,                      
        A.assigneduser   into #temp1                   
 FROM   (                      
            SELECT UL.ID,                      
                   UL.LeadNo,                      
                   UL.PersonName,                      
                   UL.CompanyName,          
                   UL.CreatedOn as CreatedOn1 ,                      
                   --ISNULL(UL.CountryCode, '') + ISNULL(UL.MobileNo, '') +                      
                  -- CASE                       
                       -- WHEN ISNULL(UL.MobileNo1, '') < > '' THEN ', ' +                       
                            -- ISNULL(UL.CountryCode1, '') + ISNULL(UL.MobileNo1, '')                    
                     case When(ISNULL(UL.CountryCode, '') <> ''            
)                          then            
                                         
                       
                         case   When(ISNULL(UL.CountryCode, '') + ISNULL(UL.MobileNo, '')) in                    
   (                    
                                select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                     
  from   Client_UnSubscribeDetails C_UDTemp join ClientPageDetail_Unsubscribe cpd on                 
                                 --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                    
                                   C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                 
                             )                    
                                                
                            then '<p style="color:red;" >'+(ISNULL(UL.Countrycode, '') + ISNULL(UL.MobileNo, ''))+ '</p>'                    
                              else                    
              (ISNULL(UL.Countrycode, '') + ISNULL(UL.MobileNo, ''))                    
                     end             
                                 
                     else ''            
                        end            
                                 
                     +                    
                                         
                       CASE                         
                        WHEN ISNULL(UL.Mobileno1, '') <> '' THEN ', ' +                     
                                            
                        case when (ISNULL(UL.Countrycode1, '') + ISNULL(UL.Mobileno1, '')) in                    
                   (                    
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                       
                      from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                 
                      --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                   
                           C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                 
                    )                    
                    then '<p style="color:red;" >'+(ISNULL(UL.Countrycode1, '') + ISNULL(UL.Mobileno1, ''))+ '</p>'                    
                    else                    
                        (ISNULL(UL.Countrycode1, '') + ISNULL(UL.Mobileno1, ''))                    
                    end                       
                                                
                                                  
                        ELSE ''                      
                  END +                      
                   CASE                       
                        WHEN ISNULL(UL.MobileNo2, '') <> '' THEN ', ' +                      
                        case when (ISNULL(UL.Countrycode2, '') + ISNULL(UL.MobileNo2, '')) in                    
              (                    
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                       
                      from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                 
                     -- 'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                  
                        C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                 
                    )                    
                    then '<p style="color:red;" >'+(ISNULL(UL.Countrycode2, '') + ISNULL(UL.Mobileno2, ''))+ '</p>'                    
                    else                    
                        (ISNULL(UL.Countrycode2, '') + ISNULL(UL.Mobileno2, ''))                    
                    end                    
                                            
                                             
                            -- ISNULL(UL.CountryCode2, '') + ISNULL(UL.MobileNo2, '')                      
                        ELSE ''                      
                   END            AS MobileNo,                      
                    CASE                                           
                        WHEN ISNULL(UL.Emailid, '') <> '' THEN ', '                     
                +                    
                           case when (ISNULL(UL.Emailid, '')) in                    
                    (                    
                     select ISNULL(C_UDTemp.Email,'') as EmailID                       
          from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                 
                      -- 'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                  
                        C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                 
                    )                    
                                    
                    then '<p style="color:red;" >'+(ISNULL(UL.Emailid, ''))+ '</p>'                    
                    else                    
                        (ISNULL(UL.Emailid, ''))                    
                    END                    
                    ELSE   ''                    
      END+                    
                                     
                 --  ISNULL(UL.EmailID, '') +                      
                   CASE                       
                        WHEN ISNULL(UL.EmailID1, '') <> '' THEN ', ' +                    
                         case when (ISNULL(UL.Emailid1, '')) in                    
                   (                    
                     select ISNULL(C_UDTemp.Email,'') as EmailID                       
                                          
                      from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                 
                      --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                 
                      C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                  
                    )                    
                    then '<p style="color:red;" >'+(ISNULL(UL.Emailid1, ''))+ '</p>'                    
else                    
                        (ISNULL(UL.Emailid1, ''))                    
                       END                    
                                                    
                                            
                                            
                        -- ISNULL(UL.EmailID1, '')                      
                        ELSE ''                      
                   END +                      
                   CASE                       
                        WHEN ISNULL(UL.EmailID2, '') <> '' THEN ', ' +                    
                        case when (ISNULL(UL.Emailid2, '')) in                    
                   (                    
      select ISNULL(C_UDTemp.Email,'') as EmailID                       
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                      
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                      
                      from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                 
                      --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                
                      C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                   
                    )                    
                    then '<p style="color:red;" >'+(ISNULL(UL.Emailid2, ''))+ '</p>'                    
                    else                    
                        (ISNULL(UL.Emailid2, ''))                    
                        end                    
                                            
                        -- ISNULL(UL.EmailID2, '')                      
                        ELSE ''                      
                   END            AS EmailID,                      
                   UL.City,                      
                   UL.[State],                      
                   UL.Country,                      
                   UL.CountryCode,                      
                   UL.PinCode,                      
                   UL.ResidentialAddress,                      
                   UL.OfficeAddress,                      
           UL.AssignedTo,                      
                   USS.Name       AS SourceName,                      
                   UMS.Name       AS MediumName,                      
                   UCS.Name       AS CampaignName,                      
                   UL.InitialRemarks,                      
                   UL.ParentID,                      
   (select FollowUpStatus from FollowUp_Status f where ul.FollowUpStatus=f.id) as FollowupStatus,                      
                   UL.NextStatusDate,                      
                   UL.Remarks,                      
                   ISNULL(UL.AmountPaid, 0) AS AmountPaid,                      
                  CONVERT(VARCHAR(10),  UL.CreatedOn, 101) +                      
STUFF(                      
            RIGHT(CONVERT(VARCHAR(26),   UL.CreatedOn, 109), 15),                      
            7,                      
            7,                      
            ' '                      
        )  AS CreatedOn,                      
                   UL.CreatedBy,                      
                   UL.ModifiedOn,                      
                   UL.ModifiedBy,                      
                   UD.User_Login,                      
                   UL.MobileNo    AS MobileNo3,                      
                   UL.MobileNo1,                      
                   UL.MobileNo2,                      
                   UL.EmailID     AS EmailID3,                      
               UL.EmailID1,                      
                   UL.EmailID2,                      
                   (                      
                       SELECT STUFF(                      
                                  (                      
                                      SELECT N', ' + ss.Name                      
                                      FROM   ProductMaster AS ss                      
                                             INNER JOIN dbo.fn_Split(ul.Products, '#') AS                       
                                                  fs                      
                                                  ON  ss.ProductID = fs.[value]                       
                                                      FOR XML PATH(''),                      
                       TYPE                      
                                  ) .value('text()[1]', 'nvarchar(max)'),                    
                                  1,                      
                                  2,                      
                                  N''                      
                              )                      
                   )              AS Products,                      
                   UD.User_Login  AS assigneduser                      
            FROM   UserLeads UL(NOLOCK)                      
                   INNER JOIN UserSourceSettings USS(NOLOCK)                     
                        ON  UL.SourceName = USS.SourceID                      
                   LEFT JOIN UserMediumSettings UMS(NOLOCK)                      
                        ON  UL.MediumName = UMS.MediumID                      
                   LEFT JOIN UserCampaignSettings UCS(NOLOCK)                      
                        ON  UL.CampaignName = UCS.CampaignID                      
                   LEFT JOIN User_Detail UD(NOLOCK)                      
                        ON  UL.AssignedTo = UD.User_ID                      
                   --LEFT JOIN FollowUp_Status FUS(NOLOCK)                      
                   --     ON  UL.FollowUpStatus = FUS.ID                      
                   LEFT JOIN User_Detail UD1(NOLOCK)                      
                        ON  UL.CreatedBy = UD1.User_ID                      
            WHERE  UL.ParentID = @ParentID                      
            AND UL.CreatedBy = CASE                       
                               WHEN (@Userid = 0) THEN UL.CreatedBy                       
                               ELSE @Userid                      
                          END                       
                                   
                   AND (                      
                           ISNULL(@txtSearch, '') = ''                      
                           OR PersonName LIKE '%' + @txtSearch + '%'                      
                           OR CompanyName LIKE '%' + @txtSearch + '%'                      
                       )                      
        )       A            
 ORDER BY                      
        A.CreatedOn1 DESC    
        IF OBJECT_ID('tempdb..##temp') IS NOT NULL   
        begin  
        select * from #temp1 x left join ##temp y on x.ID=y.leadid   
        end  
        else  
        begin  
         select * from #temp1  
         end  
        --IF OBJECT_ID('tempdb.dbo.##temp', 'U') IS NOT NULL    
  DROP TABLE ##temp;     
        drop table #temp1                
END 



GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserLeadDetails1_deepak]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

----------------------------------------------------------------------------------------------------------------------------------------------  
  
CREATE   PROCEDURE Usp_ViewUserLeadDetails1_deepak --'',31078,31078            
 @txtSearch NVARCHAR(100),                        
 @ParentID BIGINT,                        
 @Userid int=0                        
AS                        
BEGIN               
DECLARE @Pivot_Column [nvarchar](max);        
DECLARE @Query [nvarchar](max);        
        
/*Select Pivot Column*/        
SELECT @Pivot_Column= COALESCE(@Pivot_Column+',','')+ QUOTENAME(fieldname) FROM        
(SELECT DISTINCT [fieldname] FROM customfields where ParentID=@ParentID)Tab       
       
/*Create Dynamic Query*/        
SELECT @Query='SELECT leadid, '+@Pivot_Column+' into ##temp FROM         
(SELECT leadid, [fieldname] , fieldvalue FROM (select x.LeadID, y.fieldname, x.fieldvalue  From customfieldLeadvalue x inner join customfields y on x.fieldID=y.field_ID)q )Tab1        
PIVOT        
(        
max(fieldvalue) FOR [fieldname] IN ('+@Pivot_Column+')) AS Tab2        
ORDER BY Tab2.LeadID'      
EXEC  sp_executesql  @Query      
        
/*Execute Query*/        
      
--SELECT into #T1 execute ('execute ' + @Query )      
--select t2.* from ##temp t2               
 SELECT distinct A.ID,                        
        A.LeadNo,                        
        A.PersonName,                        
        A.CompanyName,                        
        A.MobileNo,                        
        A.EmailID,                        
        A.City,                        
        A.[State],                        
        A.Country,                        
        A.CountryCode,                        
        A.PinCode,                        
        A.ResidentialAddress,                        
        A.OfficeAddress,                        
        A.SourceName,                        
        A.MediumName,                        
        A.CampaignName,                        
        A.InitialRemarks,                        
        A.ParentID,                        
        A.User_Login,        
        A.FollowupDate as NextStatusDate,                       
        A.CreatedOn,            
        A.CreatedOn1,                        
        A.AssignedTo,                        
        A.Remarks,                        
        CASE                         
             WHEN ISNULL(A.FollowupStatus, '') <> '' THEN                         
                  '<p><b>Follow Up Status:&nbsp;&nbsp;</b>' + CAST(ISNULL(A.FollowupStatus, '') AS VARCHAR(50))                         
                  + '</p>'                        
             ELSE ''                        
        END +                        
        CASE                         
             WHEN ISNULL(A.FollowupDate, '') <> '' THEN                         
                  '<p><b>Next Status Date:&nbsp;&nbsp;</b>' + CAST(A.FollowupDate AS VARCHAR(50))                         
                  + '</p>'                        
             ELSE ''                        
        END +                        
        CASE                         
             WHEN ISNULL(A.Products, '') <> '' THEN                         
                  '<p><b>Next Status Date:&nbsp;&nbsp;</b>' + CAST(A.Products AS VARCHAR(50))                         
                  + '</p>'                        
             ELSE ''                        
        END +                        
        CASE                         
             WHEN ISNULL(A.AmountPaid, 0) <> 0 THEN                         
                  '<p><b>Amount Paid:&nbsp;&nbsp;</b>' + CAST(                        
                      CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS                         
                      VARCHAR(50)                        
                  ) + '</p>'                        
             ELSE ''                        
        END +                        
        CASE                         
             WHEN ISNULL(A.Remarks, '') <> '' THEN                         
                  '<p><b>Remarks:&nbsp;&nbsp;</b>' + ISNULL(A.Remarks, '') +                         
                  '</p>'                        
             ELSE ''                        
        END  AS FollowUp,                        
        A.MobileNo1,                        
        A.MobileNo2,                        
        A.MobileNo3,                        
        A.EmailID3,                        
        A.EmailID1,                  
        A.EmailID2,                        
        A.FollowupStatus,                        
        A.assigneduser   into #temp1                     
 FROM   (                        
            SELECT UL.ID,                        
                   UL.LeadNo,                        
                   UL.PersonName,                        
                   UL.CompanyName,            
                   UL.CreatedOn as CreatedOn1 ,                        
                   --ISNULL(UL.CountryCode, '') + ISNULL(UL.MobileNo, '') +                        
                  -- CASE                         
                       -- WHEN ISNULL(UL.MobileNo1, '') < > '' THEN ', ' +                         
                            -- ISNULL(UL.CountryCode1, '') + ISNULL(UL.MobileNo1, '')                      
                     case When(ISNULL(UL.CountryCode, '') <> ''              
)                          then              
                                           
                         
                         case   When(ISNULL(UL.CountryCode, '') + ISNULL(UL.MobileNo, '')) in                      
   (                      
                                select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                       
  from   Client_UnSubscribeDetails C_UDTemp join ClientPageDetail_Unsubscribe cpd on                   
                                 --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                      
                                   C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                   
                             )                      
                                                  
                            then '<p style="color:red;" >'+(ISNULL(UL.Countrycode, '') + ISNULL(UL.MobileNo, ''))+ '</p>'                      
                              else                      
              (ISNULL(UL.Countrycode, '') + ISNULL(UL.MobileNo, ''))                      
                     end               
                                   
                     else ''              
                        end              
                                   
                     +                      
                                           
                       CASE                           
                        WHEN ISNULL(UL.Mobileno1, '') <> '' THEN ', ' +                       
                                              
                        case when (ISNULL(UL.Countrycode1, '') + ISNULL(UL.Mobileno1, '')) in                      
                   (                      
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                         
                      from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                   
                      --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                     
                           C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                   
                    )                      
                    then '<p style="color:red;" >'+(ISNULL(UL.Countrycode1, '') + ISNULL(UL.Mobileno1, ''))+ '</p>'                      
                    else                      
                        (ISNULL(UL.Countrycode1, '') + ISNULL(UL.Mobileno1, ''))                      
                    end                         
               
                                                    
                        ELSE ''                        
                  END +                        
                   CASE                         
                        WHEN ISNULL(UL.MobileNo2, '') <> '' THEN ', ' +                        
                        case when (ISNULL(UL.Countrycode2, '') + ISNULL(UL.MobileNo2, '')) in                      
              (                      
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                         
                      from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                   
                     -- 'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                    
                        C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                   
                    )                      
                    then '<p style="color:red;" >'+(ISNULL(UL.Countrycode2, '') + ISNULL(UL.Mobileno2, ''))+ '</p>'                      
                    else                      
                        (ISNULL(UL.Countrycode2, '') + ISNULL(UL.Mobileno2, ''))                      
                    end                      
                                              
                                               
                            -- ISNULL(UL.CountryCode2, '') + ISNULL(UL.MobileNo2, '')                        
                        ELSE ''                        
                   END            AS MobileNo,                        
                    CASE                                             
                        WHEN ISNULL(UL.Emailid, '') <> '' THEN ', '                       
                +                      
                           case when (ISNULL(UL.Emailid, '')) in                      
                    (                      
                     select ISNULL(C_UDTemp.Email,'') as EmailID                         
          from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                   
                      -- 'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                    
                        C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                   
                    )                      
                                      
                    then '<p style="color:red;" >'+(ISNULL(UL.Emailid, ''))+ '</p>'                      
                    else                      
                        (ISNULL(UL.Emailid, ''))                      
                    END                      
                    ELSE   ''                      
      END+                      
                                       
                 --  ISNULL(UL.EmailID, '') +                        
                   CASE                         
                        WHEN ISNULL(UL.EmailID1, '') <> '' THEN ', ' +                      
                         case when (ISNULL(UL.Emailid1, '')) in                      
                   (                      
                     select ISNULL(C_UDTemp.Email,'') as EmailID                         
                                            
                      from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                   
                      --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                   
                      C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                    
                    )                      
                    then '<p style="color:red;" >'+(ISNULL(UL.Emailid1, ''))+ '</p>'                      
else                      
                        (ISNULL(UL.Emailid1, ''))                      
                       END                      
                                                      
                                       
                                              
                        -- ISNULL(UL.EmailID1, '')                        
                        ELSE ''                        
                   END +                        
                   CASE                         
                        WHEN ISNULL(UL.EmailID2, '') <> '' THEN ', ' +                      
                        case when (ISNULL(UL.Emailid2, '')) in                      
                   (                      
      select ISNULL(C_UDTemp.Email,'') as EmailID                         
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                        
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                        
                      from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                   
                      --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                  
                      C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                     
                    )                      
                    then '<p style="color:red;" >'+(ISNULL(UL.Emailid2, ''))+ '</p>'                      
                    else                      
                        (ISNULL(UL.Emailid2, ''))                      
                        end                      
                                              
                        -- ISNULL(UL.EmailID2, '')                        
                        ELSE ''                        
                   END            AS EmailID,                        
                   UL.City,                        
                   UL.[State],                        
                   UL.Country,                        
                   UL.CountryCode,                        
                   UL.PinCode,                        
                   UL.ResidentialAddress,                        
                   UL.OfficeAddress,                        
           UL.AssignedTo,                        
                   USS.Name       AS SourceName,                        
                   UMS.Name       AS MediumName,                        
                   UCS.Name       AS CampaignName,                        
                   UL.InitialRemarks,                        
                   UL.ParentID,                        
   (select FollowUpStatus from FollowUp_Status f where ul.FollowUpStatus=f.id) as FollowupStatus,                        
                   UL.FollowupDate,                        
                   UL.Remarks,                        
                   ISNULL(UL.AmountPaid, 0) AS AmountPaid,                        
                  CONVERT(VARCHAR(10),  UL.CreatedOn, 101) +                        
STUFF(                        
            RIGHT(CONVERT(VARCHAR(26),   UL.CreatedOn, 109), 15),                        
            7,                        
            7,                        
            ' '                        
        )  AS CreatedOn,                        
                   UL.CreatedBy,                        
                   UL.ModifiedOn,                        
                   UL.ModifiedBy,                        
                   UD.User_Login,                        
                   UL.MobileNo    AS MobileNo3,                        
                   UL.MobileNo1,                        
                   UL.MobileNo2,                        
                   UL.EmailID     AS EmailID3,                        
               UL.EmailID1,                        
                   UL.EmailID2,                        
                   (                        
                       SELECT STUFF(                        
                                  (                        
                                      SELECT N', ' + ss.Name                        
                                      FROM   ProductMaster AS ss                        
                                             INNER JOIN dbo.fn_Split(ul.Products, '#') AS                         
                                                  fs                        
                                                  ON  ss.ProductID = fs.[value]                         
                                                      FOR XML PATH(''),                        
                       TYPE                        
                                  ) .value('text()[1]', 'nvarchar(max)'),                      
                                  1,                        
                                  2,                        
                                  N''                        
                              )                        
                   )              AS Products,                        
                   UD.User_Login  AS assigneduser                        
            FROM   UserLeads UL(NOLOCK)                        
                   INNER JOIN UserSourceSettings USS(NOLOCK)                       
                        ON  UL.SourceName = USS.SourceID                        
                   LEFT JOIN UserMediumSettings UMS(NOLOCK)                        
                        ON  UL.MediumName = UMS.MediumID                        
                   LEFT JOIN UserCampaignSettings UCS(NOLOCK)                        
                        ON  UL.CampaignName = UCS.CampaignID                        
                   LEFT JOIN User_Detail UD(NOLOCK)                        
                        ON  UL.AssignedTo = UD.User_ID                        
                   --LEFT JOIN FollowUp_Status FUS(NOLOCK)                        
                   --     ON  UL.FollowUpStatus = FUS.ID                        
                   LEFT JOIN User_Detail UD1(NOLOCK)                        
                        ON  UL.CreatedBy = UD1.User_ID                        
            WHERE  UL.ParentID = @ParentID                        
            AND UL.CreatedBy = CASE                         
                               WHEN (@Userid = 0) THEN UL.CreatedBy                         
                               ELSE @Userid                        
                          END                         
                                     
                   AND (                        
                           ISNULL(@txtSearch, '') = ''                        
                           OR PersonName LIKE '%' + @txtSearch + '%'                        
                           OR CompanyName LIKE '%' + @txtSearch + '%'                        
                       )                        
        )       A              
 ORDER BY                        
        A.CreatedOn1 DESC      
        IF OBJECT_ID('tempdb..##temp') IS NOT NULL     
        begin    
        select * from #temp1 x left join ##temp y on x.ID=y.leadid     
        end    
        else    
        begin    
         select * from #temp1    
         end    
      IF OBJECT_ID('tempdb.dbo.##temp', 'U') IS NOT NULL 
	  begin     
  DROP TABLE ##temp;      
  end 
        drop table #temp1                  
END   


