/* ============================================================
   Procedure: [dbo].[Usp_ViewUserLeadDetails2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec Usp_ViewUserLeadDetails2 @txtSearch=N'',@ParentID=29453,@Userid=36769,@FilterText=N'',@srno=N'1',@enno=N'230'        
-- exec Usp_ViewUserLeadDetails2 @txtSearch=N'',@ParentID=32222,@Userid=0,@FilterText=N'',@srno=N'1',@enno=N'20'               
-- exec Usp_ViewUserLeadDetails2 @txtSearch=N'',@ParentID=335,@Userid=0,@FilterText=N' ( Products = ''cvx'' ) ',@srno=N'1',@enno=N'20'        
-- exec Usp_ViewUserLeadDetails2 @txtSearch=N'',@ParentID=335,@Userid=0,@FilterText=N' ( FollowupDate >= ''01/20/2020'' And FollowupDate <= ''10/31/2020'' ) ',@srno=N'1',@enno=N'20'        
-- exec Usp_ViewUserLeadDetails2 @txtSearch=N'', @ParentID=335, @Userid=0, @FilterText=N' ( FollowupCreatedDate >= ''01/20/2020'' And FollowupCreatedDate <= ''11/03/2020'' ) ', @srno=N'1', @enno=N'20'        
-- exec Usp_ViewUserLeadDetails2 @txtSearch=N'',@ParentID=335,@Userid=0,@FilterText=N' ( FollowupBy like  ''%sms%'' ) ',@srno=N'1',@enno=N'20'        
CREATE   PROCEDURE [dbo].Usp_ViewUserLeadDetails2    
(      
 @txtSearch NVARCHAR(100),      
 @ParentID BIGINT,      
 @Userid INT= 0,      
 @FilterText NVARCHAR(MAX) = '',      
 @srno NVARCHAR(100),      
 @enno NVARCHAR(100)      
)      
AS      
BEGIN      
      
declare @Parameterlist nvarchar(max) , @LoggerID bigint      
set @Parameterlist = 'txtSearch : '+ @txtSearch + ' ,ParentID : '+ CONVERT(VARCHAR(100), @ParentID) + ' ,Userid : '+ CONVERT(VARCHAR(100), @Userid) + ' ,FilterText : '+ @FilterText + ' ,srno : '+ @srno + ' ,enno : '+ @enno;      
      
insert into kit19_executionlogger(ObjectName,Parameterlist,StartDatetime,EndDatetime,Remarks)      
values('Usp_ViewUserLeadDetails2',@Parameterlist,getdate(),'','')      
      
set @LoggerID = Scope_Identity();      
      
-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=29453,@Userid INT=36769,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'200'      
      
If (CHARINDEX('FollowupCreatedDate',@FilterText) > 0 or CHARINDEX('FollowupBy',@FilterText) > 0)      
Begin      
 print 'Usp_ViewUserLeadDetails2_Followup'      
 Exec Usp_ViewUserLeadDetails2_Followup @txtSearch,@ParentID,@Userid,@FilterText,@srno,@enno      
End      
Else      
Begin      
 print 'Usp_ViewUserLeadDetails2'      
      
 IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;      
      
 Declare @NoCustomFields bigint      
 DECLARE @Pivot_Column NVARCHAR(MAX);      
 DECLARE @Query NVARCHAR(MAX)= '', @Query1 NVARCHAR(MAX)= '';      
      
 /*Select Pivot Column*/      
 SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])      
 FROM      
 (      
 SELECT DISTINCT [fieldname] FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1      
 ) AS Tab;      
      
 set @NoCustomFields = (SELECT count(DISTINCT [fieldname]) FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1)      
 DECLARE @Rcnt VARCHAR(100);      
      
 IF(@Userid > 0)      
 BEGIN      
 SELECT @Rcnt = COUNT(ID) FROM UserLeads(NOLOCK) WHERE ParentID = @ParentID and AssignedTo = @Userid;      
 END      
 ELSE      
 BEGIN      
 SELECT @Rcnt = COUNT(ID) FROM UserLeads(NOLOCK) WHERE ParentID = @ParentID;      
 END      
      
 SET @Query+=CAST(N'SELECT DISTINCT      
 [A].[ID], [A].[LeadNo], [A].[PersonName], [A].[CompanyName], [A].[MobileNo], [A].[EmailID], [A].[City], [A].[State], [A].[Country], [A].[CountryCode], [A].[PinCode], [A].[ResidentialAddress], [A].[OfficeAddress], [A].[SourceName], [A].[MediumName], [A].[CampaignName], [A].[InitialRemarks], [A].[ParentID], [A].[User_Login], [dbo].[fn_getusertimefromindiantime](' + CAST(@ParentID AS NVARCHAR(MAX)) + ', [A].[FollowupDate]) AS [FollowupDate], [dbo].[fn_getusertimefromindiantime](' + CAST(@ParentID AS NVARCHAR(MAX)) + ', [A].[CreatedOn]) AS [CreatedOn], [dbo].[fn_getusertimefromindiantime](' + CAST(@ParentID AS NVARCHAR(MAX)) + ', [A].[CreatedOn1]) AS [CreatedOn1New], [A].[CreatedOn1], [A].[AssignedTo], [A].[Remarks],CASE WHEN ISNULL([A].[FollowupStatus], '''') <> '''' THEN ''<p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL([A].[FollowupStatus], '''') AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[FollowupDate], '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST([A].[FollowupDate] AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[Products], '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST([A].[Products] AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[AmountPaid],0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL([A].[AmountPaid], 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[Remarks], '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL([A].[Remarks], '''') + ''</p>'' ELSE '''' END AS [FollowUp],[A].[MobileNo1], [A].[MobileNo2], [A].[MobileNo3], [A].[EmailID3], [A].[EmailID1], [A].[EmailID2], [A].[FollowupStatus], [A].[assigneduser], [A].[img_ext], isnull([A].[Products], '''') as Products     
 
 INTO #temp1      
 FROM      
 (      
 SELECT [UL].[ID], [UL].[LeadNo], [UL].[PersonName], [UL].[img_ext], [UL].[CompanyName], [UL].[CreatedOn] AS [CreatedOn1],      
 CASE WHEN ISNULL([UL].[CountryCode], '''') <> '''' and ISNULL([UL].[MobileNo], '''') <> ''''     
 THEN ISNULL([UL].[Countrycode], '''') + '' '' + ISNULL([UL].[MobileNo], '''')      
 ELSE '''' END +      
 CASE WHEN ISNULL([UL].[Mobileno1], '''') <> ''''      
 THEN '', ...''      
 ELSE '''' END AS [MobileNo],      
 CASE WHEN ISNULL([UL].[Emailid], '''') <> ''''      
 THEN [UL].[Emailid]      
 ELSE '''' END +      
 CASE WHEN ISNULL([UL].[EmailID1], '''') <> ''''      
 THEN '', '' ELSE '''' END +      
 CASE WHEN ISNULL([UL].[EmailID2], '''') <> ''''      
 THEN '', ''      
 ELSE '''' END AS [EmailID],      
 [UL].[City], [UL].[State], [UL].[Country], [UL].[CountryCode], [UL].[PinCode], [UL].[ResidentialAddress], [UL].[OfficeAddress], [UL].[AssignedTo], [USS].[Name] AS [SourceName], [UMS].[Name] AS [MediumName], [UCS].[Name] AS [CampaignName], [UL].[InitialRemarks], [UL].[ParentID],FUS.[FollowupStatus], [UL].[FollowupDate], [UL].[Remarks], ISNULL([UL].[AmountPaid], 0) AS [AmountPaid], CONVERT(VARCHAR(10), [UL].[CreatedOn], 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), [UL].[CreatedOn], 109), 15), 7, 7, '' '') AS [CreatedOn], [UL].[CreatedBy], [UL].[ModifiedOn], [UL].[ModifiedBy], [UD1].[User_Login], [UL].[MobileNo] AS [MobileNo3], [UL].[MobileNo1], [UL].[MobileNo2], [UL].[EmailID] AS [EmailID3], [UL].[EmailID1], [UL].[EmailID2], ( SELECT STUFF( (SELECT N'', '' + [ss].[Name] FROM [ProductMaster](nolock) AS [ss] INNER JOIN [dbo].[fn_Split]([ul].[Products], ''#'') AS [fs]  ON [ss].[ProductID] = [fs].[value] FOR XML PATH(''''), TYPE).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''')      
 ) AS [Products], [UD].[User_Login] AS [assigneduser]      
 FROM UserLeads AS UL(NOLOCK) --INNER JOIN #TMPquery1 t on UL.ID = t.LeadID      
 INNER JOIN UserSourceSettings AS USS(NOLOCK)      
 ON UL.SourceName = USS.SourceID LEFT JOIN UserMediumSettings AS UMS(NOLOCK)      
 ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)      
 ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)      
 ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)      
 ON UL.CreatedBy = UD1.User_ID left join [FollowUp_Status](NOLOCK) AS FUS      
 ON UL.[FollowUpStatus] = FUS.[id] WHERE [UL].[ParentID] = ' + CAST(@ParentID AS NVARCHAR(MAX)) + ' AND [UL].[AssignedTo] = CASE WHEN ' +      
 CAST(@Userid AS NVARCHAR(MAX)) + ' = 0 THEN [UL].[AssignedTo] ELSE ' + CAST(@Userid AS NVARCHAR(MAX)) + ' END      
 AND (ISNULL(''' + @txtSearch + ''', '''') = '''' OR [PersonName] LIKE ''%'' + ' + @txtSearch + ' + ''%'' OR [CompanyName] LIKE ''%'' + ' + @txtSearch + ' + ''%'')      
 ) AS A ORDER BY [A].[ID] DESC;' AS NVARCHAR(MAX));      
      
  print @Query    
    
 IF(@FilterText = '')      
 BEGIN      
 SET @FilterText = ' (1=1) ';      
 END;      
      
 IF(@Pivot_Column IS NOT NULL)      
 BEGIN      
 SELECT @Query+=CAST(N'; Select * From (SELECT ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, Img_Ext, Products, CreatedOn as FollowupCreatedDate, User_Login as FollowupBy, '    
 + @Pivot_Column + ' FROM      
 (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, img_ext, Products, [fieldname] , fieldvalue FROM (select L.ID, L.LeadNo, L.PersonName, L.CompanyName, L.MobileNo, 
  
L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.User_Login, L.FollowupDate, L.CreatedOn, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus, L.assigneduser, L.Img_Ext, L.Products, y.fieldname, x.fieldvalue      
 From #temp1 L left join customfieldLeadvalue(nolock) x ON L.ID = x.LeadID left join customfields(nolock) y on x.fieldID=y.field_ID      
 AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1      
 )q )Tab1      
 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2      
 WHERE ' + @FilterText + ') T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + ' ORDER BY case when cast(followupdate as date) = cast(getdate() as date) then 0   
      when followupdate < getdate()  then 1  
      when followupdate > getdate() then 2  
      when followupdate is null then 3  
       end,followupdate  ' AS NVARCHAR(MAX));      
 END      
 ELSE      
 BEGIN      
 SET @Query += CAST(N';Select *, T1.CreatedOn as FollowupCreatedDate, T1.User_Login as FollowupBy From (select ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], * from #temp1 where ' + @FilterText + ') T1 
  
   
Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + ' ORDER BY case when cast(followupdate as date) = cast(getdate() as date) then 0   
      when followupdate < getdate()  then 1  
      when followupdate > getdate() then 2  
      when followupdate is null then 3  
       end,followupdate  ' AS NVARCHAR(MAX));      
 END      
    
    
  print '@FinalQuery:- ' + cast(@Query as varchar(max))     
    
  
 EXEC sp_executesql @Query;      
      
 update kit19_executionlogger      
 set EndDatetime = getdate(),      
 Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)      
 where ID = @LoggerID      
      
 update kit19_executionlogger      
 set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)      
 where ID = @LoggerID      
      
 IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;      
End      
      
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserLeadDetails2_27-01-2020]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


      
-- exec Usp_ViewUserLeadDetails2TEST @txtSearch=N'',@ParentID=24876,@Userid=0,@FilterText=N'',@srno=N'1',@enno=N'200'        
CREATE   PROCEDURE [dbo].[Usp_ViewUserLeadDetails2_27-01-2020]          
 @txtSearch NVARCHAR(100),        
 @ParentID BIGINT,        
 @Userid int=0,        
 @FilterText nvarchar(max) = '',                  
 @srno NVARCHAR(100),              
 @enno NVARCHAR(100)         
AS                                                              
BEGIN               
        
    IF OBJECT_ID('tempdb.dbo.#temp', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #temp;        
    END;        
        
    IF OBJECT_ID('tempdb.dbo.#myleads', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #myleads;        
    END;        
        
    IF OBJECT_ID('tempdb.dbo.#myleads1', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #myleads1;        
    END;        
        
    IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #temp1;        
    END;  
 IF OBJECT_ID('tempdb.dbo.#TMPquery', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #TMPquery;        
    END;  
 IF OBJECT_ID('tempdb.dbo.#TMPquery1', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #TMPquery1;        
    END;        
 create table #TMPquery    
 (RowNumber int, LeadID bigint)  
   
 create table #TMPquery1    
 (RowNumber int, LeadID bigint)  
        
    DECLARE @Pivot_Column NVARCHAR(MAX);        
    DECLARE @Query NVARCHAR(MAX)='',@Query1 NVARCHAR(MAX)='';        
  
set @Query = @Query +'insert into #TMPquery (RowNumber,LeadID) Select ROW_NUMBER() OVER(Order By ID Desc) AS RowNumber,ID '   set @Query = @Query +' FROM UserLeads (NOLOCK) Ue where ParentID = ' + Convert(varchar(100),@ParentID)          
    set @Query = @Query + ' ;'  
  
 set @Query = @Query + 'insert INTO #TMPquery1 (RowNumber,LeadID) SELECT RowNumber, LeadID from #TMPquery WHERE  RowNumber BETWEEN ' + Convert(varchar(100),@srno) +' AND '+ Convert(varchar(100),@enno)  
   set @Query = @Query + ' ;'  
   
        
    /*Select Pivot Column*/        
    SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])        
    FROM        
    (        
    SELECT DISTINCT [fieldname]        
    FROM customfields        
    WHERE [ParentID] = @ParentID AND [isActive] = 1        
    ) AS Tab;     
   
    
        
    If(@Pivot_Column is not null)          
    Begin          
    /*Create Dynamic Query*/        
    SELECT @Query += cast(N'SELECT LeadID, ' + @Pivot_Column + ' into #temp FROM            
    (SELECT leadid, [fieldname] , fieldvalue FROM (select x.LeadID, y.fieldname, x.fieldvalue    
 From customfieldLeadvalue(nolock) x inner join customfields(nolock) y on x.fieldID=y.field_ID  
 inner join #TMPquery1 t on x.LeadID = t.LeadID   
 WHERE y.[ParentID] = ' + cast(@ParentID as nvarchar(max)) + ' AND y.[isActive] = 1)q )Tab1                     
    PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2        
    ORDER BY Tab2.LeadID; ' as nvarchar(max))        
        
    --EXEC sp_executesql @Query;        
    End    
  
  Declare @Rcnt varchar(100)    
 select  @Rcnt = Count(ID) from UserLeads  (NOLOCK)    
 where ParentID = @ParentID         
        
    SET @Query += cast(N'SELECT DISTINCT        
   [A].[ID], [A].[LeadNo], [A].[PersonName], [A].[CompanyName], [A].[MobileNo], [A].[EmailID], [A].[City], [A].[State], [A].[Country], [A].[CountryCode], [A].[PinCode], [A].[ResidentialAddress], [A].[OfficeAddress], [A].[SourceName], [A].[MediumName], [A].[CampaignName], [A].[InitialRemarks], [A].[ParentID], [A].[User_Login], [dbo].[fn_getusertimefromindiantime]('+cast(@ParentID as nvarchar(max))+', [A].[FollowupDate]) AS [FollowupDate], [dbo].[fn_getusertimefromindiantime]('+cast(@ParentID as nvarchar(max))+', [A].[CreatedOn]) AS [CreatedOn], [dbo].[fn_getusertimefromindiantime]('+cast(@ParentID as nvarchar(max))+', [A].[CreatedOn1]) AS [CreatedOn1New], [A].[CreatedOn1], [A].[AssignedTo], [A].[Remarks],CASE WHEN ISNULL([A].[FollowupStatus], '''') <> ''''          
    THEN ''<p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL([A].[FollowupStatus], '''') AS VARCHAR(50)) + ''</p>''       
    ELSE '''' END + CASE WHEN ISNULL([A].[FollowupDate], '''') <> ''''         
    THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST([A].[FollowupDate] AS VARCHAR(50)) + ''</p>'' ELSE '''' END         
    + CASE WHEN ISNULL([A].[Products], '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST([A].[Products] AS VARCHAR(50)) + ''</p>'' ELSE '''' END +         
    CASE WHEN ISNULL([A].[AmountPaid], 0) <> 0        
    THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL([A].[AmountPaid], 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END  +         
    CASE WHEN ISNULL([A].[Remarks], '''') <> ''''        
    THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL([A].[Remarks], '''') + ''</p>''        
    ELSE '''' END AS [FollowUp],[A].[MobileNo1], [A].[MobileNo2], [A].[MobileNo3], [A].[EmailID3], [A].[EmailID1], [A].[EmailID2], [A].[FollowupStatus], [A].[assigneduser], [A].[img_ext]  INTO #temp1        
    FROM        
    (        
    SELECT [UL].[ID], [UL].[LeadNo], [UL].[PersonName], [UL].[img_ext], [UL].[CompanyName], [UL].[CreatedOn] AS [CreatedOn1],
    CASE WHEN ISNULL([UL].[CountryCode], '''') <> ''''        
    THEN ISNULL([UL].[Countrycode], '''') + '' '' + ISNULL([UL].[MobileNo], '''')        
    ELSE '''' END +         
    CASE WHEN ISNULL([UL].[Mobileno1], '''') <> ''''        
    THEN '', ...''        
    ELSE '''' END AS [MobileNo],        
    CASE WHEN ISNULL([UL].[Emailid], '''') <> ''''         
    THEN '' ''         
    ELSE '''' END +         
    CASE WHEN ISNULL([UL].[EmailID1], '''') <> ''''        
    THEN '', ''  ELSE '''' END +         
    CASE WHEN ISNULL([UL].[EmailID2], '''') <> ''''        
        THEN '', ''         
        ELSE '''' END AS [EmailID],         
    [UL].[City], [UL].[State], [UL].[Country], [UL].[CountryCode], [UL].[PinCode], [UL].[ResidentialAddress], [UL].[OfficeAddress], [UL].[AssignedTo], [USS].[Name] AS [SourceName], [UMS].[Name] AS [MediumName], [UCS].[Name] AS [CampaignName], [UL].[InitialRemarks], [UL].[ParentID],        
 FUS.[FollowupStatus], [UL].[FollowupDate], [UL].[Remarks], ISNULL([UL].[AmountPaid], 0) AS [AmountPaid], CONVERT(VARCHAR(10), [UL].[CreatedOn], 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), [UL].[CreatedOn], 109), 15), 7, 7, '' '') AS [CreatedOn], [UL].[CreatedBy], [UL].[ModifiedOn], [UL].[ModifiedBy], [UD].[User_Login], [UL].[MobileNo] AS [MobileNo3], [UL].[MobileNo1], [UL].[MobileNo2], [UL].[EmailID] AS [EmailID3], [UL].[EmailID1], [UL].[EmailID2], ( SELECT STUFF( (SELECT N'', '' + [ss].[Name]
    FROM [ProductMaster](nolock) AS [ss] INNER JOIN [dbo].[fn_Split]([ul].[Products], ''#'') AS [fs]        
    ON [ss].[ProductID] = [fs].[value] FOR XML PATH(''''), TYPE        
    ).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''')        
    ) AS [Products], [UD].[User_Login] AS [assigneduser]   
    FROM UserLeads AS UL(NOLOCK) INNER JOIN #TMPquery1 t on UL.ID = t.LeadID  
 INNER JOIN UserSourceSettings AS USS(NOLOCK)        
    ON UL.SourceName = USS.SourceID LEFT JOIN UserMediumSettings AS UMS(NOLOCK)        
    ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)        
    ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)        
    ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)        
    ON UL.CreatedBy = UD1.User_ID left join [FollowUp_Status](NOLOCK) AS FUS      
 ON UL.[FollowUpStatus] = FUS.[id]  WHERE [UL].[ParentID] = ' + cast(@ParentID as nvarchar(max)) + ' AND [UL].[AssignedTo] = CASE WHEN ' + cast(@Userid as nvarchar(max)) + ' = 0 THEN [UL].[AssignedTo] ELSE ' + cast(@Userid as nvarchar(max)) + ' END 
      AND (ISNULL(''' + @txtSearch + ''', '''') = '''' OR [PersonName] LIKE ''%'' + ' + @txtSearch + ' + ''%'' OR [CompanyName] LIKE ''%'' + ' + @txtSearch + ' + ''%'')        
    ) AS A ORDER BY [A].[CreatedOn1] DESC;' as nvarchar(max))        
        
    if(@FilterText = '')          
    begin          
        set @FilterText = ' (1=1) '          
    end    
     
        
    SET @Query += cast(N' IF OBJECT_ID(''tempdb..#temp'') IS NOT NULL        
    BEGIN        
    select * into #myleads from #temp1 x left join #temp y on x.ID=y.leadid where ' + @FilterText + '
    IF EXISTS (SELECT * FROM TempDB.INFORMATION_SCHEMA.COLUMNS(nolock) WHERE COLUMN_NAME = ''LeadID'' AND TABLE_NAME LIKE ''#myleads%'')        
            ALTER TABLE #myleads DROP COLUMN LeadID;
        SELECT * FROM ( select ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], ' + cast(@Rcnt as nvarchar(max))+' AS [rc1], * FROM #myleads) AS aa        
    END        
    ELSE        
    BEGIN        
    select * into #myleads1 from #temp1 where ' + @FilterText + ' 
    IF EXISTS (SELECT * FROM TempDB.INFORMATION_SCHEMA.COLUMNS(nolock) WHERE COLUMN_NAME = ''LeadID'' AND TABLE_NAME LIKE ''#myleads1%'')        
    ALTER TABLE #myleads1 DROP COLUMN LeadID;
        SELECT * FROM ( SELECT ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], ' + cast(@Rcnt as nvarchar(max))+' AS [rc1], * FROM #myleads1) AS aa       
    END; ' as nvarchar(max))        
       
    --select len(@Query),@Query        
    EXEC sp_executesql @Query;        
        
        
    IF OBJECT_ID('tempdb.dbo.#temp', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #temp;        
    END;        
        
    IF OBJECT_ID('tempdb.dbo.#myleads', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #myleads;        
    END;        
        
    IF OBJECT_ID('tempdb.dbo.#myleads1', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #myleads1;        
    END;        
        
    IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #temp1;        
    END;     
 IF OBJECT_ID('tempdb.dbo.#TMPquery', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #TMPquery;        
    END;  
 IF OBJECT_ID('tempdb.dbo.#TMPquery1', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #TMPquery1;        
    END;       
        
END 



GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserLeadDetails2_deepak]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_ViewUserLeadDetails2_deepak] --'',1305, 29837                                  
 @txtSearch NVARCHAR(100),                                    
 @ParentID BIGINT,                                    
 @Userid int=0,
 @FilterText nvarchar(max) = '',                                 
 @srno NVARCHAR(100),                                        
 @enno NVARCHAR(100)                                    
AS                                    
BEGIN     
IF OBJECT_ID('tempdb.dbo.##temp', 'U') IS NOT NULL   
  begin                 
  DROP TABLE ##temp;                   
  end  
  IF OBJECT_ID('tempdb.dbo.##myleads', 'U') IS NOT NULL   
  begin                 
  DROP TABLE ##myleads;                   
  end               
DECLARE @Pivot_Column [nvarchar](max);                    
DECLARE @Query [nvarchar](max);                    
                    
/*Select Pivot Column*/                    
SELECT @Pivot_Column= COALESCE(@Pivot_Column+',','')+ QUOTENAME(fieldname) FROM                    
(SELECT DISTINCT [fieldname] FROM customfields where ParentID=@ParentID)Tab                   
                   
/*Create Dynamic Query*/                    
SELECT @Query='SELECT leadid, '+@Pivot_Column+' into ##temp FROM                     
(SELECT leadid, [fieldname] , fieldvalue FROM (select x.LeadID, y.fieldname, x.fieldvalue  From customfieldLeadvalue x inner join customfields y on x.fieldID=y.field_ID)q )Tab1                    
PIVOT                    
(                    
max(fieldvalue) FOR [fieldname] IN ('+@Pivot_Column+')) AS Tab2                    
ORDER BY Tab2.LeadID'                  
EXEC  sp_executesql  @Query                                
 SELECT distinct A.ID,                                    
        A.LeadNo,                                    
        A.PersonName,                                    
        A.CompanyName,                                    
        A.MobileNo,                                    
        A.EmailID,                                    
        A.City,                                    
        A.[State],                                    
        A.Country,                                    
        A.CountryCode,                                    
        A.PinCode,                                    
        A.ResidentialAddress,                                    
        A.OfficeAddress,                                    
        A.SourceName,                                    
        A.MediumName,                                    
        A.CampaignName,                                    
        A.InitialRemarks,                                    
        A.ParentID,                                    
        A.User_Login,      
        --A.FollowupDate,      
        --A.CreatedOn,          
        dbo.[fn_getusertimefromindiantime](@ParentID,A.FollowupDate) as FollowupDate,              
        dbo.[fn_getusertimefromindiantime](@ParentID,A.CreatedOn) as CreatedOn,                      
        dbo.[fn_getusertimefromindiantime](@ParentID,A.CreatedOn1) as CreatedOn1New,                      
        A.CreatedOn1,                
        A.AssignedTo,                                   
        A.Remarks,                                    
        CASE                                     
             WHEN ISNULL(A.FollowupStatus, '') <> '' THEN                                     
                  '<p><b>Follow Up Status:&nbsp;&nbsp;</b>' + CAST(ISNULL(A.FollowupStatus, '')               
                  AS VARCHAR(50))                                     
                  + '</p>'                                    
             ELSE ''                                    
        END +                                    
        CASE                                     
             WHEN ISNULL(A.FollowupDate, '') <> '' THEN                                     
                  '<p><b>Next Status Date:&nbsp;&nbsp;</b>' + CAST(A.FollowupDate AS VARCHAR(50))                    + '</p>'                                    
             ELSE ''                                    
        END +                                    
        CASE                                     
             WHEN ISNULL(A.Products, '') <> '' THEN                                     
                  '<p><b>Next Status Date:&nbsp;&nbsp;</b>' + CAST(A.Products AS VARCHAR(50))                          + '</p>'                        
             ELSE ''                                    
        END +                                    
      CASE                                     
             WHEN ISNULL(A.AmountPaid, 0) <> 0 THEN                                     
                 '<p><b>Amount Paid:&nbsp;&nbsp;</b>' + CAST(                                    
                      CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS           
                      VARCHAR(50)                                    
                  ) + '</p>'                                    
             ELSE ''                                    
    END +                                    
        CASE                                     
             WHEN ISNULL(A.Remarks, '') <> '' THEN                                     
                  '<p><b>Remarks:&nbsp;&nbsp;</b>' + ISNULL(A.Remarks, '') +                                     
                  '</p>'                                    
             ELSE ''                                    
        END  AS FollowUp,                                    
        A.MobileNo1,                                    
        A.MobileNo2,                                    
        A.MobileNo3,                                    
        A.EmailID3,                                    
        A.EmailID1,                                    
        A.EmailID2,                                    
        A.FollowupStatus,                                    
        A.assigneduser     into #temp1                                
 FROM   (                                    
            SELECT UL.ID,                                    
                   UL.LeadNo,                                    
                   UL.PersonName,                                    
                   UL.CompanyName,                        
                   UL.CreatedOn as CreatedOn1 ,                                    
                   --ISNULL(UL.CountryCode, '') + ISNULL(UL.MobileNo, '') +                                    
                  -- CASE                                     
                       -- WHEN ISNULL(UL.MobileNo1, '') < > '' THEN ', ' +                                     
                            -- ISNULL(UL.CountryCode1, '') + ISNULL(UL.MobileNo1, '')                               
                     case When(ISNULL(UL.CountryCode, '') <> ''                          
)                          then                          
                         case   When(ISNULL(UL.CountryCode, '') + ISNULL(UL.MobileNo, '')) in           (                                  
                                select ISNULL(C_UDTemp.CountryCode,'')  +               
                                ISNULL(C_UDTemp.Mobile,'') as MobileNo                                   
        from   Client_UnSubscribeDetails C_UDTemp               
        join ClientPageDetail_Unsubscribe cpd on                               
                                 --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                                  
                                   C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                                        )                                  
                                                              
                            then '<p style="color:red;" >'+(ISNULL(UL.Countrycode, '') + ISNULL(UL.MobileNo, ''))+ '</p>'                                  
                              else                                  
              (ISNULL(UL.Countrycode, '') + ISNULL(UL.MobileNo, ''))                                  
                     end                           
                                               
                     else ''                          
                        end                          
                                               
                     +                                  
                         
                       CASE                                       
                        WHEN ISNULL(UL.Mobileno1, '') <> '' THEN ', ' +                                   
                   
                        case when (ISNULL(UL.Countrycode1, '') + ISNULL(UL.Mobileno1, '')) in                                  
                   (                                  
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                                     
                      from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                               
                      --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                                 
                           C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                               
                    )                                  
                    then '<p style="color:red;" >'+(ISNULL(UL.Countrycode1, '') + ISNULL(UL.Mobileno1, ''))+ '</p>'                                  
                    else                                  
                        (ISNULL(UL.Countrycode1, '') + ISNULL(UL.Mobileno1, ''))                                  
                    end                                     
                                                              
                                                                
                        ELSE ''                                    
                  END +                                    
                   CASE                                     
                        WHEN ISNULL(UL.MobileNo2, '') <> '' THEN ', ' +                                    
                        case when (ISNULL(UL.Countrycode2, '') + ISNULL(UL.MobileNo2, '')) in                                  
                   (                                  
                     select ISNULL(C_UDTemp.CountryCode,'')  + ISNULL(C_UDTemp.Mobile,'') as MobileNo                                     
                      from   Client_UnSubscribeDetails C_UDTemp                
                      join ClientPageDetail_Unsubscribe cpd on                               
                     C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID               
                    )                                  
                    then '<p style="color:red;" >'+(ISNULL(UL.Countrycode2, '') +               
                    ISNULL(UL.Mobileno2, ''))+ '</p>'                                  
                    else                                  
                        (ISNULL(UL.Countrycode2, '') + ISNULL(UL.Mobileno2, ''))                                  
                    end                                  
                                                          
                                                           
                            -- ISNULL(UL.CountryCode2, '') + ISNULL(UL.MobileNo2, '')                      
                        ELSE ''                                    
                   END            AS MobileNo,                                    
                    CASE                                                         
                        WHEN ISNULL(UL.Emailid, '') <> '' THEN ', '                                   
                +                                  
                           case when (ISNULL(UL.Emailid, '')) in                                  
                    (                                  
                     select ISNULL(C_UDTemp.Email,'') as EmailID                                     
          from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                               
                      -- 'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                                
                        C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                               
                    )                                  
                                                  
                    then '<p style="color:red;" >'+(ISNULL(UL.Emailid, ''))+ '</p>'                                  
                    else                               
                        (ISNULL(UL.Emailid, ''))                                  
                    END                                  
                    ELSE   ''                                  
      END+                                  
                                                   
                 --  ISNULL(UL.EmailID, '') +                                    
                   CASE                                     
                        WHEN ISNULL(UL.EmailID1, '') <> '' THEN ', ' +                                  
                         case when (ISNULL(UL.Emailid1, '')) in                                  
                   (                                  
                     select ISNULL(C_UDTemp.Email,'') as EmailID                                     
                                                        
                      from   Client_UnSubscribeDetails C_UDTemp  join ClientPageDetail_Unsubscribe cpd on                               
                      --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                               
                      C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                                
                    )                                  
                    then '<p style="color:red;" >'+(ISNULL(UL.Emailid1, ''))+ '</p>'                                  
else                                  
                        (ISNULL(UL.Emailid1, ''))                                  
                       END                                  
                                                                  
                                                          
                                                          
                        -- ISNULL(UL.EmailID1, '')                                    
                        ELSE ''                                    
                   END +                                    
                   CASE                                     
                        WHEN ISNULL(UL.EmailID2, '') <> '' THEN ', ' +                                  
                        case when (ISNULL(UL.Emailid2, '')) in                                  
                   (                                  
                     select ISNULL(C_UDTemp.Email,'') as EmailID                                     
                      --from UserEnquiry UETemp inner join Client_UnSubscribeDetails C_UDTemp                                    
                      --on (UeTemp.MobileNo = C_UDTemp.Mobile and UETemp.CountryCode = C_UDTemp.CountryCode)                                    
                      from   Client_UnSubscribeDetails C_UDTemp                
                      join ClientPageDetail_Unsubscribe cpd on                               
                      --'www.kit19.com/'+C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID              
                      C_UDTemp.cname =cpd.PageName and cpd.User_ID= @ParentID                                 
                    )                                  
                    then '<p style="color:red;" >'+(ISNULL(UL.Emailid2, ''))+ '</p>'                                     else                                  
                        (ISNULL(UL.Emailid2, ''))                                  
                        end                                  
                        -- ISNULL(UL.EmailID2, '')                                    
                        ELSE ''                                    
                   END            AS EmailID,                                    
                   UL.City,                         
                   UL.[State],                                    
                   UL.Country,                                    
                   UL.CountryCode,                                    
                   UL.PinCode,                                    
                   UL.ResidentialAddress,                                    
                   UL.OfficeAddress,                                    
           UL.AssignedTo,                                    
                   USS.Name       AS SourceName,                                    
                   UMS.Name       AS MediumName,                                    
                   UCS.Name       AS CampaignName,                                    
                   UL.InitialRemarks,                                    
   UL.ParentID,                                    
   (select FollowUpStatus from FollowUp_Status f where ul.FollowUpStatus=f.id) as FollowupStatus,                                    
                   UL.FollowupDate,                                    
                   UL.Remarks,                                    
                   ISNULL(UL.AmountPaid, 0) AS AmountPaid,                                    
                  CONVERT(VARCHAR(10),  UL.CreatedOn, 101) +                                    
STUFF(                                    
            RIGHT(CONVERT(VARCHAR(26),   UL.CreatedOn, 109), 15),                                    
            7,                                    
            7,                                    
            ' '                                    
        )  AS CreatedOn,                                    
                   UL.CreatedBy,                                    
                   UL.ModifiedOn,                                    
                   UL.ModifiedBy,                                    
                   UD.User_Login,                                    
                   UL.MobileNo    AS MobileNo3,                                    
                   UL.MobileNo1,                                    
                   UL.MobileNo2,                                    
                   UL.EmailID     AS EmailID3,                                    
               UL.EmailID1,                                    
                   UL.EmailID2,                                   
                   (                                    
                       SELECT STUFF(                                    
                                  (                                    
                                      SELECT N', ' + ss.Name                                    
                                      FROM   ProductMaster AS ss                                    
                                             INNER JOIN dbo.fn_Split(ul.Products, '#') AS                                     
                                                  fs                                    
                                                  ON  ss.ProductID = fs.[value]                                     
                                                      FOR XML PATH(''),                                    
                       TYPE                                    
                                  ) .value('text()[1]', 'nvarchar(max)'),                                    
                                  1,                                    
                                  2,                                    
                                  N''                                    
                              )                                    
                   )              AS Products,                                    
                   UD.User_Login  AS assigneduser                                    
            FROM   UserLeads UL(NOLOCK)                                    
                   INNER JOIN UserSourceSettings USS(NOLOCK)                          
                        ON  UL.SourceName = USS.SourceID                                    
                   LEFT JOIN UserMediumSettings UMS(NOLOCK)                                    
                        ON  UL.MediumName = UMS.MediumID                                    
                   LEFT JOIN UserCampaignSettings UCS(NOLOCK)                                    
                        ON  UL.CampaignName = UCS.CampaignID      
                   LEFT JOIN User_Detail UD(NOLOCK)                                    
                        ON  UL.AssignedTo = UD.User_ID                                    
                   --LEFT JOIN FollowUp_Status FUS(NOLOCK)                                    
                   --     ON  UL.FollowUpStatus = FUS.ID                                    
                   LEFT JOIN User_Detail UD1(NOLOCK)                                    
                        ON  UL.CreatedBy = UD1.User_ID                                            WHERE  UL.ParentID = @ParentID                                    
            AND UL.AssignedTo = CASE                                     
                               WHEN (@Userid = 0) THEN UL.AssignedTo                                     
                               ELSE @Userid                                    
                          END                                     
             --AND UL.CreatedBy = CASE                                     
             --                  WHEN (@Userid = 0) THEN UL.CreatedBy                                     
             --                  ELSE @Userid                                    
             --             END                                        
                   AND (                                    
                           ISNULL(@txtSearch, '') = ''                                    
                           OR PersonName LIKE '%' + @txtSearch + '%'                                    
                           OR CompanyName LIKE '%' + @txtSearch + '%'                                    
                       )                                    
        )       A                                    
 ORDER BY                                    
        A.CreatedOn1 DESC               
     IF OBJECT_ID('tempdb..##temp') IS NOT NULL                 
      begin 
        if @FilterText <>''
        begin               
       set @Query='select * into ##myleads from #temp1 x left join ##temp y on x.ID=y.leadid where '+@FilterText; 
       EXEC  sp_executesql @Query;                 
        end                
        else                
        begin                
          set @Query='select * into ##myleads from #temp1 x left join ##temp y on x.ID=y.leadid' 
          EXEC  sp_executesql @Query;                     
         end 
      end
      else
         begin
             if @FilterText <>''
           begin 
         set @Query='select * into ##myleads from #temp1 where ' +@FilterText; 
         EXEC  sp_executesql @Query;    
           end
         else
           begin
            set @Query='select * into ##myleads from #temp1'  
            EXEC  sp_executesql @Query;
           end
         end
         declare @rc varchar(15) ;       
      select  @rc = Count(*) from ##myleads;
           select * from (select ROW_NUMBER() OVER(Order By ID desc) AS RowNumber1, @rc AS rc1, * from ##myleads)aa where  RowNumber1 between @srno and @enno;          
       IF OBJECT_ID('tempdb.dbo.##temp', 'U') IS NOT NULL   
  begin                 
  DROP TABLE ##temp;                   
  end  
  IF OBJECT_ID('tempdb.dbo.##myleads', 'U') IS NOT NULL   
  begin                 
  DROP TABLE ##myleads;                   
  end  
        drop table #temp1                                 
END 


GO

