CREATE   PROCEDURE [dbo].[Usp_ViewUserLeadDetails2_DynamicSearch_1]        
 (                                          
 @txtSearch NVARCHAR(max),                                          
 @ParentID BIGINT,                                          
 @Userid INT= 0,                                          
 @FilterText NVARCHAR(MAX) = '',                                          
 @srno NVARCHAR(100),                                          
 @enno NVARCHAR(100),        
 @ordstr nvarchar(Max)='' ,      
 @notfollowedup int=0                                         
)                                          
AS                                          
BEGIN

