CREATE   PROCEDURE [dbo].[Usp_ViewUserLeadDetails2_DynamicSearch_Converted_Replication$]          
 (                                            
 @txtSearch NVARCHAR(max),                                            
 @ParentID BIGINT,                                            
 @Userid INT= 0,                                            
 @FilterText NVARCHAR(MAX) = '',                                            
 @srno NVARCHAR(100),                                            
 @enno NVARCHAR(100),          
 @ordstr nvarchar(Max)='' ,        
 @notfollowedup int=0                                           
)                                            
AS                                            
BEGIN  
  
    --Declare   
    --  @txtSearch NVARCHAR(max) = N' (cast(Course_01_Name as nvarchar(max)) like ''%rpsc%'')    
    --      and  (cast(Course_01_Expire_Date as date) between ''01/20/2021'' and ''09/21/2024'' ) ',                                            
  --  @txtSearch NVARCHAR(max) = N' (1=1) ',                                            
  
 ----@txtSearch NVARCHAR(max) = N'( (  cast(Course_01_Name as nvarchar(max))   like  ''%rpsc%'' ) and (  cast(Course_01_Expire_Date as date)  >= ''2022-01-01'' ) and (  cast(Course_01_Expire_Date as date)  <= ''2022-10-07'' ) )',  
  
    --@ParentID BIGINT = 40834,                                            
    --@Userid INT= 40834,                                            
    --@FilterText NVARCHAR(MAX) = '',                                            
    --@srno NVARCHAR(100)= N'1',                                            
    --@enno NVARCHAR(100)= N'20',          
    --@ordstr nvarchar(Max)=N'' ,        
    --@notfollowedup int=0   
  
     --set @txtSearch = N' (cast(Course_01_Name as nvarchar(max)) like ''%rpsc%'')    
      --  and  (cast(Course_01_Expire_Date as date) between ''01/20/2021'' and ''09/21/2024'' ) ' ;  
   
     -- set @txtSearch = N'( (  cast(Course_01_Name as nvarchar(max))   like  ''%rpsc%'' ) and (  cast(Course_01_Expire_Date as date)  >= ''2022-01-01'' ) and (  cast(Course_01_Expire_Date as date)  <= ''2022-10-07'' ) )'    
  
      --set @ParentID  = 40834;                                            
      --set  @Userid = 40834;  
  
  
  
  
                                            
  --declare @Parameterlist nvarchar(max) , @LoggerID bigint   
  -- set @Parameterlist = 'txtSearch : '+ @txtSearch + ' ,ParentID : '+ CONVERT(VARCHAR(100), @ParentID) + ' ,Userid : '+ CONVERT(VARCHAR(100), @Userid) +  ' ,FilterText : '+ @FilterText + ' ,srno : '+ @srno + ' ,enno : '+ @enno;                            
              
                                            
       
    DECLARE @IsAdmin BIT = 0  
 DECLARE @TimeZoneName NVARCHAR(255) = isnull((  
    SELECT TimeZone  
    FROM User_Detail(NOLOCK)  
    WHERE User_ID = @Userid  
    ), 'India Standard Time')  
 DECLARE @UserIDTeam BIGINT = @Userid;  
 DECLARE @tbluser TABLE (  
  User_ID BIGINT  
  ,Name VARCHAR(100)  
  ,IMAGE VARCHAR(100)  
  )  
      
  drop table if exists #tbluserOther  
  Create TABLE #tbluserOther (User_ID BIGINT  
  ,Name VARCHAR(100)  
  ,IMAGE VARCHAR(100)  
  )      
  
  
 SELECT @IsAdmin = IsAdmin  
 FROM User_Detail(NOLOCK)  
 WHERE User_ID = @ParentID  
  
 --exec Usp_createProductMasterTable @ParentID     
 IF(@IsAdmin = 1)  
 BEGIN  
    SET @Userid = 0;  
  -- INSERT INTO @tbluser  
  ----INSERT INTO #tbluserOther  
  --(  
  --User_ID   
  --,Name   
  --,IMAGE)  
  --EXEC Use_GetUserDetails_CustomSearch @ParentId  
 END  
 --ELSE  
 --BEGIN  
       
 -- INSERT INTO @tbluser  
 -- --INSERT INTO #tbluserOther  
 -- (User_ID   
 -- ,Name   
 -- ,IMAGE)  
 -- EXEC Use_GetUserDetails_CustomSearch @UserId  
 --END  
  
 DECLARE @TeamCode VARCHAR(10) = ''  
 DECLARE @ScopeCode VARCHAR(10) = ''  
 DECLARE @UserIdTeamLst VARCHAR(4000) = ''  
 DECLARE @HierarchyJSON VARCHAR(Max) = ''  
  
 --SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')  
 --FROM @tbluser  
  
  --SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')  
  --      FROM #tbluserOther  
  
       set  @UserIdTeamLst = CAST(@ParentID as nvarchar(max))  --'40883,40865,40866,40867,40834'  
  
   --PRINT '@UserIdTeamLst: ' + @UserIdTeamLst  
      --print @UserIdTeamLst  
   --print '1234'   
 --print @UserIdTeamLst  
  
  
--insert into kit19_executionlogger(ObjectName,Parameterlist,StartDatetime,EndDatetime,Remarks)                                            
--values('Usp_ViewUserLeadDetails2_New',@Parameterlist,getdate(),'','')                                            
                                            
--set @LoggerID = Scope_Identity();                                            
  
Begin                  
 --print 'Usp_ViewUserLeadDetails2_New'                                            
                                            
IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;          
IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL BEGIN DROP TABLE #temp2; END;          
                                            
 Declare @NoCustomFields bigint, @offset int=20, @filterCnt int=0          
 DECLARE @Pivot_Column NVARCHAR(MAX);                                            
 DECLARE @Query NVARCHAR(MAX)= '', @Query1 NVARCHAR(MAX)= '',@Query2 nvarchar(max)                                          
                   
 declare @maxScore numeric(18,2)=isnull((select (max(currentscore)*100)/99 from lead_score_history(nolock)e where parentid=@ParentID),0)                  
 declare @hot int,@warm int,@cold int                  
                  
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=@ParentID                        
 if @hot is null                        
 begin                        
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=0                        
 end                        
                  
 /*Select Pivot Column*/                                            
 SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])                                            
 FROM                                            
 (                                            
 SELECT DISTINCT [fieldname] FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1                                            
 ) AS Tab;                              
                                            
 set @NoCustomFields = (SELECT count(DISTINCT [fieldname]) FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1)                                           
 DECLARE @Rcnt VARCHAR(100);                                            
          
If(@ordstr = '')          
Begin          
 set @ordstr = ' CurrentScore desc, case when cast(followupdate as date) = cast(getdate() as date) then 0          
     when followupdate < getdate()  then 1          
     when followupdate > getdate() then 2          
     when followupdate is null then 3          
      end,followupdate '          
End                                           
                  
IF(@txtSearch = '')                  
BEGIN                  
 SET @txtSearch = N' (1=1) ';          
 Set @offset=0          
END;          
          
IF(@FilterText = '')          
BEGIN          
 SET @FilterText = N' (1=1) ';                 
END;                  
                  
 IF(@FilterText = ' (1=1) ' and @txtSearch = ' (1=1) ')          
BEGIN          
 --print 'Branch A'          
  SET @Query+=CAST(N'SELECT A.ID,A.LeadNo,A.PersonName,A.CompanyName,A.MobileNo,A.EmailID,A.City,A.State,A.Country,A.CountryCode,A.CountryCode1,A.CountryCode2,A.PinCode, A.ResidentialAddress, A.OfficeAddress, isnull(A.SourceName,''Unknown'') SourceName, A.MediumName,A.CampaignName,A.InitialRemarks, A.ParentID, A.FollowupBy, /*dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',*/ A.FollowupDate/*)*/ AS FollowupDate,/*dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',*/ A.FollowupCreatedDate/*)*/ AS FollowupCreatedDate, /*dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',*/ A.CreatedOn1/*)*/ AS CreatedOn1New,  A.CreatedOn1, A.AssignedTo, A.Remarks, CASE WHEN ISNULL(A.FollowupStatus, '''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus, '''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.FollowupDate, '''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products, '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks, '''') + ''</p>'' ELSE '''' END AS FollowUp,A.MobileNo1, A.MobileNo2, A.MobileNo3, A.EmailID3, A.EmailID1, A.EmailID2, A.FollowupStatus, A.assigneduser, A.img_ext, A.WhereAddress, isnull(A.Products, '''') as Products,A.CurrentScore, A.Profit_Loss, A.ThresholdColor, RowNumber1, rc1, A.User_Login, A.LastFollowupCreatedByName  
INTO #temp1  
FROM  
 (  
 select ROW_NUMBER() OVER(ORDER BY S.ID DESC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1,*  
From (  
select *  
From (  
 SELECT UL.ID, UL.LeadNo, UL.PersonName, UL.img_ext, UL.CompanyName, UL.CreatedOn AS CreatedOn1, CASE WHEN ISNULL(UL.CountryCode, '''') <> '''' and ISNULL(UL.MobileNo, '''') <> ''''  THEN ISNULL(UL.Countrycode, '''') + '' '' + ISNULL(UL.MobileNo, '''')  ELSE '''' END +  CASE WHEN ISNULL(UL.Mobileno1, '''') <> '''' THEN '', ...'' ELSE '''' END AS MobileNo3, CASE WHEN ISNULL(UL.Emailid, '''') <> '''' THEN UL.Emailid ELSE '''' END + CASE WHEN ISNULL(UL.EmailID1, '''') <> '''' THEN '', '' ELSE '''' END +  CASE WHEN ISNULL(UL.EmailID2, '''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode,UL.CountryCode1,UL.CountryCode2, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, CONVERT(VARCHAR(10), UL.CreatedOn, 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), UL.CreatedOn, 109), 15), 7, 7, '' '') AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy, UD2.User_Login as FollowupBy, UL.MobileNo AS MobileNo, UL.MobileNo1, UL.MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, ( select isnull((select STRING_AGG(isnull(ProductName,''''),'', '') from openjson(ul.productsJson) with(ProductName nvarchar(max) ''$.ProductName'' )  where isnull(ul.productsJson,'''') != '''') , '''') ) AS Products, UD.User_Login AS assigneduser, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int), ThresholdColor=case when cast(isnull((LS.currentscore/nullif('+ cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int)>' + cast(@warm as nvarchar(max)) + ' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max))+',0.00))*99,0) as int) between ' + cast(@cold as nvarchar(max)) + ' and ' + cast(@warm as nvarchar(max)) + ' then ''Warm'' else ''Cold'' end , UD1.User_Login, UL.WhereAddress  ' as nvarchar(max)) + ', UD2.User_Login as LastFollowupCreatedByName '  
  
 select @Query +=cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)  
ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f  
left join lead_score_history_latest(nolock) LS  
ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK)  
ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)  
ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)  
ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)  
ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK)  
ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK)  
ON UL.FollowUpStatus = FUS.id   
--left join LeadPipelineMapping_latest(nolock) as lpm  
--on UL.ID = lpm.LeadID  
  
WHERE  
   exists (select 1 from leadinteractionhistory l with (nolock) join followup_status f with (nolock) on f.id=l.followupstatus and l.parentid =  
 isnull(f.parentid,l.parentid) where isconvert=1 and l.LeadNo=ul.leadno and l.ParentID = UL.ParentID)  
 and    
 UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' + CASE   
      WHEN @Userid = 0  
       THEN N' = UL.AssignedTo '  
      WHEN @Userid > 0 /*and isnull(@TeamCode,'') != ''*/  
       THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'  
      ELSE ' = ' + CAST(@Userid AS NVARCHAR(MAX))  
      END + '   
 and 1= case when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''0'' then 1 when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''1''  
 and isnull(LastFollowupCreatedBy,0)=0 then 1 else 0 end'  
 + '  
 ) T           
 ) S           
 ) AS A Where A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno+@offset) AS NVARCHAR(MAX));  
END          
ELSE          
BEGIN          
 --print 'Branch B'  
  
 SET @Query+=CAST(N'SELECT A.ID,A.LeadNo,A.PersonName,A.CompanyName,A.MobileNo,A.EmailID,A.City,A.State,A.Country,A.CountryCode,A.CountryCode1,A.CountryCode2,A.PinCode, A.ResidentialAddress,A.OfficeAddress,isnull(A.SourceName,''Unknown'') SourceName,A.MediumName,A.CampaignName,A.InitialRemarks,A.ParentID, A.FollowupBy, /*dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',*/ A.FollowupDate/*)*/ AS FollowupDate, /*dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',*/A.FollowupCreatedDate/*)*/ AS FollowupCreatedDate,/*dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',*/A.CreatedOn1/*)*/ AS CreatedOn1New,A.CreatedOn1,A.AssignedTo, A.Remarks,CASE WHEN ISNULL(A.FollowupStatus,'''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus,'''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.FollowupDate,'''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products,'''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks,'''') + ''</p>'' ELSE '''' END AS FollowUp,A.MobileNo1,A.MobileNo2,A.MobileNo3,A.EmailID3,A.EmailID1,A.EmailID2,A.FollowupStatus,A.assigneduser,A.img_ext, A.WhereAddress, isnull(A.Products, '''') as Products, A.CurrentScore,A.Profit_Loss,A.ThresholdColor,RowNumber1,rc1,A.User_Login, A.LastFollowupCreatedByName
 INTO #temp1  
 FROM  
 (  
 select ROW_NUMBER() OVER(ORDER BY S.ID DESC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1,*  
 From (  
 select *  
 From (  
 SELECT UL.ID,UL.LeadNo,UL.PersonName,UL.img_ext,UL.CompanyName,UL.CreatedOn AS CreatedOn1,  
 CASE WHEN ISNULL(UL.CountryCode,'''') <> '''' and ISNULL(UL.MobileNo,'''') <> '''' THEN ISNULL(UL.Countrycode,'''') + '' '' + ISNULL(UL.MobileNo,'''')  ELSE '''' END +  CASE WHEN ISNULL(UL.Mobileno1,'''') <> '''' THEN '', ...'' ELSE '''' END AS MobileNo3, CASE WHEN ISNULL(UL.Emailid,'''') <> '''' THEN UL.Emailid ELSE '''' END + CASE WHEN ISNULL(UL.EmailID1,'''') <> ''''  THEN '', '' ELSE '''' END +   CASE WHEN ISNULL(UL.EmailID2,'''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode,UL.CountryCode1,UL.CountryCode2, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, CONVERT(VARCHAR(10), UL.CreatedOn, 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), UL.CreatedOn, 109), 15), 7, 7, '' '') AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy, UD2.User_Login as FollowupBy, UL.MobileNo AS MobileNo, UL.MobileNo1, UL.MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, ( select isnull((select STRING_AGG(isnull(ProductName,''''),'', '') from openjson(ul.productsJson) with(ProductName nvarchar(max) ''$.ProductName'' ) where isnull(ul.productsJson,'''') != '''') , '''') ) AS Products, UD.User_Login AS assigneduser, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int) , ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' +  cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int)>' + cast(@warm as nvarchar(max)) + ' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max))+',0.00))*99,0) as int) between ' + cast(@cold as nvarchar(max)) + ' and ' + cast(@warm as nvarchar(max)) + ' then ''Warm'' else ''Cold'' end , UD1.User_Login, UL.WhereAddress ' as nvarchar(max)) +  ', UD2.User_Login as LastFollowupCreatedByName '  
  
 select @Query +=cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)  
 ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f  
 left join lead_score_history_latest(nolock) LS  
 ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK)  
 ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)  
 ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)  
 ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)  
 ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK)  
 ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK)  
 ON UL.FollowUpStatus = FUS.id  
 -- left join LeadPipelineMapping_latest(nolock) as lpm  
    --on UL.ID = lpm.LeadID  
 WHERE   
   exists (select 1 from leadinteractionhistory l with (nolock) join followup_status f with (nolock) on f.id=l.followupstatus and l.parentid =  
 isnull(f.parentid,l.parentid) where isconvert=1 and l.LeadNo=ul.leadno and l.ParentID = UL.ParentID)  
 and   
 UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' + CASE   
      WHEN @Userid = 0  
       THEN N' = UL.AssignedTo '  
      WHEN @Userid > 0 /*and isnull(@TeamCode,'') != ''*/  
       THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'  
      ELSE ' = ' + CAST(@Userid AS NVARCHAR(MAX))  
      END + '  and 1= case when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''0'' then 1 when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''1'' and isnull(LastFollowupCreatedBy,0)=0  then 1 else 0 end' + '          
) T Where ' + @FilterText + '  
) S  
 ) AS A Where ' + case when @txtSearch = ' (1=1) ' then ' A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) else ' (1=1) ' end AS NVARCHAR(MAX));            
 --) AS A ' AS NVARCHAR(MAX));            
                                            
  --print @Query                       
End          
  
                                          
 IF(nullif(@Pivot_Column,'') IS NOT NULL)  
 BEGIN          
 --print 'Branch C'          
 --IF(@FilterText = ' (1=1) ' and @txtSearch = ' (1=1) ')-- From Branch A          
 IF(@txtSearch = ' (1=1) ')-- From Branch A          
 Begin          
 --print 'Branch CA'          
SELECT @Query += CAST(N'; Select * from ( Select ID,LeadNo,PersonName, CompanyName,MobileNo as MobileNo , MobileNo1, MobileNo2,Countrycode,Countrycode1,Countrycode2,EmailID3 as EmailID, EmailID1, EmailID2, City, [State], Country, Pincode, Residentialaddress, Officeaddress, SourceName, MediumName, CampaignName, Initialremarks,CreatedOn1 as datecreated  ,AssignedTo,followupstatus,FollowupCreatedDate as nextfollowupdate ,followupdate,rownumber1,currentscore  
   From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode,CountryCode1,CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login as User_Login, FollowupDate,   FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, Img_Ext, Products, FollowupCreatedDate, FollowupBy, WhereAddress, ' + @Pivot_Column + N', CurrentScore, Profit_Loss, ThresholdColor, RowNumber1, rc1,LastFollowupCreatedByName  
   FROM  
   (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode,CountryCode1,CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy, FollowupDate, FollowupCreatedDate, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, img_ext, WhereAddress, Products, [fieldname] , fieldvalue, CurrentScore, Profit_Loss,ThresholdColor, RowNumber1, rc1 ,User_Login,LastFollowupCreatedByName   FROM (select L.ID,  L.LeadNo, L.PersonName, L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State, L.Country, L.CountryCode,L.CountryCode1,L.CountryCode2, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.FollowupBy, L.FollowupDate, L.FollowupCreatedDate, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,  L.assigneduser, L.Img_Ext, L.WhereAddress, L.Products, y.fieldname, x.fieldvalue, L.CurrentScore, L.Profit_Loss, L.ThresholdColor, L.RowNumber1, L.rc1,L.User_Login,L.LastFollowupCreatedByName  
   From #temp1 L left join customfieldLeadvalue(nolock) x  
   ON L.ID = x.LeadID left join customfields(nolock) y  
   ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1  
   )q )Tab1  
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2) T1  
  Where ' + @txtSearch + '  
  ) T2  
  Where T2.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno)  + N' ORDER BY ' + @ordstr  
  /*N' ORDER BY CurrentScore desc,          
   case when cast(followupdate as date) = cast(getdate() as date) then 0          
     when followupdate < getdate()  then 1          
     when followupdate > getdate() then 2          
     when followupdate is null then 3          
      end,followupdate  '*/ AS NVARCHAR(MAX));          
 End          
 Else-- From Branch B          
 Begin          
  --print 'Branch CB'          
          
  Select @filterCnt=count(*) From dbo.fn_Split(@txtSearch, ' ) ')          
  select @filterCnt = 1  
   
   SELECT @Query += CAST(N'; select * into #Temp2 From (select [x].LeadID, [y].[fieldname],   
    [x].[fieldvalue] from customfieldLeadvalue(nolock) x inner join customfields(nolock) y  
    ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) T1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @txtSearch AS NVARCHAR(MAX));  
     
          
  SELECT @Query += CAST(N'; Select ID,LeadNo,PersonName, CompanyName,MobileNo as MobileNo, MobileNo1, MobileNo2,Countrycode,Countrycode1,Countrycode2,EmailID3 as EmailID, EmailID1, EmailID2, City, [State], Country, Pincode, Residentialaddress, Officeaddress, SourceName, MediumName, CampaignName, Initialremarks,CreatedOn1 as datecreated  ,AssignedTo,followupstatus,FollowupCreatedDate as nextfollowupdate ,followupdate,rownumber1,currentscore from ( Select ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], *  
   From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, CountryCode1, CountryCode2,PinCode, ResidentialAddress, OfficeAddress, SourceName,  MediumName, CampaignName, InitialRemarks, ParentID, User_Login as User_Login, FollowupDate,    FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, Img_Ext, WhereAddress, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column +     
   N', CurrentScore, Profit_Loss, ThresholdColor  
   FROM  
   (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode,CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy, FollowupDate, FollowupCreatedDate,   CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, img_ext, WhereAddress, Products,' + @Pivot_Column +     
   N', CurrentScore, Profit_Loss,ThresholdColor,User_Login,LastFollowupCreatedByName  
   FROM (select L.ID, L.LeadNo, L.PersonName, L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.CountryCode1, L.CountryCode2, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.FollowupBy, L.FollowupDate, L.FollowupCreatedDate, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,  L.assigneduser, L.Img_Ext, L.WhereAddress, L.Products,' + @Pivot_Column + N',L.CurrentScore, L.Profit_Loss, L.ThresholdColor,L.User_Login,L.LastFollowupCreatedByName  
   From #Temp2 A inner join #temp1 L  
   ON A.LeadId = L.ID   
   )q )Tab1  
   ) T1  
  ) T2  
  Where T2.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) + N' ORDER BY ' + @ordstr  
  /*N' ORDER BY CurrentScore desc,          
   case when cast(followupdate as date) = cast(getdate() as date) then 0          
     when followupdate < getdate()  then 1          
     when followupdate > getdate() then 2          
     when followupdate is null then 3          
      end,followupdate  '*/ AS NVARCHAR(MAX));  
   
             
 End          
END          
ELSE          
BEGIN          
 --print 'Branch D'          
          
  SET @Query += CAST(N';Select ID,LeadNo,PersonName, CompanyName,MobileNo as MobileNo, MobileNo1, MobileNo2,Countrycode,Countrycode1,Countrycode2,EmailID3 as EmailID, EmailID1, EmailID2, City, [State], Country, Pincode, Residentialaddress, Officeaddress, SourceName, MediumName, CampaignName, Initialremarks,CreatedOn1 as datecreated  ,AssignedTo,followupstatus,FollowupCreatedDate as nextfollowupdate ,followupdate,rownumber1,currentscore  
  From #temp1          
  Where RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) + N' ORDER BY ' + @ordstr           
  /*N' ORDER BY CurrentScore desc,          
  case when cast(followupdate as date) = cast(getdate() as date) then 0          
  when followupdate < getdate() then 1          
  when followupdate > getdate() then 2          
  when followupdate is null then 3          
  end,followupdate '*/ AS NVARCHAR(MAX));          
END          
                                          
   --print '@FinalQuery:- ' + cast(@Query as varchar(max))          
   --print '@FinalQuery:- ' + cast(@Query as varchar(max))                                          
                                      
 EXEC sp_executesql @Query;                                            
                                            
 --update kit19_executionlogger                                            
 --set EndDatetime = getdate(),                                            
 --Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)                                            
 --where ID = @LoggerID                                            
                                            
 --update kit19_executionlogger                                            
 --set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)                                            
 --where ID = @LoggerID                                            
                                            
 IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;          
 IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL BEGIN DROP TABLE #temp2; END;          
End                                            
                      
END     
  
  


GO

