--exec Usp_ViewUserLeadDetails2_New @txtSearch=N' (fieldname = ''test02'' and cast(fieldvalue as varchar(100)) like  ''%2%'' )  or  (fieldname = ''test03'' and cast(fieldvalue as varchar(100)) like  ''%3%'' ) ',@ParentID=32222,@Userid=0,@FilterText=N' PersonName like  ''%test%''',@srno=N'1',@enno=N'20',@ordstr=N''        
