   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*   
exec Usp_ViewUserLeadDetails2_New_withnofollowup @txtSearch=N'',@ParentID=33819,@Userid=0,@FilterText=N'',@srno=N'1',@enno=N'20'  
