-- exec Usp_ViewUserLeadDetails2_new @txtSearch=N'', @ParentID=335, @Userid=0, @FilterText=N' ( FollowupCreatedDate >= ''01/20/2020'' And FollowupCreatedDate <= ''11/03/2020'' ) ', @srno=N'1', @enno=N'20'              
-- exec Usp_ViewUserLeadDetails2_New @txtSearch=N'',@ParentID=35610,@Userid=0,@FilterText=N' ( FollowupBy like  ''%nitin%'' and id= 1178505 ) ',@srno=N'1',@enno=N'20'              
-- exec Usp_ViewUserLeadDetails2_New @txtSearch=N'',@ParentID=38738,@Userid=0,@FilterText=N'',@srno=N'1',@enno=N'20'         
( id=11764 ) 
