CREATE   PROCEDURE [dbo].[Usp_ViewUserLeadDetails2_DynamicSearchForConv_Search_startentityid]        
 (                                          
 @txtSearch NVARCHAR(max),                                          
 @ParentID BIGINT,                                          
 @Userid INT= 0,                                          
 @FilterText NVARCHAR(MAX) = '',                                          
 @srno NVARCHAR(100),                                          
 @enno NVARCHAR(100),        
 @ordstr nvarchar(Max)='' ,      
 @notfollowedup int=0  ,
 @start_entityid bigint
)                                          
AS                                          
BEGIN 
                
   --Declare 
   ---- @txtSearch NVARCHAR(max) = N' (cast(Course_01_Name as nvarchar(max)) like ''%rpsc%'')  
   --  --     and  (cast(Course_01_Expire_Date as date) between ''01/20/2021'' and ''09/21/2024'' ) ',                                          
   --@txtSearch NVARCHAR(max) = N' (1=1) ',                                          

   --@ParentID BIGINT = 40834,                                          
   --@Userid INT= 40834,                                          
   --@FilterText NVARCHAR(MAX) = '',                                          
   --@srno NVARCHAR(100)= N'1',                                          
   --@enno NVARCHAR(100)= N'20',        
   --@ordstr nvarchar(Max)=N'' ,      
   --@notfollowedup int=0   


                         
declare @Parameterlist nvarchar(max) , @LoggerID bigint 
set @Parameterlist = 'txtSearch : '+ @txtSearch + ' ,ParentID : '+ CONVERT(VARCHAR(100), @ParentID) + ' ,Userid : '+ CONVERT(VARCHAR(100), @Userid) +  ' ,FilterText : '+ @FilterText + ' ,srno : '+ @srno + ' ,enno : '+ @enno;                                        
                                          
--insert into kit19_executionlogger(ObjectName,Parameterlist,StartDatetime,EndDatetime,Remarks)                                          
--values('Usp_ViewUserLeadDetails2_New',@Parameterlist,getdate(),'','')                                          
                                          
--set @LoggerID = Scope_Identity();                                          

Begin                
 --print 'Usp_ViewUserLeadDetails2_New'                                          
                                          
IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;        
IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL BEGIN DROP TABLE #temp2; END;        
                                          
 Declare @NoCustomFields bigint, @offset int=20, @filterCnt int=0        
 DECLARE @Pivot_Column NVARCHAR(MAX);                                          
 DECLARE @Query NVARCHAR(MAX)= '', @Query1 NVARCHAR(MAX)= '',@Query2 nvarchar(max)                                        
                 
 declare @maxScore numeric(18,2)=isnull((select (max(currentscore)*100)/99 from lead_score_history(nolock)e where parentid=@ParentID),0)                
 declare @hot int,@warm int,@cold int                
                
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=@ParentID                      
 if @hot is null                      
 begin                      
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=0                      
 end                      
                
 /*Select Pivot Column*/                                          
 SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])                                          
 FROM                                          
 (                                          
 SELECT DISTINCT [fieldname] FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1                                          
 ) AS Tab;                            
                                          
 set @NoCustomFields = (SELECT count(DISTINCT [fieldname]) FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1)                                       
    declare @IsAdmin bit = 0  
    SELECT @IsAdmin = IsAdmin
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @ParentID

	exec Usp_createProductMasterTable @ParentID

	IF(@IsAdmin = 1)
	BEGIN
		SET @Userid = 0;
	END   



 DECLARE @Rcnt VARCHAR(100);                                          
        
If(@ordstr = '')        
Begin        
 set @ordstr = ' CurrentScore desc, case when cast(followupdate as date) = cast(getdate() as date) then 0        
     when followupdate < getdate()  then 1        
     when followupdate > getdate() then 2        
     when followupdate is null then 3        
      end,followupdate '        
End                                         
                
IF(@txtSearch = '')                
BEGIN                
 SET @txtSearch = N' (1=1) ';        
 Set @offset=0        
END;        
        
IF(@FilterText = '')        
BEGIN        
 SET @FilterText = N' (1=1) ';                
END;                
                
 IF(@FilterText = ' (1=1) ' and @txtSearch = ' (1=1) ')        
BEGIN        
 --print 'Branch A'        
  SET @Query+=CAST(N'SELECT A.ID,A.LeadNo,A.PersonName,A.CompanyName,A.MobileNo,A.EmailID,A.City,A.State,A.Country,A.CountryCode,A.CountryCode1,A.CountryCode2,A.PinCode, A.ResidentialAddress, A.OfficeAddress, isnull(A.SourceName,''Unknown'') SourceName, A.MediumName,A.CampaignName,A.InitialRemarks, A.ParentID, A.FollowupBy, dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ', A.FollowupDate) AS FollowupDate,      
 dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ', A.FollowupCreatedDate) AS FollowupCreatedDate,
 dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ', A.CreatedOn1) AS CreatedOn1New,  A.CreatedOn1,
 A.AssignedTo, A.Remarks, CASE WHEN ISNULL(A.FollowupStatus, '''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus, '''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.FollowupDate, '''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products, '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks, '''') + ''</p>'' ELSE '''' END AS FollowUp,A.MobileNo1, A.MobileNo2, A.MobileNo3, A.EmailID3, A.EmailID1, A.EmailID2, A.FollowupStatus, A.assigneduser, A.img_ext, A.WhereAddress, isnull(A.Products, '''') as Products, A.CurrentScore, A.Profit_Loss, A.ThresholdColor, RowNumber1, rc1, A.User_Login
    , A.LastFollowupCreatedByName, A.WhatsAppNoColName
INTO #temp1
FROM
 (
 select ROW_NUMBER() OVER(ORDER BY S.ID ASC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1,*
From (
select *
From (
 SELECT UL.ID, UL.LeadNo, UL.PersonName, UL.img_ext, UL.CompanyName, UL.CreatedOn AS CreatedOn1, CASE WHEN ISNULL(UL.CountryCode, '''') <> '''' and ISNULL(UL.MobileNo, '''') <> ''''  THEN ISNULL(UL.Countrycode, '''') + '' '' + ISNULL(UL.MobileNo, '''')  ELSE '''' END +  CASE WHEN ISNULL(UL.Mobileno1, '''') <> '''' THEN '', ...'' ELSE '''' END AS MobileNo3, CASE WHEN ISNULL(UL.Emailid, '''') <> '''' THEN UL.Emailid ELSE '''' END + CASE WHEN ISNULL(UL.EmailID1, '''') <> '''' THEN '', '' ELSE '''' END +  CASE WHEN ISNULL(UL.EmailID2, '''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode,UL.CountryCode1,UL.CountryCode2, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, CONVERT(VARCHAR(10), UL.CreatedOn, 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), UL.CreatedOn, 109), 15), 7, 7, '' '') AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy, UD2.User_Login as FollowupBy, UL.MobileNo AS MobileNo, UL.MobileNo1, UL.MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2,  ( select isnull((select STRING_AGG(isnull(ProductName,''''),'', '') from openjson(ul.productsJson)
	               with(ProductName nvarchar(max) ''$.ProductName'' )
			       where isnull(ul.productsJson,'''') != '''') , '''') ) AS Products, UD.User_Login AS assigneduser, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int), ThresholdColor=case when cast(isnull((LS.currentscore/nullif('+ cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int)>' + cast(@warm as nvarchar(max)) + ' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max))+',0.00))*99,0) as int) between ' + cast(@cold as nvarchar(max)) + ' and ' + cast(@warm as nvarchar(max)) + ' then ''Warm'' else ''Cold'' end , UD1.User_Login, UL.WhereAddress  ' as nvarchar(max)) + ', UD2.User_Login as LastFollowupCreatedByName , UL.WhatsAppNoColName '

 select @Query +=cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)
ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f
left join lead_score_history_latest(nolock) LS
ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK)
ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)
ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)
ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)
ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK)
ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK)
ON UL.FollowUpStatus = FUS.id
-- left join LeadPipelineMapping_latest(nolock) as lpm
--on UL.ID = lpm.LeadID 
WHERE ul.id > '+cast(@start_entityid as nvarchar)+' and UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo = ' +
CASE WHEN @Userid = 0 THEN N'UL.AssignedTo' ELSE CAST(@Userid AS NVARCHAR(MAX)) END + '
 and 1= case when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''0'' then 1 when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''1''
 and isnull(LastFollowupCreatedBy,0)=0 then 1 else 0 end'
 + '
 ) T         
 ) S         
 ) AS A Where A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno+@offset) AS NVARCHAR(MAX));
END        
ELSE        
BEGIN        
 --print 'Branch B'

 SET @Query+=CAST(N'SELECT A.ID,A.LeadNo,A.PersonName,A.CompanyName,A.MobileNo,A.EmailID,A.City,A.State,A.Country,A.CountryCode,A.CountryCode1,A.CountryCode2,A.PinCode, A.ResidentialAddress,A.OfficeAddress,isnull(A.SourceName,''Unknown'') SourceName,A.MediumName,A.CampaignName,A.InitialRemarks,A.ParentID, A.FollowupBy,dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',A.FollowupDate) AS FollowupDate, dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',A.FollowupCreatedDate) AS FollowupCreatedDate,dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',A.CreatedOn1) AS CreatedOn1New,A.CreatedOn1,A.AssignedTo, A.Remarks,CASE WHEN ISNULL(A.FollowupStatus,'''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus,'''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.FollowupDate,'''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products,'''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks,'''') + ''</p>'' ELSE '''' END AS FollowUp,A.MobileNo1,A.MobileNo2,A.MobileNo3,A.EmailID3,A.EmailID1,A.EmailID2,A.FollowupStatus,A.assigneduser,A.img_ext, A.WhereAddress, isnull(A.Products, '''') as Products, A.CurrentScore,A.Profit_Loss,A.ThresholdColor,RowNumber1,rc1,A.User_Login, A.LastFollowupCreatedByName,A.WhatsAppNoColName         
	INTO #temp1
	FROM
	(
	select ROW_NUMBER() OVER(ORDER BY S.ID ASC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1,*
	From (
	select *
	From (
	SELECT UL.ID,UL.LeadNo,UL.PersonName,UL.img_ext,UL.CompanyName,UL.CreatedOn AS CreatedOn1,
	CASE WHEN ISNULL(UL.CountryCode,'''') <> '''' and ISNULL(UL.MobileNo,'''') <> '''' THEN ISNULL(UL.Countrycode,'''') + '' '' + ISNULL(UL.MobileNo,'''')  ELSE '''' END +  CASE WHEN ISNULL(UL.Mobileno1,'''') <> '''' THEN '', ...'' ELSE '''' END AS MobileNo3, CASE WHEN ISNULL(UL.Emailid,'''') <> '''' THEN UL.Emailid ELSE '''' END + CASE WHEN ISNULL(UL.EmailID1,'''') <> ''''  THEN '', '' ELSE '''' END +   CASE WHEN ISNULL(UL.EmailID2,'''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode,UL.CountryCode1,UL.CountryCode2, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, CONVERT(VARCHAR(10), UL.CreatedOn, 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), UL.CreatedOn, 109), 15), 7, 7, '' '') AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy, UD2.User_Login as FollowupBy, UL.MobileNo AS MobileNo, UL.MobileNo1, UL.MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2,  ( select isnull((select STRING_AGG(isnull(ProductName,''''),'', '') from openjson(ul.productsJson)
	               with(ProductName nvarchar(max) ''$.ProductName'' )
			       where isnull(ul.productsJson,'''') != '''') , '''') ) AS Products, UD.User_Login AS assigneduser, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int) , ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' +  cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int)>' + cast(@warm as nvarchar(max)) + ' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max))+',0.00))*99,0) as int) between ' + cast(@cold as nvarchar(max)) + ' and ' + cast(@warm as nvarchar(max)) + ' then ''Warm'' else ''Cold'' end , UD1.User_Login, UL.WhereAddress ' as nvarchar(max)) +  ', UD2.User_Login as LastFollowupCreatedByName, UL.WhatsAppNoColName '

	select @Query +=cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)
	ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f
	left join lead_score_history_latest(nolock) LS
	ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK)
	ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)
	ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)
	ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)
	ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK)
	ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK)
	ON UL.FollowUpStatus = FUS.id 
	--left join LeadPipelineMapping_latest(nolock) as lpm
    --on UL.ID = lpm.LeadID
	WHERE ul.id > '+cast(@start_entityid as nvarchar)+' and UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo = ' +
	CASE WHEN @Userid = 0 THEN N'UL.AssignedTo' ELSE CAST(@Userid AS NVARCHAR(MAX)) END + ' and 1= case when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''0'' then 1 when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''1'' and isnull(LastFollowupCreatedBy,0)=0  then 1 else 0 end' + '        
) T Where ' + @FilterText + '
) S
 ) AS A Where ' + case when @txtSearch = ' (1=1) ' then ' A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) else ' (1=1) ' end AS NVARCHAR(MAX));          
 --) AS A ' AS NVARCHAR(MAX));          
                                          
  -- print @Query                     
End        

                                        
 IF(@Pivot_Column IS NOT NULL)
 BEGIN        
   --print 'Branch C'        
 --IF(@FilterText = ' (1=1) ' and @txtSearch = ' (1=1) ')-- From Branch A        
 IF(@txtSearch = ' (1=1) ')-- From Branch A        
 Begin        
  --print 'Branch CA'        
SELECT @Query += CAST(N'; Select * from ( Select ID,LeadNo,PersonName, CompanyName,MobileNo , MobileNo1, MobileNo2,Countrycode,Countrycode1,Countrycode2,EmailID3 as EmailID, EmailID1, EmailID2, City, [State], Country, Pincode, Residentialaddress, Officeaddress, SourceName, MediumName, CampaignName, Initialremarks,CreatedOn1 as datecreated  ,AssignedTo,followupstatus,FollowupCreatedDate as nextfollowupdate,WhatsAppNoColName,isnull(followupdate,'''') as followupdate,rownumber1,currentscore
   From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode,CountryCode1,CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login as User_Login, FollowupDate,   FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, Img_Ext, Products, FollowupCreatedDate, FollowupBy, WhereAddress, ' + @Pivot_Column + N', CurrentScore, Profit_Loss, ThresholdColor, RowNumber1, rc1,LastFollowupCreatedByName,WhatsAppNoColName
   FROM
   (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode,CountryCode1,CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy, FollowupDate, FollowupCreatedDate,
   CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, img_ext, WhereAddress, Products, [fieldname] , fieldvalue, CurrentScore, Profit_Loss,ThresholdColor, RowNumber1, rc1 ,User_Login,LastFollowupCreatedByName, WhatsAppNoColName   FROM (select L.ID,  L.LeadNo, L.PersonName, L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State, L.Country, L.CountryCode,L.CountryCode1,L.CountryCode2, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.FollowupBy, L.FollowupDate, L.FollowupCreatedDate, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,  L.assigneduser, L.Img_Ext, L.WhereAddress, L.Products, y.fieldname, x.fieldvalue, L.CurrentScore, L.Profit_Loss, L.ThresholdColor, L.RowNumber1, L.rc1,L.User_Login,L.LastFollowupCreatedByName,L.WhatsAppNoColName
   From #temp1 L left join customfieldLeadvalue(nolock) x
   ON L.ID = x.LeadID left join customfields(nolock) y
   ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1
   )q )Tab1
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2) T1
  Where ' + @txtSearch + '
  ) T2
  Where T2.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno)  + N' ORDER BY ' + @ordstr
  /*N' ORDER BY CurrentScore desc,        
   case when cast(followupdate as date) = cast(getdate() as date) then 0        
     when followupdate < getdate()  then 1        
     when followupdate > getdate() then 2        
     when followupdate is null then 3        
      end,followupdate  '*/ AS NVARCHAR(MAX));        
 End        
 Else-- From Branch B        
 Begin        
  --print 'Branch CB'        
        
  Select @filterCnt=count(*) From dbo.fn_Split(@txtSearch, ' ) ')        
          
 -- SELECT @Query += CAST(N'; select x.LeadID
 -- into #Temp2
 -- from customfieldLeadvalue(nolock) x inner join customfields(nolock) y
 -- ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1
 --Where ' + @txtSearch + N'
 --group by x.LeadID
 --having count(*) >= ' + Cast(@filterCnt as NVARCHAR(MAX)) AS NVARCHAR(MAX));

     SELECT @Query += CAST(N'; select * into #Temp2 From (select [x].LeadID, [y].[fieldname], 
				[x].[fieldvalue] from customfieldLeadvalue(nolock) x inner join customfields(nolock) y
				ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) T1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @txtSearch AS NVARCHAR(MAX));
				  

        
  SELECT @Query += CAST(N'; Select ID,LeadNo,PersonName, CompanyName,MobileNo, MobileNo1, MobileNo2,Countrycode,Countrycode1,Countrycode2,EmailID3 as EmailID, EmailID1, EmailID2, City, [State], Country, Pincode, Residentialaddress, Officeaddress, SourceName, MediumName, CampaignName, Initialremarks,CreatedOn1 as datecreated  ,AssignedTo,followupstatus,FollowupCreatedDate as nextfollowupdate,WhatsAppNoColName,followupdate,rownumber1,currentscore from ( Select ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], *
   From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, CountryCode1, CountryCode2,PinCode, ResidentialAddress, OfficeAddress, SourceName,  MediumName, CampaignName, InitialRemarks, ParentID, User_Login as User_Login, FollowupDate,    FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, Img_Ext, WhereAddress, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column +   
   N', CurrentScore, Profit_Loss, ThresholdColor,WhatsAppNoColName
   FROM
   (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode,CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy, FollowupDate, FollowupCreatedDate,   CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, img_ext, WhereAddress, Products, ' + @Pivot_Column +   
   N', CurrentScore, Profit_Loss,ThresholdColor,User_Login,LastFollowupCreatedByName,WhatsAppNoColName
   FROM (select L.ID, L.LeadNo, L.PersonName, L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.CountryCode1, L.CountryCode2, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.FollowupBy, L.FollowupDate, L.FollowupCreatedDate, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,  L.assigneduser, L.Img_Ext, L.WhereAddress, L.Products, ' + @Pivot_Column +   
   N', L.CurrentScore, L.Profit_Loss, L.ThresholdColor,L.User_Login,L.LastFollowupCreatedByName,L.WhatsAppNoColName
   From #Temp2 A inner join #temp1 L
   ON A.LeadId = L.ID 
   )q )Tab1
   ) T1
  ) T2
  Where T2.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) + N' ORDER BY ' + @ordstr
  /*N' ORDER BY CurrentScore desc,        
   case when cast(followupdate as date) = cast(getdate() as date) then 0        
     when followupdate < getdate()  then 1        
     when followupdate > getdate() then 2        
     when followupdate is null then 3        
      end,followupdate  '*/ AS NVARCHAR(MAX));        
 End        
END        
ELSE        
BEGIN        
 -- print 'Branch D'        
        
  SET @Query += CAST(N';Select ID,LeadNo,PersonName, CompanyName, MobileNo, MobileNo1, MobileNo2,Countrycode,Countrycode1,Countrycode2,EmailID3 as EmailID, EmailID1, EmailID2, City, [State], Country, Pincode, Residentialaddress, Officeaddress, SourceName, MediumName, CampaignName, Initialremarks,CreatedOn1 as datecreated  ,AssignedTo,followupstatus,FollowupCreatedDate as nextfollowupdate,WhatsAppNoColName,followupdate,rownumber1,currentscore
  From #temp1        
  Where RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) + N' ORDER BY ' + @ordstr         
  /*N' ORDER BY CurrentScore desc,        
  case when cast(followupdate as date) = cast(getdate() as date) then 0        
  when followupdate < getdate() then 1        
  when followupdate > getdate() then 2        
  when followupdate is null then 3        
  end,followupdate '*/ AS NVARCHAR(MAX));        
END        
                                        
  -- print '@FinalQuery:- ' + cast(@Query as varchar(max))        
                                        
                                      
 EXEC sp_executesql @Query;                                          
                                          
 --update kit19_executionlogger                                          
 --set EndDatetime = getdate(),                                          
 --Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)                                          
 --where ID = @LoggerID                                          
                                          
 --update kit19_executionlogger                                          
 --set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)                                          
 --where ID = @LoggerID                                          
                                          
 IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;        
 IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL BEGIN DROP TABLE #temp2; END;        
End                                          
                    
END   





GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserLeadDetails2_Followup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
-- exec Usp_ViewUserLeadDetails2_Followup @txtSearch=N'', @ParentID=29453, @Userid=0, @FilterText=N'', @srno=N'1', @enno=N'20'
-- exec Usp_ViewUserLeadDetails2_Followup @txtSearch=N'', @ParentID=32222, @Userid=0, @FilterText=N'', @srno=N'1', @enno=N'20'      
-- exec Usp_ViewUserLeadDetails2_Followup @txtSearch=N'', @ParentID=335, @Userid=0, @FilterText=N' ( Products = ''cvx'' ) ', @srno=N'1', @enno=N'20'
-- exec Usp_ViewUserLeadDetails2_Followup @txtSearch=N'', @ParentID=335, @Userid=0, @FilterText=N' ( FollowupDate >= ''01/20/2020'' And FollowupDate <= ''10/31/2020'' ) ', @srno=N'1', @enno=N'20'
-- exec Usp_ViewUserLeadDetails2_Followup @txtSearch=N'', @ParentID=335, @Userid=0, @FilterText=N' ( FollowupCreatedDate >= ''01/20/2020'' And FollowupCreatedDate <= ''10/31/2020'' ) ', @srno=N'1', @enno=N'20'     
-- exec Usp_ViewUserLeadDetails2_Followup @txtSearch=N'', @ParentID=335, @Userid=0, @FilterText=N' ( FollowupCreatedDate >= ''01/20/2020'' And FollowupCreatedDate <= ''11/03/2020'' ) ', @srno=N'1', @enno=N'20'
CREATE   PROCEDURE [dbo].Usp_ViewUserLeadDetails2_Followup
(
	@txtSearch NVARCHAR(100),
	@ParentID BIGINT,
	@Userid INT= 0,
	@FilterText NVARCHAR(MAX) = '',
	@srno NVARCHAR(100),
	@enno NVARCHAR(100)
)
AS
BEGIN

/*declare @Parameterlist nvarchar(max) , @LoggerID bigint
set @Parameterlist = 'txtSearch : '+ @txtSearch + ' ,ParentID : '+ CONVERT(VARCHAR(100), @ParentID) + ' ,Userid : '+ CONVERT(VARCHAR(100), @Userid) + ' ,FilterText : '+ @FilterText + ' ,srno : '+ @srno + ' ,enno : '+ @enno;

insert into kit19_executionlogger(ObjectName,Parameterlist,StartDatetime,EndDatetime,Remarks)
values('Usp_ViewUserLeadDetails2',@Parameterlist,getdate(),'','')

set @LoggerID = Scope_Identity();*/

-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=335,@Userid INT=0,@FilterText NVARCHAR(MAX)=N' ( Products = ''cvx'' ) ',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20'

IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;

Declare @NoCustomFields bigint
DECLARE @Pivot_Column NVARCHAR(MAX);
DECLARE @Query NVARCHAR(MAX)= '', @Query1 NVARCHAR(MAX)= '';

/*Select Pivot Column*/
SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])
FROM
(
SELECT DISTINCT [fieldname] FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1
) AS Tab;

set @NoCustomFields = (SELECT count(DISTINCT [fieldname]) FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1)
DECLARE @Rcnt VARCHAR(100);

IF(@Userid > 0)
BEGIN
SELECT @Rcnt = COUNT(ID) FROM UserLeads(NOLOCK) WHERE ParentID = @ParentID and AssignedTo = @Userid;
END
ELSE
BEGIN
SELECT @Rcnt = COUNT(ID) FROM UserLeads(NOLOCK) WHERE ParentID = @ParentID;
END

SET @Query+=CAST(N'SELECT DISTINCT
[A].[ID], [A].[LeadNo], [A].[PersonName], [A].[CompanyName], [A].[MobileNo], [A].[EmailID], [A].[City], [A].[State], [A].[Country], [A].[CountryCode], [A].[PinCode], [A].[ResidentialAddress], [A].[OfficeAddress], [A].[SourceName], [A].[MediumName], [A].[CampaignName], [A].[InitialRemarks], [A].[ParentID], [A].[User_Login], [dbo].[fn_getusertimefromindiantime](' + CAST(@ParentID AS NVARCHAR(MAX)) + ', [A].[FollowupDate]) AS [FollowupDate], [dbo].[fn_getusertimefromindiantime](' + CAST(@ParentID AS NVARCHAR(MAX)) + ', [A].[CreatedOn]) AS [CreatedOn], [dbo].[fn_getusertimefromindiantime](' + CAST(@ParentID AS NVARCHAR(MAX)) + ', [A].[CreatedOn1]) AS [CreatedOn1New], [A].[CreatedOn1], [A].[AssignedTo], [A].[Remarks],CASE WHEN ISNULL([A].[FollowupStatus], '''') <> '''' THEN ''<p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL([A].[FollowupStatus], '''') AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[FollowupDate], '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST([A].[FollowupDate] AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[Products], '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST([A].[Products] AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[AmountPaid], 0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL([A].[AmountPaid], 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[Remarks], '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL([A].[Remarks], '''') + ''</p>'' ELSE '''' END AS [FollowUp],[A].[MobileNo1], [A].[MobileNo2], [A].[MobileNo3], [A].[EmailID3], [A].[EmailID1], [A].[EmailID2], [A].[FollowupStatus], [A].[assigneduser], [A].[img_ext], isnull([A].[Products], '''') as Products, [dbo].[fn_getusertimefromindiantime](' + CAST(@ParentID AS NVARCHAR(MAX)) + ', [A].[FollowupCreatedDate]) AS [FollowupCreatedDate], [A].[FollowupBy]
INTO #temp1
FROM
(
SELECT [UL].[ID], [UL].[LeadNo], [UL].[PersonName], [UL].[img_ext], [UL].[CompanyName], [UL].[CreatedOn] AS [CreatedOn1],
CASE WHEN ISNULL([UL].[CountryCode], '''') <> ''''
THEN ISNULL([UL].[Countrycode], '''') + '' '' + ISNULL([UL].[MobileNo], '''')
ELSE '''' END +
CASE WHEN ISNULL([UL].[Mobileno1], '''') <> ''''
THEN '', ...''
ELSE '''' END AS [MobileNo],
CASE WHEN ISNULL([UL].[Emailid], '''') <> ''''
THEN '' ''
ELSE '''' END +
CASE WHEN ISNULL([UL].[EmailID1], '''') <> ''''
THEN '', '' ELSE '''' END +
CASE WHEN ISNULL([UL].[EmailID2], '''') <> ''''
THEN '', ''
ELSE '''' END AS [EmailID],
[UL].[City], [UL].[State], [UL].[Country], [UL].[CountryCode], [UL].[PinCode], [UL].[ResidentialAddress], [UL].[OfficeAddress], [UL].[AssignedTo], [USS].[Name] AS [SourceName], [UMS].[Name] AS [MediumName], [UCS].[Name] AS [CampaignName], [UL].[InitialRemarks], [UL].[ParentID],FUS.[FollowupStatus], [UL].[FollowupDate], [UL].[Remarks], ISNULL([UL].[AmountPaid], 0) AS [AmountPaid], CONVERT(VARCHAR(10), [UL].[CreatedOn], 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), [UL].[CreatedOn], 109), 15), 7, 7, '' '') AS [CreatedOn], [UL].[CreatedBy], [UL].[ModifiedOn], [UL].[ModifiedBy], [UD].[User_Login], [UL].[MobileNo] AS [MobileNo3], [UL].[MobileNo1], [UL].[MobileNo2], [UL].[EmailID] AS [EmailID3], [UL].[EmailID1], [UL].[EmailID2], LIH.CreatedOn as [FollowupCreatedDate], [UD0].[User_Login] AS [FollowupBy], ( SELECT STUFF( (SELECT N'', '' + [ss].[Name]
FROM [ProductMaster](nolock) AS [ss] INNER JOIN [dbo].[fn_Split]([ul].[Products], ''#'') AS [fs]
ON [ss].[ProductID] = [fs].[value] FOR XML PATH(''''), TYPE
).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''')
) AS [Products], [UD].[User_Login] AS [assigneduser]
FROM UserLeads AS UL(NOLOCK) --INNER JOIN #TMPquery1 t on UL.ID = t.LeadID
INNER JOIN UserSourceSettings AS USS(NOLOCK)
ON UL.SourceName = USS.SourceID LEFT JOIN UserMediumSettings AS UMS(NOLOCK)
ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)
ON UL.CampaignName = UCS.CampaignID LEFT JOIN LeadInteractionHistory AS LIH(NOLOCK)
ON UL.ParentID = LIH.ParentID and UL.LeadNo = LIH.LeadNo LEFT JOIN User_Detail AS UD0(NOLOCK)
ON LIH.CreatedBy = UD0.User_ID LEFT JOIN User_Detail AS UD(NOLOCK)
ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)
ON UL.CreatedBy = UD1.User_ID left join [FollowUp_Status](NOLOCK) AS FUS
ON UL.[FollowUpStatus] = FUS.[id] WHERE [UL].[ParentID] = ' + CAST(@ParentID AS NVARCHAR(MAX)) + ' AND [UL].[AssignedTo] = CASE WHEN ' +
CAST(@Userid AS NVARCHAR(MAX)) + ' = 0 THEN [UL].[AssignedTo] ELSE ' + CAST(@Userid AS NVARCHAR(MAX)) + ' END
AND (ISNULL(''' + @txtSearch + ''', '''') = '''' OR [PersonName] LIKE ''%'' + ' + @txtSearch + ' + ''%'' OR [CompanyName] LIKE ''%'' + ' + @txtSearch + ' + ''%'')
) AS A ORDER BY [A].[ID] DESC;' AS NVARCHAR(MAX));

IF(@FilterText = '')
BEGIN
SET @FilterText = ' (1=1) ';
END;

IF(@Pivot_Column IS NOT NULL)
BEGIN
SELECT @Query+=CAST(N';Select * From (SELECT ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, Img_Ext, Products, FollowupCreatedDate, FollowupBy, '
+ @Pivot_Column + ' FROM
(SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, FollowupCreatedDate, FollowupBy, img_ext, Products, [fieldname] , fieldvalue FROM (select L.ID, L.LeadNo, L.PersonName, L.CompanyName, L.MobileNo, L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.User_Login, L.FollowupDate, L.CreatedOn, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus, L.assigneduser, L.Img_Ext, L.Products, L.FollowupCreatedDate, L.FollowupBy, y.fieldname, x.fieldvalue
From #temp1 L left join customfieldLeadvalue(nolock) x ON L.ID = x.LeadID left join customfields(nolock) y on x.fieldID=y.field_ID
AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1
)q )Tab1
PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2
WHERE ' + @FilterText + ') T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) AS NVARCHAR(MAX));
END
ELSE
BEGIN
SET @Query += CAST(N';Select * From (select ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], * from #temp1 where ' + @FilterText + ') T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) AS NVARCHAR(MAX));
END

-- print '@FinalQuery:- ' + cast(@Query as varchar(max))
EXEC sp_executesql @Query;

/*update kit19_executionlogger
set EndDatetime = getdate(),
Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)
where ID = @LoggerID

update kit19_executionlogger
set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)
where ID = @LoggerID*/

IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;

END



