CREATE   PROCEDURE [dbo].[Usp_ViewUserLeadDetails2_New$]
(                                  
 @txtSearch NVARCHAR(max),                                  
 @ParentID BIGINT,                                  
 @Userid INT= 0,                                  
 @FilterText NVARCHAR(MAX) = '',                                  
 @srno NVARCHAR(100),                                  
 @enno NVARCHAR(100)                                  
)                                  
AS                                  
BEGIN                                  
