--declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=38750,@Userid INT=38759,@FilterText NVARCHAR(MAX)=N' ( FollowupStatus = ''Call-Back'' )',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20'  -- BD
