   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec Usp_ViewUserLeadDetails2 @txtSearch=N'',@ParentID=29453,@Userid=36769,@FilterText=N'',@srno=N'1',@enno=N'230'                            
