-- exec Usp_ViewUserLeadDetails2 @txtSearch=N'', @ParentID=335, @Userid=0, @FilterText=N' ( FollowupCreatedDate >= ''01/20/2020'' And FollowupCreatedDate <= ''11/03/2020'' ) ', @srno=N'1', @enno=N'20'                            
-- exec Usp_ViewUserLeadDetails2_New @txtSearch=N'',@ParentID=335,@Userid=0,@FilterText=N' ( FollowupBy like  ''%sms%'' ) ',@srno=N'1',@enno=N'20'             
-- exec Usp_ViewUserLeadDetails2_New @txtSearch=N'',@ParentID=335,@Userid=0,@FilterText=N'',@srno=N'1',@enno=N'20'                           
CREATE   PROCEDURE [dbo].Usp_ViewUserLeadDetails2_New_OrderBy                        
(                          
 @txtSearch NVARCHAR(100),                          
 @ParentID BIGINT,                          
 @Userid INT= 0,                          
 @FilterText NVARCHAR(MAX) = '',                          
 @srno NVARCHAR(100),                          
 @enno NVARCHAR(100)                          
)                          
AS                          
BEGIN                          
                          
declare @Parameterlist nvarchar(max) , @LoggerID bigint                          
set @Parameterlist = 'txtSearch : '+ @txtSearch + ' ,ParentID : '+ CONVERT(VARCHAR(100), @ParentID) + ' ,Userid : '+ CONVERT(VARCHAR(100), @Userid) +               
' ,FilterText : '+ @FilterText + ' ,srno : '+ @srno + ' ,enno : '+ @enno;                          
                          
insert into kit19_executionlogger(ObjectName,Parameterlist,StartDatetime,EndDatetime,Remarks)                          
values('Usp_ViewUserLeadDetails2_New',@Parameterlist,getdate(),'','')                          
                          
set @LoggerID = Scope_Identity();                          
                          
-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=29453,@Userid INT=36769,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'200'                          
                          
If (CHARINDEX('FollowupCreatedDate',@FilterText) > 0 or CHARINDEX('FollowupBy',@FilterText) > 0)                          
Begin                          
 print 'Usp_ViewUserLeadDetails2_Followup_New'                          
  --Exec Usp_ViewUserLeadDetails2_Followup @txtSearch,@ParentID,@Userid,@FilterText,@srno,@enno                          
  Exec Usp_ViewUserLeadDetails2_Followup_New @txtSearch,@ParentID,@Userid,@FilterText,@srno,@enno                          
End                          
Else                          
Begin                          
 print 'Usp_ViewUserLeadDetails2_New'                          
                          
 IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;                          
                          
 Declare @NoCustomFields bigint                          
 DECLARE @Pivot_Column NVARCHAR(MAX);                          
 DECLARE @Query NVARCHAR(MAX)= '', @Query1 NVARCHAR(MAX)= '',@Query2 nvarchar(max)                          
                          
 /*Select Pivot Column*/                          
 SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])                          
 FROM                          
 (                          
 SELECT DISTINCT [fieldname] FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1                          
 ) AS Tab;            
                          
 set @NoCustomFields = (SELECT count(DISTINCT [fieldname]) FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1)                          
 DECLARE @Rcnt VARCHAR(100);                          
                          
 IF(@Userid > 0)                          
 BEGIN                          
 SELECT @Rcnt = COUNT(ID) FROM UserLeads(NOLOCK) WHERE ParentID = @ParentID and AssignedTo = @Userid;                          
 END                          
 ELSE                          
 BEGIN                          
 SELECT @Rcnt = COUNT(ID) FROM UserLeads(NOLOCK) WHERE ParentID = @ParentID;                          
 END                          
                          
 SET @Query+=CAST(N'SELECT DISTINCT                          
 [A].[ID], [A].[LeadNo], [A].[PersonName], [A].[CompanyName], [A].[MobileNo], [A].[EmailID], [A].[City], [A].[State], [A].[Country], [A].[CountryCode],       
 [A].[PinCode], [A].[ResidentialAddress], [A].[OfficeAddress], [A].[SourceName], [A].[MediumName],[A].[CampaignName], [A].[InitialRemarks], [A].[ParentID],       
 [A].[User_Login],[dbo].[fn_getusertimefromindiantime](' + CAST(@ParentID AS NVARCHAR(MAX)) + ', [A].[FollowupDate]) AS [FollowupDate],      
  [dbo].[fn_getusertimefromindiantime](' + CAST(@ParentID AS NVARCHAR(MAX)) + ', [A].[CreatedOn]) AS [CreatedOn],       
   [dbo].[fn_getusertimefromindiantime](' + CAST(@ParentID AS NVARCHAR(MAX)) + ', [A].[CreatedOn1]) AS [CreatedOn1New],  [A].[CreatedOn1],       
   [A].[AssignedTo], [A].[Remarks], CASE WHEN ISNULL([A].[FollowupStatus], ''      
'') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL([A].[FollowupStatus], '''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END +       
CASE WHEN ISNULL([A].[FollowupDate], '''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST      
([A].[FollowupDate] AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[Products], '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>''       
+ CAST([A].[Products] AS VARCHAR(50)) + ''</p>'' ELSE '''' END +        
CASE WHEN ISNULL([A].[AmountPaid],0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL([A].[AmountPaid], 0) AS DECIMAL(18, 0)) AS VARCHAR(50))       
+ ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[Remarks], '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' +       
ISNULL([A].[Remarks], '''') + ''</p>'' ELSE '''' END AS [FollowUp],[A].[MobileNo1], [A].[MobileNo2], [A].[MobileNo3], [A].[EmailID3], [A].[EmailID1],      
 [A].[EmailID2], [A].[FollowupStatus], [A].[assigneduser], [A].[img_ext], isnull([A].[Products], '''') as Products       
                
  , [A].[CurrentScore], [A].[Profit_Loss], [A].[ThresholdColor] ,[A].[ModifiedOn]                       
 INTO #temp1                          
 FROM                          
 (                          
 SELECT [UL].[ID], [UL].[LeadNo], [UL].[PersonName], [UL].[img_ext], [UL].[CompanyName], [UL].[CreatedOn] AS [CreatedOn1],      
  CASE WHEN ISNULL([UL].[CountryCode], '''') <> '''' and ISNULL([UL].[MobileNo], '''') <> ''''  THEN ISNULL([UL].[Countrycode], '''')       
+ '' '' + ISNULL([UL].[MobileNo], '''')  ELSE '''' END +           CASE WHEN ISNULL([UL].[Mobileno1], '''') <> ''''                          
 THEN '', ...''                          
 ELSE '''' END AS [MobileNo],                          
 CASE WHEN ISNULL([UL].[Emailid], '''') <> ''''                          
 THEN [UL].[Emailid]                          
 ELSE '''' END +                          
 CASE WHEN ISNULL([UL].[EmailID1], '''') <> ''''                          
 THEN '', '' ELSE '''' END +                          
 CASE WHEN ISNULL([UL].[EmailID2], '''') <> ''''                          
 THEN '', ''                          
 ELSE '''' END AS [EmailID],                          
 [UL].[City], [UL].[State], [UL].[Country], [UL].[CountryCode], [UL].[PinCode], [UL].[ResidentialAddress],               
 [UL].[OfficeAddress], [UL].[AssignedTo], [USS].[Name] AS [SourceName], [UMS].[Name] AS [MediumName], [UCS].[Name] AS [CampaignName],               
 [UL].[InitialRemarks], [UL].[ParentID],FUS.[FollowupStatus], [UL].[FollowupDate], [UL].[Remarks],              
  ISNULL([UL].[AmountPaid], 0) AS [AmountPaid], CONVERT(VARCHAR(10), [UL].[CreatedOn], 101) +               
  STUFF(RIGHT(CONVERT(VARCHAR(26), [UL].[CreatedOn], 109), 15), 7, 7, '' '') AS [CreatedOn], [UL].[CreatedBy], [UL].[ModifiedOn],              
   [UL].[ModifiedBy], [UD1].[User_Login], [UL].[MobileNo] AS [MobileNo3], [UL].[MobileNo1], [UL].[MobileNo2], [UL].[EmailID] AS [EmailID3],               
   [UL].[EmailID1], [UL].[EmailID2], ( SELECT STUFF( (SELECT N'', '' + [ss].[Name] FROM [ProductMaster](nolock) AS [ss]               
   INNER JOIN [dbo].[fn_Split]([ul].[Products], ''#'') AS [fs]  ON [ss].[ProductID]               
   = [fs].[value] FOR XML PATH(''''), TYPE).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''') ) AS [Products],               
   [UD].[User_Login] AS [assigneduser]                  
   ,f.[CurrentScore],     
   f.[Profit_Loss],              
    f.[ThresholdColor] ' as nvarchar(max))               
 select @query +=cast(N' FROM UserLeads AS UL(NOLOCK) --INNER JOIN #TMPquery1 t on UL.ID = t.LeadID                          
 INNER JOIN UserSourceSettings AS USS(NOLOCK)                          
 ON UL.SourceName = USS.SourceID         
 outer apply dbo.funcToGetScoredetails(ul.id) f    
 LEFT JOIN UserMediumSettings AS UMS(NOLOCK)                          
 ON UL.MediumName = UMS.MediumID         
 LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)                          
 ON UL.CampaignName = UCS.CampaignID         
 LEFT JOIN User_Detail AS UD(NOLOCK)                          
 ON UL.AssignedTo = UD.User_ID         
 LEFT JOIN User_Detail AS UD1(NOLOCK)                          
 ON UL.CreatedBy = UD1.User_ID         
 left join FollowUp_Status AS FUS(NOLOCK)  ON [UL].[FollowUpStatus] = FUS.[id] WHERE [UL].[ParentID] = ' + CAST(@ParentID AS NVARCHAR(MAX)) + '               
 AND [UL].[AssignedTo] =               
 CASE WHEN ' +             CAST(@Userid AS NVARCHAR(MAX)) + ' = 0 THEN [UL].[AssignedTo] ELSE ' + CAST(@Userid AS NVARCHAR(MAX)) + '               
 END                
 AND (ISNULL(''' + cast(@txtSearch as nvarchar(max)) + ''', '''') = '''' OR [PersonName] LIKE ''%'' + ' + cast(@txtSearch as nvarchar(max)) + ' + ''%'' OR [CompanyName]              
  LIKE ''%'' + ' + cast(@txtSearch as nvarchar(max)) + ' + ''%'')                        
 ) AS A ORDER BY [A].[ID] DESC;' AS NVARCHAR(MAX));                          
                          
  print @Query                        
                        
 IF(@FilterText = '')                          
 BEGIN                          
 SET @FilterText = ' (1=1) ';                          
 END;                          
                          
 IF(@Pivot_Column IS NOT NULL)                          
 BEGIN                          
 SELECT @Query += CAST(N'; Select * From (SELECT ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], ID,               
 LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress,               
 OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, CreatedOn,       
 CreatedOn1New,               
CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2,               
FollowupStatus, assigneduser, Img_Ext, Products, CreatedOn as FollowupCreatedDate, User_Login as FollowupBy,              
 '           + @Pivot_Column + ', CurrentScore, Profit_Loss, ThresholdColor, ModifiedOn  FROM                          
 (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode,      
  ResidentialAddress,               
 OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, CreatedOn, CreatedOn1New,               
 CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus,       
 assigneduser,               
 img_ext, Products, [fieldname] , fieldvalue, CurrentScore, Profit_Loss,ThresholdColor, ModifiedOn  FROM (select L.ID, L.LeadNo, L.PersonName,      
  L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.PinCode, L.ResidentialAddress,       
 L.OfficeAddress,               
 L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.User_Login, L.FollowupDate, L.CreatedOn, L.CreatedOn1New,              
  L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,               
  L.assigneduser, L.Img_Ext, L.Products, y.fieldname, x.fieldvalue, L.CurrentScore, L.Profit_Loss, L.ThresholdColor, L.ModifiedOn                         
  From #temp1 L left join customfieldLeadvalue(nolock) x ON L.ID = x.LeadID left join customfields(nolock) y on x.fieldID=y.field_ID               
  AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1                          
 )q )Tab1                          
PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2                          
 WHERE ' + @FilterText + ') T1 Where RowNumber1 BETWEEN ' +               
 CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + ' ORDER BY               
 CurrentScore desc, isnull(ModifiedOn,CreatedOn1) desc             
    --  case when cast(followupdate as date) = cast(getdate() as date) then 0                       
    --  when followupdate < getdate()  then 1                      
    --  when followupdate > getdate() then 2                      
    --  when followupdate is null then 3                      
    --   end,followupdate  '
    AS NVARCHAR(MAX));                          
 END                          
 ELSE                   
 BEGIN                          
 SET @Query += CAST(N';Select *, T1.CreatedOn as FollowupCreatedDate, T1.User_Login as FollowupBy               
 From (select ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], * from #temp1 where '               
 + @FilterText + ') T1               
Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) + ' ORDER BY T1.CurrentScore desc,   
    isnull(T1.ModifiedOn,T1.CreatedOn1) desc
--case when                          
--cast(followupdate as date) = cast(getdate() as date) then 0                       
--      when followupdate < getdate()  then 1                      
--      when followupdate > getdate() then 2                      
--      when followupdate is null then 3                      
--       end,followupdate  '
	    AS NVARCHAR(MAX));                          
 END                          
                        
                        
  print '@FinalQuery:- ' + cast(@Query as varchar(max))                         
                        
                      
 EXEC sp_executesql @Query;                          
                          
 update kit19_executionlogger                          
 set EndDatetime = getdate(),                          
 Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)                          
 where ID = @LoggerID                          
                          
 update kit19_executionlogger                          
 set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)                          
 where ID = @LoggerID                          
                          
 IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;                          
End                          
                          
END 


GO

