					Convert(VARCHAR(100), @ParentID) + N' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = UL.ID 
WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' + CASE 
