	END;

	IF (@FilterText = ' (1=1) ' AND @txtSearch = ' (1=1) ')
	BEGIN
		PRINT 'Branch A'

			SET @Query += CAST(N'SELECT A.ID,A.LeadNo,A.PersonName,A.CompanyName,A.MobileNo,A.EmailID,A.City,A.State,A.Country,A.CountryCode,A.PinCode, A.ResidentialAddress, A.OfficeAddress, isnull(A.SourceName,''Unknown'') SourceName, A.MediumName,A.CampaignName,A.InitialRemarks, A.ParentID, A.FollowupBy,format(A.FollowupDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupDate, format(A.FollowupCreatedDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupCreatedDate, format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1New, format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1 , A.AssignedTo, A.Remarks, CASE WHEN ISNULL(A.FollowupStatus, '''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus, '''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.FollowupDate, '''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products, '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks, '''') + ''</p>'' ELSE '''' END AS FollowUp,A.MobileNo1, A.MobileNo2, A.MobileNo3, A.EmailID3, A.EmailID1, A.EmailID2, A.FollowupStatus, A.assigneduser,A.assignedUserloginOnly ,A.img_ext, A.WhereAddress, A.Tags, isnull(A.Products, '''') as Products, A.CurrentScore, A.Profit_Loss, A.ThresholdColor, RowNumber1, rc1, A.User_Login, A.LastFollowupCreatedByName, format(A.LastFollowupedOn,''dd-MMM-yyyy HH:mm:ss'') as LastFollowupedOn, A.WhatsAppNoColName,A.CreatedBy, cast(A.ModifiedOn as datetime) as ModifiedOn, A.ModifiedBy,CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) as AmountPaid  INTO #temp1 FROM ( select ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + 
					N'   S.ID DESC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1, * From ( select * From ( SELECT UL.ID, UL.LeadNo, UL.PersonName, UL.img_ext, UL.WhereAddress, isnull(tg.Tags, '''') Tags, UL.CompanyName, UL.CreatedOn AS CreatedOn1,  CASE WHEN ISNULL(UL.CountryCode, '''') <> '''' and trim(ISNULL(UL.MobileNo, '''')) <> ''''  THEN TRIM(ISNULL(UL.Countrycode, '''')) + '' '' + TRIM(ISNULL(UL.MobileNo, ''''))  ELSE '''' END +  CASE WHEN trim(ISNULL(UL.Mobileno1, '''')) <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid, '''') <> '''' THEN UL.Emailid ELSE '''' END +  CASE WHEN ISNULL(UL.EmailID1, '''') <> '''' THEN '', '' ELSE '''' END +  CASE WHEN ISNULL(UL.EmailID2, '''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, [dbo].[fn_getusertimefromindiantime]('+ cast( @UserIDSql as nvarchar(50)) +',UL.FollowupDate) as FollowupDate , UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, UL.CreatedOn AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy,ISNULL(UD2.User_Login,'''') as FollowupBy, trim(UL.MobileNo) AS MobileNo3, trim(UL.MobileNo1) as MobileNo1, trim(UL.MobileNo2) as MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, (SELECT string_agg(ss.Name,'','') FROM tbl_ProductMaster_' + cast(@ParentID as nvarchar(max)) + ' (nolock) AS ss INNER JOIN dbo.fn_Split(ul.Products, ''#'') AS fs  ON ss.ProductID = case when try_cast(fs.value as bigint) is not null then try_cast(fs.value as bigint) end) AS Products, UD.User_Login + '' ('' + Ud.FName +  '' '' + Ud.LName + '')'' AS assigneduser, UD.User_Login as assignedUserloginOnly , Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) , ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int)>' + cast(@warm AS NVARCHAR(max)) + N' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) between ' + cast(@cold AS NVARCHAR(max)) + N' and ' + cast(@warm AS NVARCHAR(max)) + N' then ''Warm'' else ''Cold'' end , UD1.User_Login , ISNULL(UD2.User_Login, '''') as LastFollowupCreatedByName, ul.LastFollowupCreatedOn as LastFollowupedOn, UL.WhatsAppNoColName  ' AS NVARCHAR(max))
					
	SELECT @Query += cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)
	 ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f
	 left join lead_score_history_latest(nolock) LS 
	ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK)
	ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)
	ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)
	ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)
	ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK)
	ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK)
	ON UL.FollowUpStatus = FUS.id 
	--left join LeadPipelineMapping_latest(nolock) as lpm
	--on UL.ID = lpm.LeadID 
	 LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''lead'' and tm.ParentID = ' + 
					Convert(VARCHAR(100), @ParentID) + N' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = UL.ID 
	WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' + CASE 
						WHEN @Userid = 0
							THEN N' = UL.AssignedTo '
						WHEN @Userid > 0 /*and isnull(@TeamCode,'') != ''*/
							THEN N' in (' + isnull(@UserIdTeamLst, '') + ')'
						ELSE N' = ' + CAST(@Userid AS NVARCHAR(MAX))
						END + N'   
	and 1= case when isnull(' + cast(@notfollowedup AS NVARCHAR) + N',''0'')=''0'' then 1 when isnull(' + cast(@notfollowedup AS NVARCHAR) + N',''0'')=''1''     
	and abs(datediff(mi,ul.createdon,ul.followupdate))<=2    
	--and ul.enquirysource not between 12 and 15 and ul.enquirysource<>22      
	and ul.ModifiedOn is null  then 1 else 0 end' + '    
	) T       
	) S       
	) AS A ' --as nvarchar(max))
	+ ' Where A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno + @offset) AS NVARCHAR(MAX));
		
	END
	ELSE
	BEGIN
		PRINT 'Branch B'

		SET @Query += CAST(N'SELECT A.ID, A.LeadNo, A.PersonName, A.CompanyName, A.MobileNo, A.EmailID, A.City, A.State, A.Country, A.CountryCode, A.PinCode, A.ResidentialAddress, A.OfficeAddress,isnull(A.SourceName,''Unknown'') SourceName, A.MediumName, A.CampaignName, A.InitialRemarks, A.ParentID, A.FollowupBy, format(A.FollowupDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupDate,format(A.FollowupCreatedDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupCreatedDate,format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1New,format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1, A.AssignedTo,A.Remarks,CASE WHEN ISNULL(A.FollowupStatus,'''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus,'''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.FollowupDate,'''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products,'''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL (A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks,'''') + ''</p>'' ELSE '''' END AS FollowUp, A.MobileNo1,A.MobileNo2,A.MobileNo3,A.EmailID3,A.EmailID1,A.EmailID2,A.FollowupStatus,A.assigneduser,A.assignedUserloginOnly,A.img_ext, A.WhereAddress, A.Tags, isnull(A.Products, '''') as Products, A.CurrentScore, A.Profit_Loss, A.ThresholdColor,RowNumber1,rc1 ,A.User_Login, A.LastFollowupCreatedByName, format(A.LastFollowupedOn,''dd-MMM-yyyy HH:mm:ss'') as LastFollowupedOn,A.WhatsAppNoColName, A.CreatedBy, cast(A.ModifiedOn as datetime) as ModifiedOn, A.ModifiedBy,CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) as AmountPaid INTO #temp1 FROM ( select ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N'   S.ID DESC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1,* From ( select * From ( SELECT UL.ID,UL.LeadNo,UL.PersonName,UL.img_ext,UL.CompanyName,UL.CreatedOn AS CreatedOn1, CASE WHEN ISNULL(UL.CountryCode,'''') <> '''' and trim(ISNULL(UL.MobileNo,'''')) <> ''''  THEN TRIM(ISNULL(UL.Countrycode,'''')) + '' '' + TRIM(ISNULL(UL.MobileNo,''''))  ELSE '''' END +  CASE WHEN trim(ISNULL(UL.Mobileno1,'''')) <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid,'''') <> '''' THEN UL.Emailid ELSE '''' END + CASE WHEN ISNULL(UL.EmailID1,'''') <> '''' THEN '', '' ELSE '''' END + CASE WHEN ISNULL(UL.EmailID2,'''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, [dbo].[fn_getusertimefromindiantime]('+ cast( @UserIDSql as nvarchar(50)) +',UL.FollowupDate) as FollowupDate , UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, UL.CreatedOn AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy, ISNULL(UD2.User_Login,'''') as FollowupBy, trim(UL.MobileNo) AS MobileNo3, trim(UL.MobileNo1) as MobileNo1, trim(UL.MobileNo2) as MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, UL.WhereAddress, isnull(tg.Tags, '''') Tags, (SELECT string_agg(ss.Name,'','') FROM tbl_ProductMaster_' + cast(@ParentID as nvarchar(max)) + ' (nolock) AS ss INNER JOIN dbo.fn_Split(ul.Products,''#'') AS fs  ON ss.ProductID = case when try_cast(fs.value as bigint) is not null then try_cast(fs.value as bigint) end) AS Products,UD.User_Login + '' ('' + Ud.FName +  '' '' + Ud.LName + '')'' AS assigneduser, UD.User_Login as assignedUserloginOnly, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end,CurrentScore=cast(isnull((LS.currentscore/nullif('+ cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int), ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int)>' + cast(@warm AS NVARCHAR(max)) + N' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) between ' + cast(@cold AS NVARCHAR(max)) + N'  and ' + cast(@warm AS NVARCHAR(max)) + N' then ''Warm'' else ''Cold'' end, UD1.User_Login ' AS NVARCHAR(max)) + N', isnull(UD2.User_Login, '''') as LastFollowupCreatedByName, ul.LastFollowupCreatedOn as LastFollowupedOn, UL.WhatsAppNoColName  '

		SELECT @Query += cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)
	 ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f
	 left join lead_score_history_latest(nolock) LS ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK) ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK) ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK) ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK) ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK) ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK) ON UL.FollowUpStatus = FUS.id
	--left join LeadPipelineMapping_latest(nolock) as lpm
	--on UL.ID = lpm.LeadID
	 LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''lead'' and tm.ParentID = ' + Convert(VARCHAR(100), @ParentID) + ' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = UL.ID   
	WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' + CASE 
						WHEN @Userid = 0
							THEN N' = UL.AssignedTo '
						WHEN @Userid > 0 /*and isnull(@TeamCode,'') != ''*/
							THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'
						ELSE ' = ' + CAST(@Userid AS NVARCHAR(MAX))
						END + ' and 1= case when isnull(' + cast(@notfollowedup AS NVARCHAR) + ',''0'')=''0'' then 1 when isnull(' + cast(@notfollowedup AS NVARCHAR) + ',''0'')=''1'' and abs(datediff(mi,ul.createdon,ul.followupdate))<=2
	--and ul.enquirysource not between 12 and 15 and ul.enquirysource<>22
	and ul.ModifiedOn is null  then 1 else 0 end' + ' ) T Where ' + @FilterText + ' ) S ) AS A 
                    Where ' 
                 + CASE 
