' ,FilterText : '+ @FilterText + ' ,srno : '+ @srno + ' ,enno : '+ @enno;                                        

declare @TimeZoneName nvarchar(255) = ( select TimeZone from User_Detail(nolock) where User_ID = @Userid)

       exec Usp_createProductMasterTable @ParentID      

if(@ParentID = @Userid)
begin
	set @Userid = 0
end


