	--declare @txtSearch NVARCHAR(MAX)=N'',@ParentID BIGINT=32222,@Userid INT=0,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ordstr nvarchar(Max)='',@notfollowedup int=0  -- AC      
