CREATE   PROCEDURE [dbo].[Usp_ViewUserLeadDetails2_New_withnofollowup_Process]    
(                                      
 @txtSearch NVARCHAR(max),                                      
 @ParentID BIGINT,                                      
 @Userid INT= 0,                                      
 @FilterText NVARCHAR(MAX) = '',                                      
 @srno NVARCHAR(100),                                      
 @enno NVARCHAR(100),    
 @ordstr nvarchar(Max)='' ,  
 @notfollowedup int=null                                     
)                                      
AS                                      
BEGIN                                      
--select @txtSearch=N'',@ParentID=29453,@Userid=0,@FilterText=N'(personName like ''avni'')',@srno=N'1',@enno=N'20'                                          
declare @Parameterlist nvarchar(max) , @LoggerID bigint                                      
set @Parameterlist = 'txtSearch : '+ @txtSearch + ' ,ParentID : '+ CONVERT(VARCHAR(100), @ParentID) + ' ,Userid : '+ CONVERT(VARCHAR(100), @Userid) +                           
' ,FilterText : '+ @FilterText + ' ,srno : '+ @srno + ' ,enno : '+ @enno;                                      
                                      
insert into kit19_executionlogger(ObjectName,Parameterlist,StartDatetime,EndDatetime,Remarks)                                      
values('Usp_ViewUserLeadDetails2_New',@Parameterlist,getdate(),'','')                                      
                                      
set @LoggerID = Scope_Identity();                                      
                                      
-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=38738,@Userid INT=0,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20', @LoggerID bigint=0            
-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=29453,@Userid INT=0,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20', @LoggerID bigint=0            
-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=335,@Userid INT=0,@FilterText NVARCHAR(MAX)=N' ( Products = ''cvx'' ) ',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20', @LoggerID bigint=0            
-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=37540,@Userid INT=0,@FilterText NVARCHAR(MAX)=N' ( AssignedTo = ''37556'' ) and  ( FollowupCreatedDate >= ''07/08/2021'' And FollowupCreatedDate <= ''07/09/2021'' ) ',@srno NVARCHAR(100)=N'1',@ennoNVARCHAR(100)=N'20', @LoggerID bigint=0            
-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=32222,@Userid INT=0,@FilterText NVARCHAR(MAX)=N' ( FollowupStatus = ''Call-Back'' ) and ( FollowupDate >= ''01/01/2021'' And FollowupDate <= ''07/09/2021'' ) and ( FollowupCreatedDate >= ''01/01/2021'' And FollowupCreatedDate <= ''07/09/2021'' ) and ( FollowupBy like  ''%abhi%'' ) ',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20', @LoggerID bigint=0            
-- declare @txtSearch NVARCHAR(MAX)=N'(fieldname=''IICS_Code'' and fieldvalue=''IICS/N21/6565'')',@ParentID BIGINT=38859,@Userid INT=0,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20', @LoggerID bigint=0,@ordstr nvarchar(Max)=''            
-- declare @txtSearch NVARCHAR(MAX)=N' ( fieldname=''test02'' and cast(fieldvalue as varchar(50)) like  ''%2%'' )  or  ( fieldname=''test03'' and cast(fieldvalue as varchar(50)) like  ''%3%'' ) ',@ParentID BIGINT=32222,@Userid INT=0,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'25', @LoggerID bigint=0,@ordstr nvarchar(Max)='LeadNo desc'    
    
--declare @txtSearch NVARCHAR(MAX)=N'',@ParentID BIGINT=38750,@Userid INT=38759,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ordstr nvarchar(Max)='' -- AD    
--declare @txtSearch NVARCHAR(MAX)=N'',@ParentID BIGINT=38750,@Userid INT=38759,@FilterText NVARCHAR(MAX)=N' ( FollowupStatus = ''Call-Back'' )',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ordstr nvarchar(Max)=''  -- BD    
--declare @txtSearch NVARCHAR(MAX)=N'',@ParentID BIGINT=32222,@Userid INT=0,@FilterText NVARCHAR(MAX)=N' ( FollowupStatus = ''Call-Back'' ) and ( FollowupDate >= ''01/01/2021'' And FollowupDate <= ''07/09/2021'' ) and ( FollowupCreatedDate >= ''01/01/2021'' And FollowupCreatedDate <= ''07/09/2021'' ) and ( FollowupBy like  ''%abhi%'' ) ',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ordstr nvarchar(Max)='' -- BC    
--declare @txtSearch NVARCHAR(MAX)=N'',@ParentID BIGINT=32222,@Userid INT=0,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ordstr nvarchar(Max)=''  -- AC    
                                        
--If (CHARINDEX('FollowupCreatedDate',@FilterText) > 0 or CHARINDEX('FollowupBy',@FilterText) > 0)                                      
--Begin            
-- print 'Usp_ViewUserLeadDetails2_Followup_New'                                      
--  --Exec Usp_ViewUserLeadDetails2_Followup @txtSearch,@ParentID,@Userid,@FilterText,@srno,@enno                                      
--  Exec Usp_ViewUserLeadDetails2_Followup_New @txtSearch,@ParentID,@Userid,@FilterText,@srno,@enno                                      
--End                                      
--Else            
Begin            
 --print 'Usp_ViewUserLeadDetails2_New'                                      
                                      
IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;    
IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL BEGIN DROP TABLE #temp2; END;    
                                      
 Declare @NoCustomFields bigint, @offset int=20, @filterCnt int=0    
 DECLARE @Pivot_Column NVARCHAR(MAX);                                      
 DECLARE @Query NVARCHAR(MAX)= '', @Query1 NVARCHAR(MAX)= '',@Query2 nvarchar(max)                                    
             
 declare @maxScore numeric(18,2)=isnull((select (max(currentscore)*100)/99 from lead_score_history(nolock)e where parentid=@ParentID),0)            
 declare @hot int,@warm int,@cold int            
            
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=@ParentID                  
 if @hot is null                  
 begin                  
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=0                  
 end                  
            
 /*Select Pivot Column*/                                      
 SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])                                      
 FROM                                      
 (                                      
 SELECT DISTINCT [fieldname] FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1                                      
 ) AS Tab;                        
                                      
 set @NoCustomFields = (SELECT count(DISTINCT [fieldname]) FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1)                                      
 DECLARE @Rcnt VARCHAR(100);                                      
    
If(@ordstr = '')    
Begin    
 set @ordstr = ' CurrentScore desc, case when cast(followupdate as date) = cast(getdate() as date) then 0    
     when followupdate < getdate()  then 1    
     when followupdate > getdate() then 2    
     when followupdate is null then 3    
      end,followupdate '    
End                                     
            
IF(@txtSearch = '')            
BEGIN            
 SET @txtSearch = N' (1=1) ';    
 Set @offset=0    
END;    
    
IF(@FilterText = '')    
BEGIN    
 SET @FilterText = N' (1=1) ';            
END;            
            
 IF(@FilterText = ' (1=1) ' and @txtSearch = ' (1=1) ')    
BEGIN    
 print 'Branch A'    
  SET @Query+=CAST(N'SELECT A.ID,A.LeadNo,A.PersonName,A.CompanyName,A.MobileNo,A.EmailID,A.City,A.State,A.Country,A.CountryCode,A.PinCode, A.ResidentialAddress, A.OfficeAddress, isnull(A.SourceName,''Unknown'') SourceName, A.MediumName,A.CampaignName,A.InitialRemarks, A.ParentID, A.FollowupBy,            
 dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ', A.FollowupDate) AS FollowupDate,             
 dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ', A.FollowupCreatedDate) AS FollowupCreatedDate,            
 dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ', A.CreatedOn1) AS CreatedOn1New,  A.CreatedOn1,           
 A.AssignedTo, A.Remarks, CASE WHEN ISNULL(A.FollowupStatus, '''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus, '''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END +    
 CASE WHEN ISNULL(A.FollowupDate, '''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END +         
 CASE WHEN ISNULL(A.Products, '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END +             
CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END +         
CASE WHEN ISNULL(A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks, '''') + ''</p>'' ELSE '''' END AS FollowUp,A.MobileNo1, A.MobileNo2, A.MobileNo3, A.EmailID3, A.EmailID1, A.EmailID2, A.FollowupStatus, A.assigneduser, 
A.img_ext, isnull(A.Products, '''') as Products, A.CurrentScore, A.Profit_Loss, A.ThresholdColor, RowNumber1, rc1, A.User_Login           
 INTO #temp1    
 FROM    
 (    
 select ROW_NUMBER() OVER(ORDER BY S.ID DESC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1,*    
From (    
select *    
From (    
 SELECT UL.ID, UL.LeadNo, UL.PersonName, UL.img_ext, UL.CompanyName, UL.CreatedOn AS CreatedOn1,    
 CASE WHEN ISNULL(UL.CountryCode, '''') <> '''' and ISNULL(UL.MobileNo, '''') <> ''''  THEN ISNULL(UL.Countrycode, '''')    
+ '' '' + ISNULL(UL.MobileNo, '''')  ELSE '''' END +  CASE WHEN ISNULL(UL.Mobileno1, '''') <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid, '''') <> '''' THEN UL.Emailid ELSE '''' END +     
 CASE WHEN ISNULL(UL.EmailID1, '''') <> '''' THEN '', '' ELSE '''' END +     
 CASE WHEN ISNULL(UL.EmailID2, '''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name 
  
AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, CONVERT(VARCHAR(10), UL.CreatedOn, 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), UL.CreatedOn, 109), 15), 7, 7, '' '') AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy, UD2.User_Login as FollowupBy, UL.MobileNo AS MobileNo3, UL.MobileNo1, UL.MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, ( SELECT STUFF( (SELECT N'', '' + ss.Name FROM ProductMaster(nolock) AS ss INNER JOIN dbo.fn_Split(ul.Products, ''#'') AS fs  ON ss.ProductID = fs.value FOR XML PATH(''''), TYPE).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''') ) AS Products, UD.User_Login AS assigneduser, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int) ,ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' 
+ cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int)>' + cast(@warm as nvarchar(max)) + ' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max))+',0.00))*99,0) as int) between ' + cast(@cold as nvarchar(max)) + '
  
 and ' + cast(@warm as nvarchar(max)) + ' then ''Warm'' else ''Cold'' end , UD1.User_Login  ' as nvarchar(max))                   
 select @Query +=cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)    
 ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f    
 left join lead_score_history_latest(nolock) LS     
ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK)    
ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)    
ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)    
ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)    
ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK)
ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK)    
ON UL.FollowUpStatus = FUS.id    
WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo = ' +            
 CASE WHEN @Userid = 0 THEN N'UL.AssignedTo' ELSE CAST(@Userid AS NVARCHAR(MAX)) END + '  
 and 1= case when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''0'' then 1 when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''1''   
 and abs(datediff(mi,ul.createdon,ul.followupdate))<=2  
and ul.enquirysource not between 12 and 15 and ul.enquirysource<>22    
and ul.ModifiedOn is null  then 1 else 0 end'  
 + '  
 ) T     
 ) S     
 ) AS A Where A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno+@offset) AS NVARCHAR(MAX));      
    
END    
ELSE    
BEGIN    
 print 'Branch B'    
    
 SET @Query+=CAST(N'SELECT A.ID,A.LeadNo,A.PersonName,A.CompanyName,A.MobileNo,A.EmailID,A.City,A.State,A.Country,A.CountryCode,A.PinCode,A.ResidentialAddress,A.OfficeAddress,isnull(A.SourceName,''Unknown'') SourceName,A.MediumName,A.CampaignName,A.InitialRemarks,A.ParentID,A.FollowupBy,dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',A.FollowupDate) AS FollowupDate,dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',A.FollowupCreatedDate) AS FollowupCreatedDate,dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',A.CreatedOn1) AS CreatedOn1New,A.CreatedOn1,A.AssignedTo,A.Remarks,CASE WHEN ISNULL(A.FollowupStatus,'''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus,'''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END +    
 CASE WHEN ISNULL(A.FollowupDate,'''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products,'''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + 
  
CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL
  
(A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks,'''') + ''</p>'' ELSE '''' END AS FollowUp,A.MobileNo1,A.MobileNo2,A.MobileNo3,A.EmailID3,A.EmailID1,A.EmailID2,A.FollowupStatus,A.assigneduser,A.img_ext, isnull(A.Products, '''') as Products, A.CurrentScore,A.Profit_Loss,A.ThresholdColor,RowNumber1,rc1,A.User_Login    
 INTO #temp1    
 FROM    
 (    
 select ROW_NUMBER() OVER(ORDER BY S.ID DESC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1,*    
From (    
select *    
From (    
 SELECT UL.ID,UL.LeadNo,UL.PersonName,UL.img_ext,UL.CompanyName,UL.CreatedOn AS CreatedOn1,    
 CASE WHEN ISNULL(UL.CountryCode,'''') <> '''' and ISNULL(UL.MobileNo,'''') <> ''''  THEN ISNULL(UL.Countrycode,'''')    
+ '' '' + ISNULL(UL.MobileNo,'''')  ELSE '''' END +  CASE WHEN ISNULL(UL.Mobileno1,'''') <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid,'''') <> '''' THEN UL.Emailid ELSE '''' END + CASE WHEN ISNULL(UL.EmailID1,'''') <> ''''
  
 THEN '', '' ELSE '''' END +     
 CASE WHEN ISNULL(UL.EmailID2,'''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, CONVERT(VARCHAR(10), UL.CreatedOn, 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), UL.CreatedOn, 109), 15), 7, 7, '' '') AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy, UD2.User_Login as FollowupBy, UL.MobileNo AS MobileNo3, UL.MobileNo1, UL.MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, ( SELECT STUFF( (SELECT N'', '' + ss.Name FROM ProductMaster(nolock) AS ss INNER JOIN dbo.fn_Split(ul.Products, ''#'') AS fs  ON ss.ProductID = fs.value FOR XML PATH(''''), TYPE).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''') ) AS Products, UD.User_Login AS assigneduser, 
 Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int) ,ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' +
 cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int)>' + cast(@warm as nvarchar(max)) + ' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max))+',0.00))*99,0) as int) between ' + cast(@cold as nvarchar(max)) + ' 
and ' + cast(@warm as nvarchar(max)) + ' then ''Warm'' else ''Cold'' end , UD1.User_Login ' as nvarchar(max))                           
 select @Query +=cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)    
 ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f    
 left join lead_score_history_latest(nolock) LS     
ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK)    
ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)    
ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)    
ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)    
ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK)
ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK)    
ON UL.FollowUpStatus = FUS.id    
WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo = ' +            
 CASE WHEN @Userid = 0 THEN N'UL.AssignedTo' ELSE CAST(@Userid AS NVARCHAR(MAX)) END + '  
 and 1= case when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''0'' then 1 when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''1''   
 and abs(datediff(mi,ul.createdon,ul.followupdate))<=2  
and ul.enquirysource not between 12 and 15 and ul.enquirysource<>22    
and ul.ModifiedOn is null  then 1 else 0 end'  
 + '    
 ) T Where ' + @FilterText + '    
 ) S    
 ) AS A Where ' + case when @txtSearch = ' (1=1) ' then ' A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) else ' (1=1) ' end AS NVARCHAR(MAX));      
 --) AS A ' AS NVARCHAR(MAX));      
                                      
  --print @Query                 
End    
                                    
 IF(@Pivot_Column IS NOT NULL)    
 BEGIN    
 print 'Branch C'    
 --IF(@FilterText = ' (1=1) ' and @txtSearch = ' (1=1) ')-- From Branch A    
 IF(@txtSearch = ' (1=1) ')-- From Branch A    
 Begin    
 print 'Branch CA'    
  SELECT @Query += CAST(N'; Select * from ( Select *     
   From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login as User_Login, FollowupDate,
  
 FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, Img_Ext, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column
 +     
   N', CurrentScore, Profit_Loss, ThresholdColor, RowNumber1, rc1    
   FROM            
   (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy, FollowupDate, FollowupCreatedDate
  
,   CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, img_ext, Products, [fieldname] , fieldvalue, CurrentScore, Profit_Loss,ThresholdColor, RowNumber1, rc1 ,User_Login   
   FROM (select L.ID,  L.LeadNo, L.PersonName, L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.FollowupBy, L.FollowupDate, L.FollowupCreatedDate, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,  L.assigneduser, L.Img_Ext, L.Products, y.fieldname, x.fieldvalue, L.CurrentScore, L.Profit_Loss, L.ThresholdColor, L.RowNumber1, L.rc1,L.User_Login    
   From #temp1 L left join customfieldLeadvalue(nolock) x    
   ON L.ID = x.LeadID left join customfields(nolock) y    
   ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1    
   )q )Tab1    
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2) T1     
  Where ' + @txtSearch + '     
  ) T2     
  Where T2.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno)  + N' ORDER BY ' + @ordstr     
  /*N' ORDER BY CurrentScore desc,    
   case when cast(followupdate as date) = cast(getdate() as date) then 0    
     when followupdate < getdate()  then 1    
     when followupdate > getdate() then 2    
     when followupdate is null then 3    
      end,followupdate  '*/ AS NVARCHAR(MAX));    
 End    
 Else-- From Branch B    
 Begin    
  print 'Branch CB'    
    
  Select @filterCnt=count(*) From dbo.fn_Split(@txtSearch, ' ) ')    
      
  SELECT @Query += CAST(N'; select x.LeadID    
  into #Temp2    
  from customfieldLeadvalue(nolock) x inner join customfields(nolock) y    
  ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1    
  Where ' + @txtSearch + N'    
  group by x.LeadID    
  having count(*) >= ' + Cast(@filterCnt as NVARCHAR(MAX)) AS NVARCHAR(MAX));    
    
  SELECT @Query += CAST(N'; Select * from ( Select ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], *     
   From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login as User_Login, FollowupDate,
  
 FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, Img_Ext, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column
  
 +     
   N', CurrentScore, Profit_Loss, ThresholdColor    
   FROM            
   (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy, FollowupDate, FollowupCreatedDate
  
,           
   CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, img_ext, Products, [fieldname] , fieldvalue, CurrentScore, Profit_Loss,ThresholdColor,User_Login      
   FROM (select L.ID, L.LeadNo, L.PersonName, L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.FollowupBy, L.FollowupDate, L.FollowupCreatedDate, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,  L.assigneduser, L.Img_Ext, L.Products, y.fieldname, x.fieldvalue, L.CurrentScore, L.Profit_Loss, L.ThresholdColor,L.User_Login    
   From #Temp2 A inner join #temp1 L     
   ON A.LeadId = L.ID left join customfieldLeadvalue(nolock) x    
   ON L.ID = x.LeadID left join customfields(nolock) y    
   ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1    
   )q )Tab1    
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2) T1     
  ) T2     
  Where T2.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) + N' ORDER BY ' + @ordstr    
  /*N' ORDER BY CurrentScore desc,    
   case when cast(followupdate as date) = cast(getdate() as date) then 0    
     when followupdate < getdate()  then 1    
     when followupdate > getdate() then 2    
     when followupdate is null then 3    
      end,followupdate  '*/ AS NVARCHAR(MAX));    
 End    
END    
ELSE    
BEGIN    
 print 'Branch D'    
    
  SET @Query += CAST(N';Select *, FollowupBy as User_Login    
  From #temp1    
  Where RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) + N' ORDER BY ' + @ordstr     
  /*N' ORDER BY CurrentScore desc,    
  case when cast(followupdate as date) = cast(getdate() as date) then 0    
  when followupdate < getdate() then 1    
  when followupdate > getdate() then 2    
  when followupdate is null then 3    
  end,followupdate '*/ AS NVARCHAR(MAX));    
END    
                                    
                                    
  print '@FinalQuery:- ' + cast(@Query as varchar(max))    
                                    
                                  
 EXEC sp_executesql @Query;                                      
                                      
 --update kit19_executionlogger                                      
 --set EndDatetime = getdate(),                                      
 --Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)                                      
 --where ID = @LoggerID                                      
                                      
 --update kit19_executionlogger                                      
 --set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)                                      
 --where ID = @LoggerID                                      
                                      
 IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;    
 IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL BEGIN DROP TABLE #temp2; END;    
End                                      
                                      
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserLeadDetails2_New_withnofollowup_Replication]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_ViewUserLeadDetails2_New_withnofollowup_Replication] 
 (
	@txtSearch NVARCHAR(max)
	,@ParentID BIGINT
	,@Userid INT = 0
	,@FilterText NVARCHAR(MAX) = ''
	,@srno NVARCHAR(100)
	,@enno NVARCHAR(100)
	,@ordstr NVARCHAR(Max) = ''
	,@notfollowedup INT = NULL
)
AS
BEGIN

 --  declare  @txtSearch NVARCHAR(max) = N' (1=1) '
	--,@ParentID BIGINT = 32222
	--,@Userid INT = 32222
	----,@FilterText NVARCHAR(MAX) = N' (personname like ''%a%'' ) '
	--,@FilterText NVARCHAR(MAX) = N'( ( PersonName  like  ''%santosh%'' ) )'
	--,@srno NVARCHAR(100) = N'1'
	--,@enno NVARCHAR(100) = N'200'
	--,@ordstr NVARCHAR(Max) = N''
	--,@notfollowedup INT = 0

	--select @txtSearch=N'',@ParentID=29453,@Userid=0,@FilterText=N'(personName like ''avni'')',@srno=N'1',@enno=N'20' 
	--declare @Parameterlist nvarchar(max) , @LoggerID bigint 
	--set @Parameterlist = 'txtSearch : '+ @txtSearch + ' ,ParentID : '+ CONVERT(VARCHAR(100), @ParentID) + ' ,Userid : '+ CONVERT(VARCHAR(100), @Userid) + ' ,FilterText : '+ @FilterText + ' ,srno : '+ @srno + ' ,enno : '+ @enno; 
	--insert into kit19_executionlogger(ObjectName,Parameterlist,StartDatetime,EndDatetime,Remarks)
	--values('Usp_ViewUserLeadDetails2_New',@Parameterlist,getdate(),'','')                                        
	--set @LoggerID = Scope_Identity(); 
	-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=34594,@Userid INT=34594,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20', @LoggerID bigint=0,@ordstr nvarchar(Max)='', @notfollowedup int=0
	-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=29453,@Userid INT=29453,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20', @LoggerID bigint=0,@ordstr nvarchar(Max)='', @notfollowedup int=0
	-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=335,@Userid INT=0,@FilterText NVARCHAR(MAX)=N' ( Products = ''cvx'' ) ',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20', @LoggerID bigint=0,@ordstr nvarchar(Max)='', @notfollowedup int=0
	-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=37540,@Userid INT=0,@FilterText NVARCHAR(MAX)=N' ( AssignedTo = ''37556'' ) and  ( FollowupCreatedDate >= ''07/08/2021'' And FollowupCreatedDate <= ''07/09/2021'' ) ',@srno NVARCHAR(100)=N'1',@ennoNVARCHAR(100)=N'20', @LoggerID bigint=0,@ordstr nvarchar(Max)='', @notfollowedup int=0
	-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=32222,@Userid INT=0,@FilterText NVARCHAR(MAX)=N' ( FollowupStatus = ''Call-Back'' ) and ( FollowupDate >= ''01/01/2021'' And FollowupDate <= ''07/09/2021'' ) and ( FollowupCreatedDate >= ''01/01/2021'' And FollowupCreatedDate <= ''07/09/2021'' ) and ( FollowupBy like  ''%abhi%'' ) ',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20', @LoggerID bigint=0,@ordstr nvarchar(Max)='', @notfollowedup int=0
	-- declare @txtSearch NVARCHAR(MAX)=N'(fieldname=''IICS_Code'' and fieldvalue=''IICS/N21/6565'')',@ParentID BIGINT=38859,@Userid INT=0,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20', @LoggerID bigint=0,@ordstr nvarchar(Max)='', @notfollowedup int=0
	-- declare @txtSearch NVARCHAR(MAX)=N' ( fieldname=''test02'' and cast(fieldvalue as varchar(50)) like  ''%2%'' )  or  ( fieldname=''test03'' and cast(fieldvalue as varchar(50)) like  ''%3%'' ) ',@ParentID BIGINT=32222,@Userid INT=0,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'25', @LoggerID bigint=0,@ordstr nvarchar(Max)='LeadNo desc', @notfollowedup int=0
	--declare @txtSearch NVARCHAR(MAX)=N'',@ParentID BIGINT=38750,@Userid INT=38759,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ordstr nvarchar(Max)='',@notfollowedup int=0 -- AD
	--declare @txtSearch NVARCHAR(MAX)=N'',@ParentID BIGINT=38750,@Userid INT=38759,@FilterText NVARCHAR(MAX)=N' ( FollowupStatus = ''Call-Back'' )',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ordstr nvarchar(Max)='', @notfollowedup int=0  -- BD      
	--declare @txtSearch NVARCHAR(MAX)=N'',@ParentID BIGINT=32222,@Userid INT=0,@FilterText NVARCHAR(MAX)=N' ( FollowupStatus = ''Call-Back'' ) and ( FollowupDate >= ''01-Jan-2021'' And FollowupDate <= ''07-Dec-2022'' ) and ( FollowupCreatedDate >= ''01-Jan-2021'' And FollowupCreatedDate <= ''07-Dec-2022'' ) and ( FollowupBy like  ''%abhi%'' ) ',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ordstr nvarchar(Max)='', @notfollowedup int=0 -- BC      
	--declare @txtSearch NVARCHAR(MAX)=N'',@ParentID BIGINT=39699,@Userid INT=39699,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ordstr nvarchar(Max)='',@notfollowedup int=0  -- AC      
	--declare @txtSearch NVARCHAR(MAX)=N'',@ParentID BIGINT=39680,@Userid INT=39680,@FilterText NVARCHAR(MAX)=N' ( CreatedOn1 >= ''07-May-2022 00:00:00'' And CreatedOn1 <= ''08-May-2022 00:00:00'' )  and  ( User_Login like  ''%user1%'' ) ',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ordstr nvarchar(Max)='',@notfollowedup int=0  -- BCA      

	IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL
	BEGIN
		DROP TABLE #temp1;
	END;

	IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL
	BEGIN
		DROP TABLE #temp2;
	END;

	/* Added By DBA 
	Date : 2024-12-14
	*/
	DECLARE @is_default_params INT = 0;

	IF @FilterText= N'' AND @ordstr = N'' AND @notfollowedup=0
		BEGIN
			SET @is_default_params = 1;
		END

	--IF OBJECT_ID('tempdb.dbo.#TableData2', 'U') IS NOT NULL BEGIN DROP TABLE #TableData2; END;
	
	DECLARE @Str NVARCHAR(200) = @ordstr;--' personname desc '
	DECLARE @ColumnName NVARCHAR(200) = ''
	DECLARE @StrPredefinedOrderBy NVARCHAR(max) = ''
	DECLARE @StrCustomOrderBy NVARCHAR(max) = ''
	DECLARE @actUserID BIGINT = @Userid

	IF (rtrim(ltrim(@Str)) <> '')
	BEGIN
		SET @Str = ltrim(RTRIM(@Str))

		--select @Str
		SELECT TOP 1 @ColumnName = value
		FROM string_split(@Str, ' ')

		--select @ColumnName 
		IF (EXISTS(SELECT 1 FROM INFORMATION_SCHEMA.COLUMNS WHERE table_name = 'UserLeads' AND column_name = rtrim(ltrim(@ColumnName))))
		BEGIN
			--set @StrPredefinedOrderBy = N' order by ' +  @Str;
			SET @StrPredefinedOrderBy = N' ' + @Str + ' , ';
			SET @StrCustomOrderBy = '';
		END
		ELSE
		BEGIN
			DECLARE @FullDataType NVARCHAR(200) = 'nvarchar(max)'

			SELECT TOP 1 @FullDataType = CASE 
					WHEN ISNULL(datatype, 'v') = 'd'
						THEN 'date'
					WHEN ISNULL(datatype, 'v') = 'f'
						THEN 'bigint'
					WHEN ISNULL(datatype, 'v') = 'v'
						THEN 'nvarchar(max)'
					ELSE 'nvarchar(max)'
					END
			FROM customfields WITH (NOLOCK)
			WHERE ParentID = @Parentid
				AND fieldname = rtrim(ltrim(@ColumnName))

			DECLARE @CustomStrExp NVARCHAR(200) = '';

			IF (EXISTS (SELECT value FROM string_split(@Str, ' ') WHERE rtrim(ltrim(value)) = 'asc'))
			BEGIN
				SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  asc '
			END
			ELSE
			BEGIN
				SET @CustomStrExp = N' ' + 'CAST(' + @ColumnName + ' as  ' + @FullDataType + ')' + '  desc '
			END

			SET @StrPredefinedOrderBy = ''
			--set @StrCustomOrderBy = N' order by ' +  @Str;  
			SET @StrCustomOrderBy = N' ' + @CustomStrExp + ' , ';
		END
				--select @StrPredefinedOrderBy
				--select @StrCustomOrderBy
	END

	DECLARE @IsAdmin BIT = 0
	DECLARE @TimeZoneName NVARCHAR(255) = isnull((SELECT TimeZone FROM User_Detail(NOLOCK) WHERE User_ID = @Userid), 'India Standard Time')
	DECLARE @UserIDTeam BIGINT = @Userid;
	DECLARE @tbluser TABLE (
		User_ID BIGINT
		,Name VARCHAR(100)
		,IMAGE NVARCHAR(200)
		)

	--exec Usp_createProductMasterTable @ParentID

	SELECT @IsAdmin = IsAdmin
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @Userid

    DECLARE @ScopeCode VARCHAR(10) = ''
  --  select @ScopeCode = ScopeCode    
  --   from ufn_GetUserRoleScope(@UserId) 

	 --if(@ScopeCode = 'GLOBAL')
	 --  begin
	 --      set @IsAdmin = 1 
	 --  end


	IF (@IsAdmin = 1 or @Userid=@ParentId)
	BEGIN
		SET @Userid = 0;

		INSERT INTO @tbluser
		EXEC Use_GetUserDetails @ParentId
	END
	ELSE
	BEGIN
		INSERT INTO @tbluser
		EXEC Use_GetUserDetails @UserId
	END

	DECLARE @TeamCode VARCHAR(10) = ''
	--DECLARE @ScopeCode VARCHAR(10) = ''
	DECLARE @UserIdTeamLst VARCHAR(4000) = ''
	DECLARE @HierarchyJSON VARCHAR(Max) = ''

	SELECT @UserIdTeamLst = isnull(STRING_AGG(cast(User_ID as nvarchar(max)), ','), '')
	FROM @tbluser

	PRINT '@UserIdTeamLst: ' + @UserIdTeamLst

		--print 'Usp_ViewUserLeadDetails2_New'                                        
	DECLARE @NoCustomFields BIGINT,@offset INT = 20,@filterCnt INT = 0
	DECLARE @Pivot_Column NVARCHAR(MAX);
	DECLARE @Query NVARCHAR(MAX) = '',@Query1 NVARCHAR(MAX) = '',@Query2 NVARCHAR(max) = ''
	DECLARE @maxScore NUMERIC(18, 2) = isnull((
				SELECT (max(currentscore) * 100) / 99
				FROM lead_score_history(NOLOCK) e
				WHERE parentid = @ParentID
				), 0)
	DECLARE @hot INT,@warm INT,@cold INT

	SELECT @hot = hot,@warm = warm,@cold = cold
	FROM lead_cateogy_thresholds(NOLOCK)
	WHERE parentid = @ParentID

	IF @hot IS NULL
	BEGIN
		SELECT @hot = hot,@warm = warm,@cold = cold
		FROM lead_cateogy_thresholds(NOLOCK)
		WHERE parentid = 0
	END

	/*Select Pivot Column*/
	SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])
	FROM (
		SELECT DISTINCT [fieldname]
		FROM customfields(NOLOCK)
		WHERE [ParentID] = @ParentID AND [isActive] = 1
		) AS Tab;

	SET @NoCustomFields = (
			SELECT count(DISTINCT [fieldname])
			FROM customfields(NOLOCK)
			WHERE [ParentID] = @ParentID AND [isActive] = 1
			)

	DECLARE @Rcnt VARCHAR(100);

	IF (@ordstr = '')
	BEGIN
		--SET @ordstr = ' CurrentScore desc, case when cast(followupdate as date) = cast(getdate() as date) then 0      
   --  when followupdate < getdate()  then 1      
   --  when followupdate > getdate() then 2      
   --  when followupdate is null then 3      
   --   end,followupdate '
		-- SET @ordstr = ' CurrentScore desc, CreatedOn1 DESC '
		SET @ordstr = ' CreatedOn1New DESC '
	END

	IF (@txtSearch = '')
	BEGIN
		SET @txtSearch = N' (1=1) ';
		SET @offset = 0
	END;

	IF (@FilterText = '')
	BEGIN
		SET @FilterText = N' (1=1) ';
	END;

	/*Added By DBA*/
	-- 2024-12-13

	DROP TABLE IF EXISTS #tag
	CREATE TABLE #tag
	(
	 Tags NVARCHAR(MAX)
	,EntityID BIGINT PRIMARY KEY

	--,CONSTRAINT PK_#tag PRIMARY KEY CLUSTERED 
	--	(
	--		EntityID
	--	)
	)
	DECLARE @SQL NVARCHAR(MAX) = N''
	SELECT @SQL = N'INSERT INTO #tag select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''lead'' and tm.ParentID = ' + 
					Convert(VARCHAR(100), @ParentID) + N' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID';
	EXEC sp_executeSQL @SQL;

	DECLARE @total_count AS INT = 0;

	SELECT @SQL = N'SELECT @total_count = COUNT(*)
					FROM UserLeads AS UL (NOLOCK)
					WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' + CASE 
						WHEN @Userid = 0
							THEN N' = UL.AssignedTo '
						WHEN @Userid > 0 /*and isnull(@TeamCode,'') != ''*/
							THEN N' in (' + isnull(@UserIdTeamLst, '') + ')'
						ELSE N' = ' + CAST(@Userid AS NVARCHAR(MAX))
						END + N'   
	and 1= case when isnull(' + cast(@notfollowedup AS NVARCHAR) + N',''0'')=''0'' then 1 when isnull(' + cast(@notfollowedup AS NVARCHAR) + N',''0'')=''1''     
	and abs(datediff(mi,ul.createdon,ul.followupdate))<=2    
	and ul.enquirysource not in (12,13,14,15,28,29) and ul.enquirysource<>22      
	and ul.ModifiedOn is null  then 1 else 0 end';

	EXEC sp_executesql @SQL, N'@total_count INT OUTPUT', @total_count = @total_count OUTPUT;
	
	/* End of addition */

	IF (@FilterText = ' (1=1) ' AND @txtSearch = ' (1=1) ')
	BEGIN
		PRINT 'Branch A'

			SET @Query += CAST(N'SELECT A.ID,A.LeadNo,A.PersonName,A.CompanyName,A.MobileNo,A.EmailID,A.City,A.State,A.Country,A.CountryCode,A.PinCode, A.ResidentialAddress, A.OfficeAddress, isnull(A.SourceName,''Unknown'') SourceName, A.MediumName,A.CampaignName,A.InitialRemarks, A.ParentID, A.FollowupBy,format(A.FollowupDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupDate, format(A.FollowupCreatedDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupCreatedDate, A.CreatedOn1 as CreatedOn1New, format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1 , A.AssignedTo, A.Remarks, CASE WHEN ISNULL(A.FollowupStatus, '''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus, '''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.FollowupDate, '''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products, '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks, '''') + ''</p>'' ELSE '''' END AS FollowUp,A.MobileNo1, A.MobileNo2, A.MobileNo3, A.EmailID3, A.EmailID1, A.EmailID2, A.FollowupStatus, A.assigneduser,A.assignedUserloginOnly ,A.img_ext, A.WhereAddress, A.Tags, isnull(A.Products, '''') as Products, A.CurrentScore, A.Profit_Loss, A.ThresholdColor, RowNumber1, rc1, A.User_Login, A.LastFollowupCreatedByName, format(A.LastFollowupedOn,''dd-MMM-yyyy HH:mm:ss'') as LastFollowupedOn, A.WhatsAppNoColName,A.CreatedBy, cast(A.ModifiedOn as datetime) as ModifiedOn, A.ModifiedBy,CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) as AmountPaid  INTO #temp1 FROM ( select ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + 
					N'   S.ID DESC) AS RowNumber1, ' + IIF(@is_default_params = 1, CAST(@total_count AS NVARCHAR(10)), N'count(*) OVER(ORDER BY S.ParentID) ') + N' AS rc1, * From (' + 
					N' select ' + IIF(@is_default_params = 1, N' TOP (' + CAST((CAST(@enno AS INT) + CAST(@offset AS INT)) * 10 AS NVARCHAR(MAX)) + N')', N'') + N' * From ( SELECT UL.ID, UL.LeadNo, UL.PersonName, UL.img_ext, UL.WhereAddress, isnull(tg.Tags, '''') Tags, UL.CompanyName, UL.CreatedOn AS CreatedOn1,  CASE WHEN ISNULL(UL.CountryCode, '''') <> '''' and trim(ISNULL(UL.MobileNo, '''')) <> ''''  THEN TRIM(ISNULL(UL.Countrycode, '''')) + '' '' + TRIM(ISNULL(UL.MobileNo, ''''))  ELSE '''' END +  CASE WHEN trim(ISNULL(UL.Mobileno1, '''')) <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid, '''') <> '''' THEN UL.Emailid ELSE '''' END +  CASE WHEN ISNULL(UL.EmailID1, '''') <> '''' THEN '', '' ELSE '''' END +  CASE WHEN ISNULL(UL.EmailID2, '''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, UL.CreatedOn AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy,ISNULL(UD2.User_Login,'''') as FollowupBy, trim(UL.MobileNo) AS MobileNo3, trim(UL.MobileNo1) as MobileNo1, trim(UL.MobileNo2) as MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, (  select isnull((select STRING_AGG(isnull(ProductName,''''),'', '') from openjson(ul.productsJson)
	               with(ProductName nvarchar(max) ''$.ProductName'' )
			       where isnull(ul.productsJson,'''') != '''') , '''') ) AS Products, UD.User_Login + '' ('' + Ud.FName +  '' '' + Ud.LName + '')'' AS assigneduser, UD.User_Login as assignedUserloginOnly , Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) , ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int)>' + cast(@warm AS NVARCHAR(max)) + N' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) between ' + cast(@cold AS NVARCHAR(max)) + N' and ' + cast(@warm AS NVARCHAR(max)) + N' then ''Warm'' else ''Cold'' end , UD1.User_Login , ISNULL(UD2.User_Login, '''') as LastFollowupCreatedByName, ul.LastFollowupCreatedOn as LastFollowupedOn, UL.WhatsAppNoColName  ' AS NVARCHAR(max))
					
	SELECT @Query += cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)
	 ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f
	 left join lead_score_history_latest(nolock) LS 
	ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK)
	ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)
	ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)
	ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)
	ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK)
	ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK)
	ON UL.FollowUpStatus = FUS.id 
	--left join LeadPipelineMapping_latest(nolock) as lpm
	--on UL.ID = lpm.LeadID 
	 LEFT JOIN #tag /*( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''lead'' and tm.ParentID = ' + 
					Convert(VARCHAR(100), @ParentID) + N' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID )*/ tg on tg.EntityID = UL.ID 
	WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' + CASE 
						WHEN @Userid = 0
							THEN N' = UL.AssignedTo '
						WHEN @Userid > 0 /*and isnull(@TeamCode,'') != ''*/
							THEN N' in (' + isnull(@UserIdTeamLst, '') + ')'
						ELSE N' = ' + CAST(@Userid AS NVARCHAR(MAX))
						END + N'   
	and 1= case when isnull(' + cast(@notfollowedup AS NVARCHAR) + N',''0'')=''0'' then 1 when isnull(' + cast(@notfollowedup AS NVARCHAR) + N',''0'')=''1''     
	and abs(datediff(mi,ul.createdon,ul.followupdate))<=2    
	and ul.enquirysource  not in (12,13,14,15,28,29) and ul.enquirysource<>22      
	and ul.ModifiedOn is null  then 1 else 0 end' + '    
	) T ' + IIF(@is_default_params = 1, N'ORDER BY ID DESC', N'') +
	N') S       
	) AS A ' --as nvarchar(max))
	+ ' Where A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno + @offset) AS NVARCHAR(MAX));
		
	END
	ELSE
	BEGIN
		PRINT 'Branch B'

		SET @Query += CAST(N'SELECT A.ID, A.LeadNo, A.PersonName, A.CompanyName, A.MobileNo, A.EmailID, A.City, A.State, A.Country, A.CountryCode, A.PinCode, A.ResidentialAddress, A.OfficeAddress,isnull(A.SourceName,''Unknown'') SourceName, A.MediumName, A.CampaignName, A.InitialRemarks, A.ParentID, A.FollowupBy, format(A.FollowupDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupDate,format(A.FollowupCreatedDate,''dd-MMM-yyyy HH:mm:ss'') as FollowupCreatedDate,A.CreatedOn1 as CreatedOn1New,format(A.CreatedOn1,''dd-MMM-yyyy HH:mm:ss'') as CreatedOn1, A.AssignedTo,A.Remarks,CASE WHEN ISNULL(A.FollowupStatus,'''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus,'''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.FollowupDate,'''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products,'''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL (A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks,'''') + ''</p>'' ELSE '''' END AS FollowUp, A.MobileNo1,A.MobileNo2,A.MobileNo3,A.EmailID3,A.EmailID1,A.EmailID2,A.FollowupStatus,A.assigneduser,A.assignedUserloginOnly,A.img_ext, A.WhereAddress, A.Tags, isnull(A.Products, '''') as Products, A.CurrentScore, A.Profit_Loss, A.ThresholdColor,RowNumber1,rc1 ,A.User_Login, A.LastFollowupCreatedByName, format(A.LastFollowupedOn,''dd-MMM-yyyy HH:mm:ss'') as LastFollowupedOn,A.WhatsAppNoColName, A.CreatedBy, cast(A.ModifiedOn as datetime) as ModifiedOn, A.ModifiedBy,CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) as AmountPaid INTO #temp1 FROM ( select ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N'   S.ID DESC) AS RowNumber1, ' 
		+ IIF(@is_default_params = 1, CAST(@total_count AS NVARCHAR(10)), N'count(*) OVER(ORDER BY S.ParentID) ') + N' AS rc1,* ' +
		N'From ( ' + 
		N'select ' + IIF(@is_default_params = 1, N' TOP (' + CAST((CAST(@enno AS INT) + CAST(@offset AS INT)) * 10 AS NVARCHAR(MAX)) + N')', N'') + N' * From ( SELECT UL.ID,UL.LeadNo,UL.PersonName,UL.img_ext,UL.CompanyName,UL.CreatedOn AS CreatedOn1, CASE WHEN ISNULL(UL.CountryCode,'''') <> '''' and trim(ISNULL(UL.MobileNo,'''')) <> ''''  THEN TRIM(ISNULL(UL.Countrycode,'''')) + '' '' + TRIM(ISNULL(UL.MobileNo,''''))  ELSE '''' END +  CASE WHEN trim(ISNULL(UL.Mobileno1,'''')) <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid,'''') <> '''' THEN UL.Emailid ELSE '''' END + CASE WHEN ISNULL(UL.EmailID1,'''') <> '''' THEN '', '' ELSE '''' END + CASE WHEN ISNULL(UL.EmailID2,'''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, UL.CreatedOn AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy, ISNULL(UD2.User_Login,'''') as FollowupBy, trim(UL.MobileNo) AS MobileNo3, trim(UL.MobileNo1) as MobileNo1, trim(UL.MobileNo2) as MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, UL.WhereAddress, isnull(tg.Tags, '''') Tags, ( select isnull((select STRING_AGG(isnull(ProductName,''''),'', '') from openjson(ul.productsjson) with(ProductName nvarchar(max) ''$.ProductName'' ) where isnull(ul.productsjson,'''') != '''') , '''')) AS Products,UD.User_Login + '' ('' + Ud.FName +  '' '' + Ud.LName + '')'' AS assigneduser, UD.User_Login as assignedUserloginOnly, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end,CurrentScore=cast(isnull((LS.currentscore/nullif('+ cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int), ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int)>' + cast(@warm AS NVARCHAR(max)) + N' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore AS NVARCHAR(max)) + N',0.00))*99,0) as int) between ' + cast(@cold AS NVARCHAR(max)) + N'  and ' + cast(@warm AS NVARCHAR(max)) + N' then ''Warm'' else ''Cold'' end, UD1.User_Login ' AS NVARCHAR(max)) + N', isnull(UD2.User_Login, '''') as LastFollowupCreatedByName, ul.LastFollowupCreatedOn as LastFollowupedOn, UL.WhatsAppNoColName  '

		SELECT @Query += cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)
	 ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f
	 left join lead_score_history_latest(nolock) LS ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK) ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK) ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK) ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK) ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK) ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK) ON UL.FollowUpStatus = FUS.id
	--left join LeadPipelineMapping_latest(nolock) as lpm
	--on UL.ID = lpm.LeadID
	 LEFT JOIN #tag /*( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''lead'' and tm.ParentID = ' + Convert(VARCHAR(100), @ParentID) + ' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID )*/ tg on tg.EntityID = UL.ID   
	WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' + CASE 
						WHEN @Userid = 0
							THEN N' = UL.AssignedTo '
						WHEN @Userid > 0 /*and isnull(@TeamCode,'') != ''*/
							THEN ' in (' + isnull(@UserIdTeamLst, '') + ')'
						ELSE ' = ' + CAST(@Userid AS NVARCHAR(MAX))
						END + ' and 1= case when isnull(' + cast(@notfollowedup AS NVARCHAR) + ',''0'')=''0'' then 1 when isnull(' + cast(@notfollowedup AS NVARCHAR) + ',''0'')=''1'' and abs(datediff(mi,ul.createdon,ul.followupdate))<=2
	and ul.enquirysource  not in (12,13,14,15,28,29) and ul.enquirysource<>22
	and ul.ModifiedOn is null  then 1 else 0 end' + ' ) T Where ' + @FilterText + + IIF(@is_default_params = 1, N'ORDER BY ID DESC', N'') + N' ) S ) AS A 
                    Where ' 
                 + CASE 
						WHEN @txtSearch = ' (1=1) '
							THEN ' A.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno)
						ELSE ' (1=1) '
						END 
						AS NVARCHAR(MAX));
				--) AS A ' AS NVARCHAR(MAX)); 
		END

		PRINT cast(@Query AS VARCHAR(max))

		IF (@Pivot_Column IS NOT NULL)
		BEGIN
			PRINT 'Branch C'

			--IF(@FilterText = ' (1=1) ' and @txtSearch = ' (1=1) ')-- From Branch A 
			IF (@txtSearch = ' (1=1) ') -- From Branch A 
			BEGIN
				PRINT 'Branch CA'

				DECLARE @caQuery NVARCHAR(max) = CAST(N'; Select * from ( Select *       
   From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser,assignedUserloginOnly, Img_Ext, WhereAddress, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column + N', CurrentScore, Profit_Loss, ThresholdColor, ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + '  [ID] DESC)  ' + ' AS [RowNumber1], rc1, LastFollowupCreatedByName, LastFollowupedOn, WhatsAppNoColName,CreatedBy, ModifiedOn, ModifiedBy, AmountPaid FROM
   (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy, FollowupDate, FollowupCreatedDate, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser,assignedUserloginOnly, img_ext, WhereAddress, Products, [fieldname] , fieldvalue, CurrentScore, Profit_Loss,ThresholdColor, RowNumber1, rc1 ,User_Login,LastFollowupCreatedByName, LastFollowupedOn, WhatsAppNoColName,CreatedBy, ModifiedOn, ModifiedBy, AmountPaid FROM (select L.ID,  L.LeadNo, L.PersonName, L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.FollowupBy, L.FollowupDate, L.FollowupCreatedDate, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,  L.assigneduser,L.assignedUserloginOnly, L.Img_Ext, L.WhereAddress, L.Products, y.fieldname, x.fieldvalue, L.CurrentScore, L.Profit_Loss, L.ThresholdColor, L.RowNumber1, L.rc1, L.User_Login,L.LastFollowupCreatedByName, L.LastFollowupedOn, L.WhatsAppNoColName, L.CreatedBy, L.ModifiedOn, L.ModifiedBy, L.AmountPaid  From #temp1 L left join customfieldLeadvalue(nolock) x ON L.ID = x.LeadID left join customfields(nolock) y ON x.fieldID=y.field_ID AND y.[ParentID] = ' 
						+ CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 )q )Tab1
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @txtSearch + ' ) T1
   ) T2 ' 
        --'Where T2.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno) 
      + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));

				PRINT cast(@caQuery as varchar(max))

				SELECT @Query = @Query + @caQuery
			END
			ELSE -- From Branch B      
			BEGIN
				PRINT 'Branch CB'

				SELECT @filterCnt = count(*)
				FROM dbo.fn_Split(@txtSearch, ' ) ')
				select @filterCnt = 1

				SELECT @Query1 += CAST(N'; select * into #Temp2 From (select [x].LeadID, [y].[fieldname], [x].[fieldvalue] from customfieldLeadvalue(nolock) x inner join customfields(nolock) y ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) T1 PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2 Where ' + @txtSearch AS NVARCHAR(MAX));

				SELECT @Query1 += CAST(N'; Select * from ( Select ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + '  [ID] DESC)  ' + ' AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], * From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser,assignedUserloginOnly, Img_Ext, WhereAddress, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column + 
						N', CurrentScore, Profit_Loss, ThresholdColor, LastFollowupCreatedByName, LastFollowupedOn, WhatsAppNoColName, CreatedBy, ModifiedOn, ModifiedBy, AmountPaid 
				   From #Temp2 A inner join #temp1 L       
					ON A.LeadId = L.ID  ) T1       
				  ) T2  
				    Where  T2.RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno) 
				   + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX)) ;


				PRINT cast(@Query1 as varchar(max))

				SELECT @Query = @Query + @Query1
			END
		END
		ELSE
		BEGIN
			PRINT 'Branch D'

		SET @Query2 += CAST(N';Select *, FollowupBy as User_Login      
        From #temp1 '      
           --Where RowNumber1 BETWEEN ' + CONVERT(NVARCHAR(max), @srno) + N' AND ' + CONVERT(NVARCHAR(max), @enno) 
		  + N' ORDER BY ' + @ordstr AS NVARCHAR(MAX));

			PRINT cast(@Query2 as varchar(max))

			SELECT @Query = @Query + @Query2
		END

		--print '@FinalQuery:- ' + cast(@Query as varchar(max))      
		EXEC sp_executesql @Query;

		--update kit19_executionlogger                                        
		--set EndDatetime = getdate(),                                        
		--Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)                                        
		--where ID = @LoggerID                                        
		--update kit19_executionlogger                                        
		--set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)                                        
		--where ID = @LoggerID                                        
		IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL
		BEGIN
			DROP TABLE #temp1;
		END;

		IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL
		BEGIN
			DROP TABLE #temp2;
		END;

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @actUserID
		,@Activity_type = 'View_Lead'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'UserLeads'
END



