	DECLARE @SQL NVARCHAR(MAX) = N''
	SELECT @SQL = N'INSERT INTO #tag select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''lead'' and tm.ParentID = ' + 
					Convert(VARCHAR(100), @ParentID) + N' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID';


	EXEC sp_executeSQL @SQL;

	--select * from #tag where EntityID=19950763


	DECLARE @total_count AS INT = 0;

	SELECT @SQL = N'SELECT @total_count = COUNT(*)
					FROM UserLeads AS UL (NOLOCK)
					WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' + CASE 
						WHEN @Userid = 0
							THEN N' = UL.AssignedTo '
						WHEN @Userid > 0 /*and isnull(@TeamCode,'') != ''*/
							THEN N' in (' + isnull(@UserIdTeamLst, '') + ')'
						ELSE N' = ' + CAST(@Userid AS NVARCHAR(MAX))
						END + N'   
	and 1= case when isnull(' + cast(@notfollowedup AS NVARCHAR) + N',''0'')=''0'' then 1 when isnull(' + cast(@notfollowedup AS NVARCHAR) + N',''0'')=''1''     
	and abs(datediff(mi,ul.createdon,ul.followupdate))<=2    
	and ul.enquirysource not in (12,13,14,15,28,29) and ul.enquirysource<>22      
	and ul.ModifiedOn is null  then 1 else 0 end';

	EXEC sp_executesql @SQL, N'@total_count INT OUTPUT', @total_count = @total_count OUTPUT;
	
