 exec Usp_ViewUserLeadDetails2_New_withnofollowup_CustomFieldsNew @txtSearch=N' (fieldname = ''Course_01_Name'' and cast(fieldvalue as varchar(100)) like  ''%rpsc%'' )  
       and  (fieldname = ''Course_01_Expire_Date'' and isdate(cast(''23-Jul-2023 12:00:00 AM'' as nvarchar(100)))=1 and cast(''23-Jul-2023 12:00:00 AM'' as date) between ''01/20/2021'' and ''09/21/2024'' ) ',@ParentID=40834,@Userid=40834,@FilterText=N'',@srno=N'1',@enno=N'20',@ordstr=N'',@notfollowedup=0
