me(cast(A.ModifiedOn as datetime), '''+cast(@TimeZoneName as nvarchar(255)) +''', 0) as ModifiedOn, A.ModifiedBy INTO #temp1 FROM ( select ROW_NUMBER() OVER(ORDER BY '+ @StrPredefinedOrderBy + '   S.ID DESC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1,* From ( select * From ( SELECT UL.ID,UL.LeadNo,UL.PersonName,UL.img_ext,UL.CompanyName,UL.CreatedOn AS CreatedOn1, CASE WHEN ISNULL(UL.CountryCode,'''') <> '''' and trim(ISNULL(UL.MobileNo,'''')) <> ''''  THEN TRIM(ISNULL(UL.Countrycode,'''')) + '' '' + TRIM(ISNULL(UL.MobileNo,''''))  ELSE '''' END +  CASE WHEN trim(ISNULL(UL.Mobileno1,'''')) <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid,'''') <> '''' THEN UL.Emailid ELSE '''' END + CASE WHEN ISNULL(UL.EmailID1,'''') <> '''' THEN '', '' ELSE '''' END + CASE WHEN ISNULL(UL.EmailID2,'''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, CONVERT(VARCHAR(10), UL.CreatedOn, 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), UL.CreatedOn, 109), 15), 7, 7, '' '') AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy, ISNULL(UD2.User_Login,'''') as FollowupBy, trim(UL.MobileNo) AS MobileNo3, trim(UL.MobileNo1) as MobileNo1, trim(UL.MobileNo2) as MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, UL.WhereAddress, isnull(tg.Tags, '''') Tags, ( SELECT STUFF( (SELECT N'', '' + ss.Name FROM ProductMaster(nolock) AS ss INNER JOIN dbo.fn_Split(ul.Products, ''#'') AS fs  ON ss.ProductID = fs.value FOR XML PATH(''''), TYPE).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''') ) AS Products, UD.User_Login + '' ('' + Ud.FName +  '' '' + Ud.LName + '')'' AS assigneduser, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int), ThresholdColor=case when cast(isnull((LS.currentscore/nullif('+ cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int)>' + cast(@warm as nvarchar(max)) + ' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max))+',0.00))*99,0) as int) between ' + cast(@cold as nvarchar(max)) + '  and ' + cast(@warm as nvarchar(max)) + ' then ''Warm'' else ''Cold'' end, UD1.User_Login ' as nvarchar(max)) +  ', isnull(UD2.User_Login, '''') as LastFollowupCreatedByName, ul.LastFollowupCreatedOn as LastFollowupedOn, UL.WhatsAppNoColName  '  
 select @Query +=cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)
 ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f
 left join lead_score_history_latest(nolock) LS ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK) ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK) ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK) ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK) ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK) ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK)
ON UL.FollowUpStatus = FUS.id
--left join LeadPipelineMapping_latest(nolock) as lpm
