 print 'Branch CA'
 
  declare @caQuery nvarchar(max) = CAST(N'; Select * from ( Select *       
   From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, Img_Ext, WhereAddress, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column + N', CurrentScore, Profit_Loss, ThresholdColor, ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + '  [ID] DESC) + cast( '+ cast( @srno - 1 as nvarchar) + ' as int) ' + ' AS [RowNumber1], rc1, LastFollowupCreatedByName, LastFollowupedOn, WhatsAppNoColName,CreatedBy, ModifiedOn, ModifiedBy FROM
   (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy, FollowupDate, FollowupCreatedDate, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, img_ext, WhereAddress, Products, [fieldname] , fieldvalue, CurrentScore, Profit_Loss,ThresholdColor, RowNumber1, rc1 ,User_Login,LastFollowupCreatedByName, LastFollowupedOn, WhatsAppNoColName,CreatedBy, ModifiedOn, ModifiedBy FROM (select L.ID,  L.LeadNo, L.PersonName, L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.FollowupBy, L.FollowupDate, L.FollowupCreatedDate, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,  L.assigneduser, L.Img_Ext, L.WhereAddress, L.Products, y.fieldname, x.fieldvalue, L.CurrentScore, L.Profit_Loss, L.ThresholdColor, L.RowNumber1, L.rc1, L.User_Login,L.LastFollowupCreatedByName, L.LastFollowupedOn, L.WhatsAppNoColName, L.CreatedBy, L.ModifiedOn, L.ModifiedBy  From #temp1 L left join customfieldLeadvalue(nolock) x ON L.ID = x.LeadID left join customfields(nolock) y ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 )q )Tab1
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2) T1
  Where ' + @txtSearch + ' ) T2 Where T2.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno)  + N' ORDER BY ' + @ordstr  
  /*N' ORDER BY CurrentScore desc,      
   case when cast(followupdate as date) = cast(getdate() as date) then 0      
     when followupdate < getdate()  then 1      
     when followupdate > getdate() then 2      
     when followupdate is null then 3      
      end,followupdate  '*/ AS NVARCHAR(MAX));      
 
   print @caQuery
   SELECT @Query = @Query + @caQuery
 End      
 Else-- From Branch B      
 Begin      
  print 'Branch CB'      
      
  Select @filterCnt=count(*) From dbo.fn_Split(@txtSearch, ' ) ')      
        
  SELECT @Query1 += CAST(N'; select x.LeadID into #Temp2 from customfieldLeadvalue(nolock) x inner join customfields(nolock) y      
  ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1      
  Where ' + @txtSearch + N' group by x.LeadID having count(*) >= ' + Cast(@filterCnt as NVARCHAR(MAX)) AS NVARCHAR(MAX));     
      
	  SELECT @Query1 += CAST(N'; Select * from ( Select ROW_NUMBER() OVER(ORDER BY ' + @StrPredefinedOrderBy + N' ' + @StrCustomOrderBy + '  [ID] DESC) + cast( '+ cast( @srno - 1 as nvarchar) + ' as int) ' + ' AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], * From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, Img_Ext, WhereAddress, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column + N', CurrentScore, Profit_Loss, ThresholdColor, LastFollowupCreatedByName, LastFollowupedOn, WhatsAppNoColName, CreatedBy, ModifiedOn, ModifiedBy FROM ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy, FollowupDate, FollowupCreatedDate, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, img_ext, WhereAddress, Products, [fieldname] , fieldvalue, CurrentScore, Profit_Loss, ThresholdColor, User_Login, LastFollowupCreatedByName, LastFollowupedOn, WhatsAppNoColName, CreatedBy, ModifiedOn, ModifiedBy      
   FROM (select L.ID, L.LeadNo, L.PersonName, L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.FollowupBy, L.FollowupDate, L.FollowupCreatedDate, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,  L.assigneduser, L.Img_Ext, L.WhereAddress, L.Products, y.fieldname, x.fieldvalue, L.CurrentScore, L.Profit_Loss, L.ThresholdColor,L.User_Login,L.LastFollowupCreatedByName, L.LastFollowupedOn,L.WhatsAppNoColName, L.CreatedBy, L.ModifiedOn, L.ModifiedBy  From #Temp2 A inner join #temp1 L       
    ON A.LeadId = L.ID left join customfieldLeadvalue(nolock) x
   ON L.ID = x.LeadID left join customfields(nolock) y 
   ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) q )Tab1      
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2) T1       
  ) T2 Where T2.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) + N' ORDER BY ' + @ordstr      
  /*N' ORDER BY CurrentScore desc,      
   case when cast(followupdate as date) = cast(getdate() as date) then 0      
     when followupdate < getdate()  then 1      
     when followupdate > getdate() then 2      
     when followupdate is null then 3      
      end,followupdate  '*/ AS NVARCHAR(MAX));      

	 print @Query1
	 Select @Query = @Query + @Query1
 End      
END      
ELSE      
BEGIN      
 print 'Branch D'      
      
  SET @Query2 += CAST(N';Select *, FollowupBy as User_Login      
  From #temp1      
  Where RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) + N' ORDER BY ' + @ordstr       
  /*N' ORDER BY CurrentScore desc,      
  case when cast(followupdate as date) = cast(getdate() as date) then 0      
  when followupdate < getdate() then 1      
  when followupdate > getdate() then 2      
  when followupdate is null then 3      
  end,followupdate '*/ AS NVARCHAR(MAX));      

  print @Query2
  Select @Query = @Query + @Query2

END      
                                      
  --print '@FinalQuery:- ' + cast(@Query as varchar(max))      
                                      
                                    
 EXEC sp_executesql @Query;                                        
                                        
 --update kit19_executionlogger                                        
 --set EndDatetime = getdate(),                                        
 --Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)                                        
 --where ID = @LoggerID                                        
                                        
 --update kit19_executionlogger                                        
 --set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)                                        
 --where ID = @LoggerID                                        
                                        
 IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;      
 IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL BEGIN DROP TABLE #temp2; END;      
End                                        
                                        
end



GO

