CREATE   PROCEDURE [dbo].[Usp_ViewUserLeadDetails2_New_withnofollowup08032022] 
( 
 @txtSearch NVARCHAR(max), 
 @ParentID BIGINT, 
 @Userid INT= 0, 
 @FilterText NVARCHAR(MAX) = '', 
 @srno NVARCHAR(100), 
 @enno NVARCHAR(100), 
 @ordstr nvarchar(Max)='' , 
 @notfollowedup int=null 
) 
AS 
BEGIN 
--select @txtSearch=N'',@ParentID=29453,@Userid=0,@FilterText=N'(personName like ''avni'')',@srno=N'1',@enno=N'20' 

declare @IsAdmin bit = 0
select @IsAdmin = IsAdmin from User_Detail(nolock) where User_ID = @Userid
if(@IsAdmin = 1)
begin
	set @Userid = 0;
end

declare @Parameterlist nvarchar(max) , @LoggerID bigint 
set @Parameterlist = 'txtSearch : '+ @txtSearch + ' ,ParentID : '+ CONVERT(VARCHAR(100), @ParentID) + ' ,Userid : '+ CONVERT(VARCHAR(100), @Userid) + ' ,FilterText : '+ @FilterText + ' ,srno : '+ @srno + ' ,enno : '+ @enno;                                        

insert into kit19_executionlogger(ObjectName,Parameterlist,StartDatetime,EndDatetime,Remarks)                                        
values('Usp_ViewUserLeadDetails2_New',@Parameterlist,getdate(),'','')                                        
                                        
set @LoggerID = Scope_Identity(); 

Declare @TeamCode varchar(10) = ''
Declare @ScopeCode varchar(10) = '' 
Declare @UserIdTeamLst varchar(4000) = '' 
Declare @HierarchyJSON varchar(Max) = ''

 if Exists(select 1 from tbl_UA_UserHierarchy where ParentId = @ParentId) 
 Begin 
 Select @HierarchyJSON = HierarchyJSON from tbl_UA_UserHierarchy where ParentId = @ParentId 

  Create TABLE #TableData2 ([user_id] bigint, team_name Varchar(50), user_login varchar(50), username varchar(50), [parentid] bigint)
  Insert into #TableData2 ([user_id], team_name, user_login,username,[parentid])               
  Select [user_id], '', user_login, username, [parentid] from OPENJSON(@HierarchyJSON) with ([user_id] bigint, user_login Varchar(100), username Varchar(100), [parentid] bigint)

  ;with CTE(user_id) 
 as ( 
  select user_id 
  from #TableData2 where (User_id = @UserId or parentid = @UserId)
  union all 
  -- recursively add children
  select c.user_id
  from #TableData2 c 
  join CTE on c.parentid = CTE.User_id
 ) 
SELECT @UserIdTeamLst = STUFF((SELECT distinct ',' + Cast( a.user_id as varchar(4000)) from #TableData2 a join CTE on CTE.user_id = a.User_id FOR XML PATH('')),1,1,'')
 
--, @UserIdTeamLst = ''
 select @TeamCode = TeamCode, @ScopeCode = ScopeCode from ufn_GetUserRoleScope(@UserId) 

 --select * from #TableData2 
 --select @UserIdTeamLst 
 End
 Else
 Begin
 select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId) 
 End

-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=38738,@Userid INT=0,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20', @LoggerID bigint=0              
-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=29453,@Userid INT=0,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20', @LoggerID bigint=0              
-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=335,@Userid INT=0,@FilterText NVARCHAR(MAX)=N' ( Products = ''cvx'' ) ',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20', @LoggerID bigint=0              
-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=37540,@Userid INT=0,@FilterText NVARCHAR(MAX)=N' ( AssignedTo = ''37556'' ) and  ( FollowupCreatedDate >= ''07/08/2021'' And FollowupCreatedDate <= ''07/09/2021'' ) ',@srno NVARCHAR(100)=N'1',@ennoNVARCHAR(100)=N'20', @LoggerID bigint=0              
-- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=32222,@Userid INT=0,@FilterText NVARCHAR(MAX)=N' ( FollowupStatus = ''Call-Back'' ) and ( FollowupDate >= ''01/01/2021'' And FollowupDate <= ''07/09/2021'' ) and ( FollowupCreatedDate >= ''01/01/2021'' And FollowupCreatedDate <= ''07/09/2021'' ) and ( FollowupBy like  ''%abhi%'' ) ',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20', @LoggerID bigint=0              
-- declare @txtSearch NVARCHAR(MAX)=N'(fieldname=''IICS_Code'' and fieldvalue=''IICS/N21/6565'')',@ParentID BIGINT=38859,@Userid INT=0,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20', @LoggerID bigint=0,@ordstr nvarchar(Max)=''              
-- declare @txtSearch NVARCHAR(MAX)=N' ( fieldname=''test02'' and cast(fieldvalue as varchar(50)) like  ''%2%'' )  or  ( fieldname=''test03'' and cast(fieldvalue as varchar(50)) like  ''%3%'' ) ',@ParentID BIGINT=32222,@Userid INT=0,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'25', @LoggerID bigint=0,@ordstr nvarchar(Max)='LeadNo desc'      
      
--declare @txtSearch NVARCHAR(MAX)=N'',@ParentID BIGINT=38750,@Userid INT=38759,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ordstr nvarchar(Max)='' -- AD      
--declare @txtSearch NVARCHAR(MAX)=N'',@ParentID BIGINT=38750,@Userid INT=38759,@FilterText NVARCHAR(MAX)=N' ( FollowupStatus = ''Call-Back'' )',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ordstr nvarchar(Max)=''  -- BD      
--declare @txtSearch NVARCHAR(MAX)=N'',@ParentID BIGINT=32222,@Userid INT=0,@FilterText NVARCHAR(MAX)=N' ( FollowupStatus = ''Call-Back'' ) and ( FollowupDate >= ''01/01/2021'' And FollowupDate <= ''07/09/2021'' ) and ( FollowupCreatedDate >= ''01/01/2021'' And FollowupCreatedDate <= ''07/09/2021'' ) and ( FollowupBy like  ''%abhi%'' ) ',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ordstr nvarchar(Max)='' -- BC      
--declare @txtSearch NVARCHAR(MAX)=N'',@ParentID BIGINT=32222,@Userid INT=0,@FilterText NVARCHAR(MAX)=N'',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20',@ordstr nvarchar(Max)=''  -- AC      
                                          
--If (CHARINDEX('FollowupCreatedDate',@FilterText) > 0 or CHARINDEX('FollowupBy',@FilterText) > 0)                                        
--Begin              
-- print 'Usp_ViewUserLeadDetails2_Followup_New'                                        
--  --Exec Usp_ViewUserLeadDetails2_Followup @txtSearch,@ParentID,@Userid,@FilterText,@srno,@enno                                        
--  Exec Usp_ViewUserLeadDetails2_Followup_New @txtSearch,@ParentID,@Userid,@FilterText,@srno,@enno                                        
--End                                        
--Else              
Begin              
 --print 'Usp_ViewUserLeadDetails2_New'                                        
                                        
IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;      
IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL BEGIN DROP TABLE #temp2; END;      
                                        
 Declare @NoCustomFields bigint, @offset int=20, @filterCnt int=0      
 DECLARE @Pivot_Column NVARCHAR(MAX);                                        
 DECLARE @Query NVARCHAR(MAX)= '', @Query1 NVARCHAR(MAX)= '',@Query2 nvarchar(max)                                      
               
 declare @maxScore numeric(18,2)=isnull((select (max(currentscore)*100)/99 from lead_score_history(nolock)e where parentid=@ParentID),0)              
 declare @hot int,@warm int,@cold int              
              
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=@ParentID                    
 if @hot is null                    
 begin                    
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=0                    
 end                    
              
 /*Select Pivot Column*/                                        
 SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])                                        
 FROM                                        
 (                                        
 SELECT DISTINCT [fieldname] FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1                                        
 ) AS Tab;                          
                                        
 set @NoCustomFields = (SELECT count(DISTINCT [fieldname]) FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1)                                        
 DECLARE @Rcnt VARCHAR(100);                                        
      
If(@ordstr = '')      
Begin      
 set @ordstr = ' CurrentScore desc, case when cast(followupdate as date) = cast(getdate() as date) then 0      
     when followupdate < getdate()  then 1      
     when followupdate > getdate() then 2      
     when followupdate is null then 3      
      end,followupdate '      
End                                       
              
IF(@txtSearch = '')              
BEGIN              
 SET @txtSearch = N' (1=1) ';      
 Set @offset=0      
END;      
      
IF(@FilterText = '')      
BEGIN      
 SET @FilterText = N' (1=1) ';              
END;              
              
 IF(@FilterText = ' (1=1) ' and @txtSearch = ' (1=1) ')      
BEGIN      
 print 'Branch A'
  SET @Query+=CAST(N'SELECT A.ID,A.LeadNo,A.PersonName,A.CompanyName,A.MobileNo,A.EmailID,A.City,A.State,A.Country,A.CountryCode,A.PinCode, A.ResidentialAddress, A.OfficeAddress, isnull(A.SourceName,''Unknown'') SourceName, A.MediumName,A.CampaignName,A.InitialRemarks, A.ParentID, A.FollowupBy, dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ', A.FollowupDate) AS FollowupDate, dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ', A.FollowupCreatedDate) AS FollowupCreatedDate, dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ', A.CreatedOn1) AS CreatedOn1New,  A.CreatedOn1, A.AssignedTo, A.Remarks, CASE WHEN ISNULL(A.FollowupStatus, '''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus, '''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.FollowupDate, '''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products, '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks, '''') + ''</p>'' ELSE '''' END AS FollowUp,A.MobileNo1, A.MobileNo2, A.MobileNo3, A.EmailID3, A.EmailID1, A.EmailID2, A.FollowupStatus, A.assigneduser, A.img_ext, A.WhereAddress, A.Tags, isnull(A.Products, '''') as Products, A.CurrentScore, A.Profit_Loss, A.ThresholdColor, RowNumber1, rc1, A.User_Login, A.LastFollowupCreatedByName, A.WhatsAppNoColName INTO #temp1 FROM ( select ROW_NUMBER() OVER(ORDER BY S.ID DESC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1, * From ( select * From ( SELECT UL.ID, UL.LeadNo, UL.PersonName, UL.img_ext, UL.WhereAddress, isnull(tg.Tags, '''') Tags, UL.CompanyName, UL.CreatedOn AS CreatedOn1,  CASE WHEN ISNULL(UL.CountryCode, '''') <> '''' and ISNULL(UL.MobileNo, '''') <> ''''  THEN TRIM(ISNULL(UL.Countrycode, '''')) + '' '' + TRIM(ISNULL(UL.MobileNo, ''''))  ELSE '''' END +  CASE WHEN ISNULL(UL.Mobileno1, '''') <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid, '''') <> '''' THEN UL.Emailid ELSE '''' END +  CASE WHEN ISNULL(UL.EmailID1, '''') <> '''' THEN '', '' ELSE '''' END +  CASE WHEN ISNULL(UL.EmailID2, '''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, CONVERT(VARCHAR(10), UL.CreatedOn, 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), UL.CreatedOn, 109), 15), 7, 7, '' '') AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy, UD1.User_Login as FollowupBy, UL.MobileNo AS MobileNo3, UL.MobileNo1, UL.MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, ( SELECT STUFF( (SELECT N'', '' + ss.Name FROM ProductMaster(nolock) AS ss INNER JOIN dbo.fn_Split(ul.Products, ''#'') AS fs  ON ss.ProductID = fs.value FOR XML PATH(''''), TYPE).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''') ) AS Products, UD.User_Login AS assigneduser, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int) , ThresholdColor=case when cast(isnull((LS.currentscore/nullif('+ cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int)>' + cast(@warm as nvarchar(max)) + ' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max))+',0.00))*99,0) as int) between ' + cast(@cold as nvarchar(max)) + ' and ' + cast(@warm as nvarchar(max)) + ' then ''Warm'' else ''Cold'' end , UD1.User_Login , ISNULL(UD2.User_Login, '''') as LastFollowupCreatedByName , UL.WhatsAppNoColName '  as nvarchar(max))   
 select @Query +=cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)      
 ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f
 left join lead_score_history_latest(nolock) LS 
ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK)
ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)
ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)
ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)
ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK)
ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK)
ON UL.FollowUpStatus = FUS.id 
--left join LeadPipelineMapping_latest(nolock) as lpm
--on UL.ID = lpm.LeadID 
 LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''lead'' and tm.ParentID = '+ Convert(varchar(100),@ParentID) +' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = UL.ID
WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' +              
 CASE WHEN @Userid = 0 THEN N' = UL.AssignedTo ' 
 WHEN @Userid > 0 and isnull(@TeamCode,'') != '' THEN ' in (' + isnull(@UserIdTeamLst, '') + ')' 
 ELSE ' = ' + CAST(@Userid AS NVARCHAR(MAX)) End + '    
 and 1= case when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''0'' then 1 when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''1''     
 and abs(datediff(mi,ul.createdon,ul.followupdate))<=2    
and ul.enquirysource not between 12 and 15 and ul.enquirysource<>22      
and ul.ModifiedOn is null  then 1 else 0 end'    
 + '    
 ) T       
 ) S       
 ) AS A Where A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno+@offset) AS NVARCHAR(MAX));        
 
END      
ELSE      
BEGIN      
 print 'Branch B'      
      
 SET @Query+=CAST(N'SELECT A.ID, A.LeadNo, A.PersonName, A.CompanyName, A.MobileNo, A.EmailID, A.City, A.State, A.Country, A.CountryCode, A.PinCode, A.ResidentialAddress, A.OfficeAddress,isnull(A.SourceName,''Unknown'') SourceName, A.MediumName, A.CampaignName, A.InitialRemarks, A.ParentID, A.FollowupBy, dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',A.FollowupDate) AS FollowupDate,dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',A.FollowupCreatedDate) AS FollowupCreatedDate,dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',A.CreatedOn1) AS CreatedOn1New,A.CreatedOn1,A.AssignedTo,A.Remarks,CASE WHEN ISNULL(A.FollowupStatus,'''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus,'''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.FollowupDate,'''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products,'''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL (A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks,'''') + ''</p>'' ELSE '''' END AS FollowUp,A.MobileNo1,A.MobileNo2,A.MobileNo3,A.EmailID3,A.EmailID1,A.EmailID2,A.FollowupStatus,A.assigneduser,A.img_ext, A.WhereAddress, A.Tags, isnull(A.Products, '''') as Products, A.CurrentScore,A.Profit_Loss,A.ThresholdColor,RowNumber1,rc1 ,A.User_Login, A.LastFollowupCreatedByName,A.WhatsAppNoColName INTO #temp1 FROM ( select ROW_NUMBER() OVER(ORDER BY S.ID DESC) AS RowNumber1, count(*) OVER(ORDER BY S.ParentID) AS rc1,* From ( select * From ( SELECT UL.ID,UL.LeadNo,UL.PersonName,UL.img_ext,UL.CompanyName,UL.CreatedOn AS CreatedOn1, CASE WHEN ISNULL(UL.CountryCode,'''') <> '''' and ISNULL(UL.MobileNo,'''') <> ''''  THEN TRIM(ISNULL(UL.Countrycode,'''')) + '' '' + TRIM(ISNULL(UL.MobileNo,''''))  ELSE '''' END +  CASE WHEN ISNULL(UL.Mobileno1,'''') <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid,'''') <> '''' THEN UL.Emailid ELSE '''' END + CASE WHEN ISNULL(UL.EmailID1,'''') <> '''' THEN '', '' ELSE '''' END + CASE WHEN ISNULL(UL.EmailID2,'''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, CONVERT(VARCHAR(10), UL.CreatedOn, 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), UL.CreatedOn, 109), 15), 7, 7, '' '') AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy, UD1.User_Login as FollowupBy, UL.MobileNo AS MobileNo3, UL.MobileNo1, UL.MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, UL.WhereAddress, isnull(tg.Tags, '''') Tags, ( SELECT STUFF( (SELECT N'', '' + ss.Name FROM ProductMaster(nolock) AS ss INNER JOIN dbo.fn_Split(ul.Products, ''#'') AS fs  ON ss.ProductID = fs.value FOR XML PATH(''''), TYPE).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''') ) AS Products, UD.User_Login AS assigneduser, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int), ThresholdColor=case when cast(isnull((LS.currentscore/nullif('+ cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int)>' + cast(@warm as nvarchar(max)) + ' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max))+',0.00))*99,0) as int) between ' + cast(@cold as nvarchar(max)) + '  and ' + cast(@warm as nvarchar(max)) + ' then ''Warm'' else ''Cold'' end, UD1.User_Login ' as nvarchar(max)) +  ', isnull(UD2.User_Login, '''') as LastFollowupCreatedByName, UL.WhatsAppNoColName  ' select @Query +=cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)
 ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f
 left join lead_score_history_latest(nolock) LS
ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK)
ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)
ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)
ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)
ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK)
ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK)
ON UL.FollowUpStatus = FUS.id
--left join LeadPipelineMapping_latest(nolock) as lpm
--on UL.ID = lpm.LeadID
 LEFT JOIN ( select STRING_AGG(Tag, '','') as Tags, etm.EntityID from TagMaster(nolock) tm inner join EntityTagMapping(nolock) etm on tm.id = etm.TagID and etm.entity = ''lead'' and tm.ParentID = '+ Convert(varchar(100),@ParentID) +' where ISNULL(etm.EntityID, 0) > 0 group by etm.EntityID ) tg on tg.EntityID = UL.ID	  
 WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' +              
 CASE WHEN @Userid = 0 THEN N' = UL.AssignedTo ' 
 WHEN @Userid > 0 and isnull(@TeamCode,'') != '' THEN ' in (' + isnull(@UserIdTeamLst, '') + ')' 
 ELSE ' = ' + CAST(@Userid AS NVARCHAR(MAX)) End + ' and 1= case when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''0'' then 1 when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''1''
 and abs(datediff(mi,ul.createdon,ul.followupdate))<=2
 and ul.enquirysource not between 12 and 15 and ul.enquirysource<>22
 and ul.ModifiedOn is null  then 1 else 0 end'
 + ' ) T Where ' + @FilterText + ' ) S ) AS A Where ' + case when @txtSearch = ' (1=1) ' then ' A.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) else ' (1=1) ' end AS NVARCHAR(MAX)); 
 --) AS A ' AS NVARCHAR(MAX)); 
 
End 
 
 IF(@Pivot_Column IS NOT NULL) 
 BEGIN 
 print 'Branch C' 
 --IF(@FilterText = ' (1=1) ' and @txtSearch = ' (1=1) ')-- From Branch A 
 IF(@txtSearch = ' (1=1) ')-- From Branch A 
 Begin 
 print 'Branch CA'
 
  declare @caQuery nvarchar(max) = CAST(N'; Select * from ( Select *       
   From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy as User_Login, FollowupDate, FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, Img_Ext, WhereAddress, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column + N', CurrentScore, Profit_Loss, ThresholdColor, RowNumber1, rc1, LastFollowupCreatedByName, WhatsAppNoColName FROM
   (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy, FollowupDate, FollowupCreatedDate, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, img_ext, WhereAddress, Products, [fieldname] , fieldvalue, CurrentScore, Profit_Loss,ThresholdColor, RowNumber1, rc1 ,User_Login,LastFollowupCreatedByName, WhatsAppNoColName FROM (select L.ID,  L.LeadNo, L.PersonName, L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.FollowupBy, L.FollowupDate, L.FollowupCreatedDate, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,  L.assigneduser, L.Img_Ext, L.WhereAddress, L.Products, y.fieldname, x.fieldvalue, L.CurrentScore, L.Profit_Loss, L.ThresholdColor, L.RowNumber1, L.rc1, L.User_Login,L.LastFollowupCreatedByName,L.WhatsAppNoColName From #temp1 L left join customfieldLeadvalue(nolock) x ON L.ID = x.LeadID left join customfields(nolock) y ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 )q )Tab1
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2) T1
  Where ' + @txtSearch + ' ) T2 Where T2.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno)  + N' ORDER BY ' + @ordstr  
  /*N' ORDER BY CurrentScore desc,      
   case when cast(followupdate as date) = cast(getdate() as date) then 0      
     when followupdate < getdate()  then 1      
     when followupdate > getdate() then 2      
     when followupdate is null then 3      
      end,followupdate  '*/ AS NVARCHAR(MAX));      
 
   --print @Query
   SELECT @Query = @Query + @caQuery
 End      
 Else-- From Branch B      
 Begin      
  print 'Branch CB'      
      
  Select @filterCnt=count(*) From dbo.fn_Split(@txtSearch, ' ) ')      
        
  SELECT @Query += CAST(N'; select x.LeadID into #Temp2 from customfieldLeadvalue(nolock) x inner join customfields(nolock) y      
  ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1      
  Where ' + @txtSearch + N' group by x.LeadID having count(*) >= ' + Cast(@filterCnt as NVARCHAR(MAX)) AS NVARCHAR(MAX));     
      
	  SELECT @Query += CAST(N'; Select * from ( Select ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], * From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy as User_Login, FollowupDate, FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, Img_Ext, WhereAddress, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column + N', CurrentScore, Profit_Loss, ThresholdColor, LastFollowupCreatedByName, WhatsAppNoColName FROM ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy, FollowupDate, FollowupCreatedDate, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, img_ext, WhereAddress, Products, [fieldname] , fieldvalue, CurrentScore, Profit_Loss, ThresholdColor, User_Login, LastFollowupCreatedByName, WhatsAppNoColName       
   FROM (select L.ID, L.LeadNo, L.PersonName, L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.FollowupBy, L.FollowupDate, L.FollowupCreatedDate, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,  L.assigneduser, L.Img_Ext, L.WhereAddress, L.Products, y.fieldname, x.fieldvalue, L.CurrentScore, L.Profit_Loss, L.ThresholdColor,L.User_Login,L.LastFollowupCreatedByName,L.WhatsAppNoColName From #Temp2 A inner join #temp1 L       
    ON A.LeadId = L.ID left join customfieldLeadvalue(nolock) x
   ON L.ID = x.LeadID left join customfields(nolock) y 
   ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1 ) q )Tab1      
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2) T1       
  ) T2 Where T2.RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) + N' ORDER BY ' + @ordstr      
  /*N' ORDER BY CurrentScore desc,      
   case when cast(followupdate as date) = cast(getdate() as date) then 0      
     when followupdate < getdate()  then 1      
     when followupdate > getdate() then 2      
     when followupdate is null then 3      
      end,followupdate  '*/ AS NVARCHAR(MAX));      
 End      
END      
ELSE      
BEGIN      
 print 'Branch D'      
      
  SET @Query += CAST(N';Select *, FollowupBy as User_Login      
  From #temp1      
  Where RowNumber1 BETWEEN ' + CONVERT(nVARCHAR(max), @srno) + N' AND ' + CONVERT(nVARCHAR(max), @enno) + N' ORDER BY ' + @ordstr       
  /*N' ORDER BY CurrentScore desc,      
  case when cast(followupdate as date) = cast(getdate() as date) then 0      
  when followupdate < getdate() then 1      
  when followupdate > getdate() then 2      
  when followupdate is null then 3      
  end,followupdate '*/ AS NVARCHAR(MAX));      
END      
                                      
  print '@FinalQuery:- ' + cast(@Query as varchar(max))      
                                      
                                    
 EXEC sp_executesql @Query;                                        
                                        
 --update kit19_executionlogger                                        
 --set EndDatetime = getdate(),                                        
 --Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)                                        
 --where ID = @LoggerID                                        
                                        
 --update kit19_executionlogger                                        
 --set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)                                        
 --where ID = @LoggerID                                        
                                        
 IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;      
 IF OBJECT_ID('tempdb.dbo.#temp2', 'U') IS NOT NULL BEGIN DROP TABLE #temp2; END;      
End                                        
                                        
END 



GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserLeadDetails2222]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

    
      
-- exec Usp_ViewUserLeadDetails2 @txtSearch=N'',@ParentID=32222,@Userid=0,@FilterText=N'',@srno=N'1',@enno=N'20'                  
CREATE   PROCEDURE [dbo].Usp_ViewUserLeadDetails2222       
@txtSearch  NVARCHAR(100),       
@ParentID   BIGINT,       
@Userid     INT= 0,       
@FilterText NVARCHAR(MAX) = '',       
@srno       NVARCHAR(100),       
@enno       NVARCHAR(100)      
AS      
BEGIN      
        
 declare @Parameterlist nvarchar(max) , @LoggerID bigint      
 set @Parameterlist = 'txtSearch : '+ @txtSearch + ' ,ParentID : '+ CONVERT(VARCHAR(100), @ParentID) + ' ,Userid : '+ CONVERT(VARCHAR(100), @Userid) + ' ,FilterText : '+ @FilterText + ' ,srno : '+ @srno + ' ,enno : '+ @enno;      
      
 insert into kit19_executionlogger(ObjectName,Parameterlist,StartDatetime,EndDatetime,Remarks)      
 values('Usp_ViewUserLeadDetails2',@Parameterlist,getdate(),'','')      
      
 set @LoggerID = Scope_Identity();      
      
 -- declare @txtSearch NVARCHAR(100)=N'',@ParentID BIGINT=335,@Userid INT=0,@FilterText NVARCHAR(MAX)=N' (  Products = ''cvx''  ) ',@srno NVARCHAR(100)=N'1',@enno NVARCHAR(100)=N'20'  
  
    IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;  
  
 Declare @NoCustomFields bigint      
    DECLARE @Pivot_Column NVARCHAR(MAX);      
    DECLARE @Query NVARCHAR(MAX)= '', @Query1 NVARCHAR(MAX)= '';      
  
    /*Select Pivot Column*/      
    SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])      
    FROM      
    (      
  SELECT DISTINCT [fieldname] FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1  
    ) AS Tab;      
  
 set @NoCustomFields = (SELECT count(DISTINCT [fieldname]) FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1)      
 DECLARE @Rcnt VARCHAR(100);  
  
 IF(@Userid > 0)  
 BEGIN      
  SELECT @Rcnt = COUNT(ID) FROM UserLeads(NOLOCK) WHERE ParentID = @ParentID and AssignedTo = @Userid;      
    END      
    ELSE      
 BEGIN      
  SELECT @Rcnt = COUNT(ID) FROM UserLeads(NOLOCK) WHERE ParentID = @ParentID;      
 END      
      
 SET @Query+=CAST(N'SELECT DISTINCT  
 [A].[ID], [A].[LeadNo], [A].[PersonName], [A].[CompanyName], [A].[MobileNo], [A].[EmailID], [A].[City], [A].[State], [A].[Country], [A].[CountryCode], [A].[PinCode], [A].[ResidentialAddress], [A].[OfficeAddress], [A].[SourceName], [A].[MediumName], [A].[CampaignName], [A].[InitialRemarks], [A].[ParentID], [A].[User_Login], [dbo].[fn_getusertimefromindiantime](' + CAST(@ParentID AS NVARCHAR(MAX)) + ', [A].[FollowupDate]) AS [FollowupDate], [dbo].[fn_getusertimefromindiantime](' + CAST(@ParentID AS NVARCHAR(MAX)) + ', [A].[CreatedOn]) AS [CreatedOn], [dbo].[fn_getusertimefromindiantime](' + CAST(@ParentID AS NVARCHAR(MAX)) + ', [A].[CreatedOn1]) AS [CreatedOn1New], [A].[CreatedOn1], [A].[AssignedTo], [A].[Remarks],CASE WHEN ISNULL([A].[FollowupStatus], '''') <> '''' THEN ''<p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL([A].[FollowupStatus], '''') AS VARCHAR(50)) + ''</p>''   ELSE '''' END + CASE WHEN ISNULL([A].[FollowupDate], '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST([A].[FollowupDate] AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[Products], '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST([A].[Products] AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL([A].[AmountPaid], 0) <> 0   THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL([A].[AmountPaid], 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END +   CASE WHEN ISNULL([A].[Remarks], '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL([A].[Remarks], '''') + ''</p>''   ELSE '''' END AS [FollowUp],[A].[MobileNo1], [A].[MobileNo2], [A].[MobileNo3], [A].[EmailID3], [A].[EmailID1], [A].[EmailID2], [A].[FollowupStatus], [A].[assigneduser], [A].[img_ext], isnull([A].[Products], '''') as Products   
 INTO #temp1  
 FROM  
 (  
 SELECT [UL].[ID], [UL].[LeadNo], [UL].[PersonName], [UL].[img_ext], [UL].[CompanyName], [UL].[CreatedOn] AS [CreatedOn1],  
 CASE WHEN ISNULL([UL].[CountryCode], '''') <> ''''
 THEN ISNULL([UL].[Countrycode], '''') + '' '' + ISNULL([UL].[MobileNo], '''')  
 ELSE '''' END +  
 CASE WHEN ISNULL([UL].[Mobileno1], '''') <> ''''  
 THEN '', ...''  
 ELSE '''' END AS [MobileNo],  
 CASE WHEN ISNULL([UL].[Emailid], '''') <> ''''  
 THEN '' ''  
 ELSE '''' END +  
 CASE WHEN ISNULL([UL].[EmailID1], '''') <> ''''  
 THEN '', '' ELSE '''' END +  
 CASE WHEN ISNULL([UL].[EmailID2], '''') <> ''''  
 THEN '', ''  
 ELSE '''' END AS [EmailID],  
 [UL].[City], [UL].[State], [UL].[Country], [UL].[CountryCode], [UL].[PinCode], [UL].[ResidentialAddress], [UL].[OfficeAddress], [UL].[AssignedTo], [USS].[Name] AS [SourceName], [UMS].[Name] AS [MediumName], [UCS].[Name] AS [CampaignName], [UL].[InitialRemarks], [UL].[ParentID],  
 FUS.[FollowupStatus], [UL].[FollowupDate], [UL].[Remarks], ISNULL([UL].[AmountPaid], 0) AS [AmountPaid], CONVERT(VARCHAR(10), [UL].[CreatedOn], 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), [UL].[CreatedOn], 109), 15), 7, 7, '' '') AS [CreatedOn], [UL].[CreatedBy], [UL].[ModifiedOn], [UL].[ModifiedBy], [UD].[User_Login], [UL].[MobileNo] AS [MobileNo3], [UL].[MobileNo1], [UL].[MobileNo2], [UL].[EmailID] AS [EmailID3], [UL].[EmailID1], [UL].[EmailID2], ( SELECT STUFF( (SELECT N'', '' + [ss].[Name]  
 FROM [ProductMaster](nolock) AS [ss] INNER JOIN [dbo].[fn_Split]([ul].[Products], ''#'') AS [fs]  
 ON [ss].[ProductID] = [fs].[value] FOR XML PATH(''''), TYPE  
 ).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''')  
 ) AS [Products], [UD].[User_Login] AS [assigneduser]  
 FROM UserLeads AS UL(NOLOCK) --INNER JOIN #TMPquery1 t on UL.ID = t.LeadID  
 INNER JOIN UserSourceSettings AS USS(NOLOCK)  
 ON UL.SourceName = USS.SourceID LEFT JOIN UserMediumSettings AS UMS(NOLOCK)  
 ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)  
 ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)  
 ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)  
 ON UL.CreatedBy = UD1.User_ID left join [FollowUp_Status](NOLOCK) AS FUS  
 ON UL.[FollowUpStatus] = FUS.[id] WHERE [UL].[ParentID] = ' + CAST(@ParentID AS NVARCHAR(MAX)) + ' AND [UL].[AssignedTo] = CASE WHEN ' +   
 CAST(@Userid AS NVARCHAR(MAX)) + ' = 0 THEN [UL].[AssignedTo] ELSE ' + CAST(@Userid AS NVARCHAR(MAX)) + ' END  
 AND (ISNULL(''' + @txtSearch + ''', '''') = '''' OR [PersonName] LIKE ''%'' + ' + @txtSearch + ' + ''%'' OR [CompanyName] LIKE ''%'' + ' + @txtSearch + ' + ''%'')  
 ) AS A ORDER BY [A].[ID] DESC;' AS NVARCHAR(MAX));  
  
 IF(@FilterText = '')  
 BEGIN  
  SET @FilterText = ' (1=1) ';  
 END;  
      
 IF(@Pivot_Column IS NOT NULL)  
    BEGIN  
  SELECT @Query+=CAST(N';Select * From (SELECT ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, Img_Ext, Products, '
  + @Pivot_Column + ' FROM  
  (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, User_Login, FollowupDate, CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, img_ext, Products, [fieldname] , fieldvalue FROM (select L.ID, L.LeadNo, L.PersonName, L.CompanyName, L.MobileNo,
 L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.User_Login, L.FollowupDate, L.CreatedOn, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus, L.assigneduser, L.Img_Ext, L.Products, y.fieldname, x.fieldvalue 
  From #temp1 L left join customfieldLeadvalue(nolock) x ON L.ID = x.LeadID left join customfields(nolock) y on x.fieldID=y.field_ID  
  AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + ' AND y.[isActive] = 1  
  )q )Tab1  
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2  
  WHERE ' + @FilterText + ') T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND ' + CONVERT(VARCHAR(100), @enno) AS NVARCHAR(MAX));  
 END  
   ELSE  
 BEGIN  
  SET @Query += CAST(N';Select * From (select ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], * from #temp1 where ' + @FilterText + ') T1 Where RowNumber1 BETWEEN ' + CONVERT(VARCHAR(100), @srno) + ' AND
 ' + CONVERT(VARCHAR(100), @enno) AS NVARCHAR(MAX));  
 END  
      
    -- print '@FinalQuery:- ' + cast(@Query as varchar(max))  
    EXEC sp_executesql @Query;      
        
 update kit19_executionlogger  
 set EndDatetime = getdate(),  
 Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)  
 where ID = @LoggerID  
  
 update kit19_executionlogger  
 set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)  
 where ID = @LoggerID  
      
    IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL BEGIN DROP TABLE #temp1; END;    
    
END;    


GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserLeadDetails2bkp06012020]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
-- exec Usp_ViewUserLeadDetails2 @txtSearch=N'',@ParentID=24876,@Userid=0,@FilterText=N'',@srno=N'1',@enno=N'200'        
CREATE   PROCEDURE [dbo].[Usp_ViewUserLeadDetails2bkp06012020]          
 @txtSearch NVARCHAR(100),        
 @ParentID BIGINT,        
 @Userid int=0,        
 @FilterText nvarchar(max) = '',                  
 @srno NVARCHAR(100),              
 @enno NVARCHAR(100)         
AS                                                              
BEGIN               
                        
-- declare  @txtSearch NVARCHAR(100)='', @ParentID BIGINT=32222, @Userid int=0, @FilterText nvarchar(max) = '', @srno NVARCHAR(100)='1', @enno NVARCHAR(100)='20'         
        
    IF OBJECT_ID('tempdb.dbo.#temp', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #temp;        
    END;        
        
    IF OBJECT_ID('tempdb.dbo.#myleads', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #myleads;        
    END;        
        
    IF OBJECT_ID('tempdb.dbo.#myleads1', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #myleads1;        
    END;        
        
    IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #temp1;        
    END;        
        
    DECLARE @Pivot_Column NVARCHAR(MAX);        
    DECLARE @Query NVARCHAR(MAX)='',@Query1 NVARCHAR(MAX)='';        
        
    /*Select Pivot Column*/        
    SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])        
    FROM        
    (        
    SELECT DISTINCT [fieldname]        
    FROM customfields        
    WHERE [ParentID] = @ParentID AND [isActive] = 1        
    ) AS Tab;        
        
    If(@Pivot_Column is not null)          
    Begin          
    /*Create Dynamic Query*/        
    SELECT @Query = cast(N'SELECT LeadID, ' + @Pivot_Column + ' into #temp FROM            
    (SELECT leadid, [fieldname] , fieldvalue FROM (select x.LeadID, y.fieldname, x.fieldvalue  From customfieldLeadvalue(nolock) x inner join customfields(nolock) y on x.fieldID=y.field_ID WHERE y.[ParentID] = ' + cast(@ParentID as nvarchar(max)) + ' AND y.[isActive] = 1)q )Tab1                     
    PIVOT                                              
    (                                              
    max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + ')) AS Tab2        
    ORDER BY Tab2.LeadID; ' as nvarchar(max))        
        
    --EXEC sp_executesql @Query;        
    End        
        
    SET @Query += cast(N'SELECT DISTINCT        
   [A].[ID], [A].[LeadNo], [A].[PersonName], [A].[CompanyName], [A].[MobileNo], [A].[EmailID], [A].[City], [A].[State], [A].[Country], [A].[CountryCode], [A].[PinCode], [A].[ResidentialAddress], [A].[OfficeAddress], [A].[SourceName], [A].[MediumName], [A].[CampaignName], [A].[InitialRemarks], [A].[ParentID], [A].[User_Login], [dbo].[fn_getusertimefromindiantime]('+cast(@ParentID as nvarchar(max))+', [A].[FollowupDate]) AS [FollowupDate], [dbo].[fn_getusertimefromindiantime]('+cast(@ParentID as nvarchar(max))+', [A].[CreatedOn]) AS [CreatedOn], [dbo].[fn_getusertimefromindiantime]('+cast(@ParentID as nvarchar(max))+', [A].[CreatedOn1]) AS [CreatedOn1New], [A].[CreatedOn1], [A].[AssignedTo], [A].[Remarks],        
    CASE WHEN ISNULL([A].[FollowupStatus], '''') <> ''''         
    THEN ''<p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL([A].[FollowupStatus], '''') AS VARCHAR(50)) + ''</p>''        
    ELSE '''' END         
    +         
    CASE WHEN ISNULL([A].[FollowupDate], '''') <> ''''         
    THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST([A].[FollowupDate] AS VARCHAR(50)) + ''</p>''        
    ELSE '''' END         
    +         
    CASE WHEN ISNULL([A].[Products], '''') <> ''''         
     THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST([A].[Products] AS VARCHAR(50)) + ''</p>''        
     ELSE '''' END         
    +         
    CASE WHEN ISNULL([A].[AmountPaid], 0) <> 0        
    THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL([A].[AmountPaid], 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>''        
    ELSE '''' END         
    +         
    CASE WHEN ISNULL([A].[Remarks], '''') <> ''''        
    THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL([A].[Remarks], '''') + ''</p>''        
    ELSE '''' END AS [FollowUp],        
    [A].[MobileNo1], [A].[MobileNo2], [A].[MobileNo3], [A].[EmailID3], [A].[EmailID1], [A].[EmailID2], [A].[FollowupStatus], [A].[assigneduser], [A].[img_ext]        
    INTO [#temp1]        
    FROM        
    (        
    SELECT [UL].[ID], [UL].[LeadNo], [UL].[PersonName], [UL].[img_ext], [UL].[CompanyName], [UL].[CreatedOn] AS [CreatedOn1],        
    CASE WHEN ISNULL([UL].[CountryCode], '''') <> ''''        
    THEN ISNULL([UL].[Countrycode], '''') + '' '' + ISNULL([UL].[MobileNo], '''')        
    ELSE '''' END         
    +         
    CASE WHEN ISNULL([UL].[Mobileno1], '''') <> ''''        
    THEN '', ...''        
    ELSE '''' END AS [MobileNo],        
    CASE WHEN ISNULL([UL].[Emailid], '''') <> ''''         
    THEN '' ''         
    ELSE '''' END         
    +         
    CASE WHEN ISNULL([UL].[EmailID1], '''') <> ''''        
    THEN '', ''         
        ELSE ''''        
        END         
    +         
    CASE WHEN ISNULL([UL].[EmailID2], '''') <> ''''        
        THEN '', ''         
        ELSE '''' END AS [EmailID],         
    [UL].[City], [UL].[State], [UL].[Country], [UL].[CountryCode], [UL].[PinCode], [UL].[ResidentialAddress], [UL].[OfficeAddress], [UL].[AssignedTo], [USS].[Name] AS [SourceName], [UMS].[Name] AS [MediumName], [UCS].[Name] AS [CampaignName], [UL].[InitialRemarks], [UL].[ParentID],        
 FUS.[FollowupStatus], [UL].[FollowupDate], [UL].[Remarks], ISNULL([UL].[AmountPaid], 0) AS [AmountPaid], CONVERT(VARCHAR(10), [UL].[CreatedOn], 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), [UL].[CreatedOn], 109), 15), 7, 7, '' '') AS [CreatedOn], [UL].[CreatedBy], [UL].[ModifiedOn], [UL].[ModifiedBy], [UD].[User_Login], [UL].[MobileNo] AS [MobileNo3], [UL].[MobileNo1], [UL].[MobileNo2], [UL].[EmailID] AS [EmailID3], [UL].[EmailID1], [UL].[EmailID2],        
    (        
    SELECT STUFF(        
    (        
    SELECT N'', '' + [ss].[Name]        
    FROM [ProductMaster](nolock) AS [ss] INNER JOIN [dbo].[fn_Split]([ul].[Products], ''#'') AS [fs]        
    ON [ss].[ProductID] = [fs].[value] FOR XML PATH(''''), TYPE        
    ).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''')        
    ) AS [Products], [UD].[User_Login] AS [assigneduser]        
    FROM UserLeads AS UL(NOLOCK) INNER JOIN UserSourceSettings AS USS(NOLOCK)        
    ON UL.SourceName = USS.SourceID LEFT JOIN UserMediumSettings AS UMS(NOLOCK)        
    ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)        
    ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)        
    ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)        
    ON UL.CreatedBy = UD1.User_ID left join [FollowUp_Status](NOLOCK) AS FUS      
 ON UL.[FollowUpStatus] = FUS.[id]      
    WHERE [UL].[ParentID] = ' + cast(@ParentID as nvarchar(max)) + ' AND [UL].[AssignedTo] = CASE WHEN ' + cast(@Userid as nvarchar(max)) + ' = 0 THEN [UL].[AssignedTo] ELSE ' + cast(@Userid as nvarchar(max)) + ' END        
      AND (ISNULL(''' + @txtSearch + ''', '''') = '''' OR [PersonName] LIKE ''%'' + ' + @txtSearch + ' + ''%'' OR [CompanyName] LIKE ''%'' + ' + @txtSearch + ' + ''%'')        
    ) AS A        
    ORDER BY [A].[CreatedOn1] DESC;' as nvarchar(max))        
        
    if(@FilterText = '')          
    begin          
        set @FilterText = ' (1=1) '          
    end          
        
    SET @Query += cast(N' IF OBJECT_ID(''tempdb..#temp'') IS NOT NULL        
    BEGIN        
    select * into #myleads from #temp1 x left join #temp y on x.ID=y.leadid where ' + @FilterText + '        
        
    IF EXISTS (SELECT * FROM TempDB.INFORMATION_SCHEMA.COLUMNS(nolock) WHERE COLUMN_NAME = ''LeadID'' AND TABLE_NAME LIKE ''#myleads%'')        
            ALTER TABLE #myleads DROP COLUMN LeadID;          
        
        SELECT * FROM ( SELECT ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], COUNT([ID]) OVER (PARTITION BY [ParentID]) AS [rc1], * FROM #myleads) AS aa WHERE [RowNumber1] BETWEEN ' + @srno + ' AND ' + @enno + '        
    END        
    ELSE        
    BEGIN        
    select * into #myleads1 from #temp1 where ' + @FilterText + '        
        
    IF EXISTS (SELECT * FROM TempDB.INFORMATION_SCHEMA.COLUMNS(nolock) WHERE COLUMN_NAME = ''LeadID'' AND TABLE_NAME LIKE ''#myleads1%'')        
    ALTER TABLE #myleads1 DROP COLUMN LeadID;          
        
        SELECT * FROM ( SELECT ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], COUNT([ID]) OVER (PARTITION BY [ParentID]) AS [rc1], * FROM #myleads1) AS aa WHERE [RowNumber1] BETWEEN ' + @srno + ' AND ' + @enno + '        
    END;        
        
    ' as nvarchar(max))        
        
    --select len(@Query),@Query        
    EXEC sp_executesql @Query;        
        
        
    IF OBJECT_ID('tempdb.dbo.#temp', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #temp;        
    END;        
        
    IF OBJECT_ID('tempdb.dbo.#myleads', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #myleads;        
    END;        
        
    IF OBJECT_ID('tempdb.dbo.#myleads1', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #myleads1;        
    END;        
        
    IF OBJECT_ID('tempdb.dbo.#temp1', 'U') IS NOT NULL        
    BEGIN        
    DROP TABLE #temp1;        
    END;        
        
END 


GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserLeadDetails2Exp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_ViewUserLeadDetails2Exp] --'',1305, 29837                                                
 @txtSearch NVARCHAR(100),                                                  
 @ParentID BIGINT,                                                  
 @Userid int=0,              
 @FilterText nvarchar(max) = '',                                               
 @srno NVARCHAR(100),                                                      
 @enno NVARCHAR(100)                                                  
AS                                                  
BEGIN                   
IF OBJECT_ID('tempdb.dbo.##temp', 'U') IS NOT NULL                 
  begin                               
  DROP TABLE ##temp;                                 
  end                
  IF OBJECT_ID('tempdb.dbo.##myleads', 'U') IS NOT NULL                 
  begin                               
  DROP TABLE ##myleads;                                 
  end                             
DECLARE @Pivot_Column [nvarchar](max);                                  
DECLARE @Query [nvarchar](max);                                  
                                  
/*Select Pivot Column*/                                  
SELECT @Pivot_Column= COALESCE(@Pivot_Column+',','')+ QUOTENAME(fieldname) FROM                                  
(SELECT DISTINCT [fieldname] FROM customfields where ParentID=@ParentID and isActive=1)Tab                                 
                                 
/*Create Dynamic Query*/                                  
SELECT @Query='SELECT LeadID, '+@Pivot_Column+' into ##temp FROM                                   
(SELECT leadid, [fieldname] , fieldvalue FROM (select x.LeadID, y.fieldname, x.fieldvalue  From customfieldLeadvalue x inner join customfields y on x.fieldID=y.field_ID)q )Tab1                                  
PIVOT                                  
(                                  
max(fieldvalue) FOR [fieldname] IN ('+@Pivot_Column+')) AS Tab2                                  
ORDER BY Tab2.LeadID'                                
EXEC  sp_executesql  @Query                                              
 SELECT distinct A.ID,                                                  
        A.LeadNo,                                                  
        A.PersonName,                                                  
        A.CompanyName,                                            
        A.City,                                                  
        A.[State],                                                  
        A.Country,                                                  
        A.CountryCode,                                                  
        A.PinCode,  
        A.MobileNo1,                                                  
        A.MobileNo2,                                                  
        A.MobileNo3,                                                                                                          
        A.EmailID1,                                                  
        A.EmailID2,  
        A.EmailID3,                                                   
        A.ResidentialAddress,                                                  
        A.OfficeAddress,                                                  
        A.SourceName,                                                  
        A.MediumName,                                                  
        A.CampaignName,                                                  
        A.InitialRemarks,                                                  
        A.ParentID,                                                  
        A.User_Login,                    
        --A.FollowupDate,                    
        --A.CreatedOn,                        
        dbo.[fn_getusertimefromindiantime](@ParentID,A.FollowupDate) as FollowupDate,                            
        dbo.[fn_getusertimefromindiantime](@ParentID,A.CreatedOn) as CreatedOn,                                    
     dbo.[fn_getusertimefromindiantime](@ParentID,A.CreatedOn1) as CreatedOn1New,                                    
        A.CreatedOn1,                              
        A.AssignedTo,                                                 
        A.Remarks,                                                  
        CASE              
             WHEN ISNULL(A.FollowupStatus, '') <> '' THEN                                                   
             '<p><b>Follow Up Status:&nbsp;&nbsp;</b>' + CAST(ISNULL(A.FollowupStatus, '')                             
                  AS VARCHAR(50))                                                   
                  + '</p>'                                                  
         ELSE ''                                                  
        END +                                                  
        CASE                                                   
             WHEN ISNULL(A.FollowupDate, '') <> '' THEN                                                         '<p><b>Next Status Date:&nbsp;&nbsp;</b>' + CAST(A.FollowupDate AS VARCHAR(50))                    + '</p>'                                    
 
     
      
        
          
            
              
             ELSE ''                                                  
        END +                                                  
        CASE                                                   
             WHEN ISNULL(A.Products, '') <> '' THEN                                                   
                  '<p><b>Next Status Date:&nbsp;&nbsp;</b>' + CAST(A.Products AS VARCHAR(50))                          + '</p>'                                      
             ELSE ''                                                  
        END +                                                  
      CASE                                                   
             WHEN ISNULL(A.AmountPaid, 0) <> 0 THEN                                                   
                 '<p><b>Amount Paid:&nbsp;&nbsp;</b>' + CAST(                                                  
                      CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS                         
                      VARCHAR(50)                                                  
                  ) + '</p>'                                                  
             ELSE ''                                                  
    END +                                                  
        CASE                                                   
             WHEN ISNULL(A.Remarks, '') <> '' THEN                                                   
                  '<p><b>Remarks:&nbsp;&nbsp;</b>' + ISNULL(A.Remarks, '') +                                                   
                  '</p>'                                                  
             ELSE ''                                                  
        END  AS FollowUp,                                                                                                        
        A.FollowupStatus,                                                  
        A.assigneduser     into #temp1                                              
 FROM   (                                                  
            SELECT UL.ID,                                                  
                   UL.LeadNo,                                                  
                   UL.PersonName,                                                  
                   UL.CompanyName,                                      
                   UL.CreatedOn as CreatedOn1,  
                   UL.City,                                       
                   UL.[State],                                                  
                   UL.Country,                                                  
                   UL.CountryCode,                                                  
                   UL.PinCode,         
                   UL.ResidentialAddress,                                                  
                   UL.OfficeAddress,                                                  
           UL.AssignedTo,                                                  
                   USS.Name       AS SourceName,                                                  
                   UMS.Name       AS MediumName,                                                  
                   UCS.Name       AS CampaignName,                                                  
                   UL.InitialRemarks,                                                  
   UL.ParentID,                                                  
   (select FollowUpStatus from FollowUp_Status f where ul.FollowUpStatus=f.id) as FollowupStatus,                                                  
                   UL.FollowupDate,                                                  
                   UL.Remarks,                                                  
                   ISNULL(UL.AmountPaid, 0) AS AmountPaid,                                                  
                  CONVERT(VARCHAR(10),  UL.CreatedOn, 101) +                                                  
STUFF(                                                  
            RIGHT(CONVERT(VARCHAR(26),   UL.CreatedOn, 109), 15),                                                  
            7,                                                  
            7,                                                  
            ' '                                                  
        )  AS CreatedOn,                                                  
                   UL.CreatedBy,                                              
                   UL.ModifiedOn,                                                  
                   UL.ModifiedBy,                                                  
                   UD.User_Login,                                                  
                   UL.MobileNo    AS MobileNo1,                                                  
                   UL.MobileNo1 AS MobileNo2,                                                  
                   UL.MobileNo2 AS MobileNo3,                                   
                   UL.EmailID     AS EmailID1,                                                  
               UL.EmailID1 AS EmailID2,                                                  
                   UL.EmailID2 AS EmailID3,                                                 
                   (                                                  
                       SELECT STUFF(                                                  
                                  (                                                  
                           SELECT N', ' + ss.Name                                                  
                                      FROM   ProductMaster AS ss                                                  
                                             INNER JOIN dbo.fn_Split(ul.Products, '#') AS                                                   
                                                  fs                                                  
                                                  ON  ss.ProductID = fs.[value]                    
                                                      FOR XML PATH(''),                                                  
                       TYPE                                                  
                                  ) .value('text()[1]', 'nvarchar(max)'),                                                  
                                  1,                                                  
                                  2,                                                  
                                  N''                                                  
                              )         
                   )              AS Products,                                                  
                   UD.User_Login  AS assigneduser                                                  
            FROM   UserLeads UL(NOLOCK)                                                  
                   INNER JOIN UserSourceSettings USS(NOLOCK)                                        
                        ON  UL.SourceName = USS.SourceID                                                  
                   LEFT JOIN UserMediumSettings UMS(NOLOCK)                                                  
                        ON  UL.MediumName = UMS.MediumID                                                  
                   LEFT JOIN UserCampaignSettings UCS(NOLOCK)                                                  
                        ON  UL.CampaignName = UCS.CampaignID                    
  LEFT JOIN User_Detail UD(NOLOCK)                                                  
                        ON  UL.AssignedTo = UD.User_ID                                                  
                   --LEFT JOIN FollowUp_Status FUS(NOLOCK)                                                  
                   --     ON  UL.FollowUpStatus = FUS.ID                                                  
                   LEFT JOIN User_Detail UD1(NOLOCK)                                                  
                        ON  UL.CreatedBy = UD1.User_ID                                            WHERE  UL.ParentID = @ParentID                                                  
            AND UL.AssignedTo = CASE                                                   
                               WHEN (@Userid = 0) THEN UL.AssignedTo                                                   
                               ELSE @Userid                                                  
                          END                                                   
             --AND UL.CreatedBy = CASE                                                 
             --                  WHEN (@Userid = 0) THEN UL.CreatedBy                                                   
             --                  ELSE @Userid                                                  
             --             END                                                      
                   AND (                                                  
                           ISNULL(@txtSearch, '') = ''                                                  
                           OR PersonName LIKE '%' + @txtSearch + '%'                                                  
                           OR CompanyName LIKE '%' + @txtSearch + '%'                                                  
                       )                                                  
        )       A                                                  
 ORDER BY                                                  
        A.CreatedOn1 DESC                             
     IF OBJECT_ID('tempdb..##temp') IS NOT NULL                               
      begin               
        if @FilterText <>''              
        begin                             
       set @Query='select * into ##myleads from #temp1 x left join ##temp y on x.ID=y.leadid where '+@FilterText;               
       EXEC  sp_executesql @Query;                               
        end                              
        else                              
        begin                              
          set @Query='select * into ##myleads from #temp1 x left join ##temp y on x.ID=y.leadid'               
          EXEC  sp_executesql @Query;                                   
         end               
      end              
      else              
         begin              
             if @FilterText <>''              
           begin               
         set @Query='select * into ##myleads from #temp1 where ' +@FilterText;               
         EXEC  sp_executesql @Query;                  
           end              
         else              
           begin              
            set @Query='select * into ##myleads from #temp1'                
            EXEC  sp_executesql @Query;              
           end              
         end         
          IF OBJECT_ID('tempdb..##temp') IS NOT NULL                               
      begin           
         alter table ##myleads drop column LeadID;         
         end         
         declare @rc varchar(15) ;                     
      select  @rc = Count(*) from ##myleads;              
           select * from (select ROW_NUMBER() OVER(Order By ID desc) AS RowNumber1, @rc AS rc1, * from ##myleads)aa where  RowNumber1 between @srno and @enno;                        
       IF OBJECT_ID('tempdb.dbo.##temp', 'U') IS NOT NULL                 
  begin                               
  DROP TABLE ##temp;                                 
  end                
  IF OBJECT_ID('tempdb.dbo.##myleads', 'U') IS NOT NULL                
  begin                               
  DROP TABLE ##myleads;                                 
  end                
        drop table #temp1                                               
END 



GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserLeadDetailsPageLoad]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--------Modified By Abhishek Makkar ----------- Time: 8/18/2017 11:02:44 PM
CREATE   PROCEDURE [dbo].[Usp_ViewUserLeadDetailsPageLoad] --'',335
	@txtSearch NVARCHAR(100),
	@ParentID BIGINT
AS
BEGIN
	SELECT A.ID,
	       A.LeadNo,
	       A.PersonName,
	       A.CompanyName,
	       A.MobileNo,
	       A.EmailID,
	       A.City,
	       A.[State],
	       A.Country,
	       A.CountryCode,
	       A.PinCode,
	       A.ResidentialAddress,
	       A.OfficeAddress,
	       A.SourceName,
	       A.MediumName,
	       A.CampaignName,
	       A.InitialRemarks,
	       A.ParentID,
	       A.User_Login,
	       A.NextStatusDate,
	       A.CreatedOn,
	       A.User_Login,
	       A.FollowupStatus,
	       CASE 
	            WHEN ISNULL(A.FollowupStatus, '') <> '' THEN 
	                 '<p><b>Follow Up Status:&nbsp;&nbsp;</b>' +
	                 
	                 
	                 
	                 
	                 
	                 
	                 
	                 CAST(ISNULL(A.FollowupStatus, '') AS VARCHAR(50)) + '</p>'
	            ELSE ''
	       END + CASE 
	                  WHEN ISNULL(A.NextStatusDate, '') <>
	                       
	                       
	                       
	                       
	                       
	                       
	                       
	                       '' THEN '<p><b>Next Status Date:&nbsp;&nbsp;</b>' +
	                       
	                       
	                       
	                       
	                       
	                       
	                       
	                       CAST(A.NextStatusDate AS VARCHAR(50)) 
	                       
	                       
	                       
	                       
	                       
	                       
	                       
	                       +
	                       
	                       
	                       
	                       
	                       
	                       
	                       
	                       '</p>'
	                  ELSE ''
	             END + CASE 
	                        WHEN ISNULL(A.Products, '') <>
	                             
	                             
	                             
	                             
	                             
	                             
	                             
	                             '' THEN 
	                             '<p><b>Next Status Date:&nbsp;&nbsp;</b>' +
	                             
	                             
	                             
	                             
	                             
	                             
	                             
	                             CAST(A.Products AS VARCHAR(50)) 
	                             
	                             
	                             
	                             
	                             
	                             
	                             
	                             +
	                             
	                             
	                             
	                             
	                             
	                             
	                             
	                             '</p>'
	                        ELSE ''
	                   END +
	       
	       
	       
	       
	       
	       
	       
	       CASE 
	            WHEN ISNULL(A.AmountPaid, 0) <>
	                 
	                 
	                 
	                 
	                 
	                 
	                 
	                 0 THEN '<p><b>Amount Paid:&nbsp;&nbsp;</b>' +
	                 
	                 
	                 
	                 
	                 
	                 
	                 
	                 CAST(
	                     CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS 
	                     
	                     
	                     
	                     
	                     
	                     
	                     
	                     VARCHAR(50)
	                 ) 
	                 
	                 
	                 
	                 
	                 
	                 
	                 
	                 +
	                 
	                 
	                 
	                 
	                 
	                 
	                 
	                 '</p>'
	            ELSE ''
	       END +
	       
	       
	       
	       
	       
	       
	       
	       CASE 
	            WHEN ISNULL(A.Remarks, '') <>
	                 
	                 
	                 
	                 
	                 
	                 
	                 
	                 '' THEN '<p><b>Remarks:&nbsp;&nbsp;</b>' +
	                 
	                 
	                 
	                 
	                 
	                 
	                 
	                 ISNULL(A.Remarks, '') 
	                 
	                 
	                 
	                 
	                 
	                 
	                 
	                 +
	                 
	                 
	                 
	                 
	                 
	                 
	                 
	                 '</p>'
	            ELSE ''
	       END  AS FollowUp,
	       A.Remarks,
	       a.assigneduser
	FROM   (
	           SELECT UL.ID,
	                  UL.LeadNo,
	                  UL.PersonName,
	                  UL.CompanyName,
	                  ISNULL(UL.CountryCode, '') + ISNULL(UL.MobileNo, '') + CASE 
	                                                                              WHEN 
	                                                                                   ISNULL(UL.MobileNo1, '') 
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   <
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   >
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   '' THEN 
	                                                                                   ', ' 
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   +
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   ISNULL(UL.CountryCode1, '') 
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   +
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   
	                                                                                   ISNULL(UL.MobileNo1, '')
	                                                                              ELSE 
	                                                                                   ''
	                                                                         END 
	                  
	                  
	                  
	                  
	                  
	                  
	                  
	                  + CASE 
	                         WHEN ISNULL(UL.MobileNo2, '') <> '' THEN ', ' +
	                              
	                              
	                              
	                              
	                              
	                              
	                              
	                              ISNULL(UL.CountryCode2, '') + ISNULL(UL.MobileNo2, '')
	                         ELSE ''
	                    END          AS MobileNo,
	                  ISNULL(UL.EmailID, '') + CASE 
	                                                WHEN ISNULL(UL.EmailID1, '') 
	                                                     
	                                                     
	                                                     
	                                                     
	                                                     
	                                                     
	                                                     
	                                                     <> '' THEN ', ' +
	                                                     
	                                                     
	                                                     
	                                                     
	                                                     
	                                                     
	                                                     
	                                                     ISNULL(UL.EmailID1, '')
	                                                ELSE ''
	                                           END + CASE 
	                                                      WHEN ISNULL(UL.EmailID2, '') 
	                                                           
	                                                           
	                                                           
	                                                           
	                                                           
	                                                           
	                                                           
	                                                           <> '' THEN ', ' +
	                                                           
	                                                           
	                                                           
	                                                           
	                                                           
	                                                           
	                                                           
	                                                           ISNULL(UL.EmailID2, '')
	                                                      ELSE ''
	                                                 END AS EmailID,
	                  UL.City,
	                  UL.[State],
	                  UL.Country,
	                  UL.CountryCode,
	                  UL.PinCode,
	                  UL.ResidentialAddress,
	                  UL.OfficeAddress,
	                  UL.AssignedTo,
	                  UD.User_Login  AS assigneduser,
	                  USS.Name       AS SourceName,
	                  UMS.Name       AS MediumName,
	                  UCS.Name       AS CampaignName,
	                  UL.InitialRemarks,
	                  UL.ParentID,
	                  FUS.FollowupStatus,
	                  UL.NextStatusDate,
	                  UL.Remarks,
	                  ISNULL(UL.AmountPaid, 0) AS AmountPaid,
	                  UL.CreatedOn,
	                  UL.CreatedBy,
	                  UL.ModifiedOn,
	                  UL.ModifiedBy,
	                  UD.User_Login,
	                  (
	                      SELECT STUFF(
	                                 (
	                                     SELECT N', ' + ss.Name
	                                     FROM   ProductMaster AS ss
	                                            INNER JOIN dbo.fn_Split(ul.Products, '#') AS 
	                                                 fs
	                                                 ON  ss.ProductID = fs.[value] 
	                                                     
	                                                     
	                                                     
	                                                     
	                                                     
	                                                     
	                                                     
	                                                     FOR XML 
	                                                     
	                                                     
	                                                     
	                                                     
	                                                     
	                                                     
	                                                     
	                                                     PATH(''),
	                                            TYPE
	                                 ) 
	                                 
	                                 
	                                 
	                                 
	                                 
	                                 
	                                 
	                                 .value('text()[1]', 'nvarchar(max)'),
	                                 1,
	                                 2,
	                                 N''
	                             )
	                  )              AS Products
	           FROM   UserLeads UL(NOLOCK)
	                  LEFT JOIN UserSourceSettings USS(NOLOCK)
	                       ON  UL.SourceName = USS.SourceID
	                  LEFT JOIN UserMediumSettings UMS(NOLOCK)
	                       ON  UL.MediumName = UMS.MediumID
	                  LEFT JOIN UserCampaignSettings UCS(NOLOCK)
	                       ON  UL.CampaignName = UCS.CampaignID
	                  LEFT JOIN User_Detail UD(NOLOCK)
	                       ON  UL.AssignedTo = UD.User_ID
	                  LEFT JOIN FollowUp_Status FUS(NOLOCK)
	                       ON  UL.FollowUpStatus = FUS.ID
	                  LEFT JOIN User_Detail UD1(NOLOCK)
	                       ON  UL.CreatedBy = UD1.User_ID
	           WHERE  UL.ParentID = @ParentID
	                  AND (
	                          ISNULL(@txtSearch, '') = ''
	                          OR PersonName LIKE '%' + @txtSearch + '%'
	                          OR CompanyName LIKE '%' + @txtSearch + '%'
	                      )
	                  AND CONVERT(DATETIME, ul.NextStatusDate, 104) = CONVERT(DATETIME, CONVERT(VARCHAR, GETDATE(), 104), 104)
	       )       A
	ORDER BY
	       A.CreatedOn DESC
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserLeadDtls_withnofollowup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_ViewUserLeadDtls_withnofollowup]
( 
 @txtSearch NVARCHAR(max), 
 @ParentID BIGINT, 
 @Userid INT= 0, 
 @FilterText NVARCHAR(MAX) = '', 
 --@srno NVARCHAR(100), 
 --@enno NVARCHAR(100), 
 @ordstr nvarchar(Max)='' , 
 @notfollowedup int=null 
) 
AS 
BEGIN 
--select @txtSearch=N'',@ParentID=29453,@Userid=0,@FilterText=N'(personName like ''avni'')',@srno=N'1',@enno=N'20' 

declare @IsAdmin bit = 0
select @IsAdmin = IsAdmin from User_Detail(nolock) where User_ID = @Userid
if(@IsAdmin = 1)
begin
	set @Userid = 0;
end

declare @Parameterlist nvarchar(max) , @LoggerID bigint 
set @Parameterlist = 'txtSearch : '+ @txtSearch + ' ,ParentID : '+ CONVERT(VARCHAR(100), @ParentID) + ' ,Userid : '+ CONVERT(VARCHAR(100), @Userid) +   
' ,FilterText : '+ @FilterText;-- + ' ,srno : '+ @srno + ' ,enno : '+ @enno;                                        

Declare @TeamCode varchar(10) = ''
Declare @ScopeCode varchar(10) = '' 
Declare @UserIdTeamLst varchar(4000) = '' 
Declare @HierarchyJSON varchar(Max) = ''

 if Exists(select 1 from tbl_UA_UserHierarchy where ParentId = @ParentId) 
 Begin 
 Select @HierarchyJSON = HierarchyJSON from tbl_UA_UserHierarchy where ParentId = @ParentId 

  Create TABLE #TableData2 ([user_id] bigint, team_name Varchar(50), user_login varchar(50), username varchar(50), [parentid] bigint)
  Insert into #TableData2 ([user_id], team_name, user_login,username,[parentid])               
  Select [user_id], '', user_login, username, [parentid] from OPENJSON(@HierarchyJSON) with ([user_id] bigint, user_login Varchar(100), username Varchar(100), [parentid] bigint)

  ;with CTE(user_id) 
 as ( 
  select user_id 
  from #TableData2 where (User_id = @UserId or parentid = @UserId)
  union all 
  -- recursively add children
  select c.user_id
  from #TableData2 c 
  join CTE on c.parentid = CTE.User_id
 ) 
SELECT @UserIdTeamLst = STUFF((SELECT distinct ',' + Cast( a.user_id as varchar(4000)) from #TableData2 a join CTE on CTE.user_id = a.User_id FOR XML PATH('')),1,1,'')
 
--, @UserIdTeamLst = ''
 select @TeamCode = TeamCode, @ScopeCode = ScopeCode from ufn_GetUserRoleScope(@UserId) 

 --select * from #TableData2 
 --select @UserIdTeamLst 
 End
 Else
 Begin
 select @TeamCode = TeamCode, @ScopeCode = ScopeCode, @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId) 
 End

Begin              
 --print 'Usp_ViewUserLeadDetails2_New'                                        
                                        
IF OBJECT_ID('tempdb.dbo.#temp11', 'U') IS NOT NULL BEGIN DROP TABLE #temp11; END;      
IF OBJECT_ID('tempdb.dbo.#temp12', 'U') IS NOT NULL BEGIN DROP TABLE #temp12; END;      
                                        
 Declare @NoCustomFields bigint, @offset int=20, @filterCnt int=0      
 DECLARE @Pivot_Column NVARCHAR(MAX);                                        
 DECLARE @Query NVARCHAR(MAX)= '', @Query1 NVARCHAR(MAX)= '',@Query2 nvarchar(max)                                      
               
 declare @maxScore numeric(18,2)=isnull((select (max(currentscore)*100)/99 from lead_score_history(nolock)e where parentid=@ParentID),0)              
 declare @hot int,@warm int,@cold int              
              
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=@ParentID                    
 if @hot is null                    
 begin                    
 select @hot=hot,@warm=warm,@cold=cold from lead_cateogy_thresholds(nolock) where parentid=0                    
 end                    
              
 /*Select Pivot Column*/                                        
 SELECT @Pivot_Column = COALESCE(@Pivot_Column + ',', '') + QUOTENAME([fieldname])                                        
 FROM                                        
 (                                        
 SELECT DISTINCT [fieldname] FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1                                        
 ) AS Tab;                          
                                        
 set @NoCustomFields = (SELECT count(DISTINCT [fieldname]) FROM customfields WHERE [ParentID] = @ParentID AND [isActive] = 1)                                        
 DECLARE @Rcnt VARCHAR(100);                                        
      
If(@ordstr = '')      
Begin      
 set @ordstr = ' CurrentScore desc, case when cast(followupdate as date) = cast(getdate() as date) then 0      
     when followupdate < getdate()  then 1      
     when followupdate > getdate() then 2      
     when followupdate is null then 3      
      end,followupdate '      
End                                       
              
IF(@txtSearch = '')              
BEGIN              
 SET @txtSearch = N' (1=1) ';      
 Set @offset=0      
END;      
      
IF(@FilterText = '')      
BEGIN      
 SET @FilterText = N' (1=1) ';              
END;              
              
 IF(@FilterText = ' (1=1) ' and @txtSearch = ' (1=1) ')      
BEGIN      
 print 'Branch A'
  SET @Query+=CAST(N'SELECT A.ID,A.LeadNo,A.PersonName,A.CompanyName,A.MobileNo,A.EmailID,A.City,A.State,A.Country,A.CountryCode,A.PinCode, A.ResidentialAddress, A.OfficeAddress, isnull(A.SourceName,''Unknown'') SourceName, A.MediumName,A.CampaignName,A.InitialRemarks, A.ParentID, A.FollowupBy,              
 dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ', A.FollowupDate) AS FollowupDate,               
 dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ', A.FollowupCreatedDate) AS FollowupCreatedDate,              
 dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ', A.CreatedOn1) AS CreatedOn1New,  A.CreatedOn1,             
 A.AssignedTo, A.Remarks, CASE WHEN ISNULL(A.FollowupStatus, '''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>'' + CAST(ISNULL(A.FollowupStatus, '''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END +      
 CASE WHEN ISNULL(A.FollowupDate, '''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END +           
 CASE WHEN ISNULL(A.Products, '''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END +               
CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END +           
CASE WHEN ISNULL(A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks, '''') + ''</p>'' ELSE '''' END AS FollowUp,A.MobileNo1, A.MobileNo2, A.MobileNo3, A.EmailID3, A.EmailID1, A.EmailID2, A.FollowupStatus, A.assigneduser, A.img_ext, A.WhereAddress, isnull(A.Products, '''') as Products, A.CurrentScore, A.Profit_Loss, A.ThresholdColor, rc1, A.User_Login, A.LastFollowupCreatedByName, A.WhatsAppNoColName              
 INTO #temp11      
 FROM      
 (      
 select count(*) OVER(ORDER BY S.ParentID) AS rc1,*      
From (      
select *      
From (      
 SELECT UL.ID, UL.LeadNo, UL.PersonName, UL.img_ext, UL.WhereAddress, UL.CompanyName, UL.CreatedOn AS CreatedOn1,      
 CASE WHEN ISNULL(UL.CountryCode, '''') <> '''' and ISNULL(UL.MobileNo, '''') <> ''''  THEN TRIM(ISNULL(UL.Countrycode, ''''))      
+ '' '' + TRIM(ISNULL(UL.MobileNo, ''''))  ELSE '''' END +  CASE WHEN ISNULL(UL.Mobileno1, '''') <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid, '''') <> '''' THEN UL.Emailid ELSE '''' END +       
 CASE WHEN ISNULL(UL.EmailID1, '''') <> '''' THEN '', '' ELSE '''' END +       
 CASE WHEN ISNULL(UL.EmailID2, '''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, CONVERT(VARCHAR(10), UL.CreatedOn, 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), UL.CreatedOn, 109), 15), 7, 7, '' '') AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy, UD1.User_Login as FollowupBy, UL.MobileNo AS MobileNo3, UL.MobileNo1, UL.MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, ( SELECT STUFF( (SELECT N'', '' + ss.Name FROM ProductMaster(nolock) AS ss INNER JOIN dbo.fn_Split(ul.Products, ''#'') AS fs  ON ss.ProductID = fs.value FOR XML PATH(''''), TYPE).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''') ) AS Products, UD.User_Login AS assigneduser, Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int) , ThresholdColor=case when cast(isnull((LS.currentscore/nullif('+ cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int)>' + cast(@warm as nvarchar(max)) + ' then ''Hot'' when
 cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max))+',0.00))*99,0) as int) between ' + cast(@cold as nvarchar(max)) + '  
 and ' + cast(@warm as nvarchar(max)) + ' then ''Warm'' else ''Cold'' end , UD1.User_Login , UD2.User_Login as LastFollowupCreatedByName , UL.WhatsAppNoColName '  as nvarchar(max))      
 select @Query +=cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)      
 ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f      
 left join lead_score_history_latest(nolock) LS       
ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK)      
ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)      
ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)      
ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)      
ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK)
ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK)
ON UL.FollowUpStatus = FUS.id 
--left join LeadPipelineMapping_latest(nolock) as lpm
--on UL.ID = lpm.LeadID       
WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' +              
 CASE WHEN @Userid = 0 THEN N' = UL.AssignedTo ' 
 WHEN @Userid > 0 and isnull(@TeamCode,'') != '' THEN ' in (' + isnull(@UserIdTeamLst, '') + ')' 
 ELSE ' = ' + CAST(@Userid AS NVARCHAR(MAX)) End + '    
 and 1= case when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''0'' then 1 when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''1''     
 and abs(datediff(mi,ul.createdon,ul.followupdate))<=2    
and ul.enquirysource not between 12 and 15 and ul.enquirysource<>22      
and ul.ModifiedOn is null  then 1 else 0 end'    
 + '    
 ) T       
 ) S       
 ) AS A ' AS NVARCHAR(MAX));        
 
END      
ELSE      
BEGIN      
 print 'Branch B'      
      
 SET @Query+=CAST(N'SELECT A.ID,A.LeadNo,A.PersonName,A.CompanyName,A.MobileNo,A.EmailID,A.City,A.State,A.Country,A.CountryCode,A.PinCode,A.ResidentialAddress,A.OfficeAddress,isnull(A.SourceName,''Unknown'') SourceName,A.MediumName,A.CampaignName,A.InitialRemarks,A.ParentID,A.FollowupBy,dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',A.FollowupDate) AS FollowupDate,dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',A.FollowupCreatedDate) AS FollowupCreatedDate,dbo.fn_getusertimefromindiantime(' + CAST(@ParentID AS NVARCHAR(MAX)) + ',A.CreatedOn1) AS CreatedOn1New,A.CreatedOn1,A.AssignedTo,A.Remarks,CASE WHEN ISNULL(A.FollowupStatus,'''') <> '''' THEN '' <p><b>Follow Up Status:&nbsp;&nbsp;</b>''  
  + CAST(ISNULL(A.FollowupStatus,'''') AS VARCHAR(50))  + ''</p>'' ELSE '''' END +      
 CASE WHEN ISNULL(A.FollowupDate,'''') <> '''' THEN '' <p><b>Next Status Date:&nbsp;&nbsp;</b>'' + CAST(A.FollowupDate AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.Products,'''') <> '''' THEN ''<p><b>Next Status Date:&nbsp;&nbsp;</b>'' +  
CAST(A.Products AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL(A.AmountPaid,0) <> 0 THEN ''<p><b>Amount Paid:&nbsp;&nbsp;</b>'' + CAST(CAST(ISNULL(A.AmountPaid, 0) AS DECIMAL(18, 0)) AS VARCHAR(50)) + ''</p>'' ELSE '''' END + CASE WHEN ISNULL
 (A.Remarks, '''') <> '''' THEN ''<p><b>Remarks:&nbsp;&nbsp;</b>'' + ISNULL(A.Remarks,'''') + ''</p>'' ELSE '''' END AS FollowUp,A.MobileNo1,A.MobileNo2,A.MobileNo3,A.EmailID3,A.EmailID1,A.EmailID2,A.FollowupStatus,A.assigneduser,A.img_ext, A.WhereAddress, isnull(A.Products, '''') as Products, A.CurrentScore,A.Profit_Loss,A.ThresholdColor,rc1 ,A.User_Login, A.LastFollowupCreatedByName,A.WhatsAppNoColName 
 INTO #temp11      
 FROM      
 (      
 select count(*) OVER(ORDER BY S.ParentID) AS rc1,*      
From (      
select *      
From (      
 SELECT UL.ID,UL.LeadNo,UL.PersonName,UL.img_ext,UL.CompanyName,UL.CreatedOn AS CreatedOn1,      
 CASE WHEN ISNULL(UL.CountryCode,'''') <> '''' and ISNULL(UL.MobileNo,'''') <> ''''  THEN TRIM(ISNULL(UL.Countrycode,''''))      
+ '' '' + TRIM(ISNULL(UL.MobileNo,''''))  ELSE '''' END +  CASE WHEN ISNULL(UL.Mobileno1,'''') <> '''' THEN '', ...'' ELSE '''' END AS MobileNo, CASE WHEN ISNULL(UL.Emailid,'''') <> '''' THEN UL.Emailid ELSE '''' END + CASE WHEN ISNULL(UL.EmailID1,'''') <> ''''
 THEN '', '' ELSE '''' END +       
 CASE WHEN ISNULL(UL.EmailID2,'''') <> '''' THEN '', '' ELSE '''' END AS EmailID, UL.City, UL.State, UL.Country, UL.CountryCode, UL.PinCode, UL.ResidentialAddress, UL.OfficeAddress, UL.AssignedTo, USS.Name AS SourceName, UMS.Name AS MediumName, UCS.Name AS CampaignName, UL.InitialRemarks, UL.ParentID,FUS.FollowupStatus, UL.FollowupDate, UL.Remarks, ISNULL(UL.AmountPaid, 0) AS AmountPaid, CONVERT(VARCHAR(10), UL.CreatedOn, 101) + STUFF(RIGHT(CONVERT(VARCHAR(26), UL.CreatedOn, 109), 15), 7, 7, '' '') AS FollowupCreatedDate, UL.CreatedBy, UL.ModifiedOn, UL.ModifiedBy, UD1.User_Login as FollowupBy, UL.MobileNo AS MobileNo3, UL.MobileNo1, UL.MobileNo2, UL.EmailID AS EmailID3, UL.EmailID1, UL.EmailID2, UL.WhereAddress, ( SELECT STUFF( (SELECT N'', '' + ss.Name FROM ProductMaster(nolock) AS ss INNER JOIN dbo.fn_Split(ul.Products, ''#'') AS fs  ON ss.ProductID = fs.value FOR XML PATH(''''), TYPE).value(''text()[1]'', ''nvarchar(max)''), 1, 2, N'''') ) AS Products, UD.User_Login AS assigneduser,   
 Profit_Loss=case when LS.ScoreAdded > 0 then ''Green_Up'' when LS.ScoreAdded < 0 then ''Red_Down'' else '''' end, CurrentScore=cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int) ,
 ThresholdColor=case when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max)) + ',0.00))*99,0) as int)>' + cast(@warm as nvarchar(max)) + ' then ''Hot'' when cast(isnull((LS.currentscore/nullif(' + cast(@maxScore as nvarchar(max))+',0.00))*99,0) as int) between ' + cast(@cold as nvarchar(max)) + '  and ' + cast(@warm as nvarchar(max)) + ' then ''Warm'' else ''Cold'' end, UD1.User_Login ' as nvarchar(max)) +  ', UD2.User_Login as LastFollowupCreatedByName, UL.WhatsAppNoColName  ' 
 select @Query +=cast(N' FROM UserLeads AS UL(NOLOCK) left JOIN UserSourceSettings AS USS(NOLOCK)      
 ON UL.SourceName = USS.SourceID --outer apply dbo.funcToGetScoredetails(ul.id) f      
 left join lead_score_history_latest(nolock) LS       
ON UL.ID=LS.LeadId LEFT JOIN UserMediumSettings AS UMS(NOLOCK)      
ON UL.MediumName = UMS.MediumID LEFT JOIN UserCampaignSettings AS UCS(NOLOCK)      
ON UL.CampaignName = UCS.CampaignID LEFT JOIN User_Detail AS UD(NOLOCK)      
ON UL.AssignedTo = UD.User_ID LEFT JOIN User_Detail AS UD1(NOLOCK)      
ON UL.CreatedBy = UD1.User_ID LEFT JOIN User_Detail AS UD2(NOLOCK)
ON UL.LastFollowupCreatedBy = UD2.User_ID left join FollowUp_Status AS FUS(NOLOCK)
ON UL.FollowUpStatus = FUS.id 
--left join LeadPipelineMapping_latest(nolock) as lpm
--on UL.ID = lpm.LeadID    

WHERE UL.ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + N' AND UL.AssignedTo ' +              
 CASE WHEN @Userid = 0 THEN N' = UL.AssignedTo ' 
 WHEN @Userid > 0 and isnull(@TeamCode,'') != '' THEN ' in (' + isnull(@UserIdTeamLst, '') + ')' 
 ELSE ' = ' + CAST(@Userid AS NVARCHAR(MAX)) End + '    

 and 1= case when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''0'' then 1 when isnull('+cast(@notfollowedup as nvarchar)+',''0'')=''1''     
 and abs(datediff(mi,ul.createdon,ul.followupdate))<=2    
 and ul.enquirysource not between 12 and 15 and ul.enquirysource<>22      
 and ul.ModifiedOn is null  then 1 else 0 end' 
 + ' 
 ) T Where ' + @FilterText + ' 
 ) S 
 ) AS A Where (1=1) ' AS NVARCHAR(MAX)); 
 --) AS A ' AS NVARCHAR(MAX)); 
 
End 
 
 IF(@Pivot_Column IS NOT NULL) 
 BEGIN 
 print 'Branch C' 
 --IF(@FilterText = ' (1=1) ' and @txtSearch = ' (1=1) ')-- From Branch A 
 IF(@txtSearch = ' (1=1) ')-- From Branch A 
 Begin 
 print 'Branch CA'
 

  SELECT @Query += CAST(N'; Select * from ( Select *       
   From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy as User_Login, FollowupDate, FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, Img_Ext, WhereAddress, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column +       
   N', CurrentScore, Profit_Loss, ThresholdColor, rc1 ,LastFollowupCreatedByName, WhatsAppNoColName     
   FROM              
   (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy, FollowupDate, FollowupCreatedDate, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, img_ext, WhereAddress, Products, [fieldname] , fieldvalue, CurrentScore, Profit_Loss,ThresholdColor, rc1 ,User_Login,LastFollowupCreatedByName, WhatsAppNoColName     
   FROM (select L.ID,  L.LeadNo, L.PersonName, L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.FollowupBy, L.FollowupDate, L.FollowupCreatedDate, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,  L.assigneduser, L.Img_Ext, L.WhereAddress, L.Products, y.fieldname, x.fieldvalue, L.CurrentScore, L.Profit_Loss, L.ThresholdColor, L.rc1, L.User_Login,L.LastFollowupCreatedByName,L.WhatsAppNoColName     
   From #temp11 L left join customfieldLeadvalue(nolock) x      
   ON L.ID = x.LeadID left join customfields(nolock) y      
   ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1      
   )q )Tab1      
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2) T1       
  Where ' + @txtSearch + '       
  ) T2       
 ORDER BY ' + @ordstr       
  /*N' ORDER BY CurrentScore desc,      
   case when cast(followupdate as date) = cast(getdate() as date) then 0      
     when followupdate < getdate()  then 1      
     when followupdate > getdate() then 2      
     when followupdate is null then 3      
      end,followupdate  '*/ AS NVARCHAR(MAX));      
 
   --print @Query
 
 End      
 Else-- From Branch B      
 Begin      
  print 'Branch CB'      
      
  Select @filterCnt=count(*) From dbo.fn_Split(@txtSearch, ' ) ')      
        
  SELECT @Query += CAST(N'; select x.LeadID      
  into #Temp12      
  from customfieldLeadvalue(nolock) x inner join customfields(nolock) y      
  ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1      
  Where ' + @txtSearch + N'      
  group by x.LeadID      
  having count(*) >= ' + Cast(@filterCnt as NVARCHAR(MAX)) AS NVARCHAR(MAX));      
      
  SELECT @Query += CAST(N'; Select * from ( Select ROW_NUMBER() OVER(ORDER BY [ID] DESC) AS [RowNumber1], count(*) OVER(ORDER BY [ParentID]) AS [rc1], *       
   From ( SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy as User_Login, FollowupDate, FollowupCreatedDate as CreatedOn, CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, Img_Ext, WhereAddress, Products, FollowupCreatedDate, FollowupBy, ' + @Pivot_Column +       
   N', CurrentScore, Profit_Loss, ThresholdColor ,WhatsAppNoColName     
   FROM              
   (SELECT ID, LeadNo, PersonName, CompanyName, MobileNo, EmailID, City, State, Country, CountryCode, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, FollowupBy, FollowupDate, FollowupCreatedDate ,             
   CreatedOn1New, CreatedOn1, AssignedTo, Remarks, FollowUp, MobileNo1, MobileNo2, MobileNo3, EmailID3, EmailID1, EmailID2, FollowupStatus, assigneduser, img_ext, WhereAddress, Products, [fieldname] , fieldvalue, CurrentScore, Profit_Loss, ThresholdColor, User_Login, LastFollowupCreatedByName, WhatsAppNoColName       
   FROM (select L.ID, L.LeadNo, L.PersonName, L.CompanyName,L.MobileNo,L.EmailID, L.City, L.State, L.Country, L.CountryCode, L.PinCode, L.ResidentialAddress, L.OfficeAddress, L.SourceName, L.MediumName, L.CampaignName, L.InitialRemarks, L.ParentID, L.FollowupBy, L.FollowupDate, L.FollowupCreatedDate, L.CreatedOn1New, L.CreatedOn1, L.AssignedTo, L.Remarks, L.FollowUp, L.MobileNo1, L.MobileNo2, L.MobileNo3, L.EmailID3, L.EmailID1, L.EmailID2, L.FollowupStatus,  L.assigneduser, L.Img_Ext, L.WhereAddress, L.Products, y.fieldname, x.fieldvalue, L.CurrentScore, L.Profit_Loss, L.ThresholdColor,L.User_Login,L.LastFollowupCreatedByName,L.WhatsAppNoColName      
   From #Temp12 A inner join #temp11 L       
   ON A.LeadId = L.ID left join customfieldLeadvalue(nolock) x      
   ON L.ID = x.LeadID left join customfields(nolock) y      
   ON x.fieldID=y.field_ID AND y.[ParentID] = ' + CAST(@Parentid AS NVARCHAR(MAX)) + N' AND y.[isActive] = 1      
   )q )Tab1      
  PIVOT ( max(fieldvalue) FOR [fieldname] IN (' + @Pivot_Column + N')) AS Tab2) T1       
  ) T2 ORDER BY ' + @ordstr      
  /*N' ORDER BY CurrentScore desc,      
   case when cast(followupdate as date) = cast(getdate() as date) then 0      
     when followupdate < getdate()  then 1      
     when followupdate > getdate() then 2      
     when followupdate is null then 3      
      end,followupdate  '*/ AS NVARCHAR(MAX));      
 End      
END      
ELSE      
BEGIN      
 print 'Branch D'      
      
  SET @Query += CAST(N';Select *, FollowupBy as User_Login      
  From #temp11      
   ORDER BY ' + @ordstr       
  /*N' ORDER BY CurrentScore desc,      
  case when cast(followupdate as date) = cast(getdate() as date) then 0      
  when followupdate < getdate() then 1      
  when followupdate > getdate() then 2      
  when followupdate is null then 3      
  end,followupdate '*/ AS NVARCHAR(MAX));      
END      
                                      
  print '@FinalQuery:- ' + cast(@Query as varchar(max))      
                                      
                                    
 EXEC sp_executesql @Query;                                        
                                        
 --update kit19_executionlogger                                        
 --set EndDatetime = getdate(),                                        
 --Remarks = 'No. of Custom Fields : ' + Convert(nvarchar(100),@NoCustomFields)                                        
 --where ID = @LoggerID                                        
                                        
 --update kit19_executionlogger                                        
 --set TimeInSeconds = CAST( Datediff(ms,StartDatetime,EndDatetime) AS float) / CAST( 1000 AS float)                                        
 --where ID = @LoggerID                                        
                                        
 IF OBJECT_ID('tempdb.dbo.#temp11', 'U') IS NOT NULL BEGIN DROP TABLE #temp11; END;      
 IF OBJECT_ID('tempdb.dbo.#temp12', 'U') IS NOT NULL BEGIN DROP TABLE #temp12; END;      
End                                        
                                        
END 



