/* ============================================================
   Procedure: [dbo].[Usp_ViewUserLogin]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  
CREATE   PROC [dbo].[Usp_ViewUserLogin]            
AS             
BEGIN
	SELECT DISTINCT 
	       cul.UserID,
	       cul.UserName,
	       cul.FullName
	FROM   CRM_UserLogin AS cul
	ORDER BY
	       cul.UserName
END   


GO

/* ============================================================
   Procedure: [dbo].[Usp_ViewUserLoginInsertCRM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 
 
CREATE   PROC [dbo].[Usp_ViewUserLoginInsertCRM]    
AS     
BEGIN
	SELECT DISTINCT crul.[USER_ID],
	       NAME + ' ' + '{' + crul.[USER_NAME] + '}' AS NAME,
	       crul.[USER_NAME] INTO #TempTable
	FROM   [CRM].CRMDB.dbo.User_Login AS crul
	
	DELETE 
	FROM   CRM_UserLogin
	WHERE  UserID NOT IN (SELECT tt.[USER_ID]
	                      FROM   #TempTable tt)
	
	
	INSERT INTO CRM_UserLogin
	  (
	    -- ID -- this column value is auto-generated
	    UserID,
	    UserName,
	    FullName,
	    CreatedOn
	  )
	SELECT DISTINCT crul.USER_ID,
	       crul.[USER_NAME],
	       crul.NAME,
	       GETDATE()
	FROM   #TempTable crul
	       LEFT JOIN CRM_UserLogin AS cul
	            ON  crul.[User_ID] = cul.UserID
	WHERE  cul.ID IS NULL
	
	DROP TABLE #TempTable
END 



GO

/* ============================================================
   Procedure: [dbo].[usp_voice_bot_campaigns_Upsert]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_voice_bot_campaigns_Upsert]
 
(
 
    @parentid            BIGINT = NULL,
 
    @created_by          BIGINT = NULL,
 
    @campaign_name       NVARCHAR(200),
 
    @isactive            BIT = NULL,
 
    @campaign_settings   NVARCHAR(MAX) = NULL,
 
    @last_run            DATETIME = NULL,
 
    @next_run            DATETIME = NULL,
 
    @total_reach         INT = NULL,
 
    @campaign_end_date   DATETIME = NULL,
 
    @campaign_start_date DATETIME = NULL,
 
    @isdemo              BIT = NULL,
 
    @is_eventbased       BIT = 1,
 
    @eventid             BIGINT = NULL,
 
    @timeunit            VARCHAR(20) = NULL,
 
    @timebeforeunit      INT = 0,
 
    @day_settings        NVARCHAR(MAX) = NULL
 
)
 
AS
 
BEGIN
 
    SET NOCOUNT ON;
 
	
    DECLARE @InsertedId BIGINT;
    BEGIN TRY
 
        -- If an exact campaign exists for this parent, update it
 
        IF EXISTS (
 
            SELECT 1
 
            FROM dbo.voice_bot_campaigns WITH (NOLOCK)
 
            WHERE campaign_name = @campaign_name
 
              AND ISNULL(parentid, 0) = ISNULL(@parentid, 0)
 
        )
 
        BEGIN
 
		 DECLARE @FinalCampaignName1 NVARCHAR(200) = RTRIM(LTRIM(@campaign_name));
 
		  DECLARE @i1 INT = 1;
 
                WHILE EXISTS (
 
                    SELECT 1 FROM dbo.voice_bot_campaigns WITH (NOLOCK)
 
                    WHERE campaign_name = @FinalCampaignName1 + ' ' + CAST(@i1 AS NVARCHAR(10))
 
                      AND ISNULL(parentid, 0) = ISNULL(@parentid, 0)
 
                )
 
                BEGIN
 
                    SET @i1 = @i1 + 1;
 
                END
 
                SET @FinalCampaignName1 = @FinalCampaignName1 + ' ' + CAST(@i1 AS NVARCHAR(10));
 
            UPDATE dbo.voice_bot_campaigns
 
            SET isactive            = @isactive,
 
				campaign_name		=@FinalCampaignName1,
 
                campaign_settings   = @campaign_settings,
 
                last_run            = @last_run,
 
                next_run            = @next_run,
 
                total_reach         = @total_reach,
 
                campaign_end_date   = @campaign_end_date,
 
                campaign_start_date = getdate(),
 
                isdemo              = @isdemo,
 
                is_eventbased       = @is_eventbased,
 
                eventid             = @eventid,
 
                timeunit            = @timeunit,
 
                timebeforeunit      = @timebeforeunit
 
                --,days_json           = @day_settings
 
            WHERE campaign_name = @campaign_name
 
              AND ISNULL(parentid, 0) = ISNULL(@parentid, 0);
            SET @InsertedId = (SELECT TOP 1 id FROM dbo.voice_bot_campaigns WHERE campaign_name = @FinalCampaignName1 AND ISNULL(parentid, 0) = ISNULL(@parentid, 0) ORDER BY id DESC);
 
SELECT 'Updated Successfully.' AS [Status],
       @InsertedId AS InsertedId,
       @FinalCampaignName1 AS CampaignName;
 
        END
 
        ELSE
 
        BEGIN
 
            -- Prepare unique campaign name: append numeric suffix when needed
 
            DECLARE @FinalCampaignName NVARCHAR(200) = RTRIM(LTRIM(@campaign_name));
 
            IF EXISTS (
 
                SELECT 1 FROM dbo.voice_bot_campaigns WITH (NOLOCK)
 
                WHERE campaign_name = @FinalCampaignName
 
                  AND ISNULL(parentid, 0) = ISNULL(@parentid, 0)
 
            )
 
            BEGIN
 
                DECLARE @i INT = 1;
 
                WHILE EXISTS (
 
                    SELECT 1 FROM dbo.voice_bot_campaigns WITH (NOLOCK)
 
                    WHERE campaign_name = @FinalCampaignName + ' ' + CAST(@i AS NVARCHAR(10))
 
                      AND ISNULL(parentid, 0) = ISNULL(@parentid, 0)
 
                )
 
                BEGIN
 
                    SET @i = @i + 1;
 
                END
 
                SET @FinalCampaignName = @FinalCampaignName + ' ' + CAST(@i AS NVARCHAR(10));
 
            END
            INSERT INTO dbo.voice_bot_campaigns
 
            (
 
                parentid,
 
                created_by,
 
                created_on,
 
                campaign_name,
 
                isactive,
 
                campaign_settings,
 
                last_run,
 
                next_run,
 
                total_reach,
 
                campaign_end_date,
 
                campaign_start_date,
 
                isdemo,
 
                is_eventbased,
 
                eventid,
 
                timeunit,
 
                timebeforeunit
                --,days_json
 
            )
 
            VALUES
 
            (
 
                @parentid,
 
                @created_by,
 
                GETDATE(),
 
                @FinalCampaignName,
 
                @isactive,
 
                @campaign_settings,
 
                @last_run,
 
                @next_run,
 
                @total_reach,
 
                @campaign_end_date,
 
                getdate(),
 
                @isdemo,
 
                @is_eventbased,
 
                @eventid,
 
                @timeunit,
 
                @timebeforeunit
                --,@day_settings
 
            );
            SET @InsertedId = SCOPE_IDENTITY();
            SELECT 'Inserted Successfully.' AS [Status],
 
                   @InsertedId AS InsertedId,
 
                   @FinalCampaignName AS CampaignName;
 
        END
 
    END TRY
 
    BEGIN CATCH
 
        EXEC usp_InsertErrorInfo;
        DECLARE @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
 
        RAISERROR(@ErrorMessage, 16, 1);
 
    END CATCH
 
END



GO

/* ============================================================
   Procedure: [dbo].[usp_Voice_DeleveryReport]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_Voice_DeleveryReport] --335,'#All#'                        
@User_Id int,              
@fromDate datetime,          
@todate datetime             
as           
--if(@User_Id='364' or @User_Id='16300' or @User_Id='17626' or @User_Id='16301' or @User_Id='17809' or @User_Id='1889' or @User_Id='17492'  or @User_Id='335' or @User_Id='23513')          
begin             
 SELECT '' SenderID, VoiceID, substring(Mobile,1,6)+'****' as mobile, '********************' as message,   
  isnull((CASE Status WHEN '3' THEN 'DND' when '6' then 'Invalid' when 'NULL'   
  then 'Sent'  when '5' then 'Blacklisted'   
  when '7' then 'Sent'  when '9' then 'UNDELIV' when '' then 'Sent' ELSE Status END),'Sent')         AS MessageStatus,voiceInsertDate AS MessageDeliveredDate,LastError              
 FROM dbo.Voice_DeliveryStatus(nolock)              
  WHERE user_id = @User_Id and convert(date,voiceInsertDate)   
  between convert(date, @fromDate) and convert(datetime, @todate)              
end   


GO

/* ============================================================
   Procedure: [dbo].[usp_Voice_DeleveryReport1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC dbo.usp_Voice_DeleveryReport1 --'#All#',335,'01-Jan-2021','13-Apr-2022'                                    
 @AppName NVARCHAR(200)  
 ,@User_Id INT  
 ,@fromDate DATETIME  
 ,@todate DATETIME  
AS  
--if(@User_Id='364' or @User_Id='16300' or @User_Id='17626' or @User_Id='16301' or @User_Id='17809' or @User_Id='1889' or @User_Id='17492'  or @User_Id='335' or @User_Id='23513')                      
BEGIN  
 DECLARE @IsAdmin BIT = 0;  
 DECLARE @ParentId BIGINT = 0;  
  
 SELECT @IsAdmin = ISNULL(IsAdmin, 0)  
  ,@ParentId = isnull(ParentID, 0)  
 FROM User_Detail  
 WHERE User_ID = @User_Id  
  
 DECLARE @TimeZoneName NVARCHAR(255) = isnull((  
    SELECT TimeZone  
    FROM User_Detail(NOLOCK)  
    WHERE User_ID = @User_Id  
    ), 'india standard time')  
  
 IF (@AppName = '#All#')  
 BEGIN  
  SELECT '' SenderID  
   ,VoiceID  
   ,isnull(Mobile, '') AS mobile  
   ,isnull(CAM.AppName, '') AS message  
   ,isnull((  
     CASE VoiceSTATUS  
      WHEN '3'  
       THEN 'DND'  
      WHEN '6'  
       THEN 'Invalid'  
      WHEN 'NULL'  
       THEN 'Sent'  
      WHEN '5'  
       THEN 'Blacklisted'  
      WHEN '7'  
       THEN 'Sent'  
      WHEN '9'  
       THEN 'UNDELIV'  
      WHEN ''  
       THEN 'Sent'  
      ELSE VoiceSTATUS  
      END  
     ), 'Sent') AS MessageStatus  
   ,dbo.fn_ConvertDateTime(voiceInsertDate, @TimeZoneName, 0) AS MessageDeliveredDate  
   ,LastError  
  FROM dbo.Voice_DeliveryStatus(NOLOCK) VDS  
  LEFT JOIN Cloud_app_master(NOLOCK) CAM ON VDS.AppId = CAM.AppId  
  WHERE convert(DATE, voiceInsertDate) BETWEEN convert(DATE, @fromDate)  
    AND convert(DATETIME, @todate)  
   AND VDS.user_id = CASE   
    WHEN @IsAdmin = 1  
     THEN @ParentId  
    ELSE @User_Id  
    END  
 END  
 ELSE  
 BEGIN  
  SELECT '' SenderID  
   ,VoiceID  
   ,ISNULL(Mobile, '') AS mobile  
   ,isnull(CAM.AppName, '') AS message  
   ,isnull((  
     CASE VoiceSTATUS  
      WHEN '3'  
       THEN 'DND'  
      WHEN '6'  
       THEN 'Invalid'  
      WHEN 'NULL'  
       THEN 'Sent'  
      WHEN '5'  
       THEN 'Blacklisted'  
      WHEN '7'  
       THEN 'Sent'  
      WHEN '9'  
       THEN 'UNDELIV'  
      WHEN ''  
       THEN 'Sent'  
      ELSE VoiceSTATUS  
      END  
     ), 'Sent') AS MessageStatus  
   ,dbo.fn_ConvertDateTime(voiceInsertDate, @TimeZoneName, 0) AS MessageDeliveredDate  
   ,LastError  
  FROM dbo.Voice_DeliveryStatus(NOLOCK) VDS  
  LEFT JOIN Cloud_app_master(NOLOCK) CAM ON VDS.AppId = CAM.AppId  
  WHERE convert(DATE, voiceInsertDate) BETWEEN convert(DATE, @fromDate)  
    AND convert(DATETIME, @todate)  
   AND CAM.AppName = @AppName  
   AND VDS.user_id = CASE   
    WHEN @IsAdmin = 1  
     THEN @ParentId  
    ELSE @User_Id  
    END  
 END  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @User_Id  
  ,@Activity_type = 'View_Voice'  
  ,@ActionType = 'S'  
  ,@RowJson = ''  
  ,@Table_name = 'Voice_DeliveryStatus'  
END  


