/* ============================================================
   Procedure: [dbo].[usp_Voice_DeleveryReport1_BeforeLive]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_Voice_DeleveryReport1_BeforeLive] --'#All#',335,'01-Jan-2021','13-Apr-2022'                                  
@AppName nvarchar(200),        
@User_Id int,                        
@fromDate datetime,                    
@todate datetime                       
as                     
--if(@User_Id='364' or @User_Id='16300' or @User_Id='17626' or @User_Id='16301' or @User_Id='17809' or @User_Id='1889' or @User_Id='17492'  or @User_Id='335' or @User_Id='23513')                    
begin        
        
   declare @IsAdmin bit = 0;        
   declare @ParentId bigint = 0;        
        
   select @IsAdmin = ISNULL(IsAdmin,0), @ParentId = isnull(ParentID,0)from User_Detail where User_ID = @User_Id        
    declare @TimeZoneName nvarchar(255) = isnull( ( select TimeZone from User_Detail(nolock) where User_ID = @User_Id),'india standard time')         
        
        
if(@AppName = '#All#')         
Begin        
                      
 SELECT '' SenderID, VoiceID, isnull(Mobile,'') as mobile, isnull(CAM.AppName,'') as message,             
  isnull((CASE Status WHEN '3' THEN 'DND' when '6' then 'Invalid' when 'NULL'             
  then 'Sent'  when '5' then 'Blacklisted'             
  when '7' then 'Sent'  when '9' then 'UNDELIV' when '' then 'Sent' ELSE Status END),'Sent') AS MessageStatus,
  dbo.fn_ConvertDateTime(voiceInsertDate,@TimeZoneName,0) AS MessageDeliveredDate,LastError                        
 FROM dbo.Voice_DeliveryStatus(nolock) VDS left join Cloud_app_master(nolock) CAM        
 on VDS.AppId = CAM.AppId        
  WHERE  convert(date,voiceInsertDate)             
  between convert(date, @fromDate) and convert(datetime, @todate)        
  and         
  VDS.user_id =        
  case  when @IsAdmin = 1        
               then  @ParentId        
             else        
        @User_Id        
  end        
                          
End        
else        
  Begin        
        
   SELECT '' SenderID, VoiceID, ISNULL(Mobile,'') as mobile, isnull(CAM.AppName,'') as message,             
  isnull((CASE Status WHEN '3' THEN 'DND' when '6' then 'Invalid' when 'NULL'             
  then 'Sent'  when '5' then 'Blacklisted'             
  when '7' then 'Sent'  when '9' then 'UNDELIV' when '' then 'Sent' ELSE Status END),'Sent') AS MessageStatus,
  dbo.fn_ConvertDateTime(voiceInsertDate,@TimeZoneName,0) AS MessageDeliveredDate, LastError                        
 FROM dbo.Voice_DeliveryStatus(nolock) VDS left join Cloud_app_master(nolock) CAM        
 on VDS.AppId = CAM.AppId        
  WHERE  convert(date,voiceInsertDate)             
  between convert(date, @fromDate) and convert(datetime, @todate)   and CAM.AppName = @AppName                      
  and         
  VDS.user_id =        
  case  when @IsAdmin = 1        
               then  @ParentId        
             else        
        @User_Id        
  end        
          
        
        
  End        
        
        
        
end       


GO

