    AND convert(DATETIME, @todate)    
   AND VDS.user_id = CASE     
    WHEN @IsAdmin = 1    
     THEN @ParentId    
    ELSE @User_Id    
    END    
 END    
 ELSE    
 BEGIN    
  SELECT '' SenderID    
   ,VoiceID    
   ,ISNULL(Mobile, '') AS mobile    
   ,isnull(CAM.AppName, '') AS message    
   ,isnull((    
     CASE VoiceSTATUS    
      WHEN '3'    
       THEN 'DND'    
      WHEN '6'    
       THEN 'Invalid'    
      WHEN 'NULL'    
       THEN 'Sent'    
      WHEN '5'    
