/* ============================================================
   Procedure: [dbo].[usp_voice_GetCallSummaryDetailsByCallSid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_voice_GetCallSummaryDetailsByCallSid(
    @CallSid nvarchar(255)  
)
as
begin

    --declare 
    --	@CallSid nvarchar(255) = 'h3.07-1775825323.1981692'

    select top 1
	    c.CallSid,
	    'completed' as [CallStatus],
        c.Bot_Id,
        c.parentid,
        c.customerentity,
        c.customerentityid,
        cs.additional_details,
        cs.id as callsummaryid,
        cs.calllog_id,
        c.Customernumber,
        c.customercountrycode
    from calllog c with (nolock) 
	    inner join call_summaries cs with (nolock) on cs.calllog_id = c.id
    where c.CallSid = @CallSid
    order by c.id desc

end



GO

/* ============================================================
   Procedure: [dbo].[usp_voice_GetVoiceBotByMode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voice_GetVoiceBotByMode]
    @Mode      NVARCHAR(50)   = 'GetDdlList',
    @UserId    BIGINT         = 0,
    @JsonData  NVARCHAR(MAX)  = NULL
AS
BEGIN
    SET NOCOUNT ON;

    -- ---- GetPrebuiltTemplates: only return master prebuilt templates ----
    IF LOWER(LTRIM(RTRIM(@Mode))) = 'getprebuilttemplates'
    BEGIN
        SELECT
            id,
            Bot_name,
            [Description],
            category,
            isactive,
            is_predefined,
            is_editable,
            parentid,
            createdon,
            LanguageConfig,
            ActivePrompts,
            SystemPrompt
        FROM dbo.voice_bot_details
        WHERE is_predefined = 1
          AND parentid = 0
        ORDER BY id;
        RETURN;
    END

    -- ---- getbyid: single bot by id from JsonData ----
    IF LOWER(LTRIM(RTRIM(@Mode))) = 'getbyid'
    BEGIN
        DECLARE @BotId BIGINT = TRY_CONVERT(BIGINT, JSON_VALUE(@JsonData, '$.agentId'));
        SELECT *
        FROM dbo.voice_bot_details
        WHERE id = @BotId;
        RETURN;
    END

    -- ---- GetDdlList (default): bots belonging to the parent company ----
    DECLARE @ParentId BIGINT = CASE WHEN @UserId > 0 THEN dbo.ufn_getuserparentid(@UserId) ELSE 0 END;
    SELECT
        id,
        Bot_name,
        [Description],
        isactive,
        parentid,
        createdon,
        LanguageConfig,
        category
    FROM dbo.voice_bot_details
    WHERE is_predefined = 0
      AND parentid = @ParentId
    ORDER BY createdon DESC;
END;



GO

