        )  
   
        OUTPUT INSERTED.id INTO @InsertedIds(InsertedId)  
   
        VALUES  
   
        (  
   
            @BotName,  
   
            @Description,  
           -- @ActivePrompt,  
              
          N'[{"Prompt":"' + STRING_ESCAPE(ISNULL(@ActivePrompt,''),'json') + '"}]',
   
            @SystemPrompt,  
   
