        );  
        SET @BotId = (SELECT TOP 1 InsertedId FROM @InsertedIds ORDER BY InsertedId DESC);  
   
        SET @Action = 'insert';  
    END  
   
    ELSE  
   
    BEGIN  
        -- UPDATE existing bot  
   
        UPDATE dbo.voice_bot_details  
   
        SET  
   
            Bot_name = COALESCE(@BotName, Bot_name),  
   
            Description = COALESCE(@Description, Description),  
            SystemPrompt = COALESCE(@SystemPrompt, SystemPrompt),  
   
           -- ActivePrompts = COALESCE(@ActivePrompt, ActivePrompts),  
           ActivePrompts = N'[{"Prompt":"' + STRING_ESCAPE(ISNULL(@ActivePrompt,''),'json') + '"}]',
   
            VoiceConfig = COALESCE(@VoiceConfig, VoiceConfig),  
   
            LanguageConfig = COALESCE(@LanguageConfig, LanguageConfig),  
   
            isactive = COALESCE(@IsActive, isactive),  
   
            assistant_id = COALESCE(@AssistantId, assistant_id),  
   
            modifiedon = GETDATE(),  
   
            modifiedby = NULLIF(@UserId,0) 
           -- summary_prompt = COALESCE(@SummaryPrompt, summary_prompt)  
   
        WHERE id = @ProvidedBotId;  
        SET @BotId = @ProvidedBotId;  
   
        SET @Action = 'update';  
