      -- MODE: voice - Update voice configuration (requires existing bot)  
   ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'voice'  
        BEGIN  
            IF @BotExists = 0  
            BEGIN  
                RAISERROR('botId is required and bot must exist for voice mode.', 16, 1);  
                ROLLBACK TRANSACTION;  
                RETURN;  
            END  
  
            set @VoiceConfig  = JSON_QUERY(@payload, '$.voiceConfig');  
              
            IF @VoiceConfig IS NULL  
                SET @VoiceConfig = JSON_QUERY(@payload);  
  
            UPDATE dbo.voice_bot_details  
            SET  
                VoiceConfig = COALESCE(@VoiceConfig, VoiceConfig),  
                modifiedon = GETDATE(),  
                modifiedby = NULLIF(@UserId, 0)  
            WHERE id = @ProvidedBotId;  
  
            SET @BotId = @ProvidedBotId;  
            SET @Action = 'update';  
        END  
  
        -- MODE: language - Update language configuration (requires existing bot)  
        ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'language'  
        BEGIN  
            IF @BotExists = 0  
            BEGIN  
                RAISERROR('botId is required and bot must exist for language mode.', 16, 1);  
                ROLLBACK TRANSACTION;  
                RETURN;  
            END  
  
            set @LanguageConfig  = JSON_QUERY(@payload, '$.languageConfig');  
              
            IF @LanguageConfig IS NULL  
                SET @LanguageConfig = JSON_QUERY(@payload);  
  
            UPDATE dbo.voice_bot_details  
            SET  
                LanguageConfig = COALESCE(@LanguageConfig, LanguageConfig),  
                modifiedon = GETDATE(),  
                modifiedby = NULLIF(@UserId, 0)  
            WHERE id = @ProvidedBotId;  
  
            SET @BotId = @ProvidedBotId;  
            SET @Action = 'update';  
        END  
  
        -- MODE: handoff - Update handoff rules (requires existing bot)  
    ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'handoff'  
BEGIN  
    IF @BotExists = 0  
    BEGIN  
        RAISERROR('botId is required and bot must exist for handoff mode.', 16, 1);  
        ROLLBACK TRANSACTION;  
        RETURN;  
    END  

    DECLARE @HandoffRules NVARCHAR(MAX) = JSON_QUERY(@payload, '$.handoffRules');  
    DECLARE @Greeting NVARCHAR(MAX) = JSON_VALUE(@payload, '$.greetings');  
    DECLARE @GreetingPath NVARCHAR(500) = JSON_VALUE(@payload, '$.greeting_path');  

    -- fallback if direct JSON passed
    IF @HandoffRules IS NULL  
        SET @HandoffRules = JSON_QUERY(@payload);  

    UPDATE dbo.voice_bot_details  
    SET  
        HandoffRules = COALESCE(@HandoffRules, HandoffRules),  
        greetings = COALESCE(@Greeting, greetings),  
        --greeting_path = COALESCE(@GreetingPath, greeting_path),  
        modifiedon = GETDATE(),  
        modifiedby = NULLIF(@UserId, 0)  
    WHERE id = @ProvidedBotId;  

    SET @BotId = @ProvidedBotId;  
    SET @Action = 'update';  
END
  

  ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'goalsettings'
BEGIN
    IF @BotExists = 0
    BEGIN
        RAISERROR('botId is required for goalsettings mode.',16,1);
        ROLLBACK TRANSACTION;
        RETURN;
    END

    DECLARE @GoalName NVARCHAR(200)
    DECLARE @GoalSlots NVARCHAR(MAX)
    DECLARE @TriggerSettings NVARCHAR(MAX)

    -- Extract values
    SET @GoalName = JSON_VALUE(@payload,'$.goalName')

    SET @GoalSlots = JSON_QUERY(@payload,'$.goalSlots')

    SET @TriggerSettings = JSON_QUERY(@payload,'$.triggers')
    --SET @SummaryPrompt = JSON_QUERY(@payload,'$.summaryPrompt');   

    UPDATE voice_bot_details
    SET
        goalname = COALESCE(@GoalName, goalname),
        goalSlotSettings = COALESCE(@GoalSlots, goalSlotSettings),
        triggreseting = COALESCE(@TriggerSettings, triggreseting),
        modifiedon = GETDATE(),
        modifiedby = NULLIF(@UserId,0),
        summary_prompt= @ActivePrompt
    WHERE id = @ProvidedBotId

    ---------------------------------------------
-- STEP 1: Get Goal Slots JSON
---------------------------------------------


SET @GoalSlots = JSON_QUERY(@payload, '$.goalSlots')

---------------------------------------------
-- STEP 2: Delete old slots (for same bot)
---------------------------------------------
DELETE FROM tbl_ai_GoalSlots
WHERE GoalId = @ProvidedBotId
  AND IsDeleted = 0

---------------------------------------------
-- STEP 3: Insert new slots (row-wise)
---------------------------------------------
INSERT INTO tbl_ai_GoalSlots
(
    ParentId,
    GoalId,
    Name,
    Label,
    IsMandatory,
    IsUpdatable,
    DetailsJson,
    CreatedOn,
    CreatedBy,
    IsDeleted,
    botType
)
SELECT
    @ParentId,
    @ProvidedBotId,   -- GoalId = BotId
    JSON_VALUE(value, '$.name'),
    JSON_VALUE(value, '$.label'),
    0,                -- Mandatory always 0
    1,                -- Updatable always 1
    value,            -- full JSON stored
    GETDATE(),
    NULLIF(@UserId,0),
    0,
    'voicebot'
FROM OPENJSON(@GoalSlots)


    SET @BotId = @ProvidedBotId
    SET @Action = 'update'
END
            
  
