            moh_path,  
  
            assistant_id,  
  
            alias_id  
  
        FROM voice_bot_details  
  
        WHERE id = 1;  
   
        SET @BotId = (SELECT TOP 1 InsertedId FROM @InsertedIds ORDER BY InsertedId DESC);  
  
        SET @Action = 'insert';  
   
    END    
   
END  
   
  
-- MODE: savequickdemoagent - Insert predefined demo agent  
   ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'savequickdemoagent_old'  
  
BEGIN  
   
   -- DECLARE @PrimaryLanguage NVARCHAR(50);  
  
    --DECLARE @Prompt NVARCHAR(MAX);  
  
    DECLARE @ExistingBotId BIGINT;  
  
    DECLARE @ExistingPrompt NVARCHAR(MAX);  
   
    -------------------------------------------  
  
    -- Get company name  
  
    -------------------------------------------  
  
    SELECT TOP 1  
  
        @CompanyName = CompnayName  
  
    FROM user_detail  
  
    WHERE ParentID = @ParentId OR User_ID = @UserId;  
   
    IF ISNULL(@CompanyName,'') = ''  
  
        SET @CompanyName = 'Demo Company';  
   
    -------------------------------------------  
  
    -- JSON values  
  
    -------------------------------------------  
  
    SET @PrimaryLanguage = JSON_VALUE(@payload,'$.PrimaryLanguage');  
  
    SET @Prompt = JSON_VALUE(@payload,'$.Prompt');  
   
    -------------------------------------------  
  
    -- Check existing bot for ParentId  
  
    -------------------------------------------  
  
    SELECT TOP 1  
  
        @ExistingBotId = id,  
  
        @ExistingPrompt = JSON_VALUE(ActivePrompts,'$[0].Prompt')  
  
    FROM voice_bot_details  
  
    WHERE parentid = @ParentId  
  
    ORDER BY id DESC;  
   
    -------------------------------------------  
  
    -- If frontend not sending prompt  
  
    -- use existing saved prompt  
  
    -------------------------------------------  
  
    IF ISNULL(@Prompt,'') = ''  
  
        SET @Prompt = ISNULL(@ExistingPrompt,'');  
   
    -------------------------------------------  
  
    -- Build language config  
  
    -------------------------------------------  
  
    SET @LanguageConfig =  
  
    '{  
  
      "PrimaryLanguage": "' + ISNULL(@PrimaryLanguage,'hi-IN') + '",  
  
      "FallbackLanguages": ["en-IN","en-US"],  
  
      "SupportedLanguages": [  
  
        {"Code":"' + ISNULL(@PrimaryLanguage,'hi-IN') + '","Name":"Telugu","IsDefault":true},  
  
        {"Code":"en-IN","Name":"English (India)","IsDefault":false}  
  
      ]  
  
    }';  
   
    set @VoiceConfig='{  
  
  "Provider": "elevenlabs-ws",  
  
  "VoiceId": "Zjj2iX3aHYDcJSG4mMzk",  
  
  "Model": "eleven_flash_v2_5",  
  
  "LanguageCode": "hi-IN",  
  
  "Stability": 0.5,  
  
  "SimilarityBoost": 0.75,  
  
  "Speed": 1.10,  
  
  "UseSpeakerBoost": true,  
  
  "StreamingEnabled": true,  
  
  "ChunkSizeMs": 20  
  
}'  
  
    ------------------------------------------------------  
  
    -- UPDATE EXISTING BOT (if already present)  
  
    ------------------------------------------------------  
  
    IF ISNULL(@ExistingBotId,0) > 0  
  
    BEGIN  
   
        UPDATE voice_bot_details  
  
        SET  
  
            Bot_name = @CompanyName,  
  
            VoiceConfig=@VoiceConfig,  
  
            Description = @CompanyName + ' Bot',  
  
            LanguageConfig = @LanguageConfig,  
  
            ActivePrompts = N'[{"Prompt":"' + ISNULL(@Prompt,'') + '"}]',  
  
            modifiedby = NULLIF(@UserId,0),  
  
            modifiedon = GETDATE(),  
  
            SystemPrompt =  
  
                'You are a female sales assistant for ' + @CompanyName +  
  
                ', a company that deals in ' + @CompanyName  
  
        WHERE id = @ExistingBotId;  
   
        SET @BotId = @ExistingBotId;  
  
        SET @Action = 'update';  
   
    END  
  
    ELSE  
  
    BEGIN  
   
        --------------------------------------------------  
  
        -- INSERT NEW BOT (first time only)  
  
        --------------------------------------------------  
  
        DELETE FROM @InsertedIds;  
   
        INSERT INTO dbo.voice_bot_details  
  
        (  
  
            Bot_name,  
  
            Description,  
  
            VoiceConfig,  
  
            LanguageConfig,  
  
            HandoffRules,  
  
            ActivePrompts,  
  
            BusinessRules,  
  
            parentid,  
  
            createdon,  
  
            createdby,  
  
            modifiedby,  
  
            modifiedon,  
  
            bot_settings,  
  
            isactive,  
  
            bot_sp,  
  
            CallTerminationSettings,  
  
            STT_Config,  
  
            WelcomeMessagePath,  
  
            SystemPrompt,  
  
            moh_path,  
  
            assistant_id,  
  
            alias_id  
  
        )  
  
        OUTPUT INSERTED.id INTO @InsertedIds(InsertedId)  
  
        SELECT  
  
            @CompanyName,  
  
            @CompanyName + ' Bot',  
  
            @VoiceConfig,  
  
            @LanguageConfig,  
  
            '{  
  
              "transfer_number":"0",  
  
              "handoff_message":"Just a moment, Let me transfer the call to an agent"  
  
            }',  
  
            N'[{"Prompt":"' + ISNULL(@Prompt,'') + '"}]',  
  
            '{}',  
  
            @ParentId,  
  
            GETDATE(),  
  
            NULLIF(@UserId,0),  
  
            NULLIF(@UserId,0),  
  
            GETDATE(),  
  
            bot_settings,  
  
            isactive,  
  
            bot_sp,  
  
            CallTerminationSettings,  
  
            STT_Config,  
  
            WelcomeMessagePath,  
  
            'You are a female sales assistant for ' + @CompanyName +  
  
            ', a company that deals in ' + @CompanyName,  
  
            moh_path,  
  
            assistant_id,  
  
            alias_id  
  
        FROM voice_bot_details  
  
        WHERE id = 1;  
   
        SET @BotId = (SELECT TOP 1 InsertedId FROM @InsertedIds ORDER BY InsertedId DESC);  
  
        SET @Action = 'insert';  
   
    END  
   
END  
  
  ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'getquickdemoagentprompt'  
  
