-- MODE: getlatestdemoconversation  
  
ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'getlatestdemoconversation'  
  
BEGIN  
   
    --DECLARE  
    --@AudienceId BIGINT;  
  
   set @BotId = TRY_CONVERT(BIGINT, JSON_VALUE(@payload,'$.botId'));  
  
    DECLARE @CallLogId BIGINT;  
   
    --------------------------------------------------  
  
    -- 1?? Get LATEST processed demo request  
  
    --------------------------------------------------  
  
    SELECT TOP 1  
  
        @AudienceId = audienceid,  
  
        @BotId = BotId  
  
    FROM dbo.tbl_Voice_bot_demorequest WITH(NOLOCK)  
  
    WHERE BotId = @BotId  
  
      AND IsProcessed = 1  
  
    ORDER BY CreatedOn DESC;  
   
    --------------------------------------------------  
  
    -- 2?? Get LATEST call for that audience  
  
    --------------------------------------------------  
  
    SELECT TOP 1  
  
        @CallLogId = id  
  
    FROM dbo.calllog WITH(NOLOCK)  
  
    WHERE audienceid = @AudienceId  
  
      AND bot_id = @BotId  
  
    ORDER BY Callstarttime DESC;  
   
    --------------------------------------------------  
  
    -- 3?? Return FULL conversation  
  
    --------------------------------------------------  
  
    SELECT  
  
        id,  
  
        calllog_id,  
  
        turn_number,  
  
        user_input,  
  
        bot_response,  
  
        created_at,  
  
        sentiment_score,  
  
        ChatAgentInputTokens,  
  
        ChatAgentOutputTokens,  
  
        TTSCharacters  
  
    FROM dbo.voice_bot_conversation_turns WITH(NOLOCK)  
  
    WHERE calllog_id = @CallLogId  
  
    ORDER BY turn_number;  
   
    RETURN;  
  
END  
   
   
  
  
        -- MODE: prompts - Update active prompts (requires existing bot)  
     ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'prompts'  
        BEGIN  
            IF @BotExists = 0  
            BEGIN  
                RAISERROR('botId is required and bot must exist for prompts mode.', 16, 1);  
                ROLLBACK TRANSACTION;  
                RETURN;  
            END  
  
            DECLARE @ActivePrompts NVARCHAR(MAX) = JSON_QUERY(@payload, '$.activePrompts');  
              
            IF @ActivePrompts IS NULL  
                SET @ActivePrompts = JSON_QUERY(@payload);  
  
            UPDATE dbo.voice_bot_details  
            SET  
                ActivePrompts = COALESCE(@ActivePrompts, ActivePrompts),  
                modifiedon = GETDATE(),  
                modifiedby = NULLIF(@UserId, 0)  
            WHERE id = @ProvidedBotId;  
  
            SET @BotId = @ProvidedBotId;  
            SET @Action = 'update';  
  
            -- Return count of active prompts if present  
            IF ISJSON(@ActivePrompts) = 1  
            BEGIN  
                DECLARE @pc INT = 0;  
                SELECT @pc = COUNT(1) FROM OPENJSON(@ActivePrompts);  
                SET @ReturnPersonaCount = @pc;  
            END  
        END  
  
        -- MODE: businessrules - Update business rules (requires existing bot)  
        ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'businessrules'  
        BEGIN  
            IF @BotExists = 0  
            BEGIN  
                RAISERROR('botId is required and bot must exist for businessrules mode.', 16, 1);  
                ROLLBACK TRANSACTION;  
                RETURN;  
            END  
  
            DECLARE @BusinessRules NVARCHAR(MAX) = JSON_QUERY(@payload, '$.businessRules');  
              
            IF @BusinessRules IS NULL  
                SET @BusinessRules = JSON_QUERY(@payload);  
  
            UPDATE dbo.voice_bot_details  
            SET  
                BusinessRules = COALESCE(@BusinessRules, BusinessRules),  
                modifiedon = GETDATE(),  
                modifiedby = NULLIF(@UserId, 0)  
            WHERE id = @ProvidedBotId;  
  
            SET @BotId = @ProvidedBotId;  
            SET @Action = 'update';  
        END  
  
        -- MODE: settings - Update bot settings (requires existing bot)  
        ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'settings'  
        BEGIN  
            IF @BotExists = 0  
            BEGIN  
                RAISERROR('botId is required and bot must exist for settings mode.', 16, 1);  
                ROLLBACK TRANSACTION;  
                RETURN;  
            END  
  
            DECLARE @BotSettings NVARCHAR(MAX) = JSON_QUERY(@payload, '$.botSettings');  
              
            IF @BotSettings IS NULL  
                SET @BotSettings = JSON_QUERY(@payload);  
  
            UPDATE dbo.voice_bot_details  
            SET  
                bot_settings = COALESCE(@BotSettings, bot_settings),  
                modifiedon = GETDATE(),  
                modifiedby = NULLIF(@UserId, 0)  
            WHERE id = @ProvidedBotId;  
  
            SET @BotId = @ProvidedBotId;  
            SET @Action = 'update';  
        END  
  
        -- MODE: termination - Update call termination settings (requires existing bot)  
        ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'termination'  
        BEGIN  
            IF @BotExists = 0  
            BEGIN  
                RAISERROR('botId is required and bot must exist for termination mode.', 16, 1);  
                ROLLBACK TRANSACTION;  
                RETURN;  
            END  
  
            DECLARE @CallTerminationSettings NVARCHAR(MAX) = JSON_QUERY(@payload, '$.callTerminationSettings');  
              
            IF @CallTerminationSettings IS NULL  
                SET @CallTerminationSettings = JSON_QUERY(@payload);  
  
            UPDATE dbo.voice_bot_details  
            SET  
                CallTerminationSettings = COALESCE(@CallTerminationSettings, CallTerminationSettings),  
                modifiedon = GETDATE(),  
                modifiedby = NULLIF(@UserId, 0)  
            WHERE id = @ProvidedBotId;  
  
            SET @BotId = @ProvidedBotId;  
            SET @Action = 'update';  
        END  
  
        -- MODE: stt - Update Speech-to-Text configuration (requires existing bot)  
        ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'stt'  
        BEGIN  
            IF @BotExists = 0  
            BEGIN  
                RAISERROR('botId is required and bot must exist for stt mode.', 16, 1);  
                ROLLBACK TRANSACTION;  
                RETURN;  
            END  
  
            SET @STTConfig = JSON_QUERY(@payload, '$.sttConfig');  
              
            IF @STTConfig IS NULL  
                SET @STTConfig = JSON_QUERY(@payload);  
  
            UPDATE dbo.voice_bot_details  
            SET  
                STT_Config = COALESCE(@STTConfig, STT_Config),  
                modifiedon = GETDATE(),  
                modifiedby = NULLIF(@UserId, 0)  
            WHERE id = @ProvidedBotId;  
  
            SET @BotId = @ProvidedBotId;  
            SET @Action = 'update';  
        END  
  
        -- MODE: systemprompt - Update system prompt (requires existing bot)  
        ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'systemprompt'  
        BEGIN  
            IF @BotExists = 0  
            BEGIN  
                RAISERROR('botId is required and bot must exist for systemprompt mode.', 16, 1);  
                ROLLBACK TRANSACTION;  
                RETURN;  
            END  
  
            set @SystemPrompt  = NULL;  
  
            IF ISJSON(@effectivePayload) = 1  
            BEGIN  
                SET @SystemPrompt = COALESCE(  
                    JSON_VALUE(@effectivePayload, '$.systemPrompt'),  
                    JSON_VALUE(@effectivePayload, '$.prompt'),  
                    JSON_VALUE(@effectivePayload, '$.instruction')  
                );  
            END  
            ELSE  
            BEGIN  
                SET @SystemPrompt = LTRIM(RTRIM(@effectivePayload));  
            END  
  
            UPDATE dbo.voice_bot_details  
            SET  
                SystemPrompt = COALESCE(@SystemPrompt, SystemPrompt),  
                modifiedon = GETDATE(),  
                modifiedby = NULLIF(@UserId, 0)  
            WHERE id = @ProvidedBotId;  
  
            SET @BotId = @ProvidedBotId;  
            SET @Action = 'update';  
        END  
  
        -- MODE: welcome - Update welcome message path (requires existing bot)  
        ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'welcome'  
        BEGIN  
            IF @BotExists = 0  
            BEGIN  
                RAISERROR('botId is required and bot must exist for welcome mode.', 16, 1);  
                ROLLBACK TRANSACTION;  
                RETURN;  
            END  
  
            UPDATE dbo.voice_bot_details  
            SET  
                WelcomeMessagePath = COALESCE(@WelcomeMessagePath, WelcomeMessagePath),  
                modifiedon = GETDATE(),  
                modifiedby = NULLIF(@UserId, 0)  
            WHERE id = @ProvidedBotId;  
  
            SET @BotId = @ProvidedBotId;  
            SET @Action = 'update';  
        END  
  
        -- MODE: moh - Update music on hold path (requires existing bot)  
        ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'moh'  
        BEGIN  
            IF @BotExists = 0  
            BEGIN  
                RAISERROR('botId is required and bot must exist for moh mode.', 16, 1);  
                ROLLBACK TRANSACTION;  
                RETURN;  
            END  
  
            UPDATE dbo.voice_bot_details  
            SET  
                moh_path = COALESCE(@MohPath, moh_path),  
                modifiedon = GETDATE(),  
                modifiedby = NULLIF(@UserId, 0)  
            WHERE id = @ProvidedBotId;  
  
            SET @BotId = @ProvidedBotId;  
            SET @Action = 'update';  
        END  
  
        -- MODE: botsp - Update bot stored procedure (requires existing bot)  
        ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'botsp'  
        BEGIN  
            IF @BotExists = 0  
            BEGIN  
                RAISERROR('botId is required and bot must exist for botsp mode.', 16, 1);  
                ROLLBACK TRANSACTION;  
                RETURN;  
            END  
  
            UPDATE dbo.voice_bot_details  
            SET  
                bot_sp = COALESCE(@BotSp, bot_sp),  
                modifiedon = GETDATE(),  
                modifiedby = NULLIF(@UserId, 0)  
            WHERE id = @ProvidedBotId;  
  
            SET @BotId = @ProvidedBotId;  
            SET @Action = 'update';  
        END  
  
        -- MODE: full - Insert or Update all configurations  
        ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'full'  
        BEGIN  
            IF @BotExists = 0  
            BEGIN  
                -- INSERT new bot with all configurations  
                DELETE FROM @InsertedIds;  
                INSERT INTO dbo.voice_bot_details (  
                    Bot_name,  
                    Description,  
                    VoiceConfig,  
                    LanguageConfig,  
                    HandoffRules,  
                    ActivePrompts,  
                    BusinessRules,  
                    bot_settings,  
                    CallTerminationSettings,  
                    STT_Config,  
                    WelcomeMessagePath,  
                    SystemPrompt,  
                    moh_path,  
                    bot_sp,  
                    assistant_id,  
                    isactive,  
                    parentid,  
                    createdon,  
                    createdby  
                )  
                OUTPUT INSERTED.id INTO @InsertedIds(InsertedId)  
                VALUES (  
                    @BotName,  
                    @Description,  
                    JSON_QUERY(@payload, '$.voiceConfig'),  
                    JSON_QUERY(@payload, '$.languageConfig'),  
                    JSON_QUERY(@payload, '$.handoffRules'),  
                    JSON_QUERY(@payload, '$.activePrompts'),  
                    JSON_QUERY(@payload, '$.businessRules'),  
                    JSON_QUERY(@payload, '$.botSettings'),  
                    JSON_QUERY(@payload, '$.callTerminationSettings'),  
                    JSON_QUERY(@payload, '$.sttConfig'),  
                    @WelcomeMessagePath,  
                    JSON_VALUE(@payload, '$.systemPrompt'),  
                    @MohPath,  
                    @BotSp,  
                    @AssistantId,  
                    ISNULL(@IsActive, 1),  
                    @ParentId,  
                    GETDATE(),  
                    NULLIF(@UserId, 0)  
                );  
                SET @BotId = (SELECT TOP 1 InsertedId FROM @InsertedIds ORDER BY InsertedId DESC);  
                SET @Action = 'insert';  
            END  
            ELSE  
            BEGIN  
                -- UPDATE existing bot  
                UPDATE dbo.voice_bot_details  
                SET  
                    Bot_name = COALESCE(@BotName, Bot_name),  
                    Description = COALESCE(@Description, Description),  
                    VoiceConfig = COALESCE(JSON_QUERY(@payload, '$.voiceConfig'), VoiceConfig),  
                    LanguageConfig = COALESCE(JSON_QUERY(@payload, '$.languageConfig'), LanguageConfig),  
                    HandoffRules = COALESCE(JSON_QUERY(@payload, '$.handoffRules'), HandoffRules),  
                    ActivePrompts = COALESCE(JSON_QUERY(@payload, '$.activePrompts'), ActivePrompts),  
                    BusinessRules = COALESCE(JSON_QUERY(@payload, '$.businessRules'), BusinessRules),  
                    bot_settings = COALESCE(JSON_QUERY(@payload, '$.botSettings'), bot_settings),  
                    CallTerminationSettings = COALESCE(JSON_QUERY(@payload, '$.callTerminationSettings'), CallTerminationSettings),  
                    STT_Config = COALESCE(JSON_QUERY(@payload, '$.sttConfig'), STT_Config),  
                    WelcomeMessagePath = COALESCE(@WelcomeMessagePath, WelcomeMessagePath),  
                    SystemPrompt = COALESCE(JSON_VALUE(@payload, '$.systemPrompt'), SystemPrompt),  
                    moh_path = COALESCE(@MohPath, moh_path),  
                    bot_sp = COALESCE(@BotSp, bot_sp),  
                    assistant_id = COALESCE(@AssistantId, assistant_id),  
                    isactive = COALESCE(@IsActive, isactive),  
                    modifiedon = GETDATE(),  
                    modifiedby = NULLIF(@UserId, 0)  
                WHERE id = @ProvidedBotId;  
  
                SET @BotId = @ProvidedBotId;  
                SET @Action = 'update';  
            END  
        END  
  
  
  
ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'callflow'  
  
BEGIN  
   
   -- DECLARE   
  
    --@GreetingConfig NVARCHAR(MAX),  
  
    --  @HandoffRules NVARCHAR(MAX),  
  
           -- @CallTerminationSettings NVARCHAR(MAX)  
  
            --@MohPath NVARCHAR(MAX)  
   
    --SET @GreetingConfig = JSON_QUERY(@payload,'$.greetingConfig')  
   
    SET @HandoffRules = JSON_QUERY(@payload,'$.handoff')  
   
    SET @CallTerminationSettings = JSON_QUERY(@payload,'$.callTermination')  
   
    SET @MohPath = JSON_VALUE(@payload,'$.holdMusic.MusicPath')  
   
    UPDATE voice_bot_details  
  
    SET  
  
        --@GreetingConfig = COALESCE(@GreetingConfig,GreetingConfig),  
  
        HandoffRules = COALESCE(@HandoffRules,HandoffRules),  
  
        CallTerminationSettings = COALESCE(@CallTerminationSettings,CallTerminationSettings),  
  
        moh_path = COALESCE(@MohPath,moh_path),  
  
        modifiedon = GETDATE(),  
  
        modifiedby = NULLIF(@UserId,0)  
   
    WHERE id = JSON_VALUE(@payload,'$.botId')  
   
          SET @BotId = @ProvidedBotId;  
  
            SET @Action = 'update';  
   
END  
   
    ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'engine'
        BEGIN
            IF @BotExists = 0
            BEGIN
                RAISERROR('botId is required and bot must exist for engine mode.', 16, 1);
                ROLLBACK TRANSACTION;
                RETURN;
            END

            DECLARE @EngineSettings NVARCHAR(MAX) = JSON_QUERY(@payload, '$.engineSettings');

            IF @EngineSettings IS NOT NULL AND LEN(LTRIM(RTRIM(@EngineSettings))) > 2
            BEGIN
                DECLARE @MergedSettings NVARCHAR(MAX);

                SELECT @MergedSettings =
                    JSON_MODIFY(
                    JSON_MODIFY(
                    JSON_MODIFY(
                    JSON_MODIFY(
                    JSON_MODIFY(
                        ISNULL(bot_settings, N'{}'),
                        '$.generatePreciseTranscript',     JSON_VALUE(@EngineSettings, '$.generatePreciseTranscript')),
                        '$.wordsToWaitBeforeInterrupting', JSON_VALUE(@EngineSettings, '$.wordsToWaitBeforeInterrupting')),
                        '$.responseRate',                  JSON_VALUE(@EngineSettings, '$.responseRate')),
                        '$.endpointingMs',                 JSON_VALUE(@EngineSettings, '$.endpointingMs')),
                        '$.linearDelayMs',                 JSON_VALUE(@EngineSettings, '$.linearDelayMs')
                    )
                FROM dbo.voice_bot_details
                WHERE id = @ProvidedBotId;

                UPDATE dbo.voice_bot_details
                SET  bot_settings = @MergedSettings,
                     modifiedon   = GETDATE(),
                     modifiedby   = NULLIF(@UserId, 0)
                WHERE id = @ProvidedBotId;
            END

            SET @BotId  = @ProvidedBotId;
            SET @Action = 'update';
        END
   
  
        ELSE  
        BEGIN  
            RAISERROR('Invalid mode specified. Valid modes: basic, voice, language, handoff, prompts, businessrules, settings, termination, stt, systemprompt, welcome, moh, botsp, full', 16, 1);  
            ROLLBACK TRANSACTION;  
            RETURN;  
        END  
  
          
         
         
         
       COMMIT TRANSACTION;  
  
        -- Return result using same column names as usp_ai_SaveAgentByMode  
        SELECT   
            @BotId AS AgentId,  
            @Action AS Action,  
            @ReturnGoalId AS GoalId,  
            @ReturnWidgetId AS WidgetId,  
            @ReturnPersonaCount AS PersonaCount,  
            @ReturnTriggerCount AS TriggerCount;  
  
    END TRY  
    BEGIN CATCH  
        IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;  
          
        DECLARE @ErrMsg NVARCHAR(4000) = ERROR_MESSAGE();  
        DECLARE @ErrLine INT = ERROR_LINE();  
        DECLARE @ErrProc NVARCHAR(200) = ERROR_PROCEDURE();  
          
        RAISERROR('usp_voice_SaveVoiceBotByMode failed at line %d in %s: %s', 16, 1, @ErrLine, @ErrProc, @ErrMsg);  
        RETURN;  
    END CATCH  
END  



GO

/* ============================================================
   Procedure: [dbo].[usp_Voice_schedule_Delete]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 
---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
CREATE   PROCEDURE [dbo].[usp_Voice_schedule_Delete]         
(           
  @batchid bigint,        
  @USERID bigint,        
  @cr_amt as float          
)        
as            
begin            
  
    declare @ParentID bigint = (select top 1 isnull(ParentID,0) from User_Detail with(nolock) where USER_ID = @USERID)          
    declare @MID_P bigint = (select top 1 isnull(M_ID,0) from User_Detail with(nolock) where USER_ID = @ParentID)             
	    
DECLARE @QUERY NVARCHAR(2000)          
          
DECLARE @M_ID BIGINT          
          
DECLARE         
               
                         
@PRIORITY TINYINT,                          
@ALLOWDND TINYINT,                      
@ScheduleDate VARCHAR(50),                      
@ScheduleTime VARCHAR(50),                  
@PageName nvarchar(50),                
@UserFilter varchar(20),            
@TableName varchar(100),        
@duration bigint,          
--@MESSAGE_LEN BIGINT  ,          
--@MESSAGE_LEN_TEMP BIGINT ,          
--@MESSAGE_LEN_MAXLEN BIGINT  ,          
--@MESSAGELEN_CLONE BIGINT ,          
@CHECK_SCHEDULE BIGINT,          
@DBType char(10),        
@parentsuperresellerid bigint,        
@hassufficientvirtualcredits int,        
@country_code varchar(10), @price float,        
@AppId bigint        
DECLARE @BalanceMsg float        
        
SELECT           
@BATCHID=BatchID,          
@ALLOWDND=IsAllowDND,          
@ScheduleDate=ScheduledDate,          
--@ScheduleTime=ScheduledTime,          
@USERID=USER_ID,        
@duration= voiceDuration,          
--@IsUnicode=IsUniCode,          
@PRIORITY=IsPrority,          
@PageName='CSV',          
@TableName='Clone_VoiceScheduleStatus',          
@DBType=1,         
@AppId =AppId          
FROM Clone_VoiceScheduleStatus with(nolock)       
where  batchid=@BATCHID          
declare @creditid as bigint        
        
declare @remark varchar(max)           
select @remark = 'Amount Credited for deletion of Scheduled Voice Brodcast Batchid '      
+CAST(@BATCHID as varchar(20))      
       
        
SELECT TOP(1) @UserFilter=UserFilter,@M_ID=M_ID        
FROM USER_DETAIL with (nolock) WHERE USER_ID=@ParentID         
        
delete from dbo.Clone_VoiceScheduleStatus where BatchID=@batchid        
update BatchVoiceInfo set Deleted=1 where BatchID=@batchid        
        
--set @creditid=(select max(Credit_ID) from IntCredit_Details         
--     where User_ID=@USERID)          
            
  select top 1 @BalanceMsg =  Balance from IntCredit_Details with(nolock) where User_ID=@ParentID  order by Credit_ID desc          
           --  and Credit_ID = @creditid            
           
                   
insert into IntCredit_Details(FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,Validity,Remarks,ICD_CreatedBy)      
     values(@ParentID,@MID_P,@ParentID,0,@cr_amt,@BalanceMsg+@cr_amt,99999,@remark,@USERID)  

declare @intCreditId bigint = scope_identity()
exec usp_rf_UpdateReserveFundTransaction @CreditId = @intCreditId
        
        
select 'Scheduled Voice Deleted'        
end          



GO

/* ============================================================
   Procedure: [dbo].[usp_Voice_SearchScheduled]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROC [dbo].[usp_Voice_SearchScheduled]   -- 335,'2019-1-1','2019-1-5'                                                            
--@m_id bigint, --nvarchar(50),                                                              
@user_id bigint, --nvarchar(50),                                                            
@fdate nvarchar(100),                                                            
@tdate nvarchar(100)                                                            
as                                         
begin                                                                                                                                                    
Declare @ErrNo Int,@Query varchar(2000),@whereClause varchar(500),@operator varchar(10)                                                                                                                                  
Set Nocount on                                           
DECLARE @QUERY_FOR_BATCHINFO NVARCHAR(MAX)                                
DECLARE @TABLENAME VARCHAR(100)                               
                                                                                                                             
If (@fdate !='' and @tdate !='')                                                                
Begin                                          
 SELECT  TABLENAME,BATCHID,isPrority,VoiceCredit,ScheduledDate, ap.AppName,        
 BatchInsertTime, TotalRecords FROM BatchVoiceInfo bi        
  inner join dbo.Cloud_app_master ap on ap.AppId= bi.AppId WHERE isnull(isscheduleProcess,0)=0     
  AND USERID=@user_id and Deleted=0 and Convert(date,ScheduledDate)     
  between  CONVERT(date,@fdate)  and  CONVERT(date,@tdate)             
Set @ErrNo = @@error                                                                 
                                      
End                                                                
Else                                                                
Begin                                                     
                                                          
 Set @ErrNo = @@error                                                                
End       
    
        
                                   
                                  
End   


GO

/* ============================================================
   Procedure: [dbo].[usp_Voice_TelephonyByMode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Voice_TelephonyByMode]
(
    @Mode NVARCHAR(50),
    @UserId BIGINT = NULL,
    @JsonData NVARCHAR(MAX) = NULL
)
AS
BEGIN
    SET NOCOUNT ON;
    BEGIN TRY
        -- Declare variables once
        DECLARE
            @ph_sipname    NVARCHAR(200),
            @telephony_config NVARCHAR(MAX),
            @isactive      BIT,
            @id            INT,
            @topN          INT,
            @Operator      NVARCHAR(200),
            @PhoneNo       NVARCHAR(50),
            @PhoneType     NVARCHAR(50),
            @Category      NVARCHAR(100),
            @Active        BIT,
            @PhServer      NVARCHAR(200),
            @ContryCode      NVARCHAR(200),
            @PhSipName     NVARCHAR(200),
            @ReservedFor   NVARCHAR(200), -- maps incoming ph_country JSON
            @PhoneId       INT,
            @ParentId      INT,
            @PurchaseDt    DATETIME,
            @AppId         INT,
            @IsDefault     BIT,
            @UserPhId      INT,
            @VoiceBotId    INT;

        IF LOWER(ISNULL(@Mode,'')) = 'gettelephonyproviders'
        BEGIN
            SELECT id, ph_sipname, telephony_config, isactive, createdon
            FROM dbo.sip_telephony_providers WITH (NOLOCK)
            ORDER BY id;
            RETURN;
        END

        IF LOWER(ISNULL(@Mode,'')) = 'inserttelephonyprovider'
        BEGIN
            SET @ph_sipname = JSON_VALUE(@JsonData, '$.ph_sipname');
            SET @telephony_config = JSON_VALUE(@JsonData, '$.telephony_config');
            SET @isactive = ISNULL(
                CASE LOWER(ISNULL(JSON_VALUE(@JsonData,'$.isactive'), ''))
                     WHEN '1' THEN 1 WHEN 'true' THEN 1 ELSE 0 END, 1);

            INSERT INTO dbo.sip_telephony_providers (ph_sipname, telephony_config, isactive, createdon)
            VALUES (@ph_sipname, @telephony_config, @isactive, GETDATE());

            SELECT CAST(SCOPE_IDENTITY() AS BIGINT) AS InsertedId;
            RETURN;
        END

        IF LOWER(ISNULL(@Mode,'')) = 'updatetelephonyprovider'
        BEGIN
            SET @id = TRY_CAST(JSON_VALUE(@JsonData,'$.id') AS INT);
            SET @ph_sipname = JSON_VALUE(@JsonData, '$.ph_sipname');
            SET @telephony_config = JSON_VALUE(@JsonData, '$.telephony_config');
            SET @isactive = ISNULL(
                CASE LOWER(ISNULL(JSON_VALUE(@JsonData,'$.isactive'), ''))
                     WHEN '1' THEN 1 WHEN 'true' THEN 1 ELSE 0 END, 1);

            UPDATE dbo.sip_telephony_providers
            SET ph_sipname = ISNULL(@ph_sipname, ph_sipname),
                telephony_config = ISNULL(@telephony_config, telephony_config),
                isactive = @isactive
            WHERE id = @id;

            SELECT @@ROWCOUNT AS RowsAffected;
            RETURN;
        END

        IF LOWER(ISNULL(@Mode,'')) = 'deletetelephonyprovider'
        BEGIN
            SET @id = TRY_CAST(JSON_VALUE(@JsonData,'$.id') AS INT);
            DELETE FROM dbo.sip_telephony_providers WHERE id = @id;
            SELECT @@ROWCOUNT AS RowsAffected;
            RETURN;
        END

        -- Cloud_phone_master operations
        IF LOWER(ISNULL(@Mode,'')) = 'getcloudphonemaster'
        BEGIN
            SET @topN = TRY_CAST(JSON_VALUE(@JsonData,'$.top') AS INT);
            IF @topN IS NULL OR @topN <= 0 SET @topN = 10; -- default

            ;WITH cte AS (
                SELECT PhoneId, Operator, PhoneNo, PhoneType, Category, Active, CreatedDate, ph_server, ph_sipname, reservedfor,
                       ROW_NUMBER() OVER (ORDER BY PhoneId DESC) rn
                FROM dbo.Cloud_phone_master WITH (NOLOCK)
            )
            SELECT PhoneId, Operator, PhoneNo, PhoneType, Category, Active, CreatedDate, ph_server, ph_sipname, reservedfor
            FROM cte
            WHERE rn <= @topN
            ORDER BY PhoneId DESC;
            RETURN;
        END

        IF LOWER(ISNULL(@Mode,'')) = 'insertcloudphonemaster'
        BEGIN
            SET @Operator = JSON_VALUE(@JsonData, '$.operator');
            SET @PhoneNo = JSON_VALUE(@JsonData, '$.phoneNo');
            SET @PhoneType = JSON_VALUE(@JsonData, '$.phoneType');
            SET @Category = JSON_VALUE(@JsonData, '$.category');
            SET @ContryCode = JSON_VALUE(@JsonData, '$.CountryCode');
            SET @Active = ISNULL(
                CASE LOWER(ISNULL(JSON_VALUE(@JsonData,'$.active'), ''))
                     WHEN '1' THEN 1 WHEN 'true' THEN 1 ELSE 0 END, 1);
            SET @PhServer = JSON_VALUE(@JsonData, '$.ph_server');
            SET @PhSipName = JSON_VALUE(@JsonData, '$.ph_spiname'); -- JSON key preserved
            SET @ReservedFor = JSON_VALUE(@JsonData, '$.ph_country'); -- map to reservedfor column

            INSERT INTO dbo.Cloud_phone_master (Operator, PhoneNo,ph_countrycode, PhoneType, Active, CreatedDate, ph_server, ph_sipname, reservedfor,is_customer_owned,free,Category)
            VALUES (@Operator, @PhoneNo,@ContryCode,'normal', @Active, GETDATE(), 'Bot', @Operator, @ReservedFor,1,0,'Landline');

            SELECT CAST(SCOPE_IDENTITY() AS BIGINT) AS InsertedId;
            RETURN;
        END

        IF LOWER(ISNULL(@Mode,'')) = 'updatecloudphonemaster'
        BEGIN
            SET @PhoneId = TRY_CAST(JSON_VALUE(@JsonData,'$.phoneId') AS INT);
            SET @Operator = JSON_VALUE(@JsonData, '$.operator');
            SET @PhoneNo = JSON_VALUE(@JsonData, '$.phoneNo');
            SET @PhoneType = JSON_VALUE(@JsonData, '$.phoneType');
            SET @Category = JSON_VALUE(@JsonData, '$.category');
            SET @Active = ISNULL(
                CASE LOWER(ISNULL(JSON_VALUE(@JsonData,'$.active'), ''))
                     WHEN '1' THEN 1 WHEN 'true' THEN 1 ELSE 0 END, 1);
            SET @PhServer = JSON_VALUE(@JsonData, '$.ph_server');
            SET @PhSipName = JSON_VALUE(@JsonData, '$.ph_spiname');
            SET @ReservedFor = JSON_VALUE(@JsonData, '$.ph_country');

            UPDATE dbo.Cloud_phone_master
            SET Operator = ISNULL(@Operator, Operator),
                PhoneNo = ISNULL(@PhoneNo, PhoneNo),
                PhoneType = ISNULL(@PhoneType, PhoneType),
                Category = ISNULL(@Category, Category),
                Active = @Active,
                ph_server = ISNULL(@PhServer, ph_server),
                ph_sipname = ISNULL(@PhSipName, ph_sipname),
                reservedfor = ISNULL(@ReservedFor, reservedfor),
               is_customer_owned = 1
            WHERE PhoneId = @PhoneId;

            SELECT @@ROWCOUNT AS RowsAffected;
            RETURN;
        END

        IF LOWER(ISNULL(@Mode,'')) = 'deletecloudphonemaster'
        BEGIN
            SET @PhoneId = TRY_CAST(JSON_VALUE(@JsonData,'$.phoneId') AS INT);
            DELETE FROM dbo.Cloud_phone_master WHERE PhoneId = @PhoneId;
            SELECT @@ROWCOUNT AS RowsAffected;
            RETURN;
        END

        IF LOWER(ISNULL(@Mode,'')) = 'getclouduserphone'
        BEGIN
            SELECT userphid, Parentid, PhoneNo, PurchaseDt, AppId, Active, IsDefault
            FROM dbo.Cloud_User_Phone WITH (NOLOCK)
            WHERE (@UserId IS NULL OR Parentid = @UserId)
            ORDER BY userphid DESC;
            RETURN;
        END

        IF LOWER(ISNULL(@Mode,'')) = 'insertclouduserphone'
        BEGIN
            SET @ParentId = TRY_CAST(JSON_VALUE(@JsonData,'$.parentId') AS INT);
            SET @PhoneNo = JSON_VALUE(@JsonData, '$.phoneNo');
            SET @PurchaseDt = TRY_CAST(JSON_VALUE(@JsonData,'$.purchaseDt') AS DATETIME);
            SET @AppId = TRY_CAST(JSON_VALUE(@JsonData,'$.appId') AS INT);
            SET @VoiceBotId = TRY_CAST(JSON_VALUE(@JsonData,'$.voicebotid') AS INT);
            SET @Active = ISNULL(
                CASE LOWER(ISNULL(JSON_VALUE(@JsonData,'$.active'), ''))
                     WHEN '1' THEN 1 WHEN 'true' THEN 1 ELSE 0 END, 1);
            SET @IsDefault = ISNULL(
                CASE LOWER(ISNULL(JSON_VALUE(@JsonData,'$.isDefault'), ''))
                     WHEN '1' THEN 1 WHEN 'true' THEN 1 ELSE 0 END, 0);

            INSERT INTO dbo.Cloud_User_Phone (Parentid, PhoneNo, PurchaseDt, AppId, Active, IsDefault,voice_bot_id)
            VALUES (@ParentId, @PhoneNo, ISNULL(@PurchaseDt, GETDATE()), ISNULL(@AppId,0), @Active, @IsDefault,@VoiceBotId);

            SELECT CAST(SCOPE_IDENTITY() AS BIGINT) AS InsertedId;
            RETURN;
        END

        IF LOWER(ISNULL(@Mode,'')) = 'updateclouduserphone'
        BEGIN
            --SET @UserPhId = TRY_CAST(JSON_VALUE(@JsonData,'$.userPhId') AS INT);
            SET @ParentId = TRY_CAST(JSON_VALUE(@JsonData,'$.parentId') AS INT);
            SET @PhoneNo = JSON_VALUE(@JsonData, '$.phoneNo');
            SET @PurchaseDt = TRY_CAST(JSON_VALUE(@JsonData,'$.purchaseDt') AS DATETIME);
            SET @AppId = TRY_CAST(JSON_VALUE(@JsonData,'$.appId') AS INT);
            SET @VoiceBotId = TRY_CAST(JSON_VALUE(@JsonData,'$.voicebotid') AS INT);
            SET @Active = ISNULL(
                CASE LOWER(ISNULL(JSON_VALUE(@JsonData,'$.active'), ''))
                     WHEN '1' THEN 1 WHEN 'true' THEN 1 ELSE 0 END, 1);
            SET @IsDefault = ISNULL(
                CASE LOWER(ISNULL(JSON_VALUE(@JsonData,'$.isDefault'), ''))
                     WHEN '1' THEN 1 WHEN 'true' THEN 1 ELSE 0 END, 0);

            UPDATE dbo.Cloud_User_Phone
            SET Parentid = ISNULL(@ParentId, Parentid),
                PhoneNo = ISNULL(@PhoneNo, PhoneNo),
                PurchaseDt = ISNULL(@PurchaseDt, PurchaseDt),
                AppId = ISNULL(@AppId, AppId),
                voice_bot_id = ISNULL(@VoiceBotId, voice_bot_id),
                Active = @Active,
                IsDefault = @IsDefault
            WHERE userphid = @UserPhId;

            SELECT @@ROWCOUNT AS RowsAffected;
            RETURN;
        END

        IF LOWER(ISNULL(@Mode,'')) = 'deleteclouduserphone'
        BEGIN
            SET @UserPhId = TRY_CAST(JSON_VALUE(@JsonData,'$.userPhId') AS INT);
            DELETE FROM dbo.Cloud_User_Phone WHERE userphid = @UserPhId;
            SELECT @@ROWCOUNT AS RowsAffected;
            RETURN;
        END

 IF LOWER(ISNULL(@Mode,'')) = 'getclouduserphonefordropdowns'
BEGIN
    SELECT 
        cup.userphid, 
        cup.Parentid, 
        cup.PhoneNo, 
        cup.PurchaseDt, 
        cup.AppId, 
        cup.Active, 
        cup.IsDefault
    FROM dbo.Cloud_User_Phone cup WITH (NOLOCK)
    INNER JOIN dbo.cloud_phone_master cpm WITH (NOLOCK)
        ON cup.PhoneNo = cpm.PhoneNo
    WHERE 
        (@UserId IS NULL OR cup.Parentid = @UserId)
        AND cpm.ph_server = 'bot'
    ORDER BY cup.userphid DESC;

    RETURN;
END


     
        RAISERROR('Unknown Mode: %s', 16, 1, @Mode);
    END TRY
    BEGIN CATCH
        DECLARE @ErrMsg NVARCHAR(4000) = ERROR_MESSAGE();
        DECLARE @ErrNum INT = ERROR_NUMBER();
        RAISERROR('Error (%d): %s', 16, 1, @ErrNum, @ErrMsg);
    END CATCH
END;







GO

/* ============================================================
   Procedure: [dbo].[usp_voice_UpdateCallSummaryProcessStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE dbo.usp_voice_UpdateCallSummaryProcessStatus
    @CallSummaryId bigint,
    @IsProcessed int,
    @ErrorDescription nvarchar(max) = null,
    @InternalError nvarchar(max) = null
as
begin
    update call_summaries
    set isprocessed = @IsProcessed,
        processedon = getutcdate(),
        error_descripton = @ErrorDescription,
        internal_error = @InternalError
    where id = @CallSummaryId
end



GO

/* ============================================================
   Procedure: [dbo].[usp_voicecdrsync]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_voicecdrsync    
as    
begin    
if OBJECT_ID('tempdb..##temp') is not null                  
 Begin     
 Drop table ##temp     
 end     
  
declare @t nvarchar(50)--=isnull((select max(calldate) from kit19cdr),isnull((select top 1 datesynced from cdrsync order by id desc),cast('20180101' as datetime )))    
select @t=convert(nvarchar(50),isnull((select max(calldate) from kit19cdr),isnull((select top 1 datesynced from cdrsync order by id desc),cast('20180101' as datetime ))),121 )    
--select @t    
declare @linkedserver nvarchar(10)='mysql'    
declare @timesynced datetime=getdate()    
--declare @sql nvarchar(max)='SELECT * into ##temp FROM OPENQUERY ('+ @LinkedServer + ','+'''SELECT * FROM asteriskcdrdb.cdr where dcontext=''''outbound'''' and     
--calldate between '''''+@t+''''' and now() order by calldate desc'')'    
declare @sql nvarchar(max)='SELECT * into ##temp FROM OPENQUERY ('+ @LinkedServer + ','+'''SELECT * FROM asteriskcdrdb.cdr where     
calldate between '''''+@t+''''' and now() order by calldate desc'')'    

--select @sql    
exec(@sql)    
--select * from ##temp    

select ROW_NUMBER()over (order by calldate) as id,* into #temp from tempdb..##temp   order by calldate
declare @records int=(select count(1) from #temp) ,@tid int=0,@c int
set @c=@records
while @c>0
begin   
insert into kit19cdr (calldate, clid ,src ,dst, dcontext,channel,dstchannel,lastapp,lastdata,duration,billsec,disposition,    
amaflags,accountcode,uniqueid,userfield)    
select top 1000 calldate, clid ,src ,dst, dcontext,channel,dstchannel,lastapp,lastdata,duration,billsec,disposition,    
amaflags,accountcode,uniqueid,userfield from #temp t where id<=@tid+1000 --where not exists(select 1 from kit19cdr where uniqueid=t.uniqueid)  
delete from #temp where id<=@tid+1000
set @c=@c-1000
set @tid=@tid+1000
end    

insert into cdrsync(datesynced,recordssynced)    
select @timesynced,@records    
    
drop table if exists #temp    
drop table  if exists ##temp    
    
end




