/* ============================================================
   Procedure: [dbo].[usp_voip_ChangeDefaultCallingGateway]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE usp_voip_ChangeDefaultCallingGateway
(
	@ParentId bigint,
	@ServiceProviderId bigint,
	@ServiceName nvarchar(255),
	@CallDirection nvarchar(255)

)
as
begin
	

	if(isnull(@ServiceName, '')<>'')
	begin
		if(lower(@CallDirection) = 'incoming')
		begin
			if(exists(select 1 from tbl_ClickToCallSetting(nolock) where parentId = @ParentId))
			begin
				update tbl_ClickToCallSetting set incoming_provider = @ServiceName where parentId = @ParentId
			end
			else
			begin
				insert into tbl_ClickToCallSetting( parentId, incoming_provider, created_by )
					values( @ParentId, @ServiceName, @ParentId )
			end
		end

		if(lower(@CallDirection) = 'outgoing')
		begin
			update tbl_voip_DefaultCallingService set ServiceProviderId = @ServiceProviderId where ParentId = @ParentId

			if(exists(select 1 from tbl_ClickToCallSetting(nolock) where parentId = @ParentId))
			begin
				update tbl_ClickToCallSetting set outgoing_provider = @ServiceName where parentId = @ParentId
			end
			else
			begin
				insert into tbl_ClickToCallSetting( parentId, outgoing_provider, created_by )
					values( @ParentId, @ServiceName, @ParentId )
			end
		end
	end
end



GO

