/* ============================================================
   Procedure: [dbo].[usp_voip_ChangeStatusParentMapping]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_voip_ChangeStatusParentMapping(
	@SrvProId bigint,
	@ParentId bigint,
	@Status bit = 0,
	@Mode nvarchar(255) = 'IsActive'
)
as
begin
	if(@Mode = 'IsActive')
	begin
		update tbl_voip_ParentServiceMapping set
			 is_active = @Status
			where parent_id = @ParentId and srv_pro_id = @SrvProId
	end

	if(@Mode = 'IsDefault')
	begin
		if(@Status = 1)
		begin
			if(exists(select * from tbl_voip_DefaultCallingService where ParentId = @ParentId ))
			begin
				update tbl_voip_DefaultCallingService set 
					ServiceProviderId = @SrvProId,
					IsActive = @Status
					where ParentId = @ParentId
			end
			else
			begin
				insert into tbl_voip_DefaultCallingService(ServiceProviderId, ParentId, IsActive, CreatedOn)
					values( @SrvProId, @ParentId, 1, getdate())
			end
		end
		else
		begin
			update tbl_voip_DefaultCallingService set IsActive = @Status
				where ParentId = @ParentId and ServiceProviderId = @SrvProId 
		end
	end
end



