/* ============================================================
   Procedure: [dbo].[USP_VOIP_ClicktoCallDetailsList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[USP_VOIP_ClicktoCallDetailsList]
(
	@CreatedOn datetime,
	@ToNumber nvarchar(25),
	@RequestBody nvarchar(255),
	@AgentName nvarchar(100),
	@Entity nvarchar(10),
	@UserId bigint,
	@Offsets int = 0,
	@PageSize int =  100
)
as
begin

	--declare
	--	@CreatedOn datetime,
	--	@ToNumber nvarchar(25),
	--	@RequestBody nvarchar(255),
	--	@AgentName nvarchar(100),
	--	@Entity nvarchar(10),
	--	@UserId bigint =  32222,
	--	@Offsets int = 0,
	--	@PageSize int =  100 

	declare @ParentId bigint, @StartPoint int = 0, @EndPoint int = 0


	--SELECT @ParentId = ParentID FROM User_Detail(NOLOCK)  WHERE Mobile = @ToNumber
	SELECT @ParentId = ParentID FROM User_Detail(NOLOCK)  WHERE User_ID = @UserId
	print concat('@ParentId => ', @ParentId)

	select @StartPoint  =  @Offsets + 1, @EndPoint = @Offsets +  @PageSize

	select 
		t.Sno,
		t.Id,
		t.TotalRow,
		t.AgentName,
		t.Mobile,
		t.ProfilePictureName,
		t.requestjson,
		t.ErrorDescription,
		t.Isprocessed,
		t.IscallConnected,
		t.createdOn,
		t.Entityname,
		t.entityid,
		t.sentrequest_count,
		dbo.udf_ims_GetAssoisatedEntityProfile(t.Entityname, t.entityid) as [EntityProfile]
	from (
		select 
			Concat(ud.FName, ud.LName) as AgentName, 
			ud.Mobile,
			ud.ProfilePictureName,
			rc.id,
			rc.requestjson,
			rc.ErrorDescription,
			rc.Isprocessed,	
			rc.IscallConnected,
			rc.createdOn,
			rc.Entityname,
			rc.entityid,
			c.sentrequest_count,
			ROW_NUMBER() over (partition by ud.parentid order by rc.id desc) as Sno,
			count(1) over (partition by ud.parentid) as [TotalRow]
		
		from TBL_VOIP_SentRequestCallDetails (NOLOCK) rc 
			left join User_Detail(nolock) ud on rc.createdby  = ud.User_ID
			left join V_CliclktocallWebHookCount(NOLOCK) C on rc.id = C.requestid
		where 
			createdby in (select User_ID from User_Detail(nolock) where ParentId = @ParentId)
			and 1 = ( case when isnull(@CreatedOn, '') = '' then 1 
						when cast(rc.createdon as date) = cast(@CreatedOn as date) then 1
						else 0 end ) 
			and 1  = ( case when isnull(@ToNumber, '') = '' then 1 
						when JSON_VALUE(requestjson, '$.ToMobileNo') = @ToNumber then 1
						else 0 end ) 
			and 1 =  ( case when isnull(@RequestBody, '') = '' then 1 
						when JSON_VALUE(requestjson, '') = @RequestBody then 1
						else 0 end )
			 and 1 =  ( case when isnull(@AgentName, '') = '' then 1 
								when JSON_VALUE(requestjson, '$.UserLogin') = @AgentName then 1
								else 0 end )
			and 1 =  ( case when isnull(@Entity, '') = '' then 1 
								when (rc.entityname) = @Entity then 1
								else 0 end )
		) t where t.Sno between  @StartPoint and @EndPoint;

end



GO

/* ============================================================
   Procedure: [dbo].[usp_voip_ClickToCallRequestSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_voip_ClickToCallRequestSetting(
	@UserId bigint = 32222,
	@ApiKey nvarchar(255) = '',
	@WebhookUrl nvarchar(max) = '',
	@MethodType nvarchar(50) = '',
	@ContentType nvarchar(255) = ''
)
as
begin
	--declare 
	--	@UserId bigint = 32222,
	--	@ApiKey nvarchar(255) = '',
	--	@WebhookUrl nvarchar(max) = '',
	--	@MethodType nvarchar(50) = '',
	--	@ContentType nvarchar(255) = ''

	declare 
		@ParentId bigint = 0

	select @ParentId = ParentID from User_Detail(nolock) where User_Id = @UserId

	if(exists(select 1 from TBL_VOIP_VoiceAPIKey(nolock) where ParentId = @ParentId))
	begin
		update TBL_VOIP_VoiceAPIKey set 
			[key]  = case when ISNULL(@ApiKey, '') <> '' then @ApiKey else [key] end 
		where ParentId = @ParentId
	end
	else
	begin
		insert into TBL_VOIP_VoiceAPIKey(ParentId, [key], CreatedOn, CreatedBy, IsActive)
			values (@ParentId, @ApiKey, GETDATE(), @UserId, 1)
	end


	if(exists(select 1 from tbl_VOIP_WebHook_settings(nolock) where ParentId = @ParentId))
	begin
		update tbl_VOIP_WebHook_settings set 
			[WebHookURL]  = case when ISNULL(@WebhookUrl, '') <> '' then @WebhookUrl else [WebHookURL] end,
			[WebHookMethod]  = case when ISNULL(@MethodType, '') <> '' then @MethodType else [WebHookMethod] end,
			[ContentType]  = case when ISNULL(@ContentType, '') <> '' then @ContentType else [ContentType] end
		where ParentId = @ParentId
	end
	else
	begin
		insert into tbl_VOIP_WebHook_settings(ParentId, CreatedOn, CreatedBy, ModifiedBy, IsActive, WebHookURL, WebHookMethod, Header, ContentType)
			values (@ParentId, GETDATE(), @UserId, @UserId, 1, @WebhookUrl, @MethodType, '[]', @ContentType)
	end

end



GO

/* ============================================================
   Procedure: [dbo].[usp_voip_DedectCallCharge]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_voip_DedectCallCharge](
	@tblVoipWebhookId bigint, 
	@serviderName nvarchar(255)
)
as
begin

--declare
--	@tblVoipWebhookId bigint  = 275769, 
--	@serviderName nvarchar(255) = 'MobileLikeNumber'

declare 
	@endpointId bigint, @EntityName nvarchar(255), @EntityId bigint, 
	@AgentId bigint, @ParentId bigint, @Mid bigint, @GatewayType int  = 0,
	@UniqueIdentity nvarchar(255)

	declare @ResponseBody nvarchar(max), @RequestBody nvarchar(max)
	select @ResponseBody = request_body, @UniqueIdentity = UniqueIdentity from 
		tbl_voip_Webhook(nolock) where id = @tblVoipWebhookId

	declare @CallDuration decimal(18, 4) = 0, @Pulse int, @TotalBalance decimal(18, 4),
		@Price decimal(18,4),@Cost decimal(18,4),@aPulse int, @FromMobileNo nvarchar(50), @ToMobileNo nvarchar(50)

	

	select @CallDuration = [value] from openjson(@ResponseBody) where [key] = 'duration'

	if(@serviderName = 'MobileLikeNumber')
	begin
		set @GatewayType = 4
		select @endpointId = id, @EntityName = EntityName, @EntityId = EntityId,
			@ToMobileNo = ToMobileNo, @AgentId = AgentId, @RequestBody = request_body
			from tbl_voip_endpointInteraction(nolock) where refNumber = @UniqueIdentity 
	end

	drop table if exists #tempRequest

	select * into #tempRequest from openjson( @RequestBody )
	with (
		[key] nvarchar(50),
		[value] nvarchar(255)
	)

	select @FromMobileNo = [value] from #tempRequest where [key] = 'agentNumber'
	select @ToMobileNo = [value] from #tempRequest where [key] = 'customerNumber'

	select @ParentId = ParentID, @Mid = M_ID from User_Detail(nolock) where  User_ID = (
		select ParentID from User_Detail(nolock) where User_ID = @AgentId )


	if(@ParentId is not null)
	begin
		select @TotalBalance = balance FROM IntCredit_Details c with (nolock) 
				where user_ID = @parentid and Credit_ID=(select max(credit_id)
			from IntCredit_Details c1 with (nolock)  where c.user_id=c1.User_ID)

		select top 1 @Pulse = pulse_sec, @Price=price from tbl_obd_Base_Price(nolock)
			where service_type = 'click2call' and ( ParentId = @ParentId or ParentId = 0 ) order by parentid desc
		set @aPulse = ceiling(@CallDuration/cast(@Pulse as float))
		set @Cost = @aPulse * @Price * 1

		declare @Remarks nvarchar(max) = N'Call Charges for call dialled out to '+ @FromMobileNo 
					+ ' by agent '+ @ToMobileNo + ' at Feb 12 2022  6:41PM via gateway: 080 Number, callid: ' + cast(@endpointId as nvarchar)
	   
		if(@Cost > 0)
		begin

			declare @tcdid bigint,@itcid bigint

			insert into TelephonyCostDeducted(parentid,uniqueid,kit19callsdialledid,cost,Agenttype, GatewayType)
			select @parentid, @UniqueIdentity, @endpointId, @Cost, 'Mobile', @GatewayType
			select @tcdid=scope_identity()

			insert into IntCredit_Details(FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,Validity,Remarks,typecredit )
			select @parentid,@Mid,@parentid,@cost,0, @TotalBalance - @Cost,99999, @Remarks, 1

			select @itcid=SCOPE_IDENTITY()
			update TelephonyCostDeducted set credit_id =@itcid where id=@tcdid

			update tbl_voip_endpointInteraction set kei_IsCharged = 1,
				kei_IntCreditId = @itcid where id = @endpointId
		end
	end
end



GO

/* ============================================================
   Procedure: [dbo].[usp_voip_DedectCallChargeKit1980]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voip_DedectCallChargeKit1980]    
(    
 @UniqueIdentity bigint    
)    
as    
begin    
    
	--declare @UniqueIdentity bigint = 1666802    
    
	declare     
		@AgentId bigint,    
		@FromMobileNo nvarchar(50),    
		@ToMobileNo nvarchar(50),    
		@ParentId bigint,    
		@CallEndTime datetime,    
		@CustomerCallTime datetime,    
		@DidNo nvarchar(25),
		@AgentcallTime datetime,    
		@Createdon datetime,    
		@Mid bigint,    
		@Pulse int = 0,    
		@Price decimal(18,4) = 0,    
		@Cost decimal(18, 4) = 0,    
		@TotalBalance decimal(18, 4) = 0,    
		@GatewayType int  = 7,  
		@agentAnwer nvarchar(25) = ''   
    
	select     
		@AgentId = AgentId, @FromMobileNo = kei_AgentMobile, @ToMobileNo = kei_CustomerNoWithCountryCode,     
		@ParentId = tei_parentid, @CallEndTime = kei_CallEndTime, @CustomerCallTime = kei_CustomerCallTime,    
		@AgentcallTime = kei_AgentcallTime, @Createdon = created_on, @agentAnwer = kei_AgentDialStatus, @DidNo = kei_Dnid  
	from tbl_voip_endpointInteraction(nolock) where id = @UniqueIdentity --296335    
    
	select @ParentId = ParentID, @Mid = M_ID from User_Detail(nolock) where  User_ID = (      
	select ParentID from User_Detail(nolock) where User_ID = @AgentId )      
    
 declare @agentDuration int = 0, @cutomerDuation int = 0 , @agentPulse int = 0, @customerPulse int = 0     
    
 select     
	  @agentDuration = isnull(datediff(second, @AgentcallTime, @CallEndTime), 0),     
	  @cutomerDuation = isnull(datediff(second, @CustomerCallTime, @CallEndTime), 0)    
    
if(@agentDuration = 0 and @agentAnwer  = 'answer')  
 begin  
 set @agentDuration = 1  
 end  
    
 select top 1 @Pulse = pulse_sec, @Price=price from tbl_obd_Base_Price(nolock)      
    where service_type = 'click2call' and ( ParentId = @ParentId or ParentId = 0) order by parentid desc      
   set @agentPulse = isnull(ceiling(@agentDuration/cast(@Pulse as float)), 0)      
   set @customerPulse = isnull(ceiling(@cutomerDuation/cast(@Pulse as float)), 0)      
    
   set @Cost = (@agentPulse * @Price * 1 ) + (isnull(@customerPulse, 0) * @Price * 1 )    
    
--select @ParentId as[@ParentId], @AgentId as [@AgentId], @Mid as [@Mid], @agentDuration as [@agentDuration],   
-- @agentPulse as [@agentPulse], @cutomerDuation as [@cutomerDuation], @customerPulse as [@customerPulse], @Cost as [@Cost]    
    
  print concat('@UniqueIdentity => ', @UniqueIdentity)  
    
  if(@ParentId is not null)      
  begin      
   select @TotalBalance = balance FROM IntCredit_Details c with (nolock)       
  where user_ID = @parentid and Credit_ID=(select max(credit_id)      
    from IntCredit_Details c1 with (nolock)  where c.user_id=c1.User_ID)      
      
       
   declare @Remarks nvarchar(max) = concat( N'Call Charges for call dialled out to ', @ToMobileNo,     
    ' by agent ', @FromMobileNo, ' at ', @Createdon, ' via gateway: 080 Number, callid: ', cast(@UniqueIdentity as nvarchar))  
	
	declare @tblTotalCost as table (totalCost decimal(18, 4))

	insert into @tblTotalCost(totalCost)
	exec usp_CalculateClickToCallCost  
		@FromMobileNo = @FromMobileNo,
		@ToMobileNo = @ToMobileNo,
		@AgentCallStartTime = @AgentcallTime,
		@CustomerStartEndTime = @CustomerCallTime,
		@CallEndTime = @CallEndTime,
		@DidNo  = @DidNo,
		@AgentId  = @AgentId

	select @Cost =  totalCost from @tblTotalCost

	--select @Cost as [@Cost]

   if(@Cost > 0)      
   begin      
      
    declare @tcdid bigint,@itcid bigint      
      
    insert into TelephonyCostDeducted(parentid,uniqueid,kit19callsdialledid,cost,Agenttype, GatewayType)      
    select @parentid, @UniqueIdentity, @UniqueIdentity, @Cost, 'Mobile', @GatewayType      
    select @tcdid=scope_identity()      
      
    insert into IntCredit_Details(FromUser_ID,M_ID,User_ID,Debits,Credits,Balance,Validity,Remarks,typecredit )      
    select @parentid,@Mid,@parentid,@cost,0, @TotalBalance - @Cost,99999, @Remarks, 1      
      
    select @itcid=SCOPE_IDENTITY()      
    update TelephonyCostDeducted set credit_id =@itcid where id=@tcdid      

	exec mysms.dbo.usp_rf_UpdateReserveFundTransaction @CreditId = @itcid  

    update tbl_voip_endpointInteraction set kei_IsCharged = 1, kei_IntCreditId = @itcid where id = @UniqueIdentity    
   end  
   
 end     
end    


GO

