CREATE   PROCEDURE [dbo].[usp_voip_GetAgentSetting](
	@ServiceProviderId bigint,
	@ParentId bigint,
	@FilterText nvarchar(255)  = '',
	@OffsetValue bigint = 0,
	@PagingSize bigint = 20
)
as
begin

	--declare 
	--	@ServiceProviderId bigint = 7,
	--	@ParentId bigint = 41787,
	--	@FilterText nvarchar(255)  = '',
	--	@OffsetValue bigint = 0,
	--	@PagingSize bigint = 20

	--declare @ServiceProviderMappingId bigint = ( select id from tbl_voip_ParentServiceMapping(nolock) 
	--	where parent_id = @ParentId and srv_pro_id = @ServiceProviderId )

	select count(ud.User_ID) over() as TotalRow, ud.User_Login, uas.id,  ud.user_id, uas.ext_number, uas.mobile_no, uas.did_no, uas.created_on,	uas.created_by, uas.default_caller_no, uas.default_machine, uas.is_active
	from User_Detail(nolock) ud
		left join tbl_voip_userAgentSetting(nolock) uas on ud.User_ID = uas.user_id
		and  isnull(uas.service_provider_id, 0) = @ServiceProviderId
	where ud.ParentId = @ParentId and isnull(uas.service_provider_id, 0) = iif(isnull(uas.service_provider_id, 0) = 0, 0, @ServiceProviderId)
		order by ud.User_Login 
			offset @OffsetValue rows fetch  next @PagingSize rows only
end



