/* ============================================================
   Procedure: [dbo].[usp_voip_GetDefaultClickToCallSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voip_GetDefaultClickToCallSetting](
	@UserId bigint
)
as
begin

	--declare @UserId bigint = 34594
	declare @ParentId bigint = 0, @DefaultIncoming nvarchar(255), @DefaultOutgoing nvarchar(255)
	set @ParentId =  isnull((select ParentID from User_Detail(nolock) where User_ID = @UserId), 0)

	select Top 1 
		@DefaultIncoming = incoming_provider,
		@DefaultOutgoing = outgoing_provider
	from tbl_ClickToCallSetting(nolock) 
		where parentId =  @ParentId  or parentId =  0
			order by id desc

		SELECT * , 
			IIF(@DefaultIncoming = provider_name , 1 , 0) AS [IsIncoming],
			IIF(@DefaultOutgoing = provider_name , 1 , 0) AS [IsOutcoming]
		FROM ( 
			SELECT sp.id AS spid , sp.provider_name
			FROM tbl_voip_ServiceProvider(NOLOCK) AS sp
			WHERE sp.is_internal = 0
			UNION
			SELECT sp.id AS spid , sp.provider_name
			FROM tbl_voip_ServiceProvider(NOLOCK) AS sp 
			INNER JOIN tbl_voip_InternalServiceProviderMapping(NOLOCK) AS ism 
			ON (sp.id = ism.serv_pro_id or sp.id = 4) AND ism.is_active = 1
			WHERE 1 = ( case when sp.is_internal = 1 then 1
				when sp.id = 4 then 1 else 0 end) and ism.parent_id = @ParentId
		) AS vt;

end



GO

/* ============================================================
   Procedure: [dbo].[usp_voip_GetDefaultServiceProvider]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE usp_voip_GetDefaultServiceProvider(
	@ParentId bigint
)
as
begin

	declare @DefProvider bigint = ( select ServiceProviderId from tbl_voip_DefaultCallingService(nolock) def where ParentId = @ParentId )

	SELECT * , IIF(@DefProvider = vt.spid , 1 , 0) AS [IsDefault] FROM ( 
		SELECT sp.id AS spid , sp.provider_name
		   FROM tbl_voip_ServiceProvider(NOLOCK) AS sp
		   WHERE sp.is_internal = 0
		   UNION
		   SELECT sp.id AS spid , sp.provider_name
		   FROM tbl_voip_ServiceProvider(NOLOCK) AS sp 
		   INNER JOIN tbl_voip_InternalServiceProviderMapping(NOLOCK) AS ism 
		   ON sp.id = ism.serv_pro_id AND ism.is_active = 1
		   WHERE sp.is_internal = 1 and ism.parent_id = @ParentId
		 ) AS vt;
			
end



GO

/* ============================================================
   Procedure: [dbo].[usp_voip_GetDidNoList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voip_GetDidNoList](
	@ServiceProviderId bigint,
	@ParentId bigint,
	@FilterText nvarchar(255)  = '',
	@OffsetValue bigint = 0,
	@PagingSize bigint = 20
)
as
begin
	
	--declare 
	--	@ServiceProviderId bigint = 7,
	--	@ParentId bigint = 34594,
	--	@FilterText nvarchar(255)  = '',
	--	@OffsetValue bigint = 0,
	--	@PagingSize bigint = 20

	declare @ServiceProviderMappingId bigint = ( select id from tbl_voip_ParentServiceMapping(nolock) 
		where parent_id = @ParentId and srv_pro_id = @ServiceProviderId )
	
	declare @StartPoint int = 0, @EndPoint int  = 0
	select @StartPoint = (@OffsetValue + 1), @EndPoint = (@OffsetValue + @PagingSize)

	select * from (select 
	ROW_NUMBER() over (partition by (select null) order by Id desc) as SNo,
	count(Id) over() as TotalRow,
	* from tbl_voip_ParentServiceMappingDidNo(nolock) where 
		1 = ( case when psmap_id in ( select id from tbl_voip_ParentServiceMapping(nolock) 
                where parent_id = @ParentId and srv_pro_id = @ServiceProviderId ) then 1
               when isnull(ServiceProviderId, 0) = @ServiceProviderId then 1 
             else 0 end )
         and IsActive = 1
	) t where t.SNo between @StartPoint and @EndPoint
end



