/* ============================================================
   Procedure: [dbo].[usp_voip_GetEndpintSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voip_GetEndpintSetting](  
	@ApiName nvarchar(255),  
	@AgentId bigint,  
	@EntityName nvarchar(25),  
	@EntityId bigint  
)  
as  
begin


 --declare   
	--@ApiName nvarchar(255) = N'outbound',
	--@AgentId bigint = 49677,
	--@EntityName nvarchar(25) = N'lead',
	--@EntityId bigint = N'16525544'
  
 declare @PsmapId bigint, @SrvProId bigint, @ParentId bigint;  
 
 select @ParentId = ParentId from User_Detail(nolock)   
       where User_ID = @AgentId  

 select @SrvProId =  ( select top 1 ServiceProviderId   
    from tbl_voip_DefaultCallingService(nolock) where ParentId = @ParentId order by id desc )  
  
  declare @PersonName nvarchar(255) = ( case when @EntityName = 'lead'  
    then ( select PersonName from UserLeads(nolock) where ID  = @EntityId )  
   when @EntityName = 'enquiry'  
    then ( select PersonName from UserEnquiry(nolock) where EnquiryID  = @EntityId )  
   else '' end )  
  
  if(isnull(@SrvProId, 0) = 0)  
  begin  
   set @SrvProId = 7  
  end  
  
  select @PsmapId = id from tbl_voip_ParentServiceMapping(nolock)  
    where parent_id  = (select ParentId from User_Detail(nolock) where USER_ID = @AgentId)  
     and is_active = 1 and srv_pro_id = @SrvProId  
   
	print concat(@SrvProId,  '  ', @PsmapId   )

	declare @isInternational int = 0;
	declare @sipName nvarchar(20) = 'jio' 
	select @sipName = [dbo].[fn_getsipname](trim(dbo.fn_GetDefaultDID(@ParentId)))

	SET @isInternational = CASE WHEN LOWER(LTRIM(RTRIM(ISNULL(@sipName, '')))) LIKE 'go%' THEN 1 ELSE 0 END;
	PRINT concat('@sipName => ', @sipName, '  @isInternational => ', @isInternational);

	if( @PsmapId is not null)  
	begin
		print 'in side'
		select *, @isInternational as [isInternational] from tbl_voip_endpointSetting(nolock) es  
		where psmap_id = @PsmapId and api_type_id = ( select id from tbl_voip_api_type(nolock)   
			where Lower(ltrim(rtrim(api_name)))  = Lower(ltrim(rtrim(@ApiName)))  
			and srv_pro_id = @SrvProId  
		)  
	end  
	else   
	begin  
		
		declare @bodyPayload nvarchar(max) =  '[{"key":"exten","value":"#FromMobileNo#"},{"key":"number","value":"#ToMobileNo#"},{"key":"did","value":"#CallerId#"},{"key":"type","value":"P"},{"key":"id","value":"#UniqueIdentity#"},{"key":"t1","value":"gous"},{"key":"t2","value":"gous"}]'

		select 0 as [id], endpoint_url, request_method, content_type, request_header_json, 
			(case when @isInternational = 1 then @bodyPayload else request_body_json end) as [request_body_json], 
		response_content, is_active, created_by, created_on, callback_endpint, callback_request, callback_response, 
			api_type_id, 0 as psmap_id, is_deleted, @isInternational as [isInternational]
		from tbl_voip_endpointSetting(nolock) where id = 25  
	end  
  
	declare @ProviderName nvarchar(255) = 'Kit19 80',
		@DefaultCallerId nvarchar(255) = 'Any', @Dnid nvarchar(255) = ''
	
	if(isnull(@SrvProId, 0) > 0)
	begin
		select @ProviderName = provider_name from tbl_voip_ServiceProvider(nolock) where id = @SrvProId 
		if(@SrvProId = 7)
		begin
			declare @PhoneNo nvarchar(50)

			select top 1 @PhoneNo = p.PhoneNo from cloud_user_phone(nolock) p where p.Parentid= @ParentId
				and p.Active = 1 and dbo.fn_getsipname(p.PhoneNo) = 'jio' order by p.userphid desc

			print @PhoneNo

			if(isnull(@PhoneNo, '') = '')
			begin
				select @PhoneNo = t.PhoneNo from ( select
					row_number() over(partition by (select null) order by PhoneId) rn,
					PhoneNo from Cloud_phone_master(nolock) where reservedfor is not null
				) t where t.rn = ROUND(RAND() * 50, 0)
			end
			select @DefaultCallerId = isnull(@PhoneNo, '8035391888'),  @Dnid = isnull(@PhoneNo, '8035391888')

			set @DefaultCallerId = concat('+91', @DefaultCallerId)  -- Changes for DidNo change
			set @Dnid = concat('+91', @Dnid)

		end
	end
  
	--Agent Selection
	if(exists(select * from tbl_voip_userAgentSetting(nolock) 
		where user_id = @AgentId and is_active = 1 and service_provider_id = @SrvProId))  
	begin  
  
		print concat('@SrvProId => ', @SrvProId, ' ==> @AgentId => ', @AgentId)
		print concat('@isInternational => ', @isInternational)

		select a.Id, a.user_id,  
			(
				CASE 
					WHEN @isInternational = 1 
						THEN dbo.fn_FormatToInternational(LTRIM(RTRIM(ISNULL(NULLIF(CAST(a.ext_number AS NVARCHAR(50)), ''), ''))))
					ELSE CAST(a.ext_number AS NVARCHAR(50))
				END
			) AS [ext_number],
			(
			  CASE 
				WHEN @isInternational = 1 
				  THEN dbo.fn_FormatToInternational(
						 ISNULL(NULLIF(LTRIM(RTRIM(a.mobile_no)), ''), LTRIM(RTRIM(ud.Mobile))))
				ELSE 
				  ISNULL(NULLIF(LTRIM(RTRIM(a.mobile_no)), ''), LTRIM(RTRIM(ud.Mobile)))
			  END
			) AS [mobile_no], 
			( case when @isInternational = 1 then dbo.fn_FormatToInternational(
					 ISNULL(NULLIF(LTRIM(RTRIM(a.did_no)), ''), LTRIM(RTRIM(a.default_caller_no))))
				when @isInternational = 0 and isnull(a.did_no, a.default_caller_no) not like '+91' 
				then concat('+91', isnull(a.did_no, a.default_caller_no))
				else isnull(a.did_no, a.default_caller_no) end  ) as [did_no],
			( case when @isInternational = 1 then dbo.fn_FormatToInternational(
					ISNULL(NULLIF(LTRIM(RTRIM(a.did_no)), ''), LTRIM(RTRIM(a.default_caller_no))))
				when @isInternational = 0 and a.default_caller_no not like '+91' then concat('+91', a.default_caller_no)
				else a.default_caller_no end  ) as [default_caller_no],
			a.default_machine, a.is_active, a.created_on, a.created_by, a.is_active, isnull(a.psmap_id, 0) as [psmap_id],
				ud.ParentID, sp.provider_name, @PersonName as CustomerName,   
			concat(trim(ud.FName), ' ', trim(ud.LName)) as AgentName    
		from tbl_voip_userAgentSetting(nolock) a   
		--inner join tbl_voip_ParentServiceMapping(nolock) psm on a.psmap_id = psm.id  
		inner join tbl_voip_ServiceProvider(nolock) sp on a.service_provider_id = sp.id  
		inner join User_Detail(nolock) ud on a.user_id = ud.User_ID  
	   where a.user_id = @AgentId and a.is_active = 1 and service_provider_id = @SrvProId
  end  
  else  
  begin  
    select 0 as [Id],   
		@AgentId as [user_id],  
		@AgentId as [ext_number],  
		ud.Mobile as [mobile_no],   
		@Dnid as [did_no],  
		@DefaultCallerId as [default_caller_no],   
		'm' as [default_machine],   
		1 as [IsActive],   
		getdate() as [created_on],  
		@AgentId as [created_by],  
		1 as [is_active],  
		0 as [psmap_id], ud.ParentID, 
		@ProviderName as [provider_name],
		@PersonName as CustomerName,   
		concat(trim(ud.FName), ' ', trim(ud.LName)) as AgentName      
    from User_Detail(nolock) ud where ud.User_Id = @AgentId  
  end  
end



GO

/* ============================================================
   Procedure: [dbo].[usp_voip_GetEndpintSetting$]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voip_GetEndpintSetting$](  
 @ApiName nvarchar(255),  
 @AgentId bigint,  
 @EntityName nvarchar(25),  
 @EntityId bigint  
)  
as  
begin

	
 --declare   
	--@ApiName nvarchar(255) = N'outbound',
	--@AgentId bigint = 43673,
	--@EntityName nvarchar(25) = N'lead',
	--@EntityId bigint = N'10503943'
  
 declare @PsmapId bigint, @SrvProId bigint, @ParentId bigint;  
  

  select @ParentId = ParentId from User_Detail(nolock)   
       where User_ID = @AgentId  

 select @SrvProId =  ( select top 1 ServiceProviderId   
    from tbl_voip_DefaultCallingService(nolock)
     where ParentId = @ParentId order by id desc )  
  
  declare @PersonName nvarchar(255) = ( case when @EntityName = 'lead'  
    then ( select PersonName from UserLeads(nolock) where ID  = @EntityId )  
   when @EntityName = 'enquiry'  
    then ( select PersonName from UserEnquiry(nolock) where EnquiryID  = @EntityId )  
   else '' end )  
  
   
  if(isnull(@SrvProId, 0) = 0)  
  begin  
   set @SrvProId = 7  
  end  
  
  select @PsmapId = id from tbl_voip_ParentServiceMapping(nolock)  
    where parent_id  = (select ParentId from User_Detail(nolock) where USER_ID = @AgentId)  
     and is_active = 1 and srv_pro_id = @SrvProId  
   
 print concat(@SrvProId,  '  ', @PsmapId   )

	if( @PsmapId is not null)  
	begin
		print 'in side'
		select * from tbl_voip_endpointSetting(nolock) es  
		where psmap_id = @PsmapId and api_type_id = ( select id from tbl_voip_api_type(nolock)   
			where Lower(ltrim(rtrim(api_name)))  = Lower(ltrim(rtrim(@ApiName)))  
			and srv_pro_id = @SrvProId  
		)  
	end  
	else   
	begin  
		 select 0 as [id], endpoint_url, request_method, content_type, request_header_json, request_body_json, response_content, is_active, created_by, created_on, callback_endpint, callback_request, callback_response, api_type_id, 0 as psmap_id, is_deleted  
		from tbl_voip_endpointSetting(nolock) where id = 25  
	end  
  
	declare @ProviderName nvarchar(255) = 'Kit19 80',
		@DefaultCallerId nvarchar(255) = 'Any', @Dnid nvarchar(255) = ''
	
	if(isnull(@SrvProId, 0) > 0)
	begin
		select @ProviderName = provider_name from tbl_voip_ServiceProvider(nolock) where id = @SrvProId 
		if(@SrvProId = 7)
		begin
			declare @PhoneNo nvarchar(50)

			select top 1 @PhoneNo = p.PhoneNo from cloud_user_phone(nolock) p where p.Parentid= @ParentId
				and p.Active = 1 and dbo.fn_getsipname(p.PhoneNo) = 'jio' order by p.userphid desc

			print @PhoneNo

			if(isnull(@PhoneNo, '') = '')
			begin
				select @PhoneNo = t.PhoneNo from ( select
					row_number() over(partition by (select null) order by PhoneId) rn,
					PhoneNo from Cloud_phone_master(nolock) where reservedfor is not null
				) t where t.rn = ROUND(RAND() * 50, 0)
			end
			select @DefaultCallerId = isnull(@PhoneNo, '8035391888'),  @Dnid = isnull(@PhoneNo, '8035391888')

			set @DefaultCallerId = concat('+91', @DefaultCallerId)  -- Changes for DidNo change
			set @Dnid = concat('+91', @Dnid)

		end
	end
  
  if(exists(select * from tbl_voip_userAgentSetting(nolock) 
	where user_id = @AgentId and is_active = 1 and service_provider_id = @SrvProId))  
  begin  
  

  print concat('@SrvProId => ', @SrvProId, ' ==> @AgentId => ', @AgentId)

   select a.Id, a.user_id, a.ext_number, ( case when isnull(a.mobile_no, '') = '' then ud.Mobile else a.mobile_no end ) as [mobile_no], 
	( case
		when isnull(a.did_no, a.default_caller_no) not like '+91' then concat('+91', isnull(a.did_no, a.default_caller_no))
		else isnull(a.did_no, a.default_caller_no) end  ) as [did_no],
	( case
		when a.default_caller_no not like '+91' then concat('+91', a.default_caller_no)
		else a.default_caller_no end  ) as [default_caller_no],
		a.default_machine, a.is_active, a.created_on, a.created_by, a.is_active, isnull(a.psmap_id, 0) as [psmap_id],
		ud.ParentID, sp.provider_name, @PersonName as CustomerName,   
    concat(trim(ud.FName), ' ', trim(ud.LName)) as AgentName    
    from tbl_voip_userAgentSetting(nolock) a   
    --inner join tbl_voip_ParentServiceMapping(nolock) psm on a.psmap_id = psm.id  
    inner join tbl_voip_ServiceProvider(nolock) sp on a.service_provider_id = sp.id  
    inner join User_Detail(nolock) ud on a.user_id = ud.User_ID  
   where a.user_id = @AgentId and a.is_active = 1 and service_provider_id = @SrvProId
  end  
  else  
  begin  
    select 0 as [Id],   
    @AgentId as [user_id],  
    @AgentId as [ext_number],  
    ud.Mobile as [mobile_no],   
    @Dnid as [did_no],  
    @DefaultCallerId as [default_caller_no],   
    'm' as [default_machine],   
    1 as [IsActive],   
    getdate() as [created_on],  
    @AgentId as [created_by],  
    1 as [is_active],  
    0 as [psmap_id], ud.ParentID, 
	@ProviderName as [provider_name],
	@PersonName as CustomerName,   
    concat(trim(ud.FName), ' ', trim(ud.LName)) as AgentName      
    from User_Detail(nolock) ud where ud.User_Id = @AgentId  
  end  

end



