/* ============================================================
   Procedure: [dbo].[usp_voip_GetEndpintSettingByProviderName]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voip_GetEndpintSettingByProviderName](
	@ApiName nvarchar(255),
	@AgentId bigint,
	@EntityName nvarchar(25),
	@EntityId bigint,
	@ProviderName nvarchar(510)
)
as
begin

	--declare
	--	@ApiName nvarchar(255) = N'outbound',
	--	@AgentId bigint = 48286,
	--	@EntityName nvarchar(25) = N'lead',
	--	@EntityId bigint = N'14652984',
	--	@ProviderName nvarchar(510) = N'default'

	declare @PsmapId bigint, @SrvProId bigint
	declare @ParentId bigint = 0;	
	select @ParentId = ParentId from User_Detail(nolock) where User_ID = @AgentId

	if @EntityName='enquiry'  
	begin  
		if not exists (select 1 from userenquiry(nolock) where parentid=@ParentId and enquiryid=@EntityId)  
		and exists  (select 1 from userleads(nolock) where parentid=@ParentId and id=@EntityId)  
		begin  
			set @EntityName='lead'  
		end  
	end  
	else if @EntityName='lead'  
	begin  
		if not exists (select 1 from userleads(nolock) where parentid=@ParentId and id=@EntityId)  
		and exists  (select 1 from userenquiry(nolock) where parentid=@ParentId and enquiryid=@EntityId)  
		begin  
		set @EntityName='enquiry'  
		end
	end  


	if(@ProviderName = 'default')
	begin		
		if(exists(select top 1 provider_name from tbl_voip_DefaultCallingService(nolock) dc
				inner join tbl_voip_ServiceProvider(nolock) sp on dc.ServiceProviderId = sp.id 
			where dc.IsActive = 1 and dc.ParentId = @ParentId))
		begin
			set @ProviderName = isnull((select top 1 provider_name from tbl_voip_DefaultCallingService(nolock) dc
				inner join tbl_voip_ServiceProvider(nolock) sp on dc.ServiceProviderId = sp.id 
			where dc.IsActive = 1 and dc.ParentId = @ParentId order by dc.id desc), 'Kit19 80')
		end
	end

	if(isnull(@ProviderName, 'default') = 'default')
	begin
		set @ProviderName = 'Kit19 80'
	end

	print concat('@ProviderName => ', @ProviderName, '')

	--select @SrvProId =  ( select ServiceProviderId 
	--			from tbl_voip_DefaultCallingService(nolock) 
	--				where ParentId = @ParentId ) 


	select @SrvProId = sp.Id from tbl_voip_ParentServiceMapping(nolock) psm 
	inner join tbl_voip_ServiceProvider(nolock) sp on psm.srv_pro_id  = sp.id
		where parent_id = @ParentId and sp.provider_name = @ProviderName

	if(isnull(@SrvProId, 0) = 0)  
	begin  
		set @SrvProId = 7  
	end  
  
	select @PsmapId = id from tbl_voip_ParentServiceMapping(nolock)
			where parent_id  = (select ParentId from User_Detail(nolock) where USER_ID = @AgentId)
				and is_active = 1 and srv_pro_id = @SrvProId

	 
	
	declare @PersonName nvarchar(255) = (
		case when @EntityName = 'lead'
				then ( select PersonName from UserLeads(nolock) where ID  = @EntityId )
			when @EntityName = 'enquiry'
				then ( select PersonName from UserEnquiry(nolock) where EnquiryID  = @EntityId )
			else '' end )

	--select * from tbl_voip_endpointSetting(nolock) es
	--	where psmap_id = @PsmapId and api_type_id = ( select id from tbl_voip_api_type(nolock) 
	--		where Lower(ltrim(rtrim(api_name)))  = Lower(ltrim(rtrim(@ApiName)))
	--		and srv_pro_id = @SrvProId
	--	)

	print @SrvProId

	declare @DefaultCallerId nvarchar(255) = 'Any', @Dnid nvarchar(255) = ''

	if(isnull(@SrvProId, 0) > 0)
	begin
		select @ProviderName = provider_name from tbl_voip_ServiceProvider(nolock) where id = @SrvProId 
		if(@SrvProId = 7)
		begin
			
			declare @PhoneNo nvarchar(50)
			
			--if(exists(select 1 from tbl_voip_userAgentSetting(nolock) where parent_id = 48441))
			--begin
			--	select @DefaultCallerId from tbl_voip_userAgentSetting(nolock) where parent_id = 48441
			--end
			--else

				select top 1 @PhoneNo = p.PhoneNo from cloud_user_phone(nolock) p where p.Parentid= @ParentId
					and p.Active = 1 and dbo.fn_getsipname(p.PhoneNo) = 'jio' order by p.userphid desc

				print @PhoneNo

				if(isnull(@PhoneNo, '') = '')
				begin
					select @PhoneNo = t.PhoneNo from ( select
						row_number() over(partition by (select null) order by PhoneId) rn,
						PhoneNo from Cloud_phone_master(nolock) where reservedfor is not null
					) t where t.rn = ROUND(RAND() * 50, 0)
				end
				select @DefaultCallerId = isnull(@PhoneNo, '8035391888'),  @Dnid = isnull(@PhoneNo, '8035391888')

				set @DefaultCallerId = concat('+91', @DefaultCallerId)  -- Changes for DidNo change
				set @Dnid = concat('+91', @Dnid)
			--end


			print concat('Random DID NO. ', @Dnid)

		end
	end

	if(exists(select 1 from tbl_voip_userAgentSetting(nolock) 
		where user_id = @AgentId and is_active = 1 and service_provider_id = @SrvProId ))
	begin
		select 
			@DefaultCallerId = concat('+91', a.default_caller_no), 
			@Dnid = concat('+91', a.default_caller_no)
		from  tbl_voip_userAgentSetting(nolock) a
		where a.user_id = @AgentId and a.is_active = 1 and a.service_provider_id = @SrvProId

		print concat('Did No from tbl_voip_userAgentSetting agen Service_provider_Id. ', @Dnid)

	end
	else if(exists(select * from tbl_voip_userAgentSetting(nolock) 
	where user_id = @AgentId and is_active = 1  and psmap_id = @PsmapId 
	))
	begin
		print 'Has data'

		select 
			@DefaultCallerId = concat('+91', a.default_caller_no), 
			@Dnid = concat('+91', a.default_caller_no)
		from tbl_voip_userAgentSetting(nolock) a 
		inner join tbl_voip_ParentServiceMapping(nolock) psm on a.psmap_id = psm.id
		inner join tbl_voip_ServiceProvider(nolock) sp on psm.srv_pro_id = sp.id
		inner join User_Detail(nolock) ud on a.user_id = ud.User_ID
		where a.user_id = @AgentId and a.is_active = 1 and a.psmap_id = @PsmapId

		print concat('Did No from tbl_voip_userAgentSetting agen psmap_id. ', @Dnid)
	end

	print concat('@PsmapId => ', @PsmapId)

	
	  if(@PsmapId is not null)  
	  begin
		print 'in side'
	   select * from tbl_voip_endpointSetting(nolock) es  
		where psmap_id = @PsmapId and api_type_id = ( select id from tbl_voip_api_type(nolock)   
		 where Lower(ltrim(rtrim(api_name)))  = Lower(ltrim(rtrim(@ApiName)))  
		 and srv_pro_id = @SrvProId  
		)  
	   end  
	  else   
	  begin 
		declare @sname nvarchar(25) = case when dbo.fn_getsipname(replace(@Dnid, '+91', '')) like 'airtel%' then 'airtel'
			when dbo.fn_getsipname(replace(@Dnid, '+91', '')) like 'tata%' then 'tata' else 'jio' end

		print concat('@sname => ', @sname)

	   select 0 as [id],
			replace(endpoint_url, 'jio', @sname) as [endpoint_url],
		   request_method, content_type, request_header_json, 
		   replace(request_body_json, 'jio', @sname) as [request_body_json],
		   replace(response_content, 'jio', @sname) as [response_content],
		   is_active, created_by, created_on, callback_endpint, callback_request, callback_response, api_type_id, 0 as psmap_id, is_deleted  
		from tbl_voip_endpointSetting(nolock) where id = 25  
	  end  
  

	if(exists(select 1 from tbl_voip_userAgentSetting(nolock) 
		where user_id = @AgentId and is_active = 1 and service_provider_id = @SrvProId ))
	begin
		select a.id, a.user_id, a.ext_number, a.mobile_no, concat('+91', a.default_caller_no) as [did_no], a.created_on, a.created_by, concat('+91', a.default_caller_no) as default_caller_no, 
			a.is_active, isnull(a.psmap_id, 0) as [psmap_id], a.default_machine, a.service_provider_id, a.parent_id, ud.ParentID, sp.provider_name,
			@PersonName as CustomerName, concat(trim(ud.FName), ' ', trim(ud.LName)) as AgentName  
		from  tbl_voip_userAgentSetting(nolock) a
			inner join tbl_voip_ServiceProvider(nolock) sp on a.service_provider_id = sp.id
			inner join User_Detail(nolock) ud on a.user_id = ud.User_ID
		where a.user_id = @AgentId and a.is_active = 1 and a.service_provider_id = @SrvProId
	end
	else if(exists(select * from tbl_voip_userAgentSetting(nolock) 
	where user_id = @AgentId and is_active = 1  and psmap_id = @PsmapId 
	))
	begin
		print 'Has data'

		select a.*, ud.ParentID, sp.provider_name, @PersonName as CustomerName, 
			concat(trim(ud.FName), ' ', trim(ud.LName)) as AgentName  
			from tbl_voip_userAgentSetting(nolock) a 
			inner join tbl_voip_ParentServiceMapping(nolock) psm on a.psmap_id = psm.id
			inner join tbl_voip_ServiceProvider(nolock) sp on psm.srv_pro_id = sp.id
			inner join User_Detail(nolock) ud on a.user_id = ud.User_ID
		where a.user_id = @AgentId and a.is_active = 1 and a.psmap_id = @PsmapId
	end
	else
	begin
		print 'default data'
		select 0 as [Id],   
			@AgentId as [user_id],  
			@AgentId as [ext_number],  
			ud.Mobile as [mobile_no],   
			@Dnid as [did_no],  
			@DefaultCallerId as [default_caller_no],   
			'm' as [default_machine],   
			1 as [IsActive],   
			getdate() as [created_on],  
			@AgentId as [created_by],  
			1 as [is_active],  
			0 as [psmap_id], ud.ParentID, 
			@ProviderName as [provider_name],
			@PersonName as CustomerName,   
			concat(trim(ud.FName), ' ', trim(ud.LName)) as AgentName      
			from User_Detail(nolock) ud where ud.User_Id = @AgentId  
	end

end




GO

/* ============================================================
   Procedure: [dbo].[usp_voip_GetEndpintSettingByProviderName_PelCRM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voip_GetEndpintSettingByProviderName_PelCRM](  
 @ApiName nvarchar(255),  
 @AgentId bigint,  
 @EntityName nvarchar(25),  
 @EntityId bigint,  
 @ProviderName nvarchar(510)  
)  
as  
begin  
  
 --declare  
 -- @ApiName nvarchar(255) = N'outbound',  
 -- @AgentId bigint = 44947,  
 -- @EntityName nvarchar(25) = N'enquiry',  
 -- @EntityId bigint = N'10585955',  
 -- @ProviderName nvarchar(510) = N'default'  
  
  
 declare @PsmapId bigint, @SrvProId bigint  
 declare @ParentId bigint = 0;   
 select @ParentId = ParentId from User_Detail(nolock) where User_ID = @AgentId  
  
 if @EntityName='enquiry'    
 begin    
  if not exists (select 1 from userenquiry(nolock) where parentid=@ParentId and enquiryid=@EntityId)    
  and exists  (select 1 from userleads(nolock) where parentid=@ParentId and id=@EntityId)    
  begin    
   set @EntityName='lead'    
  end    
 end    
 else if @EntityName='lead'    
 begin    
  if not exists (select 1 from userleads(nolock) where parentid=@ParentId and id=@EntityId)    
  and exists  (select 1 from userenquiry(nolock) where parentid=@ParentId and enquiryid=@EntityId)    
  begin    
  set @EntityName='enquiry'    
  end  
 end    
  
 if(@ProviderName = 'default')  
 begin  
  select top 1 @ProviderName = provider_name from tbl_voip_DefaultCallingService(nolock) dc  
   inner join tbl_voip_ServiceProvider(nolock) sp on dc.ServiceProviderId = sp.id   
  where dc.ParentId = @ParentId  
 end  
  
  
 --select @SrvProId =  ( select ServiceProviderId   
 --   from tbl_voip_DefaultCallingService(nolock)   
 --    where ParentId = @ParentId )   
  
  
 select @SrvProId = sp.Id from tbl_voip_ParentServiceMapping(nolock) psm   
 inner join tbl_voip_ServiceProvider(nolock) sp on psm.srv_pro_id  = sp.id  
  where parent_id = @ParentId and sp.provider_name = @ProviderName  
  
 if(isnull(@SrvProId, 0) = 0)    
 begin    
  set @SrvProId = 7    
 end    
    
 select @PsmapId = id from tbl_voip_ParentServiceMapping(nolock)  
   where parent_id  = (select ParentId from User_Detail(nolock) where USER_ID = @AgentId)  
    and is_active = 1 and srv_pro_id = @SrvProId  
   
 declare @PersonName nvarchar(255) = (  
  
      select top 1 Name from [CRM].[crmdb].[dbo].Pre_Enquiry with(nolock) where EnqNo = @EntityId 
   --case when @EntityName = 'lead'  
   -- then ( select PersonName from UserLeads(nolock) where ID  = @EntityId )  
   --when @EntityName = 'enquiry'  
   -- then ( select PersonName from UserEnquiry(nolock) where EnquiryID  = @EntityId )  
   --else '' end
   
   )  
  
 --select * from tbl_voip_endpointSetting(nolock) es  
 -- where psmap_id = @PsmapId and api_type_id = ( select id from tbl_voip_api_type(nolock)   
 --  where Lower(ltrim(rtrim(api_name)))  = Lower(ltrim(rtrim(@ApiName)))  
 --  and srv_pro_id = @SrvProId  
 -- )  
  
 print @SrvProId  
  
   if(@PsmapId is not null)    
   begin  
  print 'in side'  
    select * from tbl_voip_endpointSetting(nolock) es    
  where psmap_id = @PsmapId and api_type_id = ( select id from tbl_voip_api_type(nolock)     
   where Lower(ltrim(rtrim(api_name)))  = Lower(ltrim(rtrim(@ApiName)))    
   and srv_pro_id = @SrvProId    
  )    
    end    
   else     
   begin    
    select 0 as [id], endpoint_url, request_method, content_type, request_header_json, request_body_json, response_content, is_active, created_by, created_on, callback_endpint, callback_request, callback_response, api_type_id, 0 as psmap_id, is_deleted   
 
  from tbl_voip_endpointSetting(nolock) where id = 25    
   end    
    
 declare @DefaultCallerId nvarchar(255) = 'Any', @Dnid nvarchar(255) = ''  
  
 if(isnull(@SrvProId, 0) > 0)  
 begin  
  select @ProviderName = provider_name from tbl_voip_ServiceProvider(nolock) where id = @SrvProId   
  if(@SrvProId = 7)  
  begin  
   declare @PhoneNo nvarchar(50)  
  
   select top 1 @PhoneNo = p.PhoneNo from cloud_user_phone(nolock) p where p.Parentid= @ParentId  
    and p.Active = 1 and dbo.fn_getsipname(p.PhoneNo) = 'jio' order by p.userphid desc  
  
   print @PhoneNo  
  
   if(isnull(@PhoneNo, '') = '')  
   begin  
    select @PhoneNo = t.PhoneNo from ( select  
     row_number() over(partition by (select null) order by PhoneId) rn,  
     PhoneNo from Cloud_phone_master(nolock) where reservedfor is not null  
    ) t where t.rn = ROUND(RAND() * 50, 0)  
   end  
   select @DefaultCallerId = isnull(@PhoneNo, '8035391888'),  @Dnid = isnull(@PhoneNo, '8035391888')  
  
   set @DefaultCallerId = concat('+91', @DefaultCallerId)  -- Changes for DidNo change  
   set @Dnid = concat('+91', @Dnid)  
  
  end  
 end  
  
 if(exists(select * from tbl_voip_userAgentSetting(nolock)   
 where user_id = @AgentId and is_active = 1 and psmap_id = @PsmapId ))  
 begin  
  
  select a.*, ud.ParentID, sp.provider_name, @PersonName as CustomerName,   
   concat(trim(ud.FName), ' ', trim(ud.LName)) as AgentName    
   from tbl_voip_userAgentSetting(nolock) a   
   inner join tbl_voip_ParentServiceMapping(nolock) psm on a.psmap_id = psm.id  
   inner join tbl_voip_ServiceProvider(nolock) sp on psm.srv_pro_id = sp.id  
   inner join User_Detail(nolock) ud on a.user_id = ud.User_ID  
  where a.user_id = @AgentId and a.is_active = 1 and a.psmap_id = @PsmapId  
 end  
 else  
 begin  
  select 0 as [Id],     
   @AgentId as [user_id],    
   @AgentId as [ext_number],    
   ud.Mobile as [mobile_no],     
   @Dnid as [did_no],    
   @DefaultCallerId as [default_caller_no],     
   'm' as [default_machine],     
   1 as [IsActive],     
   getdate() as [created_on],    
   @AgentId as [created_by],    
   1 as [is_active],    
   0 as [psmap_id], ud.ParentID,   
   @ProviderName as [provider_name],  
   @PersonName as CustomerName,     
   concat(trim(ud.FName), ' ', trim(ud.LName)) as AgentName        
   from User_Detail(nolock) ud where ud.User_Id = @AgentId    
 end  
  
end  


