/* ============================================================
   Procedure: [dbo].[usp_voip_GetEndpointList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_voip_GetEndpointList](
	@ServiceProviderId bigint,
	@ParentId bigint,
	@FilterText nvarchar(255)  = '',
	@OffsetValue bigint = 0,
	@PagingSize bigint = 20
)
as
begin
	
	declare @ServiceParentMappingId  bigint = ( select top 1 id from tbl_voip_ParentServiceMapping(nolock) 
		where parent_id = @ParentId and srv_pro_id = @ServiceProviderId)

	select 
		count(Id) over() as TotalRow,
		* 
		from tbl_voip_endpointSetting(nolock) where psmap_id = @ServiceParentMappingId
		order by id desc
		offset @OffsetValue rows fetch  next @PagingSize rows only

end



