/* ============================================================
   Procedure: [dbo].[usp_voip_GetVoipInterationList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voip_GetVoipInterationList] (
	@OffsetValue INT = 0
	,@PagingSize INT = 20
	,@UserId BIGINT
	,@ClientText NVARCHAR(255) = ''
	,@CallFromDate NVARCHAR(255) = ''
	,@CallToDate NVARCHAR(255) = ''
	,@AgentText NVARCHAR(255) = ''
	)
AS
BEGIN
	--declare
	--	@OffsetValue int = 0,
	--	@PagingSize int  = 1000,
	--	@UserId bigint = 31871,
	--	@ClientText nvarchar(255) = N'',
	--	@CallFromDate nvarchar(255) = N'', --N'25-Feb-2022',
	--	@CallToDate nvarchar(255) = N'', --N'27-Feb-2022',
	--	@AgentText nvarchar(255) = N''
	
	DECLARE @ParentId BIGINT

	SELECT @ParentId = ParentID
	FROM User_Detail(NOLOCK)
	WHERE User_ID = @UserId

	DECLARE @fromdate DATE = CAST(DATEADD(dd, - 60, getdate()) AS DATE)
		,@todate DATE = cast(dateadd(dd, 1, cast(CAST(getdate() AS DATE) AS DATETIME)) AS DATE)

	IF (isnull(@CallFromDate, '') <> '')
	BEGIN
		SET @fromdate = Cast(@CallFromDate AS DATE)
	END

	IF (isnull(@CallFromDate, '') <> '')
	BEGIN
		SET @todate = cast(dateadd(dd, 1, cast(@CallToDate AS DATETIME)) AS DATE)
	END

	SELECT count(t.id) OVER () AS TotalRow
		,*
	FROM (
		SELECT ei.id
			,ei.created_on
			,ei.EntityName
			,ei.EntityId
			,en.PersonName
			,ei.ToMobileNo
			,ei.CallStatus
			,ei.RecordingUrl
			,en.ProfileImgFileName
			,ei.ProviderName as [provider_name]
			,CONCAT (
				isnull(ud.FName, '')
				,' '
				,isnull(ud.LName, '')
				) AS [AgentName]
			,ud.IMAGE AS [AgentImage]
			,uas.ext_number
			,isnull(uas.mobile_no, dbo.fnGetNumericValue(ud.Mobile)) as [mobile_no]
			,psm.parent_id
			,en.LeadNo
		FROM tbl_voip_endpointInteraction(NOLOCK) ei
		left join tbl_voip_endpointSetting(NOLOCK) es ON ei.voip_ep_id = es.id
		left join tbl_voip_ParentServiceMapping(NOLOCK) psm ON es.psmap_id = psm.id
		left join tbl_voip_ServiceProvider(NOLOCK) sp ON psm.srv_pro_id = sp.id
		left join User_Detail(NOLOCK) ud ON ei.AgentId = ud.User_ID
		left join tbl_voip_userAgentSetting(NOLOCK) uas ON ud.User_ID = uas.user_id and uas.psmap_id = psm.id
		left join UserEnquiry(NOLOCK) en ON lower(ei.EntityName) = 'enquiry'
			AND ei.EntityId = en.EnquiryID
		WHERE ei.tei_parentid = @ParentId and lower(ei.EntityName) = 'enquiry'
			AND 1 = (
				CASE 
					WHEN ISNULL(@ClientText, '') = '' THEN 1
					WHEN en.PersonName LIKE '%' + @ClientText + '%' THEN 1
					WHEN ei.ToMobileNo LIKE '%' + @ClientText + '%' THEN 1
					ELSE 0 END
				)
			AND 1 = (
				CASE 
					WHEN ud.FName LIKE '%' + @AgentText + '%'
						THEN 1
					WHEN ud.LName LIKE '%' + @AgentText + '%'
						THEN 1
					WHEN uas.mobile_no LIKE '%' + @AgentText + '%'
						THEN 1
					WHEN uas.ext_number LIKE '%' + @AgentText + '%'
						THEN 1
					ELSE 0
					END
				)
			AND cast(ei.created_on as date) BETWEEN CAST(@fromdate as date) AND cast(@todate as date)
		
		UNION
		
		SELECT ei.id
			,ei.created_on
			,ei.EntityName
			,ei.EntityId
			,ul.PersonName
			,ei.ToMobileNo
			,ei.CallStatus
			,ei.RecordingUrl
			,ul.ProfileImgFileName
			,ei.ProviderName as [provider_name]
			,CONCAT (
				isnull(ud.FName, '')
				,' '
				,isnull(ud.LName, '')
				) AS [AgentName]
			,ud.IMAGE AS [AgentImage]
			,uas.ext_number
			,isnull(uas.mobile_no, dbo.fnGetNumericValue(ud.Mobile)) as [mobile_no]
			,psm.parent_id
			,ul.LeadNo
		FROM tbl_voip_endpointInteraction(NOLOCK) ei
		left JOIN tbl_voip_endpointSetting(NOLOCK) es ON ei.voip_ep_id = es.id
		left JOIN tbl_voip_ParentServiceMapping(NOLOCK) psm ON es.psmap_id = psm.id
		left JOIN tbl_voip_ServiceProvider(NOLOCK) sp ON psm.srv_pro_id = sp.id
		LEFT JOIN User_Detail(NOLOCK) ud ON ei.AgentId = ud.User_ID
		LEFT JOIN tbl_voip_userAgentSetting(NOLOCK) uas ON ud.User_ID = uas.user_id
			AND uas.psmap_id = psm.id
		left JOIN UserLeads(NOLOCK) ul ON lower(ei.EntityName) = 'lead' AND ei.EntityId = ul.ID
		WHERE ei.tei_parentid = @ParentId and lower(ei.EntityName) = 'lead'
			AND 1 = (
				CASE 
					WHEN ISNULL(@ClientText, '') = '' THEN 1
					WHEN ul.PersonName LIKE '%' + @ClientText + '%' THEN 1
					WHEN ei.ToMobileNo LIKE '%' + @ClientText + '%' THEN 1
					ELSE 0 END
				)
			AND 1 = (
				CASE 
					WHEN ud.FName LIKE '%' + @AgentText + '%'
						THEN 1
					WHEN ud.LName LIKE '%' + @AgentText + '%'
						THEN 1
					WHEN uas.mobile_no LIKE '%' + @AgentText + '%'
						THEN 1
					WHEN uas.ext_number LIKE '%' + @AgentText + '%'
						THEN 1
					ELSE 0
					END
				)
			AND cast(ei.created_on as date) BETWEEN CAST(@fromdate as date) AND cast(@todate as date)
		) t
	ORDER BY t.id DESC OFFSET @OffsetValue Rows

	FETCH NEXT @PagingSize ROWS ONLY

	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId
		,@Activity_type = 'View_VoipCal_Rpt'
		,@ActionType = 'S'
		,@RowJson = ''
		,@Table_name = 'tbl_voip_endpointInteraction'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_voip_GetVoipMappedUserList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_voip_GetVoipMappedUserList (
	@OffsetValue int = 0,
	@PageSize  int = 10
)
as
begin
	select 
		 count(psm.id) over() as TotalRow,
		psm.Id, sp.provider_name, ud.User_Login, psm.created_on, psm.modified_on, psm.is_active, dcs.IsActive as IsDefault,
		sp.id as [SrvProId], psm.parent_id as ParentId
		from tbl_voip_ParentServiceMapping(nolock)  psm
		inner join tbl_voip_ServiceProvider(nolock) sp on psm.srv_pro_id = sp.id
		inner join User_Detail(nolock) ud on psm.parent_id = ud.User_ID
		left join tbl_voip_DefaultCallingService(nolock) dcs on psm.parent_id = dcs.ParentId  and sp.id = dcs.ServiceProviderId
	order by psm.id desc
		offset @OffsetValue rows fetch next @PageSize rows only
end



GO

/* ============================================================
   Procedure: [dbo].[usp_voip_GetWebhookResponseByEIId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_voip_GetWebhookResponseByEIId](
	@InteractionId bigint
)
as
begin
	
	declare @ProviderName nvarchar(255), @RefNo nvarchar(255)
	
	select @ProviderName = sp.provider_name,  @RefNo = ei.refNumber from   tbl_voip_endpointInteraction(nolock) ei
				inner join tbl_voip_endpointSetting(nolock) es on ei.voip_ep_id = es.id
					inner join tbl_voip_ParentServiceMapping(nolock) psm on es.psmap_id = psm.id
					inner join tbl_voip_ServiceProvider(nolock) sp on psm.srv_pro_id = sp.id
			where  ei.id = @InteractionId
	
	print  @RefNo

	if(@ProviderName = 'Mobile Like Number')
	begin
		select top 1 request_body from tbl_voip_Webhook(nolock) where UniqueIdentity = @RefNo
			order by id desc
	end
	else
	begin
		select top 1 request_body from tbl_voip_Webhook(nolock) where UniqueIdentity = @InteractionId
			order by id desc
	end

	--select request_body from tbl_voip_Webhook(nolock) where endpointid = @InteractionId

end



