/* ============================================================
   Procedure: [dbo].[usp_voip_InsertEndpointSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_voip_InsertEndpointSetting](
	@EndpontId bigint = 0,
	@EndpintUrl nvarchar(255),
	@RequestMethod nvarchar(50),
	@ContentType nvarchar(255) = null,
	@RequestHeaderJson nvarchar(max),
	@RequestBodyJson nvarchar(max),
	@ResponseContent nvarchar(max) = null,
	@IsActive bit,
	@CreatedBy bigint,
	@CallBackEndPoint nvarchar(max) = null,
	@CallBackRequest nvarchar(max) = null,
	@CallBackResponse nvarchar(max) = null,
	@ApiTypeId bigint,
	@PsmapId bigint,
	@ParentId bigint,
	@ServiceProviderId bigint
)
as
begin
	
	if(@EndpontId  > 0)
	begin
		update tbl_voip_endpointSetting set
			endpoint_url = @EndpintUrl,
			request_method= @RequestMethod,
			content_type= @ContentType,
			request_header_json= @RequestHeaderJson,
			request_body_json= @RequestBodyJson,
			response_content= @ResponseContent,
			is_active= @IsActive, 
			callback_endpint= @CallBackEndPoint,
			callback_request= @CallBackRequest,
			callback_response= @CallBackResponse,
			api_type_id= @ApiTypeId
			where id = @EndpontId
		
		select 'updated'
	end
	else
	begin
		if(exists(select 1 from tbl_voip_endpointSetting(nolock) 
				where [endpoint_url] = @EndpintUrl and api_type_id = @ApiTypeId and psmap_id  = @PsmapId))
		begin
			select 'exists'
		end
		else
		begin
			insert into tbl_voip_endpointSetting( endpoint_url, request_method, content_type, request_header_json, request_body_json, response_content, is_active, created_by, callback_endpint, callback_request, callback_response, api_type_id, psmap_id)
				values( @EndpintUrl, @RequestMethod, @ContentType, @RequestHeaderJson, @RequestBodyJson, @ResponseContent, @IsActive, @CreatedBy, @CallBackEndPoint,  @CallBackRequest, @CallBackResponse, @ApiTypeId,  ( select top 1 id from tbl_voip_ParentServiceMapping(nolock) where parent_id = @ParentId and srv_pro_id = @ServiceProviderId )  )
			select 'inserted'
		end
	end


end



GO

