/* ============================================================
   Procedure: [dbo].[usp_voip_InsertNewInteraction]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voip_InsertNewInteraction](      
 @RequestHeader nvarchar(max),      
 @RequestBody nvarchar(max),      
 @ResponseHeader nvarchar(max),      
 @ResponseContent nvarchar(max),      
 @ToMobileNo  nvarchar(50),      
 @VoipEndpointId bigint,      
 @EntityName nvarchar(50) = '',      
 @EntityId bigint = 0,      
 @AgentId bigint = 0,   
 @ProviderName nvarchar(max) = ''      
)      
as      
begin      
  
 --declare  
 -- @RequestHeader nvarchar(max),      
 -- @RequestBody nvarchar(max),      
 -- @ResponseHeader nvarchar(max),      
 -- @ResponseContent nvarchar(max),      
 -- @ToMobileNo  nvarchar(50),      
 -- @VoipEndpointId bigint,      
 -- @EntityName nvarchar(50) = '',      
 -- @EntityId bigint = 0,      
 -- @AgentId bigint = 0,   
 -- @ProviderName nvarchar(max) = ''      
  
   --declare @ToMobileNo nvarchar(50) = '+91-9821592374'
	
   declare @CountryCode nvarchar(5) = '+91', @MobileNo nvarchar(20)
	set @ToMobileNo = REPLACE(trim(@ToMobileNo), '-', ' ')
	drop table if exists #tempMobileNo
	select *, ROW_NUMBER() over (partition by (select null) order by(select null)) as [rno]
		into #tempMobileNo
			from string_split(@ToMobileNo, ' ')
	declare @mCount int  = 0;
	select @mCount = count(1) from #tempMobileNo
	if(@mCount > 1)
	begin
		select @CountryCode = trim([value]) from #tempMobileNo where rno = 1
		select @MobileNo = trim([value]) from #tempMobileNo where rno = 2
	end
	else
	begin
		set @MobileNo = trim(@ToMobileNo)
	end

	select @ToMobileNo = @MobileNo





 if(isnull(@ProviderName, '') = '')      
 begin      
  set @ProviderName = (       
   select sp.provider_name from tbl_voip_endpointSetting(nolock) es      
    inner join tbl_voip_ParentServiceMapping(nolock) psm on es.psmap_id = psm.id      
    inner join tbl_voip_ServiceProvider(nolock) sp on psm.srv_pro_id = sp.id      
   where es.id = @VoipEndpointId      
  )      
 end      
    
   declare @Username nvarchar(255), @ParentId bigint      
  select @Username = User_Login, @ParentId = ParentID from User_Detail(nolock) where User_ID = @AgentId    
    
  if @EntityName='enquiry'  
  begin  
  if not exists (select 1 from userenquiry(nolock) where parentid=@parentid and enquiryid=@entityid)  
  and exists  (select 1 from userleads(nolock) where parentid=@parentid and id=@entityid)  
  begin  
  set @EntityName='lead'  
  end  
  end  
  else if @EntityName='lead'  
  begin  
  if not exists (select 1 from userleads(nolock) where parentid=@parentid and id=@entityid)  
  and exists  (select 1 from userenquiry(nolock) where parentid=@parentid and enquiryid=@entityid)  
  begin  
  set @EntityName='enquiry'  
  end  
  
  end  
  
      
 insert into tbl_voip_endpointInteraction( request_header, request_body,       
   response_header, response_content, created_on, voip_ep_id,       
  ToMobileNo, EntityName, EntityId, AgentId, ProviderName, tei_parentid,CountryCode)      
 values( @RequestHeader, @RequestBody, @ResponseHeader,  @ResponseContent,       
    getdate(), @VoipEndpointId, @ToMobileNo, @EntityName, @EntityId, @AgentId, @ProviderName, @ParentId,@CountryCode)      
      
 declare @EndpointInteractionId bigint = SCOPE_IDENTITY()      
      
 if(@EndpointInteractionId> 0)  and (isnull(@entityname,'')<>'')
 begin      
     
  declare @eventDescription nvarchar(max) = concat(@Username,' called on mobile ', @ToMobileNo, ' through gateway ', @ProviderName, '.')      
  declare @eventName nvarchar(255) = ( case       
   when lower(@EntityName) = 'lead'      
    then 'Call made to lead through gateway'      
   when lower(@EntityName) = 'enquiry'      
    then 'Call made to enquiry through gateway'      
   end )      
        
  exec UspSaveEntityActivity_withid      
   @entityname = @EntityName,      
   @EntityID = @EntityId,      
   @UserID = @AgentId,      
   @ParentID = @ParentId,      
   @EventDescription = @eventDescription,      
   @EventName = @eventName,      
   @reftables = 'tbl_voip_endpointInteraction',      
   @refid = @EndpointInteractionId      
      
 end      
   
 select @EndpointInteractionId AS [EndpointInteractionId]  
 begin try    
 exec usp_createcalllog 'tbl_voip_endpointInteraction','id', @EndpointInteractionId,'Outgoing'   
 end try    
 begin catch    
 exec usp_inserterrorinfo    
 end catch     
   
   
  
end 


GO

