/* ============================================================
   Procedure: [dbo].[usp_voip_InsertWebhookData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voip_InsertWebhookData]
(                 
 @request_body nvarchar(max),                
 @ParentId bigint,                
 @SerProName nvarchar(255),              
 @UniqueIdentity nvarchar(255) = null              
)                
as                
begin                
	 set @SerProName = LTRIM(RTRIM(LOWER(@SerProName)))              
              
	 declare @ServiceProviderId bigint,@endpointid bigint;                
	 select @ServiceProviderId = id from tbl_voip_ServiceProvider(nolock)              
	  where LTRIM(RTRIM(LOWER(provider_name))) = case when lower(@SerProName) = 'mobilelikenumber'              
	   then 'Mobile Like Number' else @SerProName  end              
              
	if(ISNULL(@UniqueIdentity, '')  = '')              
	begin              
	set @UniqueIdentity = ( case              
	when @SerProName = 'voxbay'              
		then ( select [value] from openjson(@request_body) WHERE [key] = 'param1')              
	when @SerProName = 'mobilelikenumber'              
		then (select [value] from openjson(@request_body) WHERE [key] = 'refno')              
	when @SerProName like '%_Asterisk'              
		then (select [value] from openjson(@request_body) WHERE [key] = 'refno')          
	else '' end               
	)              
            
	select @endpointid=ID from tbl_voip_endpointInteraction(nolock)            
		where 1=case when @SerProName = 'voxbay' and @UniqueIdentity=cast(id AS nvarchar) then 1             
		when @SerProName ='CloudShope' and @UniqueIdentity= cast(id as nvarchar) then 1  
		when @SerProName ='mobilelikenumber' and @UniqueIdentity= refNumber then 1           
		when @SerProName =replace(providername,' ','') and @UniqueIdentity=cast(id as nvarchar) then 1 else 0 end       
        
	if @parentid=0      
	select @parentid =isnull([dbo].[ufn_GetUserParentId](agentid),0) from tbl_voip_endpointInteraction(nolock)  where id=@endpointid         
      
	end              
	begin try              
		if(ISNULL(@UniqueIdentity, '') <> '')              
		begin              
			declare @WebhookId bigint = 0              
			insert into tbl_voip_Webhook( request_body, ParentId, srv_pro_id, UniqueIdentity,endpointid)                
			values ( @request_body, @ParentId, @ServiceProviderId, @UniqueIdentity,@endpointid )              
			set @WebhookId = SCOPE_IDENTITY()              
              
			print concat(@UniqueIdentity, @SerProName, @request_body)              
			exec usp_voip_UpdateEntityActivity @UniqueIdentity, @SerProName, @request_body
		end  
		else
		begin
			declare @ToMobileNo  nvarchar(50) = '', @VoipEndpointId bigint = '', @EntityName nvarchar(50) = '',  @EntityId bigint = 0, @AgentId bigint =0,
				 @waid nvarchar(20), @ProviderName nvarchar(max) = @SerProName, @TeiExtention nvarchar(255) = '', @PsmapId bigint = 0;
				if(@SerProName = 'voxbay')
				begin
					select @waid = [value] from openjson(@request_body) where [key] = 'destination'
					select @TeiExtention = [value] from openjson(@request_body) where [key] = 'extension'
										
					select @PsmapId = id from tbl_voip_ParentServiceMapping(nolock) where parent_id = @ParentId and srv_pro_id = ( 
						select id from tbl_voip_ServiceProvider(nolock) where provider_name =  @SerProName )

					select @VoipEndpointId = id from tbl_voip_endpointSetting(nolock) where psmap_id = @PsmapId


					select @AgentId = user_id from tbl_voip_userAgentSetting(nolock) where psmap_id = @PsmapId and ext_number = @TeiExtention

					DECLARE @cc nvarchar(10), @c nvarchar(50), @no nvarchar(20);
					SELECT @cc = countrycode, @c = Country_Name
					FROM MySMS.dbo.m_country1
					WHERE SUBSTRING(@waid, 1, LEN(replace(countrycode, '+', ''))) = replace(countrycode, '+', '');
					SELECT @no = RIGHT(@waid, LEN(@waid) - LEN(replace(@cc, '+', '')));

					set @ToMobileNo = concat(@cc, ' ', @no)

					select @EntityId = ID, @EntityName = 'Lead' from UserLeads(nolock) 
						where @no in (MobileNo, MobileNo1, MobileNo2) and ParentID= @ParentId

					if(@EntityId = 0)
					begin
						select @EntityId = EnquiryID, @EntityName = 'Enquiry' from UserEnquiry(nolock) 
							where @no in (MobileNo, MobileNo1, MobileNo2) and ParentID= @ParentId
					end

					insert into tbl_voip_endpointInteraction(created_on, voip_ep_id, ToMobileNo, EntityName, EntityId, AgentId,ProviderName,tei_extension, tei_parentid, tei_direction )
						select getdate(), @VoipEndpointId, @ToMobileNo, @EntityName, @EntityId, @AgentId, @ProviderName, @TeiExtention, @ParentId, 'Incoming'
				
					set @UniqueIdentity = SCOPE_IDENTITY();
					set @endpointid = @UniqueIdentity
           
					insert into tbl_voip_Webhook( request_body, ParentId, srv_pro_id, UniqueIdentity,endpointid)                
					values ( @request_body, @ParentId, @ServiceProviderId, @UniqueIdentity,@endpointid )              
					set @WebhookId = SCOPE_IDENTITY()              
              
					print concat(@UniqueIdentity, @SerProName, @request_body)              
					exec usp_voip_UpdateEntityActivity @UniqueIdentity, @SerProName, @request_body

					exec usp_createcalllog @reftable = 'tbl_voip_endpointInteraction',@refcolumn = 'id', @refid = @UniqueIdentity, @direction = 'Incoming'
				end
		end
	  
		if( @WebhookId > 0 and @SerProName = 'MobileLikeNumber')              
		begin               
			exec usp_voip_DedectCallCharge @WebhookId, @SerProName                 
		end              
 
		exec usp_updatecalllog_withreftable 'tbl_voip_Webhook',@WebhookId
            
	 end try              
	 begin catch              
	  exec usp_InsertErrorInfo              
	 end catch              
              
	 select @WebhookId              
end  



GO

/* ============================================================
   Procedure: [dbo].[usp_voip_IsAgentElagibleForCalling]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voip_IsAgentElagibleForCalling]      
(      
  @AgentId bigint      
)      
as      
begin    
   
	--declare   
	--@AgentId bigint = 42083  
  
	declare @ParentId bigint = ( select ParentID from User_Detail(nolock) where User_ID = @AgentId )  
	declare @TotalBalance decimal(18, 4) = 0, @MinimumBalance decimal(18, 4), @ProviderName nvarchar(255)  
	select  @TotalBalance = balance FROM IntCredit_Details c with (nolock) where user_ID=@ParentId and Credit_ID=(select max(credit_id) from IntCredit_Details c1 with (nolock)  where c.user_id=c1.User_ID)      
      
	select top 1 @MinimumBalance = amount from       
		tbl_ims_MinimumCallMoney(nolock) where parentid = @ParentId or parentid = 0 order by id desc   
    
	select @ProviderName = 'Kit19 80'  
      
	select @ProviderName = provider_name from tbl_voip_ServiceProvider(nolock) where id = ( select top 1 ServiceProviderId       
		from tbl_voip_DefaultCallingService(nolock)  where ParentId = @ParentId order by id desc)      
  
	declare @PluseRate decimal(18, 4) = 0  
  
	select top 1 @PluseRate = Price from tbl_obd_Base_Price(nolock)   
		where service_type = 'click2call' and ( parentid = @ParentId or parentid = 0) order by id desc   
  
	DECLARE @avilableBalance decimal(18,4) = dbo.GetAvailableBalanceForService(@parentid, 1)  
  
	if(trim(lower(isnull(@ProviderName, ''))) in ('mobile like number', 'kit19 80', 'kit19' ))      
	begin      
		if(@avilableBalance >= @MinimumBalance or @PluseRate = 0 )      
		begin      
			select 1 as 'status', 'success' as 'msg'      
		end      
		else      
		begin      
			select 0 as 'status', 'Balance is not sufficient for click to call service.' as 'msg'      
		end      
	end      
	else      
	begin      
		select 1 as 'status', 'success' as 'msg'      
	end      
      
end   



GO

