/* ============================================================
   Procedure: [dbo].[usp_voip_IvrDesignOperationByMode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_voip_IvrDesignOperationByMode(
	@DesignId bigint = 0,
	@DesignName nvarchar(255) = null,
	@DesignJson nvarchar(max) = null,
	@UserId bigint = 0,
	@Mode nvarchar(25) = 'LS'
)
as
begin
	declare @ParentId bigint = 0

	select @ParentId  = ParentID from User_Detail(nolock) where User_Id = @UserId

	if(@Mode = 'IN')
	begin
		if(not exists(select 1 from tbl_voip_IvrDesign(nolock) 
			where parent_id = @ParentId and design_name = @DesignName))
		begin
			declare @IvrDesignId bigint, @isDefault bit = 0

			set @isDefault = iif(exists(select 1 from tbl_voip_IvrDesign(nolock) where parent_id = @ParentId), 0 , 1)

			insert into tbl_voip_IvrDesign(design_name, design_json, created_by, parent_id, is_default)
				select @DesignName, @DesignJson, @UserId, @ParentId, @isDefault 

			set @IvrDesignId = SCOPE_IDENTITY()
			select @IvrDesignId as [IvrDesign], 'IVR design saved successfully' as [message]
		end
		else
		begin
			select 0 as [status], 'IVR design name already exists' as [message]
		end
	end


	if(@Mode = 'LS')
	begin
		select id, design_name, design_json 
			from tbl_voip_IvrDesign(nolock) where parent_id = @ParentId
	end
end



