/* ============================================================
   Procedure: [dbo].[usp_voip_NotifiyFailedCallCount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_voip_NotifiyFailedCallCount]
as
begin
	declare @Minutes int 
	set @Minutes = DATEPART(MINUTE, getdate())
	
	if(@Minutes between 0 and 6)
	begin

		declare @fBody nvarchar(max) = '', @fTableSql nvarchar(max), @fTableData nvarchar(max)
		set @fBody = '<html><body><H1>Dear Reader</H1><p>Call Count by Status till now for Today </p>'

		set @fTableSql = '<table border = 2><tr><th>CallStatus</th><th>Count</th></tr>';  
  
		select 
			@fTableData = CONCAT( @fTableData,  CONCAT('<tr><td>', id, '</td><td>', response_content,  '</td><td>', refNumber, '</td></tr>'))  
		from tbl_voip_endpointInteraction(nolock) ei
		where id > 195099 and ISNULL(isNotify, 0)  = 0 
			and webhookReceivedAt is null and ProviderName = 'Mobile Like Number'
			and DATEDIFF(MINUTE, created_on, GETDATE()) > 5

		select 
			@fTableData = CONCAT( @fTableData,  CONCAT('<tr><td>', CallStatus, '</td><td>', CallCount,  '</td></tr>'))  
		from ( select CASE WHEN GROUPING(p.status) = 1 THEN UPPER('attempted')
				ELSE UPPER(p.status) END as [CallStatus], COUNT(p.status) as CallCount
			from ( select ( (select cStatus from openjson(request_body) with ( cStatus nvarchar(50) '$.Status')) ) as status
				from tbl_voip_Webhook(nolock) where srv_pro_id = 4 and CAST(created_on as date)  = CAST(getdate() as date)) p where p.status <> 'null'
			group by  p.status with rollup
		) t where t.CallStatus in ('CHANUNAVAIL', 'CONGESTION', 'ATTEMPTED')


		set @fBody = @fBody + @fTableSql + @fTableData + '</table></body></html>';  


		select @fBody

		exec usp_enqueueemail
			@profile_name = 'Alerts',   
			@recipients = 'shashi.rana@vispl.in;ajay.koul@vispl.in',
			@copy_recipients = 'karuna@pelsoftlabs.in;mukesh-kumar@pelsoftlabs.in;mayank.nigam@pelsoftlabs.in;animesh.shukla@pelsoftlabs.in;tanweer.alam@pelsoftlabs.in;rishabh.pandey@pelsoftlabs.in;animesh.shukla@pelsoftlabs.in;vaishali.kalra@pelsoftlabs.in',
			--@recipients = 'mukesh-kumar@pelsoftlabs.in',
			@blind_copy_recipients = 'mayank.nigam@pelsoftlabs.in',  
			@subject = 'Smartping ClickToCall Call Count Status', @body = @fBody, @body_format = 'HTML'


	end

end



