/* ============================================================
   Procedure: [dbo].[usp_voip_SaveParentMappingSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_voip_SaveParentMappingSetting
(
	@SrvProId bigint,
	@ParentId bigint,
	@IsActive bit = 1, 
	@IsDefault bit = 0,
	@CreatedBy bigint
)
as
begin
	if(not exists( select *  from tbl_voip_ParentServiceMapping(nolock) 
			where parent_id = @ParentId and srv_pro_id = @SrvProId)
	)
	begin
		if(@SrvProId = 4)
		begin
			if(not exists(select * from 
				tbl_voip_InternalServiceProviderMapping(nolock) where parent_id = @ParentId and serv_pro_id = @SrvProId))
			begin
				insert into tbl_voip_InternalServiceProviderMapping( parent_id, serv_pro_id, is_active, created_on )
					values( @ParentId, @SrvProId, 1, getdate())
			end
		end

		insert into tbl_voip_ParentServiceMapping (parent_id, srv_pro_id, is_active, created_on, created_by )
			values( @ParentId, @SrvProId, @IsActive, GETDATE(), @CreatedBy)

		declare @psmId bigint  = scope_identity()

		if(@SrvProId = 4)
		begin
			insert into tbl_voip_endpointSetting(endpoint_url, request_method, content_type, request_header_json, request_body_json, is_active, created_by, created_on, api_type_id, psmap_id, is_deleted)
				values( 'http://43.242.246.83:8170/api/c2c/process', 'POST',  'application/json', '[]', '[{"key":"secretKey","value":"#mlnSecretKey#"},{"key":"clientId","value":"#mlnClientId#"},{"key":"agentNumber","value":"#FromMobileNo#"},{"key":"customerNumber","value":"#ToMobileNo#"},{"key":"agentName","value":"#AgentName#"},{"key":"customerName","value":"#PersonName#"},{"key":"callerId","value":"08037202720"}]', 1,  @CreatedBy, GETDATE(), 5, @psmId, 0)
		end

		if(@IsDefault = 1)
		begin
			exec usp_voip_ChangeStatusParentMapping @SrvProId, @ParentId,@IsDefault, @IsDefault, 'IsDefault'
		end
		select 1
	end
	else 
	begin
		select -2
	end
end



GO

