CREATE   PROCEDURE usp_voip_SetupDefaultProvider
(
	@ParentId bigint
)
as
begin
	--declare  @ParentId bigint = 34594
	if(exists(select 1 from tbl_voip_ServiceProvider(nolock) sp where sp.id not in (
		select srv_pro_id from tbl_voip_ParentServiceMapping(nolock) psm 
		where psm.parent_id = @ParentId
	)))
	begin

		insert into tbl_voip_ParentServiceMapping( parent_id, created_by, created_on, is_active, srv_pro_id )
			select  @ParentId, @ParentId, getdate(), 1, sp.id from tbl_voip_ServiceProvider(nolock) sp where sp.id not in (
		select srv_pro_id from tbl_voip_ParentServiceMapping(nolock) psm 
		where psm.parent_id = @ParentId)

		if(not exists(select 1 from tbl_voip_DefaultCallingService(nolock)))
		begin
			print 'exists'
			declare @ServiceProvider bigint = (select id from tbl_voip_ServiceProvider(nolock) sp where trim(lower(sp.provider_name)) = 'kit19')
			insert into tbl_voip_DefaultCallingService( ServiceProviderId, ParentId, IsActive, CreatedOn )
				values ( @ServiceProvider, @ParentId, 1, getdate())
		end
	end
