/* ============================================================
   Procedure: [dbo].[usp_voip_SetupKit1980ForParentUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voip_SetupKit1980ForParentUser](
	@ParentId bigint, 
	@SerProId bigint
)
as
begin
	
	--declare 
	--	@ParentId bigint  = 30846, 
	--	@SerProId bigint = 7

	begin try
		begin transaction	
		declare
			@InternalServiceId bigint = 0,
			@ParentServiceMappingId bigint = 0,
			@ProviderName nvarchar(255)

		select @ProviderName = provider_name from tbl_voip_ServiceProvider(nolock) 
			where id = @SerProId

		if exists ( select * from tbl_voip_InternalServiceProviderMapping(nolock)
			where parent_id  = @ParentId and serv_pro_id = @SerProId )
		begin
			update tbl_voip_InternalServiceProviderMapping set
				is_active  = 1 where parent_id  = @ParentId and serv_pro_id = @SerProId

			select @InternalServiceId = id from tbl_voip_InternalServiceProviderMapping(nolock) 
				where parent_id  = @ParentId and serv_pro_id = @SerProId
		end
		else
		begin
			insert into tbl_voip_InternalServiceProviderMapping( parent_id, serv_pro_id, is_active, created_on)
				select  @ParentId, @SerProId, 1, getdate() 
			set @InternalServiceId = scope_identity()
		end

		if exists ( select * from tbl_voip_ParentServiceMapping(nolock)
			where parent_id  = @ParentId and srv_pro_id = @SerProId )
		begin
			update tbl_voip_ParentServiceMapping set
				is_active = 1 where parent_id  = @ParentId and srv_pro_id = @SerProId

			select @ParentServiceMappingId = id from tbl_voip_ParentServiceMapping(nolock) 
				where parent_id  = @ParentId and srv_pro_id  = @SerProId
		end
		else
		begin
			insert into tbl_voip_ParentServiceMapping( parent_id, created_by, created_on, is_active, srv_pro_id)
				select @ParentId, @ParentId, getdate(), 1, @SerProId
			set @ParentServiceMappingId = scope_identity()
		end

		declare @endpointSettingId bigint = 0
		declare @RequestBodyJson nvarchar(max) = N'[{"key":"exten","value":"#FromMobileNo#"},{"key":"number","value":"#ToMobileNo#"},{"key":"did","value":"#CallerId#"},{"key":"type","value":"P"},{"key":"id","value":"#UniqueIdentity#"},{"key":"t1","value":"jio"},{"key":"t2","value":"jio"}]', @RequestHeaderJson nvarchar(max) = N'[]', 
		 @EndpointUrl nvarchar(max) = N'http://103.78.247.11/Click2Call/c2c.php', @RequestMethod nvarchar(50) = 'POST', @ContentType nvarchar(255) = 'application/x-www-form-urlencoded', @ApiTypeid int = 8

		if exists ( select 1 from tbl_voip_endpointSetting(nolock) 
			where api_type_id = @ApiTypeid and psmap_id = @ParentServiceMappingId)
		begin
			update tbl_voip_endpointSetting set
				is_active = 1 where api_type_id = @ApiTypeid and psmap_id = @ParentServiceMappingId
			
			select @endpointSettingId = id from tbl_voip_endpointSetting(nolock) 
				where api_type_id = @ApiTypeid and psmap_id = @ParentServiceMappingId
		end
		else
		begin
			insert into tbl_voip_endpointSetting( endpoint_url, request_method, content_type, request_header_json, request_body_json, is_active, created_by, api_type_id, psmap_id)
			select @EndpointUrl, @RequestMethod, @ContentType, @RequestHeaderJson, @RequestBodyJson, 1, @ParentId, @ApiTypeid, @ParentServiceMappingId
		
			set @endpointSettingId = scope_identity()
		end

		declare @DefaultCallingServiceId bigint = 0
		if exists(select * from tbl_voip_DefaultCallingService(nolock)
			where ParentId = @ParentId and ServiceProviderId = @SerProId)
		begin
			update tbl_voip_DefaultCallingService set
				IsActive = 1 where ParentId = @ParentId and ServiceProviderId = @SerProId
			select @DefaultCallingServiceId = id from tbl_voip_DefaultCallingService(nolock)
				where ParentId = @ParentId and ServiceProviderId = @SerProId
		end
		else
		begin
			insert into tbl_voip_DefaultCallingService(ServiceProviderId, ParentId, IsActive)
				select @SerProId, @ParentId, 1
			set @DefaultCallingServiceId  = scope_identity()
		end

		declare @ClickToCallSettingId bigint = 0
		if exists(select 1 from tbl_ClickToCallSetting(nolock) where parentId = @ParentId)
		begin
			update tbl_ClickToCallSetting set
				incoming_provider = @ProviderName,
				outgoing_provider = @ProviderName
					where parentId = @ParentId

			select @ClickToCallSettingId = id from tbl_ClickToCallSetting(nolock) where parentId = @ParentId
		end
		else
		begin
			insert into tbl_ClickToCallSetting(parentId, incoming_provider, outgoing_provider)
				select @ParentId, @ProviderName, @ProviderName
			set @ClickToCallSettingId  = scope_identity()
		end
	
		commit transaction;
	
		select 
			@InternalServiceId as InternalServiceId, 
			@ParentServiceMappingId as ParentServiceMappingId,
			@endpointSettingId as endpointSettingId,
			@DefaultCallingServiceId as DefaultCallingServiceId,
			@ClickToCallSettingId as ClickToCallSettingId

	end try
	begin catch
		rollback transaction;
		select 'data'
	end catch

end



GO

