/* ============================================================
   Procedure: [dbo].[USP_VOIP_ToGettheCallDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  
CREATE   PROCEDURE USP_VOIP_ToGettheCallDetails(     
 @ToNo nvarchar(255),    
 @ParentID nvarchar(255)    
)  
as      
begin      
  declare @EntityName nvarchar(255) = '', @EntityId bigint = 0    

       select @ParentID  = isnull(ParentID,0) from User_Detail with(nolock) where  user_Id = @ParentID
    
  select top 1 @EntityName = 'lead', @EntityId = ID from UserLeads(nolock) ul    
   where ParentID = @ParentID and @ToNo in (MobileNo, MobileNo1, MobileNo2) order by ID desc    
    
  if(isnull(@EntityName, '') = '')    
  begin    
   select top 1 @EntityName = 'enquiry', @EntityId = EnquiryID from UserEnquiry(nolock) ue    
    where ParentID = @ParentID and @ToNo in (MobileNo, MobileNo1, MobileNo2) order by EnquiryID desc    
  end    
  select @EntityName as [EntityName], @EntityId as [EntityId]    
end   


GO

