/* ============================================================
   Procedure: [dbo].[usp_voip_UpdateEndpointInteractionKit1980]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voip_UpdateEndpointInteractionKit1980](    
    @IdentityId bigint        
)        
as        
begin        
      
--declare      
-- @IdentityId bigint = 4047112        
         
 declare @WebhookMode nvarchar(255) = '', @Kit19Webhook nvarchar(max) = ''        
 select @WebhookMode = mode, @Kit19Webhook = request_body from tbl_voip_Kit19Webhooks(nolock) where id = @IdentityId        
        
 declare         
  @UniqueIdentityId bigint,        
  @ServiceProvideName nvarchar(255),        
  @ServiceProvideId bigint,        
  @ParentId bigint        
        
 set @UniqueIdentityId = cast(json_value(@Kit19Webhook, '$.Id') as bigint)        
        
 if(@UniqueIdentityId > 0)        
 begin        
        
  select @ServiceProvideName = ProviderName, @ParentId = tei_parentid         
   from tbl_voip_endpointInteraction(nolock) where Id = @UniqueIdentityId        
        
  select @ServiceProvideId = id from tbl_voip_ServiceProvider(nolock) where provider_name = @ServiceProvideName        
        
  update tbl_voip_Kit19Webhooks set        
   ParentId = @ParentId,        
   srv_pro_id = @ServiceProvideId,        
   UniqueIdentity =@UniqueIdentityId        
  where id = @IdentityId        
        
  drop table if exists #tempHook        
        
  select * into #tempHook from openjson(@Kit19Webhook) with (        
   Id bigint '$.Id',        
   AgentMobile nvarchar(255) '$.AgentMobile',        
   Dnid nvarchar(255) '$.Dnid',        
   AgentCallUniqueId nvarchar(255) '$.AgentCallUniqueId',        
   CustomerCallUniqueid nvarchar(255) '$.CustomerCallUniqueid',        
   CustomerNoWithCountryCode nvarchar(255) '$.CustomerNoWithCountryCode',        
   AgentCallDuration nvarchar(255) '$.AgentCallDuration',        
   CustomerCallDuration nvarchar(255) '$.CustomerCallDuration',        
   CallEndTime nvarchar(255) '$.CallEndTime',        
   mode nvarchar(255) '$.mode',        
   AgentChannelid nvarchar(255) '$.AgentChannelid',        
   CustomerChannelid nvarchar(255) '$.CustomerChannelid',        
   CustomerDialStatus nvarchar(255) '$.CustomerDialStatus',        
   CustomerCallTime nvarchar(255)'$.CustomerCallTime',        
   AgentDialStatus nvarchar(255) '$.AgentDialStatus',        
   AgentcallTime nvarchar(255) '$.AgentcallTime',    
   RecordUrl nvarchar(255) '$.RecordUrl'    
  )        
      
  update ei set         
     ei.kei_AgentMobile = case when isnull(th.AgentMobile, '') <> '' then  th.AgentMobile        
      else ei.kei_AgentMobile end,        
     ei.kei_Dnid = case when isnull(th.Dnid, '') <> '' then  th.Dnid        
      else ei.kei_Dnid end,        
     ei.kei_AgentCallUniqueId = case when isnull(th.AgentCallUniqueId, '') <> '' then  th.AgentCallUniqueId        
      else ei.kei_AgentCallUniqueId end,        
     ei.kei_CustomerCallUniqueid = case when isnull(th.CustomerCallUniqueid, '') <> '' then  th.CustomerCallUniqueid        
      else ei.kei_CustomerCallUniqueid end,        
     ei.kei_CustomerNoWithCountryCode = case when isnull(th.CustomerNoWithCountryCode, '') <> ''       
      then  th.CustomerNoWithCountryCode else ei.kei_CustomerNoWithCountryCode end,        
      ei.kei_AgentCallDuration = case when isnull(th.AgentCallDuration, '') <> '' then  try_convert(int, th.AgentCallDuration)        
      else ei.kei_AgentCallDuration end,        
     ei.kei_CustomerCallDuration = case when isnull(th.CustomerCallDuration, '') <> '' then try_convert(int, th.CustomerCallDuration ) else ei.kei_CustomerCallDuration end,        
     ei.kei_CallEndTime = case when isnull(th.CallEndTime, '') <> '' then  dbo.fn_StrToDate(th.CallEndTime)        
      else ei.kei_CallEndTime end,        
     ei.kei_mode = case when isnull(th.mode, '') <> '' then  th.mode        
      else ei.kei_mode end,        
     ei.kei_AgentChannelid = case when isnull(th.AgentChannelid, '') <> '' then  th.AgentChannelid        
      else ei.kei_AgentChannelid end,        
     ei.kei_CustomerChannelid = case when isnull(th.CustomerChannelid, '') <> '' then  th.CustomerChannelid        
      else ei.kei_CustomerChannelid end,        
     ei.kei_CustomerDialStatus = case when isnull(th.CustomerDialStatus, '') <> '' then  th.CustomerDialStatus        
      else ei.kei_CustomerDialStatus end,        
     ei.kei_CustomerCallTime = case when isnull(th.CustomerCallTime, '') <> '' then dbo.fn_StrToDate(th.CustomerCallTime)        
      else ei.kei_CustomerCallTime end,        
     ei.kei_AgentDialStatus = case when isnull(th.AgentDialStatus, '') <> '' then  th.AgentDialStatus        
      else ei.kei_AgentDialStatus end,        
     ei.kei_AgentcallTime = case when isnull(th.AgentcallTime, '') <> '' then dbo.fn_StrToDate(th.AgentcallTime)        
      else ei.kei_AgentcallTime end,    
     ei.RecordingUrl = case when isnull(th.RecordUrl, '') <> '' then th.RecordUrl     
  else ei.RecordingUrl end    
     
  from #tempHook th         
  inner join tbl_voip_endpointInteraction(nolock) ei on th.id = ei.id        
        
  if(not exists(select * from calllog(nolock)         
   where reftable = 'tbl_voip_endpointInteraction' and refid = @UniqueIdentityId))        
  begin        
   exec dbo.usp_createcalllog 'tbl_voip_endpointInteraction', 'id', @UniqueIdentityId, 'Outgoing'        
  end        
        
   declare @CallLog bigint  = 0        
   select top 1 @CallLog = id from calllog(nolock)         
    where reftable = 'tbl_voip_endpointInteraction' and refid = @UniqueIdentityId        
   order by id desc        
        
   if(@CallLog > 0)        
   begin        
      
       
      
 print concat('update ', ' section @CallLog => ', @CallLog        )      
      
    update cl set       
         cl.Agentpickuptime = case when isnull(ei.kei_AgentcallTime, '') <> ''         
          then ei.kei_AgentcallTime else cl.Agentpickuptime end,        
             
         cl.Customerpickuptime = case when isnull(ei.kei_CustomerCallTime, '') <> ''         
          then ei.kei_CustomerCallTime else cl.Customerpickuptime end,        
        
         cl.agentduration = case         
          when isnull(ei.kei_AgentcallTime, '') <> '' and isnull( ei.kei_CallEndTime, '') <> ''        
           then datediff(second, ei.kei_AgentcallTime, ei.kei_CallEndTime ) else cl.agentduration end,        
             
         cl.Calldurationseconds = case         
          when isnull(ei.kei_AgentcallTime, '') <> '' and isnull( ei.kei_CallEndTime, '') <> ''        
           then datediff(second, ei.kei_AgentcallTime, ei.kei_CallEndTime ) else cl.agentduration end,        
             
         cl.customerduration = case        
          when isnull(ei.kei_CustomerCallTime, '') <> '' and isnull( ei.kei_CallEndTime, '') <> ''        
           then datediff(second, ei.kei_CustomerCallTime, ei.kei_CallEndTime ) else cl.customerduration end,        
         
         cl.customercalldisposition = case when isnull(ei.kei_CustomerDialStatus, '') <> ''           
          then ei.kei_CustomerDialStatus else cl.customercalldisposition end,                
            
        cl.agentcalldisposition = case when isnull(ei.kei_AgentDialStatus, '') <> ''         
           then ei.kei_AgentDialStatus else cl.agentcalldisposition end,        
        
         cl.Callendtime = case when isnull(ei.kei_CallEndTime, '') <> ''         
          then ei.kei_CallEndTime else cl.Callendtime end,    
    
         cl.recordurl = case 
            when isnull(ei.RecordingUrl, '') <> '' and ei.RecordingUrl not like '%c2c_%' 
                then replace(ei.RecordingUrl,'recordings.kit19.com/','recordings.kit19.com/'+cast(tei_parentid as nvarchar)
                    +'/'+format(created_on,'ddMMMyyyy')+'/C2C_')
            when ei.RecordingUrl like '%/C2C_Calls%'  
                then replace(RecordingUrl,'recordings.kit19.com/C2C_Calls/','recordings.kit19.com/'
                    +cast(tei_parentid as nvarchar)+'/'+format(cl.Callstarttime, 'ddMMMyyyy')+'/C2C_')
            when isnull(ei.RecordingUrl, '') <> '' then ei.RecordingUrl
         else cl.recordurl end,    
        
         cl.Dnid = case when isnull(ei.kei_Dnid, '') <> ''         
          then ei.kei_Dnid else cl.Dnid end    
    
    from calllog(nolock) cl inner join         
     tbl_voip_endpointInteraction(nolock) ei on cl.refid = ei.id and cl.reftable = 'tbl_voip_endpointInteraction'        
    where cl.id = @CallLog        
   end        
          
        
  begin try        
   if(lower(@WebhookMode) = 'mobilecallend')        
   begin        
    exec usp_voip_DedectCallChargeKit1980 @UniqueIdentityId        
   end        
  end try        
  begin catch         
   exec dbo.usp_InsertErrorInfo        
  end catch        
        
 end        
end 



GO

/* ============================================================
   Procedure: [dbo].[usp_voip_UpdateEndpointInteractionKit1980_update]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

      
CREATE   PROCEDURE usp_voip_UpdateEndpointInteractionKit1980_update(      
 @IdentityId bigint      
)      
as      
begin      
    
    
--declare    
-- @IdentityId bigint = 260      
       
 declare @WebhookMode nvarchar(255) = '', @Kit19Webhook nvarchar(max) = ''      
 select @WebhookMode = mode, @Kit19Webhook = request_body from tbl_voip_Kit19Webhooks(nolock) where id = @IdentityId      
      
 declare       
  @UniqueIdentityId bigint,      
  @ServiceProvideName nvarchar(255),      
  @ServiceProvideId bigint,      
  @ParentId bigint      
      
 set @UniqueIdentityId = cast(json_value(@Kit19Webhook, '$.Id') as bigint)      
      
 if(@UniqueIdentityId > 0)      
 begin      
      
  select @ServiceProvideName = ProviderName, @ParentId = tei_parentid       
   from tbl_voip_endpointInteraction(nolock) where Id = @UniqueIdentityId      
      
  select @ServiceProvideId = id from tbl_voip_ServiceProvider(nolock) where provider_name = @ServiceProvideName      
      
  update tbl_voip_Kit19Webhooks set      
   ParentId = @ParentId,      
   srv_pro_id = @ServiceProvideId,      
   UniqueIdentity =@UniqueIdentityId      
  where id = @IdentityId      
      
  drop table if exists #tempHook      
      
  select * into #tempHook from openjson(@Kit19Webhook) with (      
   Id bigint '$.Id',      
   AgentMobile nvarchar(255) '$.AgentMobile',      
   Dnid nvarchar(255) '$.Dnid',      
   AgentCallUniqueId nvarchar(255) '$.AgentCallUniqueId',      
   CustomerCallUniqueid nvarchar(255) '$.CustomerCallUniqueid',      
   CustomerNoWithCountryCode nvarchar(255) '$.CustomerNoWithCountryCode',      
   AgentCallDuration nvarchar(255) '$.AgentCallDuration',      
   CustomerCallDuration nvarchar(255) '$.CustomerCallDuration',      
   CallEndTime nvarchar(255) '$.CallEndTime',      
   mode nvarchar(255) '$.mode',      
   AgentChannelid nvarchar(255) '$.AgentChannelid',      
   CustomerChannelid nvarchar(255) '$.CustomerChannelid',      
   CustomerDialStatus nvarchar(255) '$.CustomerDialStatus',      
   CustomerCallTime nvarchar(255)'$.CustomerCallTime',      
   AgentDialStatus nvarchar(255) '$.AgentDialStatus',      
   AgentcallTime nvarchar(255) '$.AgentcallTime',
   RecordUrl nvarchar(255) '$.RecordUrl'      
  )      
    
  update ei set       
   ei.kei_AgentMobile = case when isnull(th.AgentMobile, '') <> '' then  th.AgentMobile      
    else ei.kei_AgentMobile end,      
   ei.kei_Dnid = case when isnull(th.Dnid, '') <> '' then  th.Dnid      
    else ei.kei_Dnid end,      
   ei.kei_AgentCallUniqueId = case when isnull(th.AgentCallUniqueId, '') <> '' then  th.AgentCallUniqueId      
    else ei.kei_AgentCallUniqueId end,      
   ei.kei_CustomerCallUniqueid = case when isnull(th.CustomerCallUniqueid, '') <> '' then  th.CustomerCallUniqueid      
    else ei.kei_CustomerCallUniqueid end,      
   ei.kei_CustomerNoWithCountryCode = case when isnull(th.CustomerNoWithCountryCode, '') <> ''     
 then  th.CustomerNoWithCountryCode else ei.kei_CustomerNoWithCountryCode end,      
   ei.kei_AgentCallDuration = case when isnull(th.AgentCallDuration, '') <> '' then  try_convert(int, th.AgentCallDuration)      
    else ei.kei_AgentCallDuration end,      
   ei.kei_CustomerCallDuration = case when isnull(th.CustomerCallDuration, '') <> '' then try_convert(int, th.CustomerCallDuration )      
    else ei.kei_CustomerCallDuration end,      
   ei.kei_CallEndTime = case when isnull(th.CallEndTime, '') <> '' then  dbo.fn_StrToDate(th.CallEndTime)      
    else ei.kei_CallEndTime end,      
   ei.kei_mode = case when isnull(th.mode, '') <> '' then  th.mode      
    else ei.kei_mode end,      
   ei.kei_AgentChannelid = case when isnull(th.AgentChannelid, '') <> '' then  th.AgentChannelid      
    else ei.kei_AgentChannelid end,      
   ei.kei_CustomerChannelid = case when isnull(th.CustomerChannelid, '') <> '' then  th.CustomerChannelid      
    else ei.kei_CustomerChannelid end,      
   ei.kei_CustomerDialStatus = case when isnull(th.CustomerDialStatus, '') <> '' then  th.CustomerDialStatus      
    else ei.kei_CustomerDialStatus end,      
   ei.kei_CustomerCallTime = case when isnull(th.CustomerCallTime, '') <> '' then dbo.fn_StrToDate(th.CustomerCallTime)      
    else ei.kei_CustomerCallTime end,      
   ei.kei_AgentDialStatus = case when isnull(th.AgentDialStatus, '') <> '' then  th.AgentDialStatus      
    else ei.kei_AgentDialStatus end,      
   ei.kei_AgentcallTime = case when isnull(th.AgentcallTime, '') <> '' then dbo.fn_StrToDate(th.AgentcallTime)      
    else ei.kei_AgentcallTime end,
   ei.RecordingUrl = case when isnull(th.RecordUrl, '') <> '' then th.RecordUrl    
		else ei.RecordingUrl end

from #tempHook th       
  inner join tbl_voip_endpointInteraction(nolock) ei on th.id = ei.id      
      
  if(not exists(select * from calllog(nolock)       
   where reftable = 'tbl_voip_endpointInteraction' and refid = @UniqueIdentityId))      
  begin      
   exec dbo.usp_createcalllog 'tbl_voip_endpointInteraction', 'id', @UniqueIdentityId, 'Outgoing'      
  end      
      
   declare @CallLog bigint  = 0      
   select top 1 @CallLog = id from calllog(nolock)       
    where reftable = 'tbl_voip_endpointInteraction' and refid = @UniqueIdentityId      
   order by id desc      
      
   if(@CallLog > 0)      
   begin      
    
     
    
	print concat('update ', ' section @CallLog => ', @CallLog        )    
     
	update cl set   
		cl.Agentpickuptime = case when isnull(ei.kei_AgentcallTime, '') <> ''     
			then ei.kei_AgentcallTime else cl.Agentpickuptime end,    
         
		cl.Customerpickuptime = case when isnull(ei.kei_CustomerCallTime, '') <> ''     
			then ei.kei_CustomerCallTime else cl.Customerpickuptime end,    
         
		cl.agentduration = case     
			when isnull(ei.kei_AgentcallTime, '') <> '' and isnull( ei.kei_CallEndTime, '') <> ''    
				then datediff(second, ei.kei_AgentcallTime, ei.kei_CallEndTime ) else cl.agentduration end,    
         
		cl.Calldurationseconds = case     
			when isnull(ei.kei_AgentcallTime, '') <> '' and isnull( ei.kei_CallEndTime, '') <> ''    
				then datediff(second, ei.kei_AgentcallTime, ei.kei_CallEndTime ) else cl.agentduration end,    
         
		cl.customerduration = case    
			when isnull(ei.kei_CustomerCallTime, '') <> '' and isnull( ei.kei_CallEndTime, '') <> ''    
				then datediff(second, ei.kei_CustomerCallTime, ei.kei_CallEndTime ) else cl.agentduration end,    
     
		cl.customercalldisposition = case when isnull(ei.kei_CustomerDialStatus, '') <> ''       
			then ei.kei_CustomerDialStatus else cl.customercalldisposition end,            
					cl.agentcalldisposition = case when isnull(ei.kei_CustomerDialStatus, '') <> ''     
				then ei.kei_AgentDialStatus else cl.agentcalldisposition end,    
    
		cl.Callendtime = case when isnull(ei.kei_AgentcallTime, '') <> ''     
			then ei.kei_AgentcallTime else cl.Callendtime end,
		cl.recordurl = case when isnull(ei.RecordingUrl, '') <> ''     
			then ei.RecordingUrl else cl.recordurl end,    
		cl.Dnid = case when isnull(ei.kei_Dnid, '') <> ''     
			then ei.kei_Dnid else cl.Dnid end

	from calllog(nolock) cl inner join       
		tbl_voip_endpointInteraction(nolock) ei on cl.refid = ei.id and cl.reftable = 'tbl_voip_endpointInteraction'      
	where cl.id = @CallLog      
	end      
  
  
        
      
  --begin try      
  -- if(lower(@WebhookMode) = 'mobilecallend')      
  -- begin      
  --  exec usp_voip_DedectCallChargeKit1980 @UniqueIdentityId      
  -- end      
  --end try      
  --begin catch       
  -- exec dbo.usp_InsertErrorInfo      
  --end catch      
      
 end      
end   



