/* ============================================================
   Procedure: [dbo].[usp_voip_UpdateEndpointInterationRef]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voip_UpdateEndpointInterationRef]   
(        
	 @InteractionId bigint,        
	 @InterationResponse nvarchar(max),        
	 @ProviderName nvarchar(255)        
)        
as        
begin 

	--declare 
	--	@InteractionId bigint = 296313,        
	--	@InterationResponse nvarchar(max) = N'Call process at Extension: 07840049991 and mobile: 0 91 9821592374,VIR/07840049991@jio',        
	--	@ProviderName nvarchar(255)  = N'Kit19 80'

        
 declare @refNumber nvarchar(255) =  '';        
        
 set @refNumber  = ( case         
  when  trim(lower(@ProviderName)) = 'mobile like number'        
   then (select [value] from openjson(@InterationResponse)         
      where [key] = 'refno')        
  else cast(@InteractionId as nvarchar) end        
 );        
        
 update tbl_voip_endpointInteraction         
  set response_content = @InterationResponse,        
   refNumber = @refNumber,        
   ProviderName = @ProviderName        
 where id = @InteractionId        
        
 declare @Status nvarchar(255)  = ''        
 set @Status =  (case         
		when trim(lower(@ProviderName)) = 'kit19 80' and @InterationResponse like '%VIR/%'
			then 'success'
		when trim(lower(@ProviderName)) = 'voxbay'         
			then trim(lower(replace(replace(@InterationResponse, char(10), ''), char(13), '')))        
		when  trim(lower(@ProviderName)) = 'mobile like number'        
			then (select trim(lower([value])) from openjson(@InterationResponse) where lower([key]) = 'status')        
		when trim(lower(@ProviderName)) like  '%_asterisk'         
			then trim(lower(replace(replace(@InterationResponse, char(10), ''), char(13), '')))      
     end);        
        
        
 if(@Status= 'success')        
 begin        
	select 1        
 end        
 else        
 begin        
	 select 0   
	  declare @errormessage nvarchar(1000),@parentid bigint,@agentid bigint,@user nvarchar(100)
	  DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX)        
	  select @errormessage=isnull((select [value] from openjson(@InterationResponse) where [key] = 'errormessage'),'Unknown')
	  select @agentid=agentid from tbl_voip_endpointInteraction(nolock) where id=@InteractionId
	  select @parentid=parentid,@user=user_login from user_detail(nolock) where user_id=@agentid
	select @status as Status,@errormessage as Errormsg,User_login as ParentUser,@user as AgentUser,getdate() as TimeCalled into #temp
	from user_detail(nolock) where user_id=@parentid
	SET @xml =CAST(( SELECT [Status] AS 'td','',Errormsg AS 'td','',[ParentUser] AS 'td','',[AgentUser]  AS 'td','',TimeCalled
	from #temp FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))        
	SET @body ='<html><H1>Important: Error in 80 mobile like calling at '+cast (getdate() as nvarchar)+
	'</H1><body><table border = 2><tr><th>Status</th><th>Errormsg</th><th>ParentUser</th><th>AgentUser</th><th>TimeCalled</th></tr>'         
	SET @body = @body + @xml +'</table></body></html>'        
	EXEC usp_enqueueemail        
	@profile_name='Alerts',         
	@recipients='csshukla@pelsoftlabs.in;animesh.shukla@pelsoftlabs.in',        
	@blind_copy_recipients='karuna@pelsoftlabs.in',        
	@subject='Error in 80 Mobile Like calling',        
	@body = @body,        
	@body_format ='HTML'        

 end      
   
  begin try  
 exec usp_updatecalllog_withreftable 'tbl_voip_endpointInteraction',@InteractionId  
 end try  
 begin catch  
 exec usp_inserterrorinfo  
 end catch   
    
end 



GO

/* ============================================================
   Procedure: [dbo].[usp_voip_UpdateEntityActivity]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voip_UpdateEntityActivity](
	@UniqueIdentity nvarchar(255),
	@SerProName nvarchar(255),
	@wehookResponseBody nvarchar(max)
)
as
begin

	--declare	
	--	@WebhookId bigint = 181402,

	--@SerProName nvarchar(255) = 'cloudshope',
	--@wehookResponseBody nvarchar(max) =  N'[{"Key":"from_number","Value":"7266895785"},{"Key":"from_number_answer_time","Value":"27"},{"Key":"to_number","Value":"09970525128"},{"Key":"to_number_answer_time","Value":"0"},{"Key":"campaign_id","Value":"0"},{"Key":"answer_time","Value":"0"},{"Key":"status","Value":"Answered"},{"Key":"extension","Value":"-"},{"Key":"number","Value":"09970525128"},{"Key":"recording_url","Value":"''https://s3.ap-south-1.amazonaws.com/cloudshope.recordings/1639652782.43463.wav''"}'

	--@SerProName nvarchar(255) = 'voxbay',
	--@wehookResponseBody nvarchar(max) =  N'{"extension":"ani*684_113","destination":"918113919449","callerid":"914847136941","duration":"0","status":"CHANUNAVAIL","date":"2022-02-14%2017:02:50","recording_URL":"https://pbx.voxbaysolutions.com/callrecordings/918113919449--914847136941-14022022-170251","param1":"19280"}'

	--@UniqueIdentity nvarchar(255) = '3722924791-42568',
	--@SerProName nvarchar(255) = 'MobileLikeNumber',	
	--@wehookResponseBody nvarchar(max) = N'{"Status":"HangupByAgent","duration":"0","refno":"3722924791-42568","EndTime":"2022-12-28 20:00:35","Cust_Disconnection_Reason":"HangupByAgent","Disconnected_by":"Agent","StartTime":"2022-12-28 20:00:35","RecordingUrl":"http://43.242.246.83:8882/C2C/callrecordings/Single/","From":null,"To":"9441994507","Agent_Disconnection_Reason":"CONGESTION"}'

	declare @resTable as table (
		[Key] nvarchar(255),
		[Value] nvarchar(max)
	)

	if(isnull(@wehookResponseBody, '') <> '')
	begin
		if(@SerProName = 'VOXBAY')
		begin
			insert into @resTable( [Key], [Value] )
				select [key], [value] from openjson(@wehookResponseBody)
		end

		if(@SerProName = 'CloudShope')
		begin
			insert into @resTable( [Key], [Value] )
				select [Key], [Value] from openjson(@wehookResponseBody) with ( [Key] nvarchar(255), [Value] nvarchar(2000) )
		end

		if(@SerProName = 'MobileLikeNumber')
		begin
			insert into @resTable( [Key], [Value] )
				select [key], [value] from openjson(@wehookResponseBody)
		end
	end

	if(exists( select * from @resTable ))
	begin
		declare @Duration decimal(18, 4), @CallRecording nvarchar(max), @endpointIntractionId bigint, @EntityName nvarchar(50), @CallStatus nvarchar(255)

		if(@SerProName = 'VOXBAY')
		begin
			select @Duration = [Value] from @resTable where [Key] = 'duration'
			select @CallRecording = [Value] from @resTable where [Key] = 'recording_URL'
			select @CallStatus = [Value] from @resTable where [Key] = 'status'
			select @endpointIntractionId = id, @EntityName = EntityName from tbl_voip_endpointInteraction(nolock) where id = @UniqueIdentity
		end

		if(@SerProName = 'CloudShope')
		begin
			select @Duration = [Value] from @resTable where [Key] = 'from_number_answer_time'
			select @CallRecording = [Value] from @resTable where [Key] = 'recording_url'
			select @CallStatus = [Value] from @resTable where [Key] = 'status'
			select @endpointIntractionId = id, @EntityName = EntityName from tbl_voip_endpointInteraction(nolock) where id = @UniqueIdentity
		end

		if(@SerProName = 'MobileLikeNumber')
		begin
			select @Duration = [Value] from @resTable where [Key] = 'duration'
			select @CallRecording = [Value] from @resTable where [Key] = 'RecordingUrl'
			select @CallStatus = [Value] from @resTable where [Key] = 'Status'
			select @endpointIntractionId = id, @EntityName = EntityName from tbl_voip_endpointInteraction(nolock) 
				where ProviderName = 'Mobile Like Number' and  refNumber = @UniqueIdentity
		end

		declare @Status nvarchar(255) = (select [Status] from openjson(@wehookResponseBody) 
						with ( [Status] nvarchar(255) '$.Status'))

		if(lower(isnull(@Status, '')) <> 'na')
		begin
			if(isnull(@endpointIntractionId, 0) > 0)
			begin
				update tbl_voip_endpointInteraction set 
					CallStatus = @CallStatus,
					RecordingUrl = @CallRecording,
					webhookReceivedAt = getdate(),
					isNotify = 0
					where id = @endpointIntractionId
				if(@SerProName = 'MobileLikeNumber')
				begin
					update tbl_voip_endpointInteraction set 
						tie_Status = @Status,
						tie_Cust_Disconnection_Reason = (select [Cust_Disconnection_Reason] from openjson(@wehookResponseBody) 
							with ( Cust_Disconnection_Reason nvarchar(255) '$.Cust_Disconnection_Reason')),
						tie_Disconnected_by = (select [Disconnected_by] from openjson(@wehookResponseBody)
							with ( Disconnected_by nvarchar(255) '$.Disconnected_by')),
						tie_Agent_Disconnection_Reason = (select [Agent_Disconnection_Reason] from openjson(@wehookResponseBody) with ( Agent_Disconnection_Reason nvarchar(255) '$.Agent_Disconnection_Reason'))	 
					where id = @endpointIntractionId
				end
			end
		end
		
		if(@EntityName = 'enquiry')
		begin
			if(exists(select * from tbl_EnquiryEventHistory(nolock)
				where reftables = 'tbl_voip_endpointInteraction' and refids = @endpointIntractionId))
			begin
				update tbl_EnquiryEventHistory set EventDescription = concat(' Call duration: ', @Duration, ' , call recording ', @CallRecording )
					where reftables = 'tbl_voip_endpointInteraction' and refids = @endpointIntractionId;
			end
		end

		if(@EntityName = 'lead')
		begin
			if(exists(select * from tbl_LeadEventHistory(nolock)
				where reftables = 'tbl_voip_endpointInteraction' and refids = @endpointIntractionId))
			begin
				update tbl_LeadEventHistory set EventDescription = concat(EventDescription, ' Call duration: ', @Duration, ' , call recording ', @CallRecording )
					where reftables = 'tbl_voip_endpointInteraction' and refids = @endpointIntractionId
			end
		end
	end


end



GO

/* ============================================================
   Procedure: [dbo].[usp_voip_UpdateFailedCallStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_voip_UpdateFailedCallStatus(  
 @UniqueId bigint,  
 @Mode nvarchar(255)  
)as  
begin  
   
 --declare   
 -- @UniqueId bigint = 302071,  
 -- @Mode nvarchar(255) = 'Failed'  
  
 if(isnull(@Mode, '') = '')  
 begin  
  set @Mode = 'Failed';  
 end  
  
 declare @isCalllogExists bit = 0, @isWebhookExists bit = 0;
 if(exists( select 1 from CallLog(nolock) where reftable  = 'tbl_voip_endpointInteraction'  
  and refid = @UniqueId))
 begin
	set @isCalllogExists = 1;
 end
   
 if(exists(select 1 from tbl_voip_Kit19Webhooks(nolock) where UniqueIdentity = @UniqueId))
 begin
	set @isWebhookExists = 1;
 end

 if(@isCalllogExists = 1 and @isWebhookExists = 0)
 begin   
  update   CallLog set  
   agentcalldisposition = @Mode,  
   customercalldisposition = @Mode,  
   Callendtime = getdate()  
  where reftable  = 'tbl_voip_endpointInteraction'  
  and refid = @UniqueId  
 end  
  
end  



GO

/* ============================================================
   Procedure: [dbo].[usp_voip_UpdateVoipAgentDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_voip_UpdateVoipAgentDetail](
	@AgentId bigint,
	@ExtNumber nvarchar(255),
	@MobileNo nvarchar(255),
	@DefaultCaller nvarchar(20),
	@DefaultDevice nvarchar(20),
	@isActive nvarchar(5),
	@UserId bigint,
	@ServiceProviderId bigint
)
as
begin

	declare @ParentId bigint = ( select ParentID from User_Detail(nolock) where User_ID = @UserId )

	declare @ServiceProviderMappingId bigint = ( select id from tbl_voip_ParentServiceMapping(nolock) 
		where parent_id = @ParentId and srv_pro_id = @ServiceProviderId )

	if(exists(select 1 from tbl_voip_userAgentSetting(nolock) where user_id = @AgentId and service_provider_id = @ServiceProviderId))
	begin
		update tbl_voip_userAgentSetting set
			ext_number = @ExtNumber,
			mobile_no =   @MobileNo,
			default_caller_no = @DefaultCaller,
			is_active = @isActive,
			default_machine = @DefaultDevice
			where  user_id = @AgentId and service_provider_id = @ServiceProviderId
	end
	else
	begin
		insert into tbl_voip_userAgentSetting( 
				user_id, ext_number, mobile_no, default_caller_no, is_active, created_on, created_by, default_machine , psmap_id, service_provider_id, parent_id
			) values ( 
				@AgentId, @ExtNumber, @MobileNo, @DefaultCaller, 1, GETDATE(), @UserId, @DefaultDevice, @ServiceProviderMappingId, @ServiceProviderId, @ParentId
			)
	end
end



GO

/* ============================================================
   Procedure: [dbo].[usp_wa_FindEntityByModeAsync]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_wa_FindEntityByModeAsync(
	@MobileNo nvarchar(25),
	@Mode nvarchar(25),
	@ParentId bigint
)
as
begin
	
	--declare 
	--	@Mode nvarchar(25) = 'team',
	--	@MobileNo nvarchar(25) = '',
	--	@ParentId bigint = 48446

	if(@Mode = 'team')
	begin
		select
			top 1 'team' as [EntityName], User_ID as [EntityId] 
		from User_Detail(nolock) 
		where (trim(cast(mobile as nvarchar)) = trim(@MobileNo)
			or trim(cast(wa_mobile_no as nvarchar)) = trim(@MobileNo))
			and ParentID = @ParentId       
		order by User_ID desc;  
	end

	if(@Mode = 'lead')
	begin
		select
			top 1 'lead' as [EntityName], ulme_id as [EntityId] 
		from userleads_mobile_email(nolock) 
		where trim(cast(mobile as nvarchar)) = trim(@MobileNo)
			and ParentID = @ParentId       
		order by ulme_id desc;  
	end

	if(@Mode = 'enquiry')
	begin
		select
			top 1 'enquiry' as [EntityName], enquiryid as [EntityId] 
		from Userenquiry_Mobile_Email(nolock) 
		where trim(cast(Mobile as nvarchar)) = trim(@MobileNo)
			and ParentID = @ParentId       
		order by enquiryid desc;  
	end

end



