/* ============================================================
   Procedure: [dbo].[usp_wa_InsertLeadFromWhatsapp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_wa_InsertLeadFromWhatsapp
(
    @PersonName nvarchar(255),
    @CountryCode nvarchar(25),
    @MobileNo nvarchar(25),
    @CountryName nvarchar(25),
    @IntialRemarks nvarchar(1000),
    @ParentId bigint
)
as
begin
    
    --declare 
    --    @PersonName nvarchar(255),
    --    @CountryCode nvarchar(25),
    --    @MobileNo nvarchar(25),
    --    @CountryName nvarchar(25),
    --    @IntialRemarks nvarchar(1000),
    --    @ParentId bigint


    declare @SourceId bigint, @entityName nvarchar(25) = 'lead', @entityId bigint

    select @SourceId = SourceID from UserSourceSettings(nolock)       
    where UserID = @ParentId AND Name = 'Chat';      
          
      
    declare @AgentId bigint = cast(isnull((      
        select top 1 value      
        from fn_Split((select agents from CRMCampaignSettings with (nolock) where userid = @parentid ), '#' )      
        order by newid()      
    ), @parentid) as bigint)      
      
    declare @LeadId bigint ;      
          
    if(not exists (select 1 from userleads_mobile_email as ume with(nolock)      
    where Parentid = @ParentId and  Mobile <> '1' and Mobile <> '0' and isnull(Mobile,'') <> ''      
        and  isnull(Mobile,'') =  @MobileNo and isnull(CountryCode,'') = @CountryCode ))
    begin       
      
        print 'lead insert section'      
          
        set Context_Info 0x55555      
        --SET TRANSACTION ISOLATION LEVEL SERIALIZABLE;
        begin transaction;       
  
        declare @LeadNo bigint= ( select IIF(COUNT(1) > 0, MAX(LeadNo) + 1, 1)       
        from UserLeads with (UPDLOCK,HOLDLOCK) where ParentID = @ParentId );         
      
        if not exists(select * from UserLeads(nolock) where ParentID = @ParentId and (MobileNo = trim(@MobileNo) or MobileNo1 = trim(@MobileNo) or MobileNo2 = trim(@MobileNo)) )  
        begin  
            insert into UserLeads( PersonName, CountryCode, MobileNo, Country, CreatedBy, CreatedOn, AssignedTo, ParentID, SourceName, LeadNo, 
                enquirysource, InitialRemarks ,lastfollowupcreatedby,lastfollowupcreatedon)      
            values( @PersonName, @CountryCode, @MobileNo, @CountryName, @ParentId, GETDATE(), @AgentId, @ParentId, @SourceId, @LeadNo, 26, left(@IntialRemarks, 1000),      
                @ParentId,GETDATE() );      
                                
            set @LeadId = SCOPE_IDENTITY();

            set @entityId = @LeadId
        end  
  
        commit transaction;      
  
        If isnull(@LeadId,0) > 0  
        begin  
            Exec usp_ExecLeadTriggerTasks @LeadId      
       
            declare @CsvID bigint      
      
            insert into leadinteractionhistory( LeadNo, FollowUpStatus, NextStatusDate, Products, AmountPaid, Remarks, AssignedTo, ParentID, CreatedOn, CreatedBy, followupdate,id_lead )       
            select LeadNo, FollowUpStatus, NextStatusDate, Products, AmountPaid, Remarks, AssignedTo, ParentID, CreatedOn, CreatedBy, followupdate,id from userleads(nolock) ul       
            inner join dbo.fn_Split(@LeadId,  ',') cui on ul.ID = cui.[value]      
            select @CsvID=scope_identity()    
            exec usp_ExecLeadInteractionTriggerTasks @CsvID      
      
            --EXEC MySMS.dbo.usp_inserleadinteractionhistory @LeadId;      
            --exec MySMS.dbo.usp_insertdefaultfollowup @AgentId, @LeadId      
  
        end  

        SET Context_Info 0x     
           
    end      
    select isnull(@entityid,0) AS EntityId, isnull(@entityName,'') AS EntityName;
end



GO

