CREATE   PROCEDURE dbo.USP_WebControlTbl                                
(          
@Option int,                                
@ControlID bigint = null,        
 @FormID bigint = null,        
    @tbl tbl_webctrlType READONLY ,       
 @isenquery tinyint,        
 @status tinyint =NULL        
)                               
                                
as         
        
Begin         
if (@Option = 1)        
begin        
select  COUNT(*) from [WebControlTbl] where  @FormID = @FormID -- and FormName = @FormName            
end        
if (@Option = 2)        
begin        
      
         
 insert into [WebControlTbl] (FormID, ControlName, Ctrl_type, Ctrl_Label, UserControlName, isenquery,  
  opt_label,main_id)        
 select @FormID, ctrl_dtl,ctrl_type,ctrl_lbl,usrctrl_dtl, @isenquery, opt_label, main_id from @tbl aa where           
      not exists (select 1 from [WebControlTbl] bb where bb.ControlName = aa.ctrl_dtl and        
         FormID = @FormID)        
     select @@ROWCOUNT         
         
end        
if (@Option = 3)        
begin        
delete from [WebControlTbl] where FormID = @FormID        
 insert into [WebControlTbl] (FormID, ControlName, Ctrl_type, Ctrl_Label, UserControlName,  
  isenquery,opt_label,main_id)        
 select @FormID, ctrl_dtl,ctrl_type,ctrl_lbl,usrctrl_dtl, @isenquery,opt_label,main_id from @tbl aa where            not exists (select 1 from [WebControlTbl] bb where bb.ControlName = aa.ctrl_dtl and        
         FormID = @FormID)        
        select @@ROWCOUNT          
end        
if (@Option = 4)        
 select * from [WebControlTbl] where FormId= @FormId        
end 


