/* ============================================================
   Procedure: [dbo].[USP_WebControlTbl_new_1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.USP_WebControlTbl_new_1 (  
 @Option INT  
 ,@ControlID BIGINT = NULL  
 ,@FormID BIGINT = NULL  
 ,@tbl [tbl_webctrlType] READONLY  
 ,@isenquery TINYINT  
 ,@tp VARCHAR(10)  
 ,@status TINYINT = NULL  
 )  
AS  
BEGIN  
 DECLARE @PrentId BIGINT  
  ,@PageName VARCHAR(MAX)  
  
 SELECT @PrentId = ParentId  
  ,@PageName = FormName  
 FROM WebFormTbl  
 WHERE FormId = @FormId  
  
 IF (@Option = 1)  
 BEGIN  
  SELECT COUNT(*)  
  FROM [WebControlTbl]  
  WHERE @FormID = @FormID -- and FormName = @FormName                  
 END  
  
 IF (@Option = 2)  
 BEGIN  
  INSERT INTO [WebControlTbl] (  
   FormID  
   ,ControlName  
   ,Ctrl_type  
   ,Ctrl_Label  
   ,UserControlName  
   ,isenquery  
   ,opt_label  
   ,main_id  
   ,ctrltypeNm  
   )  
  SELECT @FormID  
   ,ctrl_dtl  
   ,ctrl_type  
   ,ctrl_lbl  
   ,usrctrl_dtl  
   ,@isenquery  
   ,opt_label  
   ,main_id  
   ,@tp  
  FROM @tbl aa  
  WHERE NOT EXISTS (  
    SELECT 1  
    FROM [WebControlTbl] bb  
    WHERE bb.ControlName = aa.ctrl_dtl  
     AND FormID = @FormID  
    )  
  
  SELECT @@ROWCOUNT
  
   
    if @FormId > 0 --2993
	 begin
                
        delete t from tbl_CustomFieldWebFormFieldMapping t where WebFormId = @FormId and not exists
	                      (select controlname from webcontroltbl where formid = @FormId and Ctrl_label = t.CtrlName )
      end    

 END  
  
 IF (@Option = 3)  
 BEGIN  
  DELETE  
  FROM [WebControlTbl]  
  WHERE FormID = @FormID  
   AND ctrltypeNm = @tp  
  
  INSERT INTO [WebControlTbl] (  
   FormID  
   ,ControlName  
   ,Ctrl_type  
   ,Ctrl_Label  
   ,UserControlName  
   ,isenquery  
   ,opt_label  
   ,main_id  
   ,ctrltypeNm  
   )  
  SELECT @FormID  
   ,ctrl_dtl  
   ,ctrl_type  
   ,ctrl_lbl  
   ,usrctrl_dtl  
   ,@isenquery  
   ,opt_label  
   ,main_id  
   ,@tp  
  FROM @tbl aa  
  WHERE NOT EXISTS (  
    SELECT 1  
    FROM [WebControlTbl] bb  
    WHERE bb.ControlName = aa.ctrl_dtl  
     AND FormID = @FormID  
     AND ctrltypeNm = @tp  
    )  
  
  SELECT @@ROWCOUNT  
 
    if @FormId  > 0 --2993
	 begin
                
        delete t from tbl_CustomFieldWebFormFieldMapping t where WebFormId = @FormId and not exists
	                      (select controlname from webcontroltbl where formid = @FormId and Ctrl_label = t.CtrlName )
      end    


 
 END  
  
 IF (  
   @Option = 3  
   OR @Option = 2  
   )  
 BEGIN  
  UPDATE WebFormTbl  
  SET isEnquiry = @isenquery  
  WHERE FormId = @FormId  
  
  IF @isenquery = 1  
   EXEC up_updtins_source @PrentId  
    ,@PrentId  
    ,@FormId  
    ,@PageName  
 END  
  
 IF (@Option = 4)  
  SELECT *  
  FROM [WebControlTbl]  
  WHERE FormId = @FormId  
  
 IF @Option = 3  
 BEGIN  
  DECLARE @rowJson VARCHAR(MAX) = (  
    SELECT *  
    FROM WebControlTbl(NOLOCK)  
    WHERE FormId = @FormID  
    FOR JSON AUTO  
     ,INCLUDE_NULL_VALUES  
    )  
  
  IF @rowJson IS NOT NULL  
  BEGIN  
   EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @PrentId  
    ,@Activity_type = 'Inst_WebFomCntrl'  
    ,@ActionType = 'I'  
    ,@RowJson = @rowJson  
    ,@Table_name = 'WebFormTbl'  
  END  
 END  
END  


GO

