CREATE   PROCEDURE [dbo].[Usp_WebForm_DeleteWebforms] 
@Formid bigint ,
@userid bigint 
AS 
BEGIN
	
	Declare @RowJson nvarchar(max) = (Select * from WebFormTbl where FormId=@Formid FOR  Json Auto , Include_null_values)
	Update WebFormTbl set IsActive =0 where FormId=@Formid 

	Select 'Web Form Deleted'
	if @RowJson is not null
	begin
		EXEC MySMSAudit_Dev.dbo.Usp_AuditTableDataByParentId @User_id = @userid    
		,@Activity_type = 'Delt_Wbfm'    
		,@ActionType = 'D'    
		,@RowJson = @RowJson 
		,@Table_name = 'WebFormTbl'    
	end
END 


