/* ============================================================
   Procedure: [dbo].[usp_webhook_GetWebhooks]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_webhook_GetWebhooks]

    @WebhookId BIGINT = NULL,

    @UserId BIGINT = 0,

    @SearchTerm NVARCHAR(200) = NULL,

    @PageNumber INT = 1,

    @PageSize INT = 10

AS

BEGIN

    SET NOCOUNT ON;
 
    DECLARE @ParentId BIGINT;

    IF @UserId > 0 SET @ParentId = dbo.ufn_getuserparentid(@UserId);
 
    IF @WebhookId IS NOT NULL AND @WebhookId > 0

    BEGIN

        SELECT *

        FROM dbo.webhook_definition WITH (NOLOCK)

        WHERE webhook_id = @WebhookId

          AND (parentid = @ParentId OR @ParentId IS NULL)

          AND deleted_on IS NULL;

    END

    ELSE

    BEGIN

        SELECT COUNT(1) OVER() AS TotalCount, *

        FROM dbo.webhook_definition WITH (NOLOCK)

        WHERE (parentid = @ParentId OR @ParentId IS NULL)

          AND deleted_on IS NULL

          AND (@SearchTerm IS NULL OR @SearchTerm = '' OR webhook_name LIKE '%' + @SearchTerm + '%' OR description LIKE '%' + @SearchTerm + '%')

        ORDER BY created_on DESC

        OFFSET (@PageNumber - 1) * @PageSize ROWS

        FETCH NEXT @PageSize ROWS ONLY;

    END

END




GO

/* ============================================================
   Procedure: [dbo].[usp_webhook_SaveWebhook]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


 
CREATE   PROCEDURE [dbo].[usp_webhook_SaveWebhook]

    @Mode NVARCHAR(50) = 'save',

    @UserId BIGINT = 0,

    @webhook_id BIGINT = NULL,

    @webhook_name NVARCHAR(200) = NULL,

    @description NVARCHAR(MAX) = NULL,

    @http_method NVARCHAR(20) = 'POST',

    @url_template NVARCHAR(MAX) = NULL,

    @query_template NVARCHAR(MAX) = NULL,

    @header_template NVARCHAR(MAX) = NULL,

    @body_template NVARCHAR(MAX) = NULL,

    @auth_type NVARCHAR(50) = 'none',

    @auth_config NVARCHAR(MAX) = NULL,

    @secret_ref NVARCHAR(200) = NULL,

    @extract_slots NVARCHAR(MAX) = NULL,

    @response_shaping NVARCHAR(MAX) = NULL,

    @timeout_ms INT = 3000,

    @max_response_size_bytes INT = 32768,

    @retry_max_attempts INT = 0,

    @retry_base_delay_ms INT = 500,

    @is_idempotent BIT = 0,

    @extract_on_error BIT = 0

AS

BEGIN

    SET NOCOUNT ON;
 
    DECLARE @ParentId BIGINT;

    IF @UserId > 0 SET @ParentId = dbo.ufn_getuserparentid(@UserId);
 
    DECLARE @Action NVARCHAR(50);

    DECLARE @InsertedIds TABLE (InsertedId BIGINT);
 
    BEGIN TRY

        BEGIN TRANSACTION;
 
        IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'save'

        BEGIN

            IF @webhook_id IS NOT NULL AND @webhook_id > 0 AND EXISTS (SELECT 1 FROM dbo.webhook_definition WHERE webhook_id = @webhook_id)

            BEGIN

                -- UPDATE existing webhook

                UPDATE dbo.webhook_definition

                SET 

                    webhook_name = COALESCE(@webhook_name, webhook_name),

                    description = COALESCE(@description, description),

                    http_method = COALESCE(@http_method, http_method),

                    url_template = COALESCE(@url_template, url_template),

                    query_template = COALESCE(@query_template, query_template),

                    header_template = COALESCE(@header_template, header_template),

                    body_template = COALESCE(@body_template, body_template),

                    auth_type = COALESCE(@auth_type, auth_type),

                    auth_config = COALESCE(@auth_config, auth_config),

                    secret_ref = COALESCE(@secret_ref, secret_ref),

                    extract_slots = COALESCE(@extract_slots, extract_slots),

                    response_shaping = COALESCE(@response_shaping, response_shaping),

                    timeout_ms = COALESCE(@timeout_ms, timeout_ms),

                    max_response_size_bytes = COALESCE(@max_response_size_bytes, max_response_size_bytes),

                    retry_max_attempts = COALESCE(@retry_max_attempts, retry_max_attempts),

                    retry_base_delay_ms = COALESCE(@retry_base_delay_ms, retry_base_delay_ms),

                    is_idempotent = COALESCE(@is_idempotent, is_idempotent),

                    extract_on_error = COALESCE(@extract_on_error, extract_on_error),

                    updated_by = CAST(@UserId AS NVARCHAR(100)),

                    updated_on = GETDATE(),

                    version = ISNULL(version, 1) + 1

                WHERE webhook_id = @webhook_id;

                SET @Action = 'update';

            END

            ELSE

            BEGIN

                -- INSERT new webhook

                INSERT INTO dbo.webhook_definition (

                    parentid, webhook_name, description, http_method, url_template, 

                    query_template, header_template, body_template, auth_type, auth_config, 

                    secret_ref, extract_slots, response_shaping, timeout_ms, max_response_size_bytes, 

                    retry_max_attempts, retry_base_delay_ms, is_idempotent, extract_on_error, 

                    created_by, created_on, version

                )

                OUTPUT INSERTED.webhook_id INTO @InsertedIds(InsertedId)

                VALUES (

                    @ParentId, @webhook_name, @description, @http_method, @url_template,

                    @query_template, @header_template, @body_template, @auth_type, @auth_config,

                    @secret_ref, @extract_slots, @response_shaping, ISNULL(@timeout_ms, 3000), ISNULL(@max_response_size_bytes, 32768),

                    ISNULL(@retry_max_attempts, 0), ISNULL(@retry_base_delay_ms, 500), ISNULL(@is_idempotent, 0), ISNULL(@extract_on_error, 0),

                    CAST(@UserId AS NVARCHAR(100)), GETDATE(), 1

                );
 
                SET @webhook_id = (SELECT TOP 1 InsertedId FROM @InsertedIds ORDER BY InsertedId DESC);

                SET @Action = 'insert';

            END

        END

        ELSE IF LOWER(ISNULL(LTRIM(RTRIM(@Mode)), '')) = 'delete'

        BEGIN

            IF @webhook_id IS NOT NULL AND @webhook_id > 0

            BEGIN

                -- SOFT DELETE webhook

                UPDATE dbo.webhook_definition

                SET deleted_on = GETDATE(),

                    updated_by = CAST(@UserId AS NVARCHAR(100))

                WHERE webhook_id = @webhook_id;

                SET @Action = 'delete';

            END

            ELSE

            BEGIN

                RAISERROR('webhook_id is required for delete mode.', 16, 1);

                ROLLBACK TRANSACTION;

                RETURN;

            END

        END

        ELSE

        BEGIN

            RAISERROR('Invalid mode specified. Valid modes: save, delete', 16, 1);

            ROLLBACK TRANSACTION;

            RETURN;

        END
 
        COMMIT TRANSACTION;
 
        SELECT 

            @webhook_id AS WebhookId,

            @Action AS Action;
 
    END TRY

    BEGIN CATCH

        IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;

        DECLARE @ErrMsg NVARCHAR(4000) = ERROR_MESSAGE();

        DECLARE @ErrLine INT = ERROR_LINE();

        DECLARE @ErrProc NVARCHAR(200) = ERROR_PROCEDURE();

        RAISERROR('usp_webhook_SaveWebhook failed at line %d in %s: %s', 16, 1, @ErrLine, @ErrProc, @ErrMsg);

        RETURN;

    END CATCH

END




GO

/* ============================================================
   Procedure: [dbo].[usp_wf_AddDeal_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Action Code => ( ADD_DEAL )  
CREATE   PROCEDURE usp_wf_AddDeal_New 
(   
    @LeadID               BIGINT ,   
    @PipelineID           BIGINT ,   
    @PipelineStage        BIGINT ,   
    @Amount               NUMERIC(18 , 2) ,   
    @EstimatedClosureDate DATETIME ,   
    @DealOwner            BIGINT ,   
    @CreatedBy            BIGINT ,   
    @Probability          NUMERIC(18 , 2) ,   
    @RefHistoryId         BIGINT = 0,
	@WorkFlowId			  BIGINT = NULL
)   
AS  
BEGIN  

 BEGIN TRY  
  
  PRINT '--------------BEGIN----------------------------- usp_wf_AddDeal_New ------------------------------------------------------';  
  PRINT '@LeadID: ' + CAST(@LeadID AS VARCHAR);  
  PRINT '@PipelineID: ' + CAST(@PipelineID AS VARCHAR);  
  PRINT '@PipelineStage: ' + CAST(@PipelineStage AS VARCHAR);  
  PRINT '@Amount: ' + CAST(@Amount AS VARCHAR);  
  PRINT '@EstimatedClosureDate: ' + CAST(@EstimatedClosureDate AS VARCHAR);  
  PRINT '@DealOwner: ' + CAST(@DealOwner AS VARCHAR);  
  PRINT '@CreatedBy: ' + CAST(@CreatedBy AS VARCHAR);  
  PRINT '@Probability: ' + CAST(@Probability AS VARCHAR);  
  PRINT '@RefHistoryId: ' + CAST(@RefHistoryId AS VARCHAR);  
  PRINT '@WorkFlowId: ' + CAST(isnull(@WorkFlowId,'') AS VARCHAR);  
  
  --declare @Probability numeric(18,2) = 0              
  DECLARE @pname NVARCHAR(100) , @sname NVARCHAR(100);           
  --select  top 1  @Probability = isnull(Probability,0) from PipelineStages(nolock) where               
  -- ID = @PipelineStage  and PipelineID = @pipelineID               
  DECLARE @leadpipelineid BIGINT=0;  
  SELECT @leadpipelineid=PipelineID FROM LeadPipelineMapping(NOLOCK) WHERE LeadID = @LeadID  
        AND PipelineID = @PipelineID AND  PipeLineStage = @PipelineStage AND IsDeleted = 0 and cast(createddate as date) = cast(getdate() as date)
  IF (@leadpipelineid=0)   
  BEGIN  
   INSERT INTO LeadPipelineMapping ( [LeadID] , [PipelineID] , [PipeLineStage] , [Probability] , [Amount] , [Remarks] , [CreatedDate] , [CreatedBy] , [EstimatedClosureDate] , [DealOwner]  )   
   VALUES ( @LeadID , @PipelineID , @PipelineStage , @Probability , @Amount , 'Deal created' , GETDATE() , @Createdby , @EstimatedClosureDate , @DealOwner );  
   SELECT @leadpipelineid = SCOPE_IDENTITY();  
          
   BEGIN TRY  
    SELECT @pname = name FROM Pipeline_Master(NOLOCK) WHERE id = @PipelineID;  
    SELECT @sname = Name FROM PipelineStages(NOLOCK) WHERE id = @PipelineStage;  
    DECLARE @ParentID BIGINT= 0;  
    SELECT @ParentID = ISNULL(ParentID , 0) FROM User_Detail(NOLOCK) WHERE User_ID = @CreatedBy;  
    DECLARE @eventDesc NVARCHAR(500)= [dbo].[fn_getentityfullname] ('lead', @leadid ) + '''s deal created for pipeline :' + CAST(@Pname AS NVARCHAR) + ', Stage :' + @sname;  
  
    EXEC usp_wf_SaveLeadActivity_withid @LeadID , @Createdby , @ParentID , @eventDesc , 'Deal Added' , 'LeadPipelineMapping' , @leadpipelineid , 'ID' , @RefHistoryId, @WorkFlowId;  
   END TRY  
   BEGIN CATCH  
    EXEC usp_InsertErrorInfo;  
    THROW  
   END CATCH;  
   insert into tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) values (@@SPID, cast(@leadpipelineid as nvarchar(50)), '1', 'success');  
  END;  
  ELSE  
  BEGIN  
   insert into tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) values (@@SPID, cast(@leadpipelineid as nvarchar(50)), '-2', 'LeadId Already Occupied');  
  END;  
 END TRY  
 BEGIN CATCH  
  Exec  usp_InsertErrorInfo  
  insert into tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) values (@@SPID, cast(@leadpipelineid as nvarchar(50)), '-3', 'LeadId Already Occupied');  
 END CATCH  
 PRINT '--------------END----------------------------- usp_wf_AddDeal_New ------------------------------------------------------';  
 select * from tbl_wf_WorkflowResponse  
END;  



GO

/* ============================================================
   Procedure: [dbo].[usp_wf_DeleteWorkflow]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
-- Exec usp_wf_DeleteWorkflow 32222
CREATE   PROC usp_wf_DeleteWorkflow
(
	@WorkflowId bigint
)
AS
BEGIN

	Update WM Set WM.IsActive=0
	From tbl_wf_WorkflowMaster WM 
	Where WM.WorkflowId = @WorkflowId

END



GO

/* ============================================================
   Procedure: [dbo].[usp_wf_EvaluateCondition]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--declare @retval bit; Exec @retval=usp_wf_EvaluateCondition @HistoryId=2237103,@RefHistoryId=2237103,@UserId=39662,@LeadId=1499441,@RefId=341733,@reftables='MySMSConversations.dbo.tbl_ims_schedule_message',@refColName='id',@StageId=325; select @retval   
 
--declare @retval bit; Exec @retval=usp_wf_EvaluateCondition @HistoryId=2319181,@RefHistoryId=2319181,@UserId=38333,@LeadId=1688365,@RefId=24231,@reftables='LeadPipelineMapping',@refColName='',@StageId=328; select @retval      
--declare @retval bit; Exec @retval=usp_wf_EvaluateCondition @HistoryId=11784806,@RefHistoryId=11784806,@UserId=34594,@LeadId=2042837,@RefId=103835043,@reftables='Batchinfo',@refColName='',@StageId=443; select @retval  
CREATE   PROC usp_wf_EvaluateCondition    
(    
 @HistoryId    BIGINT,    
 @RefHistoryId BIGINT,    
 @UserId       BIGINT,    
 @LeadId       BIGINT,    
 @RefId        BIGINT,    
 @reftables    NVARCHAR(1000),    
 @refColName   VARCHAR(100),    
 @StageId      BIGINT    
)    
AS    
BEGIN    
    
  -- declare @HistoryId BIGINT=11808636, @RefHistoryId BIGINT=11808636, @UserId BIGINT=39703, @LeadId BIGINT=4261813, @RefId BIGINT=7668239, @reftables NVARCHAR(1000)='LeadInteractionHistory', @refColName VARCHAR(100)='', @StageId BIGINT=388    
    
 DECLARE @ConditionRow_Cnt INT= 0, @ConditionRow_ID INT= 1, @ConditionId BIGINT, @OpSequenceNo INT,   
   @Operand1 VARCHAR(100), @Operator VARCHAR(100), @Operand2 VARCHAR(100), @Conjunction VARCHAR(10),  
   @ConditionType VARCHAR(10), @ConditionExpr VARCHAR(1000)= '', @EntityName VARCHAR(100)= '',     
   @ParentId bigint;    
 DECLARE @fieldName VARCHAR(100), @fieldValue NVARCHAR(MAX), @fieldTableName VARCHAR(max),     
   @csvCustomfields VARCHAR(max), @ItemCnt INT= 0;    
 DECLARE @SQL NVARCHAR(4000)= '';    
    
 Select @ParentId=ParentID From User_Detail(nolock) Where USER_ID=@UserId    
    
 PRINT '-----------------------------Begin------ usp_wf_EvaluateCondition ----------------------------------------';    
 PRINT '@HistoryId: ' + CAST(@HistoryId AS VARCHAR);    
 PRINT '@RefHistoryId: ' + CAST(@RefHistoryId AS VARCHAR);    
 PRINT '@UserId: ' + CAST(@UserId AS VARCHAR);    
 PRINT '@ParentId: ' + CAST(@ParentId AS VARCHAR);    
 PRINT '@LeadId: ' + CAST(@LeadId AS VARCHAR);    
 PRINT '@RefId: ' + CAST(@RefId AS VARCHAR);    
 PRINT '@reftables: ' + ISNULL(@reftables, '');    
 PRINT '@refColName: ' + ISNULL(@refColName, '');    
 PRINT '@StageId: ' + CAST(@StageId AS VARCHAR);    
    
 IF OBJECT_ID('tempdb..#tbl_WorkflowStageCondition') IS NOT NULL BEGIN DROP TABLE #tbl_WorkflowStageCondition; END;    
 IF OBJECT_ID('tempdb..#tblResult') IS NOT NULL BEGIN DROP TABLE #tblResult; END;    
 IF OBJECT_ID('tempdb..#tblItem') IS NOT NULL BEGIN DROP TABLE #tblItem; END;    
    
 CREATE TABLE #tbl_WorkflowStageCondition    
 (    
  [ConditionRow_Id] INT IDENTITY(1, 1),    
  [ConditionId]     BIGINT,    
  [WorkflowId]      BIGINT,    
  [SequenceNo]      INT,    
  [Operand1]        VARCHAR(100),    
  [Operator]        VARCHAR(100),    
  [Operand2]        VARCHAR(100),    
  [Conjunction]     VARCHAR(10),    
  [ConditionType]   VARCHAR(10)    
 );    
    
 CREATE TABLE #tblResult    
 (    
  [Result] VARCHAR(3)    
 );    
    
 CREATE TABLE #tblItem    
 (    
  [Id]   INT IDENTITY(1, 1),    
  [Item] VARCHAR(100)    
 );    
    
 INSERT INTO #tbl_WorkflowStageCondition([ConditionId], [WorkflowId], [SequenceNo], [Operand1], [Operator],    
   [Operand2], [Conjunction], [ConditionType])    
 SELECT [ConditionId], [WorkflowId], [SequenceNo], [Operand1], [Operator], [Operand2], [Conjunction], [ConditionType]    
 FROM   tbl_wf_WorkflowStageConditionMaster(NOLOCK)    
 WHERE  [StageId] = @StageId AND [IsActive] = 1;    
    
 SELECT @ConditionRow_Cnt = COUNT(*) FROM #tbl_WorkflowStageCondition;    
 PRINT '@ConditionRow_Cnt: ' + CAST(@ConditionRow_Cnt AS VARCHAR);    
    
 WHILE( @ConditionRow_ID <= @ConditionRow_Cnt )    
 BEGIN    
  PRINT '@ConditionRow_ID: ' + CAST(@ConditionRow_ID AS VARCHAR);    
    
  SELECT @ConditionId = [ConditionId], @OpSequenceNo = [SequenceNo], @Operand1 = [Operand1],     
    @Operator = [Operator], @Operand2 = [Operand2], @Conjunction = [Conjunction],     
    @ConditionType = [ConditionType]    
  FROM   #tbl_WorkflowStageCondition    
  WHERE  [ConditionRow_ID] = @ConditionRow_ID;    
    
  TRUNCATE TABLE #tblItem;    
    
  SELECT TOP 1 @fieldTableName = [Item] FROM dbo.SplitString(@Operand1, '.');    
    
  INSERT INTO #tblItem    SELECT [Item] FROM dbo.SplitString(@fieldTableName, '_');    
    
  SET @fieldTableName = '';    
  SELECT @ItemCnt = COUNT(*) FROM #tblItem;    
    
  SELECT @fieldTableName = IIF(@fieldTableName != '', @fieldTableName + '_', '') + [Item]    
  FROM   #tblItem    
  WHERE  [ID] > 1 AND [id] < @ItemCnt;    
  SELECT @EntityName = [Item] FROM #tblItem WHERE [ID] = @ItemCnt;    
    
  SELECT @fieldTableName = CASE @fieldTableName    
         WHEN 'Batchemail_infos'    
          THEN 'V_BatchMail'    
         WHEN 'UserLeads'    
          THEN 'V_UserLeads'    
         WHEN 'LeadPipelineMapping'    
          THEN 'V_PipelineMapping'    
         WHEN 'tbl_tsk_TaskHistory'    
          THEN 'V_TaskAppointment'    
         ELSE @fieldTableName    
         END;    
    
  PRINT '@Operand1: ' + ISNULL(@Operand1, '');    
  PRINT '@ItemCnt: ' + CAST(@ItemCnt AS VARCHAR);    
  PRINT '@fieldTableName: ' + ISNULL(@fieldTableName, '');    
  PRINT '@EntityName: ' + ISNULL(@EntityName, '');    
    
  TRUNCATE TABLE #tblItem;    
    
  INSERT INTO #tblItem    
  SELECT [Item] FROM dbo.SplitString(@Operand1, '.');    
    
  SELECT TOP 1 @fieldName = [Item] FROM #tblItem ORDER BY [Id] DESC;    
    
  SELECT @fieldName = CASE ISNULL(@fieldName, '')    
       WHEN ''    
        THEN ''    
       WHEN 'MailLinkVisited'    
        THEN 'destination_url'    
       WHEN 'Source'    
        THEN @fieldName + 'Name'    
       WHEN 'Medium'    
        THEN @fieldName + 'Name'    
       WHEN 'Campaign'    
        THEN @fieldName + 'Name'    
       WHEN 'EntityCreatedOn'    
        THEN 'DATEDIFF(DAY,GETDATE(),CreatedOn)'    
       WHEN 'MessageText'    
        THEN( CASE    
           WHEN @fieldTableName = 'Batchinfo'    
            THEN 'bMessage'    
           WHEN @fieldTableName = 'V_BatchMail'    
            THEN 'Message'    
           ELSE @fieldName    
           END )    
       ELSE @fieldName    
       END;    
    
  PRINT '@fieldName: ' + ISNULL(@fieldName, '');    
    
  SELECT @refColName = CASE ISNULL(@refColName, '')    
        WHEN 'MailLinkVisited'    
         THEN 'destination_url'    
        WHEN ''    
         THEN( CASE    
            WHEN @fieldTableName IN('V_BatchMail', 'WBatchinfo', 'Batchinfo')    
             THEN 'BatchID'    
            ELSE 'id'    
            END )    
        ELSE @refColName    
        END;    
    
  PRINT '@refColName: ' + ISNULL(@refColName, '');    
    
  IF(@EntityName = 'Entity')    
  BEGIN    
   select @csvCustomfields=STRING_AGG('['+CF.fieldname+'] sql_variant',',') WITHIN GROUP (ORDER BY CF.FieldName) from customfields(nolock) CF where CF.parentId=@ParentId and CF.isActive=1 and exists (Select CFL.fieldid from customfieldLeadvalue(nolock) CFL where CFL.fieldid=CF.field_id)    
       
   If(len(@csvCustomfields)>0)    
   Begin    
    drop table if exists #tblCustomLeadList    
    Create table #tblCustomLeadList    
    (    
     LeadID bigint    
    )    
    
    --set @csvCustomfields += ' sql_variant'    
    print 'alter table #tblCustomLeadList add ' + @csvCustomfields    
    exec('alter table #tblCustomLeadList add ' + @csvCustomfields)    
    SET @fieldTableName = 'customfieldLeadvalue CFL WITH (nolock, INDEX = IX_customfieldLeadvalue_fieldID) inner join customfields(nolock) CF ON CFL.fieldID=CF.field_ID and CF.ParentID=' + cast(@ParentId as varchar)    
    
    insert into #tblCustomLeadList     
    exec uspGenCrossTab 'LeadID','FieldName','Fieldvalue',@fieldTableName, 'customfields','isactive=1',' 1=1 ','min',' 1=1 '    
    
    SET @fieldTableName = 'V_UserLeads(nolock) UL left Join #tblCustomLeadList CL ON UL.ID=CL.LeadID';    
    
    IF EXISTS (SELECT * FROM TempDB.INFORMATION_SCHEMA.COLUMNS WHERE COLUMN_NAME = @fieldName AND TABLE_NAME LIKE '#tblCustomLeadList%')    
    BEGIN    
     SELECT @fieldName = 'cast(' + @fieldName + ' as nvarchar(max))'    
    END    
   End    
   Else    
   Begin    
    SET @fieldTableName = 'V_UserLeads(nolock)';    
   End    
   SET @refColName = 'ID';    
   SET @RefId = @LeadId;    
  END;    
    
  IF(@EntityName = 'User')    
  BEGIN    
   SET @fieldTableName = 'User_Detail';    
   SET @refColName = 'User_ID';    
   SET @RefId = @UserId;    
  END;    
    
  IF(@EntityName = 'Activity')    
  BEGIN    
   IF(@reftables = 'EngagementEventOpenClick')    
   BEGIN    
    SET @refColName = 'Id';    
   END;    
   ELSE IF(@fieldTableName = 'tbl_tsk_TaskHistory' or @fieldTableName = 'V_TaskAppointment')    
   BEGIN    
    SELECT @fieldName = case @fieldName when 'ActivityObjectCreatedOn' then 'CreatedOn' when 'ActivityObjectstatus' then 'STATUS' when 'ActivityObjectStartDate' then 'EndDate' else @fieldName end;    
    SELECT @refColName = case @refColName when 'BatchID' then 'id' else @refColName end;    
   END;    
   ELSE IF(@reftables = 'Batchinfo' or @reftables = 'V_BatchMail' or @fieldTableName = 'Batchinfo' or @fieldTableName = 'V_BatchMail')    
   BEGIN    
    SET @refColName = 'BatchID';    
   END;    
   ELSE IF(@fieldTableName = 'LeadInteractionHistory')      
   BEGIN      
    SELECT @fieldName = case @fieldName when 'ActivityFollowupStatus' then 'FollowupStatusName' when 'ActivityRemarks' then 'Remarks' when 'ActivityAmountPaid' then 'AmountPaid' when 'ActivityObjectCreatedOn' then 'CreatedOn' when 'ActivityProducts' then 'ProductsName' else @fieldName end;      
    SET @fieldTableName='V_LeadInteractionHistory'    
   END;      
   ELSE    
   BEGIN    
    SET @refColName = 'id';    
   END;    
  END;    
    
  IF(@Operator = '%[A]%')    
  BEGIN    
   SET @ConditionExpr = @fieldName + ' like ''%' + @Operand2 + '%''';    
  END;    
  ELSE    
  BEGIN    
   IF(@Operator = 'not %[A]%')    
   BEGIN    
    SET @ConditionExpr = @fieldName + ' not like ''%' + @Operand2 + '%''';    
   END;    
   ELSE    
   BEGIN    
    IF(@Operator = '[A]%')    
    BEGIN    
     SET @ConditionExpr = @fieldName + ' like ''' + @Operand2 + '%''';    
    END;    
    ELSE    
    BEGIN    
     IF(@Operator = 'not [A]%')    
     BEGIN    
      SET @ConditionExpr = @fieldName + ' not like ''' + @Operand2 + '%''';    
     END;    
     ELSE    
     BEGIN    
      IF(@Operator = '%[A]')    
      BEGIN    
       SET @ConditionExpr = @fieldName + ' like ''%' + @Operand2 + '''';    
      END;    
      ELSE    
      BEGIN    
       IF(@fieldName = 'not %[A]')    
       BEGIN    
        SET @ConditionExpr = @fieldName + ' not like ''%' + @Operand2 + '''';    
       END;    
       ELSE    
       BEGIN    
        SET @ConditionExpr = @fieldName + ' ' + @Operator + ' ''' + @Operand2 + '''';    
       END;    
      END;    
     END;    
    END;    
   END;    
  END;    
    
  PRINT '@ConditionExpr: ' + ISNULL(@ConditionExpr, '');    
    
  PRINT ''    
  PRINT '@fieldTableName: ' + ISNULL(@fieldTableName, '');    
  PRINT '@refColName: ' + ISNULL(@refColName, '');    
  PRINT '@RefId: ' + CAST(@RefId AS VARCHAR);    
    
  SET @SQL = 'If exists(SELECT ''Y'' FROM ' + @fieldTableName + ' WHERE ' + @refColName + ' = ' + CAST(@RefId AS VARCHAR) + ' and ' + @ConditionExpr + ') Begin insert into #tblResult values(''Y''); End Else Begin insert into #tblResult values(''N''); End';    
    
  PRINT '@SQL: ' + ISNULL(@SQL, '');    
  EXEC (@SQL);    
    
  SET @ConditionRow_ID = @ConditionRow_ID + 1;    
 END;--End While      
    
 SELECT * FROM #tblResult;    
    
 IF EXISTS(SELECT * FROM #tblResult)    
 BEGIN    
  IF(@Conjunction = 'OR')    
  BEGIN    
   IF EXISTS(SELECT * FROM #tblResult WHERE [Result] = 'Y')    
   BEGIN--True Condition      
    PRINT 'Condition Valid, @Conjunction: ' + @Conjunction;    
    RETURN 1;    
   END    
   ELSE--FALSE    
   BEGIN    
    PRINT 'Condition InValid, @Conjunction: ' + @Conjunction;    
    RETURN 0;    
   END    
  END;    
  ELSE    
  BEGIN--AND      
   IF EXISTS(SELECT * FROM #tblResult WHERE [Result] = 'N')    
   BEGIN--False Condition      
    PRINT 'Condition InValid, @Conjunction: ' + @Conjunction;    
    RETURN 0;    
   END;    
   ELSE    
   BEGIN--All conditions true      
    PRINT 'Condition Valid, @Conjunction: ' + @Conjunction;    
    RETURN 1;    
   END;    
  END;    
 END;    
 ELSE    
 BEGIN    
  IF(@ConditionRow_Cnt = 0)    
  BEGIN    
   PRINT 'Condition Valid, Stage without Condition';    
   RETURN 1;    
  END;    
  ELSE    
  BEGIN    
   PRINT 'Condition InValid, Missing Info.';    
   RETURN 0;    
  END;    
 END;    
    
 PRINT '-----------------------------End------ usp_wf_EvaluateCondition ----------------------------------------';    
    
END; 



GO

/* ============================================================
   Procedure: [dbo].[usp_wf_EvalWaitCondition]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_wf_EvalWaitCondition
(
	@WorkflowId bigint,
	@RefHistoryId BIGINT,
	@ScheduledAfterHrs VARCHAR(50),
	@ScheduledField varchar(100), 
	@ScheduledOperator varchar(50),
	@StageId BIGINT
)
As
Begin
	--declare @WorkflowId bigint=96,@ScheduledAfterHrs VARCHAR(50),@ScheduledField varchar(100)='FromDate_ddlAction1_simple_num0',@ScheduledOperator varchar(50)='',@StageId BIGINT=301,@RefHistoryId BIGINT=1826252

	declare @FieldName Nvarchar(100), @ActionName varchar(50), @SequenceNo int, @RefId BIGINT, 
			@reftables NVARCHAR(1000), @refColName NVARCHAR(1000), @ScheduledFieldValue datetime
	DECLARE @SQLString NVARCHAR(max), @ParmDefinition NVARCHAR(max);  

	Select * from dbo.fn_Split(@ScheduledField,'_')
	Select @FieldName=value from dbo.fn_Split(@ScheduledField,'_') where position=1
	Select @ActionName=value from dbo.fn_Split(@ScheduledField,'_') where position=2

	select @SequenceNo=replace(@ActionName,'ddlAction','')+1
	Select @SequenceNo

	SELECT	@reftables = [reftables], @RefId = [refids], @refColName = [refColName]
	FROM	tbl_wf_WorkflowProcessInitMaster(NOLOCK)
	WHERE	isnull(refHistoryId,HistoryId) = @RefHistoryId and SequenceNo = @SequenceNo;

	If(@reftables='tbl_tsk_TaskHistory')
	Begin
		Select @FieldName=case @FieldName when 'DueDate' then 'EndDate' when 'FromDate' then 'StartDate' else @FieldName end
	End

	If(@reftables='MySMSConversations.dbo.tbl_ims_schedule_message')
	Begin
		Select @FieldName=case @FieldName when 'ScheduledDatetime' then 'ScheduledOn' else @FieldName end
	End

	print 'select ' + @FieldName + ' from ' + @reftables + '(NOLOCK) Where ' + @refColName + '=' + cast(@RefId as varchar)
  
	SET @SQLString = N'SELECT @SFDateOUT = ' + @FieldName + N'   
	   FROM ' + @reftables + N'(NOLOCK)  
	   WHERE ' + @refColName + ' = @ID';  
	SET @ParmDefinition = N'@ID BIGINT, @SFDateOUT datetime OUTPUT';  
  
	EXECUTE sp_executesql @SQLString, @ParmDefinition, @ID = @RefId, @SFDateOUT=@ScheduledFieldValue OUTPUT;  
	SELECT @ScheduledFieldValue; 

	If(@ScheduledOperator = '=')
	Begin
		IF(cast(DATEADD(hour, CAST(ISNULL(@ScheduledAfterHrs, '0') AS NUMERIC(18, 2)), @ScheduledFieldValue) as date) = cast(GETDATE() as date))
		Begin
			Return 1
		End
		Else
		Begin
			Return 0
		End
	End

	If(@ScheduledOperator = '!=')
	Begin
		IF(cast(DATEADD(hour, CAST(ISNULL(@ScheduledAfterHrs, '0') AS NUMERIC(18, 2)), @ScheduledFieldValue) as date) != cast(GETDATE() as date))
		Begin
			Return 1
		End
		Else
		Begin
			Return 0
		End
	End

	If(@ScheduledOperator = '>')
	Begin
		IF(DATEADD(hour, CAST(ISNULL(@ScheduledAfterHrs, '0') AS NUMERIC(18, 2)), @ScheduledFieldValue) > GETDATE())
		Begin
			Return 1
		End
		Else
		Begin
			Return 0
		End
	End

	If(@ScheduledOperator = '>=')
	Begin
		IF(DATEADD(hour, CAST(ISNULL(@ScheduledAfterHrs, '0') AS NUMERIC(18, 2)), @ScheduledFieldValue) >= GETDATE())
		Begin
			Return 1
		End
		Else
		Begin
			Return 0
		End
	End

	If(@ScheduledOperator = '<=')
	Begin
		IF(DATEADD(hour, CAST(ISNULL(@ScheduledAfterHrs, '0') AS NUMERIC(18, 2)), @ScheduledFieldValue) <= GETDATE())
		Begin
			Return 1
		End
		Else
		Begin
			Return 0
		End
	End

	If(@ScheduledOperator = '<')
	Begin
		IF(DATEADD(hour, CAST(ISNULL(@ScheduledAfterHrs, '0') AS NUMERIC(18, 2)), @ScheduledFieldValue) < GETDATE())
		Begin
			Return 1
		End
		Else
		Begin
			Return 0
		End
	End

End



GO

