	Else If(@ActionCode='ADD_DEAL')
	Begin
		-- {"DealValue":"34","DealPipeline":"15","DealStage":"102","Probability":"44","DealOwner":"32222","EstimatedClosureDate":"3"}
		select	@PipelineID=DealPipeline, @PipelineStage=DealStage, @Amount=DealValue, @EstimatedClosureDate=DATEADD(hour, EstimatedClosureDate, @LastExecDate), @DealOwner=DealOwner, @Probability=Probability
		from openjson(@JsonAction)
		with
