		/* declare @custom1 customleads1,@JsonAction nvarchar(max)=N'{"PersonName":"ram","InitialRemarks":"rem","MobileNo":"+91 9313943059","MobileNo1":"","MobileNo2":"","EmailID":"mayank.nigam@pelsoftlabs.in","EmailID1":"","EmailID2":"","ResidentialAddress":"vikaspuri","Country":"101","State":"10","City":"706","Pincode":"110018","SourceName":"528603","MediumName":"375711","CampaignName":"41702","FollowupStatus":"1","Remarks":"frem","AssignedTo":"32222","NextStatusDate":"4","test01":"4","test02":"4","test03":"4","test04":"","test12":"","test06":"","test07":"","test08":"","test11":"","test10":"","dateofbirth":"","Budget":"","project":"","alpha":"","yujhu":"","newfield":"","test13":"","test14":"","test15":"","test16":"","test17":"","test18":"","test19":"","test20":"","test21":"","test22":"","test23":"","test24":"","test25":"","test26":"","test36":"","test27":"","test28":"","test29":"","test30":"","test31":"","test32":"","test33":"","test34":"","test35":"","UNGALI":"","Yes":"","abcd":"","DOBPAN":"","NEWMOBILE":"+919313943059","NAMEONE":"gdfhgfd"}'
		
		--insert into @custom1(fieldid,fieldvalue)
