		On	CV.[Key]  COLLATE DATABASE_DEFAULT=CF.fieldname  COLLATE DATABASE_DEFAULT and CF.isActive=1 and CF.ParentID=32222--@ParentID
		Where CV.[key] not in ('PersonName','InitialRemarks','MobileNo','MobileNo1','MobileNo2','EmailID','EmailID1','EmailID2','ResidentialAddress','Country','State','City','Pincode','SourceName','MediumName','CampaignName','FollowupStatus','Remarks','AssignedTo','NextStatusDate','AmountPaid')
		and [value] != ''

		-select * from @custom1
		*/

		Select @PersonName=PersonName, @Mobile_No=MobileNo, @Mobile_No1=MobileNo1, @Mobile_No2=MobileNo2, @Email_ID=EmailID, @Email_ID1=EmailID1, @Email_ID2=EmailID2, @City=City, @State=[State], @Country=Country, @Pincode=Pincode, @ResidentialAddress=ResidentialAddress, @SourceName=SourceName, @MediumName=MediumName, @CampaignName=CampaignName, @Remarks=Remarks, @AssignedTo=AssignedTo, @FollowupStatus=FollowupStatus, @NextStatusDate=DATEADD(hour,NextStatusDate,@LastExecDate)
		From openjson(@JsonAction)
		with
