		--declare @LeadId bigint=1666848,@ParentID bigint=32222,@JsonAction nvarchar(max)=N'{"PersonName":"","InitialRemarks":"","MobileNo":"","MobileNo1":"","MobileNo2":"","EmailID":"","EmailID1":"","EmailID2":"","ResidentialAddress":"","Country":"0","State":null,"City":null,"Pincode":"","SourceName":"0","MediumName":"0","CampaignName":"45550","FollowupStatus":"30","Remarks":"","Name1":"","Name2":"","Name3":"","Name4":"","test12":"","test06":"","test07":"","test08":"","test11":"","test10":"","dateofbirth":"","Budget":"","project":"","alpha":"","":"","newfield":"","test13":"","test14":"rttre","test15":"","test16":"","test17":"","test18":"","test19":"","test20":"","test21":"","test22":"444","test23":"","test24":"","test25":"","test26":"","test36":"","test27":"","test28":"","test29":"","test30":"","test31":"","test32":"","test33":"","test34":"","test35":"","UNGALI":"","Yes":"","abcd":"","DOBPAN":"","NEWMOBILE":"","NAMEONE":""}'

		declare @tblFields table (fieldid bigint,fieldname varchar(100), fieldvalue varchar(max))
		declare @tblOldFieldVal table (fieldid bigint,fieldname varchar(100), fieldvalue varchar(max))
		declare @CustomValJson nvarchar(max)='',@OldValJson nvarchar(max)='',@NewValJson nvarchar(max)=''
		declare @strsql nvarchar(max)='', @strMainFields nvarchar(max)=''

		insert into @tblFields(fieldid,fieldname,fieldvalue)
		select CF.field_ID, CF.fieldname,CV.[value] 
		From openjson(@JsonAction) CV inner join customfields(nolock) CF
		On	CV.[Key]  COLLATE DATABASE_DEFAULT=CF.fieldname  COLLATE DATABASE_DEFAULT and CF.isActive=1 and CF.ParentID=@ParentID
		Where CV.[key] not in ('PersonName','InitialRemarks','MobileNo','MobileNo1','MobileNo2','EmailID','EmailID1','EmailID2','ResidentialAddress','Country','State','City','Pincode','SourceName','MediumName','CampaignName','FollowupStatus','Remarks','AssignedTo','NextStatusDate','AmountPaid')
		and isnull(value,'0') != '0' and isnull(value,'0') != ''

		--select * from @tblFields
		
		select @CustomValJson=isnull(STRING_AGG('"'+CF.fieldname+'":"'+cast(isnull(CFL.fieldvalue,'null') as varchar)+'"',','),'')
		from
		(
			SELECT * FROM  customfields(nolock) Where parentid=ParentID
		) CF left join
		( 
			SELECT * FROM  customfieldLeadvalue(nolock) WHERE LeadID = @LeadId  
		) CFL
		ON CF.field_ID=CFL.fieldID
		Where CF.field_ID in (select fieldid from @tblFields Where fieldid is not null)
		--select @CustomValJson
		
		print '@CustomValJson: ' + @CustomValJson
	
		insert into @tblFields(fieldname,fieldvalue)
		select [Key],[value]
		From openjson(@JsonAction)
		Where [key] in ('PersonName','InitialRemarks','MobileNo','MobileNo1','MobileNo2','EmailID','EmailID1','EmailID2','ResidentialAddress','Country','State','City','Pincode','SourceName','MediumName','CampaignName','FollowupStatus','Remarks','AssignedTo','NextStatusDate','AmountPaid')
		and isnull(value,'0') != '0' and isnull(value,'0') != ''

		--select * from @tblFields
		
		select @strMainFields=isnull(STRING_AGG(fieldname,','),'') 
		from @tblFields
		where fieldid is null

		print '@strMainFields: ' + isnull(@strMainFields,'--')
		
		if(@strMainFields != '')--main fields
		Begin
			set @strsql = 'set @OldVal_Json=(select ' + @strMainFields + ' from UserLeads(nolock) where id=' + cast(@LeadId as varchar) + ' for json auto,WITHOUT_ARRAY_WRAPPER)'
			print '@strsql: ' + @strsql
			EXECUTE sp_executesql @strsql, N'@OldVal_Json nvarchar(max) output', @OldVal_Json = @OldValJson output
			print '@OldValJson:(main fields) ' + @OldValJson

			If(len(@CustomValJson)>2)
			Begin
				set @OldValJson = REPLACE(@OldValJson,'}',','+@CustomValJson+'}')
				print '@OldValJson:(main+custom fields) ' + @OldValJson
			End

			select @strMainFields=isnull(STRING_AGG(fieldname+'='''+ CAST(fieldvalue AS varchar) +'''',','),'') 
			from @tblFields
			where fieldid is null
			print '@strMainFields: (update) ' + @strMainFields

			set @strsql = 'update UserLeads set ' + @strMainFields + '  where id=' + cast(@LeadId as varchar)
			print '@strsql(update): ' + @strsql
			exec(@strsql)
		end
		Else
		Begin--custom fields
			If(len(@CustomValJson)>2)
			Begin
				set @OldValJson = '{'+@CustomValJson+'}'
				print '@OldValJson:(custom fields) ' + @OldValJson
			End
		End

		select @NewValJson=isnull(STRING_AGG('"'+fieldname+'":"'+cast(isnull(fieldvalue,'null') as varchar)+'"',','),'') 
		from @tblFields 
		set @NewValJson = '{'+@NewValJson+'}'
		print '@NewValJson:(main+custom fields) ' + @NewValJson

		If(len(@CustomValJson)>2)
		Begin
			update CFL Set CFL.fieldvalue=cast(TF.fieldvalue as nvarchar)
			From customfieldleadvalue CFL inner join @tblFields TF
			On CFL.fieldId=TF.fieldid and CFL.LeadID=@LeadId
			Where TF.fieldid is not null

			insert into customfieldleadvalue(LeadID,FieldID,fieldvalue)
			select @LeadId, TF.fieldid, cast(TF.fieldvalue as nvarchar)
			from @tblFields TF
			where TF.fieldid not in (select fieldid from customfieldleadvalue(nolock) CFL where CFL.fieldid=isnull(TF.fieldid,0) and CFL.leadID=@LeadId) and TF.fieldid is not null
		End

		Select @Mobile_No=MobileNo, @Mobile_No1=MobileNo1, @Mobile_No2=MobileNo2
		From openjson(@JsonAction)
		with
		(
			MobileNo VARCHAR(100), 
			MobileNo1 VARCHAR(100),
			MobileNo2 VARCHAR(100) 
		)

		If(isnull(@Mobile_No,'')!='')
		Begin
			Select top 1 @CountryCode=value From dbo.fn_Split(@Mobile_No,' ')
			Select top 1 @Mobile_No=value From dbo.fn_Split(@Mobile_No,' ') order by position desc
			SET Context_Info 0x55555
			update userleads set CountryCode=@CountryCode,MobileNo=@Mobile_No where id=@LeadId
			SET Context_Info 0x 
		End

		If(isnull(@Mobile_No1,'')!='')
		Begin
			Select top 1 @CountryCode1=value From dbo.fn_Split(@Mobile_No1,' ')
			Select top 1 @Mobile_No1=value From dbo.fn_Split(@Mobile_No1,' ') order by position desc
