			)

			Delete From	tbl_wf_WorkflowResponse Where SPId=@@SPID
			Exec usp_wf_SendMailFromLeads_WithTemplateID @LeadId, @Account, @Subject, @TemplateID, @Sender, @ReplyTo, @EmailId, @EmailId1, @EmailId2, @UserId, @RefHistoryId, @WorkFlowId
		End
		Else
		Begin
			select @EmailId=EmailId, @EmailId1=EmailId1, @EmailId2=EmailId2, @Account=Account, @Sender=Sender, @Subject=[Subject], @ReplyTo=ReplyTo, @Message=[Message]
			from openjson(@JsonAction)
			with
			(
				EmailId		bit,
				EmailId1	bit,
				EmailId2	bit,
				Account		bigint,
				Sender		varchar(100),
				[Subject]	varchar(1000),
				ReplyTo		varchar(1000),
