		End
	End
	Else If(@ActionCode='EM_TO_ASG' OR @ActionCode='EM_TO_CRE')
	Begin
	/*{"EmailId":true,"EmailId1":false,"EmailId2":true,"Account":"34594","Sender":"sales@pelsoftlabs.in","ReplyTo":"sales@pelsoftlabs.in","Subject":"Subject","TemplateID":"4111"}
	{"EmailId":true,"EmailId1":false,"EmailId2":true,"Account":"32222","Sender":"abhshek.kumar@Support.appmails.in.net","ReplyTo":"abhshek.kumar@Support.appmails.in.net","Subject":"Compose Msg","Message":"Compose Msg Content"}*/


		if exists(select * from openjson(@JsonAction) where [key]='TemplateID')
		Begin
			select @EmailId=EmailId, @EmailId1=EmailId1, @EmailId2=EmailId2, @Account=Account, @Sender=Sender, @Subject=[Subject], @ReplyTo=ReplyTo, @TemplateID=TemplateID
			from openjson(@JsonAction)
			with
			(
				EmailId		bit,
				EmailId1	bit,
				EmailId2	bit,
				Account		bigint,
				Sender		varchar(100),
				[Subject]	varchar(1000),
				ReplyTo		varchar(1000),
				TemplateID	bigint
			)

			Delete From	tbl_wf_WorkflowResponse Where SPId=@@SPID
			Exec usp_wf_SendMailFromLeads_WithTemplateIDToUser @ActionCode, @LeadId, @Account, @Subject, @TemplateID, @Sender, @ReplyTo, @EmailId, @EmailId1, @EmailId2, @UserId, @RefHistoryId, @WorkFlowId
		End
		Else
		Begin
			select @EmailId=EmailId, @EmailId1=EmailId1, @EmailId2=EmailId2, @Account=Account, @Sender=Sender, @Subject=[Subject], @ReplyTo=ReplyTo, @Message=[Message]
			from openjson(@JsonAction)
			with
			(
				EmailId		bit,
				EmailId1	bit,
				EmailId2	bit,
				Account		bigint,
				Sender		varchar(100),
				[Subject]	varchar(1000),
				ReplyTo		varchar(1000),
				[Message]	VARCHAR(MAX)
			)

			Delete From	tbl_wf_WorkflowResponse Where SPId=@@SPID
			Exec usp_wf_SendMailFromLeads @LeadId, @Account, @Subject, @Message, @Sender, @ReplyTo, @EmailId, @EmailId1, @EmailId2, @UserId, @RefHistoryId, @WorkFlowId
