		-- {"Account":"34594","Sender":"159564","DLTTemplateID":"1707160822091194683","Message":"sms content","MobileNo":false,"MobileNo1":true,"MobileNo2":false,"IsUnicode":true}

		select @Account=Account, @SenderID=Sender, @Message=[Message], @IsUnicode=IsUnicode, @MobileNo=MobileNo, @MobileNo1=MobileNo1, @MobileNo2=MobileNo2, @DLTTemplateID=DLTTemplateID
		from openjson(@JsonAction)
		with
		(
			Account		bigint,
			Sender		varchar(100),
			[Message]	VARCHAR(MAX),
