		-- {"Account":"34594","Sender":"159564","DLTTemplateID":"1707160822091194683","Message":"sms content","MobileNo":false,"MobileNo1":true,"MobileNo2":false,"IsUnicode":true}

		select @Account=Account, @SenderID=Sender, @Message=[Message], @IsUnicode=IsUnicode, @MobileNo=MobileNo, @MobileNo1=MobileNo1, @MobileNo2=MobileNo2, @DLTTemplateID=DLTTemplateID
		from openjson(@JsonAction)
		with
		(
			Account		bigint,
			Sender		varchar(100),
			[Message]	VARCHAR(MAX),
			IsUnicode	bit,
			MobileNo	bit,
			MobileNo1	bit,
			MobileNo2	bit,
			DLTTemplateID nvarchar(200)
		)

		Delete From	tbl_wf_WorkflowResponse Where SPId=@@SPID
		Exec usp_wf_IntindSMSFromLeads_New1_WithDLTTemplateIDToUser  @ActionCode, @LeadId, @Account, @SenderID, @Message, @IsUnicode, @MobileNo, @MobileNo1, @MobileNo2, @DLTTemplateID, @UserId, @RefHistoryId, @WorkFlowId
	End
	Else If(@ActionCode='VOI_TO_LD' or @ActionCode='VOI_TO_OWN')
	Begin
		--{"MobileNo":false,"MobileNo1":true,"MobileNo2":false,"Route":"trans","CallerID":"7303390732","appid":"4109","Duration":"30"}

		select @MobileNo=MobileNo, @MobileNo1=MobileNo1, @MobileNo2=MobileNo2, @route=[Route], @callerid=CallerID, @appid=appid, @duration=Duration
		from openjson(@JsonAction)
		with
		(
			MobileNo	bit,
			MobileNo1	bit,
			MobileNo2	bit,
			[Route]		nvarchar(20),
			appid		int,
			Duration	int,
			CallerID	nvarchar(20)
		)

		Select @strmobile +=	iif(isnull(MobileNo,'') = '','', iif(@strmobile='','',',') + MobileNo)
		From UserLeads(nolock) 
		Where Id=@LeadId and @MobileNo=1

		Select @strmobile +=	iif(isnull(MobileNo1,'') = '','', iif(@strmobile='','',',') + MobileNo1)
		From UserLeads(nolock) 
		Where Id=@LeadId and @MobileNo1=1

		Select @strmobile +=	iif(isnull(MobileNo2,'') = '','', iif(@strmobile='','',',') + MobileNo2)
		From UserLeads(nolock) 
		Where Id=@LeadId and @MobileNo2=1

		if(@strmobile != '')
		Begin
			Delete From	tbl_wf_WorkflowResponse Where SPId=@@SPID
			Exec usp_wf_insertnewcallForBroadcast @UserId, @route, @strmobile, @appid, @callerid, @duration, @scheduledfor, @EntityName, @EntityId, @RefHistoryId, @WorkFlowId
		End
	End
	Else If(@ActionCode='WAP_TO_LD' or @ActionCode='WAP_TO_OWN')
	Begin
		-- declare @JsonAction nvarchar(max)= '{"BroadcastName":"reply","ScheduledDatetime":"0","IncludeCriteria":["236847"],"IncludeCriteriaAdditional":"","ContactType":"C","TemplateID":"902"}'

		select *--@BroadcastName=BroadcastName, @ScheduledDatetime=DATEADD(hour, ScheduledDatetime, @LastExecDate), @IncludeCriteria=IncludeCriteria, @IncludeCriteriaAdditional=IncludeCriteriaAdditional, @ContactType=ContactType, @WTemplateId=TemplateID, @jsonTemplateFields=CF
		from openjson(@JsonAction)
		with
		(
			BroadcastName				nvarchar(200),
			ScheduledDatetime			int,
			IncludeCriteria				nvarchar(max) as json,
			IncludeCriteriaAdditional	nvarchar(max),
			ContactType					varchar(1),
			TemplateID					int,
			CF							nvarchar(max) as Json
		)

		Set @IncludeCriteria=REPLACE(REPLACE(REPLACE(@IncludeCriteria,'[',''),']',''),'"','')

		Delete From	tbl_wf_WorkflowResponse Where SPId=@@SPID
		--Exec MySMSConversations.dbo.usp_wf_AddBroadcastMessage @BroadcastName,@IncludeCriteria,@IncludeCriteriaAdditional,@ContactType,@WTemplateId,@ScheduledDatetime,@UserId,@jsonTemplateFields, @RefHistoryId, @WorkFlowId
		DECLARE @Query NVARCHAR(MAX);

-- Build the dynamic SQL query string using ~ as the delimiter
SET @Query = CONCAT(
    'EXEC usp_wf_AddBroadcastMessage ',
    '''', REPLACE(@BroadcastName, '''', ''''''), '''~',
    '''', REPLACE(@IncludeCriteria, '''', ''''''), '''~',
    '''', REPLACE(@IncludeCriteriaAdditional, '''', ''''''), '''~',
    '''', REPLACE(@ContactType, '''', ''''''), '''~',
    ISNULL(CAST(@WTemplateId AS NVARCHAR), 'NULL'), '~',
    '''', CONVERT(NVARCHAR, @ScheduledDatetime, 120), '''~',
    ISNULL(CAST(@UserId AS NVARCHAR), 'NULL'), '~',
    '''', REPLACE(@jsonTemplateFields, '''', ''''''), '''~',
    ISNULL(CAST(@RefHistoryId AS NVARCHAR), 'NULL'), '~',
    ISNULL(CAST(@WorkFlowId AS NVARCHAR), 'NULL')
);

-- Execute the dynamic SQL query
EXEC usp_clr_ExecuteRemoteQuery @Query;

	End
	--Else If(@ActionCode='TRG_WEB')
	--Begin
	--End

	print '-----------------------------End------ usp_wf_ExecAction ----------------------------------------'

END



GO

/* ============================================================
   Procedure: [dbo].[usp_wf_GetTriggerEvent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
-- Exec usp_wf_GetTriggerEvent 'LE'
CREATE   PROC usp_wf_GetTriggerEvent
(
	@EventType varchar(5)='LE'
)
AS
BEGIN

	If(@EventType='L')--Lead
	Begin
		Select *
		From activitymaster(nolock) AM 
		Where AM.context in ('lead') 
	End

	If(@EventType='E')--enquiry
	Begin
		Select *
		From activitymaster(nolock) AM 
		Where AM.context in ('enquiry')
	End

	If(@EventType='LE')--Lead & enquiry
	Begin
		Select *
		From activitymaster(nolock) AM 
		Where AM.context in ('Lead','enquiry')
	End

	If(@EventType='A')--All
	Begin
		Select *
		From activitymaster(nolock) AM 
	End

END



GO

