  w.EntityId,
  w.EntryDate,
  w.formname,   
  w.Name,
  w.Email,
  w.ContactDate,
  w.Address,   
  w.DynimicAttr,
  w.Remarks,
  w.Status,  
  w.mail_body,
  w.msg_body,
  w.CampaignName,   
  u.User_Id,
  u.User_Login as AgentName,
  u.FName,
  u.LName,
  u.Image
 from WebEntryTbl(nolock) w inner join 
