/* ============================================================
   Procedure: [dbo].[usp_wf_GetWebformLeadReport_MOB]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_wf_GetWebformLeadReport_MOB](    
 @LeadId bigint,
 @FilterText varchar(50)= '',
 @OffsetValue int =0,
 @PagingSize int = 10
)
as
begin

select count(w.EntryId) over() TotalRows,
  w.EntryId, 
  w.EntryNo, 
  w.EntityId,  
  w.EntryDate,  
  w.formname,     
  w.Name,  
  w.Email,  
  w.ContactDate,  
  w.Address,     
  w.DynimicAttr,  
  w.Remarks,  
  w.Status,    
  w.mail_body,  
  w.msg_body,  
  w.CampaignName,     
  u.User_Id,  
  u.User_Login as AgentName,  
  u.FName,  
  u.LName,  
  u.Image  
 from WebEntryTbl(nolock) w inner join   
 User_Detail(nolock) u on w.AgentId = u.User_ID  
 where w.EntityName = 'lead' and w.EntityId = @LeadId  --1049641     
 Group by w.EntryId, w.EntryNo, w.EntityId, w.EntryDate, w.formname, w.Name, w.Email, w.ContactDate, w.Address, w.DynimicAttr, w.Remarks,  
  w.Status, w.mail_body, w.msg_body, w.CampaignName, u.User_Id, u.User_Login, u.FName, u.LName, u.Image
 Order by w.EntryId Asc
 OFFSET @OffsetValue ROWS FETCH NEXT @PagingSize ROWS ONLY
end   



GO

