SET QUOTED_IDENTIFIER ON

  
-- Exec usp_wf_GetWorkflow 32222
CREATE   PROC usp_wf_GetWorkflow
(
	@UserId bigint
)
AS
BEGIN

	Select WM.*,UD.User_Login,'' as ExecutedOn, '' as LastExecutedOn, '' as ScheduledOn
	From tbl_wf_WorkflowMaster(nolock) WM inner join User_Detail(nolock) UD
	ON	 WM.CreatedBy=UD.User_ID
	Where WM.IsActive=1 and WM.CreatedBy = @UserId

END



