/* ============================================================
   Procedure: [dbo].[usp_wf_GetWorkflowProcessList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_wf_GetWorkflowProcessList
(
  @UserId      BIGINT, 
  @FilterText  NVARCHAR(MAX)='', 
  @OffsetValue INT          =0, 
  @PagingSize  INT          =20)
AS
BEGIN	
--declare
--@UserId bigint = 34594,
--@FilterText nvarchar(max) = '',
--@OffsetValue int  = 0,
--@PagingSize int  = 20 
DECLARE 
  @ParentId BIGINT;
SELECT @ParentId=ParentID
FROM User_Detail( NOLOCK )
WHERE User_ID=@UserId;
DECLARE 
  @QueryString NVARCHAR(MAX)=N' select count(WProcessId) over() as TotalRow, WProcessId, WorkflowName, StageName, Status, CreatedOn, ExecEndDate from (
	select im.WProcessId, wm.WorkflowName, sm.StageName, im.Status, im.CreatedOn, im.ExecEndDate
	from tbl_wf_WorkflowProcessInitMaster(nolock) im 
		inner join tbl_wf_WorkflowMaster(nolock) wm on im.WorkflowId = wm.WorkflowId --and im.WorkflowId = 80
		inner join tbl_wf_WorkflowStageMaster(nolock) sm on  im.StageId = sm.StageId
	where im.ParentId = '+STR( @ParentId )+' and im.refHistoryId is null ) t  ';
IF ISNULL( @FilterText, '' )<>''
BEGIN
SET @QueryString=@QueryString+' '+@FilterText;
END;
SET @QueryString=@QueryString+' order by CreatedOn desc offset '+STR( @OffsetValue )+' rows fetch next '+STR( @PagingSize )+' rows only  ';
PRINT @QueryString;
EXECUTE sp_executesql 
        @QueryString;
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_wf_GetWorkflowSubSetProcessList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_wf_GetWorkflowSubSetProcessList](@WProcessId BIGINT)
AS
BEGIN
    --declare @WProcessId bigint = 2112
    DECLARE @WorkflowId BIGINT, @HistroyId BIGINT;
    SELECT @WorkflowId = WorkflowId, 
            @HistroyId = HistoryId
    FROM tbl_wf_WorkflowProcessInitMaster(NOLOCK) WHERE WProcessId = @WProcessId;

    SELECT im.WProcessId, im.HistoryId, wm.WorkflowName, sm.StageName, sm.StageType, sm.SequenceNo, am.ActionName,
            im.STATUS, im.CreatedOn, im.ExecEndDate, im.ResponseCode, 
			( case when trim(isnull(im.ResponseText, '')) = ''
				then 'An unexpected error occured'
				else im.ResponseText end ) as ResponseText
    FROM
    (
        SELECT WProcessId, HistoryId, WorkflowId,  StageId, STATUS, CreatedOn, ExecEndDate, ResponseCode, ResponseText
			FROM tbl_wf_WorkflowProcessInitMaster(NOLOCK)
			WHERE WProcessId = @WProcessId
        UNION
        SELECT WProcessId, HistoryId, WorkflowId, StageId, STATUS, CreatedOn, ExecEndDate, ResponseCode, ResponseText
			FROM tbl_wf_WorkflowProcessInitMaster(NOLOCK)
        WHERE refHistoryId = @HistroyId AND WorkflowId = @WorkflowId
    ) im
    INNER JOIN tbl_wf_WorkflowMaster(NOLOCK) wm ON im.WorkflowId = wm.WorkflowId
    INNER JOIN tbl_wf_WorkflowStageMaster(NOLOCK) sm ON im.StageId = sm.StageId
	LEFT JOIN tbl_wf_WorkflowActionMaster(NOLOCK) am ON sm.ActionCode = am.ActionCode
		where sm.StageType <> ''
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_wf_Insert_Lead_Details_ChangeWithFollowupDate2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Action Code => ( ADD_LD )  
CREATE   PROCEDURE [dbo].[usp_wf_Insert_Lead_Details_ChangeWithFollowupDate2]  
(  
 @ParentID           BIGINT,   
 @PersonName         VARCHAR(100),   
 @CompanyName        VARCHAR(100),   
 @MobileNo           VARCHAR(100),   
 @MobileNo1          VARCHAR(100),   
 @MobileNo2          VARCHAR(100),   
 @EmailID            VARCHAR(100),   
 @EmailID1           VARCHAR(100),   
 @EmailID2           VARCHAR(100),   
 @City               VARCHAR(100),   
 @State              VARCHAR(100),   
 @Country            VARCHAR(100),   
 @CountryCode        VARCHAR(50),   
 @CountryCode1       VARCHAR(50),   
 @CountryCode2       VARCHAR(50),   
 @PinCode            BIGINT,   
 @ResidentialAddress VARCHAR(500),   
 @OfficialAddress    VARCHAR(500),   
 @SourceName         BIGINT,   
 @MediumName         BIGINT,   
 @CampaignName       BIGINT,   
 @Remarks            VARCHAR(1000),   
 @CreatedBy          BIGINT,   
 @AssignedTo         BIGINT,   
 @FollowUpStatus     INT,   
 @NextStatusDate     VARCHAR(50),   
 @Products           VARCHAR(1000),   
 @AmountPaid         NUMERIC(18, 2),   
 @FollowUpRemarks    VARCHAR(1000),   
 @WhereAddress       NVARCHAR(255)  = '',   
 @WhereLatitude      NVARCHAR(255)  = '',   
 @WhereLongitude     NVARCHAR(255)  = '',   
 @LeadTags           NVARCHAR(MAX)  = NULL,   
 @custom             CUSTOMLEADS1 READONLY,   
 @RefHistoryId       BIGINT,  
 @WorkFlowId		 BIGINT = NULL
)  
AS  
BEGIN  
 --declare @tbl_Response as tbl_Response  
  
 BEGIN TRY  
        PRINT '-------------BEGIN---------------------- usp_wf_Insert_Lead_Details_ChangeWithFollowupDate2 --------------------------------';  
        DECLARE @newlead BIGINT;  
        DECLARE @FollowupDate DATETIME= NULL;  
        IF(@NextStatusDate <> '')  
        BEGIN  
            SET @FollowupDate = @NextStatusDate;  
        END;  
        CREATE TABLE #temp (  
			mobile VARCHAR(100),   
			email  VARCHAR(100)  
        );  
        INSERT INTO #temp ( mobile, email )  
            SELECT(CAST(ISNULL(NULLIF(CountryCode, ''), 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo, ''), 0) AS NVARCHAR)),   
                    ISNULL(NULLIF(EmailID, ''), 0) FROM UserLeads WHERE ParentID = @PARENTID  
            UNION  
            SELECT(CAST(ISNULL(NULLIF(CountryCode1, ''), 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo1, ''), 0) AS NVARCHAR)),   
                    ISNULL(NULLIF(EmailID1, ''), 0) FROM UserLeads WHERE ParentID = @PARENTID  
            UNION  
            SELECT(CAST(ISNULL(NULLIF(CountryCode2, ''), 0) AS NVARCHAR) + CAST(ISNULL(NULLIF(MobileNo2, ''), 0) AS NVARCHAR)),   
                    ISNULL(NULLIF(EmailID2, ''), 0) FROM UserLeads WHERE ParentID = @PARENTID;  
  
        IF EXISTS (SELECT 1 FROM UserLeads WHERE ParentID = @ParentID AND ( CAST(ISNULL(NULLIF(@CountryCode, ''), 1) AS NVARCHAR) + CAST(ISNULL(NULLIF(@MobileNo, ''), 1) AS NVARCHAR) IN ( SELECT Mobile FROM #temp )))  
        BEGIN  
			--insert into @tbl_Response values('0', '-2', 'Lead with Mobile ' + @mobileno + ' already exists' );  
			insert into tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) values (@@SPID,'0', '-2', 'Lead with Mobile ' + @mobileno + ' already exists' );  
            GOTO LeadNotInserted;  
        END;  
  
        IF EXISTS (SELECT 1 FROM UserLeads WHERE ParentID = @ParentID AND (CAST(ISNULL(NULLIF(@CountryCode1, ''), 1) AS NVARCHAR) + CAST(ISNULL(NULLIF(@MobileNo1, ''), 1) AS NVARCHAR) IN( SELECT Mobile FROM #temp )) )  
        BEGIN  
			--insert into @tbl_Response values('0', '-2', 'Lead with Mobile ' + @mobileno1 + ' already exists' );  
			insert into tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) values (@@SPID,'0', '-2', 'Lead with Mobile ' + @mobileno1 + ' already exists' );  
            GOTO LeadNotInserted;  
        END;  
  
        IF EXISTS (SELECT 1 FROM UserLeads WHERE ParentID = @ParentID AND (CAST(ISNULL(NULLIF(@CountryCode2, ''), 1) AS NVARCHAR) + CAST(ISNULL(NULLIF(@MobileNo2, ''), 1) AS NVARCHAR) IN ( SELECT Mobile FROM #temp )))  
        BEGIN  
			--insert into @tbl_Response values('0', '-2', 'Lead with Mobile ' + @mobileno2 + ' already exists' )  
			insert into tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) values (@@SPID,'0', '-2', 'Lead with Mobile ' + @mobileno2 + ' already exists' )  
            GOTO LeadNotInserted;  
        END;  
          
		IF EXISTS (SELECT 1 FROM UserLeads WHERE ParentID = @ParentID AND (CAST(ISNULL(NULLIF(@EmailID, ''), 1) AS NVARCHAR) IN ( SELECT email FROM #temp )))  
        BEGIN  
			--insert into @tbl_Response values('0', '-2', 'Lead with Email ' + @EmailID + ' already exists' )  
			insert into tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) values (@@SPID,'0', '-2', 'Lead with Email ' + @EmailID + ' already exists' )  
            GOTO LeadNotInserted;  
        END;  
          
		IF EXISTS (SELECT 1 FROM UserLeads WHERE ParentID = @ParentID AND (CAST(ISNULL(NULLIF(@EmailID1, ''), 1) AS NVARCHAR) IN ( SELECT email FROM #temp )))  
        BEGIN  
			--insert into @tbl_Response values('0', '-2', 'Lead with Email ' + @EmailID1 + ' already exists' )  
			insert into tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) values (@@SPID,'0', '-2', 'Lead with Email ' + @EmailID1 + ' already exists' )  
            GOTO LeadNotInserted;  
        END;  
          
		IF EXISTS (SELECT 1 FROM UserLeads WHERE ParentID = @ParentID AND (CAST(ISNULL(NULLIF(@EmailID2, ''), 1) AS NVARCHAR) IN ( SELECT email FROM #temp)))  
        BEGIN  
			--insert into @tbl_Response values('0', '-2', 'Lead with Email ' + @EmailID2 + ' already exists' )  
			insert into tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) values (@@SPID,'0', '-2', 'Lead with Email ' + @EmailID2 + ' already exists' )  
            GOTO LeadNotInserted;  
        END;  
          
		DECLARE @Leadno BIGINT= ISNULL((SELECT MAX(LeadNo) FROM UserLeads WHERE ParentID = @ParentID ), 0) + 1;  
        DECLARE @latitude FLOAT= NULL;  
        IF(ISNULL(@WhereLatitude, '') <> '')  
        BEGIN  
            SET @latitude = CAST(@WhereLatitude AS FLOAT);  
        END;  
          
		DECLARE @longitude FLOAT= NULL;  
        IF(ISNULL(@WhereLatitude, '') <> '')  
        BEGIN  
            SET @longitude = CAST(@WhereLongitude AS FLOAT);  
        END;  
  
        PRINT '@ParentID: ' + CAST(@ParentID AS VARCHAR);  
        PRINT '@LeadNo: ' + CAST(@LeadNo AS VARCHAR);  
        PRINT '@PersonName: ' + CAST(@PersonName AS VARCHAR);  
        PRINT '@CompanyName: ' + CAST(@CompanyName AS VARCHAR);  
        PRINT '@MobileNo: ' + CAST(@MobileNo AS VARCHAR);  
        PRINT '@MobileNo1: ' + CAST(@MobileNo1 AS VARCHAR);  
        PRINT '@MobileNo2: ' + CAST(@MobileNo2 AS VARCHAR);  
        PRINT '@EmailID: ' + CAST(@EmailID AS VARCHAR);  
        PRINT '@EmailID1: ' + CAST(@EmailID1 AS VARCHAR);  
        PRINT '@EmailID2: ' + CAST(@EmailID2 AS VARCHAR);  
        PRINT '@City: ' + CAST(@City AS VARCHAR);  
        PRINT '@State: ' + CAST(@State AS VARCHAR);  
        PRINT '@Country: ' + CAST(@Country AS VARCHAR);  
        PRINT '@CountryCode: ' + CAST(@CountryCode AS VARCHAR);  
        PRINT '@CountryCode1: ' + CAST(@CountryCode1 AS VARCHAR);  
        PRINT '@CountryCode2: ' + CAST(@CountryCode2 AS VARCHAR);  
        PRINT '@PinCode: ' + CAST(@PinCode AS VARCHAR);  
        PRINT '@ResidentialAddress: ' + CAST(@ResidentialAddress AS VARCHAR);  
        PRINT '@OfficialAddress: ' + CAST(@OfficialAddress AS VARCHAR);  
        PRINT '@SourceName: ' + CAST(@SourceName AS VARCHAR);  
        PRINT '@MediumName: ' + CAST(@MediumName AS VARCHAR);  
        PRINT '@CampaignName: ' + CAST(@CampaignName AS VARCHAR);  
        PRINT '@Remarks: ' + CAST(@Remarks AS VARCHAR);  
        PRINT '@CreatedBy: ' + CAST(@CreatedBy AS VARCHAR);  
        PRINT '@AssignedTo: ' + CAST(@AssignedTo AS VARCHAR);  
        PRINT '@FollowUpStatus: ' + CAST(@FollowUpStatus AS VARCHAR);  
        PRINT '@NextStatusDate: ' + CAST(@NextStatusDate AS VARCHAR);  
        PRINT '@Products: ' + CAST(@Products AS VARCHAR);  
        PRINT '@AmountPaid: ' + CAST(@AmountPaid AS VARCHAR);  
        PRINT '@FollowUpRemarks: ' + CAST(@FollowUpRemarks AS VARCHAR);  
        PRINT '@FollowupDate: ' + CAST(@FollowupDate AS VARCHAR);  
        PRINT '@WhereAddress: ' + CAST(@WhereAddress AS VARCHAR);  
        PRINT '@latitude: ' + CAST(@latitude AS VARCHAR);  
        PRINT '@longitude: ' + CAST(@longitude AS VARCHAR);  
		PRINT '@RefHistoryId: ' + CAST(@RefHistoryId AS VARCHAR);
		PRINT '@WorkFlowId: ' + CAST(@WorkFlowId AS VARCHAR);
          
		INSERT INTO UserLeads (ParentID, LeadNo, PersonName, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, City, 
		STATE, Country, CountryCode, CountryCode1, CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName,
		CampaignName, InitialRemarks, CreatedOn, CreatedBy, AssignedTo, FollowUpStatus, NextStatusDate, Products, AmountPaid, Remarks,
		FollowupDate, enquirysource, whereAddress, latitude, longitude)  
        VALUES (@ParentID,  @LeadNo, @PersonName, @CompanyName, @MobileNo, @MobileNo1, @MobileNo2, @EmailID, @EmailID1, @EmailID2, @City,
		@State, @Country, @CountryCode, @CountryCode1, @CountryCode2, @PinCode, @ResidentialAddress, @OfficialAddress, @SourceName,@MediumName,
		@CampaignName, @Remarks, GETDATE(), @CreatedBy, @AssignedTo, @FollowUpStatus, @NextStatusDate, @Products, @AmountPaid,@FollowUpRemarks,
		@FollowupDate, 12,   
  -- Manual Desktop Kit19                                            
         --@CreatedBy,                  
         -- 1,                                                
         -- cast(DATEPART(yyyy,getdate()) as nvarchar) +'-'+ RIGHT('00' + cast(DATEPART(dd,getdate()) as nvarchar(2)),2) +'-'+ RIGHT('00' + cast(DATEPART(MM,getdate()) as nvarchar(2)),2),                                                
         -- 'Lead Created'        
         @WhereAddress,  @latitude,  @longitude  
        );  
        SET @newlead = SCOPE_IDENTITY();  
        PRINT '@newlead: ' + CAST(@newlead AS VARCHAR);  
  
        --  AssignedTo,                                                
        --FollowUpStatus,                                                
        --NextStatusDate,                                            
        --Products ,                                            
        --AmountPaid  ,                                                 
        --Remarks                                             
  
        INSERT INTO LeadInteractionHistory ( [LeadNo], [FollowUpStatus], [NextStatusDate], [Remarks], [Products],  AmountPaid,  [AssignedTo],  [ParentID], [CreatedOn],  [CreatedBy],  FollowupDate )  
        SELECT @LeadNo, @FollowUpStatus, @NextStatusDate, @FollowUpRemarks, @Products, @AmountPaid, @AssignedTo,  
            --,cast(DATEPART(yyyy,getdate()) as nvarchar) +'-'+ RIGHT('00' + cast(DATEPART(dd,getdate()) as nvarchar(2)),2) +'-'+ RIGHT('00' + cast(DATEPART(MM,getdate()) as nvarchar(2)),2)                                                
            --,'Lead Created'                                                
            --,0                                                
            --,@createdby                                                 
            @ParentID, GETDATE(), @CreatedBy, @FollowupDate;  
  
        /* Start Lead activity Lead added  */  
  
        IF(ISNULL(@LeadTags, '') <> '')  
        BEGIN  
            DROP TABLE IF EXISTS #tempTagName;  
            SELECT tn.*, tm.ID AS tagId, 0 AS isProcess  
            INTO #tempTagName  
            FROM  
            (  
                SELECT [position] AS [id], LTRIM(RTRIM(IIF(CHARINDEX(':', [value], 1) = 0, [value], SUBSTRING([value], 1, CHARINDEX(':', [value], 1) - 1)))) AS [tagName]  
                FROM fn_Split(@LeadTags, ',')  
            ) AS tn  
            LEFT JOIN TagMaster(NOLOCK) AS tm ON tm.ParentID = @ParentID AND LOWER(tm.Tag) = LOWER(tagName);  

            WHILE(EXISTS (SELECT * FROM #tempTagName WHERE isProcess = 0))  
            BEGIN  
                DECLARE @tId INT, @tTagName NVARCHAR(255), @tagId BIGINT;  
                SELECT TOP 1 @tId = id, @tTagName = tagName, @tagId = tagId  
                FROM #tempTagName  
                WHERE isProcess = 0;  
                PRINT @tTagName;  
                IF(@tagId IS NULL)  
                BEGIN  
                    INSERT INTO TagMaster  
                    (Tag, ParentID, CreatedDate, CreatedBy)  
                    VALUES  
                    (@tTagName, @ParentID, GETDATE(), @CreatedBy);  
                    DECLARE @sId BIGINT= SCOPE_IDENTITY();  
                    UPDATE #tempTagName SET tagId = @sId WHERE id = @tId;  
                END;  
				UPDATE #tempTagName SET isProcess = 1 WHERE id = @tId;  
			END;  
			DELETE EntityTagMapping WHERE EntityID = @newlead AND LOWER(Entity) = 'lead';  
			INSERT INTO EntityTagMapping ( EntityID, Entity, TagID, CreatedDate )  
            SELECT @newlead, 'lead', tagId, GETDATE() FROM #tempTagName;  
		END;  
        BEGIN TRY  
            DECLARE @UserID_LDACTV BIGINT= @CreatedBy;  
            DECLARE @ParentID_LDACTV BIGINT= @ParentID;  
            DECLARE @LeadID_LDACTV BIGINT= @newlead;  
            CREATE TABLE #tblEventDescrb(EVNT_Description NVARCHAR(MAX));  
            IF(ISNULL(@LeadID_LDACTV, 0) > 0)  
            BEGIN  
                INSERT INTO #tblEventDescrb  
				EXEC Usp_EventTemplate_DynamicVarReplacement 'Lead added', @UserID_LDACTV, '', '', @LeadID_LDACTV, '', NULL, 0, 0, '', '', 0,
				'', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, NULL, 
				NULL, NULL, 0, NULL, NULL, NULL, 0, NULL, NULL;  
                DECLARE @evntMessage NVARCHAR(MAX)= '';  
                SELECT @evntMessage = ISNULL(EVNT_Description, '')  
                FROM #tblEventDescrb;  
                IF(@evntMessage <> '')  
                BEGIN  
                    EXEC usp_wf_SaveLeadActivity_withid  @LeadID_LDACTV, @UserID_LDACTV, @ParentID_LDACTV, @evntMessage,  'Lead added', 'UserLeads', @newlead, 'ID', @RefHistoryId, @WorkFlowId;  
                END;  
            END;  
        END TRY  
        BEGIN CATCH  
            EXEC usp_insertErrorInfo;  
        END CATCH;  
        IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence                
        BEGIN  
            DROP TABLE #tblEventDescrb;  
        END;  
  
        /* End Lead activity Lead added  */  
  
        DECLARE @insertcount SMALLINT;  
        SELECT @insertcount = ISNULL(COUNT(fieldID), 0)  
        FROM @custom;  
        IF(@insertcount > 0)  
        BEGIN  
            SELECT * INTO #temp29 FROM @custom;  
            UPDATE #temp29 SET LeadID = @newlead;  
            INSERT INTO customfieldLeadvalue ( LeadID, EnquiryID, fieldID, fieldvalue )  
            SELECT * FROM #temp29;  
            DROP TABLE #temp29;  
        END;  
          
		--insert into @tbl_Response values( cast(@LeadNo as nvarchar(50)), '1',  'success')  
		insert into tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) values (@@SPID, cast(@LeadNo as nvarchar(50)), '1',  'success')  
        LeadNotInserted:                                         
        --SELECT SCOPE_IDENTITY() AS [leadid];                   
  
        PRINT '-------------END---------------------- usp_wf_Insert_Lead_Details_ChangeWithFollowupDate2 --------------------------------';  
 END TRY  
 BEGIN CATCH  
  EXEC usp_InsertErrorInfo  
  --insert into @tbl_Response values( '0', '-1',  ERROR_MESSAGE())  
  insert into tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) values (@@SPID, '0', '-1',  ERROR_MESSAGE())  
 END CATCH  
 --select * from @tbl_Response   
 select * from tbl_wf_WorkflowResponse   
END;  



GO

/* ============================================================
   Procedure: [dbo].[usp_wf_IntindSMSFromLeads_New1_WithDLTTemplateID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Action Code => ( SMS_TO_LD, SMS_TO_ASG, SMS_TO_CRE )  
CREATE   PROCEDURE usp_wf_IntindSMSFromLeads_New1_WithDLTTemplateID  
(@ID            VARCHAR(500),   
 @Account       BIGINT,   
 @SenderID      VARCHAR(50),   
 @Message       NVARCHAR(4000),   
 @IsUnicode     BIT,   
 @Mobile        BIT,   
 @mobile1       BIT,   
 @Mobile2       BIT,   
 @DLTTemplateID NVARCHAR(200),   
 @UserId        BIGINT = 0,   
 @RefHistoryId  BIGINT = 0,
 @WorkFlowId	BIGINT = null
)  
AS  
BEGIN  
    -- DECLARE @tbl_Response AS TBL_RESPONSE;  
    BEGIN TRY  
        -- BatchID -- this column value is auto-generated                                                      
  
        PRINT '----------BEGIN------------------- usp_wf_IntindSMSFromLeads_New1_WithDLTTemplateID ---------------------------------';  
        PRINT '@ID: ' + CAST(@ID AS VARCHAR);  
        PRINT '@Account: ' + CAST(@Account AS VARCHAR);  
        PRINT '@SenderID: ' + CAST(@SenderID AS VARCHAR);  
        PRINT '@Message: ' + CAST(@Message AS VARCHAR);  
        PRINT '@IsUnicode: ' + CAST(@IsUnicode AS VARCHAR);  
        PRINT '@Mobile: ' + CAST(@Mobile AS VARCHAR);  
        PRINT '@mobile1: ' + CAST(@mobile1 AS VARCHAR);  
        PRINT '@Mobile2: ' + CAST(@Mobile2 AS VARCHAR);  
        PRINT '@DLTTemplateID: ' + CAST(@DLTTemplateID AS VARCHAR);  
        PRINT '@UserId: ' + CAST(@UserId AS VARCHAR);  
        PRINT '@RefHistoryId: ' + CAST(@RefHistoryId AS VARCHAR); 
        PRINT '@WorkFlowId: ' + CAST(isnull(@WorkFlowId,'') AS VARCHAR); 
		
        DECLARE @BatchID BIGINT;  
        BEGIN TRAN;  
        INSERT INTO GetBatchRecord  
        ([User_id],   
            RandNum  
        )  
        VALUES  
        (@Account,   
            @Account  
        );  
        SELECT @BatchID = SCOPE_IDENTITY();  
        DELETE FROM GetBatchRecord  
        WHERE batchid = @batchid;  
        COMMIT;  
        CREATE TABLE #tmpflint  
        ([BatchID]                     [BIGINT] NULL,   
            [Country_code]                [VARCHAR](10) NULL,   
            [Mobile]                      [VARCHAR](20) NULL,   
            [Message]                     [NVARCHAR](2500) NULL,   
            [MessageStatus]               [VARCHAR](20) NULL,   
            [SenderID]                    [NCHAR](40) NULL,   
            [MessageInsertDate]           [DATETIME] NULL,   
            [ScheduledDate]               [VARCHAR](50) NULL,   
            [ScheduledTime]               [VARCHAR](50) NULL,   
            [SmppID]                      [TINYINT] NULL,   
            [U_ID]                        [INT] NULL,   
            [IsUniCode]                   [BIT] NULL,   
            [IsDnd]                       [BIT] NULL,   
            [IsAirtel]                    [BIT] NULL,   
            [MobileSubSet]                [BIGINT] NULL,   
            [ValidNo]                     [TINYINT] NULL,   
            [IsPrority]                   [TINYINT] NULL,   
            [IsAllowDND]                  [TINYINT] NULL,   
            [DBType]                      [NCHAR](10) NULL,   
            [campaignid]                  [BIGINT] NULL,   
            [Processed]                   [INT] NULL,   
            [Hasvirtualcredits]           [INT] NULL,   
            [HasSufficientvirtualcredits] [INT] NULL,   
            [price]                       [FLOAT] NULL  
        );                                
        --drop table #tmpflind                                
        CREATE TABLE #tmpflind  
        ([BatchID]           [BIGINT] NULL,   
            [Country_code]      [VARCHAR](10) NULL,   
            [Mobile]            [VARCHAR](20) NULL,   
            [Message]           [NVARCHAR](2500) NULL,   
            [MessageStatus]     [VARCHAR](20) NULL,   
            [SenderID]          [NCHAR](40) NULL,   
            [MessageInsertDate] [DATETIME] NULL,   
            [ScheduledDate]     [VARCHAR](50) NULL,   
            [ScheduledTime]     [VARCHAR](50) NULL,   
            [SmppID]            [TINYINT] NULL,   
            [U_ID]              [INT] NULL,   
            [IsUniCode]         [BIT] NULL,   
            [IsDnd]             [BIT] NULL,   
            [IsAirtel]          [BIT] NULL,   
            [MobileSubSet]      [BIGINT] NULL,   
            [ValidNo]           [TINYINT] NULL,   
            [IsPrority]         [TINYINT] NULL,   
            [IsAllowDND]        [TINYINT] NULL,   
            [DBType]            [NCHAR](10) NULL,   
            [LeadId]            [BIGINT], --,                                
        --[campaignid] [bigint] NULL,                                
        --[Processed] [int] NULL,                                
        --[Hasvirtualcredits] [int] NULL,                                
        --[HasSufficientvirtualcredits] [int] NULL                                
        );  
        DECLARE @Uccode VARCHAR(20);  
        SELECT TOP 1 @Uccode = ISNULL(CountryCode, '+91') FROM User_Detail AS ud WHERE ud.[User_ID] = @Account;  
        INSERT INTO #tmpflind  
        (BatchID, Mobile, Country_Code, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID,
		 U_ID, IsUnicode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType, LeadId)  
        SELECT BatchID, Mobile, CountryCode, Messagetext, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID,
		U_ID, IsUnicode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType, LeadId  
        FROM  
        (  
            SELECT @BatchID AS BatchID,  
                    CASE WHEN @Mobile = 1 THEN ISNULL(NULLIF(ue.MobileNo, ''), '0') ELSE '0' END AS Mobile,  
                    CASE WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode, '') ELSE '' END AS CountryCode,   
                    dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo) AS Messagetext, NULL AS MessageStatus, @SenderID AS SenderID,   
                    GETDATE() AS MessageInsertDate, NULL AS ScheduledDate, NULL AS ScheduledTime,   
					(SELECT TOP 1 ud.SmppID  FROM User_Detail AS ud WHERE ud.[User_ID] = @Account) AS SmppID,   
                    @Account AS U_ID, @IsUnicode AS IsUnicode, 0 AS IsDnd, 0 AS IsAirtel, 0 AS MobileSubSet, 1 AS ValidNo, 1 AS IsPrority,   
                    0 AS IsAllowDND, 0 AS DBType, ue.ID AS LeadId  
            FROM UserLeads AS ue  
            WHERE ue.ID = @ID AND ISNULL(NULLIF(ue.MobileNo, ''), '') <> '' AND ISNULL(NULLIF(ue.MobileNo, ''), '') NOT IN (  
                SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo  
                FROM UserLeads AS UETemp INNER JOIN Client_UnSubscribeDetails AS C_UDTemp
				ON	(UeTemp.MobileNo = C_UDTemp.Mobile AND UETemp.CountryCode = C_UDTemp.CountryCode AND C_UDTemp.ParentId = UETemp.ParentID)  
                WHERE UE.ID = @ID  
            )  
            UNION  
            SELECT @BatchID, CASE WHEN @mobile1 = 1 THEN ISNULL(NULLIF(ue.MobileNo1, ''), '0') ELSE '0' END AS Mobile,  
                    CASE WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode, '') ELSE '' END AS CountryCode,   
                    dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo1),  NULL AS MessageStatus, @SenderID, GETDATE(), NULL, NULL,   
					(SELECT TOP 1 ud.SmppID FROM User_Detail AS ud WHERE ud.[User_ID] = @Account),   
                    @Account, @IsUnicode, 0, 0, 0, 1, 1, 0, 0, ue.ID AS LeadId  
            FROM UserLeads AS ue  
            WHERE ue.ID = @ID AND ISNULL(NULLIF(ue.MobileNo1, ''), '') <> '' AND ISNULL(NULLIF(ue.MobileNo1, ''), '') NOT IN  
            (SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo1
			 FROM UserLeads AS UETemp INNER JOIN Client_UnSubscribeDetails AS C_UDTemp 
			 ON	(UeTemp.MobileNo1 = C_UDTemp.Mobile AND UETemp.CountryCode1 = C_UDTemp.CountryCode AND C_UDTemp.ParentId = UETemp.ParentID)
			 WHERE UE.ID = @ID  
            )  
            UNION  
            SELECT @BatchID, CASE WHEN @Mobile2 = 1 THEN ISNULL(NULLIF(ue.MobileNo2, ''), '0') ELSE '0' END AS Mobile,  
                    CASE WHEN @Mobile = 1 THEN ISNULL(ue.CountryCode, '') ELSE '' END AS CountryCode,   
                    dbo.fn_getLeadsMessage(ue.ParentID, @Message, ue.MobileNo2), NULL AS MessageStatus, @SenderID, GETDATE(), NULL, NULL,   
					(SELECT TOP 1 ud.SmppID  FROM User_Detail AS ud WHERE ud.[User_ID] = @Account),   
                    @Account, @IsUnicode, 0, 0, 0, 1, 1, 0, 0, ue.ID AS LeadId  
            FROM UserLeads AS ue  
            WHERE ue.ID = @ID AND ISNULL(NULLIF(ue.MobileNo2, ''), '') <> '' AND ISNULL(NULLIF(ue.MobileNo2, ''), '') NOT IN  
            (  SELECT ISNULL(C_UDTemp.Mobile, '') AS MobileNo2  
               FROM UserLeads AS UETemp INNER JOIN Client_UnSubscribeDetails AS C_UDTemp
			   ON	(UeTemp.MobileNo2 = C_UDTemp.Mobile AND UETemp.CountryCode2 = C_UDTemp.CountryCode AND C_UDTemp.ParentId = UETemp.ParentID)
               WHERE UE.ID = @ID  
            )  
        ) AS A  
        WHERE A.Mobile <> '0';  
        IF @Uccode = '+91'  
        BEGIN  
            INSERT INTO #tmpflint  
            (BatchID, Country_code, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID,
			 U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType)  
            SELECT BatchID, Country_code, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, 
			U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType  
            FROM #tmpflind  
            WHERE Country_Code <> '+91';  
            DELETE FROM #tmpflind  
            WHERE Country_Code <> '+91';  
		END;  
        ELSE  
        BEGIN  
            INSERT INTO #tmpflint  
            (BatchID, Country_code, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID,
			 U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType)  
            SELECT BatchID, Country_code, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, 
			U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType  
            FROM #tmpflind;  
		END;  
        DECLARE @NoOfSMS BIGINT= 0, @intsms BIGINT= 0;  
        SELECT @intsms = COUNT(*) FROM #tmpflint;  
        DECLARE @intprc INT= 0, @indprc INT= 0;  
        IF @intsms > 0  
        BEGIN  
            UPDATE #tmpflint SET price = (CASE  
                                WHEN IsUniCode = 0 AND LEN(message) <= 160  
                                THEN 1  
                                WHEN IsUniCode = 0 AND LEN(message) > 160  
                                THEN CEILING(LEN(message) / CAST(153 AS FLOAT))  
                                WHEN IsUniCode = 1 AND LEN(message) <= 70  
                                THEN 1  
                                ELSE CEILING(LEN(message) / CAST(67 AS FLOAT))  
                            END) *  
            (  
                SELECT price FROM dbo.IntSMSRateMast WHERE country_code = #tmpflint.country_code  
            );  
            DECLARE @Cr_amt FLOAT, @balance FLOAT;  
            SELECT @Cr_amt = SUM(price)  
            FROM #tmpflint;  
            SELECT TOP 1 @balance = Balance  
            FROM dbo.IntCredit_Details  
            WHERE USER_ID = @Account;  
            IF @balance < @Cr_amt  
                BEGIN  
                    SET @intprc = 1;  
            END;  
		END;  
        IF @intprc = 0  
        BEGIN  
            SELECT @NoOfSMS = COUNT(*)  
            FROM #tmpflind;  
            IF @NoOfSMS > 0  
            BEGIN  
                DECLARE @CurrentBalance BIGINT=  
                (  
                    SELECT TOP 1 ISNULL(cd.Balance, 0)  
                    FROM Credit_Details AS cd(NOLOCK)  
                    WHERE cd.[User_ID] = @Account  
                    ORDER BY cd.Credit_ID DESC  
                );  
                DECLARE @mBalance BIGINT= @CurrentBalance - @NoOfSMS;  
                IF @mBalance >= 0  
                BEGIN  
                    INSERT INTO CloneMessageDeliveryStatus  
                    (BatchID, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, 
					 ScheduledTime, SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, 
					 DBType, sms_source)  
                    SELECT BatchID, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ISNULL(ScheduledDate, ''), 
					ISNULL(ScheduledTime, ''), SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND,
					DBType, 'Mass Send Lead'
					FROM #tmpflind;  
                    BEGIN TRY  
                        EXEC Usp_Save_DLTTemplateID_with_BatchID @batchid, @DLTTemplateID;  
					END TRY  
                    BEGIN CATCH  
                        EXEC usp_InsertErrorInfo;  
					END CATCH;  
				END;  
                ELSE  
                BEGIN  
                    SET @indprc = 1;  
                END;  
			END;  
        END;    
        IF @intprc = 0 AND @indprc = 0  
        BEGIN  
            IF(@UserId > 0)  
            BEGIN  
                DECLARE @leadActivityHistory AS LEADACTIVITYWITHID_TBLTYPE;  
                DECLARE @Username NVARCHAR(255), @ParentId BIGINT= 0;  

                SELECT @Username = User_Login, @ParentId = ParentID  
                FROM User_Detail(NOLOCK)  
                WHERE User_Id = @UserId;  
                        
				INSERT INTO @leadActivityHistory  
                (LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid)  
                SELECT leadid, @UserId, @parentid, concat(@Username, ' sent an sms with content ', Message, ' on mobile ', Mobile), 'SMS sent to lead', 'Batchinfo', @BatchID  
				FROM #tmpflind;  
                        
				EXEC usp_wf_SaveLeadActivity_withMultipleValue_withid @leadActivityHistory, 'BatchID', @RefHistoryId, @WorkFlowId;  
            END;  
            --INSERT INTO @tbl_Response VALUES('0', '1', 'success');  
            INSERT INTO tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) VALUES(@@SPID,'0', '1', 'success');  
        END;  
        ELSE  
        BEGIN  
            --INSERT INTO @tbl_Response VALUES('0', '-1', 'Insufficient Balance');  
            insert into tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) VALUES(@@SPID, '0', '-1', 'Insufficient Balance');  
        END;  
        PRINT '----------END------------------- usp_wf_IntindSMSFromLeads_New1_WithDLTTemplateID ---------------------------------';  
    END TRY  
    BEGIN CATCH  
        EXEC usp_InsertErrorInfo;  
        --INSERT INTO @tbl_Response VALUES ('0', '-1', ERROR_MESSAGE());  
        INSERT INTO tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) VALUES (@@SPID, '0', '-1', ERROR_MESSAGE());  
    END CATCH;  
    --select * from @tbl_Response;  
    select * from tbl_wf_WorkflowResponse;  
END  



GO

/* ============================================================
   Procedure: [dbo].[usp_wf_IntindSMSFromLeads_New1_WithDLTTemplateIDToUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Action Code => (SMS_TO_ASG, SMS_TO_CRE )    
CREATE   PROCEDURE usp_wf_IntindSMSFromLeads_New1_WithDLTTemplateIDToUser    
(@ActionCode varchar(10),
 @ID            VARCHAR(500),     
 @Account       BIGINT,     
 @SenderID      VARCHAR(50),     
 @Message       NVARCHAR(4000),     
 @IsUnicode     BIT,     
 @Mobile        BIT,     
 @mobile1       BIT,     
 @Mobile2       BIT,     
 @DLTTemplateID NVARCHAR(200),     
 @UserId        BIGINT = 0,     
 @RefHistoryId  BIGINT = 0,  
 @WorkFlowId BIGINT = null  
)    
AS    
BEGIN    
    -- DECLARE @tbl_Response AS TBL_RESPONSE;    
    BEGIN TRY    
        -- BatchID -- this column value is auto-generated                                                        
    
        PRINT '----------BEGIN------------------- usp_wf_IntindSMSFromLeads_New1_WithDLTTemplateIDToUser ---------------------------------';    
        PRINT '@ActionCode: ' + CAST(@ActionCode AS VARCHAR);    
        PRINT '@ID: ' + CAST(@ID AS VARCHAR);    
        PRINT '@Account: ' + CAST(@Account AS VARCHAR);    
        PRINT '@SenderID: ' + CAST(@SenderID AS VARCHAR);    
        PRINT '@Message: ' + CAST(@Message AS VARCHAR);    
        PRINT '@IsUnicode: ' + CAST(@IsUnicode AS VARCHAR);    
        PRINT '@Mobile: ' + CAST(@Mobile AS VARCHAR);    
        PRINT '@mobile1: ' + CAST(@mobile1 AS VARCHAR);    
        PRINT '@Mobile2: ' + CAST(@Mobile2 AS VARCHAR);    
        PRINT '@DLTTemplateID: ' + CAST(@DLTTemplateID AS VARCHAR);    
        PRINT '@UserId: ' + CAST(@UserId AS VARCHAR);    
        PRINT '@RefHistoryId: ' + CAST(@RefHistoryId AS VARCHAR);   
        PRINT '@WorkFlowId: ' + CAST(isnull(@WorkFlowId,'') AS VARCHAR);   
    
        DECLARE @BatchID BIGINT;    
        BEGIN TRAN;    
        INSERT INTO GetBatchRecord    
        ([User_id],     
            RandNum    
        )    
        VALUES    
        (@Account,     
            @Account    
        );    
        SELECT @BatchID = SCOPE_IDENTITY();    
        DELETE FROM GetBatchRecord    
        WHERE batchid = @batchid;    
        COMMIT;    
        CREATE TABLE #tmpflint    
        ([BatchID]                     [BIGINT] NULL,     
            [Country_code]                [VARCHAR](10) NULL,     
            [Mobile]                      [VARCHAR](20) NULL,     
            [Message]                     [NVARCHAR](2500) NULL,     
            [MessageStatus]               [VARCHAR](20) NULL,     
            [SenderID]                    [NCHAR](40) NULL,     
            [MessageInsertDate]           [DATETIME] NULL,     
            [ScheduledDate]               [VARCHAR](50) NULL,     
            [ScheduledTime]               [VARCHAR](50) NULL,     
            [SmppID]                      [TINYINT] NULL,     
            [U_ID]                        [INT] NULL,     
            [IsUniCode]                   [BIT] NULL,     
            [IsDnd]                       [BIT] NULL,     
            [IsAirtel]                    [BIT] NULL,     
            [MobileSubSet]                [BIGINT] NULL,     
            [ValidNo]                     [TINYINT] NULL,     
            [IsPrority]                   [TINYINT] NULL,     
            [IsAllowDND]                  [TINYINT] NULL,     
            [DBType]                      [NCHAR](10) NULL,     
            [campaignid]                  [BIGINT] NULL,     
            [Processed]                   [INT] NULL,     
            [Hasvirtualcredits]           [INT] NULL,     
            [HasSufficientvirtualcredits] [INT] NULL,     
            [price]                       [FLOAT] NULL    
        );                                  
        --drop table #tmpflind                                  
        CREATE TABLE #tmpflind    
        ([BatchID]           [BIGINT] NULL,     
            [Country_code]      [VARCHAR](10) NULL,     
            [Mobile]            [VARCHAR](20) NULL,     
            [Message]           [NVARCHAR](2500) NULL,     
            [MessageStatus]     [VARCHAR](20) NULL,     
            [SenderID]          [NCHAR](40) NULL,     
            [MessageInsertDate] [DATETIME] NULL,     
            [ScheduledDate]     [VARCHAR](50) NULL,     
            [ScheduledTime]     [VARCHAR](50) NULL,     
            [SmppID]            [TINYINT] NULL,     
            [U_ID]              [INT] NULL,     
            [IsUniCode]         [BIT] NULL,     
            [IsDnd]             [BIT] NULL,     
            [IsAirtel]          [BIT] NULL,     
            [MobileSubSet]      [BIGINT] NULL,     
            [ValidNo]           [TINYINT] NULL,     
            [IsPrority]         [TINYINT] NULL,     
            [IsAllowDND]        [TINYINT] NULL,     
            [DBType]            [NCHAR](10) NULL,     
            [LeadId]            [BIGINT], --,                                  
        --[campaignid] [bigint] NULL,                                  
        --[Processed] [int] NULL,                                  
        --[Hasvirtualcredits] [int] NULL,                                  
        --[HasSufficientvirtualcredits] [int] NULL                                  
        );    
        DECLARE @Uccode VARCHAR(20);    
        SELECT TOP 1 @Uccode = ISNULL(CountryCode, '+91') FROM User_Detail AS ud WHERE ud.[User_ID] = @Account;    
        INSERT INTO #tmpflind    
        (BatchID, Mobile, Country_Code, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, U_ID, IsUnicode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType, LeadId)    
        SELECT BatchID, Mobile, CountryCode, Messagetext, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, U_ID, IsUnicode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType, LeadId    
        FROM    
        (    
            SELECT @BatchID AS BatchID, cast(UD.Mobile as numeric(18,0)) as Mobile, UD.CountryCode,     
                    dbo.fn_getLeadsUserMessage(ue.ID, ue.ParentID, @Message) AS Messagetext, NULL AS MessageStatus, @SenderID AS SenderID, GETDATE() AS MessageInsertDate, NULL AS ScheduledDate, NULL AS ScheduledTime,
					(SELECT TOP 1 ud.SmppID  FROM User_Detail AS ud WHERE ud.[User_ID] = @Account) AS SmppID,     
                    @Account AS U_ID, @IsUnicode AS IsUnicode, 0 AS IsDnd, 0 AS IsAirtel, 0 AS MobileSubSet, 1 AS ValidNo, 1 AS IsPrority, 0 AS IsAllowDND, 0 AS DBType, ue.ID AS LeadId    
            FROM UserLeads(nolock) ue inner join User_Detail(nolock) UD
			On iif(@ActionCode = 'SMS_TO_ASG',ue.AssignedTo,ue.createdBy)=UD.User_ID
            WHERE ue.ID = @ID 
        ) AS A    
        WHERE A.Mobile <> '0';    

        IF @Uccode = '+91'    
        BEGIN    
            INSERT INTO #tmpflint    
            (BatchID, Country_code, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType)    
            SELECT BatchID, Country_code, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType   
            FROM #tmpflind    
            WHERE Country_Code <> '+91';    

            DELETE FROM #tmpflind    
            WHERE Country_Code <> '+91';    
		END;    
        ELSE    
        BEGIN    
            INSERT INTO #tmpflint    
            (BatchID, Country_code, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType)    
            SELECT BatchID, Country_code, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate, ScheduledTime, SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND, DBType
            FROM #tmpflind;    
		END;    

        DECLARE @NoOfSMS BIGINT= 0, @intsms BIGINT= 0;    
        SELECT @intsms = COUNT(*) FROM #tmpflint;    
        DECLARE @intprc INT= 0, @indprc INT= 0;    
        IF @intsms > 0    
        BEGIN    
            UPDATE #tmpflint SET price = (CASE    
                                WHEN IsUniCode = 0 AND LEN(message) <= 160    
                                THEN 1    
                                WHEN IsUniCode = 0 AND LEN(message) > 160    
                                THEN CEILING(LEN(message) / CAST(153 AS FLOAT))    
                                WHEN IsUniCode = 1 AND LEN(message) <= 70    
                                THEN 1    
                                ELSE CEILING(LEN(message) / CAST(67 AS FLOAT))    
                            END) *    
            (    
                SELECT price FROM dbo.IntSMSRateMast WHERE country_code = #tmpflint.country_code    
            );    
            DECLARE @Cr_amt FLOAT, @balance FLOAT;    
            SELECT @Cr_amt = SUM(price)    
            FROM #tmpflint;    
            SELECT TOP 1 @balance = Balance    
            FROM dbo.IntCredit_Details    
            WHERE USER_ID = @Account;    
            IF @balance < @Cr_amt    
            BEGIN    
                SET @intprc = 1;    
            END;    
		END;    

        IF @intprc = 0    
        BEGIN    
            SELECT @NoOfSMS = COUNT(*)    
            FROM #tmpflind;    
            IF @NoOfSMS > 0    
            BEGIN    
                DECLARE @CurrentBalance BIGINT=    
                (   
                    SELECT TOP 1 ISNULL(cd.Balance, 0)    
                    FROM Credit_Details AS cd(NOLOCK)    
                    WHERE cd.[User_ID] = @Account    
                    ORDER BY cd.Credit_ID DESC    
                );    
                DECLARE @mBalance BIGINT= @CurrentBalance - @NoOfSMS;    
                IF @mBalance >= 0    
                BEGIN    
                    INSERT INTO CloneMessageDeliveryStatus    
                    (BatchID, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ScheduledDate,   
					ScheduledTime, SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority, IsAllowDND,   
					DBType, sms_source)    
                    SELECT BatchID, Mobile, Message, MessageStatus, SenderID, MessageInsertDate, ISNULL(ScheduledDate, ''),   
					ISNULL(ScheduledTime, ''), SmppID, U_ID, IsUniCode, IsDnd, IsAirtel, MobileSubSet, ValidNo, IsPrority,
					IsAllowDND, DBType, 'Mass Send Lead'  
					FROM #tmpflind;    

                    BEGIN TRY    
                        EXEC Usp_Save_DLTTemplateID_with_BatchID @batchid, @DLTTemplateID;    
					END TRY    
                    BEGIN CATCH    
                        EXEC usp_InsertErrorInfo;    
					END CATCH;    
				END;    
                ELSE    
                BEGIN    
                    SET @indprc = 1;    
                END;    
			END;    
        END;      
        IF @intprc = 0 AND @indprc = 0    
        BEGIN    
            IF(@UserId > 0)    
            BEGIN    
                DECLARE @leadActivityHistory AS LEADACTIVITYWITHID_TBLTYPE;    
                DECLARE @Username NVARCHAR(255), @ParentId BIGINT= 0;    
  
                SELECT @Username = User_Login, @ParentId = ParentID    
                FROM User_Detail(NOLOCK)    
                WHERE User_Id = @UserId;    
                          
    INSERT INTO @leadActivityHistory    
                (LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid)    
                SELECT leadid, @UserId, @parentid, concat(@Username, ' sent an sms with content ', Message, ' on mobile ', Mobile), 'SMS sent to lead', 'Batchinfo', @BatchID    
    FROM #tmpflind;    
                          
    EXEC usp_wf_SaveLeadActivity_withMultipleValue_withid @leadActivityHistory, 'BatchID', @RefHistoryId, @WorkFlowId;    
            END;    
            --INSERT INTO @tbl_Response VALUES('0', '1', 'success');    
            INSERT INTO tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) VALUES(@@SPID,'0', '1', 'success');    
        END;    
        ELSE    
        BEGIN    
            --INSERT INTO @tbl_Response VALUES('0', '-1', 'Insufficient Balance');    
            insert into tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) VALUES(@@SPID, '0', '-1', 'Insufficient Balance');    
        END;    
        PRINT '----------END------------------- usp_wf_IntindSMSFromLeads_New1_WithDLTTemplateIDToUser ---------------------------------';    
    END TRY    
    BEGIN CATCH    
        EXEC usp_InsertErrorInfo;    
        --INSERT INTO @tbl_Response VALUES ('0', '-1', ERROR_MESSAGE());    
        INSERT INTO tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) VALUES (@@SPID, '0', '-1', ERROR_MESSAGE());    
    END CATCH;    
    --select * from @tbl_Response;    
    select * from tbl_wf_WorkflowResponse;    
END    



