/* ============================================================
   Procedure: [dbo].[usp_wf_job_FillProcessInitWorkflow]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_wf_job_FillProcessInitWorkflow      
(      
 @BatchSize int=50      
)      
AS      
BEGIN      
      
 -- declare @BatchSize int=50      
 Declare @LowerBound bigint=1591366, @UpperBound bigint      
 Select @UpperBound=max(HistoryId) From tbl_wf_WorkflowProcessInitMaster(nolock)      
      
 set @UpperBound=case When isnull(@UpperBound,@LowerBound) > @LowerBound then isnull(@UpperBound,@LowerBound) else @LowerBound end      
      
 insert into tbl_wf_WorkflowProcessInitMaster(HistoryId, UserId, ParentId, LeadId, EventId, reftables, refids, refColName, EventDate, [Status], refHistoryId, WorkflowId, StageId, SequenceNo)      
 select top (@BatchSize)  LEH.HistoryId,LEH.UserId,LEH.ParentId,LEH.LeadId,LEH.EventId,LEH.reftables,LEH.refids,LEH.refColName,LEH.EventDate,'raw' as Status, LEH.refHistoryId, WM.WorkflowId, WSM.StageId, WSM.SequenceNo      
 From tbl_LeadEventHistory(nolock) LEH inner join tbl_wf_WorkflowMaster(nolock) WM      
 on  LEH.ParentID=WM.ParentId and WM.IsActive=1 inner join tbl_wf_WorkflowStageMaster(nolock) WSM      
 on WM.WorkflowId=WSM.WorkflowId and WSM.SequenceNo=1 and LEH.EventID=WSM.TriggerId      
 Where  LEH.Historyid > @UpperBound --and LEH.RefHistoryId is null      
 union      
 select top (@BatchSize) LEH.HistoryId,LEH.UserId,LEH.ParentId,LEH.LeadId,LEH.EventId,LEH.reftables,LEH.refids,LEH.refColName,LEH.EventDate,'invoked' as Status, LEH.refHistoryId, WM.WorkflowId, WSM.StageId, WSM.SequenceNo      
 From tbl_LeadEventHistory(nolock) LEH inner join tbl_wf_WorkflowMaster(nolock) WM      
 on  LEH.ParentID=WM.ParentId and LEH.WorkflowId=WM.WorkflowId and WM.IsActive=1 inner join (SELECT WSM.StageId, WSM.StageName, WSM.SequenceNo, WSM.WorkflowId, WSM.StageType, WSM.ActionCode, WAM.EventId FROM tbl_wf_WorkflowStageMaster AS WSM WITH (nolock) INNER JOIN tbl_wf_WorkflowActionMaster AS WAM WITH (nolock) ON WSM.ActionCode = WAM.ActionCode) WSM
 on WM.WorkflowId=WSM.WorkflowId and LEH.EventID=WSM.EventID and WSM.SequenceNo > 1      
 Where LEH.Historyid > @UpperBound and LEH.RefHistoryId is not null      
 order by 1, 12, 14       
            
END      



GO

/* ============================================================
   Procedure: [dbo].[usp_wf_job_FillProcessWorkflow]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_wf_job_FillProcessWorkflow
CREATE   PROC usp_wf_job_FillProcessWorkflow
(
	@BatchSize int=20
)
AS
BEGIN

	-- declare @BatchSize int=20
	Declare @LowerBound bigint=1247192, @UpperBound bigint

	Select @UpperBound=max(HistoryId) From tbl_wf_WorkflowProcessMaster(nolock)

	set @UpperBound=case When isnull(@UpperBound,@LowerBound) > @LowerBound then isnull(@UpperBound,@LowerBound) else @LowerBound end

	insert into tbl_wf_WorkflowProcessMaster(HistoryId,UserId,ParentId,LeadId,EventId,reftables,refids,refColName,EventDate,Status,refHistoryId)
	select top (@BatchSize) LEH.HistoryId,LEH.UserId,LEH.ParentId,LEH.LeadId,LEH.EventId,LEH.reftables,LEH.refids,LEH.refColName,LEH.EventDate,'raw' as Status, LEH.refHistoryId
	From tbl_LeadEventHistory(nolock) LEH inner join tbl_wf_WorkflowMaster(nolock) WM
	on	 LEH.ParentID=WM.ParentId and WM.IsActive=1 inner join tbl_wf_WorkflowStageMaster(nolock) WSM
	on	WM.WorkflowId=WSM.WorkflowId and WSM.SequenceNo=1 and LEH.EventID=WSM.TriggerId
	Where LEH.Historyid > @UpperBound and LEH.RefHistoryId is null
	union 
	select top (@BatchSize) LEH.HistoryId,LEH.UserId,LEH.ParentId,LEH.LeadId,LEH.EventId,LEH.reftables,LEH.refids,LEH.refColName,LEH.EventDate,'raw' as Status, LEH.refHistoryId
	From tbl_LeadEventHistory(nolock) LEH inner join tbl_wf_WorkflowMaster(nolock) WM
	on	 LEH.ParentID=WM.ParentId and WM.IsActive=1
	Where LEH.Historyid > @UpperBound and LEH.RefHistoryId is not null

END



GO

/* ============================================================
   Procedure: [dbo].[usp_wf_job_ProcessWorkflow]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_wf_job_ProcessWorkflow
CREATE   PROC usp_wf_job_ProcessWorkflow
(
	@BatchSize int=20
)
AS
BEGIN

	Declare @LowerBound bigint=0, @RowId int=1, @RowCnt int=0

	select @LowerBound=min(HistoryID) From tbl_wf_WorkflowProcessMaster(nolock)
	Where [Status] not in ('finished','notfound','failed') and StageId is null

	if object_id('tempdb..#tblWPId') is not null begin drop table #tblWPId end

	Create table #tblWPId
	(
		Row_Id int identity(1,1),
		HistoryID bigint
	)

	insert into #tblWPId
	select top(@BatchSize) HistoryId From tbl_wf_WorkflowProcessMaster(nolock) Where HistoryID >= @LowerBound and [Status] not in ('finished','notfound','failed') and StageId is null

	select @RowCnt=count(*) From #tblWPId

	While(@RowId <= @RowCnt)
	Begin
		Select @LowerBound=HistoryID From #tblWPId Where Row_Id=@RowId

		Exec usp_wf_ProcessWorkflow @LowerBound

		Set @RowId=@RowId+1
	End
END



GO

/* ============================================================
   Procedure: [dbo].[usp_wf_ProcessInitWorkflow]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_wf_ProcessInitWorkflow 3
CREATE   PROC [dbo].[usp_wf_ProcessInitWorkflow]
(
	@WProcessId BIGINT
)
AS
BEGIN
	--declare @WProcessId bigint=15671  
	DECLARE @Row_Id BIGINT=1, @EventId BIGINT, @UserId BIGINT, @LeadId BIGINT, @RefId BIGINT, 
			@reftables NVARCHAR(1000), @Row_Cnt BIGINT=0, @LastStageStatus VARCHAR(10)= '', @WorkflowId BIGINT,
			@ParentId BIGINT, @refColName VARCHAR(100), @ConditionExpr VARCHAR(1000)= '', @RefHistoryId BIGINT,
			@EventDate DATETIME, @LastStageId BIGINT= 0, @ExecStartDate DATETIME= GETDATE();
	DECLARE @StageRow_Id INT= 1, @StageRow_Cnt INT= 0, @StageId BIGINT, @SequenceNo INT, @StageType VARCHAR(2), 
			@ActionCode VARCHAR(10), @Webhook VARCHAR(500), @ScheduledAfterHrs VARCHAR(50), 
			@ScheduledHrsType varchar(50), @ScheduledField varchar(100), @ScheduledOperator varchar(50),
			@JsonStageData NVARCHAR(MAX)= '', @retval BIT= 0, @HistoryId BIGINT;
	DECLARE @ConditionId BIGINT, @OpSequenceNo INT, @Operand1 VARCHAR(100), @Operator VARCHAR(100), 
			@Operand2 VARCHAR(100), @Conjunction VARCHAR(10), @ConditionType VARCHAR(10), 
			@ConditionRow_ID INT= 1, @ConditionRow_Cnt INT= 0, @retValWait int=0;
	DECLARE @fieldName VARCHAR(100), @fieldValue NVARCHAR(MAX), @fieldTableName VARCHAR(100), @ItemCnt INT= 0, 
			@ScopeId VARCHAR(20)= '0', @ResponseId VARCHAR(10)= '0', @ResponseText NVARCHAR(MAX)= '', 
			@ErrId INT= 0;
	DECLARE @SQL NVARCHAR(4000)= '';

	IF OBJECT_ID('tempdb..#tblItem') IS NOT NULL BEGIN DROP TABLE #tblItem;	END;
	IF OBJECT_ID('tempdb..#tbl_WorkflowId') IS NOT NULL BEGIN DROP TABLE #tbl_WorkflowId; END;
	IF OBJECT_ID('tempdb..#tbl_WorkflowStage') IS NOT NULL BEGIN DROP TABLE #tbl_WorkflowStage; END;
	IF OBJECT_ID('tempdb..#tblResult') IS NOT NULL BEGIN DROP TABLE #tblResult; END;

	CREATE TABLE #tblItem
	(
		[Id]   INT IDENTITY(1, 1),
		[Item] VARCHAR(100)
	);

	CREATE TABLE #tbl_WorkflowId
	(
		[Row_Id]     BIGINT IDENTITY(1, 1),
		[WorkflowId] BIGINT,
		[ParentId]   BIGINT
	);

	CREATE TABLE #tbl_WorkflowStage
	(
		[StageRow_Id]       INT IDENTITY(1, 1),
		[StageId]           BIGINT,
		[SequenceNo]        INT,
		[StageType]         VARCHAR(2),
		[ActionCode]        VARCHAR(10),
		[Webhook]           VARCHAR(500),
		[ScheduledAfterHrs] VARCHAR(50),
		[ScheduledField]	varchar(50),
		[ScheduledOperator] varchar(10),
		[JsonStageData]     NVARCHAR(MAX)
	);

	CREATE TABLE #tblResult
	(
		[Result] VARCHAR(3)
	);

	SELECT	@LeadID = [LeadID], @EventId = [EventID], @ParentId = [ParentId], @reftables = [reftables], 
			@RefId = [refids], @refColName = [refColName], @RefHistoryId = ISNULL([RefHistoryId], [HistoryId]),
			@HistoryId = [HistoryId], @EventDate = [EventDate], @UserId = [UserId], @WorkflowId = [WorkflowId]
	FROM	tbl_wf_WorkflowProcessInitMaster(NOLOCK)
	WHERE	[WProcessId] = @WProcessId;

	SELECT TOP 1 @LastStageId = ISNULL([StageId], 0), @LastStageStatus = ISNULL([Status], '')
	FROM         tbl_wf_WorkflowProcessInitMaster(NOLOCK)
	WHERE        ISNULL([RefHistoryId], [HistoryId]) = @RefHistoryId AND [WorkflowId] = @WorkflowId AND [Status] not in ('raw'/*,'invoked'*/)
	ORDER BY [HistoryId] DESC;

	PRINT '-----------------------------Begin------ usp_wf_ProcessInitWorkflow ----------------------------------------';
	 PRINT concat('@WProcessId: ' ,@WProcessId);  
	 PRINT concat('@LeadID: ' ,@LeadID);  
	 PRINT concat('@EventId: ' ,@EventID);  
	 PRINT concat('@ParentId: ' ,@ParentId);  
	 PRINT concat('@reftables: ' ,@reftables);  
	 PRINT concat('@RefId: ' ,@RefId);  
	 PRINT concat('@refColName: ' ,@refColName);  
	 PRINT concat('@UserId: ' ,@UserId);  
	 PRINT concat('@HistoryId: ' ,@HistoryId);  
	 PRINT concat('@RefHistoryId: ' ,@RefHistoryId);  
	 PRINT concat('@LastStageId: ' ,@LastStageId);  
	 PRINT concat('@LastStageStatus: ' ,@LastStageStatus);  
	 PRINT concat('@WorkflowId: ' ,@WorkflowId);  

	-- fetching first trigger event  
	SELECT @EventId = [EventID]
	FROM   tbl_wf_WorkflowProcessInitMaster(NOLOCK)
	WHERE  [HistoryId] = @RefHistoryId AND [WorkflowId] = @WorkflowId;

	PRINT 'First Trigger @EventId: ' + CAST(@EventID AS VARCHAR);

	INSERT INTO #tbl_WorkflowId([WorkflowId], [ParentId])
		   SELECT [WM].[WorkflowId], [WM].[ParentId]
		   FROM   tbl_wf_WorkflowMaster(NOLOCK) AS WM INNER JOIN tbl_wf_WorkflowStageMaster(NOLOCK) AS WSM
		   ON	  WM.WorkflowId = WSM.WorkflowId AND WSM.SequenceNo = 1 /*AND WM.IsActive = 1*/ AND WSM.IsActive = 1
		   WHERE  [WSM].[TriggerId] = @EventId AND [WM].[WorkflowId] = @WorkflowId;

	SELECT @Row_Cnt = COUNT(*) FROM #tbl_WorkflowId;
	PRINT '@Row_Cnt: ' + CAST(@Row_Cnt AS VARCHAR);

	WHILE(@Row_Id <= @Row_Cnt)
	BEGIN
		PRINT '@Row_Id: ' + CAST(@Row_Id AS VARCHAR);
		SELECT @WorkflowId = [WorkflowId] FROM #tbl_WorkflowId WHERE [Row_Id] = @Row_Id;

		PRINT '@WorkflowId: ' + CAST(@WorkflowId AS VARCHAR);

		INSERT INTO #tbl_WorkflowStage
		SELECT	[StageId], [SequenceNo], [StageType], [ActionCode], [Webhook], [ScheduledAfterHrs],
				[ScheduledField], [ScheduledOperator], [JsonStageData]
		FROM	tbl_wf_WorkflowStageMaster(NOLOCK)
		WHERE	[WorkflowId] = @WorkflowId AND [IsActive] = 1
		ORDER BY [SequenceNo];

		SELECT @StageRow_Cnt = COUNT(*) FROM #tbl_WorkflowStage;
		PRINT '@StageRow_Cnt: ' + CAST(@StageRow_Cnt AS VARCHAR);

		WHILE( @StageRow_Id <= @StageRow_Cnt )
		BEGIN
			PRINT '@StageRow_Id: ' + CAST(@StageRow_Id AS VARCHAR);
			SELECT	@StageId = [StageId], @SequenceNo = [SequenceNo], @StageType = [StageType],
					@ActionCode = [ActionCode],	@Webhook = [Webhook], @ScheduledAfterHrs = [ScheduledAfterHrs],
					@ScheduledField = [ScheduledField], @ScheduledOperator = [ScheduledOperator], 
					@JsonStageData = [JsonStageData]
			FROM   #tbl_WorkflowStage(NOLOCK)
			WHERE  [StageRow_Id] = @StageRow_Id;

			PRINT concat('@StageId: ' , @StageId);  
			PRINT concat('@SequenceNo: ' , @SequenceNo);  
			PRINT concat('@StageType: ' , @StageType);  
			PRINT concat('@ActionCode: ' , @ActionCode);  
			PRINT concat('@Webhook: ' , @Webhook);  
			PRINT concat('@ScheduledAfterHrs: ' , @ScheduledAfterHrs);  
			PRINT concat('@ScheduledField: ' , @ScheduledField);  
			PRINT concat('@ScheduledOperator: ' ,@ScheduledOperator);  
			PRINT concat('@JsonStageData: ' ,@JsonStageData);  

			SELECT @ConditionType = [ConditionType]
			FROM   tbl_wf_WorkflowStageConditionMaster(NOLOCK)
			WHERE  [WorkflowId] = @WorkflowId AND [StageId] = @StageId AND [IsActive] = 1;

			PRINT '@ConditionType: ' + ISNULL(@ConditionType, '');

			IF( @LastStageId < @StageId )
			BEGIN
				IF( @LastStageStatus IN('failed', 'finished', 'error', 'notfound', 'skipped') )
				BEGIN
					UPDATE tbl_wf_WorkflowProcessInitMaster 
					SET [Status] = CASE WHEN [Status] in ('raw'/*,'invoked'*/) THEN 'skipped' ELSE [Status] END, [LastUpdatedOn] = GETDATE(), [ExecStartDate] = @ExecStartDate, [ExecEndDate] = GETDATE()
					WHERE [WProcessId] = @WProcessId;

					PRINT 'Stage skipped due to status of previous stage';
					RETURN;
				END;

				IF(@LastStageStatus = 'invoked')
				Begin
					UPDATE tbl_wf_WorkflowProcessInitMaster 
					SET [Status] = CASE WHEN @SequenceNo = @StageRow_Cnt THEN 'finished' ELSE 'processed' END, 
						[LastUpdatedOn] = GETDATE(), [ExecStartDate] = @ExecStartDate, [ExecEndDate] = GETDATE(),
						[ResponseCode] = @RefId, [ResponseText] = 'Success'
					WHERE [WProcessId] = @WProcessId;

					PRINT 'Invoked Stage processed continue to next stage';
					SET @StageRow_Id = @StageRow_Id + 1;
					SET @LastStageId = @StageId;
					SET @LastStageStatus = 'processed';
					continue;
				End

				IF( @StageType = 'TC' )
				BEGIN
					EXEC @retval = usp_wf_EvaluateCondition @HistoryId, @RefHistoryId, @UserId, @LeadId, @RefId, @reftables, @refColName, @StageId;
					print concat('(@StageType=TC) @retval: ',@retval)

					IF(@retval = 0)
					BEGIN
						UPDATE tbl_wf_WorkflowProcessInitMaster 
						SET [Status] = 'failed', [ExecStartDate] = @ExecStartDate, [ExecEndDate] = GETDATE(),
							[LastUpdatedOn] = GETDATE(),[ResponseCode] = -1, [ResponseText] = 'Trigger Condition Failed'
						WHERE [WProcessId] = @WProcessId;

						RETURN;
					END;
					ELSE
					BEGIN
						UPDATE tbl_wf_WorkflowProcessInitMaster 
						SET [Status] = 'processed', [LastUpdatedOn] = GETDATE(), 
							[ExecStartDate] = @ExecStartDate, [ExecEndDate] = GETDATE(),
							[ResponseCode] = 1, [ResponseText] = 'Success'
						WHERE [WProcessId] = @WProcessId;

						SET @LastStageId = @StageId;
						CONTINUE;
					END;
				END;
				ELSE
				BEGIN
					IF( @StageType = 'AS' )
					BEGIN
						print 'executing ' + @StageType
						EXEC usp_wf_ExecAction @RefHistoryId, @WorkFlowId, @StageId, @LeadId, @UserId, @ActionCode, @JsonStageData;

						SELECT @ScopeId = [ScopeId], @ErrId = CAST([ResponseId] AS INT), @ResponseText = [ResponseText]
						FROM   tbl_wf_WorkflowResponse(NOLOCK)
						WHERE  [SPId] = @@SPID;

						DELETE FROM tbl_wf_WorkflowResponse WHERE [SPId] = @@SPID;

						UPDATE tbl_wf_WorkflowProcessInitMaster 
						SET [Status] = CASE WHEN @SequenceNo = @StageRow_Cnt THEN 'finished' 
											WHEN @ErrId < 0 THEN 'error' ELSE 'processed' END, 
							[LastUpdatedOn] = GETDATE(), [ExecStartDate] = @ExecStartDate, [ExecEndDate] = GETDATE(),
							[ResponseCode] = @ErrId, [ResponseText] = @ResponseText
						WHERE [WProcessId] = @WProcessId;

						SET @LastStageId = @StageId;
					END;
					ELSE
					BEGIN
						IF( @StageType = 'AC' )
						BEGIN
							IF( @ConditionType = 'pre' )
							BEGIN
							print 'executing pre ' + @StageType
								EXEC @retval = usp_wf_EvaluateCondition @HistoryId, @RefHistoryId, @UserId, @LeadId, @RefId, @reftables, @refColName, @StageId;

								IF( @retval = 1 )
								BEGIN
									EXEC usp_wf_ExecAction @RefHistoryId, @WorkFlowId, @StageId, @LeadId, @UserId, @ActionCode, @JsonStageData;

									SELECT	@ScopeId = [ScopeId], @ErrId = CAST([ResponseId] AS INT), 
											@ResponseText = [ResponseText]
									FROM   tbl_wf_WorkflowResponse(NOLOCK)
									WHERE  [SPId] = @@SPID;

									DELETE FROM tbl_wf_WorkflowResponse WHERE [SPId] = @@SPID;

									UPDATE tbl_wf_WorkflowProcessInitMaster 
									SET [Status] = CASE WHEN @SequenceNo = @StageRow_Cnt THEN 'finished' 
														WHEN @ErrId < 0 THEN 'error' ELSE 'processed' END,
										[LastUpdatedOn] = GETDATE(), [ExecStartDate] = @ExecStartDate, 
										[ExecEndDate] = GETDATE(), [ResponseCode] = @ErrId, 
										[ResponseText] = @ResponseText
									WHERE [WProcessId] = @WProcessId;

									SET @LastStageId = @StageId;
								END;
								ELSE
								BEGIN
									UPDATE tbl_wf_WorkflowProcessInitMaster 
									SET [Status] = 'failed', [LastUpdatedOn] = GETDATE(),
										[ExecStartDate] = @ExecStartDate, [ExecEndDate] = GETDATE(),
										[ResponseCode] = -1, [ResponseText] = ISNULL(@ResponseText, 'Pre Condition Failed')
									WHERE [WProcessId] = @WProcessId;

									RETURN;
								END;
							END;

							IF( @ConditionType = 'post' )
							BEGIN
								print 'executing post ' + @StageType
								EXEC usp_wf_ExecAction @RefHistoryId, @WorkFlowId, @StageId, @LeadId, @UserId, @ActionCode, @JsonStageData;

								SELECT	@ScopeId = [ScopeId], @ErrId = CAST([ResponseId] AS INT), 
										@ResponseText = [ResponseText]
								FROM   tbl_wf_WorkflowResponse(NOLOCK)
								WHERE  [SPId] = @@SPID;

								DELETE FROM tbl_wf_WorkflowResponse WHERE [SPId] = @@SPID;

								EXEC @retval = usp_wf_EvaluateCondition @HistoryId, @RefHistoryId, @UserId, @LeadId, @RefId, @reftables, @refColName, @StageId;

								IF(@retval = 1)
								BEGIN
									UPDATE tbl_wf_WorkflowProcessInitMaster 
									SET [Status] = CASE WHEN @SequenceNo = @StageRow_Cnt THEN 'finished' 
														WHEN @ErrId < 0 THEN 'error' ELSE 'processed' END,
										[LastUpdatedOn] = GETDATE(), [ExecStartDate] = @ExecStartDate,
										[ExecEndDate] = GETDATE(), [ResponseCode] = @ErrId, 
										[ResponseText] = @ResponseText
									WHERE [WProcessId] = @WProcessId;

									SET @LastStageId = @StageId;
								END;
								ELSE
								BEGIN
									UPDATE tbl_wf_WorkflowProcessInitMaster 
									SET [Status] = 'failed', [LastUpdatedOn] = GETDATE(),
									[ExecStartDate] = @ExecStartDate, [ExecEndDate] = GETDATE(),
									[ResponseCode] = @ErrId, [ResponseText] = ISNULL(@ResponseText, 'Post Condition Failed')
									WHERE [WProcessId] = @WProcessId;

									RETURN;
								END;
							END;
						END;
						ELSE
						BEGIN
							IF( @StageType = 'AW' )
							BEGIN
								IF(ISNULL(@ScheduledAfterHrs, '0') = '0' OR ISNULL(@ScheduledAfterHrs, '') = '')
								BEGIN
									print 'executing ' + @StageType
									EXEC @retval = usp_wf_EvaluateCondition @HistoryId, @RefHistoryId, @UserId, @LeadId, @RefId, @reftables, @refColName, @StageId;
									print concat('(@StageType=AW) @retval: ',@retval)

									IF( @retval = 1 )
									BEGIN
										EXEC usp_wf_ExecAction @RefHistoryId, @WorkFlowId, @StageId, @LeadId, @UserId, @ActionCode, @JsonStageData;

										SELECT	@ScopeId = [ScopeId], @ErrId = CAST([ResponseId] AS INT), 
												@ResponseText = [ResponseText]
										FROM   tbl_wf_WorkflowResponse(NOLOCK)
										WHERE  [SPId] = @@SPID;

										DELETE FROM tbl_wf_WorkflowResponse WHERE [SPId] = @@SPID;

										UPDATE tbl_wf_WorkflowProcessInitMaster 
										SET [Status] = CASE WHEN @SequenceNo = @StageRow_Cnt THEN 'finished' 
															WHEN @ErrId<0 THEN 'error' ELSE 'processed' END,
											[LastUpdatedOn] = GETDATE(), [ExecStartDate] = @ExecStartDate,
											[ExecEndDate] = GETDATE(), [ResponseCode] = @ErrId, 
											[ResponseText] = @ResponseText
										WHERE [WProcessId] = @WProcessId;

										SET @LastStageId = @StageId;
									END;
									ELSE
									BEGIN
										UPDATE tbl_wf_WorkflowProcessInitMaster 
										SET [Status] = 'failed', [LastUpdatedOn] = GETDATE(), 
											[ExecStartDate] = @ExecStartDate, [ExecEndDate] = GETDATE(), 
											[ResponseCode] = @ErrId, [ResponseText] = isnull(@ResponseText,'Wait Condition Failed')
										WHERE [WProcessId] = @WProcessId;

										RETURN;
									END;
								END;
								ELSE
								BEGIN
									Exec @retValWait=usp_wf_EvalWaitCondition @WorkflowId, @RefHistoryId, @ScheduledAfterHrs, @ScheduledField, @ScheduledOperator, @StageId
									print concat('(@StageType=AW) @retValWait: ',@retValWait)

									--IF(DATEADD(hour, CAST(ISNULL(@ScheduledAfterHrs, '0') AS NUMERIC(18, 2)), @EventDate) < GETDATE())--FromDate_ddlAction1_simple_num0
									IF(@retValWait=1)
									BEGIN
										print 'executing ' + @StageType
										EXEC usp_wf_ExecAction @RefHistoryId, @WorkFlowId, @StageId, @LeadId, @UserId, @ActionCode, @JsonStageData;

										SELECT	@ScopeId = [ScopeId], @ErrId = CAST([ResponseId] AS INT), 
												@ResponseText = [ResponseText]
										FROM   tbl_wf_WorkflowResponse(NOLOCK)
										WHERE  [SPId] = @@SPID;

										DELETE FROM tbl_wf_WorkflowResponse WHERE [SPId] = @@SPID;

										UPDATE tbl_wf_WorkflowProcessInitMaster 
										SET [Status] = CASE WHEN @SequenceNo = @StageRow_Cnt THEN 'finished' 
															WHEN @ErrId<0 THEN 'error' ELSE 'processed' END,
											[LastUpdatedOn] = GETDATE(), [ExecStartDate] = @ExecStartDate,
											[ExecEndDate] = GETDATE(), [ResponseCode] = @ErrId, 
											[ResponseText] = @ResponseText
										WHERE [WProcessId] = @WProcessId;

										SET @LastStageId = @StageId;
									END;
								END;
							END;
							ELSE
							BEGIN
								IF(@StageType = 'AT')
								BEGIN
									PRINT @StageType;
									SET @LastStageId = @StageId;
								END;
							END;
						END;
					END;
				END;

				RETURN; -- One Action execution per WProcessId  
			END;--endif  
			IF(@SequenceNo = @StageRow_Cnt)
			BEGIN
				UPDATE tbl_wf_WorkflowProcessInitMaster 
				SET [Status] = 'finished', [LastUpdatedOn] = GETDATE(), 
					[ExecStartDate] = @ExecStartDate, [ExecEndDate] = GETDATE(),
					[ResponseCode] = 1, [ResponseText] = 'Success'
				WHERE [WProcessId] = @WProcessId;

				PRINT 'finished';
				RETURN;
			END;

			SET @StageRow_Id = @StageRow_Id + 1;
			SET @retValWait=0;
		END; -- EndWhile  
		SET @Row_Id = @Row_Id + 1;
	END;

	IF(@Row_Cnt = 0)
	BEGIN
		UPDATE tbl_wf_WorkflowProcessInitMaster 
		SET [Status] = 'notfound', [LastUpdatedOn] = GETDATE(), [ExecStartDate] = @ExecStartDate, [ExecEndDate] = GETDATE()
		WHERE [WProcessId] = @WProcessId;
	END;
	PRINT '-----------------------------End------ usp_wf_ProcessInitWorkflow ----------------------------------------';

END;



GO

/* ============================================================
   Procedure: [dbo].[usp_wf_ProcessWorkflow]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_wf_ProcessWorkflow 1214666
CREATE   PROC usp_wf_ProcessWorkflow
(
	@HistoryId bigint
)
AS
BEGIN
	-- declare @HistoryId bigint=1214666
	Declare @Row_Id bigint=1, @EventId bigint, @UserId bigint, @LeadId bigint, @RefId bigint, @reftables nvarchar(1000), @Row_Cnt bigint=0,
			@WorkflowId bigint, @ParentId bigint, @refColName varchar(100), @ConditionExpr varchar(1000)='', @RefHistoryId bigint, 
			@EventDate datetime, @LastStageId bigint=0
	Declare	@StageRow_Id int=1, @StageRow_Cnt int=0, @StageId bigint, @SequenceNo int, @StageType varchar(2), @ActionCode varchar(10),
			@Webhook varchar(500), @ScheduledAfterHrs varchar(5), @JsonStageData nvarchar(max)='', @retval bit=0, @WProcessId bigint
	Declare @ConditionId bigint, @OpSequenceNo int, @Operand1 varchar(100), @Operator varchar(100), @Operand2 varchar(100), 
			@Conjunction varchar(10), @ConditionType varchar(10), @ConditionRow_ID int=1, @ConditionRow_Cnt int=0
	declare @fieldName varchar(100), @fieldValue nvarchar(max), @fieldTableName varchar(100), @ItemCnt int=0
	DECLARE @SQL NVARCHAR(4000) = '';

	if object_id('tempdb..#tblItem') is not null begin drop table #tblItem end      
	if object_id('tempdb..#tbl_WorkflowId') is not null begin drop table #tbl_WorkflowId end      
	if object_id('tempdb..#tbl_WorkflowStage') is not null begin drop table #tbl_WorkflowStage end      
	if object_id('tempdb..#tblResult') is not null begin drop table #tblResult end      

	create table #tblItem 
	(
		Id int identity(1,1), 
		Item varchar(100)
	)

	Create table #tbl_WorkflowId
	(
		Row_Id bigint identity(1,1),
		WorkflowId bigint,
		ParentId bigint
	)

	Create table #tbl_WorkflowStage
	(
		StageRow_Id int identity(1,1),
		StageId bigint,
		SequenceNo int,
		StageType varchar(2),
		ActionCode varchar(10),
		Webhook varchar(500),
		ScheduledAfterHrs varchar(5),
		JsonStageData nvarchar(max)
	)

	Create table #tblResult (Result varchar(3))

	Select	@LeadID=LeadID,@EventId=EventID,@ParentId=ParentId,@reftables=reftables,@RefId=refids,@refColName=refColName,
			@RefHistoryId=isnull(RefHistoryId,HistoryId), @WProcessId=WProcessId, @EventDate=EventDate, @UserId=UserId
	from	tbl_wf_WorkflowProcessMaster(nolock)
	Where	Historyid=@HistoryId--1118995

	Select  @LastStageId=isnull(StageId,0)
	from	tbl_wf_WorkflowProcessMaster(nolock)
	Where	RefHistoryId=@RefHistoryId and StageId is not null
	Order by HistoryId desc

	print '-----------------------------Begin------ usp_wf_ProcessWorkflow ----------------------------------------'
	print '@WProcessId: ' + cast(@WProcessId as varchar) 
	print '@LeadID: ' + cast(@LeadID as varchar) 
	print '@EventId: ' + cast(@EventID as varchar)
	print '@ParentId: ' + cast(@ParentId as varchar)
	print '@reftables: ' + isnull(@reftables,'')
	print '@RefId: ' + cast(@RefId as varchar)
	print '@refColName: ' + isnull(@refColName,'')
	print '@UserId: ' + cast(@UserId as varchar)
	print '@HistoryId: ' + cast(@HistoryId as varchar)
	print '@RefHistoryId: ' + cast(@RefHistoryId as varchar)
	print '@LastStageId: ' + cast(@LastStageId as varchar)

	-- fetching first trigger event
	Select  @EventId=EventID
	from	tbl_wf_WorkflowProcessMaster(nolock)
	Where	HistoryId=@RefHistoryId

	print 'First Trigger @EventId: ' + cast(@EventID as varchar)

	insert into #tbl_WorkflowId(WorkflowId,ParentId)
	Select WM.WorkflowId,WM.ParentId 
	from tbl_wf_WorkflowMaster(nolock) WM inner join  tbl_wf_WorkflowStageMaster(nolock) WSM
	On	WM.WorkflowId = WSM.WorkflowId and WSM.SequenceNo=1 and WM.IsActive=1 and WSM.IsActive=1
	Where WSM.TriggerId=@EventId
			and WM.ParentId=@ParentId

	Select @Row_Cnt=count(*) From #tbl_WorkflowId
	print '@Row_Cnt: ' + cast(@Row_Cnt as varchar)
	
	While(@Row_Id<=@Row_Cnt)
	Begin
		print '@Row_Id: ' + cast(@Row_Id as varchar)
		Select @WorkflowId=WorkflowId From #tbl_WorkflowId Where Row_Id=@Row_Id

		print '@WorkflowId: ' + cast(@WorkflowId as varchar)

		insert into #tbl_WorkflowStage
		Select StageId, SequenceNo, StageType, ActionCode, Webhook, ScheduledAfterHrs, JsonStageData 
		from tbl_wf_WorkflowStageMaster(nolock) 
		Where WorkflowId=@WorkflowId 
		and IsActive=1
		Order by SequenceNo

		Select @StageRow_Cnt=count(*) From #tbl_WorkflowStage
		print '@StageRow_Cnt: ' + cast(@StageRow_Cnt as varchar)

		While(@StageRow_Id <= @StageRow_Cnt)
		Begin
			print '@StageRow_Id: ' + cast(@StageRow_Id as varchar)
			Select @StageId=StageId, @SequenceNo=SequenceNo, @StageType=StageType, @ActionCode=ActionCode, @Webhook=Webhook, @ScheduledAfterHrs=ScheduledAfterHrs, @JsonStageData=JsonStageData 
			from #tbl_WorkflowStage 
			Where StageRow_Id=@StageRow_Id

			print '@StageType: ' + @StageType
			Select @ConditionType=ConditionType
			from tbl_wf_WorkflowStageConditionMaster(nolock)
			Where WorkflowId=@WorkflowId and StageId=@StageId and IsActive=1

			If(@LastStageId < @StageId)
			Begin
				If(@StageType='TC')
				Begin
					Exec @retval=usp_wf_EvaluateCondition @HistoryId,@RefHistoryId,@UserId,@LeadId,@RefId,@reftables,@refColName,@StageId;
				
					If(@retval=0)
					Begin
						Update tbl_wf_WorkflowProcessMaster Set [Status]='failed',LastUpdatedOn=GETDATE(), StageId=@StageId 
						Where WProcessId=@WProcessId
						return
					End
					Else
					Begin
						Update tbl_wf_WorkflowProcessMaster Set [Status]='waiting',LastUpdatedOn=GETDATE(), StageId=@StageId 
						Where WProcessId=@WProcessId

						Set @LastStageId = @StageId
					End
				End
				Else If(@StageType='AS')
				Begin
					Exec usp_wf_ExecAction @RefHistoryId, @WorkFlowId, @StageId, @LeadId, @UserId,	@ActionCode, @JsonStageData

					Update tbl_wf_WorkflowProcessMaster Set [Status]='processed',LastUpdatedOn=GETDATE(), StageId=@StageId 
					Where WProcessId=@WProcessId

					Set @LastStageId = @StageId
				End
				Else If(@StageType='AC')
				Begin
					If(@ConditionType='pre')
					Begin
						Exec @retval=usp_wf_EvaluateCondition @HistoryId,@RefHistoryId,@UserId,@LeadId,@RefId,@reftables,@refColName,@StageId;

						If(@retval=1)
						Begin
							Exec usp_wf_ExecAction @RefHistoryId, @WorkFlowId, @StageId, @LeadId, @UserId,	@ActionCode, @JsonStageData
							Update tbl_wf_WorkflowProcessMaster Set [Status]='processed',LastUpdatedOn=GETDATE(), StageId=@StageId 
							Where WProcessId=@WProcessId

							Set @LastStageId = @StageId
						End
						Else
						Begin
							Update tbl_wf_WorkflowProcessMaster Set [Status]='failed',LastUpdatedOn=GETDATE(), StageId=@StageId
							Where WProcessId=@WProcessId
							return
						End
					End

					If(@ConditionType='post')
					Begin
						Exec usp_wf_ExecAction @RefHistoryId, @WorkFlowId, @StageId, @LeadId, @UserId,	@ActionCode, @JsonStageData

						Exec @retval=usp_wf_EvaluateCondition @HistoryId,@RefHistoryId,@UserId,@LeadId,@RefId,@reftables,@refColName,@StageId;

						If(@retval=1)
						Begin
							Update tbl_wf_WorkflowProcessMaster Set [Status]='processed',LastUpdatedOn=GETDATE(), StageId=@StageId
							Where WProcessId=@WProcessId

							Set @LastStageId = @StageId
						End
						Else
						Begin
							Update tbl_wf_WorkflowProcessMaster Set [Status]='failed',LastUpdatedOn=GETDATE(), StageId=@StageId
							Where WProcessId=@WProcessId
							return;
						End
					End
				End
				Else If(@StageType='AW')
				Begin
					If(isnull(@ScheduledAfterHrs,'0') = '0' or isnull(@ScheduledAfterHrs,'') = '')
					Begin
						Exec @retval=usp_wf_EvaluateCondition @HistoryId,@RefHistoryId,@UserId,@LeadId,@RefId,@reftables,@refColName,@StageId;

						If(@retval=1)
						Begin
							Exec @retval=usp_wf_EvaluateCondition @HistoryId,@RefHistoryId,@UserId,@LeadId,@RefId,@reftables,@refColName,@StageId;
							Update tbl_wf_WorkflowProcessMaster Set [Status]='processed',LastUpdatedOn=GETDATE(), StageId=@StageId
							Where WProcessId=@WProcessId

							Set @LastStageId = @StageId
						End
						Else
						Begin
							Update tbl_wf_WorkflowProcessMaster Set [Status]='failed',LastUpdatedOn=GETDATE(), StageId=@StageId
							Where WProcessId=@WProcessId
							return
						End
					End
					Else
					Begin
						If(DATEADD(hour,cast(isnull(@ScheduledAfterHrs,'0') as numeric(18,2)),@EventDate) < GETDATE())
						Begin
							Exec @retval=usp_wf_EvaluateCondition @HistoryId,@RefHistoryId,@UserId,@LeadId,@RefId,@reftables,@refColName,@StageId;

							Update tbl_wf_WorkflowProcessMaster Set [Status]='processed',LastUpdatedOn=GETDATE(), StageId=@StageId
							Where WProcessId=@WProcessId

							Set @LastStageId = @StageId
						End
					End
				End
				Else If(@StageType='AT')
				Begin
					print @StageType
					Set @LastStageId = @StageId
				End
			End--endif

			If(@SequenceNo = @StageRow_Cnt)
			Begin
				Update tbl_wf_WorkflowProcessMaster Set [Status]='finished',LastUpdatedOn=GETDATE(), StageId=@StageId
				Where WProcessId=@WProcessId
				return
			End

			Set @StageRow_Id = @StageRow_Id+1
		End

		Set @Row_Id = @Row_Id + 1
	End

	If(@Row_Cnt = 0)
	Begin
		Update tbl_wf_WorkflowProcessMaster Set [Status]='notfound',LastUpdatedOn=GETDATE() Where WProcessId=@WProcessId
	End
	--Select * from tbl_wf_WorkflowStageMaster(nolock) 
	--Select * from tbl_wf_WorkflowStageConditionMaster(nolock)

	print '-----------------------------End------ usp_wf_ProcessWorkflow ----------------------------------------'

END



