-- Exec usp_wf_QueueInitWorkflow @BucketId=0,@BucketSize=2,@PageSize=10
-- Exec usp_wf_QueueInitWorkflow @BucketId=1,@BucketSize=2,@PageSize=10
CREATE   PROC usp_wf_QueueInitWorkflow
(
	@BucketId int,
	@BucketSize int=4,
	@PageSize int=20
)
AS
BEGIN

	--Declare @BucketId int=1,@BucketSize int=4,@PageSize int=10
	--Set @PageSize=0
	select top(@PageSize) * From tbl_wf_WorkflowProcessInitMaster(nolock) Where IsActive=1 and (WProcessId % @BucketSize) = @BucketId and [Status] in ( 'raw','invoked') --not in ('finished','notfound','failed','error','processed')

END



