/* ============================================================
   Procedure: [dbo].[usp_wf_SaveLeadActivity_withid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_wf_SaveLeadActivity_withid]                
(                
 @LeadID BIGINT,    
 @UserID BIGINT,    
 @ParentID BIGINT,    
 @EventDescription NVARCHAR(MAX),    
 @EventName NVARCHAR(500),    
 @reftables NVARCHAR(500),    
 @refid NVARCHAR(100),    
 @RefColName VARCHAR(100)='',    
 @RefHistoryId BIGINT=0,    
 @WorkFlowId BIGINT=null    
)                
AS                
BEGIN            
begin try              
 DECLARE @EventID BIGINT= 0, @activityid BIGINT;                
                
 SELECT @EventID = ISNULL([ID], 0) FROM   ActivityMaster(NOLOCK) WHERE  [EventName] = @EventName;                
    
print '-----------------------------Begin------ usp_wf_SaveLeadActivity_withid ----------------------------------------'    
    
 IF(ISNULL(@ParentID, 0) = 0)                
 BEGIN                
  SELECT @ParentID = [ParentID] FROM   User_Detail(NOLOCK) WHERE  User_ID = @UserID;                
 END;                
                
 IF (@eventid <> 17 OR (@eventid = 17 AND NOT EXISTS(SELECT 1 FROM tbl_LeadEventHistory(NOLOCK) WHERE  [leadid] = @LeadID AND [eventid] = 17) ) )          
 BEGIN                
    
 print '@ParentID: ' + cast(@ParentID as varchar)    
 print '@UserID: ' + cast(@UserID as varchar)    
 print '@LeadID: ' + cast(@LeadID as varchar)    
 print '@EventDescription: ' + cast(@EventDescription as varchar)    
 print '@EventID: ' + cast(@EventID as varchar)    
 print '@reftables: ' + cast(@reftables as varchar)    
 print '@refid: ' + cast(@refid as varchar)    
 print '@RefColName: ' + cast(@RefColName as varchar)    
 print '@RefHistoryId: ' + cast(@RefHistoryId as varchar)    
 print '@WorkFlowId: ' + cast(isnull(@WorkFlowId,'') as varchar)    
    
  INSERT INTO tbl_LeadEventHistory                
    ([ParentID], [UserID], [LeadID], [EventDescription], [EventDate], [EventID], [reftables], [refids],[refColName],[refHistoryId], [WorkflowId])                
  VALUES (@ParentID, @UserID, @LeadID, @EventDescription, GETDATE(), @EventID, @reftables, @refid, @RefColName, @RefHistoryId, @WorkFlowId);                
                
  SELECT @activityid = SCOPE_IDENTITY();                
    
 print '@activityid: ' + cast(@activityid as varchar)    
                  
  EXEC usp_insertleadscore @activityid;                
                
  Exec usp_es_SaveLoyaltyTransaction @activityid                
          
  exec usp_insertnotification @activityid,'lead'          
  if dbo.fn_has_active_whatsapp(@parentid)=1
begin        
  exec usp_updatelastactivityinconvuser 'lead',@activityid          
end
  begin try          
   exec [dbo].[usp_automationrulesapply_activity_insert] @activityid,'lead'            
  end try                 
 begin catch                 
 exec usp_inserterrorinfo                 
 end catch 
           
exec usp_insertenagagementactivity @activityid,'lead'   
exec usp_insertcalculatedfields 'lead',@activityid,@parentid

 /*                 
  DECLARE @nid TABLE                
  (                
   [modeid]         INT,                
   [notificationid] BIGINT,                
   [roleid]         INT,                
   [activityid]     INT              
  );                
                  
  INSERT INTO @nid([modeid], [notificationid], [roleid], [activityid])                
      SELECT [modeid], [id], [roleid], [activityid]                 
      FROM   notificationsmaster(NOLOCK)                
      WHERE  [activityid] = @EventID;                
                
                
  INSERT INTO notificationhistory([notificationid], [reftable], [refid], [content],n_userid)                
  SELECT [notificationid], 'tbl_LeadEventHistory', @activityid, [t].[EventDescription],              
   case when roleid=6 then @UserID when roleid=3 then @ParentID end               
      FROM   tbl_leadeventhistory(NOLOCK) AS t JOIN @nid AS n                
      ON n.activityid = t.EventID AND n.modeid = 1 AND t.HistoryID = @activityid;                
*/          
        
 --insert into eventsexecuted( activityid,isprocessed)        
 --select    @activityid,0        
 --declare @eei bigint=scope_identity()        
 exec usp_executeeventcampaign1 'lead',@activityid            
 --update eventsexecuted set isprocessed=1 where id=@eei        
            
 END;          
 end try          
 begin catch          
 exec usp_InsertErrorInfo          
 end catch          
                 
print '-----------------------------End------ usp_wf_SaveLeadActivity_withid ----------------------------------------'    
    
END;         
  


GO

/* ============================================================
   Procedure: [dbo].[usp_wf_SaveLeadActivity_withMultipleValue_withid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


  
CREATE   PROCEDURE [dbo].[usp_wf_SaveLeadActivity_withMultipleValue_withid]          
 (          
   @tbl  LeadActivitywithid_Tbltype READONLY,  
   @RefColName varchar(100)='',  
   @RefHistoryId bigint=0,  
   @WorkFlowId bigint=null  
 )          
 as          
 Begin          
 begin try         
   SELECT  RowID = ROW_NUMBER() OVER (          
                   ORDER BY T.LeadID) ,          
      T.LeadID ,          
      T.UserID ,          
      T.ParentID,          
      T.EventDescription,          
      T.EventName,        
   T.reftable,        
   T.Refid          
   INTO #TempTbl          
   FROM @tbl T          
          
   declare @count int  = 0          
   declare @RowNo int = 1           
   select @count =  isnull(count(1),0) from  #TempTbl          
   Declare @ParentID bigint = 0          
   Declare @UserID bigint = 0          
   Declare @EventName nvarchar(500)           
   DECLARE @EventID BIGINT= 0,@refid nvarchar(100),@reftable nvarchar(100),@activityid bigint;        
              
    print '----------------Begin---- sp: usp_wf_SaveLeadActivity_withMultipleValue_withid ----------------------------'      
   while(@RowNo <= @count )          
    Begin          
          
 select @EventName = isnull(EventName,''), @ParentID = isnull(ParentID,0) ,@UserID = isnull(UserID,0),@reftable=isnull(reftable,''),@refid=isnull(refid,'')  from #TempTbl where RowID = @RowNo          
           
            
    SELECT @EventID = ISNULL(ID , 0)  FROM ActivityMaster(nolock)  WHERE EventName = @EventName;            
            
   IF(@ParentID = 0)            
    BEGIN            
     SELECT @ParentID = ParentID FROM User_Detail  WHERE User_ID = @UserID;            
   END            
  
   print '@RowNo: ' + cast(@RowNo as varchar)  
   print '@UserID: ' + cast(@UserID as varchar)  
   print '@EventID: ' + cast(@EventID as varchar)  
   print '@reftable: ' + cast(@reftable as varchar)  
   print '@refid: ' + cast(@refid as varchar)  
   print '@RefColName: ' + cast(@RefColName as varchar)  
   print '@RefHistoryId: ' + cast(@RefHistoryId as varchar)  
   print '@WorkFlowId: ' + cast(isnull(@WorkFlowId,'') as varchar)  
            
    INSERT INTO tbl_LeadEventHistory ( ParentID , UserID , LeadID , EventDescription , EventDate , EventID ,reftables,refids,refColName,refHistoryId,WorkFlowId)  
   select @ParentID , @UserID , LeadID ,EventDescription , GETDATE() , @EventID,@reftable,@refid, @RefColName, @RefHistoryId, @WorkFlowId  
   from #TempTbl where RowID = @RowNo          
     
   select @activityid=SCOPE_IDENTITY()         
  --VALUES ( @ParentID , @UserID , @LeadID , @EventDescription , GETDATE() , @EventID );       
  EXEC usp_insertleadscore @activityid;            
  Exec usp_es_SaveLoyaltyTransaction @activityid   
  if dbo.fn_has_active_whatsapp(@parentid)=1
  begin
  exec usp_updatelastactivityinconvuser 'lead',@activityid  
  end
  exec usp_insertnotification @activityid,'lead'      
  exec usp_executeeventcampaign1 'lead',@activityid     
  exec usp_insertenagagementactivity @activityid,'lead'   
  exec usp_insertcalculatedfields 'lead',@activityid,@parentid

          
  set @RowNo = @RowNo + 1           
          
 End             
   print '----------------End---- sp: usp_wf_SaveLeadActivity_withMultipleValue_withid ----------------------------'      
   drop table #TempTbl           
     end try      
 begin catch      
 exec usp_InsertErrorInfo      
 end catch           
 End  




GO

