--exec usp_wf_SaveWorkflow @WorkflowId=0,@WorkflowName=N'Workflow 1',@EventId=17,@UserId=32222,@jsonStageList=N'[{"StageId":0,"StageName":"Trigger Condition","SequenceNo":1,"StageType":"TC","ActionCode":"","JsonStageData":{},"ScheduledAfterHrs":"","Webhook":"","lstCondition":[]},{"StageId":0,"StageName":"Action 1","SequenceNo":2,"StageType":"AS","ActionCode":"ADD_APMT","JsonStageData":{"Title":"Title","Description":"Description","Remarks":"Remarks","FromDate":"-1","DueDate":"1","Where":"Delhi","Address":"vikaspuri","Owner":"32222","Collaborators":["32226"]},"ScheduledAfterHrs":"","Webhook":"","lstCondition":[]},{"StageId":0,"StageName":"Action 2","SequenceNo":3,"StageType":"AC","ActionCode":"ADD_DEAL","JsonStageData":{"DealValue":"566","DealPipeline":"15","DealStage":"102","Probability":"89","DealOwner":"32222","EstimatedClosureDate":"2"},"ScheduledAfterHrs":"","Webhook":"","lstCondition":[{"SequenceNo":1,"Operand1":"Action2_LeadPipelineMapping_Entity.Entity.leadno","Operator":">","Operand2":"0","Conjunction":"AND","ConditionType":"pre"}]},{"StageId":0,"StageName":"Action 3","SequenceNo":4,"StageType":"AW","ActionCode":"VOI_TO_LD","JsonStageData":{"MobileNo":true,"MobileNo1":false,"MobileNo2":false,"Route":"promo","CallerID":"1204759570","appid":"931","Duration":"1"},"ScheduledAfterHrs":"scheduled","Webhook":"","lstCondition":[{"SequenceNo":1,"Operand1":"EstimatedClosureDate_ddlAction2_conditional_num3","Operator":">=","Operand2":"3","Conjunction":"OR","ConditionType":""}]}]'
CREATE   PROC usp_wf_SaveWorkflow
(
	@WorkflowId bigint,
	@WorkflowName varchar(100),
	@EventId int,
	@UserId bigint,
	@jsonStageList nvarchar(max)=''
)
AS
BEGIN
	Declare @ParentId bigint=0, @WflCnt int=0, @RowId int=1
	Declare @StageId int, @StageName varchar(100), @SequenceNo int, @StageType varchar(2), 
			@JsonStageData nvarchar(max), @ActionCode varchar(10), @Webhook varchar(500), 
			@JsonCondition nvarchar(max), @ScheduledAfterHrs varchar(50), @ScheduledHrsType varchar(50),
			@ScheduledField varchar(100), @ScheduledOperator varchar(50)

	Select @ParentId = ParentID From User_Detail(nolock) Where User_ID=@UserId

	If exists(select * from tbl_wf_WorkflowMaster(nolock) Where ParentId=@ParentId and IsActive=1 and WorkflowName=@WorkflowName and WorkflowId != @WorkflowId)
	Begin
		Select -1 as Code, 'Workflow Name already exists' as Msg
	End
	Else
	Begin
		If(@WorkflowId > 0)
		Begin
			Update tbl_wf_WorkflowMaster Set IsActive=0, ModifiedBy=@UserId, ModifiedOn=getdate() Where WorkflowId=@WorkflowId
			Set @WorkflowId=0
		End

		If(@WorkflowId = 0)
		Begin
			insert into tbl_wf_WorkflowMaster(WorkflowName,ParentId,IsActive,CreatedBy,CreatedOn)
			values(@WorkflowName,@ParentId,1,@UserId,GETDATE())
			Set @WorkflowId=SCOPE_IDENTITY()

			if object_id('tempdb..#tbl_Workflow') is not null begin drop table #tbl_Workflow end      

			create table #tbl_Workflow
			(
				Row_Id int identity(1,1),
				StageId bigint not null,
				StageName varchar(100) not null,
				SequenceNo int not null,
				StageType varchar(5) not null,
				ActionCode varchar(10),
				JsonStageData nvarchar(max),
				ScheduledAfterHrs varchar(10),
				--ScheduledField varchar(50),
				--ScheduledOperator varchar(10),
				Webhook varchar(500),
				JsonCondition nvarchar(max)
			)

			-- declare @jsonStageList nvarchar(max)=N'[{"StageId":0,"StageName":"Trigger Condition","SequenceNo":1,"StageType":"TC","ActionCode":"","JsonStageData":{},"ScheduledAfterHrs":"","Webhook":"","lstCondition":[]},{"StageId":0,"StageName":"Action 1","SequenceNo":2,"StageType":"AS","ActionCode":"ADD_APMT","JsonStageData":{"Title":"Title","Description":"Description","Remarks":"Remarks","FromDate":"-1","DueDate":"1","Where":"Delhi","Address":"vikaspuri","Owner":"32222","Collaborators":["32226"]},"ScheduledAfterHrs":"","Webhook":"","lstCondition":[]},{"StageId":0,"StageName":"Action 2","SequenceNo":3,"StageType":"AC","ActionCode":"ADD_DEAL","JsonStageData":{"DealValue":"566","DealPipeline":"15","DealStage":"102","Probability":"89","DealOwner":"32222","EstimatedClosureDate":"2"},"ScheduledAfterHrs":"","Webhook":"","lstCondition":[{"SequenceNo":1,"Operand1":"Action2_LeadPipelineMapping_Entity.Entity.leadno","Operator":">","Operand2":"0","Conjunction":"AND","ConditionType":"pre"}]},{"StageId":0,"StageName":"Action 3","SequenceNo":4,"StageType":"AW","ActionCode":"VOI_TO_LD","JsonStageData":{"MobileNo":true,"MobileNo1":false,"MobileNo2":false,"Route":"promo","CallerID":"1204759570","appid":"931","Duration":"1"},"ScheduledAfterHrs":"scheduled","Webhook":"","lstCondition":[{"SequenceNo":1,"Operand1":"EstimatedClosureDate_ddlAction2_conditional_num3","Operator":">=","Operand2":"3","Conjunction":"OR","ConditionType":""}]}]'


			Insert into	#tbl_Workflow
			Select	StageId, StageName, SequenceNo, StageType, ActionCode, JsonStageData, ScheduledAfterHrs, Webhook, lstCondition
			from openjson(@jsonStageList)
			With
			(
				StageId				int						'$.StageId',
				StageName			varchar(100)			'$.StageName',
				SequenceNo			int						'$.SequenceNo',
				StageType			varchar(2)				'$.StageType',
				ActionCode			varchar(10)				'$.ActionCode',
				[JsonStageData]		nvarchar(max) as json,
				ScheduledAfterHrs	varchar(50)				'$.ScheduledAfterHrs',
				Webhook				varchar(500)			'$.Webhook',
				[lstCondition]		nvarchar(max) as json
			)

			Select @WflCnt=count(*) from #tbl_Workflow

			While(@RowId <= @WflCnt)
			Begin
				Select @StageId=StageId, @StageName=StageName, @SequenceNo=SequenceNo, @StageType=StageType, @ActionCode=ActionCode, @JsonStageData=JsonStageData, @Webhook=Webhook, @JsonCondition=JsonCondition, @ScheduledHrsType=ScheduledAfterHrs
				From #tbl_Workflow 
				Where Row_Id=@RowId

				If(@ScheduledHrsType='scheduled')
				Begin
					select @ScheduledAfterHrs=Operand2, @ScheduledOperator=Operator, @ScheduledField=Operand1
					from openjson(@JsonCondition)
					with
					(
						Operand1		varchar(100)	'$.Operand1',
						Operator		varchar(50)		'$.Operator',
						Operand2		varchar(100)	'$.Operand2'
					)
				End

				insert into tbl_wf_WorkflowStageMaster(StageName, SequenceNo, WorkflowId, StageType, TriggerId, ActionCode, IsActive, Webhook, ScheduledAfterHrs, JsonStageData, ScheduledOperator, ScheduledField)
				values(@StageName, @SequenceNo, @WorkflowId, @StageType, @EventId, @ActionCode, 1, @Webhook, @ScheduledAfterHrs, @JsonStageData, @ScheduledOperator, @ScheduledField)
				Set @StageId=SCOPE_IDENTITY()

				insert into tbl_wf_WorkflowStageConditionMaster(StageId, SequenceNo, Operand1, Operator, Operand2, Conjunction, ConditionType, WorkflowId, IsActive)
				select @StageId, SequenceNo, Operand1, Operator, Operand2, Conjunction, ConditionType, @WorkflowId, 1
				from openjson(@JsonCondition)
				With
				(
					SequenceNo		int				'$.SequenceNo',
					Operand1		varchar(100)	'$.Operand1',
					Operator		varchar(50)		'$.Operator',
					Operand2		varchar(100)	'$.Operand2',
					Conjunction		varchar(10)		'$.Conjunction',
					ConditionType	varchar(10)		'$.ConditionType'
				)
				Where @ScheduledHrsType != 'scheduled'

				Set @RowId=@RowId+1
			End

			Select @WorkflowId as Code, 'Workflow Saved Successfully' as Msg

			End
	End

END



GO

/* ============================================================
   Procedure: [dbo].[usp_wf_SendMailFromLeads]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Action Code => ( EM_TO_LD, EM_TO_ASG, EM_TO_CRE )  
CREATE   PROCEDURE [dbo].[usp_wf_SendMailFromLeads]
(
 @IDS varchar(max),  
 @Account bigint,  
 @Email_Subject varchar(1000), 
 @Message varchar(max), 
 @SenderName varchar(100), 
 @ReplyTo varchar(1000), 
 @EmailId bit, 
 @EmailId1 bit, 
 @EmailId2 bit, 
 @UserId bigint=0, 
 @RefHistoryId bigint=0,  
 @WorkFlowId bigint=null
 )
AS  
BEGIN       
-- DECLARE @tbl_Response AS tbl_response;  
BEGIN TRY  
 --select @Email_Subject=isnull(nullif(@Email_Subject,''),(select mailsubject from UserMailTemplate(nolock) where id=@message_templateID))  
 PRINT '-------------BEGIN------------------------------------ usp_wf_SendMailFromLeads ----------------------------------------------';  
 PRINT '@IDS: ' + CAST(@IDS AS varchar);  
 PRINT '@Account: ' + CAST(@Account AS varchar);  
 PRINT '@Email_Subject: ' + CAST(@Email_Subject AS varchar);  
 PRINT '@Message: ' + CAST(@Message AS varchar);  
 PRINT '@SenderName: ' + CAST(@SenderName AS varchar);  
 PRINT '@ReplyTo: ' + CAST(@ReplyTo AS varchar);  
 PRINT '@EmailId: ' + CAST(@EmailId AS varchar);  
 PRINT '@EmailId1: ' + CAST(@EmailId1 AS varchar);  
 PRINT '@EmailId2: ' + CAST(@EmailId2 AS varchar);  
 PRINT '@UserId: ' + CAST(@UserId AS varchar);  
 PRINT '@RefHistoryId: ' + CAST(@RefHistoryId AS varchar);  
 PRINT '@WorkFlowId: ' + CAST(isnull(@WorkFlowId,'') AS varchar);  
  
 DECLARE @MailCount bigint, @IsMonitor bit= 1;  
 DECLARE @m_id bigint, @parentid bigint;  
 SELECT @m_id = ud.M_ID, @parentid = parentid  
 FROM User_Detail AS ud(NOLOCK)  
 WHERE ud.[User_ID] = @Account;  
 SELECT @MailCount =  
 (  
  SELECT COUNT(1)  
  FROM dbo.fn_split( @IDS, '#' )  
 );  
 DECLARE @CurrentBalance bigint=  
 (  
  SELECT TOP 1 mcd.Balance  
  FROM MailCreditDetails AS mcd(NOLOCK)  
  WHERE mcd.[User_ID] = @parentid  
  ORDER BY mcd.Credit_ID DESC  
 );  
  
 DECLARE @Balance bigint= @CurrentBalance - @MailCount;  
 IF @Balance > 0  
 BEGIN  
  
  SELECT A.EmailID, A.AccountID, A.SenderName, A.MailContent, A.MailSubject, A.ReplyTo, A.leadid  
  INTO #tempTableSendMail  
  FROM  
  (  
   SELECT ISNULL(A.EmailID, '') AS EmailID, @Account AS AccountID, @SenderName AS SenderName, A.MailContent, @Email_Subject AS MailSubject, @ReplyTo AS ReplyTo, Leadid  
   FROM  
   (  
    SELECT CASE  
        WHEN @EmailId = 1 THEN ul.EmailID  
        ELSE ''  
        END AS EmailID, dbo.fn_getLeadsMailMessage( ul.ParentID, @Message, ul.EmailID ) AS MailContent, ul.ID AS leadid  
    FROM UserLeads AS ul(NOLOCK)  
    WHERE ul.ID IN  
    (  
     SELECT [value]  
     FROM dbo.fn_Split( @IDS, '#' ) AS fs  
    ) AND   
       ISNULL(NULLIF(CAST(ul.EmailID AS varchar), ''), '') <> '' AND   
       ISNULL(NULLIF(CAST(ul.EmailID AS varchar), ''), '') NOT IN  
    (  
     SELECT ISNULL(C_UDTemp.Email, '') AS EmailID  
     FROM UserLeads AS UETemp(NOLOCK)  
       INNER JOIN  
       Client_UnSubscribeDetails AS C_UDTemp(NOLOCK)  
       ON(UETemp.EmailID = C_UDTemp.Email)  
     WHERE ul.ID IN  
     (  
      SELECT fs.value  
      FROM dbo.fn_Split( @IDS, '#' ) AS fs  
     )  
    )  
    UNION ALL  
    SELECT CASE  
        WHEN @EmailId1 = 1 THEN ul.EmailID1  
        ELSE ''  
        END AS EmailID, dbo.fn_getLeadsMailMessage( ul.ParentID, @Message, ul.EmailID1 ), ul.ID AS leadid  
    FROM UserLeads AS ul(NOLOCK)  
    WHERE ul.ID IN  
    (  
     SELECT [value]  
     FROM dbo.fn_Split( @IDS, '#' ) AS fs  
    ) AND   
       ISNULL(NULLIF(CAST(ul.EmailID1 AS varchar), ''), '') <> '' AND   
       ISNULL(NULLIF(CAST(ul.EmailID1 AS varchar), ''), '') NOT IN  
    (  
     SELECT ISNULL(C_UDTemp.Email, '') AS EmailID  
     FROM UserLeads AS UETemp(NOLOCK)  
       INNER JOIN  
       Client_UnSubscribeDetails AS C_UDTemp(NOLOCK)  
       ON(UETemp.EmailID1 = C_UDTemp.Email)  
     WHERE ul.ID IN  
     (  
      SELECT fs.value  
      FROM dbo.fn_Split( @IDS, '#' ) AS fs  
     )  
    ) AND   
     ISNULL(NULLIF(CAST(ul.EmailID2 AS varchar), ''), '') <> '' AND   
     ISNULL(NULLIF(CAST(ul.EmailID2 AS varchar), ''), '') NOT IN  
    (  
     SELECT ISNULL(C_UDTemp.Email, '') AS EmailID  
     FROM UserLeads AS UETemp(NOLOCK)  
       INNER JOIN  
       Client_UnSubscribeDetails AS C_UDTemp(NOLOCK)  
       ON(UETemp.EmailID2 = C_UDTemp.Email)  
     WHERE ul.ID IN  
     (  
      SELECT fs.value  
      FROM dbo.fn_Split( @IDS, '#' ) AS fs  
     )  
    )  
    UNION ALL  
    SELECT CASE  
        WHEN @EmailId2 = 1 THEN ul.EmailID2  
        ELSE ''  
        END AS EmailID, dbo.fn_getLeadsMailMessage( ul.ParentID, @Message, ul.EmailID2 ), ul.ID AS leadid  
    FROM UserLeads AS ul(NOLOCK)  
    WHERE ul.ID IN  
    (  
     SELECT [value]  
     FROM dbo.fn_Split( @IDS, '#' ) AS fs  
    )  
   ) AS A  
   WHERE ISNULL(A.EmailID, '') <> ''  
  ) AS A;  
  
  
  
  DECLARE @Status bigint= 0, @CountLimit bigint= 0;  
  SELECT @Status = STATUS, @CountLimit = Plimit  
  FROM ProcessMailLimit;  
  IF(@Status = 1)  
  BEGIN  
   BEGIN  
    IF(@MailCount > @CountLimit)  
    BEGIN  
     SET @IsMonitor = 0;  
    END;  
   END;  
  END;  
  
  
  
  DECLARE @BatchID bigint;  
  BEGIN TRAN;  
  INSERT INTO GetBatchRecord( [User_id], RandNum )  
  VALUES( @Account, @Account );  
  SELECT @BatchID = SCOPE_IDENTITY();  
  DELETE FROM GetBatchRecord  
  WHERE batchid = @BatchID;  
  COMMIT;  
  
  
  DECLARE @Mail_FromEmail varchar(500)= '';  
  
  SELECT @Mail_FromEmail = COALESCE(  
  (  
   SELECT TOP 1 mail_id  
   FROM defaultmailid(NOLOCK)  
   WHERE user_id = @account  
   ORDER BY datecreated DESC  
  ),  
  (  
   SELECT ud.EMail  
   FROM User_Detail AS ud(NOLOCK)  
   WHERE ud.[User_ID] = @Account  
  ), 'contactus@email19.in');  
  
  INSERT INTO CloneEmailsFilter( Mail_FromEmail, Mail_ToEmail, Mail_Subject, Mail_TempleteName, Messages, Mail_InsertedDate, Mail_UserID, Mail_ParentID, ReplyTo, Mail_BatchID, Mail_Priority, Mail_ScheduleDate, Mail_ScheduledTime, Mail_Attechement, Mail_TempleteBody, IsMonitor, TemplateID, Count, Source )  
      SELECT @Mail_FromEmail, A.EmailID, A.MailSubject, '', A.MailContent, GETDATE(), A.AccountID, @parentid, A.ReplyTo, @BatchID, 1, '', '', '', A.MailContent, @ismonitor, 0, @mailcount, 'Leads-MassSend'  
      FROM #tempTableSendMail AS A;  
  
  IF(@UserId > 0)  
  BEGIN  
   DECLARE @leadActivityHistory AS leadactivitywithid_tbltype;  
   DECLARE @Username nvarchar(255)=  
   (  
    SELECT User_Login  
    FROM User_Detail(NOLOCK)  
    WHERE User_Id = @UserId  
   );  
   INSERT INTO @leadActivityHistory( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )  
       SELECT leadid, @UserId, @parentid, concat(@Username, ' sent a mail with subject ', MailSubject, ' to emailid ', EmailID), 'Mail sent to lead', 'Batchemail_infos', @BatchID  
       FROM #tempTableSendMail;  
  
   EXEC usp_wf_SaveLeadActivity_withMultipleValue_withid @leadActivityHistory, 'BatchID', @RefHistoryId, @WorkFlowId;  
  END;  
  
  --INSERT INTO @tbl_Response( ScopeId, ResponseId, ResponseText) VALUES( '0', '1', 'success' );  
  INSERT INTO tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) VALUES(@@SPID, '0', '1', 'success' );  
 END;  
 ELSE  
 BEGIN  
  --INSERT INTO @tbl_Response( ScopeId, ResponseId, ResponseText) VALUES( '0', '-2', 'Insufficient Balance' );  
  INSERT INTO tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) VALUES(@@SPID,'0', '-2', 'Insufficient Balance' );  
 END;  
  
 DROP TABLE #tempTableSendMail;  
  
 PRINT '-------------END------------------------------------ usp_wf_SendMailFromLeads ----------------------------------------------';  
END TRY  
BEGIN CATCH  
 Exec  usp_InsertErrorInfo  
 --INSERT INTO @tbl_Response( ScopeId, ResponseId, ResponseText) VALUES( '0', '-1', ERROR_MESSAGE() );  
 INSERT INTO tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) VALUES(@@SPID, '0', '-1', ERROR_MESSAGE() );  
END CATCH  
-- SELECT * FROM @tbl_Response;  
SELECT * FROM tbl_wf_WorkflowResponse;  
END  



GO

