   INTO #tempTableSendMailTempId  
   FROM  
   (  
    SELECT ISNULL(T.EmailID, '') AS EmailID, @Account AS AccountID, @SenderName AS SenderName, T.MailContent, @Email_Subject AS MailSubject, @ReplyTo AS ReplyTo, Leadid  
    FROM  
    (  
     SELECT UD.Email AS EmailID, dbo.fn_getLeadsUserMailMessage( ul.ID, ul.ParentID, @Message ) AS MailContent, ul.ID AS leadid
     FROM UserLeads AS ul(NOLOCK) inner join User_Detail(nolock) UD
	 On iif(@ActionCode = 'EM_TO_ASG',ul.AssignedTo,ul.createdBy)=UD.User_ID
     WHERE ul.ID IN  
     (  
      SELECT [value]  
      FROM dbo.fn_Split( @IDS, '#' ) AS fs  
     ) 
    AND ISNULL(UD.Email, '') <> ''  
   ) T 
   ) AS A;   
  
  
   DECLARE @Status bigint= 0, @CountLimit bigint= 0;  
