    WHERE ud.[User_ID] = @Account  
   ), 'contactus@email19.in');  
  
   INSERT INTO CloneEmailsFilter( Mail_FromEmail, Mail_ToEmail, Mail_Subject, Mail_TempleteName, Messages, Mail_InsertedDate, Mail_UserID, Mail_ParentID, ReplyTo, Mail_BatchID, Mail_Priority, Mail_ScheduleDate, Mail_ScheduledTime, Mail_Attechement, Mail_TempleteBody, IsMonitor, TemplateID, Count, Source )  
       SELECT @Mail_FromEmail, A.EmailID, A.MailSubject, ISNULL(@tname, ''), A.MailContent, GETDATE(), A.AccountID, @parentid, A.ReplyTo, @BatchID, 1, '', '', '', A.MailContent, @ismonitor, 0, @mailcount, 'Lead-MassSend'  
       FROM #tempTableSendMailTempId AS A;  
  
   PRINT '@Mail_FromEmail: ' + CAST(@Mail_FromEmail AS varchar);  
  
  
   IF(@UserId > 0)  
   BEGIN  
    DECLARE @leadActivityHistory AS leadactivitywithid_tbltype;  
    DECLARE @Username nvarchar(255)=  
    (  
     SELECT User_Login  
     FROM User_Detail(NOLOCK)  
     WHERE User_Id = @UserId  
    );  
    INSERT INTO @leadActivityHistory( LeadID, UserID, ParentID, EventDescription, EventName, RefTable, refid )  
        SELECT leadid, @UserId, @parentid, concat(@Username, ' sent a mail with subject ', MailSubject, ' to emailid ', EmailID), 'Mail sent to lead', 'Batchemail_infos', @BatchID  
        FROM #tempTableSendMailTempId;  
  
    EXEC usp_wf_SaveLeadActivity_withMultipleValue_withid @leadActivityHistory, 'BatchID', @RefHistoryId, @WorkFlowId;  
   END;  
  
   --INSERT INTO @tbl_Response( ScopeId, ResponseId, ResponseText) VALUES( '0', '1', 'success' );  
   INSERT INTO tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) VALUES(@@SPID, '0', '1', 'success' );  
  END;  
  ELSE  
  BEGIN  
   --INSERT INTO @tbl_Response( ScopeId, ResponseId, ResponseText) VALUES( '0', '-2', 'Insufficient Balance' );  
   INSERT INTO tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) VALUES(@@SPID, '0', '-2', 'Insufficient Balance' );  
  END;  
  
  DROP TABLE IF EXISTS #tempTableSendMailTempId;  
  
  PRINT '-------END------------------------------ usp_wf_SendMailFromLeads_WithTemplateIDToUser ----------------------------------------';  
 END TRY  
 BEGIN CATCH  
  Exec  usp_InsertErrorInfo  
  --INSERT INTO @tbl_Response( ScopeId, ResponseId, ResponseText) VALUES( '0', '-1', ERROR_MESSAGE() );  
  INSERT INTO tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) VALUES( @@SPID, '0', '-1', ERROR_MESSAGE() );  
 END CATCH;  
 --SELECT * FROM @tbl_Response;  
 SELECT * FROM tbl_wf_WorkflowResponse;  
END; 



GO

/* ============================================================
   Procedure: [dbo].[usp_wf_tsk_InsertNewAppointment]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Action Code => ADD_APMT  
CREATE   PROCEDURE usp_wf_tsk_InsertNewAppointment(    
 @RefHistoryId bigint,  
 @WorkFlowId bigint,  
 @StageId bigint,  
 @LeadId bigint,  
 @UserId bigint,  
 @ParentID bigint,  
 @JsonAction nvarchar(max)  
)  
AS                      
BEGIN   
 --declare @tbl_Response as tbl_Response  
 begin try  
  declare @KeyStr varchar(max),@ValueStr varchar(max), @EventDescription nvarchar(max), @ID bigint, @User_Login varchar(50), @TasKName varchar(255), @Title varchar(255), @LastExecDate datetime=getdate()  
  
   Select @User_Login=User_Login from User_Detail(nolock) Where USER_ID=@UserId

   INSERT INTO tbl_tsk_TaskHistory (Title, Description, Address, StartDate, EndDate, LeadId, AssignedTo, IsActive, CreatedOn, TaskId, CreatedBy, OutcomesId, STATUS, IsTask, IsAppointment, TaskType, CompleteAddress, Latitude, Longitude, Remarks)  
   select Title, [Description], [Where], DATEADD(hour,FromDate, @LastExecDate), DATEADD(hour, DueDate, @LastExecDate), @LeadId, [Owner] as AssignedTo, 1 as IsActive, GETDATE() as CreatedOn, 8 as TaskId, @UserId as CreatedBy, 0 as OutcomesId, 'open' as STATUS, 0 as IsTask, 1 as IsAppointment, '' as TaskType, CompleteAddress, NULL as Latitude, NULL as Longitude, Remarks   
   From openjson(@JsonAction)  
   with  
   (  
    Title   varchar(255),  
    [Description] varchar(1000),  
    [Where]   varchar(500),  
    FromDate  int,  
    DueDate   int,  
    [Owner]   bigint,  
    CompleteAddress varchar(500),  
    Collaborators nvarchar(4000),  
    Remarks   nvarchar(4000)  
   )  
  
   Set @ID=SCOPE_IDENTITY()  
   Select @Title=Title From tbl_tsk_TaskHistory(nolock) Where id=@ID  
   Select @TasKName=Cast(CreatedOn as varchar) From tbl_tsk_TaskHistory(nolock) Where id=@ID  
   Set @EventDescription = @User_Login + ' added an appointment with title ' + @Title + ' for ' + @TasKName  
   Exec usp_wf_SaveLeadActivity_withid @LeadId, @UserId, @ParentID, @EventDescription, 'Appointment Added', 'tbl_tsk_TaskHistory', @ID, 'Id', @RefHistoryId, @WorkFlowId 
  
   insert into tbl_tsk_CollaborationUserMapping(User_Id,CreatedOn,CreatedBy,TaskHistoryId)   
   select value AS UserId, GETDATE() as CreatedOn, @UserId as CreatedBy, @ID as TaskHistoryId   
   From STRING_SPLIT((select Collaborators  
   From openjson(@JsonAction)  
   with  
   (  
    Collaborators nvarchar(4000)  
   )  
   ),'#')  
   --insert into @tbl_Response values( cast(@ID as nvarchar), '1',  'success')  
   insert into tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) values (@@SPID, cast(@ID as nvarchar), '1',  'success')  
 end try  
 begin catch  
  Exec  usp_InsertErrorInfo  
  --insert into @tbl_Response values( '0', '-1',  ERROR_MESSAGE())  
  insert into tbl_wf_WorkflowResponse(SPId,ScopeId,ResponseId,ResponseText) values (@@SPID, '0', '-1',  ERROR_MESSAGE())  
 end catch  
   
 --select * from @tbl_Response   
 select * from tbl_wf_WorkflowResponse   
END;  



GO

