/* ============================================================
   Procedure: [dbo].[usp_wix_GetWebhooksLeadList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_wix_GetWebhooksLeadList]    
	@UserId bigint = 32222,
	@CreatedOn datetime = null, 
	@RequestJson nvarchar(max) = '',                  
	@PersonName nvarchar(max) = '',                  
	@ErrDesc nvarchar(max) = '',                  
	@IsProcessed bit= 0,                  
	@ProcessedDate datetime= null,
	@OffsetValue int = 40,
	@PagingSize int  = 20        
 as    
begin   
	--declare 
	--	@UserId bigint = 32222,
	--	@CreatedOn datetime = null, 
	--	@RequestJson nvarchar(max) = '',                  
	--	@PersonName nvarchar(max) = '',                  
	--	@ErrDesc nvarchar(max) = '',                  
	--	@IsProcessed bit= 0,                  
	--	@ProcessedDate datetime= null,
	--	@OffsetValue int = 40,
	--	@PagingSize int  = 20   

	declare 
		@StartPoint int  = (@OffsetValue + 1), @Endpoint int = (@OffsetValue + @PagingSize), @ParentId bigint = 0

	select @ParentId =  ParentID from User_Detail(nolock) where User_ID = @UserId

	 select * from ( select
		  row_number() over(partition by A.ParentId order by A.Id desc) as SNo,
		  count(A.ParentId) over() as TotalRow,
		  A.Id, 
		  FORMAT( A.CreatedOn, 'dd-MMM-yyyy HH:mm:ss' ) CreatedOn, 
		  A.RequestJson, 
		  en.PersonName, 
		  en.MobileNo, 
		  (
			case when A.isprocessed = 1 then 'true' when A.isprocessed = '' then 'false' end
		  ) as isprocessed, 
		  A.Processederror as ErrorDes, 
		  FORMAT(
			A.Processeddate, 'dd-MMM-yyyy HH:mm:ss'
		  ) Processeddate 
		from 
		  tbl_wix_Webhooks A 
		  left join UserEnquiry(nolock) en on a.EnquiryId = en.EnquiryId 
		where A.parentid = @ParentId 
			and 1 = (case when isnull(@ErrDesc, '') = '' then 1 
					when isnull(@ErrDesc, '') <> '' and A.Processederror like '%'+@ErrDesc+'%' then 1
				else 0 end )
			and 1 = (case when isnull(@CreatedOn, '') = '' then 1 
					when isnull(@CreatedOn, '') <> '' and cast( A.CreatedOn as date) = cast(@CreatedOn as date) then 1
				else 0 end )
			and 1 = (case when isnull(@RequestJson, '') = '' then 1 
					when isnull(@RequestJson, '') <> '' and A.RequestJson like '%'+@RequestJson+'%' then 1
				else 0 end )
			and 1 = (case when isnull(@PersonName, '') = '' then 1 
					when isnull(@PersonName, '') <> '' and en.PersonName like '%'+@PersonName+'%' then 1
				else 0 end )
			and 1 = (case when isnull(@ProcessedDate, '') = '' then 1 
					when isnull(@ProcessedDate, '') <> '' and cast( A.Processeddate as date) = cast(@ProcessedDate as date) then 1
				else 0 end ) ) b where b.SNo between @StartPoint and @Endpoint
  
  
END 




GO

