   Procedure: [dbo].[usp_wix_GetWixApiKeyList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_wix_GetWixApiKeyList(
	@UserId bigint = 34594,
	@FilterText nvarchar(225) = '',
	@OffsetValue int = 0,
	@PagingSize int = 10
)
as
begin
	--declare 
	--	@UserId bigint = 34594,
	--	@FilterText nvarchar(225),
	--	@OffsetValue int = 0,
	--	@PagingSize int = 10

	declare 
		@StartPoint int = (@OffsetValue + 1), 
		@EndPoint int = (@OffsetValue + @PagingSize),
		@ParentId bigint = 0

	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId

	select * from ( select 
	 row_number() over(partition by parentid order by id desc) as SNo,
	 count(parentid) over() as TotalRecords,		
	 id, parentid, [key], createdby, isactive, createdon, wix_name
	from tbl_Wix_apiKey(nolock)
		where parentid = @ParentId and isactive	 = 1
	) t where t.SNo	between @StartPoint	and @EndPoint

end



