/* ============================================================
   Procedure: [dbo].[usp_wix_ManageWixOperationByMode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_wix_ManageWixOperationByMode(
	@Mode nvarchar(25) = 'get',
	@ApiKeyId bigint = 0,
	@ApiKey nvarchar(255) = '',
	@ApiKeyName nvarchar(255) = '',
	@SettingJSON nvarchar(max) = '',
	@UserId bigint = 0
)
as
begin
	
	--declare 
	--	@Mode nvarchar(25) = N'save_mapping',
	--	@ApiKeyId bigint = N'8',
	--	@ApiKey nvarchar(255) = N'',
	--	@ApiKeyName nvarchar(255) = N'',
	--	@SettingJSON nvarchar(max) = N'{"SourceSetting":{"id":"585749","name":"ServiceTicketSignup"},"MediumSetting":{"id":"406149","name":"WixApi"},"CampaignSetting":{"id":"60721","name":"ghdhtdghd"},"colMappings":[{"country_code":"","wix_field_name":"field:comp-lq26rmcd","wix_field_path":"data.field:comp-lq26rmcd","enquir_col_name":"addresstt","default_value":""},{"country_code":"","wix_field_name":"formName","wix_field_path":"data.formName","enquir_col_name":"PersonName","default_value":""},{"country_code":"+93","wix_field_name":"field:comp-lq26v2kr","wix_field_path":"data.field:comp-lq26v2kr","enquir_col_name":"MobileNo","default_value":"+93"}]}',
	--	@UserId bigint = 34594


	declare @ParentId bigint
	select @ParentId = ParentID from User_Detail(nolock) where User_ID = @UserId
	
	declare @status bit = 0, @message nvarchar(255) = 'failed', @data nvarchar(max) = '{}'

	if(@Mode = 'get')
	begin
		set @data = ( select * from tbl_wix_FormFieldMappingSetting(nolock) 
			where apiKeyId = @ApiKeyId and isactive = 0 for json path)
		select @status = 1, @message = 'success'
	end

	if(@Mode = 'create')
	begin
		if(not exists(select 1 from tbl_Wix_apiKey(nolock) where [key] = @ApiKey and isactive = 1))
		begin
			insert into tbl_Wix_apiKey(parentid, [key], createdby, isactive, createdon, wix_name)
				select @ParentId, @ApiKey, @UserId, 1, GETDATE(), @ApiKeyName

			set @data = (select SCOPE_IDENTITY() as ApiKeyId for json path, without_array_wrapper)

			select @status = 1, @message = 'success'
		end
		else
		begin
			select @status = 0, @message = 'exists'
		end
	end

	if(@Mode = 'update')
	begin
		update tbl_Wix_apiKey set wix_name = @ApiKeyName, [key] = @ApiKey where id = @ApiKeyId	
		select @status = 1, @message = 'success'
	end

	if(@Mode = 'remove')
	begin
		update tbl_Wix_apiKey set isactive = 0 where id = @ApiKeyId	
		select @status = 1, @message = 'success'
	end

	if(@Mode = 'mapping')
	begin
		select top 1 @data = RequestJson from tbl_wix_Webhooks(nolock) 
			where ParentId = @ParentId and api_key_id = @ApiKeyId order by 1 desc

		select 
			@status = case when len(@data) > 3 then 1 else  0 end, 
			@message = 'success'
	end

	if(@Mode = 'save_mapping')
	begin
		print 'save_mapping'

		declare @fmsId bigint = 0, @SourceId bigint, @MediumId bigint, @CampaignId bigint, @colMappings nvarchar(max)
;
		if(exists( select 1 from tbl_wix_FormFieldMappingSetting(nolock) 
				where apiKeyId = @ApiKeyId and parentid = @ParentId))
		begin
			select @fmsId = id from tbl_wix_FormFieldMappingSetting(nolock) 
				where apiKeyId = @ApiKeyId and parentid = @ParentId
		end

		select @SourceId = SourceId, @MediumId = MediumId, @CampaignId = CampaignId, @colMappings = colMappings
			from openjson(@SettingJSON) with(
				SourceId bigint '$.SourceSetting.id',
				MediumId bigint '$.MediumSetting.id',
				CampaignId bigint '$.CampaignSetting.id',
				colMappings nvarchar(max) '$.colMappings' as json
			)

			-- @ParentId, @UserId, GETDATE(), 1, GETDATE(), @SettingJSON, SourceId, MediumId, CampaignId, @ApiKeyId, colMappings
		
		if(@fmsId > 0)
		begin
			update tbl_wix_FormFieldMappingSetting set 
				modifiedon = GETDATE(), 
				settingJson = @SettingJSON,
				sourceId = @SourceId, 
				mediumId = @MediumId, 
				campaignId = @CampaignId,
				apiKeyId = @ApiKeyId,
				colMappings = @colMappings 
			where id = @fmsId
		end
		else
		begin
			insert into tbl_wix_FormFieldMappingSetting(parentid, createdby, createdon, isactive, modifiedon, settingJson, sourceId, mediumId, campaignId, apiKeyId, colMappings) 
			select @ParentId, @UserId, GETDATE(), 1, GETDATE(), @SettingJSON, @SourceId, @MediumId, @CampaignId, @ApiKeyId, @colMappings
			set @fmsId = SCOPE_IDENTITY()
		end

		set @data = (select SCOPE_IDENTITY() as SettingId for json path, without_array_wrapper)

		select @status = 1, @message = 'success'
	end

	select @status as [status], @message as [message], @data as [data]

end



GO

