/* ============================================================
   Procedure: [dbo].[usp_wix_SaveFeildMapping]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_wix_SaveFeildMapping]       
 @WixFieldMapping WixFieldMapping readonly,  @ParentId bigint, @CreatedBy bigint      
AS      
BEGIN      
 --declare  @WixMapping WixMapping ,  @ParentId bigint=34594, @CreatedBy bigint=34594  
 DECLARE @Id INT,  @SID BIGINT      
 DROP TABLE IF EXISTS #tempWixMapping     
      
 SELECT * INTO #tempWixMapping from @WixFieldMapping     
 IF(EXISTS(SELECT 1 FROM #tempWixMapping))     
 BEGIN     
    
  delete f from #tempWixMapping m    
  inner join tbl_wix_FormFieldMapping(nolock) f on  f.ParentId = @ParentId  
  
  INSERT INTO tbl_wix_FormFieldMapping  ( wixFieldName, EnFieldName, CreatedOn, ParentId,CreatedBy,DefaultValue )      
   SELECT wixFieldName, EnFieldName, GETDATE(), @ParentId, @CreatedBy,DefaultValue from #tempWixMapping     
  
 END      
END;      



