/* ============================================================
   Procedure: [dbo].[usp_wix_saveWebhooks]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_wix_saveWebhooks](  
	@RequestJson nvarchar(max),
	@ApiKey nvarchar(255) = '',
	@ParentId bigint     
)        
as        
begin   
