/* ============================================================
   Procedure: [dbo].[UspAddImportList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[UspAddImportList]   
(  
 @ImportName varchar(250),  
 @Column1 varchar(50),   
 @Column2 varchar(50),   
 @Column3 varchar(50),   
 @Column4 varchar(50),   
 @Column5 varchar(50),   
 @Column6 varchar(50),   
 @Column7 varchar(50),   
 @Column8 varchar(50),   
 @Column9 varchar(50),   
 @Column10 varchar(50),    
 @ParentID Bigint,  
 @CreatedBy Bigint  
)  
as  
Begin  
if not exists (select 'x' from UserImportedListColumn where ParentID = @ParentID and ImportName = @ImportName)  
 Begin  
    insert into UserImportedListColumn  
    (ImportName,Column1,Column2,Column3,Column4,Column5,Column6,Column7,Column8,Column9,             Column10,ParentID,CreatedOn,CreatedBy  
    )  
    values  
    (  
      @ImportName,@Column1,@Column2,@Column3,@Column4,@Column5,@Column6,@Column7,@Column8,  
      @Column9,@Column10,@ParentID,GETDATE(),@CreatedBy  
    )  
    select 'Success'   
 End  
else  
  Begin  
   select 'Already Exists'   
  End  
End


GO

/* ============================================================
   Procedure: [dbo].[UspAddMobSeries]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE dbo.UspAddMobSeries
(
  @CountryCode nvarchar(10),
  @MobSeries nvarchar(20)
)
as
Begin
  if(not exists(select 'x' from MobExceptionSeries where CountryCode=@CountryCode and MobSeries            = @MobSeries))
     Begin
         insert into MobExceptionSeries(CountryCode,MobSeries)values(@CountryCode,@MobSeries)
         select 'Record Saved'
         
     End
     else
         Begin
           select 'Record Already Exists'
         End

End








