/* ============================================================
   Procedure: [dbo].[UspBindGroupby]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------


CREATE   PROC [dbo].[UspBindGroupby]
@group_id bigint
as

SELECT     Group_Detail.Group_Name, Contact_Detail.Contact_Name, Contact_Detail.Contact_Mobile, Contact_Detail.Contact_Email, 
                      Contact_Detail.Group_ID
FROM         Contact_Detail LEFT OUTER JOIN
                      Group_Detail ON Contact_Detail.Group_ID = Group_Detail.Group_ID where Contact_Detail.group_id=@group_id





GO

