/* ============================================================
   Procedure: [dbo].[UspDataTransferFromKit19ToCRM_UserSetup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
  
CREATE   PROCEDURE dbo.UspDataTransferFromKit19ToCRM_UserSetup    
(    
  @BeginID bigint,    
  @EndID  bigint     
)    
as    
Begin    
    
  CREATE TABLE #TempLinked                                    
    (                                    
      Result VARCHAR(200)                                    
    )           
                      
     INSERT INTO #TempLinked                                    
     EXEC GetStatusofLinkedServer 'CRM'                                    
     IF NOT EXISTS(                                    
        SELECT 'x'                                    
        FROM   #TempLinked                                    
    )                         
    begin     
            
   insert into CRM.CRMDB.dbo.UserSetUpStages    
   (    
    [Enqno]      
      ,[kit19user_id]      
      ,[StageType]      
      ,[SetUpStage]      
      ,[StageStatus]      
      ,[StageScore]      
      ,[StageDate]      
      ,[CreatedOn]      
      ,[Createdby]
	  ,BatchID    
   )    
   select   [Enqno]      
      ,[kit19user_id]      
      ,[StageType]      
      ,[SetUpStage]      
      ,[StageStatus]      
      ,[StageScore]      
      ,[StageDate]      
      ,[CreatedOn]      
      ,[Createdby]    
       ,BatchID 
   from UserSetUpStages where Id >= @BeginID and id <= @EndID     
     
 End    
    
 drop table #TempLinked;    
    
 select 'Record Saved'    
    
End  
  
  
  
  


GO

