CREATE   PROCEDURE [dbo].[UspDeleteAddwordCampaign]
(    
  @CampaignId bigint    
)    
as    
Begin    
      
   update tblCampaign set IsDeleted = 1 where CampaignId = @CampaignId      
   update tblAdGroup set IsDeleted = 1 where CampAd_id in (select CampAd_id from tblCampaign where CampaignId = @CampaignId)      
   update tblAds set IsDeleted = 1 where CampaignId in (select CampAd_id from tblCampaign where CampaignId = @CampaignId)
  
   --update tblCampaign set IsActive = 0 where isnull(InProcess,0) = 0 and CampaignId = @CampaignId      
   --update tblAdGroup set IsActive = 0 where isnull(InProcess,0) = 0 and CampAd_id = @CampaignId      
   --update tblAds set IsActive = 0 where isnull(InProcess,0) = 0 and CampaignId = @CampaignId     
       
  --delete from tblCampaign where CampaignId = @CampaignId     
  --delete from tblAdGroup where CampAd_id = @CampaignId    
  --delete from tblAds where CampaignId = @CampaignId    
     
  select 'Record Deleted'    
       
End
 



