/* ============================================================
   Procedure: [dbo].[UspFailedSMSStatusDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  CREATE   PROCEDURE [dbo].[UspFailedSMSStatusDetails] --27828,'','',null,null   --335,'se','hon','01/18/2017','01/25/2018'      
  (        
    @UserID int,      
    @UserLogin nvarchar(100)=null,      
    @MessageContent nvarchar(max)=null,      
    @FromDate  nvarchar(100) =null,      
    @Todate    nvarchar(100)=null         
  )        
   as         
  Begin       
  set @UserLogin = coalesce(@UserLogin,'')
  set @MessageContent = coalesce(@MessageContent,'')       
  set @FromDate = coalesce(@FromDate,dateadd(d,-1,getdate()))      
  set @Todate = coalesce(@ToDate,getdate())
  
  set @UserLogin = ''
  set @MessageContent = ''       
  set @FromDate = dateadd(d,-1,getdate())      
  set @Todate = getdate()       
        
SELECT [MessageInsertDate] as SentDate,u.user_login as UserName,[SenderID],count(batchid) as SMSCount,[Message],f.SmppID,[IsUniCode],[BatchID] FROM failedmessages f join user_detail u (nolock) on u.User_ID=f.U_ID where messageinsertdate between @FromDate 
  
and @Todate     
and u.user_login like '%'+@UserLogin+ '%' and Message like '%'+@MessageContent+ '%' and u.ParentSuperResellerId=@UserID      
group by [MessageInsertDate],u.user_login,[SenderID],[Message],f.SmppID,[IsUniCode],[BatchID]       
 end  
  
  


GO

