)  
AS    
BEGIN    
  
    --declare @SelectColList varchar(max)='LeadID' , @pivotCol varchar(200)='FieldName' ,   @PivotValueCol varchar(200)='Fieldvalue',   @TableExpr varchar(max)='customfieldLeadvalue(nolock) CFL inner join customfields(nolock) CF ON CFL.fieldID=CF.field_ID and CF.ParentID=36950',   @PivotColNameListTableExpr varchar(max)='customfields', @TableWhereExpr varchar(max) = 'CF.ParentID = 36950 and isactive=1',  @PivotColNameListWhereExpr varchar(max) = ' 1=1 ', @PivotColAggregateName varchar(100) = ' min ',  @FinalWhereExpr varchar(max) = ' LeadID = 595414 '    
  
    -- SET NOCOUNT ON added to prevent extra result sets from    
    -- interfering with SELECT statements.    
    SET NOCOUNT ON;    
    DECLARE @SQL nvarchar(max)    
    DECLARE @SQLSelect nvarchar(max)    
    DECLARE @SQLFrom nvarchar(max)    
    DECLARE @SQLPivot nvarchar(max)    
    DECLARE @CPivotColNameList nvarchar(max)    
    DECLARE @PivotColNameList nvarchar(max)    
    
    SET @CPivotColNameList=''    
    SET @SQLSelect = 'SELECT @CPivotColNameList=@CPivotColNameList + ''COALESCE([''+' + @pivotCol + '+''],0) AS [''+' + @pivotCol + '+''],'' FROM ' + @TableExpr + ' WHERE ' + @TableWhereExpr + ' GROUP BY ' + @pivotCol    
    --PRINT @SQLSelect    
    
    EXEC sp_executesql @SQLSelect,N'@CPivotColNameList varchar(max) output',@CPivotColNameList output    
       
    IF LEN(@CPivotColNameList) > 0    
    BEGIN    
        SET @CPivotColNameList = SUBSTRING(@CPivotColNameList,1,LEN(@CPivotColNameList)-1)    
        --PRINT @CPivotColNameList    
    END    
       
    SET @PivotColNameList=''    
    SET @SQLSelect = 'SELECT @PivotColNameList=@PivotColNameList + ''[''+' + @pivotCol + '+''],'' FROM ' + @PivotColNameListTableExpr + ' WHERE ' + @PivotColNameListWhereExpr + ' GROUP BY ' + @pivotCol    
    --PRINT @SQLSelect    
    
    EXEC sp_executesql @SQLSelect,N'@PivotColNameList varchar(max) output',@PivotColNameList output    
       
    IF LEN(@PivotColNameList) > 0    
    BEGIN    
        SET @PivotColNameList = SUBSTRING(@PivotColNameList,1,LEN(@PivotColNameList)-1)    
        --PRINT @PivotColNameList    
    END    
       
    SET @SQLSelect    = ' SELECT ' + @SelectColList + ',' + @CPivotColNameList    
    SET @SQLFrom    = ' FROM  ( SELECT ' + @SelectColList + ',' + @pivotCol + ',' + @PivotValueCol + ' FROM ' + @TableExpr + ') AS tblData'    
    SET @SQLPivot    = ' PIVOT ( ' + @PivotColAggregateName + '(' + @PivotValueCol + ')' + ' FOR ' + @pivotCol    
    SET @SQLPivot    = @SQLPivot + ' IN (' + @PivotColNameList + ')    ) AS tblPivot '    
    
    PRINT  cast(@SQLSelect as varchar(max))  
    PRINT  cast(@SQLFrom as varchar(max))  
    PRINT  cast(@SQLPivot as varchar(max))  
    PRINT  cast(@FinalWhereExpr as varchar(max))  
    SET @SQL =  @SQLSelect + @SQLFrom + @SQLPivot + ' Where ' + @FinalWhereExpr  
    EXEC sp_executesql  @SQL    
    
END  



GO

/* ============================================================
   Procedure: [dbo].[UspGenerateGuidForResetPWD]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.UspGenerateGuidForResetPWD --335    
(    
  @UserID int    
)    
as    
Begin    
  declare @Guid nvarchar(200)
  while(1=1)    
   Begin    
   set @Guid = NEWID()    
   if(not exists (select 'x' from user_detail where isnull(resetGuid,'') = @Guid ))    
   Begin    
   update user_detail set resetGuid =@Guid,resetrequested = GETDATE(),resetexpired = 0 where USER_ID= @UserID  
   break;    
   End    
   End     
   select resetGuid,resetrequested,resetexpired from User_Detail where USER_ID = @UserID    
    
End


GO

/* ============================================================
   Procedure: [dbo].[uspGetActivityList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*
if object_id('uspGetActivityList') is not null
begin
 drop procedure uspGetActivityList
end

command =

 uspGetActivityList 'USER'

*/
CREATE   PROC uspGetActivityList
(
	@search_text varchar(100)=''
)
AS
BEGIN

	if (@search_text <> '') BEGIN
		SELECT top 20 ID, EventName  FROM ActivityMaster(nolock) WHERE EVENTNAME  LIKE '%'+ COALESCE(@search_text,'') +'%' 
	END
	ELSE  BEGIN
		SELECT '0' AS ID, '' AS EventName 
	END

	
END


GO

