  @SMS Bit,      
  @Mail Bit        
      
)      
as      
      
Begin      
        
         
  --Declare @FromDate varchar(50) = '14/10/2017',@ToDate varchar(50) = '25/10/2017'      
  --Declare @SMS Bit = 1 , @Mail bit = 1       
  --Declare @UserLogin varchar(100) =  'sms19'      
        
  Declare @User_ID int       
            
  if(@UserLogin <> '')      
  Begin          
        
  select @User_ID = USER_ID from User_Detail where User_Login = @UserLogin                 
            
   select UCM.ID,      
      case when UCH.IsSMS = 1      
                then 'SMS'      
                else 'Mail'      
                end as Type,      
                (select User_Login  from User_Detail where User_ID = @User_ID) as UserLogin,      
                  UCM.CampaignName,UCM.NextExecuteDateTime,      
                  (select tbl1.CreatedOn from (    
                 SELECT CampaignID,CreatedOn FROM UserCampaignHistory UCH2 WHERE UCH2.ID = (select MIN(uch3.id) from UserCampaignHistory uch3 where uch3.CampaignID=uch2.CampaignID)) as tbl1 where tbl1.CampaignID = UCM.ID) as FirstExecutionDateTime,    
                   
                 (select tbl1.CreatedOn from (    
                 SELECT CampaignID,CreatedOn FROM UserCampaignHistory UCH2 WHERE UCH2.ID = (select max(uch3.id) from UserCampaignHistory uch3 where uch3.CampaignID=uch2.CampaignID)) as tbl1 where tbl1.CampaignID = UCM.ID) as LastExecutionDateTime,    
                  
                      
                      
               (      
            case when  UCM.NextExecuteDateTime < GETDATE() AND (SELECT top 1 UCH1.ID FROM USERCAMPAIGNHISTORY UCH1 where UCH1.CampaignID = UCM.ID ) IS NULL then 'Execution Not Attempted' WHEN UCM.NextExecuteDateTime > GETDATE()      
                             then 'Yet To Be Executed'  WHEN UCH.Step3=1 THEN 'Executed at' + ISNULL(CAST(STEP3DATETIME AS NVARCHAR),'') WHEN Step2=1 THEN  'Step2 Executed at'+ISNULL(CAST(STEP2DATETIME AS NVARCHAR),'') WHEN Step1=1 THEN 'Step1 Executed at
  
    
'+ ISNULL(CAST(STEP1DATETIME AS NVARCHAR),'') when UCH.Step1 = 0 then 'Execution Started at' + CAST(UCH.CreatedOn as varchar)      
                      end                   
                   ) as Status                
                     
     from UserCampaignMaster UCM(NoLock)      
    left outer join UserCampaignHistory UCH(Nolock)  on UCM.ID = UCH.CampaignID       
    where UCM.NextExecuteDateTime between CONVERT(datetime,@FromDate,104) and  CONVERT(datetime,@ToDate,104)      
          and (      
                 UCM.ParentID = @User_ID      
              )      
                
                
          and ( ( UCH.IsSMS =      case when @SMS = 1      
                                    then @SMS      
                                    else null      
                                    end      
                 )       
                 or      
                 (      
                    UCH.IsMail =      case when @Mail = 1      
                                    then @Mail      
                                    else null      
                                    end      
                 )                     
               )      
                and  (UCH.ID IS NULL OR uch.ID=(select MAX(id) from UserCampaignHistory uch1 where uch1.CampaignID=uch.CampaignID))     
     group by UCM.id,UCM.Createdby,UCM.CampaignName,NextExecuteDateTime,uch.IsSMS ,uch.CreatedOn ,uch.CampaignID,uch.id ,UCH.Step1,UCH.Step1DateTime,UCH.Step2,UCH.Step2DateTime,UCH.Step3,UCH.Step3DateTime       
     End      
   Else      
      Begin      
          
      --declare @CountID bigint =0    
      --  SELECT @CountID = Count(UCH.ID)FROM USERCAMPAIGNHISTORY UCH JOIN USERCAMPAIGNMASTER UCM ON UCH.CampaignID=UCM.ID    
                     
   select UCM.ID,      
      case when UCH.IsSMS = 1   
                then 'SMS'      
                else 'Mail'      
                end as Type,      
                (select User_Login  from User_Detail where User_ID = UCM.Createdby) as UserLogin,      
                UCM.CampaignName,UCM.NextExecuteDateTime,     
                (select tbl1.CreatedOn from (    
                 SELECT CampaignID,CreatedOn FROM UserCampaignHistory UCH2 WHERE UCH2.ID = (select MIN(uch3.id) from UserCampaignHistory uch3 where uch3.CampaignID=uch2.CampaignID)) as tbl1 where tbl1.CampaignID = UCM.ID) as FirstExecutionDateTime,    
                   
                 (select tbl1.CreatedOn from (    
                 SELECT CampaignID,CreatedOn FROM UserCampaignHistory UCH2 WHERE UCH2.ID = (select max(uch3.id) from UserCampaignHistory uch3 where uch3.CampaignID=uch2.CampaignID)) as tbl1 where tbl1.CampaignID = UCM.ID) as LastExecutionDateTime,    
                  
                     
                (      
            case when  UCM.NextExecuteDateTime < GETDATE() AND (SELECT top 1 UCH1.ID FROM USERCAMPAIGNHISTORY UCH1 where UCH1.CampaignID = UCM.ID ) IS NULL then 'Execution Not Attempted' WHEN UCM.NextExecuteDateTime > GETDATE()      
                             then 'Yet To Be Executed'  WHEN UCH.Step3=1 THEN 'Executed at' + ISNULL(CAST(STEP3DATETIME AS NVARCHAR),'') WHEN Step2=1 THEN  'Step2 Executed at'+ISNULL(CAST(STEP2DATETIME AS NVARCHAR),'') WHEN Step1=1 THEN 'Step1 Executed a
t  
    
'+ ISNULL(CAST(STEP1DATETIME AS NVARCHAR),'') when UCH.Step1 = 0 then 'Execution Started at' + CAST(UCH.CreatedOn as varchar)      
                      end                   
                   ) as Status                
                     
     from UserCampaignMaster UCM(NoLock)      
     left outer Join UserCampaignHistory UCH(Nolock)  on UCM.ID = UCH.CampaignID      
    where UCM.NextExecuteDateTime between CONVERT(datetime,@FromDate,104) and  CONVERT(datetime,@ToDate,104)      
          and (      
                1=1      
              )      
                
                
          and ( ( UCH.IsSMS =      case when @SMS = 1      
                                    then @SMS      
                                    else null      
                                    end      
                 )       
                 or      
                 (      
                    UCH.IsMail =      case when @Mail = 1      
                                    then @Mail      
                                    else null      
                                    end      
                 )                     
               )      
               and  (UCH.ID IS NULL OR uch.ID=(select MAX(id) from UserCampaignHistory uch1 where uch1.CampaignID=uch.CampaignID))      
                              group by UCM.id,UCM.Createdby,UCM.CampaignName,NextExecuteDateTime,uch.IsSMS ,uch.CreatedOn ,uch.CampaignID,uch.id ,UCH.Step1,UCH.Step1DateTime,UCH.Step2,UCH.Step2DateTime,UCH.Step3,UCH.Step3DateTime      
      End      
                 
  End               


