          --     )      
                and  (UCH.ID IS NULL OR uch.ID=(select MAX(id) from #temp2 uch1 (nolock) where uch1.CampaignID=uch.CampaignID))     
     group by UCM.id,UCM.Createdby,UCM.CampaignName,NextExecuteDateTime,uch.IsSMS ,uch.CreatedOn ,uch.CampaignID,uch.id ,UCH.Step1,UCH.Step1DateTime,UCH.Step2,UCH.Step2DateTime,UCH.Step3,UCH.Step3DateTime,ucm.MailReplyTo       
     End      
   Else      
      Begin      
          
      --declare @CountID bigint =0    
      --  SELECT @CountID = Count(UCH.ID)FROM #temp2 UCH JOIN #temp UCM ON UCH.CampaignID=UCM.ID    
                     
   select UCM.ID,ucm.mailreplyto,      
      case when UCM.MailReplyTo = ''      
                then 'SMS'      
                else 'Mail'      
                end as Type,      
                (select User_Login  from User_Detail where User_ID = UCM.Createdby) as UserLogin,      
                UCM.CampaignName,UCM.NextExecuteDateTime,     
                (select tbl1.CreatedOn from (    
                 SELECT CampaignID,CreatedOn FROM #temp2 UCH2 (nolock) WHERE UCH2.ID = (select MIN(uch3.id) from #temp2 uch3 (nolock)where uch3.CampaignID=uch2.CampaignID)) as tbl1 where tbl1.CampaignID = UCM.ID) as FirstExecutionDateTime,    
                   
                 (select tbl1.CreatedOn from (    
                 SELECT CampaignID,CreatedOn FROM #temp2 UCH2 (nolock) WHERE UCH2.ID = (select max(uch3.id) from #temp2 uch3 (nolock)where uch3.CampaignID=uch2.CampaignID)) as tbl1 where tbl1.CampaignID = UCM.ID) as LastExecutionDateTime,    
                  
                     
                (      
            case when  UCM.NextExecuteDateTime < GETDATE() AND (SELECT top 1 UCH1.ID FROM #temp2 UCH1 (nolock) where UCH1.CampaignID = UCM.ID ) IS NULL then 'Execution Not Attempted' WHEN UCM.NextExecuteDateTime > GETDATE()      
                             then 'Yet To Be Executed'  WHEN UCH.Step3=1 THEN 'Executed at ' + ISNULL(CAST(STEP3DATETIME AS NVARCHAR),'') WHEN Step2=1 THEN  'Step2 Executed at '+ISNULL(CAST(STEP2DATETIME AS NVARCHAR),'') WHEN Step1=1 THEN 'Step1 Executed at '+ ISNULL(CAST(STEP1DATETIME AS NVARCHAR),'') when UCH.Step1 = 0 then 'Execution Started at ' + CAST(UCH.CreatedOn as varchar)      
                      end                   
                   ) as Status                
                     
     from #temp UCM(NoLock)      
     left outer Join #temp2 UCH(Nolock)  on UCM.ID = UCH.CampaignID      
    where CONVERT(varchar, CONVERT(datetime, UCM.NextExecuteDateTime, 121), 112) between CONVERT(varchar, CONVERT(datetime, @FromDate, 103), 112)  and  CONVERT(varchar,dateadd(d,1,CONVERT(datetime,@ToDate, 103)), 112)       
          and (      
                1=1      
              )      
               and isnull(UCH.IsSMS,0) =(case when @both=0 and @SMS = 0      
                                    then 0 when @both=0 and IsMail=0 then 1 else isnull(uch.issms,0)     
                                    end)    
                
                
          --and ( ( UCH.IsSMS =      case when @SMS = 1      
          --                          then @SMS      
          --                          else null      
          --                          end      
          --       )       
          --       or      
          --       (      
          --          UCH.IsMail =      case when @Mail = 1      
          --                          then @Mail      
          --                          else null      
          --                          end      
          --       )                     
          --     )      
               and  (UCH.ID IS NULL OR uch.ID=(select MAX(id) from #temp2 uch1 where uch1.CampaignID=uch.CampaignID))      
                              group by UCM.id,UCM.Createdby,UCM.CampaignName,NextExecuteDateTime,uch.IsSMS ,uch.CreatedOn ,uch.CampaignID,uch.id ,UCH.Step1,UCH.Step1DateTime,UCH.Step2,UCH.Step2DateTime,UCH.Step3,UCH.Step3DateTime,ucm.MailReplyTo  order by NextExecuteDateTime     
      End      
      drop table #temp
      drop table #temp2
                 
  End               


