/* ============================================================
   Procedure: [dbo].[UspGetCustomFieldData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[UspGetCustomFieldData]    
@parentid BIGINT    
AS    
BEGIN     
 SET NOCOUNT ON    
 --declare @parentid bigint = 34594    
 SELECT field_ID,fieldname,    
  (case     
   when datatype = 'd' then 'Date Time'    
   when datatype = 'f' then 'Numeric'    
   when datatype = 'v' then 'Text'    
     
   when datatype = 'r' then 'RadioBox'    
   when datatype = 'l' then 'List'    
   when datatype = 'c' then 'CheckBox'    
   when datatype = 'm' then 'Multiline'    
   when datatype = 's' then 'Select'    
  end ) as datatype,    
  ParentID,      
  sequence,    
  minvalue,    
  maxvalue,    
  addedon ,    
  isActive,    
  isMandatory,    
  defaultValue,    
  quickAdd,    
  currentDate,    
  tooltip,    
  choices    
 FROM customfields (NOLOCK)    
 WHERE ParentID=@parentid  and isActive=1  and datatype<>'e'  
 order by Sequence    
END


GO

