/* ============================================================
   Procedure: [dbo].[UspGetEnquiryMonthwise]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  CREATE   PROCEDURE dbo.UspGetEnquiryMonthwise --335        
  (        
    @UserID bigint          
  )          
  as        
  Begin        
      
    Declare @IsAdmin bit = 0       
        
    select @IsAdmin = isnull(IsAdmin,0) from User_Detail(nolock) where User_ID = @UserID      
      
      
   CREATE TABLE #TempMonth        
    (        
       MonthNum int,        
       MonthName varchar(50),    
    Dates nvarchar(50)        
    )        
            
 CREATE TABLE #EnquirySummary        
     (        
      MonthNum int,        
      MonthName varchar(50),        
      Count  int,    
   Dates nvarchar(50)                 
    )        
        
 INSERT INTO  #TempMonth         
    SELECT STR(MONTH(DATEADD(mm, -number, GETDATE())), 2) AS MonthNum,         
    DATENAME(month, DATEADD(month, MONTH(DATEADD(mm, -number, GETDATE())), 0) - 1) AS MonthName,    
    DATEAdd(mm, -number, GETDATE())  AS Dates     
    FROM master.dbo.spt_values        
    WHERE (name IS NULL) AND (number BETWEEN 0 AND 11) ORDER BY DATEAdd(mm, -number, GETDATE())   --STR(MONTH(DATEADD(mm, number, GETDATE())), 2)        
        
    --SELECT * FROM #TempMonth order by MonthNum asc        
            
 INSERT INTO  #EnquirySummary        
 select  MonthNum,MonthName,        
    count(CreatedDate) over(partition by datepart(year,CreatedDate),DATEPART(MONTH,CreatedDate)) as Count        
    ,Dates    
 from UserEnquiry(nolock) a         
     join #TempMonth b on DATEPART(MONTH,CreatedDate) = b.MonthNum and datepart(year,CreatedDate) = datepart(year,b.Dates)        
     where        
     @UserID =      
        case when @IsAdmin = 0      
      then (a.CreatedBy)       
      else       
           (a.ParentID)      
    end         
        
      order by MonthName        
             
        
  --select distinct * from #EnquirySummary order by MonthName          
          
  select TM.MonthNum,TM.MonthName,TM.Dates        
    ,(        
       case when exists(select top 1 1  from #EnquirySummary as ES  where Es.MonthNum = TM.MonthNum)        
          then (select top 1 ES1.Count  from #EnquirySummary as ES1 where ES1.MonthNum = TM.MonthNum)        
    else 0        
    end         
     )as Count           
          
          
     from #TempMonth as TM  order by convert(date,TM.Dates) desc        
         
        
  DROP Table #TempMonth        
  DROP Table #EnquirySummary        
        
  End 


GO

