/* ============================================================
   Procedure: [dbo].[UspGetHeirarchicalDisplay]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.UspGetHeirarchicalDisplay      
As       
Begin      
      
WITH Hierarchy(ChildId, ChildName, Generation, ParentId,sequence)      
AS      
(      
    SELECT ID,MenuName, 0,MenuParentID ,Sequence     
        FROM Menu(nolock) AS FirtGeneration      
        WHERE MenuParentID = 0            
    UNION ALL      
    SELECT NextGeneration.Id, NextGeneration.MenuName, Parent.Generation + 1, Parent.ChildId  ,NextGeneration.Sequence    
        FROM Menu(nolock) AS NextGeneration      
        INNER JOIN Hierarchy AS Parent ON NextGeneration.MenuParentID = Parent.ChildId          
)       
    SELECT HR.ChildId, HR.ChildName, HR.Generation, HR.ParentId,HR.Sequence,   
   isnull( (select isnull(Path,'') from Page where ID = (select top 1 isnull(PageID,0)  from Menu(nolock) where id = HR.ChildId) ),'') as URL    
    FROM Hierarchy  as HR  order by HR.Sequence asc  
    OPTION(MAXRECURSION 32767)      
End 


GO

