    UNION ALL    
    SELECT NextGeneration.Id, NextGeneration.MenuName, Parent.Generation + 1, Parent.ChildId    
        FROM Menu AS NextGeneration    
        INNER JOIN Hierarchy AS Parent ON NextGeneration.MenuParentID = Parent.ChildId        
)     
    SELECT HR.ChildId, HR.ChildName, HR.Generation, HR.ParentId,  
   isnull( (select isnull(Path,'') from Page where ID = (select top 1 isnull(PageID,0)  from Menu where id = HR.ChildId) ),'') as URL  
    FROM Hierarchy  as HR  
    OPTION(MAXRECURSION 32767)    
End    


