      isnull((select top 1 Title from TBL_UA_ModuleMaster(nolock)   
   where ModuleId = (select top 1 isnull(ModuleID,0) from TBL_UA_ModuleMaster(nolock) where isnull(Active,0) = 1 and ModuleId = HR.ChildId) ),'') as Title,  
     isnull((select top 1 Tag from TBL_UA_ModuleMaster(nolock)   
   where ModuleId = (select top 1 isnull(ModuleID,0) from TBL_UA_ModuleMaster(nolock) where isnull(Active,0) = 1 and ModuleId = HR.ChildId) ),'') as Tag ,  
        isnull((select top 1 replace(ModuleDescription,'Kit19',@displayname) from TBL_UA_ModuleMaster(nolock)   
