  (select Cast(@IsAdmin as varchar(10)) + cast(@IsClassic as varchar(10)) + cast(@IsExpired as varchar(10)) + @ScopeCode + @RoleCode) RajnishUser,          
    isnull((select [View]                 
  from TBL_UA_RolePermissionMappingMaster(nolock) turpm                 
   inner join TBL_UA_EntityActionMappingMaster(nolock) tueam on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode                
   --inner join VW_SystemRole_RoleMaster urmm on urmm.RoleCode = turpm.RoleCode                
   --left join TBL_UA_ModuleMaster umod on umod.ModuleCode = turpm.ModuleCode                
   where turpm.ParentId = @ParentId and turpm.ScopeCode = @ScopeCode and turpm.RoleCode = @RoleCode and turpm.ModuleCode = HR.ChildCode), 0) [View],   
   ISNULL((
    SELECT 
        CASE 
            WHEN URL = '#' OR URL IS NULL THEN ''
            WHEN @DomainURL LIKE '%kit19.com%' THEN URL
            ELSE 
                -- Replace domain from URL like 'medialibrary.kit19.com' to 'medialibrary.crmapp.net.in'
                -- Logic assumes subdomain is like 'medialibrary.kit19.com'
                REPLACE(URL, '.kit19.com', '.crmapp.in.net')
        END
    FROM TBL_UA_ModuleMaster(nolock)  
    WHERE isnull(Active, 0) = 1 AND ModuleId = (
        SELECT TOP 1 ISNULL(ModuleID, 0)
        FROM TBL_UA_ModuleMaster(nolock)
        WHERE isnull(Active, 0) = 1 AND ModuleId = HR.ChildId
    )
), '') AS URL  
   , isnull((select top 1 StaticPath from TBL_UA_ModuleMaster(nolock)  
   where isnull(Active,0) = 1 and ModuleId = (select top 1 isnull(ModuleID,0) from TBL_UA_ModuleMaster(nolock) where isnull(Active,0) = 1 and ModuleId = HR.ChildId) ),'') as StaticPath,  
    isnull((select top 1 Title from TBL_UA_ModuleMaster(nolock)   
   where ModuleId = (select top 1 isnull(ModuleID,0) from TBL_UA_ModuleMaster(nolock) where isnull(Active,0) = 1 and ModuleId = HR.ChildId) ),'') as Title,  
     isnull((select top 1 Tag from TBL_UA_ModuleMaster(nolock)   
   where ModuleId = (select top 1 isnull(ModuleID,0) from TBL_UA_ModuleMaster(nolock) where isnull(Active,0) = 1 and ModuleId = HR.ChildId) ),'') as Tag ,  
    isnull((select top 1 replace(ModuleDescription,'Kit19',@displayname) from TBL_UA_ModuleMaster(nolock)   
   where ModuleId = (select top 1 isnull(ModuleID,0) from TBL_UA_ModuleMaster(nolock) where isnull(Active,0) = 1 and ModuleId = HR.ChildId) ),'') as ModuleDescription      
   FROM Hierarchy  as HR   
       WHERE 
HR.ChildId NOT IN (296, 297, 299, 300)
/*AND (
        HR.ChildId NOT IN (407, 406)
        OR @UserId IN (34594, 32222)
    )     
    */
)t  
 where ((t.[Type] = 'Module') or (t.[Type] = 'Page' and t.[URL] != ''))  
  
order by t.Sequence asc                 
 --  OPTION(MAXRECURSION 32767)                 
                 
   End                
  Else if(@IsExpired = 1 and (@IsAdmin = 0 or (@ScopeCode = 'USER' and @RoleCode = 'SYS_GUEST')))                
 Begin                
 Print 4  
                
  set @ParentId = 335                
  --set @ScopeCode = 'USER'                
                 
  ;WITH Hierarchy(ChildId, ChildCode, ChildName, Generation, ParentId, sequence, [Type],SequnceStructure)        
  AS                 
   (                 
    SELECT ModuleId, ModuleCode, ModuleName, 0,ParentModuleId, Sequence, [Type], CAST(ModuleName AS VARCHAR(255)) AS SequnceStructure                 
        FROM tbl_ua_ModuleMaster(nolock) AS FirtGeneration                        
        WHERE isnull(FirtGeneration.Active,0) = 1 and  ParentModuleId = 0 and IsClassic = @IsClassic                 
  and FirtGeneration.IsInternal = case when @IsInternal = 0 then 0                
                                 else FirtGeneration.IsInternal                
             end                   
    
    UNION ALL               
       SELECT NextGeneration.ModuleId, NextGeneration.ModuleCode, NextGeneration.ModuleName, Parent.Generation + 1, Parent.ChildId, NextGeneration.Sequence,                 
    NextGeneration.[Type],CAST(Parent.SequnceStructure + '/' + NextGeneration.ModuleName AS VARCHAR(255))                      
        FROM tbl_ua_ModuleMaster(nolock) AS NextGeneration                        
        INNER JOIN Hierarchy AS Parent ON NextGeneration.ParentModuleId = Parent.ChildId                
  WHERE isnull(NextGeneration.Active,0) = 1 and NextGeneration.IsInternal = case when @IsInternal = 0 then 0                
                                 else NextGeneration.IsInternal                
             end                    
     )                    
select * from (  
   SELECT HR.ChildId, HR.ChildCode, HR.ChildName, HR.Generation, HR.ParentId,HR. Sequence, HR.[Type], HR.SequnceStructure,                   
  (select Cast(@IsAdmin as varchar(10)) + cast(@IsClassic as varchar(10)) + cast(@IsExpired as varchar(10)) + @ScopeCode + @RoleCode) RajnishGuest,          
   isnull((select [View] from TBL_UA_RolePermissionMappingMaster(nolock) turpm                 
   inner join TBL_UA_EntityActionMappingMaster(nolock) tueam on tueam.EntityActionMappingCode = turpm.EntityActionMappingCode                
   --inner join VW_SystemRole_RoleMaster urmm on urmm.RoleCode = turpm.RoleCode                
   --left join TBL_UA_ModuleMaster umod on umod.ModuleCode = turpm.ModuleCode                
   where turpm.ParentId = @ParentId and turpm.ScopeCode = @ScopeCode and turpm.RoleCode = @RoleCode and turpm.ModuleCode = HR.ChildCode), 0) [View],   
   ISNULL((
    SELECT 
        CASE 
            WHEN URL = '#' OR URL IS NULL THEN ''
            WHEN @DomainURL LIKE '%kit19.com%' THEN URL
            ELSE 
                -- Replace domain from URL like 'medialibrary.kit19.com' to 'medialibrary.crmapp.net.in'
                -- Logic assumes subdomain is like 'medialibrary.kit19.com'
                REPLACE(URL, '.kit19.com', '.crmapp.in.net')
        END
    FROM TBL_UA_ModuleMaster(nolock)  
    WHERE isnull(Active, 0) = 1 AND ModuleId = (
        SELECT TOP 1 ISNULL(ModuleID, 0)
        FROM TBL_UA_ModuleMaster(nolock)
        WHERE isnull(Active, 0) = 1 AND ModuleId = HR.ChildId
    )
), '') AS URL, isnull((select top 1 StaticPath from TBL_UA_ModuleMaster(nolock)  
   where isnull(Active,0) = 1 and ModuleId = (select top 1 isnull(ModuleID,0) from TBL_UA_ModuleMaster(nolock) where isnull(Active,0) = 1 and ModuleId = HR.ChildId) ),'') as StaticPath,  
    isnull((select top 1 Title from TBL_UA_ModuleMaster(nolock)   
   where ModuleId = (select top 1 isnull(ModuleID,0) from TBL_UA_ModuleMaster(nolock) where isnull(Active,0) = 1 and ModuleId = HR.ChildId) ),'') as Title,  
     isnull((select top 1 Tag from TBL_UA_ModuleMaster(nolock)   
   where ModuleId = (select top 1 isnull(ModuleID,0) from TBL_UA_ModuleMaster(nolock) where isnull(Active,0) = 1 and ModuleId = HR.ChildId) ),'') as Tag ,  
    isnull((select top 1 replace(ModuleDescription,'Kit19',@displayname) from TBL_UA_ModuleMaster(nolock)   
   where ModuleId = (select top 1 isnull(ModuleID,0) from TBL_UA_ModuleMaster(nolock) where isnull(Active,0) = 1 and ModuleId = HR.ChildId) ),'') as ModuleDescription      
   FROM Hierarchy  as HR   
      WHERE 
 HR.ChildId NOT IN (296, 297, 299, 300)

--   WHERE 
--HR.ChildId NOT IN (296, 297, 299, 300)
--AND (
--        HR.ChildId NOT IN (407, 406)
--        OR @UserId IN (34594, 32222)
--    )  
-- )t
)t
 where ((t.[Type] = 'Module') or (t.[Type] = 'Page' and t.[URL] != ''))  
  
 order by t.Sequence asc                 
--   OPTION(MAXRECURSION 32767)           
            
  End          
 Else if(@IsExpired = 0 and (@IsAdmin = 1 or (@ScopeCode != '')))                
  Begin              
 Print 5   
              
  ;WITH Hierarchy(ChildId, ChildCode, ChildName, Generation, ParentId, sequence, [Type], SequnceStructure)                 
AS                 
(                 
    SELECT   
        ModuleId,   
        ModuleCode,   
        ModuleName,   
        0,   
        ParentModuleId,   
        Sequence,   
        [Type],   
        CAST(ModuleName AS VARCHAR(255)) AS SequnceStructure  
    FROM   
        tbl_ua_ModuleMaster (NOLOCK) AS FirtGeneration                        
    WHERE   
        ISNULL(FirtGeneration.Active, 0) = 1    
        AND ParentModuleId = 0                 
        AND FirtGeneration.IsInternal = CASE   
                                      WHEN @IsInternal = 0 THEN 0                
                                            ELSE FirtGeneration.IsInternal                
                                        END                   
                
    UNION ALL                        
  
    SELECT   
        NextGeneration.ModuleId,   
        NextGeneration.ModuleCode,   
        NextGeneration.ModuleName,   
        Parent.Generation + 1,   
        Parent.ChildId,   
        NextGeneration.Sequence,                 
        NextGeneration.[Type],   
        CAST(Parent.SequnceStructure + '/' + NextGeneration.ModuleName AS VARCHAR(255))  
    FROM   
        tbl_ua_ModuleMaster (NOLOCK) AS NextGeneration                        
        INNER JOIN Hierarchy AS Parent ON NextGeneration.ParentModuleId = Parent.ChildId                
    WHERE   
        ISNULL(NextGeneration.Active, 0) = 1   
        AND NextGeneration.IsInternal = CASE   
                                            WHEN @IsInternal = 0 THEN 0                
                                            ELSE NextGeneration.IsInternal                
                                        END                    
)                    
SELECT   
    *   
FROM   
    (  
        SELECT   
            HR.ChildId,   
            HR.ChildCode,   
            HR.ChildName,   
            HR.Generation,   
            HR.ParentId,  
            HR.Sequence,   
            HR.[Type],   
            HR.SequnceStructure,         
            (  
                SELECT   
                    CAST(@IsAdmin AS VARCHAR(10)) + CAST(@IsClassic AS VARCHAR(10)) + CAST(@IsExpired AS VARCHAR(10)) + @ScopeCode + @RoleCode  
            ) RajnishTeam,   
            CASE               
                WHEN ((@ParentId != @UserId) AND (@IsAdmin = 0) AND EXISTS (  
                    SELECT DISTINCT 1   
                    FROM   
                        TBL_UA_UserRoleMappingMaster (NOLOCK) urmp                 
                        INNER JOIN VW_SystemRole_RoleMaster (NOLOCK) urmm ON urmm.RoleCode = urmp.RoleCode                 
                        INNER JOIN TBL_UA_RolePermissionMappingMaster (NOLOCK) turpm ON turpm.RoleCode = urmp.RoleCode                 
                        LEFT JOIN TBL_UA_TeamUserMappingMaster (NOLOCK) utumm ON utumm.UserId = urmp.UserId                 
                        LEFT JOIN TBL_UA_TeamMaster (NOLOCK) uatm ON uatm.TeamCode = utumm.TeamCode                 
                        LEFT JOIN TBL_UA_ModuleMaster (NOLOCK) umod ON umod.ModuleCode = turpm.ModuleCode                 
                    WHERE   
                        ISNULL(umod.Active, 0) = 1   
                        AND urmp.UserId = @UserId OR utumm.UserId = @UserId  
                ))  
                THEN ISNULL((  
                    SELECT DISTINCT 1   
                    FROM   
                        dbo.usp_Tbl_UA_ModuleMasterModuleCodeList (@UserId, @ScopeCode, @RoleCode, HR.ChildCode)  
                ), 0)   
                WHEN ((@ParentId != @UserId) AND (@IsAdmin = 1) AND NOT EXISTS (  
                    SELECT DISTINCT 1   
                    FROM   
                        TBL_UA_UserRoleMappingMaster (NOLOCK) urmp                 
                        INNER JOIN VW_SystemRole_RoleMaster urmm ON urmm.RoleCode = urmp.RoleCode                 
                        INNER JOIN TBL_UA_RolePermissionMappingMaster (NOLOCK) turpm ON turpm.RoleCode = urmp.RoleCode                 
                        LEFT JOIN TBL_UA_TeamUserMappingMaster (NOLOCK) utumm ON utumm.UserId = urmp.UserId                 
                        LEFT JOIN TBL_UA_TeamMaster (NOLOCK) uatm ON uatm.TeamCode = utumm.TeamCode                 
                        LEFT JOIN TBL_UA_ModuleMaster (NOLOCK) umod ON umod.ModuleCode = turpm.ModuleCode                 
                    WHERE   
                        ISNULL(umod.Active, 0) = 1   
                        AND urmp.UserId = @UserId   
                ) AND ([Type] = 'Page'))  
                THEN 1   
                WHEN ((@ParentId != @UserId) AND (@IsAdmin = 1) AND NOT EXISTS (  
                    SELECT DISTINCT 1   
                    FROM   
                        TBL_UA_UserRoleMappingMaster (NOLOCK) urmp                 
                        INNER JOIN VW_SystemRole_RoleMaster (NOLOCK) urmm ON urmm.RoleCode = urmp.RoleCode                 
                        INNER JOIN TBL_UA_RolePermissionMappingMaster (NOLOCK) turpm ON turpm.RoleCode = urmp.RoleCode                 
                        LEFT JOIN TBL_UA_TeamUserMappingMaster (NOLOCK) utumm ON utumm.UserId = urmp.UserId                 
                        LEFT JOIN TBL_UA_TeamMaster (NOLOCK) uatm ON uatm.TeamCode = utumm.TeamCode                 
                        LEFT JOIN TBL_UA_ModuleMaster (NOLOCK) umod ON umod.ModuleCode = turpm.ModuleCode                 
                    WHERE   
                        ISNULL(umod.Active, 0) = 1   
                        AND urmp.UserId = @UserId   
                ) AND ([Type] = 'Module'))  
                THEN 0   
                WHEN ((@ParentId = @UserId) AND (@IsAdmin = 1) AND (@IsInternal = 0) AND ([Type] = 'Page'))  
                THEN 1   
                WHEN ((@ParentId = @UserId) AND (@IsAdmin = 1) AND (@IsInternal = 0) AND ([Type] = 'Module'))  
                THEN 0   
                WHEN ((@ParentId = @UserId) AND (@IsAdmin = 1) AND (@IsInternal = 1) AND ([Type] = 'Page'))  
                THEN 1   
                WHEN ((@ParentId = @UserId) AND (@IsAdmin = 1) AND (@IsInternal = 1) AND ([Type] = 'Module'))  
                THEN 0   
                WHEN ((@ParentId != @UserId) AND EXISTS (  
                    SELECT DISTINCT 1   
                    FROM   
                        TBL_UA_UserRoleMappingMaster (NOLOCK) urmp  
                        INNER JOIN VW_SystemRole_RoleMaster urmm ON urmm.RoleCode = urmp.RoleCode                 
                        INNER JOIN TBL_UA_RolePermissionMappingMaster (NOLOCK) turpm ON turpm.RoleCode = urmp.RoleCode                 
                        LEFT JOIN TBL_UA_TeamUserMappingMaster (NOLOCK) utumm ON utumm.UserId = urmp.UserId                 
                        LEFT JOIN TBL_UA_TeamMaster (NOLOCK) uatm ON uatm.TeamCode = utumm.TeamCode                 
                        LEFT JOIN TBL_UA_ModuleMaster (NOLOCK) umod ON umod.ModuleCode = turpm.ModuleCode                 
                    WHERE   
                        ISNULL(umod.Active, 0) = 1   
                        AND urmp.UserId = @UserId OR utumm.UserId = @UserId       
                        AND turpm.ScopeCode = @ScopeCode   
                        AND turpm.RoleCode = @RoleCode  
                ))  
                THEN ISNULL((  
                    SELECT TOP 1 [View]   
                    FROM   
                        TBL_UA_UserRoleMappingMaster (NOLOCK) urmp                 
                        INNER JOIN VW_SystemRole_RoleMaster urmm ON urmm.RoleCode = urmp.RoleCode                 
                        INNER JOIN TBL_UA_RolePermissionMappingMaster (NOLOCK) turpm ON turpm.RoleCode = urmp.RoleCode                 
                        INNER JOIN TBL_UA_EntityActionMappingMaster (NOLOCK) tueam ON tueam.EntityActionMappingCode = turpm.EntityActionMappingCode                 
                        LEFT JOIN TBL_UA_TeamUserMappingMaster (NOLOCK) utumm ON utumm.UserId = urmp.UserId                 
                        LEFT JOIN TBL_UA_TeamMaster (NOLOCK) uatm ON uatm.TeamCode = utumm.TeamCode                 
                        LEFT JOIN TBL_UA_ModuleMaster (NOLOCK) umod ON umod.ModuleCode = turpm.ModuleCode                 
                    WHERE   
                        ISNULL(umod.Active, 0) = 1   
                        AND urmp.UserId = @UserId   
                        AND turpm.ScopeCode = @ScopeCode   
                        AND turpm.RoleCode = @RoleCode          
                        AND turpm.ModuleCode = HR.ChildCode   
                        AND umod.IsInternal != 1  
                ), 0)  
            END AS [View],                 
           ISNULL((
    SELECT 
        CASE 
            WHEN URL = '#' OR URL IS NULL THEN ''
            WHEN @DomainURL LIKE '%kit19.com%' THEN URL
            ELSE 
                -- Replace domain from URL like 'medialibrary.kit19.com' to 'medialibrary.crmapp.net.in'
                -- Logic assumes subdomain is like 'medialibrary.kit19.com'
                REPLACE(URL, '.kit19.com', '.crmapp.in.net')
        END
    FROM TBL_UA_ModuleMaster(nolock)  
    WHERE isnull(Active, 0) = 1 AND ModuleId = (
        SELECT TOP 1 ISNULL(ModuleID, 0)
        FROM TBL_UA_ModuleMaster(nolock)
        WHERE isnull(Active, 0) = 1 AND ModuleId = HR.ChildId
    )
), '') AS URL,   
            ISNULL((  
                SELECT   
                    TOP 1 StaticPath   
                FROM   
                    TBL_UA_ModuleMaster (NOLOCK)  
                WHERE   
                    ISNULL(Active, 0) = 1   
                    AND ModuleId = (  
                        SELECT TOP 1 ISNULL(ModuleID, 0)   
                        FROM   
                            TBL_UA_ModuleMaster (NOLOCK)   
                        WHERE    
                            ISNULL(Active, 0) = 1   
                            AND ModuleId = HR.ChildId  
                    )  
            ), '') AS StaticPath,  
            ISNULL((  
                SELECT   
                    TOP 1 Title   
                FROM   
                    TBL_UA_ModuleMaster (NOLOCK)   
                WHERE   
                    ModuleId = (  
                        SELECT TOP 1 ISNULL(ModuleID, 0)   
                        FROM   
                            TBL_UA_ModuleMaster (NOLOCK)   
                        WHERE   
                            ISNULL(Active, 0) = 1   
                            AND ModuleId = HR.ChildId  
                    )  
            ), '') AS Title,  
            ISNULL((  
                SELECT   
                    TOP 1 Tag   
                FROM   
                    TBL_UA_ModuleMaster (NOLOCK)   
                WHERE   
                    ModuleId = (  
                        SELECT TOP 1 ISNULL(ModuleID, 0)   
                        FROM   
                            TBL_UA_ModuleMaster (NOLOCK)   
                        WHERE   
                            ISNULL(Active, 0) = 1   
                            AND ModuleId = HR.ChildId  
                    )  
            ), '') AS Tag ,  
    isnull((select top 1 replace(ModuleDescription,'Kit19',@displayname) from TBL_UA_ModuleMaster(nolock)   
   where ModuleId = (select top 1 isnull(ModuleID,0) from TBL_UA_ModuleMaster(nolock) where isnull(Active,0) = 1 and ModuleId = HR.ChildId) ),'') as ModuleDescription      
        FROM   
            Hierarchy AS HR    
        WHERE   
            HR.ChildId NOT IN (296, 297, 299, 300,379,380,390,391)  
        --  WHERE 
--HR.ChildId NOT IN (296, 297, 299, 300,379,380,390,391)
--AND (
  --      HR.ChildId NOT IN (407, 406)
    --    OR @UserId IN (34594, 32222)
    --)  
          
 
    ) t  
WHERE   
    ((t.[Type] = 'Module') OR (t.[Type] = 'Page' AND t.[URL] != ''))  
ORDER BY   
    t.Sequence ASC  
               
--   OPTION(MAXRECURSION 32767)                 
            
End                  
 End   


