/* ============================================================
   Procedure: [dbo].[UspGetHeirarchicalDisplay_WithUserIDModule_Mob]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[UspGetHeirarchicalDisplay_WithUserIDModule_Mob]  
(  
 @UserID bigint  
)  
As  
Begin                  
      
	--insert into tbl_trace_DbObjectExecution(DbOjectName,DbObjectType,MetaData,ActionDescription,ActionTimeStamp)
	--select 'UspGetHeirarchicalDisplay_WithUserIDModule_Mob','SP',concat('@UserID:',@UserID),'Begin',getdate()

-- Declare @UserID bigint = 32222 --34594      
 --Declare @UserID bigint = 34081      
      
 Declare @IsSiteOwner bit = 0      
 Declare @ParentId bigint = 0      
 Declare @IsAdmin int = 0      
 Declare @IsInternal bit = 0      
 Declare @ScopeCode varchar(10) = ''      
 Declare @M_ID bigint = 0      
 Declare @IsClassic bigint = 0      
 Declare @IsExpired bit = 0      
 Declare @RoleCode varchar(10) = ''      
      
 select @IsAdmin = isnull(IsAdmin, 0), @ParentId = isnull(ud.ParentId, 0), @M_ID = isnull(M_ID, 0) from User_Detail(nolock) ud where ud.USER_ID = @UserID                     
        
 select @IsInternal = isnull(sysrole.IsInternal,0)       
 from User_Detail(nolock) ud inner join TBL_UA_UserRoleMappingMaster(nolock) turmm       
 on turmm.UserId = ud.User_Id inner join VW_SystemRole_RoleMaster(nolock) sysrole       
 on sysrole.RoleCode = turmm.RoleCode      
 where ud.USER_ID = @UserID      
      
 drop table if Exists #NewTable      
 Create table #NewTable (ChildId bigint, ChildCode Varchar(50), ChildName Varchar(150), Generation bit, ParentId int, Sequence decimal(18,4), [Type] varchar(10), AccessType varchar(100), [View] bit, [URL] varchar(200), StaticPath nvarchar(200))           

 if(@M_ID = '10043' or @M_ID = '10001')                    
 Begin                    
  set @IsClassic = 0                    
 End                    
 else                     
 Begin                    
  set @IsClassic = 1                    
 End                    
                    
 set @IsExpired =  isnull((select top 1 0 from Price_UserSubscriptionDetails(nolock) where Userid = @ParentID and Convert(date, getdate(), 103) between PlanStartDate and PlanEndDate), 1)      
              
 select top 1 @ScopeCode = turpm.ScopeCode, @RoleCode =turpm.RoleCode       
 from TBL_UA_UserRoleMappingMaster(nolock) urmp inner join VW_SystemRole_RoleMaster(nolock) urmm       
 on urmm.RoleCode = urmp.RoleCode inner join TBL_UA_RolePermissionMappingMaster(nolock) turpm       
 on turpm.RoleCode = urmp.RoleCode left join TBL_UA_TeamUserMappingMaster(nolock) utumm       
 on utumm.UserId = urmp.UserId left join TBL_UA_TeamMaster(nolock) uatm       
 on uatm.TeamCode = utumm.TeamCode left join TBL_UA_ModuleMaster(nolock) umod       
 on umod.ModuleCode = turpm.ModuleCode      
 where isnull(umod.Active,0) = 1  and urmp.UserId = @UserId or utumm.UserId = @UserId              
              
 --Select @IsAdmin IsAdmin, @IsClassic IsClassic, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode      
 --set @ScopeCode = 'TEAM'      
          
 if(@ScopeCode = '' or @IsExpired = 1)      
 Begin      
  print 'A0'      
  set @ScopeCode = 'USER'      
 End      
 -- Select @IsAdmin IsAdmin, @IsClassic IsClassic, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode               
            
 if((@RoleCode = '') and ((@IsAdmin = 0) or (@IsAdmin = 1)))      
 Begin      
  print 'A1'      
  set @RoleCode = 'SYS_USER'      
 End      
 else if((@RoleCode = '') and (@IsExpired = 1) and (@IsAdmin = 0))      
 Begin      
  print 'A2'      
  set @RoleCode = 'SYS_GUEST'      
 End      
          
  --Select @IsAdmin IsAdmin, @IsClassic IsClassic, @IsExpired IsExpired, @ScopeCode ScopeCode, @RoleCode RoleCode       
 print '@IsAdmin: ' + Cast(@IsAdmin as varchar)      
 print '@IsClassic: ' + cast(@IsClassic as varchar)      
 print '@IsExpired: ' + cast(@IsExpired as varchar)      
 print '@ScopeCode: ' + cast(@ScopeCode as varchar)      
 print '@RoleCode: ' + cast(@RoleCode as varchar)      
 print '@IsInternal: ' + cast(@IsInternal as varchar)      
      
 if((@UserID = '36950') or (@UserID = '32222'))        
 Begin      
