  where (HR.ChildCode in ('MOD10176','PAG10002','PAG10031','PAG10103','PAG10043','PAG10034','PAG10035','PAG10163','PAG10223','PAG10222','PAG10039','PAG10038','PAG10308','PAG10309','PAG10310','PAG10042','PAG10264','PAG10321','PAG10362','PAG10317','PAG10331','PAG10323','PAG10320','PAG10297','PAG10296','PAG10371','PAG10380','PAG10388','PAG10391','PAG10381','PAG10383','PAG10384','PAG10274','PAG10399'))         
  ) tHR where (tHR.[View] > 0 or tHR.ChildCode = 'MOD10176' or tHR.ChildCode = 'PAG10371')      
  order by tHR.Sequence asc                     
  OPTION(MAXRECURSION 32767)       
       
 End                      
 End   

 --	insert into tbl_trace_DbObjectExecution(DbOjectName,DbObjectType,MetaData,ActionDescription,ActionTimeStamp)
