/* ============================================================
   Procedure: [dbo].[UspGetLast7DayLeads]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.UspGetLast7DayLeads --335        
(        
  @UserID bigint        
)         
as        
Begin        
            
  Declare @LastDateLeads datetime = getdate()       
  Declare @IsAdmin bit = 0       
  select @IsAdmin = isnull(IsAdmin,0) from User_Detail(nolock) where User_ID = @UserID      
             
 --Declare @ParentID bigint = 0;        
 --select @ParentID = ISNULL(ParentID,0) from User_Detail where User_ID = @UserID           
       
        
  --select top 1 @LastDateLeads = CreatedOn  from UserLeads where      
  --  @UserID = case when @IsAdmin = 0      
  --                    then CreatedBy      
  --                   else ParentID      
  --   end                    
      
  -- order by Createdon desc         
 set @LastDateLeads = isnull(@LastDateLeads,GETDATE());         
        
   CREATE TABLE #TempLast7Dates        
    (        
       Dates nvarchar(50),        
       RowNum int        
    )        
        
   insert into #TempLast7Dates        
   SELECT Dates, RowNum   FROM        
    (        
     SELECT CAST(@LastDateLeads AS DATE) AS Dates, 7 as RowNum        
  UNION        
  SELECT CAST(DATEADD(DAY, -1, @LastDateLeads) AS DATE) AS Dates, 6 as RowNum         
  UNION        
  SELECT CAST(DATEADD(DAY, -2, @LastDateLeads) AS DATE) AS Dates,5 as RowNum        
  UNION        
  SELECT CAST(DATEADD(DAY, -3, @LastDateLeads) AS DATE) AS Dates,4 as RowNum        
  UNION        
  SELECT CAST(DATEADD(DAY, -4, @LastDateLeads) AS DATE) AS Dates,3 as RowNum        
  UNION        
  SELECT CAST(DATEADD(DAY, -5, @LastDateLeads) AS DATE) AS Dates,2 as RowNum        
  UNION        
  SELECT CAST(DATEADD(DAY, -6, @LastDateLeads) AS DATE) AS Dates,1 as RowNum        
   ) AS the_table order by RowNum asc         
        
    -- select * from #TempLast7Dates        
              
  select *,ROW_NUMBER() over(order by CountNum desc) as RowNum into #Top5UsersTbl         
    from (        
        select top 5 Count(*) as CountNum, CreatedBy as UserID  from UserLeads(nolock)     
        
   where      
       
         @UserID = case when @IsAdmin = 0      
                      then CreatedBy      
                     else ParentID      
     end                    
        
   -- ParentID = @ParentID         
              
        
  and  CreatedOn >= @LastDateLeads - 6        
        group by CreatedBy         
        order by CountNum desc        
        ) as tbl        
             
  --select * from #Top5UsersTbl          
    declare @UsersCount int = 0        
       Declare @UserRowCount int = 1         
    Declare @DateRowCount int = 1        
        
    select @UsersCount =  isnull(count(1),0) from #Top5UsersTbl        
        
    create table #FinalTopLeads        
    (        
      LeadDate date,         
      UserID bigint,        
   LeadCount int        
    )        
        
    Declare @LeadDate date        
    Declare @UserIDLead bigint = 0        
    Declare @LeadCount int = 0        
        
        
    while(@UserRowCount <= @UsersCount)        
     Begin        
             
     while(@DateRowCount <= 7)        
          Begin        
           select @LeadDate = Dates  from #TempLast7Dates where RowNum = @DateRowCount        
        select @UserIDLead = UserID from #Top5UsersTbl where RowNum = @UserRowCount        
        select @LeadCount = isnull(Count(1),0) from UserLeads(nolock) where CONVERT(date,CreatedOn) = @LeadDate and CreatedBy =     @UserIDLead        
        
        insert into #FinalTopLeads         
        select @LeadDate,@UserIDLead,isnull(@LeadCount,0)        
        
       set @DateRowCount = @DateRowCount + 1        
             End        
        
        
        
     set @UserRowCount = @UserRowCount + 1         
  End          
            
  select *,(select User_login from user_detail(nolock) where user_id = UserID) as UserLogin from #FinalTopLeads        
        
  drop table #TempLast7Dates        
  drop table #Top5UsersTbl        
  drop table #FinalTopLeads         
        
End 


GO

