CREATE   PROCEDURE dbo.UspGetLeadActivityDetails_ByLeadID          
(        
  @LeadID bigint        
)        
as        
Begin        
        
   SELECT  top 10      
       [HistoryID]        
      ,[UserID]        
   ,isnull((select isnull(User_Login,'') from User_Detail where User_ID = UserID),'') as UserName        
      ,[LeadID]        
   ,isnull((select isnull(PersonName,'') from UserLeads where ID = LeadID),'') as PersonName        
   ,isnull((select isnull(ProfileImgFileName,'') from UserLeads where ID = LeadID),'') as ProfileImgFileName         
      ,[ParentID]        
      ,[EventDescription]        
      ,[EventDate]        
      ,[IPAddress]        
      ,[EventID]        
      ,isnull((Select isnull(EventName,'') from ActivityMaster where ID = isnull(EventID,0)),'') as EventName        
      ,isnull((Select isnull(EventType,'') from ActivityMaster where ID = isnull(EventID,0)),'') as  EventType      
      ,CONVERT(datetime,EventDate) as EventSQLDatetime        
         
         
   FROM [tbl_LeadEventHistory](nolock) where LeadID = @LeadID and eventID is not null  order by HistoryID desc        
           
End


