/* ============================================================
   Procedure: [dbo].[UspGetLeadActivityDetails_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.UspGetLeadActivityDetails_New --34594            
(            
  @ParentID bigint            
)            
as            
Begin    
--declare @ParentID bigint =34594           
     Declare @Cold int = 0,@Warm int = 0,@Hot int =  0   ,@hcount int        
  
    if(exists(select 1 from lead_cateogy_thresholds(nolock) where parentid = @ParentID ))        
      Begin        
       select top 1  @Cold = isnull(Cold,0), @Warm = isnull(Warm,0), @Hot = isnull(Hot,0)  from lead_cateogy_thresholds(nolock) where parentid  = @ParentID        
   End        
    else        
      Begin        
      select top 1  @Cold = isnull(Cold,0), @Warm = isnull(Warm,0), @Hot = isnull(Hot,0)  from lead_cateogy_thresholds(nolock) where parentid  = 0         
   End      
      
 --select @hcount=count(1) from [tbl_LeadEventHistory](nolock) t where t.ParentID = @ParentID and eventID is not null  
 --and datediff(dd,t.EventDate,getdate())<=30   
      
 --if @hcount>100  
 --set @hcount=100  
 drop table if exists #tbl_leadeventhistory
 drop table if exists #userleads
  
  select top 100 * into #tbl_leadeventhistory from tbl_LeadEventHistory(nolock) where parentid=@parentid and cast(EventDate as date)=cast(getdate() as date) 
  select id,personname,ProfileImgFileName into #userleads from userleads u join #tbl_leadeventhistory t on t.LeadID=u.id
  
   SELECT
       [HistoryID]            
      ,[UserID]            
   , isnull(User_Login,'') as UserName            
      ,t.[LeadID]            
   ,isnull(PersonName,'')  as PersonName            
   ,isnull(ProfileImgFileName,'') as ProfileImgFileName             
      ,t.[ParentID]            
      ,[EventDescription]            
      ,cast( [EventDate] as nvarchar)   as EventDate            
      ,[IPAddress]            
      ,[EventID]            
      ,isnull(EventName,'') as EventName            
      ,isnull(EventType,'')  as  EventType          
      ,CONVERT(datetime,EventDate) as EventSQLDatetime          
   ,isnull(l.ScoreAdded,0) ScoreAdded                
 ,[dbo].[fn_getrelativescore](t.LeadID) as CurrentScore      
 ,(      
     case when [dbo].[fn_getrelativescore](t.LeadID) <= @Cold  then 'Cold'       
       when [dbo].[fn_getrelativescore](t.LeadID) > @Cold and [dbo].[fn_getrelativescore](t.LeadID) <= @Warm      
          then 'Warm'      
    else 'Hot'      
    end                               
  )  as ThresholdColor      
       
           
 -- isnull(ProfileImgFileName,'') as ProfileImgFileName         
      FROM #tbl_leadeventhistory(nolock) t 
	  left join lead_score_history(nolock) l on l.lead_activity_id=t.HistoryID         
   left join #userleads(nolock) u on u.id=t.leadid         
   left join user_detail(nolock) d on d.user_id=t.userid        
   left join activitymaster(nolock)a on a.id=t.EventID        
     order by HistoryID desc            
               
End


GO

/* ============================================================
   Procedure: [dbo].[UspGetLeadActivityDetails_NewWithPaging]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 
CREATE   PROCEDURE [dbo].[UspGetLeadActivityDetails_NewWithPaging]
(
    @ParentID BIGINT,
    @PageNo INT = 1,
    @PageSize INT = 20
)
AS
BEGIN
    --DECLARE @ParentID BIGINT = 46828,
    --        @PageNo INT = 1,
    --        @PageSize INT = 20;
 
    DECLARE @Cold INT = 0, @Warm INT = 0, @Hot INT = 0;
 
    -- Thresholds
    IF EXISTS (SELECT 1 FROM lead_cateogy_thresholds (NOLOCK) WHERE ParentID = @ParentID)
        SELECT TOP 1 
               @Cold = ISNULL(Cold, 0), 
               @Warm = ISNULL(Warm, 0), 
               @Hot  = ISNULL(Hot, 0)
        FROM lead_cateogy_thresholds (NOLOCK)
        WHERE ParentID = @ParentID;
    ELSE
        SELECT TOP 1 
               @Cold = ISNULL(Cold, 0), 
               @Warm = ISNULL(Warm, 0), 
               @Hot  = ISNULL(Hot, 0)
        FROM lead_cateogy_thresholds (NOLOCK)
        WHERE ParentID = 0;
 
    -- Temporary tables
    DROP TABLE IF EXISTS #tbl_leadeventhistory;
    DROP TABLE IF EXISTS #userleads;
    DROP TABLE IF EXISTS #tmpLeadActivity;
 
    SELECT TOP 100 *
    INTO #tbl_leadeventhistory
    FROM tbl_LeadEventHistory (NOLOCK)
    WHERE ParentID = @ParentID 
      AND CAST(EventDate AS DATE) = CAST(GETDATE() AS DATE);
 
    SELECT u.id, u.PersonName, u.ProfileImgFileName
    INTO #userleads
    FROM userleads u
    JOIN #tbl_leadeventhistory t ON t.LeadID = u.id;
 
    -- Main data with row numbering
    SELECT 
        ROW_NUMBER() OVER (ORDER BY t.HistoryID DESC) AS RecNo,
        t.[HistoryID],
        t.[UserID],
        ISNULL(d.User_Login, '') AS UserName,
        t.[LeadID],
        ISNULL(u.PersonName, '') AS PersonName,
        ISNULL(u.ProfileImgFileName, '') AS ProfileImgFileName,
        t.[ParentID],
        t.[EventDescription],
        CAST(t.[EventDate] AS NVARCHAR) AS EventDate,
        t.[IPAddress],
        t.[EventID],
        ISNULL(a.EventName, '') AS EventName,
        ISNULL(a.EventType, '') AS EventType,
        CONVERT(DATETIME, t.EventDate) AS EventSQLDatetime,
        ISNULL(l.ScoreAdded, 0) AS ScoreAdded,
        [dbo].[fn_getrelativescore](t.LeadID) AS CurrentScore,
        CASE 
            WHEN [dbo].[fn_getrelativescore](t.LeadID) <= @Cold THEN 'Cold'
            WHEN [dbo].[fn_getrelativescore](t.LeadID) > @Cold 
                 AND [dbo].[fn_getrelativescore](t.LeadID) <= @Warm THEN 'Warm'
            ELSE 'Hot'
        END AS ThresholdColor
    INTO #tmpLeadActivity
    FROM #tbl_leadeventhistory t
    LEFT JOIN lead_score_history (NOLOCK) l ON l.lead_activity_id = t.HistoryID
    LEFT JOIN #userleads u ON u.id = t.LeadID
    LEFT JOIN user_detail (NOLOCK) d ON d.user_id = t.UserID
    LEFT JOIN activitymaster (NOLOCK) a ON a.id = t.EventID;
 
    DECLARE @TotalRecords INT = (SELECT COUNT(1) FROM #tmpLeadActivity);
 
    -- Pagination with TotalRecords included in same result
    SELECT 
        *,
        @TotalRecords AS TotalRecords
    FROM #tmpLeadActivity
    WHERE RecNo BETWEEN ((@PageNo - 1) * @PageSize + 1) AND (@PageNo * @PageSize)
    ORDER BY RecNo;
END



GO

