/* ============================================================
   Procedure: [dbo].[UspGetPageDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.UspGetPageDetails   --335   
(      
  @ParentID bigint      
)      
as      
Begin      
     Select       
       PR.ID      
      ,PR.TypeID      
      ,PR.PageName      
      ,PR.Status      
      ,PR.ParentID      
      ,PR.Content      
      ,PR.Remarks      
      ,PR.CreatedOn      
      ,PR.CreatedBy  
   ,(Select user_login from User_Detail where User_ID = PR.CreatedBy) as CreatedByName      
  -- ,DME.URL      
    ,isnull((Select isnull(URL,'') from DigitalMarketingEntities where PageRequestID = PR.ID),'') as URL
	,
    STUFF((SELECT ';' + cast(PD.DocPath as nvarchar(max)) --Path                   
    FROM PageDocs PD inner join PageRequests PR1                  
    on PD.RequestID = PR1.ID                  
    where PD.RequestID = PR.ID                  
     FOR XML PATH('')), 1, 1, '')  as PageDocPath        
    
   from  PageRequests as PR  --left outer join      
   --DigitalMarketingEntities as DME      
   --on PR.TypeID = DME.TypeID      
   -- on PR.ID = DME.PageRequestID
    where PR.ParentID = @ParentID       
   order by Id desc       
End 


GO

/* ============================================================
   Procedure: [dbo].[UspGetPageDetails_ByID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.UspGetPageDetails_ByID --1        
(        
  @RequestID bigint        
)        
as        
Begin        
     Select         
       PR.ID        
      ,PR.TypeID        
      ,PR.PageName        
      ,PR.Status        
      ,PR.ParentID        
      ,PR.Content        
      ,PR.Remarks        
      ,PR.CreatedOn        
      ,PR.CreatedBy    
   ,(Select user_login from User_Detail where User_ID = PR.CreatedBy) as CreatedByName        
   ,
     -- DME.URL        
     isnull((select top 1 isnull(URL,'') from DigitalMarketingEntities where PageRequestID = PR.ID),'') as URL
	
	,(select top 1  isnull(AssignedTo,0) from PageRequestHistory where RequestID = PR.ID order by Id desc) as AssignedTo  
 ,  
   
    STUFF((SELECT ';' + cast(PD.DocPath as nvarchar(max)) --Path                     
    FROM PageDocs PD inner join PageRequests PR1                    
    on PD.RequestID = PR1.ID                    
    where PD.RequestID = PR.ID                    
     FOR XML PATH('')), 1, 1, '')  as PageDocPath          
      
   from  PageRequests as PR 
  --  join        
  -- DigitalMarketingEntities as DME        
  -- on PR.TypeID = DME.TypeID        
    where PR.ID = @RequestID         
   order by Id desc         
End 


