/* ============================================================
   Procedure: [dbo].[UspGetThisYearLead]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.UspGetThisYearLead --335           
(          
 @UserID bigint          
)          
as          
Begin          
             
  Declare @IsAdmin bit = 0         
     select @IsAdmin = isnull(IsAdmin,0) from User_Detail(nolock) where User_ID = @UserID        
        
        
  select *, (  
    
          -- select isnull(ProfilePicturePath,'') from User_Detail(nolock) where User_ID = CreatedBy) as ProfilePicPath  
       select isnull(Image,'') from User_Detail(nolock) where User_ID = CreatedBy) as ProfilePicPath  
    ,      
        
     (select User_login from user_detail(nolock) where user_id = CreatedBy) as UserLogin from (        
        
      Select CreatedBy,count(CreatedBy) as LeadCount from UserLeads(nolock) where  datePart(YEAR,CreatedOn) = datepart(Year,GETDATE())           
             and          
    (        
      @UserID = case when @IsAdmin = 0        
                      then CreatedBy        
                     else ParentID        
                end          
            
    )        
    --CreatedBy in (select USER_ID from User_Detail where ParentID = @ParentID)            
    group by CreatedBy        
   ) as tbl           
          
end 


GO

/* ============================================================
   Procedure: [dbo].[UspGetTimeZoneByCountryID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



 CREATE   PROCEDURE dbo.UspGetTimeZoneByCountryID --63    
(    
  @CountryId int    
)    
as    
Begin    
    
 if(exists(SELECT  1  FROM sys.time_zone_info TZF inner join CountryAndTimezone CAT      
  on  TZF.name  =  CAT.Dateline_Standard_Time    
   where CAT.Country_ID = @CountryID))  
   Begin  
  
 SELECT     
  name as TimeZone ,name + '(GMT'+current_utc_offset+')' as TimeZoneDisplay     
  FROM sys.time_zone_info TZF inner join CountryAndTimezone CAT      
  on  TZF.name  =  CAT.Dateline_Standard_Time    
   where CAT.Country_ID = @CountryID     
    
    End  
  else  
    Begin  
     select name as TimeZone  ,name  + '( UTC'+ c.current_utc_offset+' )' as TimeZoneDisplay from sys.time_zone_info s join  
         (select distinct current_utc_offset from sys.time_zone_info where is_currently_dst=0 ) c  on s.current_utc_offset=c.current_utc_offset  
          where name=(select min(name) from sys.time_zone_info where current_utc_offset=s.current_utc_offset)  
 End  
  
  
  
  End


GO

