CREATE   PROCEDURE dbo.UspGetUserSetupStagesFromKit19        
(        
  @EnqNo bigint,        
  @Kit19UserID bigint        
        
)        
as        
Begin        
        
   CREATE TABLE #TempLinked                                      
    (                                      
      Result VARCHAR(200)                                      
    )             
                        
     INSERT INTO #TempLinked                                      
     EXEC GetStatusofLinkedServer 'CRM'                                      
     IF NOT EXISTS(                                      
        SELECT 'x'                                      
        FROM   #TempLinked                                      
    )                           
    begin              
   exec CRM.CRMDB.dbo.UspGetUserSetupStagesForEventNotification @EnqNo, @Kit19UserID             
 End      
else      
    begin      
      
  select         
       [id]        
      ,[Enqno]        
      ,[kit19user_id]        
      ,[StageType]        
      ,[SetUpStage]        
      ,[StageStatus]        
      ,[StageScore]        
      ,[StageDate]        
      ,[CreatedOn]        
      ,[Createdby]
	  ,[BatchID] from UserSetUpStages where Enqno = @EnqNo and kit19user_id = @Kit19UserID   and   StageType = 'EventNotifiation' and  SetUpStage like '%Set Up & Round Up Notification Day%'      
        
     end      
      
  drop table #TempLinked;        
      
end    
    


