CREATE   PROCEDURE dbo.UspGetVisitDetails --'ip123',335,'Webform'  
(  
 @Cname nvarchar(500),  
 @UserID bigint,  
 @Type nvarchar(50)  
)  
as  
Begin  
  -- declare @Cname nvarchar(500) = 'landingpagekit19'  
  -- declare @UserID bigint = 335;  
