/* ============================================================
   Procedure: [dbo].[UspInsertSyncIntoTable]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[UspInsertSyncIntoTable] --335,40,5,'column_1',335    
(    
  @ParentID bigint,    
  @FilteredID bigint,    
  @ImportedListID bigint,    
  @MappedColumnName varchar(200),    
  @MappedWith varchar(200),    
  @CreatedBy bigint,  
  @AllowDuplicates bit  
      
)    
as    
Begin    
   Declare @SyncID bigint = 0,@ParsingID bigint = 0    
       
   if not exists( select 'x' from syncing where FilterID = @FilteredID and ImportListID = @ImportedListID    
     and ParentID = @ParentID    
    )     
   Begin    
   insert into syncing(FilterID,ImportListID,ParentID,CreatedOn,ModifiedOn,CreatedBy,AllowDuplicates)    
   values    
   (    
     @FilteredID,@ImportedListID,@ParentID,GETDATE(),GETDATE(),@CreatedBy,@AllowDuplicates    
   )      
        
    SELECT @SyncID = IDENT_CURRENT('syncing')    
   End    
   else    
      Begin     
      select top 1 @SyncID = ID from syncing where FilterID = @FilteredID and ImportListID =     
         @ImportedListID    
         and ParentID = @ParentID order by CreatedOn Desc     
      End    
           
    --select  @SyncID     
        
   select top 1 @ParsingID = ID from UserMailsParsing where FilterID = @FilteredID and MappingColumn =     
   @MappedColumnName order by CreatedOn desc      
        
    if(@ParsingID<>0)    
      Begin    
         insert into ColumnSync(SyncID,ParsingID,ColumnMapped,CreatedOn,ModifiedOn,CreatedBy)     
         values(@SyncID,@ParsingID,@MappedWith,GETDATE(),GETDATE(),@CreatedBy)    
             
         --update UserMailsFilters set IsMapped = 1 ,IsNotMapped = 0 where ID = @FilteredID     
             
         select 'Success'    
             
      End    
    else    
      Begin    
           select 'No Parsing ID Exists'    
      End       
       
End



GO

/* ============================================================
   Procedure: [dbo].[UspInsertUserEnquiryDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext UspInsertUserEnquiryDetails
--sp_helptext Usp_Insert_Lead_Details

CREATE   PROCEDURE [dbo].[UspInsertUserEnquiryDetails]      
 @PersonName NVARCHAR(100),      
 @CompanyName NVARCHAR(100),      
 @MobileNo NVARCHAR(100),      
 @MobileNo1 NVARCHAR(100),      
 @MobileNo2 NVARCHAR(100),      
 @EmailID NVARCHAR(100),      
 @EmailID1 NVARCHAR(100),      
 @EmailID2 NVARCHAR(100),      
 @City NVARCHAR(50),      
 @State NVARCHAR(50),      
 @Country NVARCHAR(50),      
 @CountryCode NVARCHAR(50),      
 @CountryCode1 NVARCHAR(50),      
 @CountryCode2 NVARCHAR(50),      
 @ResidentialAddress NVARCHAR(500),      
 @OfficeAddress NVARCHAR(500),      
 @PinCode BIGINT,      
 @SourceName BIGINT,      
 @MediumName BIGINT,      
 @CampaignName BIGINT,      
 @InitialRemarks NVARCHAR(1000),      
 @ParentID BIGINT,      
 @CreatedBy NVARCHAR(50)      
AS      
BEGIN 

create table #temp(mobile varchar(100),email varchar(100))                
insert into #temp(mobile,email)              
select (cast(isnull(CountryCode,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo,''),0) as nvarchar)),isnull(NULLIF(EmailID,''),0) from UserLeads where ParentID=@PARENTID                
union                 
select (cast(isnull(CountryCode1,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo1,''),0) as nvarchar)),isnull(NULLIF(EmailID1,''),0) from UserLeads where ParentID=@PARENTID               
union                 
select (cast(isnull(CountryCode2,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo2,''),0) as nvarchar)),isnull(NULLIF(EmailID2,''),0) from UserLeads where ParentID=@PARENTID              
declare @leadn as bigint

if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(@CountryCode,1) as nvarchar)+ cast(isnull(@MobileNo,1) as nvarchar) in (select Mobile from #temp))) 
           
BEGIN              

select @leadn = leadno from UserLeads where ParentID=@ParentID and 
(cast(isnull(@CountryCode,1) as nvarchar)+ cast(isnull(@MobileNo,1) as nvarchar) in (select Mobile from #temp))
                
END 
if (@leadn='') 
begin              
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(@CountryCode1,1) as nvarchar)+ cast(isnull(@MobileNo1,1) as nvarchar) in (select Mobile from #temp)))               
BEGIN               
select @leadn = leadno from UserLeads where ParentID=@ParentID and 
(cast(isnull(@CountryCode1,1) as nvarchar)+ cast(isnull(@MobileNo1,1) as nvarchar) in (select Mobile from #temp))                
END 
end
if (@leadn='') 
begin              
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(@CountryCode2,1) as nvarchar)+ cast(isnull(@MobileNo2,1) as nvarchar) in (select Mobile from #temp)))                
BEGIN              
select @leadn = leadno from UserLeads where ParentID=@ParentID and 
(cast(isnull(@CountryCode2,1) as nvarchar)+ cast(isnull(@MobileNo2,1) as nvarchar) in (select Mobile from #temp))                
END 
end
if (@leadn='') 
begin            
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(NULLIF(@EmailID,''),1) as nvarchar) in (select email from #temp)))                
BEGIN              
select @leadn = leadno from UserLeads where ParentID=@ParentID  
and (cast(isnull(NULLIF(@EmailID,''),1) as nvarchar) in (select email from #temp))           
END
end 
if (@leadn='') 
begin              
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(NULLIF(@EmailID1,''),1) as nvarchar) in (select email from #temp)))                
BEGIN              
select @leadn = leadno from UserLeads where ParentID=@ParentID  
and (cast(isnull(NULLIF(@EmailID1,''),1) as nvarchar) in (select email from #temp))                 
END
end
if (@leadn='') 
begin               
if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(NULLIF(@EmailID2,''),1) as nvarchar) in (select email from #temp)))                
BEGIN              
select @leadn = leadno from UserLeads where ParentID=@ParentID  
and (cast(isnull(NULLIF(@EmailID2,''),1) as nvarchar) in (select email from #temp))              
END  
end


     
 INSERT INTO UserEnquiry      
   (      
     PersonName,      
     CompanyName,      
     MobileNo,      
     MobileNo1,      
     MobileNo2,      
     EmailID,      
     EmailID1,      
     EmailID2,      
     City,      
     STATE,      
     Country,      
     CountryCode,      
     CountryCode1,      
     CountryCode2,      
     ResidentialAddress,      
     OfficeAddress,      
     PinCode,      
     SourceName,      
     MediumName,      
     CampaignName,      
     InitialRemarks,      
     ParentID,      
     CreatedDate,      
     CreatedBy , LeadNo     
   )      
 VALUES      
   (      
     @PersonName,      
     @CompanyName,      
     @MobileNo,      
     @MobileNo1,      
     @MobileNo2,      
     @EmailID,      
     @EmailID1,      
     @EmailID2,      
     @City,      
     @State,      
     @Country,      
     @CountryCode,      
     @CountryCode1,      
     @CountryCode2,      
     @ResidentialAddress,      
     @OfficeAddress,      
     @PinCode,      
     @SourceName,      
     @MediumName,      
     @CampaignName,      
     @InitialRemarks,      
     @ParentID,      
     GETDATE(),      
     @CreatedBy,
     @leadn    
   )                
       
 --SELECT 'Record Saved Successfully'      
     
 SELECT SCOPE_IDENTITY() AS [Enquiryid];      
    
END  


