/*          
declare @p24 dbo.customEnquiry          
insert into @p24 values(NULL,N'10',N'10/26/2019')          
          
exec UspInsertUserEnquiryDetails1 @PersonName=N'uuiuiut',@CompanyName=N'',@MobileNo=N'',@MobileNo1=N'',@MobileNo2=N'',@EmailID=N'dhsj@ds.in',@EmailID1=N'',@EmailID2=N'',@City=N'',@State=N'',@Country=N'',@CountryCode=N'',@CountryCode1=N'',@CountryCode2=N''
  
    
      
        
,@ResidentialAddress=N'',@OfficeAddress=N'',@PinCode=0,@SourceName=475563,@MediumName=0,@CampaignName=0,@InitialRemarks=N'',@ParentID=335,@CreatedBy=N'335',@custom=@p24          
go          
*/      
CREATE   PROCEDURE dbo.UspInsertUserEnquiryDetails1 (      
 @PersonName NVARCHAR(100)      
 ,@CompanyName NVARCHAR(100)      
 ,@MobileNo NVARCHAR(100)      
 ,@MobileNo1 NVARCHAR(100)      
 ,@MobileNo2 NVARCHAR(100)      
 ,@EmailID NVARCHAR(100)      
 ,@EmailID1 NVARCHAR(100)      
 ,@EmailID2 NVARCHAR(100)      
 ,@City NVARCHAR(50)      
 ,@State NVARCHAR(50)      
 ,@Country NVARCHAR(50)      
 ,@CountryCode NVARCHAR(50)      
 ,@CountryCode1 NVARCHAR(50)      
 ,@CountryCode2 NVARCHAR(50)      
 ,@ResidentialAddress NVARCHAR(500) = ''      
 ,@OfficeAddress NVARCHAR(500) = ''     
 ,@PinCode BIGINT      
 ,@SourceName BIGINT      
 ,@MediumName BIGINT      
 ,@CampaignName BIGINT      
 ,@InitialRemarks NVARCHAR(1000)      
 ,@ParentID BIGINT      
 ,@CreatedBy NVARCHAR(50)      
 ,@WhereAddress NVARCHAR(255) = ''      
 ,@WhereLatitude NVARCHAR(255) = ''      
 ,@WhereLongitude NVARCHAR(255) = ''      
 ,@EnquiryTags NVARCHAR(max) = NULL      
 ,@custom CUSTOMENQUIRY1 READONLY      
 )      
AS      
BEGIN      
 SET @MobileNo = rtrim(ltrim(@MobileNo))      
 SET @MobileNo1 = rtrim(ltrim(@MobileNo1))      
 SET @MobileNo2 = rtrim(ltrim(@MobileNo2))      
      
 --declare @MobileNo NVARCHAR(100)='9015559488',@MobileNo1 NVARCHAR(100)='',@MobileNo2 NVARCHAR(100)='',@EmailID NVARCHAR(100)='',@EmailID1 NVARCHAR(100)='',@EmailID2 NVARCHAR(100)='',@CountryCode NVARCHAR(50)='+91',@CountryCode1 NVARCHAR(50)='',@CountryCode2 NVARCHAR(50)='',@ParentID bigint=39348           
 DECLARE @newenq BIGINT;      
 -- drop table if exists #temp      
 -- CREATE TABLE #temp            
 -- (            
 --leadno bigint,      
 --mobile VARCHAR(100),          
 --email VARCHAR(100)          
 -- );            
 --INSERT INTO #temp            
 --(leadno,mobile, email)            
 --SELECT leadno,CAST(ISNULL(CountryCode, 0) AS NVARCHAR)+CAST(ISNULL(NULLIF(MobileNo, ''), 0) AS NVARCHAR), ISNULL(NULLIF(EmailID, ''), 0)            
 --FROM UserLeads(nolock)      
 --WHERE ParentID=@PARENTID      
 --UNION            
 --SELECT leadno,CAST(ISNULL(CountryCode1, 0) AS NVARCHAR)+CAST(ISNULL(NULLIF(MobileNo1, ''), 0) AS NVARCHAR), ISNULL(NULLIF(EmailID1, ''), 0)            
 --FROM UserLeads(nolock)            
 --WHERE ParentID=@PARENTID      
 --UNION            
 --SELECT leadno,CAST(ISNULL(CountryCode2, 0) AS NVARCHAR)+CAST(ISNULL(NULLIF(MobileNo2, ''), 0) AS NVARCHAR), ISNULL(NULLIF(EmailID2, ''), 0)            
 --FROM UserLeads(nolock)      
 --WHERE ParentID=@PARENTID      
 DECLARE @leadn AS BIGINT;      
      
 SELECT @leadn = UL.LeadNo      
 FROM UserLeads(NOLOCK) UL      
 INNER JOIN Userleads_Mobile_Email VUL ON UL.LeadNo = VUL.leadno      
  AND UL.ParentID = VUL.Parentid      
 WHERE UL.ParentID = @ParentID      
  AND (      
   VUL.CountryCode + VUL.Mobile = CAST(ISNULL(@CountryCode, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo, 1) AS NVARCHAR)      
   OR VUL.CountryCode + VUL.Mobile = CAST(ISNULL(@CountryCode1, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo1, 1) AS NVARCHAR)      
   OR VUL.CountryCode + VUL.Mobile = CAST(ISNULL(@CountryCode2, 1) AS NVARCHAR) + CAST(ISNULL(@MobileNo2, 1) AS NVARCHAR)      
   OR VUL.email = CAST(ISNULL(NULLIF(@EmailID, ''), '11') AS NVARCHAR)      
   OR VUL.email = CAST(ISNULL(NULLIF(@EmailID1, ''), '22') AS NVARCHAR)      
   OR VUL.email = CAST(ISNULL(NULLIF(@EmailID2, ''), '33') AS NVARCHAR)      
   )      
      
 --  IF EXISTS(SELECT 1 FROM UserLeads(nolock) WHERE ParentID=@ParentID AND CAST(ISNULL(@CountryCode, 1) AS NVARCHAR)+CAST(ISNULL(@MobileNo, 1) AS NVARCHAR) IN (SELECT Mobile FROM #temp))            
 --  BEGIN            
 --SELECT @leadn=leadno        
 --FROM UserLeads(nolock)      
 --WHERE ParentID=@ParentID AND CAST(ISNULL(@CountryCode, 1) AS NVARCHAR)+CAST(ISNULL(@MobileNo, 1) AS NVARCHAR) IN (SELECT Mobile FROM #temp);         
 --  END;            
 --  IF @leadn=''      
 --  BEGIN            
 --IF EXISTS(SELECT 1 FROM UserLeads WHERE ParentID=@ParentID AND CAST(ISNULL(@CountryCode1, 1) AS NVARCHAR)+CAST(ISNULL(@MobileNo1, 1) AS NVARCHAR) IN (SELECT Mobile FROM #temp))            
 --BEGIN            
 --SELECT @leadn=leadno            
 --FROM UserLeads            
 --WHERE ParentID=@ParentID AND CAST(ISNULL(@CountryCode1, 1) AS NVARCHAR)+CAST(ISNULL(@MobileNo1, 1) AS NVARCHAR) IN (SELECT Mobile FROM #temp);            
 --END;            
 --IF EXISTS(SELECT 1 FROM UserLeads WHERE ParentID=@ParentID AND CAST(ISNULL(@CountryCode2, 1) AS NVARCHAR)+CAST(ISNULL(@MobileNo2, 1) AS NVARCHAR) IN (SELECT Mobile FROM #temp))            
 --BEGIN            
 --SELECT @leadn=leadno            
 --FROM UserLeads            
 --WHERE ParentID=@ParentID AND CAST(ISNULL(@CountryCode2, 1) AS NVARCHAR)+CAST(ISNULL(@MobileNo2, 1) AS NVARCHAR) IN (SELECT Mobile FROM #temp);            
 --END;            
 --  IF EXISTS(SELECT 1 FROM UserLeads WHERE ParentID=@ParentID AND CAST(ISNULL(NULLIF(@EmailID, ''), 1) AS NVARCHAR) IN (SELECT email FROM #temp))            
 --BEGIN            
 --SELECT @leadn=leadno            
 --FROM UserLeads            
 --WHERE ParentID=@ParentID AND CAST(ISNULL(NULLIF(@EmailID, ''), 1) AS NVARCHAR) IN (SELECT email FROM #temp);            
 --END;            
 --IF EXISTS(SELECT 1 FROM UserLeads WHERE ParentID=@ParentID AND CAST(ISNULL(NULLIF(@EmailID1, ''), 1) AS NVARCHAR) IN (SELECT email FROM #temp))            
 --BEGIN            
 --SELECT @leadn=leadno            
 --FROM UserLeads            
 --WHERE ParentID=@ParentID AND CAST(ISNULL(NULLIF(@EmailID1, ''), 1) AS NVARCHAR) IN (SELECT email FROM #temp);            
 --END;            
 --IF EXISTS(SELECT 1 FROM UserLeads WHERE ParentID=@ParentID AND CAST(ISNULL(NULLIF(@EmailID2, ''), 1) AS NVARCHAR) IN (SELECT email FROM #temp))            
 --BEGIN            
 --SELECT @leadn=leadno            
 --FROM UserLeads            
 --WHERE ParentID=@ParentID AND CAST(ISNULL(NULLIF(@EmailID2, ''), 1) AS NVARCHAR) IN (SELECT email FROM #temp);            
 --END;            
 --  END;            
 --select @leadn      
 DECLARE @latitude FLOAT = NULL;      
      
 IF (ISNULL(@WhereLatitude, '') <> '')      
 BEGIN      
  SET @latitude = cast(@WhereLatitude AS FLOAT)      
 END      
      
 DECLARE @longitude FLOAT = NULL;      
      
 IF (ISNULL(@WhereLatitude, '') <> '')      
 BEGIN      
  SET @longitude = cast(@WhereLongitude AS FLOAT)      
 END      
      
 IF NOT EXISTS (      
   SELECT 1      
   FROM UserEnquiry      
   WHERE PersonName = @PersonName      
    AND MobileNo = @MobileNo      
    AND MobileNo1 = @MobileNo1      
    AND MobileNo2 = @MobileNo2      
    AND EmailID = @EmailID      
    AND EmailID1 = @EmailID1      
    AND EmailID2 = @EmailID2      
    AND CountryCode = @CountryCode      
    AND CountryCode1 = @CountryCode1      
    AND CountryCode2 = @CountryCode2      
    AND SourceName = @SourceName      
    AND ParentID = @ParentID      
    AND CreatedBy = @CreatedBy      
   )      
 BEGIN      
  INSERT INTO UserEnquiry (      
   PersonName      
   ,CompanyName      
   ,MobileNo      
   ,MobileNo1      
   ,MobileNo2      
   ,EmailID      
   ,EmailID1      
   ,EmailID2      
   ,City      
   ,STATE      
   ,Country      
   ,CountryCode      
   ,CountryCode1      
   ,CountryCode2      
   ,ResidentialAddress      
   ,OfficeAddress      
   ,PinCode      
   ,SourceName      
   ,MediumName      
   ,CampaignName      
   ,InitialRemarks      
   ,ParentID      
   ,CreatedDate      
   ,CreatedBy      
   ,LeadNo      
   ,enquirysource      
   ,whereAddress      
 ,latitude      
   ,longitude      
   ,IsOpen      
   )      
  VALUES (      
   @PersonName      
   ,@CompanyName      
   ,@MobileNo      
   ,@MobileNo1      
   ,@MobileNo2      
   ,@EmailID      
   ,@EmailID1      
   ,@EmailID2      
   ,@City      
   ,@State      
   ,@Country      
   ,@CountryCode      
   ,@CountryCode1      
   ,@CountryCode2      
   ,@ResidentialAddress      
   ,@OfficeAddress      
   ,@PinCode      
   ,@SourceName      
   ,@MediumName      
   ,@CampaignName      
   ,@InitialRemarks      
   ,@ParentID      
   ,GETDATE()      
   ,@CreatedBy      
   ,@leadn      
   ,12      
   ,@WhereAddress      
   ,@latitude      
   ,@longitude      
   ,CASE       
    WHEN @leadn IS NULL      
     THEN 1      
    ELSE 0      
    END      
   );      
      
  --SELECT 'Record Saved Successfully'                          
  --SELECT SCOPE_IDENTITY() AS [Enquiryid];                    
  SET @newenq = SCOPE_IDENTITY();      
      
  DECLARE @insertcount SMALLINT;      
      
  SELECT @insertcount = ISNULL(COUNT(fieldID), 0)      
  FROM @custom;      
      
  IF @insertcount > 0      
  BEGIN      
   SELECT *      
   INTO #temp19      
   FROM @custom;      
      
   UPDATE #temp19      
   SET EnquiryID = @newenq;      
      
   INSERT INTO customfieldEnquiryvalue (      
    EnquiryID      
    ,fieldID      
    ,fieldvalue      
    )      
   SELECT *      
   FROM #temp19;      
      
   DROP TABLE #temp19;      
  END;      
      
  IF (ISNULL(@EnquiryTags, '') <> '')      
  BEGIN      
   DROP TABLE      
      
   IF EXISTS #tempTagName      
    SELECT tn.*      
     ,tm.ID AS tagId      
     ,0 AS isProcess      
    INTO #tempTagName      
    FROM (      
     SELECT [position] AS [id]      
      ,LTRIM(RTRIM(iif(CHARINDEX(':', [value], 1) = 0, [value], SUBSTRING([value], 1, CHARINDEX(':', [value], 1) - 1)))) AS [tagName]      
     FROM fn_Split(@EnquiryTags, ',')      
     ) AS tn      
    LEFT JOIN TagMaster(NOLOCK) tm ON tm.ParentID = @ParentID      
     AND lower(tm.Tag) = lower(tagName)      
      
   WHILE (      
     EXISTS (      
      SELECT *      
      FROM #tempTagName      
      WHERE isProcess = 0      
      )      
     )      
   BEGIN      
    DECLARE @tId INT      
     ,@tTagName NVARCHAR(255)      
     ,@tagId BIGINT      
      
    SELECT TOP 1 @tId = id      
     ,@tTagName = tagName      
     ,@tagId = tagId      
    FROM #tempTagName      
    WHERE isProcess = 0      
      
    PRINT @tTagName      
      
    IF (@tagId IS NULL)      
    BEGIN      
     INSERT INTO TagMaster (      
      Tag      
      ,ParentID      
      ,CreatedDate      
      ,CreatedBy      
      )      
     VALUES (      
      @tTagName      
      ,@ParentID      
      ,getdate()      
      ,@CreatedBy      
      )      
      
     DECLARE @sId BIGINT = scope_identity()      
      
     UPDATE #tempTagName      
     SET tagId = @sId      
     WHERE id = @tId      
    END      
      
    UPDATE #tempTagName      
    SET isProcess = 1      
    WHERE id = @tId      
   END      
      
   DELETE EntityTagMapping      
   WHERE EntityID = @newenq      
    AND lower(Entity) = 'enquiry'      
      
   INSERT INTO EntityTagMapping (      
    EntityID      
    ,Entity      
    ,TagID      
    ,CreatedDate      
    )      
   SELECT @newenq      
    ,'Enquiry'      
    ,tagId      
    ,getdate()      
   FROM #tempTagName      
  END      
      
  SELECT @newenq AS Enquiryid;      
 END      
 ELSE      
 BEGIN      
  SELECT '' AS Enquiryid;      
 END      
      
 DECLARE @rowJson NVARCHAR(MAX) = (      
   SELECT *      
   FROM UserEnquiry  WITH(NOLOCK)    
   WHERE EnquiryID = @newenq      
   FOR JSON AUTO      
    ,INCLUDE_NULL_VALUES      
   )      
      
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy      
  ,@Activity_type = 'Inst_enqry'      
  ,@ActionType = 'I'      
  ,@RowJson = @rowJson      
  ,@Table_name = 'UserEnquiry'      
END; 


GO

