select  tagName,@ParentID,getdate(),@createdby  FROM #tempTagName t where not exists  
(select 1 from tagmaster(nolock) where parentid=@parentid and tag= t.tagname)  
  
update t set tagid=g.id from #tempTagName t join #tagid g on g.tagname=t.tagName  
  
   DELETE EntityTagMapping  WHERE parentid=@parentid and EntityID = @newenq  AND lower(Entity) = 'enquiry'          
          
   INSERT INTO EntityTagMapping (          
    EntityID          
    ,Entity          
    ,TagID          
    ,CreatedDate          
    )          
   SELECT @newenq          
    ,'Enquiry'          
,tagId          
    ,getdate()          
   FROM #tempTagName          
  END          
ENd          
SELECT @newenq AS Enquiryid;          
ENd          
 ELSE          
 BEGIN          
  SELECT '' AS Enquiryid;          
 END          
          
 DECLARE @rowJson NVARCHAR(MAX) = (          
   SELECT *          
   FROM UserEnquiry (nolock)         
   WHERE EnquiryID = @newenq          
   FOR JSON AUTO          
    ,INCLUDE_NULL_VALUES          
   )          
          
