CREATE   PROCEDURE [dbo].[UspInsertUserLeadDetails]          
 @EnquiryID BIGINT,          
 @AssignedTo BIGINT,          
 @ParentID BIGINT,          
 @FollowUpStatus BIGINT,          
 @NextStatusDate VARCHAR(50),          
 @Remarks VARCHAR(1000),          
 @Products VARCHAR(1000),          
 @AmountPaid NUMERIC(18, 2),          
 @CreatedBy BIGINT          
AS          
BEGIN          
 DECLARE @PersonName NVARCHAR(100),          
         @CompanyName NVARCHAR(100),          
         @MobileNo NVARCHAR(100),          
         @MobileNo1 NVARCHAR(100),          
         @MobileNo2 NVARCHAR(100),          
         @EmailID NVARCHAR(100),          
         @EmailID1 NVARCHAR(100),          
         @EmailID2 NVARCHAR(100),          
         @City NVARCHAR(50),          
         @State NVARCHAR(50),          
         @Country NVARCHAR(50),          
         @CountryCode NVARCHAR(50),          
         @ResidentialAddress NVARCHAR(500),          
         @OfficeAddress NVARCHAR(500),          
         @PinCode BIGINT,          
         @SourceName BIGINT,          
         @MediumName BIGINT,          
         @CampaignName BIGINT,          
         @InitialRemarks NVARCHAR(1000)                  
           
 DECLARE @LeadNo BIGINT    
 declare @leadid bigint                
  declare @conversion varchar(50)=null         
 SELECT @LeadNo = ISNULL(MAX(LeadNo), 0) + 1          
 FROM   UserLeads          
 WHERE  ParentID = @ParentID                    
  declare @FollowupDate   Datetime = null        
  if(@NextStatusDate !='' and @NextStatusDate is not null)
begin
begin try
  set @FollowupDate=convert(datetime,@NextStatusDate)
end try
begin catch
  if(@FollowupDate is null)
   begin
   set @conversion= 'Invalid Date'
   end
end catch   
end         
           
           
 SELECT @PersonName = PersonName,          
        @CompanyName            = CompanyName,          
        @MobileNo               = MobileNo,          
        @MobileNo1              = MobileNo1,          
        @MobileNo2              = MobileNo2,          
        @EmailID                = EmailID,          
        @EmailID1               = EmailID1,          
        @EmailID2               = EmailID2,          
        @City                   = City,          
        @State                  = STATE,          
        @Country                = Country,          
        @CountryCode            = CountryCode,          
        @ResidentialAddress     = ResidentialAddress,          
        @OfficeAddress          = OfficeAddress,          
        @PinCode                = PinCode,          
        @SourceName             = SourceName,          
        @MediumName             = MediumName,          
        @CampaignName           = CampaignName,          
        @InitialRemarks         = InitialRemarks          
 FROM   UserEnquiry          
 WHERE  EnquiryID               = @EnquiryID             
           
           
           
 INSERT INTO UserLeads          
   (          
     LeadNo,          
     PersonName,          
     CompanyName,          
     MobileNo,          
     MobileNo1,          
     MobileNo2,          
     EmailID,          
     EmailID1,          
     EmailID2,          
     City,          
     STATE,          
     Country,          
     CountryCode,          
     ResidentialAddress,          
     OfficeAddress,          
     PinCode,          
     AssignedTo,          
     SourceName,          
     MediumName,          
     CampaignName,          
     InitialRemarks,          
     ParentID,          
     FollowUpStatus,          
     NextStatusDate,          
     Remarks,          
     Products,          
     AmountPaid,          
     CreatedOn,          
     CreatedBy,          
     ModifiedOn,          
     ModifiedBy,
     FollowupDate          
   )          
 VALUES          
   (          
     @LeadNo,          
     @PersonName,          
     @CompanyName,          
     @MobileNo,          
     @MobileNo1,          
     @MobileNo2,          
     @EmailID,          
     @EmailID1,          
     @EmailID2,          
     @City,          
     @State,          
     @Country,          
     @CountryCode,          
     @ResidentialAddress,          
     @OfficeAddress,          
     @PinCode,          
     @AssignedTo,          
     @SourceName,          
     @MediumName,          
     @CampaignName,          
     @InitialRemarks,          
     @ParentID,          
     @FollowUpStatus,          
     @NextStatusDate,          
     @Remarks,          
     @Products,          
     @AmountPaid,          
     GETDATE(),          
     @CreatedBy,          
     GETDATE(),          
     @CreatedBy,
     @FollowupDate          
