   values(          
   @EnquiryID,          
   @LeadNo,          
   0          
   )                     
             
             
 UPDATE UserEnquiry            
 SET    IsOpen = 0, LeadNo =@LeadNo           
 WHERE  EnquiryID = @EnquiryID            
             
 SELECT 'Record Saved Successfully'            
END 


