/* ============================================================
   Procedure: [dbo].[UspInsertUserLeadDetails1WithLocation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[UspInsertUserLeadDetails1WithLocation] (  
 @EnquiryID BIGINT  
 ,@AssignedTo BIGINT  
 ,@ParentID BIGINT  
 ,@FollowUpStatus BIGINT  
 ,@NextStatusDate VARCHAR(50)  
 ,@Remarks VARCHAR(1000)  
 ,@Products VARCHAR(1000)  
 ,@AmountPaid NUMERIC(18, 2)  
 ,@CreatedBy BIGINT  
 ,@IsReAssign BIT = 0  
 ,@WhereLatitude NVARCHAR(100) = ''            
 ,@WhereLongitude NVARCHAR(100) = ''             
 )  
AS  
BEGIN  
 DECLARE @PersonName NVARCHAR(100)  
  ,@CompanyName NVARCHAR(100)  
  ,@MobileNo NVARCHAR(100)  
  ,@MobileNo1 NVARCHAR(100)  
  ,@MobileNo2 NVARCHAR(100)  
  ,@EmailID NVARCHAR(100)  
  ,@EmailID1 NVARCHAR(100)  
  ,@EmailID2 NVARCHAR(100)  
  ,@City NVARCHAR(50)  
  ,@State NVARCHAR(50)  
  ,@Country NVARCHAR(50)  
  ,@CountryCode NVARCHAR(50)  
  ,@CountryCode1 NVARCHAR(50)  
  ,@CountryCode2 NVARCHAR(50)  
  ,@ResidentialAddress NVARCHAR(500)  
  ,@OfficeAddress NVARCHAR(500)  
  ,@PinCode BIGINT  
  ,@SourceName BIGINT  
  ,@MediumName BIGINT  
  ,@CampaignName BIGINT  
  ,@InitialRemarks NVARCHAR(1000)  
 DECLARE @LeadNo BIGINT  
  ,@EnqLeadNo BIGINT  
 DECLARE @FollowupDate DATETIME = NULL  
 DECLARE @conversion VARCHAR(50) = NULL  
  
 SELECT @PersonName = PersonName  
  ,@CompanyName = CompanyName  
  ,@MobileNo = isnull(MobileNo, '')  
  ,@MobileNo1 = isnull(MobileNo1, '')  
  ,@MobileNo2 = isnull(MobileNo2, '')  
  ,@EmailID = isnull(EmailID, '')  
  ,@EmailID1 = isnull(EmailID1, '')  
  ,@EmailID2 = isnull(EmailID2, '')  
  ,@City = City  
  ,@State = STATE  
  ,@Country = Country  
  ,@CountryCode = isnull(CountryCode, '')  
  ,@CountryCode1 = isnull(CountryCode1, '')  
  ,@CountryCode2 = isnull(CountryCode2, '')  
  ,@ResidentialAddress = ResidentialAddress  
  ,@OfficeAddress = OfficeAddress  
  ,@PinCode = PinCode  
  ,@SourceName = SourceName  
  ,@MediumName = MediumName  
  ,@CampaignName = CampaignName  
  ,@InitialRemarks = InitialRemarks  
  ,@EnqLeadNo = isnull(LeadNo, 0)  
   
 FROM UserEnquiry(NOLOCK)  
 WHERE EnquiryID = @EnquiryID  
  
 IF (@EnqLeadNo = 0)  
 BEGIN  
  -- declare @CountryCode NVARCHAR(100)='+91',@MobileNo NVARCHAR(100)='9313943055', @CountryCode1 NVARCHAR(100)='', @MobileNo1 NVARCHAR(100)='', @CountryCode2 NVARCHAR(100)='', @MobileNo2 NVARCHAR(100)='', @EmailID NVARCHAR(100)='', @EmailID1 NVARCHAR(100)='', @EmailID2 NVARCHAR(100)='', @ParentID BIGINT=32222      
  IF EXISTS (  
    SELECT 1  
    FROM userleads_mobile_email(NOLOCK)  
    WHERE ParentID = @ParentID  
     AND (  
      (  
       mobile <> '0'  
       AND mobile IN (  
        @MobileNo  
        ,@MobileNo1  
        ,@MobileNo2  
        )  
       )  
      OR (  
       email <> '1'  
       AND email IN (  
        @EmailID  
        ,@EmailID1  
        ,@EmailID2  
        )  
       )  
      )  
    )  
   --(      
   -- select (isnull(CountryCode,'') + isnull(MobileNo,'')) as MobileNo, isnull(EmailID,'') as EmailID       
   -- from UserLeads(nolock) where ParentID=@ParentID      
   -- union                             
   -- select (isnull(CountryCode1,'') + isnull(MobileNo1,'')) as MobileNo, isnull(EmailID1,'') as EmailID       
   -- from UserLeads(nolock) where ParentID=@ParentID      
   -- union                             
   -- select (isnull(CountryCode2,'') + isnull(MobileNo2,'')) as MobileNo, isnull(EmailID2,'') as EmailID      
   -- from UserLeads(nolock) where ParentID=@ParentID      
   --) A      
   --Where (A.MobileNo != '' and  A.MobileNo in (@CountryCode+@MobileNo,@CountryCode1+@MobileNo1,@CountryCode2+@MobileNo2)) or       
   --  (A.EmailID != '' and  A.EmailID in (@EmailID,@EmailID1,@EmailID2))      
  BEGIN  
   SELECT @LeadNo = max(LeadNo)  
   FROM userleads_mobile_email(NOLOCK)  
   WHERE ParentID = @ParentID  
    AND (  
     (  
      mobile <> '0'  
      AND mobile IN (  
       @MobileNo  
       ,@MobileNo1  
       ,@MobileNo2  
       )  
      )  
     OR (  
      email <> '1'  
      AND email IN (  
       @EmailID  
       ,@EmailID1  
       ,@EmailID2  
       )  
      )  
     )  
  
   --(      
   -- select (isnull(CountryCode,'') + isnull(MobileNo,'')) as MobileNo, isnull(EmailID,'') as EmailID, LeadNo       
   -- from UserLeads(nolock) where ParentID=@ParentID      
   -- union                             
   -- select (isnull(CountryCode1,'') + isnull(MobileNo1,'')) as MobileNo, isnull(EmailID1,'') as EmailID, LeadNo      
   -- from UserLeads(nolock) where ParentID=@ParentID      
   -- union                             
   -- select (isnull(CountryCode2,'') + isnull(MobileNo2,'')) as MobileNo, isnull(EmailID2,'') as EmailID, LeadNo      
   -- from UserLeads(nolock) where ParentID=@ParentID      
   --) A      
   --Where (A.MobileNo != '' and  A.MobileNo in (@CountryCode+@MobileNo,@CountryCode1+@MobileNo1,@CountryCode2+@MobileNo2)) or (A.EmailID != '' and  A.EmailID in (@EmailID,@EmailID1,@EmailID2))      
   UPDATE UserEnquiry  
   SET IsOpen = 0  
    ,LeadNo = @LeadNo  
   WHERE EnquiryID = @EnquiryID  
  
   SELECT 'Lead already Generated' AS Msg  
    ,0 AS leadid  
  END  
  ELSE  
  BEGIN  
   SELECT @LeadNo = ISNULL(MAX(LeadNo), 0) + 1  
   FROM UserLeads(NOLOCK)  
   WHERE ParentID = @ParentID  
  
   IF (  
     @NextStatusDate != ''  
     AND @NextStatusDate IS NOT NULL  
     )  
   BEGIN  
    BEGIN TRY  
     SET @FollowupDate = convert(DATETIME, @NextStatusDate)  
  
     SELECT @FollowupDate = dbo.[fn_getISTtimefromusertime](@CreatedBy, @FollowupDate)  
  
     SELECT @NextStatusDate = convert(NVARCHAR(50), @FollowupDate)  
    END TRY  
  
    BEGIN CATCH  
     IF (@FollowupDate IS NULL)  
     BEGIN  
      SET @conversion = 'Invalid Date'  
     END  
    END CATCH  
   END  
  
   DECLARE @leadid BIGINT  
   DECLARE @insertcount INT  
  
   INSERT INTO UserLeads (  
    LeadNo  
    ,PersonName  
    ,CompanyName  
    ,MobileNo  
    ,MobileNo1  
    ,MobileNo2  
    ,EmailID  
    ,EmailID1  
    ,EmailID2  
    ,City  
    ,STATE  
    ,Country  
    ,CountryCode  
    ,ResidentialAddress  
    ,OfficeAddress  
    ,PinCode  
    ,AssignedTo  
    ,SourceName  
    ,MediumName  
    ,CampaignName  
    ,InitialRemarks  
    ,ParentID  
    ,FollowUpStatus  
    ,NextStatusDate  
    ,Remarks  
    ,Products  
    ,AmountPaid  
    ,CreatedOn  
    ,CreatedBy  
    ,ModifiedOn  
    ,ModifiedBy  
    ,FollowupDate  
    ,enquirysource  
    ,latitude  
    ,longitude  
  
    )  
   VALUES (  
    @LeadNo  
    ,@PersonName  
    ,@CompanyName  
    ,@MobileNo  
    ,@MobileNo1  
    ,@MobileNo2  
    ,@EmailID  
    ,@EmailID1  
    ,@EmailID2  
    ,@City  
    ,@State  
    ,@Country  
    ,@CountryCode  
    ,@ResidentialAddress  
    ,@OfficeAddress  
    ,@PinCode  
    ,@AssignedTo  
    ,@SourceName  
    ,@MediumName  
    ,@CampaignName  
    ,@InitialRemarks  
    ,@ParentID  
    ,@FollowUpStatus  
    ,@NextStatusDate  
    ,@Remarks  
    ,@Products  
    ,@AmountPaid  
    ,GETDATE()  
    ,@CreatedBy  
    ,GETDATE()  
    ,@CreatedBy  
    ,@FollowupDate  
    ,15 --Merge    
    ,@WhereLatitude  
    ,@WhereLongitude  
    )  
  
   SELECT @leadid = SCOPE_IDENTITY();  
  
   IF (@conversion = 'Invalid Date')  
   BEGIN  
    INSERT INTO followupDateError (  
     leadid  
     ,nextstatusdate  
     ,parentid  
     )  
    VALUES (  
     @leadid  
     ,@NextStatusDate  
     ,@ParentID  
     )  
   END  
  
   SELECT EnquiryID  
    ,fieldID  
    ,fieldvalue  
   INTO #tolead  
   FROM customfieldEnquiryvalue(NOLOCK)  
   WHERE EnquiryID = @EnquiryID  
  
   SELECT @insertcount = isnull(COUNT(fieldID), 0)  
   FROM #tolead  
  
   IF (@insertcount > 0)  
   BEGIN  
    UPDATE #tolead  
    SET EnquiryID = @leadid;  
  
    INSERT INTO customfieldLeadvalue (  
     LeadID  
     ,fieldID  
     ,fieldvalue  
     )  
    SELECT EnquiryID  
     ,fieldID  
     ,fieldvalue  
    FROM #tolead;  
   END  
  
   DROP TABLE #tolead;  
  
   INSERT INTO LeadInteractionHistory (  
    LeadNo  
    ,FollowUpStatus  
    ,NextStatusDate  
    ,Products  
    ,AmountPaid  
    ,Remarks  
    ,AssignedTo  
    ,ParentID  
    ,CreatedOn  
    ,CreatedBy  
    ,FollowupDate  
    ,IsReAssign  
    )  
   --VALUES ( @LeadNo, @FollowUpStatus, @NextStatusDate, @Products, @AmountPaid, @Remarks,    
   -- @AssignedTo, @ParentID, GETDATE(), @CreatedBy, @FollowupDate, @IsReAssign )     
   SELECT LeadNo  
    ,FollowUpStatus  
    ,NextStatusDate  
    ,Products  
    ,AmountPaid  
    ,Remarks  
    ,AssignedTo  
    ,ParentID  
    ,GETDATE()  
    ,CreatedBy  
    ,FollowupDate  
    ,@IsReAssign  
   FROM UserLeads(NOLOCK)  
   WHERE ID = @leadid  
  
   --DELETE            
   --FROM UserEnquiry            
   --WHERE EnquiryID = @EnquiryID;            
   DECLARE @mergid BIGINT  
  
   INSERT INTO tbl_MergeLeadsEnquiry (  
    EnquiryNo  
    ,LeadNo  
    ,IsOpen  
    )  
   VALUES (  
    @EnquiryID  
    ,@LeadNo  
    ,0  
    )  
  
   SELECT @mergid = SCOPE_IDENTITY()  
  
   UPDATE UserEnquiry  
   SET IsOpen = 0  
    ,LeadNo = @LeadNo  
   WHERE EnquiryID = @EnquiryID  
  
   /*Start Enquiry Id Associate to Lead Id Associate with Wtatsapp */  
     
   EXEC usp_ims_UpgradeEnquiryToLead @leadid  
  
  
   /*Start Lead activity*/  
   BEGIN TRY  
    DECLARE @UserID_LDACTV BIGINT = @CreatedBy  
    DECLARE @ParentID_LDACTV BIGINT = @ParentID  
    DECLARE @LeadID_LDACTV BIGINT = isnull(@leadid, 0)  
  
    CREATE TABLE #tblEventDescrb (EVNT_Description NVARCHAR(max))  
  
    IF (isnull(@LeadID_LDACTV, 0) > 0)  
    BEGIN  
     INSERT INTO #tblEventDescrb  
     EXEC Usp_EventTemplate_DynamicVarReplacement 'Lead added from enquiry'  
      ,@UserID_LDACTV  
      ,''  
      ,''  
      ,@LeadID_LDACTV  
      ,''  
      ,NULL  
      ,0  
      ,0  
      ,''  
      ,''  
      ,0  
      ,''  
      ,0  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,NULL  
      ,0  
      ,0  
      ,0  
      ,NULL  
      ,NULL  
      ,NULL  
      ,0  
      ,NULL  
      ,NULL  
      ,NULL  
      ,0  
      ,NULL  
      ,NULL  
  
     DECLARE @evntMessage NVARCHAR(max) = ''  
  
     SELECT @evntMessage = isnull(EVNT_Description, '')  
     FROM #tblEventDescrb  
  
     IF (@evntMessage <> '')  
     BEGIN  
      EXEC UspSaveLeadActivity_withid @LeadID_LDACTV  
       ,@UserID_LDACTV  
       ,@ParentID_LDACTV  
       ,@evntMessage  
       ,'Lead added from enquiry'  
       ,'tbl_MergeLeadsEnquiry'  
       ,@mergid  
     END  
    END  
   END TRY  
  
   BEGIN CATCH  
    EXEC usp_InsertErrorInfo  
   END CATCH  
  
   IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence          
   BEGIN  
    DROP TABLE #tblEventDescrb  
   END  
  
   /*End Lead activity*/  
   SELECT 'Record Saved Successfully' AS Msg  
    ,isnull(@leadid, 0) AS leadid  
  END  
 END  
 ELSE  
 BEGIN  
  SELECT 'Lead already Generated' AS Msg  
   ,0 AS leadid  
 END  
  
 DECLARE @rowJson NVARCHAR(MAX) = (  
   SELECT *  
   FROM UserLeads WITH(NOLOCK)  
   WHERE ID = @leadid  
   FOR JSON AUTO  
    ,INCLUDE_NULL_VALUES  
   )  
  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy  
  ,@Activity_type = 'Inst_lead_frenqry'  
  ,@ActionType = 'I'  
  ,@RowJson = @rowJson  
  ,@Table_name = 'UserLeads'  
END  


