/* ============================================================
   Procedure: [dbo].[uspkit19Calls_LeadActivity]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.uspkit19Calls_LeadActivity
(
 @Kit19CallsID int
)
as
Begin

    Declare @CallerID nvarchar(50) = ''
	Declare @DNIDNo nvarchar(50) = ''
	Declare @ClientID nvarchar(50) = '0'
	Declare @RecordURL nvarchar(500) = ''
	Declare @CallAnswerTime datetime = null
	Declare @CallEndTime datetime = null 
    Declare @UniqueID nvarchar(50) = ''  
	Declare @DialStatus  nvarchar(50) = '' 
	Declare @Context nvarchar(50) = ''
	Declare @EventName nvarchar(500) =  'lead calls up'

	select top 1 @CallerID = isnull(callerid,''),@DNIDNo = ISNULL(dnid,'')
	    ,@ClientID = ISNULL(clientid,''),@RecordURL = ISNULL(recordurl,'') 
	    ,@UniqueID = isnull(uniqueid,''),@Context = isnull(context,'')

	    from Kit19Calls where id = @Kit19CallsID
     
	Select @DialStatus = isnull(dialstatus,''),@CallAnswerTime = call_answer_time
	   ,@CallEndTime = call_end_time
	 from Kit19CallsDialled where uniqueid = isnull(@UniqueID,'')
	 and  isnull(@UniqueID,'') <> ''
	  
    
	 if(rtrim(ltrim(@Context)) = 'inbound')
	    Begin

		 Declare @LeadID bigint = 0  
		 Declare @LeadName nvarchar(500) = ''
		 Declare @UserID bigint = 0
		 Declare @ParentID bigint = 0  
		 Declare @UserName nvarchar(500)
		 Declare @EventID int = 0
		 Declare @EventMSG nvarchar(max) = 0  
		 DEclare @CallDuration int = 0


		select @EventID = isnull(ID,0) from ActivityMaster where  EventName = @EventName 
        select @EventMSG =  isnull(EventTemplate,'')   from ActivityMaster where ID = @EventID


		set @UserID = isnull(@ClientID,0) 
		select @ParentID = isnull(ParentID,0),@UserName = isnull(User_Login,'')  from User_Detail where User_ID = @UserID


	 select @LeadID = isnull(ID,0),@LeadName = ISNULL(PersonName,'')  from userleads where ((MobileNo = @CallerID)
		 or(MobileNo1 = @CallerID)or(MobileNo2 = @CallerID)) and @CallerID <> ''   
		        
	       if( isnull(@LeadID,0) > 0 )
		    Begin

			   if((@CallAnswerTime is not null) and (@CallEndTime is not null) )
				   Begin    
			           select @CallDuration = DATEDIFF(SECOND,@CallAnswerTime,@CallEndTime)
 				   end
               else 
			       Begin
				       set @CallDuration = 0
				   End 

		  if(@EventMSG <> '')
		     Begin
	        select @EventMSG =
			 
     		REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(@EventMSG,'#leadname#',isnull(@LeadName,'')),'#didno#',isnull(@DNIDNo,''))
			 ,'#username#',isnull(@UserName,'')),'#callduration#',cast(isnull(@CallDuration,0) as nvarchar))
			 ,'#recordurl#',isnull(@RecordURL,''))
			 
			 if(@DialStatus = 'ANSWER')
			    Begin
				    select @EventMSG = replace(@EventMSG,'not answered/','') 
				End
			 else
			    Begin
				    select @EventMSG = replace(@EventMSG,'/answered ','') 
				End  

			   exec UspSaveLeadActivity @LeadID,@UserID,@ParentID,@EventMSG,
	                @EventName

			 
			 End




	 		End  
		
		
		
		End



    


End


GO

