   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.UspLast7DaysMailCounsumption    
(    
  @Enqno bigint,    
  @Kit19UserID bigint    
)    
as    
Begin    
        
  Declare @DateCurrentTo date = null    
    
   CREATE TABLE #TempLinked                                      
    (                                      
      Result VARCHAR(200)                                      
    )             
                        
     INSERT INTO #TempLinked                                      
     EXEC GetStatusofLinkedServer 'CRM'                                      
     IF NOT EXISTS(                                      
        SELECT 'x'                                      
        FROM   #TempLinked                                      
    )                           
    begin       
           
 select @DateCurrentTo = convert(date,CreatedDate) From CRM.CRMDB.dbo.AccountSetup where EnqNo = @Enqno and UserBy = @Kit19UserID     
 and Stage = 'Customer Accepted Setup Request'      
    
    
     
      
 Declare @DateCurrentFrom date = null    
    
 set @DateCurrentFrom =  DATEADD(day,-7, @DateCurrentTo);     
 set @DateCurrentTo =  DATEADD(day,1, @DateCurrentTo);     
     
 select sum(TotalMailConsumption) as TotalMailConsumption From DailyMailConsumption where [Date] between @DateCurrentFrom  and @DateCurrentTo and USER_ID = @Kit19UserID    
    
    
    
    
    
    End      
      
    
 drop table #TempLinked;      
      
     
        
    
    
End




