/* ============================================================
   Procedure: [dbo].[UspLastTotalCampaigns_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON




CREATE   PROCEDURE dbo.UspLastTotalCampaigns_New --444,335          
(          
  @Enqno bigint,          
  @Kit19UserID bigint          
)          
as          
Begin          
 Declare @DateCurrentTo datetime = null          
          
   CREATE TABLE #TempLinked                                            
    (                                            
      Result VARCHAR(200)                                            
    )                   
                              
     INSERT INTO #TempLinked                                            
     EXEC GetStatusofLinkedServer 'CRM'                                            
     IF NOT EXISTS(                                            
        SELECT 'x'                                            
        FROM   #TempLinked                                            
    )                                 
    begin             
          
    select @DateCurrentTo = convert(date,CreatedDate) From CRM.CRMDB.dbo.AccountSetup where EnqNo = @Enqno and UserBy = @Kit19UserID           
 and Stage = 'Customer Accepted Setup Request'            
           
 --for temp          
  -- set @DateCurrentTo = '2016-01-01 21:08:03.167'          
          
    select   CONVERT(date,CreatedOn) as Date,COUNT(CONVERT(date,CreatedOn)) as Count into #t1 From UserCampaignMaster where IsEventBased = 1 and ParentID = @Kit19UserID   
  and CONVERT(date,CreatedOn) >= convert(date,@DateCurrentTo)  group by CONVERT(date,CreatedOn)     
      
  order by  CONVERT(date,CreatedOn) asc              
          
   select   CONVERT(date,CreatedOn) as Date,COUNT(CONVERT(date,CreatedOn)) as Count into #t2  From UserCampaignMaster where IsScheduled = 1 and ParentID = @Kit19UserID  
    and CONVERT(date,CreatedOn) >= convert(date,@DateCurrentTo)  group by CONVERT(date,CreatedOn)      
     
  order by  CONVERT(date,CreatedOn) asc      
    
    
 --  select * from    
 -- (    
 -- select Date,isnull(#t1.Count,0) as EventBased , 0 as ScheduledBased  From #t1     
 -- union    
 -- Select Date,0 as EventBased , isnull(#t2.Count,0) as ScheduledBased    From #t2 --on #t1.Date = #t2.Date    
     
 --) as tbl order by date asc    
            
  
  
select tbl.Date as Date ,isnull(tbl.EventBased,0) as EventBased,isnull(tbl.ScheduledBased,0) as ScheduledBased from    
  (    
  select Date,isnull(#t1.Count,0) as EventBased ,(select ISNULL(#t2.Count,0) from #t2 where #t2.Date = #t1.date) as ScheduledBased  From #t1     
  union    
  Select Date,(select ISNULL(#t1.Count,0) from #t1 where #t1.Date = #t2.date) as EventBased , isnull(#t2.Count,0) as ScheduledBased    From #t2 --on #t1.Date = #t2.Date    
 ) as tbl order by date asc   
  
  
  
   end            
            
  drop table  #TempLinked      
  drop table #t1    
  drop table #t2            
           
 End 





GO

