/* ============================================================
   Procedure: [dbo].[UspLastTotalEshopOrders]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

     
CREATE   PROCEDURE dbo.UspLastTotalEshopOrders --678993,33097        
 (        
   @Enqno bigint,        
   @Kit19UserID bigint        
 )        
as        
Begin        
 Declare @DateCurrentTo date = null        
        
   CREATE TABLE #TempLinked                                          
    (                                          
      Result VARCHAR(200)                                          
    )                 
                            
     INSERT INTO #TempLinked                                          
     EXEC GetStatusofLinkedServer 'CRM'                                          
     IF NOT EXISTS(                                          
        SELECT 'x'                                          
        FROM   #TempLinked                                          
    )                               
    begin           
        
    select @DateCurrentTo = convert(date,CreatedDate) From CRM.CRMDB.dbo.AccountSetup where EnqNo = @Enqno and UserBy = @Kit19UserID         
           and Stage = 'Customer Accepted Setup Request'          
         
 --for temp        
    -- set  @DateCurrentTo = '2019-10-12 21:08:03.167'        
         
   
  select convert(date,OrderDate) as Date ,Count(convert(date,OrderDate)) as 'Count' into #t1  from [order] where user_id = @Kit19UserID and CONVERT(date,OrderDate) >= convert(date,@DateCurrentTo)  
     group by convert(date,OrderDate) order by convert(date,OrderDate) asc   
        
     select CONVERT(date,OrderDate) as Date, count(distinct(CustomerID)) as 'Count' into #t2  From [order]  where  USER_ID = @Kit19UserID and CONVERT(date,OrderDate) >= convert(date,@DateCurrentTo)  
     group by CONVERT(date,OrderDate) order by convert(date,OrderDate) asc    
  
    
 select tbl.Date as Date ,isnull(tbl.OrderBased,0) as OrderBased,isnull(tbl.CustomerBased,0) as CustomerBased from        
  (        
    select Date,isnull(#t1.Count,0) as OrderBased ,(select ISNULL(#t2.Count,0) from #t2 where #t2.Date = #t1.date) as CustomerBased  From #t1         
      union        
    Select Date,(select ISNULL(#t1.Count,0) from #t1 where #t1.Date = #t2.date) as OrderBased , isnull(#t2.Count,0) as CustomerBased    From #t2 --on #t1.Date = #t2.Date        
  ) as tbl order by date asc       
  
  drop table #t1  
  drop table #t2  
  
  
  
  
  
  
   End          
          
        
 drop table #TempLinked;        
         
 End 


GO

