/* ============================================================
   Procedure: [dbo].[UspMailConsumptionSignalR]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.UspMailConsumptionSignalR  --30061,10043,200      
(       
 @UserID bigint,      
 @Mid bigint,      
 @Balance bigint,    
 @tblName nvarchar(200),    
 @RefID nvarchar(50)       
)      
as      
Begin      
      
    Declare @BalanceTemp numeric(18,2) = 0;      
 Declare @AVGConsumption numeric(18,2) = 0;      
      
 set @BalanceTemp = cast(@Balance as numeric(18,2))       
      
 select @AVGConsumption = dbo.FuncMailConsumption(@UserID)      
      
 if(@BalanceTemp < @AVGConsumption and not exists (select 1 from userevent(nolock) where userid=@userid and event='Low Balance Mail'  and datediff(hh,createdon,getdate())<3))      
   Begin      
             
  insert into UserEvent      
   (      
    [Event]      
         ,UserID      
         ,CRMEntry      
         ,[Description]      
         ,CreatedOn    
   ,RefTable    
   ,RefID      
   )      
   select       
     'Low Balance Mail'      
     ,User_ID      
     ,0      
     ,'User '+ user_login +'has low Mail Balance. His current balance is: '+ cast(@Balance as nvarchar) + ' while his last 7 days average consumption is: '+ CAST(@AVGConsumption as nvarchar)      
     ,getdate()    
  ,@tblName    
  ,@RefID    
    from user_detail where user_id=@userid    
         
         
   End      
        
      
End


GO

/* ============================================================
   Procedure: [dbo].[UspMoneyConsumptionSignalR]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE procedure [dbo].[UspMoneyConsumptionSignalR]  --33396,10043,200      
(       
 @UserID bigint,      
 @Mid bigint,      
 @Balance Numeric(18,4),    
 @tblName nvarchar(200),    
 @RefID nvarchar(50)       
)      
as      
Begin      
Declare @active int=(select status from user_detail(nolock) where user_id=@UserID)      
 Declare @BalanceTemp numeric(18,4) = 0;      
 Declare @AVGConsumption numeric(18,4) = 0;      
 Declare @user_login nvarchar(100)=(select user_login from user_detail(nolock) where user_id=@UserID)  
      
 set @BalanceTemp = cast(@Balance as numeric(18,4))       
      
 select @AVGConsumption = dbo.FuncMoneyConsumption(@UserID)      
      
 if(@active=1 and ((@BalanceTemp < (@AVGConsumption*7)) or @BalanceTemp<20)
 and not exists (select 1 from userevent(nolock) where userid=@UserID and event='Low Balance International Money' and datediff(hh,CreatedOn,getdate())<3)
 )      
   Begin      
             
  insert into UserEvent      
   (      
    [Event]      
         ,UserID      
         ,CRMEntry      
         ,[Description]      
         ,CreatedOn    
   ,RefTable    
   ,RefID      
   )      
   values      
   (      
     'Low Balance International Money'      
     ,@UserID      
     ,0      
     ,'User '+cast(@user_login as nvarchar)+' has low International Balance. Current balance is '+ cast(@BalanceTemp as nvarchar) +   
  ' which is low & may not last for 7 days looking at the average consumption'   
     ,getdate()    
  ,@tblName    
  ,@RefID      
   )      
         
         
   End      
        
      
End


GO

