/* ============================================================
   Procedure: [dbo].[uspReportChartCampaign]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[uspReportChartCampaign]  
 @FromDate VARCHAR(50) = NULL,  
 @ToDate VARCHAR(50) = NULL,  
 @Type VARCHAR(50) = NULL,  
 @Campaigns VARCHAR(550) = NULL,  
 @Tags VARCHAR(550) = NULL  
AS  
BEGIN  
 IF (  
        ISNULL(@fromDate, '') = ''  
        AND ISNULL(@ToDate, '') = ''  
        AND ISNULL(@Campaigns, '') = ''  
        AND ISNULL(@Tags, '') = ''  
    )  
 BEGIN  
     SELECT A.[TYPE],  
            SUM(A.NoOfRecipients)  AS NoOfRecipients,  
            SUM(A.Response)        AS Response,  
            SUM(A.Unsubscribe)     AS Unsubscribe,  
            SUM(A.Enrolled)        AS Enrolled  
     FROM   (  
                SELECT DISTINCT CASE   
                                     WHEN cm.SenderID IS NULL THEN 'MAIL'  
                                     ELSE 'SMS'  
                                END    AS [TYPE],  
                       ISNULL(cm.NoOfRecipients, 0) AS NoOfRecipients,  
                       (  
                           SELECT COUNT(*)  
                           FROM   ClientLeadDetails AS cld  
                           WHERE  cld.CampaignName = cm.CampaignName  
                                  AND cld.IsCallMicrosite = CASE   
                                                                 WHEN @Type  
                                                                      =  
                                                                      'C' THEN   
                                                                      0  
                                                                 ELSE 1  
                                                            END  
                                  AND cld.cname IN (SELECT TOP 1 csu.URLName  
                                                    FROM   CampaignShortURL AS   
                                                           csu  
                                                    WHERE  csu.CampaignName =   
                                                           cm.CampaignName  
                                                           AND csu.Track_Unsubscribe =   
                                                               0  
                                                    ORDER BY  
                                                           cld.DateCreated   
                                                           DESC)  
                       )               AS Response,  
                       (  
                           SELECT COUNT(*)  
                           FROM   ClientLeadDetails AS cld  
                           WHERE  cld.CampaignName = cm.CampaignName  
                                  AND cld.IsCallMicrosite = CASE   
                                                                 WHEN @Type  
                                                                      =  
                                                                      'C' THEN   
                                                                      0  
                                                                 ELSE 1  
                                                            END  
                                  AND cld.cname IN (SELECT TOP 1 csu.URLName  
                                                    FROM   CampaignShortURL AS   
                                                           csu  
                                                    WHERE  csu.CampaignName =   
                                                           cm.CampaignName  
                                                           AND csu.Track_Unsubscribe =   
                                                               1  
                                                    ORDER BY  
                                                           cld.DateCreated   
                                                           DESC)  
                       )               AS Unsubscribe,  
                       (  
                           SELECT COUNT(ad.EnqNo)  
                          FROM   [CRM].CRMDB.dbo.Appointment_details AS ad  
                           WHERE  ad.MeetingStatus = 'Enrolled'  
                                  AND (DATEDIFF(DAY, cm.ExecuteTime, GETDATE()) > 0)  
                       )               AS Enrolled  
                FROM   CampaignMaster  AS cm  
                WHERE  cm.IsExecuted = 1  
            )                         A  
     GROUP BY  
            A.[TYPE]  
     ORDER BY  
            A.[TYPE] DESC  
 END  
 ELSE  
 BEGIN  
     IF ISNULL(@Campaigns, '') = ''  
        AND ISNULL(@Tags, '') = ''  
     BEGIN  
         SELECT A.[TYPE],  
                SUM(A.NoOfRecipients)  AS NoOfRecipients,  
                SUM(A.Response)        AS Response,  
                SUM(A.Unsubscribe)     AS Unsubscribe,  
                SUM(A.Enrolled)        AS Enrolled  
         FROM   (  
                    SELECT DISTINCT CASE   
                                         WHEN cm.SenderID IS NULL THEN 'MAIL'  
                                         ELSE 'SMS'  
                                    END AS [TYPE],  
                           cm.ExecuteTime,  
                           ISNULL(cm.NoOfRecipients, 0) AS NoOfRecipients,  
                           (  
                               SELECT COUNT(*)  
                               FROM   ClientLeadDetails AS cld  
                               WHERE  cld.CampaignName = cm.CampaignName  
                                      AND cld.IsCallMicrosite = CASE   
                                                                     WHEN @Type  
                                                                          =  
                                                                          'C' THEN   
                                                                          0  
                                                                     ELSE 1  
                                                                END  
                                      AND cld.cname IN (SELECT TOP 1 csu.URLName  
                                                        FROM     
                                                               CampaignShortURL AS   
                                                               csu  
                                                        WHERE  csu.CampaignName =   
                                                               cm.CampaignName  
                                                               AND csu.Track_Unsubscribe =   
                                                                   0  
                                                        ORDER BY  
                                                               cld.DateCreated   
                                                               DESC)  
                           )  AS Response,  
                           (  
                               SELECT COUNT(*)  
                               FROM   ClientLeadDetails AS cld  
                               WHERE  cld.CampaignName = cm.CampaignName  
                                      AND cld.IsCallMicrosite = CASE   
                                                                     WHEN @Type  
                                                                          =  
                                                                          'C' THEN   
                                                                          0  
                                                                     ELSE 1  
                                                                END  
                                      AND cld.cname IN (SELECT TOP 1 csu.URLName  
                                                        FROM     
                                                               CampaignShortURL AS   
                                                               csu  
                                                        WHERE  csu.CampaignName =   
                                         cm.CampaignName  
                                                               AND csu.Track_Unsubscribe =   
                                                                   1  
                                                        ORDER BY  
                                                               cld.DateCreated   
                                                               DESC)  
                           )  AS Unsubscribe,  
                           (  
                               SELECT COUNT(ad.EnqNo)  
                               FROM   [CRM].CRMDB.dbo.Appointment_details AS ad  
                               WHERE  ad.MeetingStatus = 'Enrolled'  
                                      AND (DATEDIFF(DAY, cm.ExecuteTime, GETDATE()) > 0)  
                           )  AS Enrolled  
                    FROM   CampaignMaster AS cm  
                    WHERE  cm.IsExecuted = 1  
                )                         A  
         WHERE  CONVERT(DATETIME, A.ExecuteTime, 101) BETWEEN CASE   
                                                                   WHEN   
                                                                        ISNULL(@fromDate, '')   
                                                                        <>  
                                                                        '' THEN   
                                                                        CONVERT(DATETIME, ISNULL(@fromDate, ''), 101)  
                                                                   ELSE A.ExecuteTime  
                                                              END AND CASE   
                                                                           WHEN   
                                                                                ISNULL(@ToDate, '')   
                                                                                <  
                                                                                >  
                                                                                '' THEN   
                                                                                CONVERT(DATETIME, ISNULL(@ToDate, ''), 101)  
                                                                           ELSE   
                                                                                A.ExecuteTime  
                                                                      END  
         GROUP BY  
                A.[TYPE]  
         ORDER BY  
                A.[TYPE] DESC  
     END  
     ELSE   
     IF ISNULL(@Tags, '') = ''  
        AND ISNULL(@Campaigns, '') <> ''  
     BEGIN  
         SELECT A.[TYPE],  
                SUM(A.NoOfRecipients)  AS NoOfRecipients,  
                SUM(A.Response)        AS Response,  
                SUM(A.Unsubscribe)     AS Unsubscribe,  
                SUM(A.Enrolled)        AS Enrolled  
         FROM   (  
                    SELECT DISTINCT CASE   
                                         WHEN cm.SenderID IS NULL THEN 'MAIL'  
                                         ELSE 'SMS'  
                                    END AS [TYPE],  
                           cm.ExecuteTime,  
                           ISNULL(cm.NoOfRecipients, 0) AS NoOfRecipients,  
                           (  
                               SELECT COUNT(*)  
                               FROM   ClientLeadDetails AS cld  
                               WHERE  cld.CampaignName = cm.CampaignName  
                                      AND cld.IsCallMicrosite = CASE   
                                                                     WHEN @Type  
                                                                          =  
                                                                          'C' THEN   
                                                                          0  
                                                                     ELSE 1  
                                                END  
                                      AND cld.cname IN (SELECT TOP 1 csu.URLName  
                                                        FROM     
                                                               CampaignShortURL AS   
                                                               csu  
                                                        WHERE  csu.CampaignName =   
                                                               cm.CampaignName  
                                                               AND csu.Track_Unsubscribe =   
                                                                   0  
                                                        ORDER BY  
                                                               cld.DateCreated   
                                                               DESC)  
                           )  AS Response,  
                           (  
                               SELECT COUNT(*)  
                               FROM   ClientLeadDetails AS cld  
                               WHERE  cld.CampaignName = cm.CampaignName  
                                      AND cld.IsCallMicrosite = CASE   
                                                                     WHEN @Type  
                                                                          =  
                                                                          'C' THEN   
                                                                          0  
                                                                     ELSE 1  
                                                                END  
                                      AND cld.cname IN (SELECT TOP 1 csu.URLName  
                                                        FROM     
                                                               CampaignShortURL AS   
                                                               csu  
                                                        WHERE  csu.CampaignName =   
                                                               cm.CampaignName  
                                                               AND csu.Track_Unsubscribe =   
                                                                   1  
                                                        ORDER BY  
                                                               cld.DateCreated   
                                                               DESC)  
                           )  AS Unsubscribe,  
                           (  
                               SELECT COUNT(ad.EnqNo)  
                               FROM   [CRM].CRMDB.dbo.Appointment_details AS ad  
                               WHERE  ad.MeetingStatus = 'Enrolled'  
                                      AND (DATEDIFF(DAY, cm.ExecuteTime, GETDATE()) > 0)  
                           )  AS Enrolled  
                    FROM   CampaignMaster AS cm  
                    WHERE  cm.IsExecuted = 1  
                           AND cm.ID IN (SELECT fs.[value]  
                                         FROM   dbo.fn_Split(@Campaigns, '#') AS   
                                                fs)  
                )                         A  
         WHERE  CONVERT(DATETIME, A.ExecuteTime, 101) BETWEEN CASE   
                                                                   WHEN   
                                                                        ISNULL(@fromDate, '')   
                                                                        <>  
                                                                        '' THEN   
                                                                        CONVERT(DATETIME, ISNULL(@fromDate, ''), 101)  
                                                                   ELSE A.ExecuteTime  
                                                              END AND CASE   
                                      WHEN   
                                                                                ISNULL(@ToDate, '')   
                                                                                <  
                                                                                >  
                                                                                '' THEN   
                                                                                CONVERT(DATETIME, ISNULL(@ToDate, ''), 101)  
                                                                           ELSE   
                                                                                A.ExecuteTime  
                                                                      END  
         GROUP BY  
                A.[TYPE]  
         ORDER BY  
                A.[TYPE] DESC  
     END  
     ELSE   
     IF ISNULL(@Campaigns, '') = ''  
        AND ISNULL(@Tags, '') <> ''  
     BEGIN  
         SELECT A.[TYPE],  
                SUM(A.NoOfRecipients)  AS NoOfRecipients,  
                SUM(A.Response)        AS Response,  
                SUM(A.Unsubscribe)     AS Unsubscribe,  
                SUM(A.Enrolled)        AS Enrolled  
         FROM   (  
                    SELECT DISTINCT CASE   
                                         WHEN cm.SenderID IS NULL THEN 'MAIL'  
                                         ELSE 'SMS'  
                                    END AS [TYPE],  
                           cm.ExecuteTime,  
                           ISNULL(cm.NoOfRecipients, 0) AS NoOfRecipients,  
                           (  
                               SELECT COUNT(*)  
                               FROM   ClientLeadDetails AS cld  
                               WHERE  cld.CampaignName = cm.CampaignName  
                                      AND cld.IsCallMicrosite = CASE   
                                                                     WHEN @Type  
                                                                          =  
                                                                          'C' THEN   
                                                                          0  
                                                                     ELSE 1  
                                                                END  
                                      AND cld.cname IN (SELECT TOP 1 csu.URLName  
                                                        FROM     
                                                               CampaignShortURL AS   
                                                               csu  
                                                        WHERE  csu.CampaignName =   
                                                               cm.CampaignName  
                                                               AND csu.Track_Unsubscribe =   
                                                                   0  
                                                        ORDER BY  
                                                               cld.DateCreated   
                                                               DESC)  
                           )  AS Response,  
                           (  
                               SELECT COUNT(*)  
                               FROM   ClientLeadDetails AS cld  
                               WHERE  cld.CampaignName = cm.CampaignName  
                                      AND cld.IsCallMicrosite = CASE   
                                                                     WHEN @Type  
                                                                          =  
                                                                          'C' THEN   
                                                                          0  
                                                                     ELSE 1  
                                                                END  
                            AND cld.cname IN (SELECT TOP 1 csu.URLName  
                                                        FROM     
                                                               CampaignShortURL AS   
                                                               csu  
                                                        WHERE  csu.CampaignName =   
                                                               cm.CampaignName  
                                                               AND csu.Track_Unsubscribe =   
                                                                   1  
                                                        ORDER BY  
                                                               cld.DateCreated   
                                                               DESC)  
                           )  AS Unsubscribe,  
                           (  
                               SELECT COUNT(ad.EnqNo)  
                               FROM   [CRM].CRMDB.dbo.Appointment_details AS ad  
                               WHERE  ad.MeetingStatus = 'Enrolled'  
                                      AND (DATEDIFF(DAY, cm.ExecuteTime, GETDATE()) > 0)  
                           )  AS Enrolled  
                    FROM   CampaignMaster AS cm  
                           OUTER APPLY dbo.fn_Split(cm.Tags, ',') AS fs2  
                    WHERE  cm.IsExecuted = 1  
                           AND LTRIM(RTRIM(fs2.[value])) IN (SELECT fs.[value]  
                                                             FROM   dbo.fn_Split(ISNULL(@Tags, ''), '#') AS   
                                                                    fs)  
                )                         A  
         WHERE  CONVERT(DATETIME, A.ExecuteTime, 101) BETWEEN CASE   
                                                                   WHEN   
                                                                        ISNULL(@fromDate, '')   
                                                                        <>  
                                                                        '' THEN   
                                                                        CONVERT(DATETIME, ISNULL(@fromDate, ''), 101)  
                                                                   ELSE A.ExecuteTime  
                                                              END AND CASE   
                                                                           WHEN   
                                                                                ISNULL(@ToDate, '')   
                                                                                <  
                                                                                >  
                                                                                '' THEN   
                                                                                CONVERT(DATETIME, ISNULL(@ToDate, ''), 101)  
                                                                           ELSE   
                                                                                A.ExecuteTime  
                                                                      END  
         GROUP BY  
                A.[TYPE]  
         ORDER BY  
                A.[TYPE] DESC  
     END  
 END  
END  



GO

