                                                                          =  
                                                                          'C' THEN   
                                                                          0  
                                                                     ELSE 1  
                                                                END  
                                      AND cld.cname IN (SELECT TOP 1 csu.URLName  
                                                        FROM     
                                                               CampaignShortURL AS   
                                                               csu  
                                                        WHERE  csu.CampaignName =   
                                                               cm.CampaignName  
                                                      AND csu.Track_Unsubscribe =   
                                                                   1  
                                                        ORDER BY  
                                                               cld.DateCreated   
                                                               DESC)  
                           )  AS Unsubscribe,  
                           (  
                               SELECT COUNT(ad.EnqNo)  
                               FROM   [CRM].CRMDB.dbo.Appointment_details AS ad  
                               WHERE  ad.MeetingStatus = 'Enrolled'  
                                      AND (DATEDIFF(DAY, cm.ExecuteTime, GETDATE()) > 0)  
                           )  AS Enrolled  
                    FROM   CampaignMaster AS cm  
                    WHERE  cm.IsExecuted = 1  
                )                         A  
         WHERE  CONVERT(DATETIME, A.ExecuteTime, 101) BETWEEN CASE   
                                                                   WHEN   
                                                                        ISNULL(@fromDate, '')   
                                                                        <>  
                                                                        '' THEN   
                                                                        CONVERT(DATETIME, ISNULL(@fromDate, ''), 101)  
                                                                   ELSE A.ExecuteTime  
                                                              END AND CASE   
                                                                           WHEN   
                                                                                ISNULL(@ToDate, '')   
                                                                                <  
                                                                                >  
                                                                                '' THEN   
                                                                                CONVERT(DATETIME, ISNULL(@ToDate, ''), 101)  
                                                                           ELSE   
                                                                                A.ExecuteTime  
                                                                      END  
         GROUP BY  
                A.[TYPE]  
         ORDER BY  
                A.[TYPE] DESC  
     END  
     ELSE   
     IF ISNULL(@Tags, '') = ''  
        AND ISNULL(@Campaigns, '') <> ''  
     BEGIN  
         SELECT A.[TYPE],  
                SUM(A.NoOfRecipients)  AS NoOfRecipients,  
                SUM(A.Response)        AS Response,  
                SUM(A.Unsubscribe)     AS Unsubscribe,  
                SUM(A.Enrolled)        AS Enrolled  
         FROM   (  
                    SELECT DISTINCT cm.CampaignName AS [TYPE],  
                           cm.ExecuteTime,  
                           ISNULL(cm.NoOfRecipients, 0) AS NoOfRecipients,  
                           (  
                               SELECT COUNT(*)  
                               FROM   ClientLeadDetails AS cld  
                               WHERE  cld.CampaignName = cm.CampaignName  
                                      AND cld.IsCallMicrosite = CASE   
                                                                     WHEN   
                                                                          ISNULL(@Type, '')  
                                                                          =  
                                                                          'C' THEN   
                                                                          0  
                                                                     ELSE 1  
                                                                END  
                                      AND cld.cname IN (SELECT TOP 1 csu.URLName  
                                                 FROM     
                                                               CampaignShortURL AS   
                                                               csu  
                                                        WHERE  csu.CampaignName =   
                                                               cm.CampaignName  
                                                               AND csu.Track_Unsubscribe =   
                                                                   0  
                                                        ORDER BY  
                                                               cld.DateCreated   
                                                               DESC)  
                           )  AS Response,  
                           (  
                               SELECT COUNT(*)  
                               FROM   ClientLeadDetails AS cld  
                               WHERE  cld.CampaignName = cm.CampaignName  
                                      AND cld.IsCallMicrosite = CASE   
                                                                     WHEN   
                                                                          ISNULL(@Type, '')  
                                                                          =  
                                                                          'C' THEN   
                                                                          0  
                                                                     ELSE 1  
                                                                END  
                                      AND cld.cname IN (SELECT TOP 1 csu.URLName  
                                                        FROM     
                                                               CampaignShortURL AS   
                                                               csu  
                                                        WHERE  csu.CampaignName =   
                                                               cm.CampaignName  
                                                               AND csu.Track_Unsubscribe =   
                                                                   1  
                                                        ORDER BY  
                                                               cld.DateCreated   
                                                               DESC)  
                           )  AS Unsubscribe,  
                           (  
                               SELECT COUNT(ad.EnqNo)  
                               FROM   [CRM].CRMDB.dbo.Appointment_details AS ad  
                               WHERE  ad.MeetingStatus = 'Enrolled'  
                                      AND (DATEDIFF(DAY, cm.ExecuteTime, GETDATE()) > 0)  
                           )  AS Enrolled  
                    FROM   CampaignMaster AS cm  
                    WHERE  cm.IsExecuted = 1  
                           AND cm.ID IN (SELECT fs.[value]  
                                         FROM   dbo.fn_Split(ISNULL(@Campaigns, ''), '#') AS   
                                                fs)  
                )                         A  
         WHERE  CONVERT(DATETIME, A.ExecuteTime, 101) BETWEEN CASE   
                                                                   WHEN   
                                                                        ISNULL(@fromDate, '')   
                                                                        <  
                                                                        >  
                                                                        '' THEN   
                                                                        CONVERT(DATETIME, ISNULL(@fromDate, ''), 101)  
                                                                   ELSE A.ExecuteTime  
                                                              END AND CASE   
                                                                      WHEN   
                                                                                ISNULL(@ToDate, '')   
                                                                                <  
                                                                                >  
                                                                                '' THEN   
                                                                                CONVERT(DATETIME, ISNULL(@ToDate, ''), 101)  
                                                                           ELSE   
                                                                                A.ExecuteTime  
                                                                      END  
         GROUP BY  
                A.[TYPE]  
         ORDER BY  
                A.[TYPE] DESC  
     END  
     ELSE   
     IF ISNULL(@Campaigns, '') = ''  
        AND ISNULL(@Tags, '') <> ''  
     BEGIN  
         SELECT A.[TYPE],  
                SUM(A.NoOfRecipients)  AS NoOfRecipients,  
                SUM(A.Response)        AS Response,  
                SUM(A.Unsubscribe)     AS Unsubscribe,  
                SUM(A.Enrolled)        AS Enrolled  
         FROM   (  
                    SELECT DISTINCT cm.CampaignName AS [TYPE],  
                           cm.ExecuteTime,  
                           ISNULL(cm.NoOfRecipients, 0) AS NoOfRecipients,  
                           (  
                               SELECT COUNT(*)  
                               FROM   ClientLeadDetails AS cld  
                               WHERE  cld.CampaignName = cm.CampaignName  
                                      AND cld.IsCallMicrosite = CASE   
                                                                     WHEN   
                                                                          ISNULL(@Type, '')  
                                                                          =  
                                                                          'C' THEN   
                                                                          0  
                                                                     ELSE 1  
                                                                END  
                                      AND cld.cname IN (SELECT TOP 1 csu.URLName  
                                                        FROM     
                                                               CampaignShortURL AS   
                                                               csu  
                                                        WHERE  csu.CampaignName =   
                                                               cm.CampaignName  
                                                               AND csu.Track_Unsubscribe =   
                                                                   0  
                                                        ORDER BY  
                                                               cld.DateCreated   
                                                               DESC)  
                           )  AS Response,  
                           (  
                               SELECT COUNT(*)  
                               FROM   ClientLeadDetails AS cld  
                               WHERE  cld.CampaignName = cm.CampaignName  
                                      AND cld.IsCallMicrosite = CASE   
                                                                     WHEN   
                                                                          ISNULL(@Type, '')  
                                                                          =  
                                                                          'C' THEN   
                                                                          0  
                                                                     ELSE 1  
                              END  
                                      AND cld.cname IN (SELECT TOP 1 csu.URLName  
                                                        FROM     
                                                               CampaignShortURL AS   
                                                               csu  
                                                        WHERE  csu.CampaignName =   
                                                               cm.CampaignName  
                                                               AND csu.Track_Unsubscribe =   
                                                                   1  
                                                        ORDER BY  
                                                               cld.DateCreated   
                                                               DESC)  
                           )  AS Unsubscribe,  
                           (  
                               SELECT COUNT(ad.EnqNo)  
                               FROM   [CRM].CRMDB.dbo.Appointment_details AS ad  
                               WHERE  ad.MeetingStatus = 'Enrolled'  
                                      AND (DATEDIFF(DAY, cm.ExecuteTime, GETDATE()) > 0)  
                           )  AS Enrolled  
                    FROM   CampaignMaster AS cm  
                           OUTER APPLY dbo.fn_Split(cm.Tags, ',') AS fs2  
                    WHERE  cm.IsExecuted = 1  
                           AND RTRIM(LTRIM(fs2.[value])) IN (SELECT fs.[value]  
                                                             FROM   dbo.fn_Split(ISNULL(@Tags, ''), '#') AS   
                                                                    fs)  
                )                         A  
         WHERE  CONVERT(DATETIME, A.ExecuteTime, 101) BETWEEN CASE   
                                                                   WHEN   
                                                                        ISNULL(@fromDate, '')   
                                                                        <  
                                                                        >  
                                                                        '' THEN   
                                                                        CONVERT(DATETIME, ISNULL(@fromDate, ''), 101)  
                                                                   ELSE A.ExecuteTime  
                                                              END AND CASE   
                                                                           WHEN   
                                                                                ISNULL(@ToDate, '')   
                                                                                <  
                                                                                >  
                                                                                '' THEN   
                                                                                CONVERT(DATETIME, ISNULL(@ToDate, ''), 101)  
                                                                           ELSE   
                                                                                A.ExecuteTime  
                                                                      END  
         GROUP BY  
                A.[TYPE]  
         ORDER BY  
                A.[TYPE] DESC  
     END  
 END  
END  



