SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.UspRequestDemoLeadList    
(    
  @Name nvarchar(200),            
  @Email nvarchar(200),          
  @CountryCode nvarchar(10),            
  @PhoneNo nvarchar(50),          
  @CompanyName nvarchar(200),            
  @Description nvarchar(500)    
 )    
 as    
 Begin    
     
  if(rtrim(ltrim(@CountryCode)) = '')
       Begin
	       set @CountryCode = '+91'
	   End
 
 if(@CountryCode <> '+91')    
 Begin   
 select @Description=@Description + ' Country code: '+@CountryCode  
 end  
 
      
  Declare @LeadDetails nvarchar(max) = ''     
  if(@Name <> '')    
     Begin    
        if(@LeadDetails = '')    
       Begin    
          set @LeadDetails = 'Name'    
    End    
           else     
       Begin    
         set @LeadDetails = @LeadDetails + '|Name'     
    End    
  End    
    
  if(@PhoneNo <> '')    
     Begin    
        if(@LeadDetails = '')    
       Begin    
          set @LeadDetails = 'Mobile'
		  set @LeadDetails = @LeadDetails + '|CountryCode'    
    End    
           else     
       Begin    
         set @LeadDetails = @LeadDetails + '|Mobile'
		 set @LeadDetails = @LeadDetails + '|CountryCode'         
    End    
  End    
    
   if(@Email <> '')    
      Begin    
         if(@LeadDetails = '')    
        Begin    
           set @LeadDetails = 'EmailID'    
    End    
           else     
       Begin    
         set @LeadDetails = @LeadDetails + '|EmailID'     
    End    
   End    
    
    
    if(@CompanyName <> '')    
      Begin    
         if(@LeadDetails = '')    
        Begin    
           set @LeadDetails = 'Company'    
    End    
           else     
       Begin    
         set @LeadDetails = @LeadDetails + '|Company'     
    End    
   End    
    
    
   if(@Description <> '')    
      Begin    
         if(@LeadDetails = '')    
        Begin    
           set @LeadDetails = 'Remarks'    
    End    
           else     
       Begin    
         set @LeadDetails = @LeadDetails + '|Remarks'     
    End    
   End    
    
  if(charindex('Mobile',@LeadDetails) <> 0)    
    Begin    
   --exec Usp_insertIntoLeadList 'RequestDemo',@LeadDetails,@Name,@PhoneNo,@Email,@CompanyName,'',@Description,335     
   exec [Usp_insertIntoLeadList_ProcessWithCountryCode] 'RequestDemo',@LeadDetails,@Name,@PhoneNo,@Email,@CompanyName,'',@Description,335,@CountryCode,0 
	    
   --@Source  nvarchar(200)              
 -- ,@LeadDetails nvarchar(max)              
 -- ,@Name nvarchar(200)              
 -- ,@Mobile nvarchar(50)              
 -- ,@EmailID nvarchar(500)              
 -- ,@Company nvarchar(500)              
 -- ,@Address nvarchar(max)              
 -- ,@Remarks nvarchar(max)              
 -- ,@ParentID bigint   
 -- ,@CountryCode nvarchar(10),  
 --  @leadsettingid int=null    
                
    
 -- End    
    
      End    
 End    
    


