/* ============================================================
   Procedure: [dbo].[UspSaveCriteriaToClientPage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.UspSaveCriteriaToClientPage (
	@CriteriaID BIGINT
	,@CNameOnly NVARCHAR(200)
	,@UserID BIGINT
	)
AS
BEGIN
	DECLARE @ParentID BIGINT = (
			SELECT isnull(ParentID, 0)
			FROM User_Detail(NOLOCK)
			WHERE User_ID = @UserID
			)

	UPDATE ClientPageDetail
	SET CriteriaID = @CriteriaID
	WHERE PageName = 'www.kit19.com/' + @CNameOnly
		AND User_ID = @ParentID

	SELECT 'Updated' AS MSG

	DECLARE @rowJson VARCHAR(MAX) = (
			SELECT *
			FROM ClientPageDetail WITH(NOLOCK)
			WHERE PageName = 'www.kit19.com/' + @CNameOnly
				AND User_ID = @ParentID
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	IF @rowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserID
			,@Activity_type = 'Updt_microsite'
			,@ActionType = 'U'
			,@RowJson = @rowJson
			,@Table_name = 'userleads'
	END
END



GO

