   Procedure: [dbo].[UspSaveEntityActivity_withid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[UspSaveEntityActivity_withid]  
(  
@entityname nvarchar(100),  
 @EntityID           BIGINT,  
 @UserID           BIGINT,  
 @ParentID         BIGINT,  
 @EventDescription NVARCHAR(MAX),  
 --@EventID bigint                      
 @EventName        NVARCHAR(500),  
 @reftables        NVARCHAR(500),  
 @refid            NVARCHAR(100)  
   
)  
AS  
BEGIN  
if @entityname='lead'  
begin  
exec uspsaveleadactivity_withid @entityID ,@UserID ,@ParentID ,@EventDescription ,@EventName,  
 @reftables ,@refid  
end  
else if @entityname='enquiry'  
begin  
exec uspsaveenquiryactivity_withid @entityID ,@UserID ,@ParentID ,@EventDescription ,@EventName,  
 @reftables ,@refid  
end  
if @entityname='Conversationcontact'  
begin  
exec uspsavecontactactivity_withid @entityID ,@UserID ,@ParentID ,@EventDescription ,@EventName,  
 @reftables ,@refid  
end  
if @entityname='user'  
begin  
exec UspSaveuserActivity_withid @entityID ,@UserID ,@ParentID ,@EventDescription ,@EventName,  
 @reftables ,@refid  
end  
  
END;  
  



