CREATE   PROCEDURE  UspSaveentityActivity_withMultipleValue_Spid
 @spid int
as
begin
	
	begin try																
		
		declare @imsLeadEvent as LeadActivitywithid_Tbltype

		insert into  @imsLeadEvent( LeadId, UserID, ParentID, [EventDescription], [EventName], [RefTable], [refid])
		select LeadId, UserID, ParentID, [EventDescription], [EventName], [RefTable], [refid]
		from tbl_LeadActivitywithidTbltype(nolock) sm where sm.Spid = @spid


		EXEC UspSaveentityActivity_withMultipleValue_withid_bulk @imsLeadEvent

		delete from tbl_LeadActivitywithidTbltype where Spid = @spid

	end try
	begin catch
		exec usp_InsertErrorInfo
	end catch
end


