/* ============================================================
   Procedure: [dbo].[UspSaveentityActivity_withMultipleValue_withid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[UspSaveentityActivity_withMultipleValue_withid]             
(             
 @tbl LeadActivitywithid_Tbltype READONLY             
)             
 as             
 Begin             
 begin try             
 SELECT RowID = ROW_NUMBER() OVER (             
 ORDER BY T.LeadID) ,             
 T.LeadID ,             
 T.UserID ,             
 T.ParentID,             
 T.EventDescription,             
 T.EventName,             
 T.reftable,             
 T.Refid             
 INTO #TempTbl             
 FROM @tbl T             
             
 declare @count int = 0             
 declare @RowNo int = 1             
 select @count = isnull(count(1),0) from #TempTbl             
 Declare @ParentID bigint = 0             
 Declare @UserID bigint = 0             
 Declare @EventName nvarchar(500) ,@activityid bigint             
 DECLARE @EventID BIGINT= 0,@refid nvarchar(100),@reftable nvarchar(100),@eventby nvarchar(20);             
             
    declare @leadHistoryid bigint = 0  
while(@RowNo <= @count )             
Begin             
print concat('Activity Records left to process: ',@rowno)             
select @EventName = isnull(EventName,''), @ParentID = isnull(ParentID,0) ,@UserID = isnull(UserID,0),@reftable=isnull(reftable,''),@refid=isnull(refid,'') from #TempTbl where RowID = @RowNo             
SELECT @EventID = ISNULL(ID , 0), @eventby=context FROM ActivityMaster(nolock) WHERE EventName = @EventName;             
IF(@ParentID = 0)             
BEGIN             
SELECT @ParentID = ParentID FROM User_Detail WHERE User_ID = @UserID;             
END             
             
if @eventby='lead'             
begin             
 INSERT INTO tbl_LeadEventHistory ( ParentID , UserID , LeadID , EventDescription , EventDate , EventID ,reftables,refids )             
  select @ParentID , @UserID , LeadID ,EventDescription , GETDATE() , @EventID,@reftable,@refid from #TempTbl where RowID = @RowNo   
  
 set @leadHistoryid = SCOPE_IDENTITY()  
 exec usp_st_SaleActivityMasterManage @leadHistoryid  
 set @leadHistoryid = 0  
  
end             
else if @eventby='enquiry'             
begin             
 INSERT INTO tbl_EnquiryEventHistory ( ParentID , UserID , EnquiryID , EventDescription , EventDate , EventID ,reftables,refids )             
 select @ParentID , @UserID , LeadID ,EventDescription , GETDATE() , @EventID,@reftable,@refid from #TempTbl where RowID = @RowNo             
end             
else if @eventby='ConversationContact'             
begin             
 INSERT INTO tbl_ContactEventHistory ( ParentID , UserID , ConversationContactID , EventDescription , EventDate , EventID ,reftables,refids )             
 select @ParentID , @UserID , LeadID ,EventDescription , GETDATE() , @EventID,@reftable,@refid from #TempTbl where RowID = @RowNo             
end             
else if @eventby='user'             
begin             
 INSERT INTO tbl_UserEventHistory ( ParentID , UserID , UserID , EventDescription , EventDate , EventID ,reftables,refids )             
 select @ParentID , @UserID , LeadID ,EventDescription , GETDATE() , @EventID,@reftable,@refid from #TempTbl where RowID = @RowNo             
end             
select @activityid=scope_identity()             
--exec usp_updatelastactivityinconvuser @eventby,@activityid             
--if @eventby='lead'             
--begin             
----EXEC usp_insertleadscore @activityid;             
----Exec usp_es_SaveLoyaltyTransaction @activityid             
--end             
             
             
/*             
DECLARE @nid TABLE             
 (             
 [modeid] INT,             
 [notificationid] BIGINT,             
 [roleid] INT,             
 [activityid] INT             
 );             
             
 drop table if exists #mgr             
