 SELECT [modeid], [id], [roleid], [activityid]             
 FROM notificationsmaster(NOLOCK)             
 WHERE [activityid] = @EventID;             
             
 INSERT INTO notificationhistory([notificationid], [reftable], [refid], [content],n_userid)             
 SELECT [notificationid], case             
 when @eventby='user' then 'tbl_UserEventHistory'             
 when @eventby='ConversationContact' then 'tbl_ContactEventHistory'             
 when @eventby='enquiry' then 'tbl_enquiryEventHistory'             
 when @eventby='lead' then 'tbl_leadEventHistory' end             
 , @activityid, [t].[EventDescription],          
 case             
 when roleid=6 then @UserID             
