/* ============================================================
   Procedure: [dbo].[UspSaveentityActivity_withMultipleValue_withid_bulk]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[UspSaveentityActivity_withMultipleValue_withid_bulk]                     
(                     
 @tbl LeadActivitywithid_Tbltype READONLY                     
)                     
as                     
Begin       
  print concat(getdate(),': Activity Proc Start' )    
begin try              
 declare @count int = 0                     
 declare @RowNo int = 1                     
 select @count = isnull(count(1),0) from @tbl                     
 Declare @ParentID bigint = 0                     
 Declare @UserID bigint = 0                     
 Declare @EventName nvarchar(500) ,@activityid bigint                     
 DECLARE @EventID BIGINT= 0,@refid nvarchar(100),@reftable nvarchar(100),@eventby nvarchar(20);                     
          
 select top 1 @eventby=context FROM ActivityMaster(nolock) WHERE EventName = (select top 1 eventname from @tbl)          
drop table if exists #activityids          
drop table if exists #IsconvertedData        
create table #multi_activityids(activityid bigint)          
   --select top 1 @parentid=   dbo.ufn_getuserparentid(userid) from @tbl    
if @eventby='lead'                     
begin                     
 INSERT INTO tbl_LeadEventHistory ( ParentID , UserID , LeadID , EventDescription , EventDate , EventID ,reftables,refids )            
 output inserted.historyid as activityid into #multi_activityids          
 select dbo.ufn_getuserparentid(userid), UserID , LeadID ,EventDescription , GETDATE() , a.ID,reftable,refid from @tbl t join activitymaster(nolock)          
 a on a.eventname=t.EventName  where t.leadid is not null        
        
        
  select dbo.ufn_getuserparentid(userid) ParentID, UserID , LeadID ,EventDescription , GETDATE() EventDate, reftable, refid Into #IsconvertedData        
 from @tbl t          
 join LeadInteractionHistory (nolock) lih on Cast(lih.ID as varchar) =t.refid        
 join FollowUp_Status (nolock) fup on fup.ID=lih.FollowUpStatus         
 where lih.ParentID=@parentid and  fup.IsConvert=1        
        
 if Exists(Select 1 from #IsconvertedData)        
 BEGIN        
 print '#IsconvertedData Start'      
  Declare @scoresetting int = (select ScoreSettingType from lead_cateogy_thresholds (nolock) where parentid = @parentid)        
  Declare @ScoreAdded int         
  if @scoresetting=2        
  BEGIN        
           
   Select ParentID , UserID , LeadID , EventDescription , EventDate  ,reftable,refid         
    from #IsconvertedData        
        
   select cnvt.ParentID,cnvt.LeadID,0,lsh.ScoreAdded,0,GETDATE(), CurrentScore, act.activityid, 17 from lead_score_history lsh         
    join #IsconvertedData cnvt on cnvt.LeadID=lsh.leadid        
    outer apply  #multi_activityids act        
   update  ul set IsScoreeligible=0          
   from UserLeads ul         
   join #IsconvertedData cnvt on cnvt.LeadID=ul.id        
        
  END        
  if @scoresetting=3        
  BEGIN        
   Select ParentID , UserID , LeadID , EventDescription , EventDate  ,reftable,refid         
    from #IsconvertedData        
        
   select cnvt.ParentID,cnvt.LeadID,0,lsh.ScoreAdded,0,GETDATE(), CurrentScore, act.activityid, 17 from lead_score_history lsh         
    join #IsconvertedData cnvt on cnvt.LeadID=lsh.leadid        
    outer apply  #multi_activityids act        
   update  ul set IsScoreeligible=1         
   from UserLeads ul         
   join #IsconvertedData cnvt on cnvt.LeadID=ul.id        
        
  END        
  if @scoresetting=1        
  BEGIN        
  update  ul set IsScoreeligible=1         
   from UserLeads ul         
   join #IsconvertedData cnvt on cnvt.LeadID=ul.id        
           
  END        
  print '#IsconvertedData end'      
 END        
        
          
end                     
else if @eventby='enquiry'                     
begin                     
 INSERT INTO tbl_EnquiryEventHistory ( ParentID , UserID , EnquiryID , EventDescription , EventDate , EventID ,reftables,refids )                     
 output inserted.historyid as activityid into #multi_activityids         
 select dbo.ufn_getuserparentid(userid), UserID , LeadID ,EventDescription , GETDATE() , a.ID,reftable,refid from @tbl t join activitymaster(nolock)          
 a on a.eventname=t.EventName          
end                     
else if @eventby='ConversationContact'                     
begin                     
 INSERT INTO tbl_ContactEventHistory ( ParentID , UserID , ConversationContactID , EventDescription , EventDate , EventID ,reftables,refids )                     
 output inserted.historyid as activityid into #multi_activityids          
 select dbo.ufn_getuserparentid(userid), UserID , LeadID ,EventDescription , GETDATE() , a.ID,reftable,refid from @tbl t join activitymaster(nolock)          
 a on a.eventname=t.EventName          
end                     
else if @eventby='user'                     
begin                     
 INSERT INTO tbl_UserEventHistory ( ParentID ,UserID , EventDescription , EventDate , EventID ,reftables,refids )                     
 output inserted.historyid as activityid into #multi_activityids          
 select dbo.ufn_getuserparentid(userid), UserID ,EventDescription , GETDATE() , a.ID,reftable,refid from @tbl t join activitymaster(nolock)          
 a on a.eventname=t.EventName          
end                     
          
declare @multiactivity as multiactivity          
          
insert into @multiactivity(context,activityid)          
select @eventby,activityid from #multi_activityids    
  
begin try  
 print concat(getdate(),': Starting usp_ManageSaleActivityQueue')      
 declare @SaleActivityQueueType as SaleActivityQueueType  
 insert into @SaleActivityQueueType(EntityName, EntityId, ActivityId, IsProcessed, ErrorDescription)  
 select @eventby, 0, activityid, 0, null from #multi_activityids     
 exec usp_ManageSaleActivityQueue @Mode = 'BulkInsert', @BulkData = @SaleActivityQueueType, @ProcessStatus = 0  
 print concat(getdate(),': Ended usp_ManageSaleActivityQueue')  
   
   
end try  
begin catch  
  exec usp_inserterrorinfo   
end catch  
  
begin try          
print concat(getdate(),': Start usp_insertnotification_multi')      
exec usp_insertnotification_multi @multiactivity     
  
print concat(getdate(),': Start usp_insert_in_entityactivityqueue_multi')      
exec usp_insert_in_entityactivityqueue_multi  @multiactivity  
  
if @eventby in ('enquiry','lead')                     
begin    
--if dbo.fn_has_active_whatsapp(@parentid)=1    
--begin    
--print concat(getdate(),': Start usp_updatelastactivityinconvuser_multi')      
--exec dbo.usp_updatelastactivityinconvuser_multi @multiactivity      
--end    
print concat(getdate(),': Start usp_automationrulesapply_activity_insert_multi' )     
exec [dbo].[usp_automationrulesapply_activity_insert_multi] @multiactivity          
print concat(getdate(),': Start usp_executeeventcampaign1_multi')      
exec usp_executeeventcampaign1_multi @multiactivity     
print concat(getdate(),': Start usp_insertcalculatedfields_bulk')      
exec usp_insertcalculatedfields_bulk @multiactivity  
  
end                     
          
end try                     
 begin catch                     
 exec usp_inserterrorinfo                     
 end catch                 
                     
                     
                      
 end try                     
 begin catch                     
 exec usp_inserterrorinfo                     
 end catch                     
 print concat(getdate(),': Activity Proc End'  )    
 End   


GO

/* ============================================================
   Procedure: [dbo].[UspSaveHiringInfo]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[UspSaveHiringInfo]        
(        
       @Name nvarchar(500)        
      ,@EmailID nvarchar(500)        
      ,@CountryCode nvarchar(20)        
      ,@Mobile nvarchar(50)        
      ,@Department nvarchar(500)        
      ,@AdditionalInfo nvarchar(max)        
      ,@ResumeHeader nvarchar(500)        
      ,@ResumePath nvarchar(max)        
)        
As        
Begin    
declare @hid bigint        
     insert into tbl_HiringInfo        
   ([Name]        
      ,[EmailID]        
      ,[CountryCode]        
      ,[Mobile]        
      ,[Department]        
      ,[AdditionalInfo]        
      ,[ResumeHeader]        
      ,[ResumePath]        
      ,[CreatedOn]        
   )         
   values(        
    @Name,        
    @EmailID,        
    @CountryCode,        
    @Mobile        
      ,@Department        
      ,@AdditionalInfo        
      ,@ResumeHeader        
      ,@ResumePath        
      ,getdate()        
   )        
select @hid=SCOPE_IDENTITY()    
select 'Data Saved Successfully'        
    
DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX),@deptt nvarchar(100)                  
select  isnull(Name,'') [Name],isnull(emailid,'') [EmailID],cast(ltrim(rtrim(isnull([CountryCode],''))) as nvarchar)+cast([Mobile]    
as nvarchar) Mobile,isnull([Department],'') [Department],isnull([AdditionalInfo],'') [AdditionalInfo],    
isnull([ResumeHeader],'') [ResumeHeader],isnull([ResumePath],'') ResumePath    
into #temp        
from tbl_HiringInfo(nolock) where id=@hid    
    
select @deptt=department from #temp    
    
SET @xml =CAST(( SELECT Name AS 'td','',EmailID AS 'td','',Mobile AS 'td','',Department AS 'td','',               
AdditionalInfo  AS 'td','',ResumeHeader AS 'td','',ResumePath from #temp FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))              
    
SET @body ='<html><H1>Candidate details received: '    
+'</H1><body><table border = 2><tr><th>Name</th><th>EmailID</th><th>Mobile</th><th>Department</th><th>AdditionalInfo</th>        
<th>ResumeHeader</th><th>ResumePath</th></tr>'               
    
SET @body = @body + @xml +'</table></body></html>'              
    
declare @subject nvarchar(200)='New Resume received via Kit19 at '+cast(getdate() as nvarchar)+ ' for '+ isnull(nullif(@deptt,''),'Unknown') +' department'    
    
EXEC usp_enqueueemail              
@profile_name='Alerts',               
@recipients='csshukla@pelsoftlabs.in;hr@pelsoftlabs.in',              
@blind_copy_recipients='karuna@pelsoftlabs.in',              
@subject=@subject,              
@body = @body,              
@body_format ='HTML'              
drop table #temp              
    
    
End



GO

