/* ============================================================
   Procedure: [dbo].[UspSaveLeadActivity_withid_logging]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[UspSaveLeadActivity_withid_logging]                          
(                          
 @LeadID           BIGINT,                          
 @UserID           BIGINT,                          
 @ParentID         BIGINT,                          
 @EventDescription NVARCHAR(MAX),                          
 --@EventID bigint                                              
 @EventName        NVARCHAR(500),                          
 @reftables        NVARCHAR(500),                          
 @refid            NVARCHAR(100)                          
)                          
AS                          
BEGIN                      
begin try                        
 DECLARE @EventID BIGINT= 0, @activityid BIGINT,@eei bigint;  
 declare @leadscore bit=0,@eshopl bit=0,@automation bit=0,@notifi bit=0,@lastact bit=0,@event bit=0  
                          
 SELECT @EventID = ISNULL([ID], 0) FROM   ActivityMaster(NOLOCK) WHERE  [EventName] = @EventName;                          
                          
 IF(ISNULL(@ParentID, 0) = 0)                          
 BEGIN       
   
  SELECT @ParentID = [ParentID] FROM   User_Detail(NOLOCK) WHERE  User_ID = @UserID;                          
 END;                          
                          
 IF (@eventid <> 17 OR (@eventid = 17 AND NOT EXISTS(SELECT 1 FROM tbl_LeadEventHistory(NOLOCK) WHERE  [leadid] = @LeadID AND [eventid] = 17) ) )                          
 BEGIN                          
  INSERT INTO tbl_LeadEventHistory                          
    ([ParentID], [UserID], [LeadID], [EventDescription], [EventDate], [EventID], [reftables], [refids])                          
  VALUES (@ParentID, @UserID, @LeadID, @EventDescription, GETDATE(), @EventID, @reftables, @refid);                          
                          
  SELECT @activityid = SCOPE_IDENTITY();
  
  -- Inserting Lead Interaction Data Into SalesActivity for Pipeline
  exec usp_st_SaleActivityMasterManage @activityid
    
  insert into eventsexecuted(activityid)  
  select @activityid  
  select @eei=SCOPE_IDENTITY();  
  
  begin try  
  EXEC usp_insertleadscore @activityid;                          
  select @leadscore=1  
  end try  
  begin catch  
  exec usp_inserterrorinfo  
  end catch  
  
begin try                          
  Exec usp_es_SaveLoyaltyTransaction @activityid                          
select @eshopl=1  
  end try  
  begin catch  
  exec usp_inserterrorinfo  
  end catch  
                
begin try       
  exec usp_insertnotification @activityid,'lead'         
  select @notifi=1  
  end try  
  begin catch  
  exec usp_inserterrorinfo  
  end catch  
  
begin try      
  exec usp_automationrulesapply_activity_insert @activityid,'lead'    
  select @automation=1  
  end try  
  begin catch  
  exec usp_inserterrorinfo  
  end catch  
  
--  if dbo.fn_has_active_whatsapp(@parentid)=1
--begin
--  begin try                  
--  exec usp_updatelastactivityinconvuser 'lead',@activityid                    
--  select @lastact=1  
--  end try  
--  begin catch  
--  exec usp_inserterrorinfo  
--  end catch  
--  end
begin try                     
exec usp_executeeventcampaign1 'lead',@activityid    
select @event=1  
  end try  
  begin catch  
  exec usp_inserterrorinfo  
  end catch  
  
 exec usp_insertcalculatedfields 'lead',@activityid,@parentid

update eventsexecuted set   
is_leadscore=@leadscore,  
is_automation=@automation,  
is_eshopl=@eshopl,  
is_event=@event,  
is_notifi=@notifi,  
is_lastact=@lastact,  
isprocessed=1 where id=@eei                  
                      
 END;                    
 end try                    
 begin catch                    
 exec usp_InsertErrorInfo                    
 end catch                    
                           
                          
END                  



