/* ============================================================
   Procedure: [dbo].[UspSaveLeadActivity_withMultipleValue]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[UspSaveLeadActivity_withMultipleValue]    
 (    
   @tbl  LeadActivity_Tbltype READONLY    
 )    
 as    
 Begin    
 begin try   
   SELECT  RowID = ROW_NUMBER() OVER (    
                   ORDER BY T.LeadID) ,    
      T.LeadID ,    
      T.UserID ,    
      T.ParentID,    
      T.EventDescription,    
      T.EventName    
   INTO #TempTbl    
   FROM @tbl T    
    
   declare @count int  = 0    
   declare @RowNo int = 1     
   select @count =  isnull(count(1),0) from  #TempTbl    
   Declare @ParentID bigint = 0    
   Declare @UserID bigint = 0    
   Declare @EventName nvarchar(500) ,@activityid bigint    
   DECLARE @EventID BIGINT= 0;     
    
   while(@RowNo <= @count )    
    Begin    
    
 select @EventName = isnull(EventName,''), @ParentID = isnull(ParentID,0) ,@UserID = isnull(UserID,0)  from #TempTbl where RowID = @RowNo    
     
      
    SELECT @EventID = ISNULL(ID , 0)  FROM ActivityMaster(nolock)  WHERE EventName = @EventName;      
      
   IF(@ParentID = 0)      
    BEGIN      
     SELECT @ParentID = ParentID FROM User_Detail  WHERE User_ID = @UserID;      
   END      
      
    INSERT INTO tbl_LeadEventHistory ( ParentID , UserID , LeadID , EventDescription , EventDate , EventID                                         )       
   select @ParentID , @UserID , LeadID ,EventDescription , GETDATE() , @EventID  from #TempTbl where RowID = @RowNo    
    select @activityid=scope_identity()  
  --VALUES ( @ParentID , @UserID , @LeadID , @EventDescription , GETDATE() , @EventID );     
  EXEC usp_insertleadscore @activityid;        
  Exec usp_es_SaveLoyaltyTransaction @activityid        
  exec usp_insertnotification @activityid,'lead'  


--  if dbo.fn_has_active_whatsapp(@parentid)=1
--begin
--  exec usp_updatelastactivityinconvuser 'lead',@activityid  
--  end

    exec usp_insert_in_entityactivityqueue @activityid,'lead'

  exec usp_executeeventcampaign 'lead',@activityid 
  exec usp_insertenagagementactivity @activityid,'lead'   
  exec usp_insertcalculatedfields 'lead',@activityid,@parentid


  -- Inserting Lead Interaction Data Into SalesActivity for Pipeline
  exec usp_st_SaleActivityMasterManage @activityid
		

  set @RowNo = @RowNo + 1     
    
 End    
    
   drop table #TempTbl     
  end try  
 begin catch  
 exec usp_InsertErrorInfo  
 end catch        
 End



GO

