BEGIN

 --Declare @PartnerID        BIGINT = 335,
	-- @UserID           BIGINT = 34954,   
	-- @SecondarypartnerID BIGINT  = 32222 ,
 --@EventDescription NVARCHAR(MAX) = 'testsdf created a new white-labeled partner named sms19 ',                                                                               
 --@EventName        NVARCHAR(500) = 'Partner Created White-Labeled Partner',                              
 --@reftables        NVARCHAR(500) = 'tetstable',                              
 --@refid            NVARCHAR(100)  = '99' 


	BEGIN TRY

		 DECLARE @EventID BIGINT= 0, @activityid BIGINT , @Eventype nvarchar(100);                            
		 SELECT @EventID = ISNULL([ID], 0) , @Eventype = EventType FROM   ActivityMaster(NOLOCK) WHERE  [EventName] like '%'+ rtrim( @EventName) +'%';      
		 print  @EventID;

		 IF ( 1 =1)                              
		 BEGIN    

			---select dbo.ufn_getuserparentid(@Userid), @UserID, @PartnerID, @EventDescription, GETDATE(), @EventID, @reftables, @refid
			PRINT 'Activity record insert started.'

			PRINT CONCAT(@PartnerID,  dbo.ufn_getuserparentid(@PartnerID), @UserID,  dbo.ufn_getuserparentid(@ChildPartnerID), @EventDescription, GETDATE(), @EventID, @reftables, @refid);

			  INSERT INTO tbl_PartnerEventHistory                              
