/* ============================================================
   Procedure: [dbo].[UspSaveuserActivity_withid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[UspSaveuserActivity_withid]                
(                
 @EntityID           BIGINT,                
 @UserID           BIGINT,                
 @ParentID         BIGINT,                
 @EventDescription NVARCHAR(MAX),                
 --@EventID bigint                                    
 @EventName        NVARCHAR(500),                
 @reftables        NVARCHAR(500),                
 @refid            NVARCHAR(100)                
)                
AS                
BEGIN                
 DECLARE @EventID BIGINT= 0, @activityid BIGINT;                
                
 SELECT @EventID = ISNULL([ID], 0) FROM   ActivityMaster(NOLOCK) WHERE  [EventName] = @EventName;                
                
 IF(ISNULL(@ParentID, 0) = 0)                
 BEGIN                
  SELECT @ParentID = [ParentID] FROM   User_Detail(NOLOCK) WHERE  User_ID = @UserID;                
 END;                
    
  print concat('print started:','') 

   INSERT INTO tbl_userEventHistory                
    ([ParentID], [UserID], [EventDescription], [EventDate], [EventID], [reftables], [refids])                
  VALUES (@ParentID, @UserID, @EventDescription, GETDATE(), @EventID, @reftables, @refid);                
                
  SELECT @activityid = SCOPE_IDENTITY();        
    
     print concat( 'Event id ', cast( @EventID as nvarchar),
	              ' activityId ', cast( @activityid as nvarchar),
				  ' Event Name ', cast( @EventName as nvarchar)
	             )

  ---mod 29.06.2024 by satya sharma  
   declare @cur_date datetime =  getdate();  
  
  EXEC usp_sm_InsertscoringRecord @EventName , @cur_date , @UserID , 'tbl_userEventHistory' , @activityid ;  
  
  
                  
  DECLARE @nid TABLE                
  (                
   [modeid]         INT,                
   [notificationid] BIGINT,                
   [roleid]         INT,                
   [activityid]     INT                
  );             
          
  create table #mgr(mgrid bigint)        
  if @EventID in (select id from activitymaster where EventType='TimeTracking')        
  begin        
  insert into #mgr(mgrid)        
  select manageruser_id from mysmstimetrack.[dbo].[timetracking_roleusermapping] where user_id=@userid        
  end           
                  
  INSERT INTO @nid([modeid], [notificationid], [roleid], [activityid])                
      SELECT [modeid], [id], [roleid], [activityid]                
      FROM   notificationsmaster(NOLOCK)                
      WHERE  [activityid] = @EventID;                
                
  INSERT INTO notificationhistory([notificationid], [reftable], [refid], [content],n_userid)                
  SELECT [notificationid], 'tbl_UserEventHistory', @activityid, [t].[EventDescription],            
   case         
   when roleid=6 then @UserID         
   when roleid=3 then @ParentID         
   when roleid=5 then mgrid end                 
  FROM   tbl_UserEventHistory(NOLOCK) AS t JOIN @nid AS n                
      ON n.activityid = t.EventID AND n.modeid = 1 AND t.HistoryID = @activityid        
   left join #mgr on 1=1 and n.roleid=5;                
          
END;         
        
        


GO

