 WHERE [activityid] = @EventID; 
 
 INSERT INTO notificationhistory([notificationid], [reftable], [refid], [content],n_userid) 
 SELECT [notificationid], 'tbl_UserEventHistory', @activityid, [t].[EventDescription], 
 case 
 when roleid=6 then @UserID 
 when roleid=3 then @ParentID 
 when roleid=5 then mgrid end 
 FROM tbl_UserEventHistory(NOLOCK) AS t JOIN @nid AS n 
 ON n.activityid = t.EventID AND n.modeid = 1 AND t.HistoryID = @activityid 
 left join #mgr on 1=1 and n.roleid=5; 
*/ 
set @RowNo = @RowNo + 1 
