/* ============================================================
   Procedure: [dbo].[UspSearchEnquiryLead]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE UspSearchEnquiryLead
(
@SearchParameter VARCHAR(1000) ,
@SearchType varchar(1) --[E]nquiry,[L]ead
)

AS
BEGIN
	If(@SearchType = 'E')
	Begin
		Select * from UserEnquiry Where PersonName like'%'+ @SearchParameter+'%' or CompanyName like'%'+ @SearchParameter+'%' 
										or EmailID like '%'+@SearchParameter+'%' or EmailID1 like '%'+@SearchParameter+'%' or EmailID2 like '%'+@SearchParameter+'%' 
										or MobileNo like '%'+@SearchParameter+'%' or MobileNo1 like '%'+@SearchParameter+'%' or  MobileNo2 like '%'+@SearchParameter+'%'
										
	End
	Else --Lead
	Begin
	Select * from UserLeads Where PersonName like'%'+ @SearchParameter+'%' or CompanyName like'%'+ @SearchParameter+'%' 
										or EmailID like '%'+@SearchParameter+'%' or EmailID1 like '%'+@SearchParameter+'%' or EmailID2 like '%'+@SearchParameter+'%' 
										or MobileNo like '%'+@SearchParameter+'%' or MobileNo1 like '%'+@SearchParameter+'%' or  MobileNo2 like '%'+@SearchParameter+'%'
			
	End

END


GO

