CREATE   PROCEDURE [dbo].[uspSelectCountryCode]    
AS    
BEGIN    
 SELECT Country_Name,    
        '+' + CountryCode AS CountryCode,    
        Country_ID    
 FROM   M_Country    
 ORDER BY    
        Country_Name    
END 


