/* ============================================================
   Procedure: [dbo].[uspSelectCountryCodeWithMobile]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[uspSelectCountryCodeWithMobile]  
AS  
BEGIN  

SELECT  RTRIM(LTRIM(CountryCode)) AS CountryCode,  
        Country_Name + ': ' + CountryCode AS Country_NameTXT  
 FROM   m_country1  
 WHERE  Country_Name = 'India'   
   
 UNION ALL     
   
 SELECT  RTRIM(LTRIM(CountryCode)) AS CountryCode,  
        Country_Name + ': ' + CountryCode AS Country_NameTXT  
