 --FROM   M_Country  
 --WHERE  Country_Name = 'India'   
   
 --UNION ALL     
   
 --SELECT '+' + RTRIM(LTRIM(CountryCode)) AS CountryCode,  
 --       Country_Name + ': +' + CountryCode AS Country_NameTXT  
 --FROM   M_Country  
 --WHERE  Country_Name <> 'India' --order by Country_Name  
END  


