/* ============================================================
   Procedure: [dbo].[UspSMSConsumptionSignalR]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.UspSMSConsumptionSignalR  --16453,10043,200      
(       
 @UserID bigint,      
 @Mid bigint,      
 @Balance bigint,    
 @tblName nvarchar(200),    
 @RefID nvarchar(50)       
)      
as      
Begin      
      
    Declare @BalanceTemp numeric(18,2) = 0;      
 Declare @AVGConsumption numeric(18,2) = 0;      
      
 set @BalanceTemp = cast(@Balance as numeric(18,2))       
      
 select @AVGConsumption = dbo.FuncSMSConsumption(@UserID)      
      
 if(@BalanceTemp < @AVGConsumption and not exists (select 1 from userevent(nolock) where userid=@UserID and event='Low Balance SMS' 
 and datediff(hh,createdon,getdate())<3)
 )      
   Begin      
             
  insert into UserEvent      
   (      
    [Event]      
         ,UserID      
         ,CRMEntry      
         ,[Description]      
         ,CreatedOn    
   ,RefTable    
   ,RefID      
   )      
   select   
     'Low Balance SMS'      
     ,User_ID      
     ,0      
     ,'User '+ user_login +'has low SMS Balance. His current balance is: '+ cast(@Balance as nvarchar) + ' while his last 7 days average consumption is: '+ CAST(@AVGConsumption as nvarchar)      
     ,getdate()    
  ,@tblName    
  ,@RefID      
   from user_detail where user_id=@userid  
         
         
   End      
        
      
End


GO

/* ============================================================
   Procedure: [dbo].[UspToCheckValidity]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.UspToCheckValidity --2335
(
  @UserID bigint
)
as
Begin

  if(exists(select 1 from  Price_UserSubscriptionDetails where UserID = @UserID))
   Begin
	  if(exists(
	   select 'x' from Price_UserSubscriptionDetails where USERID = @UserID and PlanEndDate >= convert(date,getdate()) and
	   id in (select MAX(id) from Price_UserSubscriptionDetails where UserID = @UserID)
	   ))
	   begin
			select 'Valid' as status
	   End
	   else
	   Begin
			select 'Expired' as status
	   End 

	end
   else
    Begin
	    select 'Valid' as status
	End

end



GO

/* ============================================================
   Procedure: [dbo].[UspToCheckValidityofSubscription]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.UspToCheckValidityofSubscription --335        
(        
  @UserID bigint        
)        
as        
Begin        
        
 Declare @ParentID bigint = 0    
 select  @ParentID = isnull(ParentID,0) from User_Detail(nolock) where User_ID = @UserID    
    
    
    
  if(exists(select 1 from  Price_UserSubscriptionDetails(nolock) where UserID = @ParentID))        
   Begin        
   if(exists(        
    select 'x' from Price_UserSubscriptionDetails(nolock) where USERID = @ParentID and PlanEndDate >= convert(date,getdate()) and isnewplan=1       
 --and  id in (select MAX(id) from Price_UserSubscriptionDetails where UserID = @ParentID)        
    ))        
    begin        
   select 'Valid' as status        
    End        
    else        
    Begin        
   select 'Expired' as status        
    End         
        
 end        
   else        
    Begin        
     select 'Expired' as status        
 End        
        
end 


GO

/* ============================================================
   Procedure: [dbo].[UspToGetBatchID_ToTransferData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.UspToGetBatchID_ToTransferData
as
begin
       
	 IF OBJECT_ID('tempdb..#Temp_BatchEmailInfo_Part1', 'U') IS NOT NULL
	    DROP TABLE #Temp_BatchEmailInfo_Part1;
		
	   select top 1 
	   --*
	   ID
,BatchID
,UserID
,SenderName
--,Message
,TotalRecords
,TotalProcessed
,ProcessTable
,IsProcess
,Priority_Level
,BatchInsertTime
,BatchProcessTime
,ScheduledDate
,ScheduledTime
,TemplateID
,Route
,PageName
,IsScheduled
,Email_Subject
,ReplyTo
,Amount
,Currency
,Tablename
,ScheduledMailProcessed
,isrunning
,ispersonalized
,MailSize
,CreditsUsed
,CreatedBy
,mail_source
,isstopped
,filterpriority
,mailroute
,finalmailroute
,bmonitor
,isbatchdeleted
	   
	   into #Temp_BatchEmailInfo_Part1 from [Mysms].[DBO].BatchEmail_Infos with(nolock)
	       where
	         isnull(IsProcess,0) = 0 and isnull(isrunning,0) = 0     
             and cast(batchInsertTime as date) >= CAST(getdate() -1 as date)    
             and isnull(isscheduled,0) = 0
			 and  isnull(ScheduledDate,dateadd(dd,-1,getdate()))<=GETDATE()
			 -- and OBJECT_ID(isnull(nullif(TableName,''),'CloneEmailsFilter')) is not null    
              and batchID  = 136847610 --131988507 --131967581          
             order by id asc 

       declare @BatchID bigint = 0;
	   select @BatchID = BatchID from #Temp_BatchEmailInfo_Part1

	  Declare @SyncMode int = 0 
	  select @SyncMode = isnull(SyncIntMode,0) from SyncHandle with(nolock) 

	   select
	    --*
  ID
,BatchID
,UserID
,SenderName
--,Message
,TotalRecords
,TotalProcessed
,ProcessTable
,IsProcess
,Priority_Level
,BatchInsertTime
,BatchProcessTime
,ScheduledDate
,ScheduledTime
,TemplateID
,Route
,PageName
,IsScheduled
,Email_Subject
,ReplyTo
,Amount
,Currency
,Tablename
,ScheduledMailProcessed
,isrunning
,ispersonalized
,MailSize
,CreditsUsed
,CreatedBy
,mail_source
,isstopped
,filterpriority
,mailroute
,finalmailroute
,bmonitor
,isbatchdeleted
	 , @SyncMode as SyncMode from #Temp_BatchEmailInfo_Part1

	   update BatchEmail_Infos set isrunning = 1 where BatchID = @BatchID  
		
      IF OBJECT_ID('tempdb..#Temp_BatchEmailInfo_Part1', 'U') IS NOT NULL
	    DROP TABLE #Temp_BatchEmailInfo_Part1;
	  
         
end


