/* ============================================================
   Procedure: [dbo].[UspUpdatePage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.UspUpdatePage      
(      
  @PageName nvarchar(500),      
  @PageTitle nvarchar(500),      
  @Path nvarchar(max),  
  @PageID int      
)      
as      
Begin      
       
  if(not exists (select 1 from Page where PageName = @PageName and PageTitle = @PageTitle and @Path = @Path and ID <> @PageID ))    
   Begin  
     update Page set PageTitle = @PageTitle,PageName=@PageName,Path = @Path where ID = @PageID  
    select 'Record Updated'    
    end    
 else     
 Begin    
         select 'Page Already Exists'            
 End    
    
end


GO

