   Procedure: [dbo].[UspUpdateUserEnquiryDetails1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[UspUpdateUserEnquiryDetails1]                         
(                        
    @EnquiryID BIGINT,                        
    @PersonName NVARCHAR(200),                        
    @CompanyName NVARCHAR(500),                        
    @MobileNo NVARCHAR(100),                        
    @MobileNo1 NVARCHAR(100),                        
    @MobileNo2 NVARCHAR(100),                        
    @EmailID NVARCHAR(100),                        
    @EmailID1 NVARCHAR(100),                        
    @EmailID2 NVARCHAR(100),                        
    @City NVARCHAR(50),                        
    @State NVARCHAR(50),                        
    @Country NVARCHAR(50),                        
    @CountryCode NVARCHAR(50),                        
    @CountryCode1 NVARCHAR(50),                        
    @CountryCode2 NVARCHAR(50),                        
    @ResidentialAddress NVARCHAR(500),                        
    @OfficeAddress NVARCHAR(500),                        
    @PinCode BIGINT,                        
    --@AssignedTo Bigint,                                  
    @SourceName BIGINT,                        
    @MediumName BIGINT,                        
    @CampaignName BIGINT,                        
    @InitialRemarks NVARCHAR(1000),                        
    @ParentID BIGINT,            
 @WhereAddress       NVARCHAR(255) = '',            
 @WhereLatitude      NVARCHAR(255) = '',            
 @WhereLongitude     NVARCHAR(255) = '',            
 @EnquiryTags        NVARCHAR(max) = null,            
    @custom customEnquiry2 readonly                        
)                                    
AS                                     
BEGIN                 
          
          
 declare @latitude float = null;          
 if(ISNULL(@WhereLatitude, '') <> '')          
 begin          
  set @latitude = cast(@WhereLatitude as float)          
 end          
 declare @longitude float = null;          
 if(ISNULL(@WhereLatitude, '') <> '')          
 begin          
  set @longitude = cast(@WhereLongitude as float)           
 end          
          
          
 UPDATE UserEnquiry                        
 SET    PersonName = @PersonName,                        
        CompanyName = @CompanyName,                        
        MobileNo = @MobileNo,                        
        MobileNo1 = @MobileNo1,                        
        MobileNo2 = @MobileNo2,                        
        EmailID = @EmailID,                        
        EmailID1 = @EmailID1,                        
        EmailID2 = @EmailID2,                        
        City = @City,                        
        STATE = @State,                        
        Country = @Country,                        
        CountryCode = @CountryCode,                        
        CountryCode1 = @CountryCode1,                        
        CountryCode2 = @CountryCode2,                        
        ResidentialAddress = @ResidentialAddress,                        
        OfficeAddress = @OfficeAddress,                        
        PinCode = @PinCode,                        
        SourceName = @SourceName,                        
        MediumName = @MediumName,                        
        CampaignName = @CampaignName,                        
        InitialRemarks = @InitialRemarks,             
        ParentID = @ParentID,            
  whereAddress = @WhereAddress,             
  latitude = @latitude,             
  longitude = @longitude            
 WHERE  EnquiryID = @EnquiryID                      
                    
 if(ISNULL(@EnquiryTags, '') <> '')            
 begin            
             
  drop table if exists #tempTagName            
  select tn.*, tm.ID as tagId, 0 as isProcess  into #tempTagName from ( select [position] as [id],  LTRIM(RTRIM(            
   iif(            
    CHARINDEX(':', [value],  1 ) = 0 ,             
    [value],             
    SUBSTRING([value], 1, CHARINDEX(':', [value],  1 ) - 1)            
   ))) as [tagName]             
 from fn_Split(@EnquiryTags, ',') ) as tn             
  left join TagMaster(nolock) tm on tm.ParentID = @ParentID and lower(tm.Tag) = lower(tagName)            
            
  while(exists(select * from #tempTagName where isProcess = 0))            
  begin            
   declare @tId int, @tTagName nvarchar(255), @tagId bigint            
   select top 1 @tId = id, @tTagName = tagName, @tagId = tagId from #tempTagName where isProcess = 0            
            
   print @tTagName            
            
   if(@tagId is null)            
   begin            
    insert into TagMaster(Tag, ParentID, CreatedDate, CreatedBy)            
     values ( @tTagName, @ParentID, getdate(),@ParentID )            
            
    declare @sId bigint =  scope_identity()            
    update #tempTagName set tagId = @sId where id = @tId           
   end            
   update #tempTagName set isProcess = 1 where id = @tId            
  end            
            
  delete EntityTagMapping where EntityID = @EnquiryID and lower(Entity) = 'enquiry'            
            
  insert into EntityTagMapping(EntityID, Entity, TagID, CreatedDate)            
   select @EnquiryID, 'Enquiry', tagId, getdate() from #tempTagName            
            
 end            
            
  select * into #update from @custom                    
  update #update set EnquiryID=@EnquiryID;                      
   select * into #insert from #update where fieldID not in (select isnull(fieldID, 0) From customfieldEnquiryvalue where EnquiryID = @EnquiryID)                      
   delete From #update where EnquiryID in (select EnquiryID from #insert)                      
   declare @updatecount smallint                      
   declare @insertcount smallint                      
   select @updatecount=isnull(COUNT(fieldID), 0) from #update                      
   select @insertcount=isnull(COUNT(fieldID), 0) from #insert                       
   if(@updatecount >0)                      
   begin                      
  Update customfieldEnquiryvalue SET fieldvalue = r.fieldvalue                        
    from #update r                        
    Where customfieldEnquiryvalue.EnquiryID = r.EnquiryID and customfieldEnquiryvalue.fieldID=r.fieldID                        
    end                      
    if(@insertcount >0)                      
    begin                      
    insert into customfieldEnquiryvalue (EnquiryID,fieldID,fieldvalue) select * from #insert;                      
   end                      
   drop table #update;                      
   drop table #insert;                        
-- select * into #temp191 from @custom;                          
--        update #temp191 set EnquiryID=@EnquiryID;                      
-- if exists(select * from customfieldEnquiryvalue where EnquiryID=@EnquiryID)                      
-- begin                      
-- Update customfieldEnquiryvalue                        
--    SET                         
--    fieldvalue = r.fieldvalue                        
--    from #temp191 r                        
--    Where customfieldEnquiryvalue.EnquiryID = r.EnquiryID and customfieldEnquiryvalue.fieldID=r.fieldID;                      
--end                      
-- else                      
--     begin                        
--        insert into customfieldEnquiryvalue (EnquiryID,fieldID,fieldvalue) select * from #temp191;                   end                      
--   drop table #temp191;                      
 SELECT 'Record Updated Successfully'                        
END 


GO

