/* ============================================================
   Procedure: [dbo].[UspUpdateUserEnquiryLeadNo]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[UspUpdateUserEnquiryLeadNo]                  
 @EnquiryID bigint=null,                      
 @LeadNo int=null                    
AS                      
BEGIN                      
 update UserEnquiry set LeadNo=@LeadNo, IsOpen=0 where EnquiryID=@EnquiryID                 
 SELECT 'Record updated Successfully'         
declare @mergid bigint             
  
-- update tbl_MergeLeadsEnquiry set LeadNo = @LeadNo,   IsOpen = 1              
-- where  EnquiryNo =  @EnquiryID      
-- select @mergid=id from tbl_MergeLeadsEnquiry where  EnquiryNo =  @EnquiryID      
-- end           
--else        
 if not exists(select 1 from tbl_MergeLeadsEnquiry(nolock) where  EnquiryNo =  @EnquiryID and leadno=@LeadNo)             
 begin        
    insert into tbl_MergeLeadsEnquiry                 
   (                  
   EnquiryNo,                  
   LeadNo,            
   IsOpen                  
   )                  
   values(                  
   @EnquiryID,                  
   @LeadNo,                  
   1                  
   )                   
select @mergid=scope_identity()    
end  
else  
begin  
select @mergid=id from tbl_MergeLeadsEnquiry(nolock) where  EnquiryNo =  @EnquiryID and leadno=@LeadNo     
end  


    
Begin try      
      
  Declare @EnquiryID_LDACTV bigint = @EnquiryID ,@enqcreated datetime,@leadcreated datetime     
  Declare @LeadNo_LDACTV bigint = @LeadNo      
  Declare @LeadID_LDACTV bigint = 0      
      
  Declare @UserID_LDACTV bigint = 0      
  Declare @ParentID_LDACTV bigint = 0      
      
  select top 1 @UserID_LDACTV = ISNULL(CreatedBy,0),@ParentID_LDACTV = isnull(ParentID,0),@enqcreated=CreatedDate  from UserEnquiry(nolock) where EnquiryID = @EnquiryID_LDACTV      
      
  select top 1 @LeadID_LDACTV = isnull(id,0),@leadcreated=createdon from UserLeads(nolock) where LeadNo = @LeadNo_LDACTV and ParentID =  @ParentID_LDACTV      
      
 
 if datediff(mi,@leadcreated,@enqcreated)>5
 begin
   create table #tblEventDescrb      
   (      
     EVNT_Description nvarchar(max)       
   )      
      
  if( isnull(@LeadID_LDACTV,0) > 0)      
   Begin      
          
   insert into #tblEventDescrb      
      exec  Usp_EventTemplate_DynamicVarReplacement 'Lead generated new enquiry',@UserID_LDACTV,'','',@LeadID_LDACTV,'',null      
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,null,null      
   ,null,null,null,null,null,null,null,null,      
   0,0,0,null,null,null,0,null,null,null,@EnquiryID_LDACTV,null,null      
           
   declare @evntMessage nvarchar(max) = ''       
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb      
       
   if(@evntMessage <> '')      
   Begin      
   exec UspSaveLeadActivity_withid @LeadID_LDACTV,@UserID_LDACTV,@ParentID_LDACTV,@evntMessage,    'Lead generated new enquiry','tbl_MergeLeadsEnquiry',@mergid      
   end      
end      
      
   End        
      
   end try      
   Begin catch      
      
     exec usp_insertErrorInfo      
      
   End catch      
      
    IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence        
   Begin        
        DROP TABLE #tblEventDescrb        
    End        
        
  END


GO

/* ============================================================
   Procedure: [dbo].[UspUpdateUserLogin]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[UspUpdateUserLogin]
(
  @Userlogin nvarchar(200)
 ,@UserID bigint
)
as
Begin
--declare 
--  @Userlogin nvarchar(200)='32222-ramabcdtttteas',
-- @UserID bigint=44551
declare @ParentId bigint 
     if(exists(select 1 from User_Detail with(nolock) where User_Login = @Userlogin and User_ID <> @UserID))
 	    begin
		   select 'Userlogin already exists'
		end
     else
	    begin
		   update User_Detail set  User_Login = @Userlogin where User_ID = @UserID
		   select 'Userlogin updated' 		   
		end

		------Ticket Portal User Update--------------------------------------------------------
		SELECT @ParentId = ParentId 
        FROM tbl_tp_UserLogin WITH (NOLOCK) 
        WHERE LoginName = @Userlogin AND User_ID <> @UserID;
		if(exists(select 1 from tbl_tp_UserLogin with(nolock) where LoginName = @Userlogin and User_ID <> @UserID and ParentId=@ParentId))
 	    begin
		   print 'Userlogin already exists'
		end
     else
	    begin
		   update tbl_tp_UserLogin set  LoginName = @Userlogin where User_ID = @UserID and ParentId=@ParentId
		   print 'Userlogin updated' 		   
		end

End




GO

/* ============================================================
   Procedure: [dbo].[UspVirtualMailStatusDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



 CREATE   PROCEDURE dbo.UspVirtualMailStatusDetails --335,'','','','01/18/2016','01/25/2018'    
  (      
    @UserID int,    
    @UserLogin nvarchar(100),    
    @MessageSubject nvarchar(100),    
    @MessageContent nvarchar(max),    
    @FromDate  nvarchar(100),    
    @Todate    nvarchar(100)       
  )      
   as       
         
   Begin      
         
     --if(@FromDate ='')    
     --   Begin    
     --     set @FromDate = '01/01/2000'    
     --   end    
     --if(@Todate='')    
     --    Begin    
     --      set @Todate = GETDATE()        
     --    End    
         
    set @FromDate = coalesce(@FromDate,dateadd(d,-1,getdate()))    
    set @Todate = coalesce(@ToDate,getdate())   
         
         
     declare @parentsuperresellerid bigint    
     select @parentsuperresellerid =parentsuperresellerid from user_detail where USER_ID=@USERID    
         
         
         
    select VEF.Mail_BatchID,    
       VEF.[Mail_InsertedDate] as SentDate      
      ,u.user_login as UserName      
      , count(mail_batchid) as MailCount      
      , VEF.Mail_Subject      
      --, VEF.Mail_TempleteName    
      --,CAST(Mail_TempleteBody as nvarchar(max)) as Mail_TempleteBody    
      --,CAST(Messages as nvarchar(Max)) as Messages     
                 
    FROM [VirtualEmailsFilter](nolock) VEF      
           
      inner join    
   
   user_detail u on u.User_ID=vef.mail_batchid                
           
         where --VEF.[Mail_UserID] = @UserID    
               U.ParentSuperResellerId=@UserID   
               and u.User_Login like '%'+@UserLogin+'%'      
               and  VEF.Messages like '%'+@MessageContent+'%'     
               and  VEF.Mail_Subject like '%'+@MessageSubject+'%'      
               and VEF.[Mail_InsertedDate] between @FromDate and @Todate    
               
  group by VEF.Mail_BatchID,    
       VEF.[Mail_InsertedDate],u.user_login, VEF.Mail_Subject
             
     End 






GO

/* ============================================================
   Procedure: [dbo].[voice_mobile_fmenqld]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC voice_mobile_fmenqld --'100622,100621,100620' ,0     
(      
@endid varchar(max),      
@opt int      
)      
as      
begin      
select ROW_NUMBER() over( order by item) rno,* into #nomobile                          
from dbo.SplitString(@endid, ',')        
      
if @opt = 1      
begin      
select MobileNo from UserEnquiry where EnquiryID in (select Item from #nomobile)      
 and isnull(MobileNo,'') !=''      
union all      
select MobileNo1 from UserEnquiry where EnquiryID in (select Item from #nomobile)      
 and isnull(MobileNo1,'') !=''      
union all      
select MobileNo2 from UserEnquiry where EnquiryID in (select Item from #nomobile)      
 and isnull(MobileNo2,'') !=''      
end      
if @opt = 0      
begin      
select MobileNo from UserLeads where ID in (select Item from #nomobile)      
 and isnull(MobileNo,'') !=''      
union all      
select MobileNo1 from UserLeads where ID in (select Item from #nomobile)      
 and isnull(MobileNo1,'') !=''      
union all      
select MobileNo2 from UserLeads where ID in (select Item from #nomobile)      
 and isnull(MobileNo2,'') !=''      
end      
drop table #nomobile      
end 


GO

/* ============================================================
   Procedure: [dbo].[voice_mobile_fmenqldTemp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[voice_mobile_fmenqldTemp] --'100622,100621,100620' ,0     
(      
@endid varchar(max),      
@opt int,  
@a char(1),  
@b char(1),  
@c char(1),
@massbatchid bigint =0
)      
as      
begin      
if @massbatchid IS NOT NULL AND @massbatchid <> 0
	BEGIN
		select @endid= STRING_AGG(cast(Entityid as nvarchar(max)),',') from Tbl_MassOperationDetails where SummaryId=@massbatchid 
	END
		
select ROW_NUMBER() over( order by item) rno,* into #nomobile                          
from dbo.SplitString(@endid, ',')        
    create table #temp_mob  
(  
  mob varchar(15) null,
  LeadID bigint  
)  
if @opt = 1      
begin      
select MobileNo from UserEnquiry where EnquiryID in (select Item from #nomobile)      
 and isnull(MobileNo,'') !=''      
union all      
select MobileNo1 from UserEnquiry where EnquiryID in (select Item from #nomobile)      
 and isnull(MobileNo1,'') !=''      
union all      
select MobileNo2 from UserEnquiry where EnquiryID in (select Item from #nomobile)      
 and isnull(MobileNo2,'') !=''      
end      
if @opt = 0      
begin   
if (@a='Y')  
begin  
insert into  #temp_mob select MobileNo,ID from UserLeads where ID in (select Item from #nomobile) and isnull(MobileNo,'') !='' and  LEN( isnull(MobileNo,'') ) <16  
 end     
 if (@b='Y')  
begin  
insert into  #temp_mob select MobileNo1,ID from UserLeads where ID in (select Item from #nomobile) and isnull(MobileNo1,'') !='' and  LEN( isnull(MobileNo,'') ) <16    
 end   
 if (@c='Y')  
begin  
insert into  #temp_mob select MobileNo2,ID from UserLeads where ID in (select Item from #nomobile) and isnull(MobileNo2,'') !=''  and  LEN( isnull(MobileNo,'') ) <16
 end   
 select distinct mob,LeadID from #temp_mob  
end      
drop table #nomobile   
drop table #temp_mob     
end 



GO


